window.RG_DATA["unit:07-verbs"]={"id":"07-verbs","num":7,"title":"PHẦN 7: ĐỘNG TỪ (Глагол)","vi":"Động từ","ru":"Глагол","icon":"🏃","color":"#ef4444","sections":[{"id":"07-s001","type":"grammar","title":"PHẦN NGỮ PHÁP: ĐỘNG TỪ (Trang 255)","num":null,"blocks":[{"t":"para","text":"Biến đổi phụ âm ở gốc động từ (Глаголы с чередованием согласных в корне) Khi chia động từ, đặc biệt là ở ngôi thứ nhất số ít (Я - tôi) hoặc tất cả các ngôi (tùy nhóm), phụ âm cuối của gốc từ thường bị biến đổi."},{"t":"subhead","text":"Quy tắc chung:","b":1},{"t":"example","text":"к → ч (печь - пеку́ - печёт)"},{"t":"example","text":"г → ж (мочь - могу́ - мо́жет)"},{"t":"example","text":"х → ш (маха́ть - машу́)"},{"t":"example","text":"т → ч / щ (хоте́ть - хочу́; свети́ть - свечу́)"},{"t":"example","text":"д → ж (видеть - вижу)"},{"t":"example","text":"з → ж (резать - режу)"},{"t":"example","text":"с → ш (писать - пишу)"},{"t":"example","text":"ст → щ (свистеть - свищу)"},{"t":"example","text":"б, п, в, ф, м → thêm л (б → бл, v.v.) (любить - люблю)"}]},{"id":"07-s002","type":"exercise","title":"BÀI TẬP 503 (Trang 255)","num":503,"blocks":[{"t":"instruction","text":"Yêu cầu: Chia động từ theo mẫu. Xác định sự biến đổi phụ âm."},{"t":"para","text":"a) Замеча́ть — заме́чу, заме́тишь... (sai, đây là mẫu của заметить, замечать chia là замечаю). Sửa lại theo sách:","b":1},{"t":"vocab","ru":"Замеча́ть (NSW - chưa hoàn thành)","vi":"замеча́ю, замеча́ешь, замеча́ет... (Không biến đổi phụ âm).","g":null},{"t":"vocab","ru":"Заме́тить (SW - hoàn thành)","vi":"заме́чу (t->ч), заме́тишь, заме́тит, заме́тим, заме́тите, заме́тят.","g":null},{"t":"vocab","ru":"Отмеча́ть (NSW)","vi":"отмеча́ю...","g":null},{"t":"vocab","ru":"Отме́тить (SW)","vi":"отме́чу (t->ч), отме́тишь...","g":null},{"t":"vocab","ru":"Отвеча́ть (NSW)","vi":"отвеча́ю...","g":null},{"t":"vocab","ru":"Отве́тить (SW)","vi":"отве́чу (t->ч), отве́тишь...","g":null},{"t":"vocab","ru":"б) 1. Печь (Nướng)","vi":"пеку́ (gốc k), печёшь (k->ч), печёт, печём, печёте, пеку́т (quay lại k).","g":null},{"t":"vocab","ru":"Течь (Chảy)","vi":"теку́, течёшь, течёт, течём, течёте, теку́т.","g":null},{"t":"vocab","ru":"Влечь (Lôi cuốn)","vi":"влеку́, влечёшь, влечёт, влечём, влечёте, влеку́т.","g":null},{"t":"vocab","ru":"Стричь (Cắt tóc)","vi":"стригу́ (gốc g), стрижёшь (g->ж), стрижёт, стрижём, стрижёте, стригу́т.","g":null},{"t":"vocab","ru":"Стере́чь (Canh gác)","vi":"стерегу́, стережёшь... стерегу́т.","g":null},{"t":"vocab","ru":"Бере́чь (Giữ gìn)","vi":"берегу́,бережёшь... берегу́т.","g":null},{"t":"vocab","ru":"Пренебре́чь (Coi thường)","vi":"пренебрегу́, пренебрежёшь... пренебрегу́т.","g":null},{"t":"vocab","ru":"в) 1. Верте́ть (Xoay)","vi":"верчу́ (t->ч), ве́ртишь (giữ nguyên t), ве́ртит... ве́ртят. (Chỉ biến đổi ở ngôi Я).","g":null},{"t":"vocab","ru":"Крути́ть (Vặn)","vi":"кручу́, кру́тишь...","g":null},{"t":"vocab","ru":"Встре́тить (Gặp)","vi":"встре́чу (t->ч), встре́тишь...","g":null},{"t":"vocab","ru":"Лете́ть (Bay)","vi":"лечу́ (t->ч), лети́шь...","g":null},{"t":"vocab","ru":"Пря́тать (Giấu)","vi":"пря́чу (t->ч), пря́чешь, пря́чет... пря́чут. (Động từ nhóm 1 biến đổi ở tất cả các ngôi).","g":null},{"t":"vocab","ru":"г) Запрети́ть (Cấm)","vi":"запрещу́ (t->щ), запрети́шь...","g":null},{"t":"vocab","ru":"Возврати́ть (Trả lại)","vi":"возвращу́, возврати́шь...","g":null},{"t":"vocab","ru":"Освети́ть (Chiếu sáng)","vi":"освещу́, освети́шь...","g":null},{"t":"vocab","ru":"Прекрати́ть (Ngừng)","vi":"прекращу́, прекрати́шь...","g":null},{"t":"vocab","ru":"Сократи́ть (Rút ngắn)","vi":"сокращу́, сократи́шь...","g":null},{"t":"vocab","ru":"Защити́ть (Bảo vệ)","vi":"защищу́, защити́шь...","g":null},{"t":"vocab","ru":"Посети́ть (Thăm)","vi":"посещу́, посети́шь...","g":null},{"t":"vocab","ru":"д) 1. Носи́ть (Mang/Mặc)","vi":"ношу́ (s->sh), но́сишь...","g":null},{"t":"vocab","ru":"Коси́ть (Cắt cỏ/Lác mắt)","vi":"кошу́, ко́сишь...","g":null},{"t":"vocab","ru":"Проси́ть (Xin)","vi":"прошу́, про́сишь...","g":null},{"t":"vocab","ru":"Ве́сить (Cân nặng)","vi":"ве́шу, ве́сишь...","g":null},{"t":"vocab","ru":"Зави́сеть (Phụ thuộc)","vi":"зави́шу, зави́сишь...","g":null},{"t":"vocab","ru":"Возвы́сить (Nâng cao)","vi":"возвы́шу, возвы́сишь...","g":null},{"t":"vocab","ru":"Писа́ть (Viết)","vi":"пишу́ (s->sh), пи́шешь, пи́шет... пи́шут. (Nhóm 1 biến đổi hết).","g":null},{"t":"vocab","ru":"Пляса́ть (Nhảy múa)","vi":"пляшу́, пля́шешь...","g":null},{"t":"vocab","ru":"Причеса́ть (Chải đầu)","vi":"причешу́, приче́шешь...","g":null},{"t":"vocab","ru":"Броса́ть (Ném - NSW)","vi":"броса́ю, броса́ешь... (Không đổi).","g":null},{"t":"vocab","ru":"Бро́сить (Ném - SW)","vi":"бро́шу (s->sh), бро́сишь...","g":null},{"t":"vocab","ru":"е) Маха́ть (Vẫy)","vi":"машу́ (h->sh), ма́шешь... ма́шут.","g":null},{"t":"vocab","ru":"Паха́ть (Cày)","vi":"пашу́, па́шешь...","g":null},{"t":"vocab","ru":"ж) 1. Изобрази́ть (Mô tả)","vi":"изображу́ (z->zh), изобрази́шь...","g":null},{"t":"vocab","ru":"Вообрази́ть (Tưởng tượng)","vi":"воображу́, вообрази́шь...","g":null},{"t":"vocab","ru":"Тормози́ть (Phanh)","vi":"торможу́, тормози́шь...","g":null},{"t":"vocab","ru":"Вози́ть (Chở)","vi":"вожу́ (z->zh), во́зишь...","g":null},{"t":"vocab","ru":"Ма́зать (Bôi)","vi":"ма́жу (z->zh), ма́жешь... (Nhóm 1 biến đổi hết).","g":null},{"t":"vocab","ru":"Сказа́ть (Nói)","vi":"скажу́ (z->zh), ска́жешь...","g":null},{"t":"vocab","ru":"Вяза́ть (Đan/Buộc)","vi":"вяжу́, вя́жешь...","g":null},{"t":"vocab","ru":"Обяза́ть (Bắt buộc)","vi":"обяжу́, обя́жешь...","g":null},{"t":"vocab","ru":"з) 1. Утверди́ть (Khẳng định)","vi":"утвержу́ (d->zh), утверди́шь...","g":null},{"t":"vocab","ru":"Гляде́ть (Nhìn)","vi":"гляжу́, гляди́шь...","g":null},{"t":"vocab","ru":"Сиде́ть (Ngồi)","vi":"сижу́, сиди́шь...","g":null},{"t":"vocab","ru":"Охлади́ть (Làm lạnh)","vi":"охлажу́, охлади́шь...","g":null},{"t":"para","text":"2. (Các động từ khuyết ngôi thứ nhất số ít):","b":1},{"t":"vocab","ru":"Убеди́ть (Thuyết phục), Победи́ть (Chiến thắng)","vi":"Không dùng dạng \"pobedu/ubedu\". Phải dùng: смогу́ победи́ть (sẽ có thể thắng), одержу́ побе́ду (giành chiến thắng).","g":null},{"t":"vocab","ru":"Награди́ть (Thưởng)","vi":"награжу́, награди́шь...","g":null},{"t":"vocab","ru":"Вреди́ть (Làm hại)","vi":"врежу́, вреди́шь...","g":null},{"t":"vocab","ru":"Предупреди́ть (Cảnh báo)","vi":"предупрежу́, предупреди́шь...","g":null},{"t":"vocab","ru":"Разбуди́ть (Đánh thức)","vi":"разбужу́, разбуди́шь...","g":null},{"t":"vocab","ru":"(Tiếp) Ходи́ть (Đi bộ)","vi":"хожу́ (d->zh), хо́дишь...","g":null},{"t":"vocab","ru":"Броди́ть (Lang thang)","vi":"брожу́, бро́дишь...","g":null},{"t":"vocab","ru":"Посади́ть (Trồng/Đặt ngồi)","vi":"посажу́, посади́шь...","g":null},{"t":"vocab","ru":"Гла́дить (Vuốt ve/Là ủi)","vi":"гла́жу, гла́дишь...","g":null}]},{"id":"07-s003","type":"exercise","title":"BÀI TẬP 504 (Trang 256)","num":504,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, chia động từ ở thì hiện tại (với động từ chưa hoàn thành) hoặc tương lai đơn (với động từ hoàn thành)."},{"t":"para","text":"1. По вечера́м я (броди́ть) брожу́ по па́рку, со мно́ю по алле́ям па́рка (броди́ть) бро́дит моя́ соба́ка.","b":1},{"t":"para","text":"Dịch: Vào các buổi tối tôi thường lang thang trong công viên, con chó của tôi cũng lang thang cùng tôi dọc theo các lối đi."},{"t":"example","text":"Giải thích: Броди́ть (lang thang) là động từ chưa hoàn thành, chỉ thói quen -> chia thì hiện tại. Я брожу (d->zh), собака бродит."},{"t":"para","text":"2. Е́сли ты не (бере́чь) бережёшь своё здоро́вье, мне на́до о нём позабо́титься: я (запрети́ть) запрещу́ тебе́ гуля́ть, е́сли ты бу́дешь без ша́пки бе́гать по у́лицам.","b":1},{"t":"para","text":"Dịch: Nếu con không giữ gìn sức khỏe, mẹ phải lo cho nó: mẹ sẽ cấm con đi chơi nếu con cứ chạy ngoài đường mà không đội mũ."},{"t":"example","text":"Giải thích: Беречь (NSW) -> бережёшь (k/ch/zh). Запретить (SW - tương lai) -> запрещу (t->щ)."},{"t":"para","text":"3. Его́ всегда́ (влечь) влечёт всё неизве́стное, неизве́данное.","b":1},{"t":"para","text":"Dịch: Những điều chưa biết, chưa khám phá luôn lôi cuốn anh ấy."},{"t":"example","text":"Giải thích: Влечь -> ngôi thứ 3 số ít: влечёт."},{"t":"para","text":"4. По пе́рвому вы́зову он (лете́ть) лети́т в са́мые отдалённые райо́ны.","b":1},{"t":"para","text":"Dịch: Ngay khi có cuộc gọi đầu tiên, anh ấy bay tới những vùng xa xôi nhất."},{"t":"example","text":"Giải thích: Лете́ть -> лети́т."},{"t":"para","text":"5. Я (прекрати́ть) прекращу́ задава́ть вопро́сы, как то́лько ты (отве́тить) отве́тишь хотя́ бы на не́которые из них.","b":1},{"t":"para","text":"Dịch: Tôi sẽ ngừng đặt câu hỏi ngay khi cậu trả lời được ít nhất vài câu."},{"t":"example","text":"Giải thích: Прекратить (SW) -> прекращу (t->щ). Ответить (SW) -> ответишь."},{"t":"para","text":"6. Я никогда́ ничего́ не (печь) пеку́, но моя́ ма́ма (печь) печёт удиви́тельные бу́лочки.","b":1},{"t":"para","text":"Dịch: Tôi chẳng bao giờ nướng gì cả, nhưng mẹ tôi nướng bánh mì ngon tuyệt."},{"t":"example","text":"Giải thích: Печь -> Я пеку (gốc k), мама печёт (k->ч)."},{"t":"para","text":"7. Посмотри́, твой се́стра (маха́ть) ма́шет тебе́ из окна́.","b":1},{"t":"para","text":"Dịch: Nhìn kìa, em gái cậu đang vẫy cậu từ cửa sổ."},{"t":"example","text":"Giải thích: Махать -> машет (h->sh)."},{"t":"para","text":"8. Мой парикма́хер, я уве́рена, (причеса́ть) приче́шет тебя́ наилу́чшим о́бразом.","b":1},{"t":"para","text":"Dịch: Thợ cắt tóc của tớ, tớ tin là sẽ chải/làm tóc cho cậu đẹp nhất."},{"t":"example","text":"Giải thích: Причесать (SW) -> причешет (s->sh)."},{"t":"example","text":"9. Я (убеди́ть) постара́юсь убеди́ть / смогу́ убеди́ть его́ не де́лать поспе́шных вы́водов. (Lưu ý: Động từ убедить không có ngôi thứ nhất số ít убежу)."},{"t":"para","text":"Dịch: Tôi sẽ cố gắng thuyết phục anh ấy đừng vội kết luận."},{"t":"example","text":"Giải thích: Dùng động từ bổ trợ. Sách có thể chấp nhận убежу trong bài tập ngữ pháp thuần túy để luyện quy tắc d->zh, nhưng trong thực tế người Nga tránh dùng. Đáp án an toàn: постараюсь убедить."},{"t":"para","text":"10. Заче́м ты (пря́тать) пря́чешь от меня́ глаза́?","b":1},{"t":"para","text":"Dịch: Tại sao em lại giấu ánh mắt đi (tránh nhìn anh)?"},{"t":"example","text":"Giải thích: Прятать -> прячешь (t->ч)."},{"t":"para","text":"11. Я то́лько (погляде́ть) погляжу́ на э́ту игру́шку и да́же не возьму́ её в ру́ки.","b":1},{"t":"para","text":"Dịch: Con chỉ nhìn đồ chơi này một cái thôi chứ không cầm lên đâu."},{"t":"example","text":"Giải thích: Поглядеть (SW) -> погляжу (d->zh)."},{"t":"para","text":"12. На э́той карти́не я (изобрази́ть) изображу́ наш дом и лужа́йку пе́ред ним.","b":1},{"t":"para","text":"Dịch: Trong bức tranh này tôi sẽ vẽ/mô tả ngôi nhà của chúng ta và bãi cỏ trước nhà."},{"t":"example","text":"Giải thích: Изобразить (SW) -> изображу (z->zh)."},{"t":"para","text":"13. Я то́лько (предупреди́ть) предупрежу́ его́ о твоём прихо́де, а пото́м (встре́тить) встре́чу тебя́ на вера́нде и (проводи́ть) провожу́ к нему́.","b":1},{"t":"para","text":"Dịch: Tớ chỉ báo trước cho ông ấy về việc cậu đến, rồi sau đó tớ sẽ đón cậu ở hiên và dẫn vào gặp ông ấy."},{"t":"example","text":"Giải thích: Предупредить -> предупрежу (d->zh). Встретить -> встречу (t->ч). Проводить -> провожу (d->zh)."},{"t":"para","text":"14. Он рабо́тает (паха́ть) па́шет как вол, рабо́тает по 10-12 часо́в в су́тки.","b":1},{"t":"para","text":"Dịch: Anh ấy làm việc (cày) như trâu, làm 10-12 tiếng một ngày."},{"t":"example","text":"Giải thích: Пахать -> пашет (h->sh)."},{"t":"para","text":"15. Я не (прекрати́ть) прекращу́ заня́тия, да́же е́сли мне (запрети́ть) запретя́т занима́ться.","b":1},{"t":"para","text":"Dịch: Tôi sẽ không ngừng học, ngay cả khi người ta cấm tôi."},{"t":"example","text":"Giải thích: Прекратить -> прекращу (t->щ). Запретить -> запретят (số nhiều, họ cấm)."},{"t":"para","text":"16. В свобо́дное вре́мя она́ (вяза́ть) вя́жет и́ли (вози́ться) во́зится с цвета́ми в саду́.","b":1},{"t":"para","text":"Dịch: Lúc rảnh rỗi cô ấy đan lát hoặc cặm cụi/bận bịu với hoa trong vườn."},{"t":"example","text":"Giải thích: Вязать -> вяжет (z->zh). Возиться -> возится."},{"t":"para","text":"17. Я то́лько (заме́тить) заме́чу, что, е́сли ты не (прекрати́ть) прекрати́шь спо́рить со мной по любо́му по́воду, я (возвраща́ться) возвращу́сь домо́й оди́н.","b":1},{"t":"para","text":"Dịch: Anh chỉ lưu ý rằng, nếu em không ngừng tranh cãi với anh về mọi lý do, anh sẽ quay về nhà một mình."},{"t":"example","text":"Giải thích: Заметить -> замечу. Прекратить -> прекратишь. Возвратиться (SW - ở đây nên dùng SW để chỉ tương lai dứt khoát) -> возвращусь. (Lưu ý sách ghi возвращаться là NSW, nếu chia NSW thì là буду возвращаться hoặc возвращаюсь (hiện tại), nhưng ngữ cảnh đe dọa thường dùng SW возвращусь). Nếu bắt buộc dùng động từ trong ngoặc возвращаться -> бу́ду возвраща́ться hoặc возвраща́юсь (ý tương lai gần). Tuy nhiên, возвращусь (từ возвратиться) hợp lý hơn."},{"t":"para","text":"18. Ду́маю, я (отказа́ть) откажу́ ему́; в настоя́щиий моме́нт я не могу́ приня́ть его́ предложе́ние, но он до́лжен поня́ть, что моё реше́ние (зави́сеть) зави́сит от обстоя́тельств.","b":1},{"t":"para","text":"Dịch: Tôi nghĩ tôi sẽ từ chối anh ấy... quyết định của tôi phụ thuộc vào hoàn cảnh."},{"t":"example","text":"Giải thích: Отказать -> откажу. Зависеть -> зависит."}]},{"id":"07-s004","type":"exercise","title":"BÀI TẬP 505 (Trang 257)","num":505,"blocks":[{"t":"instruction","text":"Yêu cầu: Tạo thể mệnh lệnh (Imperative - Повелительное наклонение) từ các động từ."},{"t":"subhead","text":"Quy tắc:","b":1},{"t":"example","text":"Lấy ngôi họ (они) ở thì hiện tại/tương lai."},{"t":"example","text":"Bỏ đuôi (-ут/-ют/-ат/-ят)."},{"t":"para","text":"Xét gốc từ còn lại:"},{"t":"example","text":"Tận cùng bằng nguyên âm → thêm -й (чита-ют -> чита -> читай)."},{"t":"example","text":"Tận cùng bằng phụ âm + trọng âm ở đuôi (ngôi 1 số ít я) → thêm -и (пиш-ут -> пиш -> пиши vì я пишУ)."},{"t":"example","text":"Tận cùng bằng phụ âm + không trọng âm ở đuôi → thêm -ь (ответ-ят -> ответ -> ответь)."},{"t":"para","text":"a)","b":1},{"t":"para","text":"Замеча́ть (замеча́ют -> замеча́й) -> замеча́йте."},{"t":"example","text":"Заме́тить (заме́тят -> замет- -> заме́ть) -> заме́тьте. (Lưu ý trọng âm заме́чу ở gốc, nên thêm ь)."},{"t":"para","text":"Отмеча́ть -> отмеча́йте."},{"t":"para","text":"Отвеча́ть -> отвеча́йте."},{"t":"para","text":"б)","b":1},{"t":"example","text":"Печь (пеку́т -> пек- -> trọng âm пекУ) -> пеки́те."},{"t":"para","text":"Течь (теку́т) -> теки́те."},{"t":"para","text":"Увле́чь (увлеку́т) -> увлеки́те."},{"t":"para","text":"Стричь (стригу́т) -> стриги́те."},{"t":"para","text":"Стере́чь (стерегу́т) -> стереги́те."},{"t":"para","text":"Бере́чь (берегу́т) -> береги́те."},{"t":"para","text":"Напря́чь (напрягу́т) -> напряги́те."},{"t":"para","text":"в)","b":1},{"t":"example","text":"Верте́ть (ве́ртят -> верт- -> trọng âm верчУ) -> верти́те."},{"t":"para","text":"Крути́ть -> крути́те."},{"t":"example","text":"Встре́тить (встре́тят -> встрет- -> trọng âm встре́чу) -> встре́тьте."},{"t":"para","text":"Встреча́ть -> встреча́йте."},{"t":"example","text":"Лете́ть (летя́т -> лет- -> trọng âm лечУ) -> лети́те."},{"t":"example","text":"Пря́тать (пря́чут -> пряч- -> trọng âm пря́чу) -> пря́чьте."},{"t":"para","text":"Запрети́ть -> запрети́те."},{"t":"para","text":"Возврати́ть -> возврати́те."},{"t":"para","text":"Освети́ть -> освети́те."},{"t":"para","text":"Прекрати́ть -> прекрати́те."},{"t":"para","text":"Сократи́ть -> сократи́те."},{"t":"para","text":"Защити́ть -> защити́те."},{"t":"para","text":"Посети́ть -> посети́те."},{"t":"para","text":"д)","b":1},{"t":"para","text":"Носи́ть -> носи́те."},{"t":"para","text":"Коси́ть -> коси́те."},{"t":"para","text":"Проси́ть -> проси́те."},{"t":"example","text":"Взве́сить (взве́сят -> взвес- -> взве́шу) -> взве́сьте."},{"t":"para","text":"Обезопа́сить -> обезопа́сьте."},{"t":"para","text":"Висе́ть -> виси́те."},{"t":"para","text":"Писа́ть -> пиши́те."},{"t":"para","text":"Пляса́ть -> пляши́те."},{"t":"para","text":"Причеса́ть -> причеши́те."},{"t":"para","text":"Броса́ть (броса́ют) -> броса́йте."},{"t":"example","text":"Бро́сить (бро́сят -> брос- -> бро́шу) -> бро́сьте."},{"t":"para","text":"е)","b":1},{"t":"vocab","ru":"Маха́ть (ма́шут -> маш- -> машу́) -> маши́те. (Lưu ý","vi":"Có dạng махайте trong văn nói, nhưng chuẩn mực là машите).","g":null},{"t":"para","text":"Паха́ть -> паши́те."},{"t":"para","text":"ж)","b":1},{"t":"para","text":"Изобрази́ть -> изобрази́те."},{"t":"para","text":"Вообрази́ть -> вообрази́те."},{"t":"para","text":"Тормози́ть -> тормози́те."},{"t":"para","text":"Вози́ть -> вози́те."},{"t":"example","text":"Ма́зать (ма́жут -> маж- -> ма́жу) -> ма́жьте."},{"t":"para","text":"Ре́зать -> ре́жьте."},{"t":"example","text":"Вяза́ть (вя́жут -> вяж- -> вяжу́) -> вяжи́те."},{"t":"para","text":"Обяза́ть -> обяжи́те."},{"t":"para","text":"Сказа́ть -> скажи́те."},{"t":"para","text":"Показа́ть -> покажи́те."},{"t":"para","text":"з)","b":1},{"t":"para","text":"Утверди́ть -> утверди́те."},{"t":"para","text":"Гляде́ть -> гляди́те."},{"t":"para","text":"Сиде́ть -> сиди́те."},{"t":"para","text":"Охлади́ть -> охлади́те."},{"t":"example","text":"Убеди́ть -> (Không có mệnh lệnh trực tiếp, dùng постарайтесь убедить)."},{"t":"para","text":"Победи́ть -> победи́те."},{"t":"para","text":"Награди́ть -> награди́те."},{"t":"example","text":"Вреди́ть -> вреди́те (thường dùng не вреди́те)."},{"t":"para","text":"Предупреди́ть -> предупреди́те."},{"t":"para","text":"Разубеди́ть -> разубеди́те."},{"t":"para","text":"Броди́ть -> броди́те."},{"t":"para","text":"Посади́ть -> посади́те."},{"t":"para","text":"Проводи́ть -> проводи́те."},{"t":"para","text":"Разбуди́ть -> разбуди́те."},{"t":"example","text":"Гла́дить (гла́дят -> глад- -> гла́жу) -> гла́дьте."}]},{"id":"07-s005","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 258)","num":null,"blocks":[{"t":"para","text":"Thể mệnh lệnh của động từ phản thân (Повелительное наклонение возвратных глаголов):","b":1},{"t":"para","text":"Đối với các động từ ở ngôi thứ 2 số nhiều (вы), thể mệnh lệnh được hình thành bằng cách thêm hậu tố -ся hoặc -сь."},{"t":"para","text":"Vị trí: Hậu tố phản thân -сь đứng SAU đuôi -те."},{"t":"subhead","text":"Quy tắc:"},{"t":"example","text":"Sau nguyên âm: dùng -сь (Ví dụ: улыба́й + те + сь → улыба́йтесь - hãy mỉm cười)."},{"t":"example","text":"Sau phụ âm: dùng -ся (Ví dụ: гото́вь + те + ся → гото́вьтесь - hãy chuẩn bị)."}]},{"id":"07-s006","type":"exercise","title":"BÀI TẬP 506 (Trang 258)","num":506,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay thế các cấu trúc đi kèm động từ nguyên thể (инфинитив) bằng động từ ở thể mệnh lệnh. Xác định câu nào là tục ngữ (пословица)."},{"t":"para","text":"1. Вы не могли́ бы отре́зать мне кусо́к то́рта?","b":1},{"t":"para","text":"Viết lại: Отре́жьте мне кусо́к то́рта."},{"t":"para","text":"Dịch: Bạn cắt cho tôi một miếng bánh gato nhé."},{"t":"example","text":"Giải thích: Отре́зать (cắt) → mệnh lệnh: отре́жь (số ít) / отре́жьте (số nhiều/lịch sự)."},{"t":"para","text":"2. Ты до́лжен бере́чь пла́тье сно́ву, а честь смо́лоду. (Tục ngữ)"},{"t":"para","text":"Viết lại: Береги́ пла́тье сно́ву, а честь смо́лоду."},{"t":"para","text":"Dịch: Hãy giữ gìn quần áo khi còn mới, và (giữ) danh dự khi còn trẻ."},{"t":"para","text":"Giải thích: Tục ngữ khuyên răn về việc giữ gìn phẩm giá từ sớm."},{"t":"vocab","ru":"Попро́буй вообрази́ть","vi":"всё произошло́ так бы́стро, что я не успе́ла ничего́ заме́тить.","g":null},{"t":"para","text":"Viết lại: Вообрази́: всё произошло́ так бы́стро..."},{"t":"para","text":"Dịch: Hãy tưởng tượng xem: mọi chuyện diễn ra nhanh đến mức tôi không kịp nhận thấy gì cả."},{"t":"vocab","ru":"Сто́ит заме́тить","vi":"э́то предложи́ли вы, а не я.","g":null},{"t":"para","text":"Viết lại: Заме́тьте: э́то предложи́ли вы, а не я."},{"t":"para","text":"Dịch: Xin lưu ý rằng: điều này là do các bạn đề xuất, chứ không phải tôi."},{"t":"para","text":"5. Вам на́до возврати́ть кни́гу не по́зже обозна́ченного здесь сро́ка.","b":1},{"t":"para","text":"Viết lại: Возврати́те кни́гу не по́зже обозна́ченного здесь сро́ка."},{"t":"para","text":"Dịch: Hãy trả lại sách không muộn hơn thời hạn được ghi ở đây."},{"t":"para","text":"6. Е́сли вы бу́дете у нас в го́роде, вы обяза́тельно должны́ посети́ть дельфина́рий.","b":1},{"t":"para","text":"Viết lại: ..., посети́те (обяза́тельно) дельфина́рий."},{"t":"para","text":"Dịch: Nếu các bạn đến thành phố chúng tôi, hãy (nhất định) ghé thăm khu biểu diễn cá heo."},{"t":"para","text":"7. Не смогу́ я пое́хать с тобо́й за́втра, и не на́до проси́ть об э́том.","b":1},{"t":"para","text":"Viết lại: ..., и не проси́ об э́том."},{"t":"para","text":"Dịch: Tớ không thể đi cùng cậu ngày mai được đâu, và đừng nài nỉ/xin về việc đó nữa."},{"t":"para","text":"8. Ты до́лжен неме́дленно прекрати́ть спо́рить со мной, э́тот вопро́с давно́ решён.","b":1},{"t":"para","text":"Viết lại: Неме́дленно прекрати́ спо́рить со мной..."},{"t":"para","text":"Dịch: Hãy ngừng ngay việc tranh cãi với tôi, vấn đề này đã được quyết định từ lâu rồi."},{"t":"para","text":"9. Тебе́ лу́чше лете́ть у́тренним ре́йсом, е́сли хо́чешь успе́ть во́время.","b":1},{"t":"para","text":"Viết lại: Лети́ у́тренним ре́йсом, е́сли..."},{"t":"para","text":"Dịch: Hãy bay chuyến buổi sáng nếu cậu muốn kịp giờ."},{"t":"para","text":"10. Пожа́луйста, вы должны́ отве́тить мне ещё на оди́н вопро́с.","b":1},{"t":"para","text":"Viết lại: Пожа́луйста, отве́тьте мне ещё на оди́н вопро́с."},{"t":"para","text":"Dịch: Làm ơn, hãy trả lời cho tôi thêm một câu hỏi nữa."},{"t":"para","text":"11. Вам сто́ит верну́ться на своё ме́сто.","b":1},{"t":"para","text":"Viết lại: Верни́тесь на своё ме́сто."},{"t":"para","text":"Dịch: Hãy quay về chỗ của mình đi."},{"t":"para","text":"12. Е́сли у тебя́ за́втра не бу́дет свобо́дного вре́мени, что́бы встре́титься с ним, сто́ит сказа́ть ему́ об э́том сего́дня.","b":1},{"t":"para","text":"Viết lại: ..., скажи́ ему́ об э́том сего́дня."},{"t":"para","text":"Dịch: Nếu mai bạn không rảnh để gặp anh ấy, thì hãy nói cho anh ấy biết ngay hôm nay."},{"t":"para","text":"13. Постара́йся разбуди́ть меня́ за́втра пора́ньше.","b":1},{"t":"para","text":"Viết lại: Разбуди́ меня́ за́втра пора́ньше."},{"t":"para","text":"Dịch: Hãy đánh thức tớ dậy sớm hơn vào ngày mai nhé."},{"t":"para","text":"14. Тебе́ лу́чше нама́зать хлеб ма́слом и отре́зать сы́ра.","b":1},{"t":"para","text":"Viết lại: Нама́жь хлеб ма́слом и отре́жь сы́ра."},{"t":"para","text":"Dịch: Hãy phết bơ lên bánh mì và cắt một ít phô mai đi."},{"t":"para","text":"15. Пожа́луйста, помоги́ развяза́ть э́тот у́зел, у меня́ ничего́ не получа́ется.","b":1},{"t":"para","text":"Viết lại: Пожа́луйста, развяжи́ э́тот у́зел..."},{"t":"para","text":"Dịch: Làm ơn hãy cởi/gỡ cái nút thắt này giúp, tôi làm mãi không được."},{"t":"para","text":"16. Не могли́ бы вы постри́чь меня́, как в про́шлый раз.","b":1},{"t":"para","text":"Viết lại: Постриги́те меня́, как в про́шлый раз."},{"t":"para","text":"Dịch: Hãy cắt tóc cho tôi giống như lần trước nhé."},{"t":"para","text":"17. Попро́буй разубеди́ть его́ поступа́ть в институ́т в э́том году́, он ещё не гото́в к вступи́тельным экза́менам.","b":1},{"t":"para","text":"Viết lại: Разубеди́ его́ поступа́ть..."},{"t":"para","text":"Dịch: Hãy khuyên can/thuyết phục nó đừng thi vào đại học năm nay, nó vẫn chưa sẵn sàng cho kỳ thi đầu vào đâu."},{"t":"para","text":"18. Ты должна́ погла́дить свою́ блу́зку.","b":1},{"t":"para","text":"Viết lại: Погла́дь свою́ блу́зку."},{"t":"para","text":"Dịch: Hãy là/ủi cái áo blouse của con đi."},{"t":"para","text":"19. Пожа́луйста, не могли́ бы вы притормози́ть, мне на́до зайти́ в магази́н.","b":1},{"t":"para","text":"Viết lại: Пожа́луйста, притормози́те, мне на́до..."},{"t":"para","text":"Dịch: Làm ơn hãy hãm phanh/dừng lại một chút, tôi cần ghé vào cửa hàng."},{"t":"para","text":"20. Ты до́лжен не болта́ть нога́ми и прекрати́ть чита́ть во вре́мя еды́.","b":1},{"t":"para","text":"Viết lại: Не болта́й нога́ми и прекрати́ чита́ть во вре́мя еды́."},{"t":"para","text":"Dịch: Đừng rung đùi và ngừng đọc sách trong khi ăn."},{"t":"para","text":"21. Бою́сь, я опозда́ю, постара́йся предупреди́ть об э́том мои́х роди́телей.","b":1},{"t":"para","text":"Viết lại: ..., предупреди́ об э́том мои́х роди́телей."},{"t":"para","text":"Dịch: Sợ là tớ sẽ đến muộn, hãy báo trước việc này cho bố mẹ tớ nhé."},{"t":"para","text":"22. Постара́йся напря́чь всю свою́ па́мять и вспо́мнить но́мер его́ телефо́на.","b":1},{"t":"para","text":"Viết lại: Напряги́ всю свою́ па́мять и вспо́мни..."},{"t":"para","text":"Dịch: Hãy căng trí nhớ ra và nhớ lại số điện thoại của cậu ấy xem."},{"t":"para","text":"23. Вам сто́ит бро́сить э́то заня́тие, ни к чему́ хоро́шему оно́ вас не приведёт.","b":1},{"t":"para","text":"Viết lại: Бро́сьте э́то заня́тие..."},{"t":"para","text":"Dịch: Hãy bỏ cái trò đó đi, nó chẳng dẫn các bạn đến điều gì tốt đẹp đâu."}]},{"id":"07-s007","type":"exercise","title":"BÀI TẬP 507 (Trang 258)","num":507,"blocks":[{"t":"instruction","text":"Yêu cầu: Chia động từ theo mẫu. Xác định sự biến đổi phụ âm ở gốc từ."},{"t":"subhead","text":"Quy tắc biến đổi phụ âm (Чередование согласных):"},{"t":"example","text":"ст → щ (пустить - пущу)"},{"t":"example","text":"б, п, в, ф, м → thêm л (любить - люблю)"},{"t":"example","text":"д → ж (видеть - вижу)"},{"t":"example","text":"т → ч (вертеть - верчу) hoặc щ (светить - свещу)"},{"t":"example","text":"з → ж (возить - вожу)"},{"t":"example","text":"с → ш (писать - пишу)"},{"t":"subhead","text":"а) Nhóm biến đổi ст → щ (ở ngôi Я) hoặc с → ш / з → ж:","b":1},{"t":"vocab","ru":"Пусти́ть","vi":"пущу́, пу́стишь, пу́стят. (st → щ).","g":null},{"t":"vocab","ru":"Опусти́ть (Hạ xuống)","vi":"опущу́, опу́стишь.","g":null},{"t":"vocab","ru":"Пропусти́ть (Bỏ lỡ)","vi":"пропущу́, пропу́стишь.","g":null},{"t":"vocab","ru":"Прости́ть (Tha thứ)","vi":"прощу́, прости́шь.","g":null},{"t":"vocab","ru":"Навести́ть (Thăm)","vi":"навещу́, навести́шь.","g":null},{"t":"vocab","ru":"Блесте́ть (Lấp lánh)","vi":"блещу́, блести́шь.","g":null},{"t":"vocab","ru":"Грусти́ть (Buồn)","vi":"грущу́, грусти́шь.","g":null},{"t":"vocab","ru":"Свисте́ть (Huýt sáo)","vi":"свищу́, свисти́шь.","g":null},{"t":"vocab","ru":"Иска́ть (Tìm - sk → щ)","vi":"ищу́, и́щешь.","g":null},{"t":"vocab","ru":"Класть (Đặt - s → d)","vi":"кладу́, кладёшь. (Lưu ý: đây là động từ bất quy tắc, gốc клад-).","g":null},{"t":"subhead","text":"б) Nhóm biến đổi Môi + Л (б, п, в, ф, м → бл, пл, вл, фл, мл):","b":1},{"t":"vocab","ru":"Люби́ть","vi":"люблю́, лю́бишь.","g":null},{"t":"vocab","ru":"Лови́ть (Bắt)","vi":"ловлю́, ло́вишь.","g":null},{"t":"vocab","ru":"Корми́ть (Cho ăn)","vi":"кормлю́, ко́рмишь.","g":null},{"t":"vocab","ru":"Купи́ть (Mua)","vi":"куплю́, ку́пишь.","g":null},{"t":"vocab","ru":"Копи́ть (Tiết kiệm)","vi":"коплю́, ко́пишь.","g":null},{"t":"vocab","ru":"Терпе́ть (Chịu đựng)","vi":"терплю́, те́рпишь.","g":null},{"t":"vocab","ru":"Торопи́ться (Vội)","vi":"тороплю́сь, торо́пишься.","g":null},{"t":"vocab","ru":"Оскорби́ть (Xúc phạm)","vi":"оскорблю́, оскорби́шь.","g":null},{"t":"vocab","ru":"Укрепи́ть (Củng cố)","vi":"укреплю́, укрепи́шь.","g":null},{"t":"vocab","ru":"Спать (Ngủ)","vi":"сплю, спишь.","g":null},{"t":"subhead","text":"в) Nhóm khác (gồm cả biến đổi ст → т, с → д...):","b":1},{"t":"vocab","ru":"Мести́ (Quét)","vi":"мету́, метёшь. (s → t).","g":null},{"t":"vocab","ru":"Цвести́ (Nở hoa)","vi":"цвету́, цветёшь.","g":null},{"t":"vocab","ru":"Плести́ (Tết/đan)","vi":"плету́, плетёшь.","g":null},{"t":"vocab","ru":"Вести́ (Dẫn đi)","vi":"веду́, ведёшь. (s → d).","g":null},{"t":"vocab","ru":"Брести́ (Lê bước)","vi":"бреду́, бредёшь.","g":null},{"t":"vocab","ru":"Нести́ (Mang)","vi":"несу́, несёшь. (Giữ nguyên s).","g":null},{"t":"vocab","ru":"Трясти́ (Rung/lắc)","vi":"трясу́, трясёшь.","g":null},{"t":"vocab","ru":"Спасти́ (Cứu)","vi":"спасу́, спасёшь.","g":null},{"t":"vocab","ru":"Запасти́ (Dự trữ)","vi":"запасу́, запасёшь.","g":null},{"t":"vocab","ru":"Везти́ (Chở)","vi":"везу́, везёшь. (z → z).","g":null},{"t":"vocab","ru":"Грести́ (Chèo)","vi":"гребу́, гребёшь. (s → b).","g":null},{"t":"vocab","ru":"Упа́сть (Ngã)","vi":"упаду́, упадёшь. (s → d).","g":null},{"t":"vocab","ru":"Укра́сть (Ăn trộm)","vi":"украду́, украдёшь.","g":null},{"t":"vocab","ru":"Сесть (Ngồi)","vi":"ся́ду, ся́дешь. (s → d, e → я).","g":null},{"t":"vocab","ru":"Надое́сть (Làm chán)","vi":"надое́м, надое́шь (Chia như есть).","g":null},{"t":"vocab","ru":"Лезть (Leo/chui)","vi":"ле́зу, ле́зешь. (z giữ nguyên).","g":null},{"t":"vocab","ru":"Идти́ (Đi)","vi":"иду́, идёшь.","g":null},{"t":"vocab","ru":"Найти́ (Tìm thấy)","vi":"найду́, найдёшь.","g":null},{"t":"vocab","ru":"Вы́йти (Ra ngoài)","vi":"вы́йду, вы́йдешь.","g":null}]},{"id":"07-s008","type":"exercise","title":"BÀI TẬP 508 (Trang 259)","num":508,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, chia động từ ở thì hiện tại (với động từ chưa hoàn thành) hoặc tương lai đơn (với động từ hoàn thành)."},{"t":"para","text":"1. Я не (спать) сплю уже́ вторы́е су́тки, (задрема́ть) задремлю́ ненадо́лго и опя́ть не могу́ сомкну́ть глаз.","b":1},{"t":"para","text":"Dịch: Tôi không ngủ đã hai ngày nay rồi, chỉ chợp mắt một chút rồi lại không thể nhắm mắt được nữa."},{"t":"example","text":"Giải thích: Спать (NSW - hiện tại) → сплю. Задремать (SW - tương lai) → задремлю́."},{"t":"para","text":"2. — Чем вы (корми́ть) ко́рмите свою́ ко́шку? — (Корми́ть) Кормлю́ тем же, что (есть) ем сам, она́ у меня́ непривере́дливая.","b":1},{"t":"para","text":"Dịch: — Bạn cho mèo ăn gì thế? — Tôi cho ăn những gì chính tôi ăn, nó không kén chọn đâu."},{"t":"example","text":"Giải thích: Кормить → ко́рмите (bạn), кормлю́ (tôi). Есть (ăn) → ем (tôi)."},{"t":"para","text":"3. Не беспоко́йся, я обяза́тельно (навести́ть) навещу́ твои́х роди́телей.","b":1},{"t":"para","text":"Dịch: Đừng lo, tớ chắc chắn sẽ thăm bố mẹ cậu."},{"t":"example","text":"Giải thích: Навестить (SW - tương lai) → навещу́ (st → щ)."},{"t":"example","text":"4. Не меша́й мне, а не то я (просы́пать) просы́плю крупу́ на пол. (Lưu ý: Động từ ở đây là просы́пать - làm đổ (hoàn thành), không phải просыпа́ть - ngủ quên)."},{"t":"para","text":"Dịch: Đừng làm phiền mẹ/tôi, nếu không mẹ sẽ làm đổ ngũ cốc ra sàn mất."},{"t":"example","text":"Giải thích: Просы́пать (SW) → просы́плю (p → pl)."},{"t":"para","text":"5. Не волну́йся, ско́ро ему́ (надое́сть) надое́ст с тобо́й спо́рить.","b":1},{"t":"para","text":"Dịch: Đừng lo, sớm muộn gì nó cũng sẽ chán tranh cãi với cậu thôi."},{"t":"example","text":"Giải thích: Надоесть chia giống есть → ngôi thứ 3 số ít: надое́ст."},{"t":"para","text":"6. Посмотри́, как краси́во (цвести́) цвету́т я́блони!","b":1},{"t":"para","text":"Dịch: Nhìn kìa, những cây táo nở hoa đẹp làm sao!"},{"t":"example","text":"Giải thích: Цвести (NSW - hiện tại, số nhiều) → цвету́т (st → t)."},{"t":"para","text":"7. Когда́ де́душка (дрема́ть) дре́млет в кре́сле, я (хоте́ть) хочу́, что́бы ему́ не меша́ли.","b":1},{"t":"para","text":"Dịch: Khi ông thiu thiu ngủ trên ghế bành, tôi muốn mọi người đừng làm phiền ông."},{"t":"example","text":"Giải thích: Дремать → дре́млет (m → ml). Хотеть → хочу́ (t → ч)."},{"t":"para","text":"8. — Он никогда́ не (лгать) лжёт, и ты (оскорби́ть) оскорби́шь его́ таки́м предположе́нием. — Ду́маю, я никого́ не (оскорби́ть) оскорблю́, е́сли задам́ ему́ не́сколько вопро́сов.","b":1},{"t":"para","text":"Dịch: — Cậu ấy không bao giờ nói dối, và cậu sẽ xúc phạm cậu ấy với giả thiết như vậy đấy. — Tớ nghĩ tớ sẽ không xúc phạm ai nếu tớ hỏi vài câu."},{"t":"example","text":"Giải thích: Лгать → лжёт. Оскорбить → оскорби́шь (b → b), оскорблю́ (b → bl)."},{"t":"para","text":"9. Положе́ние серьёзное, нас (спасти́) спасёт то́лько чу́до.","b":1},{"t":"para","text":"Dịch: Tình hình nghiêm trọng lắm, chỉ có phép màu mới cứu được chúng ta."},{"t":"example","text":"Giải thích: Спасти (SW) → спасёт."},{"t":"para","text":"10. Не волну́йся, я (опусти́ть) опущу́ твоё письмо́ в почто́вый я́щик по доро́ге на рабо́ту.","b":1},{"t":"para","text":"Dịch: Đừng lo, tôi sẽ bỏ thư của bạn vào hòm thư trên đường đi làm."},{"t":"example","text":"Giải thích: Опустить (SW) → опущу́ (st → щ)."},{"t":"example","text":"11. Я (люби́ть) люблю́ отдыха́ть по́сле обе́да и, е́сли вы не возража́ете, (приле́чь) приля́гу ненадо́лго. (Sách gốc dùng прилечь, không phải привлечь hay từ khác)."},{"t":"para","text":"Dịch: Tôi thích nghỉ ngơi sau bữa trưa và, nếu các bạn không phản đối, tôi sẽ nằm nghỉ một lát."},{"t":"example","text":"Giải thích: Любить → люблю́. Прилечь (SW) → приля́гу (k/g/ch biến đổi: лечь - лягу)."},{"t":"para","text":"12. Я не (пропусти́ть) пропущу́ бо́льше ни одно́го заня́тия.","b":1},{"t":"para","text":"Dịch: Em sẽ không bỏ lỡ/nghỉ buổi học nào nữa đâu ạ."},{"t":"example","text":"Giải thích: Пропустить (SW) → пропущу́ (st → щ)."},{"t":"para","text":"13. Я не (копи́ть) коплю́ де́ньги, я их (тра́тить) тра́чу и (иска́ть) ищу́ возмо́жность зарабо́тать но́вые.","b":1},{"t":"para","text":"Dịch: Tôi không tích cóp tiền, tôi tiêu chúng và tìm cơ hội kiếm tiền mới."},{"t":"example","text":"Giải thích: Копить → коплю́. Тратить → тра́чу. Искать → ищу́."},{"t":"para","text":"14. Я не (надое́сть) надое́м тебе́ бы́стро.","b":1},{"t":"para","text":"Dịch: Em sẽ không làm anh chán nhanh đâu."},{"t":"example","text":"Giải thích: Надоесть chia như есть → надое́м."},{"t":"vocab","ru":"(Лови́ть) Ловлю́ тебя́ на сло́ве","vi":"ты обяза́тельно до́лжен прие́хать к нам за́втра ве́чером.","g":null},{"t":"para","text":"Dịch: Tớ bắt lấy lời cậu đấy (nhớ giữ lời): cậu nhất định phải đến chỗ tớ tối mai."},{"t":"example","text":"Giải thích: Ловить → ловлю́."},{"t":"para","text":"16. Ты меня́ подвёл, и я (отомсти́ть) отомщу́ тебе́ за э́то.","b":1},{"t":"para","text":"Dịch: Cậu đã làm tớ thất vọng/lỡ việc, và tớ sẽ trả thù cậu vì chuyện này."},{"t":"example","text":"Giải thích: Отомстить (SW) → отомщу́ (st → щ)."},{"t":"para","text":"17. За стено́й (шуме́ть) шумя́т, наве́рное, у них вечери́нка.","b":1},{"t":"para","text":"Dịch: Sau bức tường người ta đang làm ồn, chắc là họ có tiệc."},{"t":"example","text":"Giải thích: Шуметь → шумя́т."},{"t":"para","text":"18. Без твои́х сове́тов я, наве́рное, (пропа́сть) пропаду́.","b":1},{"t":"para","text":"Dịch: Không có lời khuyên của cậu chắc tớ tiêu tùng/mất phương hướng mất."},{"t":"example","text":"Giải thích: Пропасть → пропаду́."},{"t":"para","text":"19. Извини́, я (торопи́ться) тороплю́сь, опа́здываю на заня́тия.","b":1},{"t":"para","text":"Dịch: Xin lỗi, tớ đang vội, tớ muộn học rồi."},{"t":"example","text":"Giải thích: Торопиться → тороплю́сь."}]},{"id":"07-s009","type":"exercise","title":"BÀI TẬP 509 (Trang 260)","num":509,"blocks":[{"t":"instruction","text":"Yêu cầu: Tạo thể mệnh lệnh (Imperative) từ các động từ."},{"t":"para","text":"a)","b":1},{"t":"vocab","ru":"Пусти́ть","vi":"пусти́.","g":null},{"t":"vocab","ru":"Опусти́ть","vi":"опусти́.","g":null},{"t":"vocab","ru":"Пропусти́ть","vi":"пропусти́.","g":null},{"t":"vocab","ru":"Прости́ть","vi":"прости́.","g":null},{"t":"vocab","ru":"Навести́ть","vi":"навести́.","g":null},{"t":"vocab","ru":"Блесте́ть","vi":"блести́.","g":null},{"t":"vocab","ru":"Грусти́ть","vi":"грусти́.","g":null},{"t":"vocab","ru":"Мстить","vi":"мсти. (Nhưng thường dùng dạng phủ định не мсти).","g":null},{"t":"vocab","ru":"Свисте́ть","vi":"свисти́.","g":null},{"t":"vocab","ru":"Иска́ть","vi":"ищи́.","g":null},{"t":"vocab","ru":"Класть","vi":"клади́.","g":null},{"t":"para","text":"б)","b":1},{"t":"vocab","ru":"Люби́ть","vi":"люби́.","g":null},{"t":"vocab","ru":"Купи́ть","vi":"купи́.","g":null},{"t":"vocab","ru":"Копи́ть","vi":"копи́.","g":null},{"t":"vocab","ru":"Терпе́ть","vi":"терпи́.","g":null},{"t":"vocab","ru":"Лови́ть","vi":"лови́.","g":null},{"t":"vocab","ru":"Корми́ть","vi":"корми́.","g":null},{"t":"vocab","ru":"Оскорби́ть","vi":"оскорби́.","g":null},{"t":"vocab","ru":"Укрепи́ть","vi":"укрепи́.","g":null},{"t":"vocab","ru":"Шуме́ть","vi":"шуми́.","g":null},{"t":"vocab","ru":"Спать","vi":"спи.","g":null},{"t":"vocab","ru":"Пра́вить","vi":"правь. (Lưu ý: gốc прав-, trọng âm không ở đuôi → thêm ь).","g":null},{"t":"vocab","ru":"Гото́вить","vi":"гото́вь.","g":null},{"t":"vocab","ru":"Сы́пать","vi":"сыпь.","g":null},{"t":"vocab","ru":"Дрема́ть","vi":"дремли́.","g":null},{"t":"para","text":"в)","b":1},{"t":"vocab","ru":"Мести́","vi":"мети́.","g":null},{"t":"vocab","ru":"Цвести́","vi":"цвети́.","g":null},{"t":"vocab","ru":"Вести́","vi":"веди́.","g":null},{"t":"vocab","ru":"Брести́","vi":"бреди́.","g":null},{"t":"vocab","ru":"Нести́","vi":"неси́.","g":null},{"t":"vocab","ru":"Трясти́","vi":"тряси́.","g":null},{"t":"vocab","ru":"Спасти́","vi":"спаси́.","g":null},{"t":"vocab","ru":"Запасти́","vi":"запаси́.","g":null},{"t":"vocab","ru":"Везти́","vi":"вези́.","g":null},{"t":"vocab","ru":"Грести́","vi":"греби́.","g":null},{"t":"vocab","ru":"Упа́сть","vi":"упади́.","g":null},{"t":"vocab","ru":"Пропа́сть","vi":"пропади́.","g":null},{"t":"vocab","ru":"Ле́зть","vi":"лезь.","g":null},{"t":"vocab","ru":"Есть","vi":"ешь.","g":null},{"t":"vocab","ru":"Е́хать","vi":"поезжа́й(те) (Động từ đặc biệt, không dùng едь).","g":null}]},{"id":"07-s010","type":"exercise","title":"BÀI TẬP 510 (Trang 260)","num":510,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay thế các cấu trúc với động từ nguyên thể bằng động từ mệnh lệnh. Xác định câu nào là tục ngữ."},{"t":"para","text":"1. Е́сли не хо́чешь спать, попро́буй подрема́ть немно́го.","b":1},{"t":"para","text":"Viết lại: ..., подремли́ немно́го."},{"t":"para","text":"Dịch: Nếu không muốn ngủ, hãy thiu thiu/chợp mắt một chút đi."},{"t":"para","text":"2. Ты опя́ть не сде́лал дома́шнее зада́ние! — Не на́до сы́пать мне соль на ра́ны. (Thành ngữ/Tục ngữ)."},{"t":"para","text":"Viết lại: — Не сыпь мне соль на ра́ны."},{"t":"para","text":"Dịch: — Đừng xát muối vào vết thương của tôi nữa. (Đừng nhắc lại nỗi đau/lỗi lầm)."},{"t":"para","text":"3. Попро́буй приле́чь и закры́ть глаза́, мо́жет быть, тебе́ уда́стся усну́ть.","b":1},{"t":"para","text":"Viết lại: Приля́г и закро́й глаза́..."},{"t":"para","text":"Dịch: Hãy nằm xuống và nhắm mắt lại, biết đâu bạn sẽ ngủ được."},{"t":"para","text":"4. На́до опусти́ть жето́н в автома́т, и по́сле э́того мо́жно проходи́ть че́рез турнике́т.","b":1},{"t":"para","text":"Viết lại: Опусти́ жето́н в автома́т..."},{"t":"para","text":"Dịch: Hãy bỏ thẻ/xu vào máy..."},{"t":"para","text":"5. Ты до́лжен испра́вить оши́бки сам.","b":1},{"t":"para","text":"Viết lại: Испра́вь оши́бки сам."},{"t":"para","text":"Dịch: Hãy tự sửa lỗi đi."},{"t":"para","text":"6. Не на́до шуме́ть, ребёнок усну́л.","b":1},{"t":"para","text":"Viết lại: Не шуми́те, ребёнок усну́л."},{"t":"para","text":"Dịch: Đừng làm ồn, đứa bé đã ngủ rồi."},{"t":"para","text":"7. Где он? Ещё мину́ту наза́д был здесь. — Был да ушёл, ле́гче иска́ть ве́тра в по́ле. (Tục ngữ)."},{"t":"para","text":"Viết lại: ..., ищи́ ве́тра в по́ле."},{"t":"para","text":"Dịch: — Có mà đi tìm gió vào nhà trống / Mò kim đáy bể. (Ý nói tìm vô ích)."},{"t":"vocab","ru":"Ты до́лжен бежа́ть на рабо́ту. (Phần sau bị cắt trong sách","vi":"а то опоздаешь).","g":null},{"t":"para","text":"Viết lại: Беги́ на рабо́ту."},{"t":"para","text":"Dịch: Chạy đi làm đi."},{"t":"para","text":"9. Не на́до лгать мне, пожа́луйста.","b":1},{"t":"para","text":"Viết lại: Не лги мне, пожа́луйста."},{"t":"para","text":"Dịch: Làm ơn đừng nói dối tôi."},{"t":"vocab","ru":"Постара́йся прости́ть меня́","vi":"я никогда́ так не бу́ду де́лать.","g":null},{"t":"para","text":"Viết lại: Прости́ меня́..."},{"t":"para","text":"Dịch: Hãy tha thứ cho tôi..."},{"t":"para","text":"11. Начина́й грести́ к бе́регу, мы уже́ доста́точно поката́лись на ло́дке.","b":1},{"t":"para","text":"Viết lại: Греби́ к бе́регу..."},{"t":"para","text":"Dịch: Hãy chèo vào bờ đi..."},{"t":"para","text":"12. Не на́до грусти́ть, всё бу́дет хорошо́.","b":1},{"t":"para","text":"Viết lại: Не грусти́, всё бу́дет хорошо́."},{"t":"para","text":"Dịch: Đừng buồn, mọi chuyện sẽ ổn thôi."},{"t":"para","text":"13. Вы должны́ полюби́ть нас чёрненькими, а бе́ленькими нас вся́кий полю́бит. (Tục ngữ/Câu nói nổi tiếng - Gogol)."},{"t":"para","text":"Viết lại: Полюби́те нас чёрненькими..."},{"t":"para","text":"Dịch: Hãy yêu chúng tôi khi chúng tôi còn xấu xí/đen đúa (khó khăn), chứ khi trắng trẻo (tốt đẹp) thì ai chẳng yêu."},{"t":"para","text":"14. Тебе́ сто́ит напра́вить свою́ эне́ргию на друго́е де́ло.","b":1},{"t":"para","text":"Viết lại: Напра́вь свою́ эне́ргию..."},{"t":"para","text":"Dịch: Hãy hướng năng lượng của cậu vào việc khác đi."},{"t":"para","text":"15. Постара́йся есть быстре́е, мы опа́здываем.","b":1},{"t":"para","text":"Viết lại: Ешь быстре́е..."},{"t":"para","text":"Dịch: Ăn nhanh lên, chúng ta muộn rồi."},{"t":"vocab","ru":"Не на́до свисте́ть, ты не в лесу́. (Tục ngữ","vi":"Не свисти - денег не будет).","g":null},{"t":"para","text":"Viết lại: Не свисти́, ты не в лесу́."},{"t":"para","text":"Dịch: Đừng huýt sáo, cậu có phải đang ở trong rừng đâu."},{"t":"para","text":"17. Ты до́лжен немно́го потерпе́ть, сейча́с бу́дет бо́льно.","b":1},{"t":"para","text":"Viết lại: Потерпи́ немно́го..."},{"t":"para","text":"Dịch: Hãy chịu đựng/cố nhịn một chút, bây giờ sẽ đau đấy (lời bác sĩ)."},{"t":"para","text":"18. Постара́йся класть ве́щи на своё ме́сто.","b":1},{"t":"para","text":"Viết lại: Клади́ ве́щи на своё ме́сто."},{"t":"para","text":"Dịch: Hãy đặt/cất đồ đạc vào đúng chỗ của nó."},{"t":"para","text":"19. Тебе́ лу́чше сесть за стол со все́ми.","b":1},{"t":"para","text":"Viết lại: Сядь за стол со все́ми."},{"t":"para","text":"Dịch: Hãy ngồi vào bàn cùng mọi người đi."}]},{"id":"07-s011","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 261 - Trước bài 511)","num":null,"blocks":[{"t":"para","text":"Động từ có sự biến đổi nguyên âm ở gốc (Глаголы с чередованием гласных в корне): Đây là nhóm động từ khi chia ở thì hiện tại hoặc tương lai đơn sẽ thay đổi nguyên âm trong gốc từ so với dạng nguyên thể (Infinitive). Các kiểu biến đổi phổ biến:"},{"t":"vocab","ru":"а (я) // н (м)","vi":"встать – вста́ну (đứng dậy), взять – возьму́ (lấy).","g":null},{"t":"vocab","ru":"и // ь","vi":"пить – пью (uống).","g":null},{"t":"vocab","ru":"ы // о","vi":"мыть – мо́ю (rửa).","g":null},{"t":"vocab","ru":"о // е","vi":"моло́ть – мелю́ (xay).","g":null},{"t":"vocab","ru":"ере // р","vi":"умере́ть – умру́ (chết).","g":null}]},{"id":"07-s012","type":"exercise","title":"BÀI TẬP 511 (Trang 261)","num":511,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Gọi tên (xác định) động từ nguyên thể (инфинитив) của các động từ được in nghiêng/đậm."},{"t":"para","text":"1. Я бу́ду на вокза́ле во вто́рник в 7 часо́в утра́; 2. В э́тот день мы вста́нем пора́ньше, что́бы не опозда́ть; 4. От него́ ничего́ не скро́ешь, он всё всегда́ узна́ет пе́рвым; 5. Не беспоко́йся, они́ при́мут все необходи́мые ме́ры; 6. Когда́ бу́дешь уходи́ть, запри́, пожа́луйста, дверь; 7. Мы не, мы про́сто напи́шем письмо́ по́зже; 9. По утра́м, когда́ он ме́лет ко́фе, звук его́ кофемо́лки разно́сится по всему́ до́му; 10. Заче́м ты мнёшь пальто́ и шля́пу, а пото́м присоедини́шься к вам; 12. Осторо́жно, ты льёшь во́ду на пол; 13. Что вы возьмёте с собо́й в о́тпуск? 14. Мно́гим лю́дям ка́жется, что они́ бу́дут жить ве́чно и никогда́ не умру́т; 15. В э́том обме́нном пу́нкте беру́т комиссио́нный сбор; 16. Ду́маю, в газе́тах подни́мут шум по э́тому по́воду; 17. Заче́м ты так го́нишь (маши́ну), ра́зве мы торо́пимся? 18. Мя́гко сте́лет, да жёстко спать (пословица); 19. В па́рке жгут прошло́годние ли́стья; 20. Чего́ ты бои́шься? Не отниму́ я у тебя́ твой кусо́к то́рта; 21. Она́ пи́шет что́-то на стекле́ и бы́стро стира́ет напи́санное ладо́нью; 22. Таки́е глубо́кие я́мы обы́чно ро́ют для хране́ния карто́феля; 23. Дай обниму́ тебя́, мы не ви́делись уже́ почти́ полго́да; 24. Она́ великоле́пная хозя́йка, прекра́сно вя́жет и шьёт.","b":1},{"t":"para","text":"Giải thích và đáp án:","b":1},{"t":"vocab","ru":"Вста́нем (chúng tôi sẽ dậy) → Nguyên thể","vi":"Встать.","g":null},{"t":"vocab","ru":"Опозда́ть (đến muộn) → Nguyên thể","vi":"Опозда́ть.","g":null},{"t":"vocab","ru":"Скро́ешь (bạn sẽ giấu) → Nguyên thể","vi":"Скрыть.","g":null},{"t":"vocab","ru":"Узна́ет (anh ấy sẽ biết) → Nguyên thể","vi":"Узна́ть.","g":null},{"t":"vocab","ru":"При́мут (họ sẽ thực hiện/tiếp nhận) → Nguyên thể","vi":"Приня́ть.","g":null},{"t":"vocab","ru":"Запри́ (hãy khóa lại) → Nguyên thể","vi":"Запере́ть.","g":null},{"t":"vocab","ru":"Напи́шем (chúng tôi sẽ viết) → Nguyên thể","vi":"Написа́ть.","g":null},{"t":"para","text":"(Trong câu gốc bị nhảy số hoặc in thiếu, ở đây là câu 4 trong sách): Ме́лет (anh ấy xay) → Nguyên thể: Моло́ть."},{"t":"vocab","ru":"Мнёшь (bạn làm nhàu) → Nguyên thể","vi":"Мять.","g":null},{"t":"vocab","ru":"Присоедини́шься (bạn sẽ tham gia) → Nguyên thể","vi":"Присоедини́ться. (Lưu ý: trong sách câu này có thể bị in lỗi cú pháp, đại ý là \"sau đó bạn sẽ tham gia\").","g":null},{"t":"vocab","ru":"Льёшь (bạn đang đổ/rót) → Nguyên thể","vi":"Лить.","g":null},{"t":"vocab","ru":"Возьмёте (các bạn sẽ cầm/lấy) → Nguyên thể","vi":"Взять.","g":null},{"t":"vocab","ru":"Умру́т (họ sẽ chết) → Nguyên thể","vi":"Умере́ть.","g":null},{"t":"vocab","ru":"Беру́т (người ta lấy/thu) → Nguyên thể","vi":"Брать.","g":null},{"t":"vocab","ru":"Подни́мут (người ta sẽ làm dấy lên) → Nguyên thể","vi":"Подня́ть.","g":null},{"t":"vocab","ru":"Го́нишь (bạn lái nhanh/lùa) → Nguyên thể","vi":"Гнать.","g":null},{"t":"vocab","ru":"Торо́пимся (chúng ta vội) → Nguyên thể","vi":"Торопи́ться.","g":null},{"t":"vocab","ru":"Сте́лет (trải) → Nguyên thể","vi":"Стели́ть. (Tục ngữ: Trải thì êm nhưng ngủ thì cứng - Nói ngọt lọt đến xương).","g":null},{"t":"vocab","ru":"Жгут (người ta đốt) → Nguyên thể","vi":"Жечь.","g":null},{"t":"vocab","ru":"Отниму́ (tôi sẽ lấy mất/cướp đi) → Nguyên thể","vi":"Отня́ть.","g":null},{"t":"vocab","ru":"Пи́шет (cô ấy viết) → Nguyên thể","vi":"Писа́ть. (Lưu ý: стирает → стирать).","g":null},{"t":"vocab","ru":"Ро́ют (người ta đào) → Nguyên thể","vi":"Рыть.","g":null},{"t":"vocab","ru":"Обниму́ (tôi sẽ ôm) → Nguyên thể","vi":"Обня́ть.","g":null},{"t":"para","text":"Вя́жет (đan) → Вяза́ть; Шьёт (may) → Шить."}]},{"id":"07-s013","type":"exercise","title":"BÀI TẬP 512 (Trang 261-262)","num":512,"blocks":[{"t":"instruction","text":"Yêu cầu: Chia động từ theo mẫu. Xác định sự biến đổi nguyên âm và phụ âm trong gốc động từ."},{"t":"subhead","text":"a) Nhóm động từ một âm tiết có nguyên âm И (biến đổi И → ЬJ):","b":1},{"t":"vocab","ru":"Лить (rót/đổ)","vi":"лью, льёшь, льёт, льём, льёте, льют. (Mệnh lệnh: лей).","g":null},{"t":"vocab","ru":"Пить (uống)","vi":"пью, пьёшь, пьёт, пьём, пьёте, пьют.","g":null},{"t":"vocab","ru":"Шить (may)","vi":"шью, шьёшь, шьёт, шьём, шьёте, шьют.","g":null},{"t":"vocab","ru":"Витъ (uốn/bện)","vi":"вью, вьёшь...","g":null},{"t":"vocab","ru":"Бить (đánh)","vi":"бью, бьёшь...","g":null},{"t":"subhead","text":"б) Nhóm động từ một âm tiết có nguyên âm Ы (biến đổi Ы → О):","b":1},{"t":"vocab","ru":"Мыть (rửa)","vi":"мо́ю, мо́ешь, мо́ет, мо́ем, мо́ете, мо́ют.","g":null},{"t":"vocab","ru":"Крыть (lợp/che)","vi":"кро́ю, кро́ешь...","g":null},{"t":"vocab","ru":"Скрыть (giấu)","vi":"скро́ю, скро́ешь...","g":null},{"t":"vocab","ru":"Рыть (đào)","vi":"ро́ю, ро́ешь...","g":null},{"t":"vocab","ru":"Ныть (kêu ca/nhức)","vi":"но́ю, но́ешь...","g":null},{"t":"vocab","ru":"Быть (thì/là/ở - tương lai)","vi":"бу́ду, бу́дешь, бу́дет, бу́дем, бу́дете, бу́дут. (Lưu ý: быть biến đổi đặc biệt ы → у).","g":null},{"t":"subhead","text":"в) Nhóm động từ kết thúc bằng -НЯТЬ (biến đổi Я → ИМ/ИН):","b":1},{"t":"vocab","ru":"Обня́ть (ôm)","vi":"обниму́, обни́мешь, обни́мет, обни́мем, обни́мете, обни́мут.","g":null},{"t":"vocab","ru":"Подня́ть (nâng lên)","vi":"подниму́, подни́мешь...","g":null},{"t":"vocab","ru":"Снять (tháo/cởi/thuê/chụp)","vi":"сниму́, сни́мешь...","g":null},{"t":"vocab","ru":"Приня́ть (tiếp nhận)","vi":"приму́, при́мешь... (Lưu ý trọng âm: при́мешь, nhưng приму́).","g":null},{"t":"subhead","text":"г) Động từ đặc biệt:","b":1},{"t":"vocab","ru":"Моло́ть (xay)","vi":"мелю́, ме́лешь, ме́лет, ме́лем, ме́лете, ме́лют. (Biến đổi оло → е).","g":null},{"t":"subhead","text":"д) Nhóm động từ biến đổi phụ âm và nguyên âm:","b":1},{"t":"vocab","ru":"Гнать (đuổi/lùa/lái nhanh)","vi":"гоню́, го́нишь, го́нит, го́ним, го́ните, го́нят. (Quy tắc ngoại lệ, chia như nhóm II).","g":null},{"t":"vocab","ru":"Брать (lấy)","vi":"беру́, берёшь, берёт, берём, берёте, беру́т. (Thêm nguyên âm đệm е).","g":null},{"t":"vocab","ru":"Взять (lấy - hoàn thành)","vi":"возьму́, возьмёшь...","g":null},{"t":"vocab","ru":"Встать (đứng dậy)","vi":"вста́ну, вста́нешь...","g":null},{"t":"vocab","ru":"Стлать (trải)","vi":"стелю́, сте́лешь... (Hoặc сте́лю - biến đổi а → е).","g":null},{"t":"vocab","ru":"Звать (gọi)","vi":"зову́, зовёшь... (Thêm nguyên âm о).","g":null},{"t":"subhead","text":"е) Nhóm động từ có đuôi -чь hoặc biến đổi -ере-:","b":1},{"t":"vocab","ru":"Жечь (đốt)","vi":"жгу, жжёшь, жжёт, жжём, жжёте, жгут. (Gốc г, biến đổi г → ж ở các ngôi trừ я và они).","g":null},{"t":"vocab","ru":"Тере́ть (cọ xát)","vi":"тру, трёшь, трёт, трём, трёте, трут. (Rút gọn ере → р).","g":null},{"t":"vocab","ru":"Запере́ть (khóa)","vi":"запру́, запрёшь...","g":null},{"t":"vocab","ru":"Стере́ть (xóa)","vi":"сотру́, сотрёшь...","g":null},{"t":"vocab","ru":"Умере́ть (chết)","vi":"умру́, умрёшь...","g":null},{"t":"vocab","ru":"Проче́сть (đọc)","vi":"прочту́, прочтёшь...","g":null},{"t":"vocab","ru":"Вы́честь (trừ)","vi":"вы́чту, вы́чтешь...","g":null}]},{"id":"07-s014","type":"exercise","title":"BÀI TẬP 513 (Trang 262)","num":513,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, chia động từ ở thì hiện tại (động từ chưa hoàn thành - НСВ) hoặc tương lai đơn (động từ hoàn thành - СВ)."},{"t":"para","text":"1. Сейча́с я тебе́ ничего́ не могу́ сказа́ть, я (приня́ть) приму́ реше́ние по́зже.","b":1},{"t":"para","text":"Dịch: Bây giờ tôi không thể nói gì với bạn cả, tôi sẽ đưa ra quyết định sau."},{"t":"example","text":"Giải thích: Приня́ть (СВ) → tương lai: приму́."},{"t":"para","text":"2. Наде́юсь, у тебя́ есть ключи́, а я уйду́ и (запере́ть) запру́ дверь.","b":1},{"t":"para","text":"Dịch: Hy vọng cậu có chìa khóa, còn tớ sẽ đi và khóa cửa lại."},{"t":"example","text":"Giải thích: Запере́ть (СВ) → запру́."},{"t":"para","text":"3. Дождь (лить) льёт как из ведра́.","b":1},{"t":"para","text":"Dịch: Mưa đang trút như trút nước (xối xả)."},{"t":"example","text":"Giải thích: Лить (НСВ) → hiện tại: льёт."},{"t":"para","text":"4. На выпускно́й ве́чер ма́ма (сшить) сошьёт мне но́вое пла́тье; я (взять) возьму́ сала́т, омле́т и ча́шку ко́фе.","b":1},{"t":"para","text":"Dịch: Vào buổi dạ hội tốt nghiệp mẹ sẽ may cho tôi chiếc váy mới; tôi sẽ lấy/gọi món salad, trứng ốp lết và một tách cà phê."},{"t":"example","text":"Giải thích: Сшить → сошьёт. Взять → возьму́."},{"t":"para","text":"5. Ты (постели́ть) посте́лешь ска́терть, (принести́) принесёшь прибо́ры, а твоя́ сестра́ (позва́ть) позовёт всех к столу́.","b":1},{"t":"para","text":"Dịch: Con hãy trải khăn bàn, mang bát đĩa ra, còn em gái con sẽ gọi mọi người vào bàn ăn. (Dùng tương lai để chỉ mệnh lệnh nhẹ nhàng hoặc phân công)."},{"t":"example","text":"Giải thích: Постели́ть → посте́лешь. Принести́ → принесёшь. Позва́ть → позовёт."},{"t":"para","text":"6. Я (стере́ть) сотру́ э́то воспомина́ние из свое́й па́мяти.","b":1},{"t":"para","text":"Dịch: Tôi sẽ xóa ký ức này khỏi trí nhớ của mình."},{"t":"example","text":"Giải thích: Стере́ть → сотру́."},{"t":"para","text":"7. Они́ (проче́сть) прочту́т э́тот абза́ц по́зже.","b":1},{"t":"para","text":"Dịch: Họ sẽ đọc đoạn văn này sau."},{"t":"example","text":"Giải thích: Проче́сть → прочту́т."},{"t":"para","text":"8. Я уве́рен, ты (приня́ть) при́мешь пра́вильное реше́ние.","b":1},{"t":"para","text":"Dịch: Tôi tin là bạn sẽ đưa ra quyết định đúng đắn."},{"t":"example","text":"Giải thích: Приня́ть → при́мешь."},{"t":"para","text":"9. Выполне́ние в срок э́того зака́за (подня́ть) подни́мет прести́ж на́шей фи́рмы.","b":1},{"t":"para","text":"Dịch: Việc hoàn thành đơn hàng này đúng hạn sẽ nâng cao uy tín của công ty chúng ta."},{"t":"example","text":"Giải thích: Подня́ть → подни́мет."},{"t":"para","text":"10. Никто́ не (скрыть) скро́ет от меня́ пра́вду, я всё равно́ всё узна́ю.","b":1},{"t":"para","text":"Dịch: Không ai sẽ giấu được sự thật với tôi đâu, đằng nào tôi cũng biết hết."},{"t":"example","text":"Giải thích: Скрыть → скро́ет."},{"t":"para","text":"11. Я звони́л Евге́нию Алекса́ндровичу, он (приня́ть) при́мет тебя́ за́втра в 12 часо́в.","b":1},{"t":"para","text":"Dịch: Tớ đã gọi cho Evgeny Alexandrovich, ông ấy sẽ tiếp cậu vào 12 giờ ngày mai."},{"t":"example","text":"Giải thích: Приня́ть → при́мет."},{"t":"para","text":"12. Кофемо́лка рабо́тает норма́льно, (моло́ть) ме́лет ко́фе испра́вно, попро́буй сам.","b":1},{"t":"para","text":"Dịch: Máy xay cà phê hoạt động bình thường, nó xay cà phê tốt lắm, thử mà xem."},{"t":"example","text":"Giải thích: Моло́ть → ме́лет."},{"t":"para","text":"13. Я (нама́зать) нама́жу твою́ ра́ну йо́дом, потерпи́ немно́жко.","b":1},{"t":"para","text":"Dịch: Mẹ sẽ bôi i-ốt vào vết thương cho con, chịu đau một tí nhé."},{"t":"example","text":"Giải thích: Нама́зать → нама́жу (z → zh)."},{"t":"para","text":"14. Ой, о́чень (жечь) жжёт!","b":1},{"t":"para","text":"Dịch: Ôi, nó làm rát/bỏng (da) quá!"},{"t":"example","text":"Giải thích: Жечь → жжёт."},{"t":"para","text":"15. На пе́рвые ме́сяцы они́ (снять) сни́мут кварти́ру, а пото́м (подыска́ть) поды́щут постоя́нное жильё.","b":1},{"t":"para","text":"Dịch: Những tháng đầu họ sẽ thuê căn hộ, rồi sau đó sẽ tìm chỗ ở cố định."},{"t":"example","text":"Giải thích: Снять (thuê) → сни́мут. Подыска́ть → поды́щут."},{"t":"para","text":"16. Е́сли когда́-нибудь (быть) бу́дете в на́шем го́роде, заходи́те, мы (быть) бу́дем ра́ды вас ви́деть.","b":1},{"t":"para","text":"Dịch: Nếu khi nào đó các bạn có mặt/đến thành phố chúng tôi, hãy ghé chơi, chúng tôi sẽ rất vui được gặp các bạn."},{"t":"example","text":"Giải thích: Быть → бу́дете, бу́дем."},{"t":"vocab","ru":"Не на́до бы́ло ему́ есть солёное","vi":"тепе́рь он весь день (пить) пьёт холо́дную во́ду.","g":null},{"t":"para","text":"Dịch: Lẽ ra nó không nên ăn đồ mặn: bây giờ nó uống nước lạnh cả ngày."},{"t":"example","text":"Giải thích: Пить → пьёт."},{"t":"vocab","ru":"Ты сли́шком мно́го (брать) берёшь на себя́","vi":"одному́ тебе́ с э́той рабо́той не спра́виться.","g":null},{"t":"para","text":"Dịch: Cậu ôm đồm/nhận quá nhiều việc vào mình đấy: một mình cậu không xong việc này đâu."},{"t":"example","text":"Giải thích: Брать → берёшь."}]},{"id":"07-s015","type":"exercise","title":"BÀI TẬP 514 (Trang 262)","num":514,"blocks":[{"t":"instruction","text":"Yêu cầu: Tạo thể mệnh lệnh (Imperative) từ các động từ."},{"t":"subhead","text":"a) Nhóm 1 âm tiết (nguyên âm и):","b":1},{"t":"vocab","ru":"Лить (rót)","vi":"лей.","g":null},{"t":"vocab","ru":"Пить (uống)","vi":"пей.","g":null},{"t":"vocab","ru":"Бить (đánh)","vi":"бей.","g":null},{"t":"vocab","ru":"Шить (may)","vi":"шей.","g":null},{"t":"vocab","ru":"Сшить (may xong)","vi":"сшей.","g":null},{"t":"subhead","text":"б) Nhóm 1 âm tiết (nguyên âm ы):","b":1},{"t":"vocab","ru":"Мыть (rửa)","vi":"мой.","g":null},{"t":"vocab","ru":"Крыть (lợp)","vi":"крой.","g":null},{"t":"vocab","ru":"Скрыть (giấu)","vi":"скрой.","g":null},{"t":"vocab","ru":"Рыть (đào)","vi":"рой.","g":null},{"t":"vocab","ru":"Ныть (than vãn)","vi":"ной. (Có thể có dạng phủ định не ной).","g":null},{"t":"vocab","ru":"Быть (hãy là/hãy có mặt)","vi":"будь.","g":null},{"t":"subhead","text":"в) Nhóm -нять:","b":1},{"t":"vocab","ru":"Обня́ть (ôm)","vi":"обними́.","g":null},{"t":"vocab","ru":"Подня́ть (nâng)","vi":"подними́.","g":null},{"t":"vocab","ru":"Снять (cởi/thuê)","vi":"сними́.","g":null},{"t":"vocab","ru":"Приня́ть (nhận)","vi":"прими́.","g":null},{"t":"subhead","text":"г) Đặc biệt:","b":1},{"t":"vocab","ru":"Моло́ть (xay)","vi":"мели́.","g":null},{"t":"subhead","text":"д) Nhóm khác:","b":1},{"t":"vocab","ru":"Гнать (đuổi/lái)","vi":"гони́.","g":null},{"t":"vocab","ru":"Брать (cầm/lấy)","vi":"бери́.","g":null},{"t":"vocab","ru":"Взять (cầm/lấy - SW)","vi":"возьми́.","g":null},{"t":"vocab","ru":"Встать (đứng dậy)","vi":"встань.","g":null},{"t":"vocab","ru":"Стлать (trải)","vi":"стели́.","g":null},{"t":"vocab","ru":"Звать (gọi)","vi":"зови́.","g":null},{"t":"subhead","text":"е) Nhóm -чь / -ере-:","b":1},{"t":"vocab","ru":"Жечь (đốt)","vi":"жги.","g":null},{"t":"vocab","ru":"Тере́ть (cọ)","vi":"три.","g":null},{"t":"vocab","ru":"Запере́ть (khóa)","vi":"запри́.","g":null},{"t":"vocab","ru":"Стере́ть (xóa)","vi":"сотри́.","g":null},{"t":"vocab","ru":"Проче́сть (đọc)","vi":"прочти́.","g":null},{"t":"vocab","ru":"Вы́честь (trừ)","vi":"вы́чти.","g":null}]},{"id":"07-s016","type":"exercise","title":"BÀI TẬP 515 (Trang 263)","num":515,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay thế các cấu trúc với động từ nguyên thể bằng động từ ở thể mệnh lệnh. Xác định câu nào là tục ngữ/thành ngữ."},{"t":"note","text":"Lưu ý khung ngữ pháp (Trang 263):","b":1},{"t":"example","text":"Hình thức mệnh lệnh của động từ ngôi thứ 3 được tạo thành bằng cách dùng tiểu từ пусть (hãy để cho/cầu cho). Ví dụ: Пусть он придёт (Hãy để anh ấy đến / Bảo anh ấy đến)."},{"t":"para","text":"1. Не на́до рыть друго́му я́му, сам в неё попадёшь. (Tục ngữ)."},{"t":"para","text":"Viết lại: Не ро́й друго́му я́му, сам в неё попадёшь."},{"t":"para","text":"Dịch: Đừng đào hố hại người, (kẻo) chính mình lại rơi xuống đấy. (Gậy ông đập lưng ông)."},{"t":"para","text":"2. Ты до́лжен позва́ть к телефо́ну Андре́я Ива́новича.","b":1},{"t":"para","text":"Viết lại: Позови́ к телефо́ну Андре́я Ива́новича."},{"t":"para","text":"Dịch: Hãy gọi Andrey Ivanovich ra nghe điện thoại."},{"t":"para","text":"3. По́сле того́ как суп закипи́т, на́до накры́ть кастрю́лю кры́шкой.","b":1},{"t":"para","text":"Viết lại: ..., накро́й кастрю́лю кры́шкой."},{"t":"para","text":"Dịch: Sau khi súp sôi, hãy đậy nắp nồi lại."},{"t":"para","text":"4. Тебе́ сто́ит брать приме́р со своего́ бра́та, он всегда́ следи́т за свое́й оде́ждой.","b":1},{"t":"para","text":"Viết lại: Бери́ приме́р со своего́ бра́та..."},{"t":"para","text":"Dịch: Hãy noi/lấy gương anh trai cậu đi, anh ấy luôn giữ gìn quần áo."},{"t":"para","text":"5. Э́ту су́мму лу́чше вы́честь из моего́ жа́лованья.","b":1},{"t":"para","text":"Viết lại: Вы́чти (Вычтите) э́ту су́мму из моего́ жа́лованья."},{"t":"para","text":"Dịch: Hãy trừ khoản này vào lương của tôi."},{"t":"para","text":"6. Поче́му́ ты спишь на дива́не, тебе́ лу́чше постели́ть бельё и лечь на крова́ть.","b":1},{"t":"para","text":"Viết lại: ..., постели́ бельё и ляг на крова́ть."},{"t":"example","text":"Dịch: Sao cậu ngủ trên ghế sofa thế, hãy trải ga ra và nằm lên giường đi. (Chú ý: лечь → mệnh lệnh ляг)."},{"t":"para","text":"7. Не на́до лить слёзы, тепе́рь не помо́жешь; мо́жно проли́ть всё молоко́. (Câu gốc trong sách có vẻ ghép 2 ý: \"Đừng khóc\" và \"Có thể làm đổ sữa\")."},{"t":"example","text":"Ý 1: Не ле́й слёзы... (Đừng khóc lóc nữa...)."},{"t":"example","text":"Ý 2: (Cảnh báo): Не проле́й молоко́. (Đừng làm đổ sữa). Hoặc nếu là câu tường thuật можно пролить thì chuyển thành mệnh lệnh: Смотри, не пролей (Coi chừng đừng làm đổ). Ngữ cảnh bài tập thường là: Не ле́й слёзы (đừng khóc)."},{"t":"example","text":"8. Пусть кто́-нибудь сотрёт с доски́.*"},{"t":"example","text":"Viết lại: (Giữ nguyên cấu trúc với Пусть vì đây là mệnh lệnh ngôi thứ 3, hoặc chuyển sang ngôi thứ 2 nếu muốn ra lệnh trực tiếp)."},{"t":"example","text":"Nếu chuyển sang mệnh lệnh ngôi 2: Сотри́ с доски́. (Em hãy xóa bảng đi)."},{"t":"example","text":"Giải thích: Sách hướng dẫn dùng Пусть cho ngôi thứ 3 (\"Ai đó hãy xóa bảng\")."},{"t":"para","text":"9. Не на́до гнать лошаде́й, мы мо́жем переверну́ться.","b":1},{"t":"para","text":"Viết lại: Не гони́ лошаде́й..."},{"t":"example","text":"Dịch: Đừng thúc ngựa chạy nhanh quá, chúng ta có thể bị lật xe đấy. (Thành ngữ: Не гони лошадей - Đừng vội vàng/hấp tấp)."},{"t":"para","text":"10. Мо́жет быть, ты э́то сде́лал наро́чно? — Не на́до моло́ть чепуху́.","b":1},{"t":"para","text":"Viết lại: — Не мели́ чепуху́."},{"t":"para","text":"Dịch: Có khi cậu cố tình làm thế? — Đừng có nói nhảm/nói bậy."},{"t":"para","text":"11. Тебе́ лу́чше самому́ проче́сть э́то письмо́.","b":1},{"t":"para","text":"Viết lại: Прочти́ сам э́то письмо́."},{"t":"para","text":"Dịch: Cậu hãy tự đọc lá thư này đi."},{"t":"para","text":"12. Тебе́ придётся взять его́ с собо́й.","b":1},{"t":"para","text":"Viết lại: Возьми́ его́ с собо́й."},{"t":"para","text":"Dịch: Hãy mang/cầm nó theo đi."},{"t":"para","text":"13. Тебе́ лу́чше приня́ть всё случи́вшееся как до́лжное и продолжа́ть рабо́тать над свое́й те́мой.","b":1},{"t":"para","text":"Viết lại: Прими́ всё случи́вшееся как до́лжное..."},{"t":"para","text":"Dịch: Hãy chấp nhận mọi chuyện đã xảy ra như một lẽ tất yếu và tiếp tục làm việc..."},{"t":"example","text":"14. Не на́до быть та́к не ма́ленький. (Sách in так не маленький? Có lẽ ý là так как маленький hoặc таким маленьким)."},{"t":"example","text":"Giả định câu đúng: Не надо быть таким маленьким / Не будь маленьким."},{"t":"para","text":"Viết lại: Не будь ма́леньким / Не будь как ма́ленький."},{"t":"para","text":"Dịch: Đừng có (cư xử) như trẻ con thế."},{"t":"para","text":"15. Я жела́ю вам быть здоро́вым и счастли́вым.","b":1},{"t":"para","text":"Viết lại: Будь здоро́в и сча́стлив (số ít) / Бу́дьте здоро́вы и сча́стливы (số nhiều)."},{"t":"para","text":"Dịch: Chúc/Hãy mạnh khỏe và hạnh phúc."},{"t":"para","text":"16. Ты до́лжен заже́чь газ и поста́вить на ого́нь ча́йник.","b":1},{"t":"para","text":"Viết lại: Зажги́ газ и поста́вь..."},{"t":"para","text":"Dịch: Hãy bật bếp ga và đặt ấm nước lên."},{"t":"para","text":"17. Тебе́ лу́чше не спо́рить со мной.","b":1},{"t":"para","text":"Viết lại: Не спорь со мной."},{"t":"para","text":"Dịch: Tốt nhất là đừng tranh cãi với tôi."}]},{"id":"07-s017","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 263-264)","num":null,"blocks":[{"t":"para","text":"Lý thuyết về cấu tạo thì quá khứ (Hình thành từ động từ nguyên thể đặc biệt):","b":1},{"t":"para","text":"1. Quy tắc chung:","b":1},{"t":"vocab","ru":"Đối với các động từ nguyên thể kết thúc bằng -чь (ví dụ","vi":"печь) và một số động từ kết thúc bằng -сти (ví dụ: нести), thì quá khứ được hình thành từ thân từ (gốc động từ) kết thúc bằng phụ âm.","g":null},{"t":"para","text":"Giống cái, giống trung và số nhiều: Thêm hậu tố -л- vào sau gốc phụ âm."},{"t":"example","text":"Ví dụ: пек-ла́, пек-ло́, пек-ли́."},{"t":"para","text":"Giống đực: Hậu tố -л- thường bị lược bỏ nếu thân từ kết thúc bằng phụ âm (để dễ phát âm)."},{"t":"example","text":"Ví dụ: печь (gốc пек-) → пёк (không có -л)."},{"t":"example","text":"Ví dụ: нести (gốc нес-) → нёс."},{"t":"subhead","text":"2. Động từ kết thúc bằng -ереть (như умере́ть - chết, тере́ть - cọ xát):","b":1},{"t":"para","text":"Ở thì quá khứ giống đực, hậu tố -е- trong gốc từ và hậu tố -л đều biến mất."},{"t":"example","text":"Умере́ть → у́мер (Giống đực)."},{"t":"subhead","text":"Các giống khác vẫn giữ -ер- và thêm -л-:"},{"t":"example","text":"Умерла́ (Cái), у́мерло (Trung), у́мерли (Nhiều)."}]},{"id":"07-s018","type":"exercise","title":"BÀI TẬP 516 (Trang 263)","num":516,"blocks":[{"t":"instruction","text":"Yêu cầu: Từ các động từ cho trước, hãy hình thành các dạng của thì quá khứ (Giống đực, cái, trung, và số nhiều)."},{"t":"subhead","text":"a) Nhóm kết thúc bằng -чь (Gốc từ biến đổi thành k hoặc g):","b":1},{"t":"vocab","ru":"Печь (nướng)","vi":"пёк, пекла́, пекло́, пекли́.","g":null},{"t":"vocab","ru":"Течь (chảy)","vi":"тёк, текла́, текло́, текли́.","g":null},{"t":"vocab","ru":"Увле́чь (lôi cuốn)","vi":"увлёк, увлекла́, увлекло́, увлекли́.","g":null},{"t":"vocab","ru":"Обре́чь (kết án, đày đọa)","vi":"обрёк, обрекла́, обрекло́, обрекли́.","g":null},{"t":"vocab","ru":"Пресе́чь (ngăn chặn)","vi":"пресёк, пресекла́, пресекло́, пресекли́.","g":null},{"t":"vocab","ru":"Отвле́чь (làm xao lãng)","vi":"отвлёк, отвлекла́, отвлекло́, отвлекли́.","g":null},{"t":"vocab","ru":"Стере́чь (canh gác)","vi":"стерёг, стерегла́, стерегло́, стерегли́.","g":null},{"t":"vocab","ru":"Бере́чь (giữ gìn)","vi":"берёг, берегла́, берегло́, берегли́.","g":null},{"t":"vocab","ru":"Пренебре́чь (coi thường/bỏ qua)","vi":"пренебрёг, пренебрегла́, пренебрегло́, пренебрегли́.","g":null},{"t":"vocab","ru":"Лечь (nằm xuống - gốc ляг)","vi":"лёг, легла́, легло́, легли́.","g":null},{"t":"subhead","text":"b) Nhóm kết thúc bằng -сти (Gốc từ là d hoặc t):","b":1},{"t":"vocab","ru":"Мести́ (quét)","vi":"мёл, мела́, мело́, мели́.","g":null},{"t":"vocab","ru":"Цвести́ (nở hoa)","vi":"цвёл, цвела́, цвело́, цвели́.","g":null},{"t":"vocab","ru":"Вести́ (dẫn đi)","vi":"вёл, вела́, вело́, вели́.","g":null},{"t":"vocab","ru":"Брести́ (lê bước)","vi":"брёл, брела́, брело́, брели́.","g":null},{"t":"vocab","ru":"Плести́ (tết, đan)","vi":"плёл, плела́, плело́, плели́.","g":null},{"t":"subhead","text":"в) Nhóm kết thúc bằng -сти/-зти (Gốc từ là s hoặc z):","b":1},{"t":"vocab","ru":"Нести́ (mang, vác)","vi":"нёс, несла́, несло́, несли́.","g":null},{"t":"vocab","ru":"Везти́ (chở đi)","vi":"вёз, везла́, везло́, везли́.","g":null},{"t":"vocab","ru":"Расти́ (lớn lên - gốc рос)","vi":"рос, росла́, росло́, росли́.","g":null},{"t":"vocab","ru":"Грести́ (chèo)","vi":"грёб, гребла́, гребло́, гребли́.","g":null},{"t":"vocab","ru":"Трясти́ (rung, lắc)","vi":"тряс, трясла́, трясло́, трясли́.","g":null},{"t":"vocab","ru":"Спасти́ (cứu)","vi":"спас, спасла́, спасло́, спасли́.","g":null},{"t":"vocab","ru":"Запасти́ (dự trữ)","vi":"запас, запасла́, запасло́, запасли́.","g":null}]},{"id":"07-s019","type":"exercise","title":"BÀI TẬP 517 (Trang 264)","num":517,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì quá khứ."},{"t":"para","text":"1. Э́то де́ло (увле́чь) меня́ с голово́й.","b":1},{"t":"para","text":"Viết lại: Э́то де́ло увлекло́ меня́ с голово́й."},{"t":"para","text":"Dịch: Công việc này đã lôi cuốn tôi hoàn toàn (ngập đầu)."},{"t":"example","text":"Giải thích: Chủ ngữ Э́то де́ло là giống trung → động từ увлекло́."},{"t":"para","text":"2. Мы (расти́), как все де́ти на́шего во́зраста.","b":1},{"t":"para","text":"Viết lại: Мы росли́, как все де́ти на́шего во́зраста."},{"t":"para","text":"Dịch: Chúng tôi đã lớn lên như tất cả những đứa trẻ cùng trang lứa."},{"t":"example","text":"Giải thích: Chủ ngữ Мы (số nhiều) → росли́."},{"t":"para","text":"3. Э́то письмо́ я (сжечь).","b":1},{"t":"para","text":"Viết lại: Э́то письмо́ я сжёг."},{"t":"para","text":"Dịch: Tôi đã đốt lá thư này rồi."},{"t":"example","text":"Giải thích: Chủ ngữ Я (người nói là nam - giả định trong văn học/ngữ cảnh chung nếu không rõ giới tính thì ưu tiên giống đực hoặc tùy người nói, nhưng сжёг là dạng cơ bản) → сжёг."},{"t":"para","text":"4. Всё (вы́йти) по-мо́ему, как я тебе́ и говори́л.","b":1},{"t":"para","text":"Viết lại: Всё вы́шло по-мо́ему, как я тебе́ и говори́л."},{"t":"para","text":"Dịch: Mọi thứ đã diễn ra/xảy ra đúng theo ý tôi, như tôi đã nói với bạn."},{"t":"example","text":"Giải thích: Chủ ngữ Всё (đại từ giống trung) → вы́шло."},{"t":"para","text":"5. Каки́е рабо́ты (лечь) в осно́ву ва́шего докла́да?","b":1},{"t":"para","text":"Viết lại: Каки́е рабо́ты легли́ в осно́ву ва́шего докла́да?"},{"t":"para","text":"Dịch: Những công trình nghiên cứu nào đã là nền tảng (nằm làm nền) cho bài báo cáo của ông?"},{"t":"example","text":"Giải thích: Chủ ngữ рабо́ты (số nhiều) → легли́."},{"t":"para","text":"6. Э́то не (мочь) не отрази́ться на его́ рабо́те.","b":1},{"t":"para","text":"Viết lại: Э́то не могло́ не отрази́ться на его́ рабо́те."},{"t":"para","text":"Dịch: Điều này không thể không ảnh hưởng tới công việc của anh ấy."},{"t":"example","text":"Giải thích: Chủ ngữ Э́то (giống trung) → могло́."},{"t":"para","text":"7. Со́лнце (сжечь) всю зе́млю.","b":1},{"t":"para","text":"Viết lại: Со́лнце сожгло́ всю зе́млю."},{"t":"para","text":"Dịch: Mặt trời đã thiêu đốt cả mặt đất."},{"t":"example","text":"Giải thích: Chủ ngữ Со́лнце (giống trung) → сожгло́."},{"t":"vocab","ru":"Он (трясти́) меня́ за пле́чи, повторя́я","vi":"\"Заче́м ты э́то сде́лал?\".","g":null},{"t":"para","text":"Viết lại: Он тряс меня́ за пле́чи, повторя́я..."},{"t":"para","text":"Dịch: Anh ta lắc vai tôi và lặp đi lặp lại: \"Tại sao cậu lại làm thế?\"."},{"t":"example","text":"Giải thích: Chủ ngữ Он (giống đực) → тряс (không có -л)."},{"t":"para","text":"9. Я (пренебре́чь) его́ сове́тами, и мне бы́ло сты́дно.","b":1},{"t":"para","text":"Viết lại: Я пренебрёг его́ сове́тами, и мне бы́ло сты́дно."},{"t":"para","text":"Dịch: Tôi đã phớt lờ/bỏ qua những lời khuyên của anh ấy, và tôi cảm thấy xấu hổ."},{"t":"example","text":"Giải thích: Chủ ngữ Я (giống đực) → пренебрёг."},{"t":"para","text":"10. Подожди́ мину́ту, сейча́с я зако́нчу, меня́ (отвле́чь) телефо́нный звоно́к.","b":1},{"t":"para","text":"Viết lại: ..., меня́ отвлёк телефо́нный звоно́к."},{"t":"para","text":"Dịch: Đợi một phút, tôi xong ngay đây, cú điện thoại đã làm tôi xao lãng."},{"t":"example","text":"Giải thích: Chủ ngữ звоно́к (giống đực) → отвлёк."},{"t":"para","text":"11. Э́ти собы́тия не (мочь) пройти́ для него́ бессле́дно.","b":1},{"t":"para","text":"Viết lại: Э́ти собы́тия не могли́ пройти́ для него́ бессле́дно."},{"t":"para","text":"Dịch: Những sự kiện này không thể trôi qua mà không để lại dấu vết gì với anh ấy."},{"t":"example","text":"Giải thích: Chủ ngữ собы́тия (số nhiều) → могли́."},{"t":"para","text":"12. Он (напря́чь) зре́ние, но никого́ не смог различи́ть в темноте́ у́лицы.","b":1},{"t":"para","text":"Viết lại: Он напря́г зре́ние, но никого́ не смог различи́ть..."},{"t":"para","text":"Dịch: Anh ấy đã căng mắt ra nhìn, nhưng không thể phân biệt được ai trong bóng tối của con đường."},{"t":"example","text":"Giải thích: Chủ ngữ Он (giống đực) → напря́г."},{"t":"para","text":"13. В э́тот год осо́бенно (цвести́) тополя́, и по всей земле́ лете́л их пух, как сне́жные хло́пья.","b":1},{"t":"para","text":"Viết lại: В э́тот год осо́бенно цвели́ тополя́..."},{"t":"para","text":"Dịch: Năm đó hàng cây bạch dương nở hoa rực rỡ đặc biệt, và phấn hoa bay khắp mặt đất như những bông tuyết."},{"t":"example","text":"Giải thích: Chủ ngữ тополя́ (số nhiều) → цвели́."},{"t":"para","text":"14. Э́та случа́йность (спасти́) мне жизнь.","b":1},{"t":"para","text":"Viết lại: Э́та случа́йность спасла́ мне жизнь."},{"t":"para","text":"Dịch: Sự tình cờ này đã cứu mạng tôi."},{"t":"example","text":"Giải thích: Chủ ngữ случа́йность (giống cái) → спасла́."},{"t":"para","text":"15. Вообще́, мне в жи́зни (везти́).","b":1},{"t":"para","text":"Viết lại: Вообще́, мне в жи́зни везло́."},{"t":"para","text":"Dịch: Nhìn chung, trong cuộc đời tôi (luôn) gặp may."},{"t":"example","text":"Giải thích: Cấu trúc vô nhân xưng với động từ везти (may mắn) dùng giống trung → везло́."},{"t":"para","text":"16. На у́лице (мести́) позёмка, дере́вья стоя́ли в снегу́.","b":1},{"t":"para","text":"Viết lại: На у́лице мела́ позёмка..."},{"t":"para","text":"Dịch: Ngoài đường tuyết đang quét là là mặt đất (bão tuyết thấp), cây cối phủ đầy tuyết."},{"t":"example","text":"Giải thích: Chủ ngữ позёмка (giống cái) → мела́."},{"t":"para","text":"17. Я (лечь) на дива́н и усну́л.","b":1},{"t":"para","text":"Viết lại: Я лёг на дива́н и усну́л."},{"t":"para","text":"Dịch: Tôi đã nằm xuống sofa và ngủ thiếp đi."},{"t":"example","text":"Giải thích: Я (giống đực vì уснул) → лёг."},{"t":"para","text":"18. Холо́дная вода́ (течь) из кра́на без перебо́ев, а вот с горя́чей водо́й ча́сто быва́ли пробле́мы.","b":1},{"t":"para","text":"Viết lại: Холо́дная вода́ текла́ из кра́на..."},{"t":"para","text":"Dịch: Nước lạnh đã chảy ra từ vòi không bị ngắt quãng, nhưng nước nóng thì thường xuyên gặp vấn đề."},{"t":"example","text":"Giải thích: Chủ ngữ вода́ (giống cái) → текла́."},{"t":"para","text":"19. Мили́ция (пресе́чь) их незако́нные де́йствия.","b":1},{"t":"para","text":"Viết lại: Мили́ция пресекла́ их незако́нные де́йствия."},{"t":"para","text":"Dịch: Cảnh sát đã ngăn chặn những hành động phi pháp của họ."},{"t":"example","text":"Giải thích: Chủ ngữ Мили́ция (giống cái) → пресекла́."},{"t":"para","text":"20. — Куда́ ты шёл? — Никуда́, (брести́) куда́ глаза́ глядя́т.","b":1},{"t":"para","text":"Viết lại: ..., брёл куда́ глаза́ глядя́т."},{"t":"para","text":"Dịch: — Cậu đã đi đâu thế? — Chẳng đâu cả, cứ lang thang/lê bước tùy ý (mắt nhìn đâu đi đó)."},{"t":"example","text":"Giải thích: Chủ ngữ ẩn Я (giống đực, dựa vào câu hỏi шёл) → брёл."}]},{"id":"07-s020","type":"grammar","title":"PHẦN NGỮ PHÁP (Ôn lại từ trang 263-264)","num":null,"blocks":[{"t":"para","text":"Trước khi làm bài, bạn cần nhớ các quy tắc sau để chia động từ ở thì quá khứ:"},{"t":"subhead","text":"Động từ kết thúc bằng -чь (như печь, мочь):","b":1},{"t":"example","text":"Giống đực: Biến đổi phụ âm cuối và không có đuôi -л (ví dụ: печь → пёк, мочь → мог)."},{"t":"example","text":"Các giống khác: Thêm -ла, -ло, -ли vào sau gốc phụ âm (ví dụ: пекла́, могло́)."},{"t":"subhead","text":"Động từ kết thúc bằng -сти/-зти (như нести, везти):","b":1},{"t":"example","text":"Giống đực: Thường không có đuôi -л nếu gốc từ kết thúc bằng phụ âm (ví dụ: нёс, вёз)."},{"t":"example","text":"Ngoại lệ: Một số động từ vẫn giữ -л (ví dụ: мести → мёл)."},{"t":"example","text":"Các giống khác: Thêm -ла, -ло, -ли (ví dụ: несла́, везло́)."},{"t":"subhead","text":"Động từ kết thúc bằng -ереть (như умере́ть, запере́ть):","b":1},{"t":"example","text":"Giống đực: Rút gọn âm -е- ở gốc và không có đuôi -л (ví dụ: у́мер, за́пер)."},{"t":"example","text":"Các giống khác: Giữ nguyên gốc và thêm đuôi (ví dụ: умерла́, за́перло)."}]},{"id":"07-s021","type":"exercise","title":"BÀI TẬP 518 (Trang 264-265)","num":518,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì quá khứ."},{"t":"para","text":"1. К пра́зднику моя́ ма́ма (испе́чь) испекла́ бу́лочки и (запе́чь) запекла́ в духо́вке инде́йку.","b":1},{"t":"para","text":"Dịch: Vào ngày lễ, mẹ tôi đã nướng bánh mì ngọt và quay gà tây trong lò."},{"t":"example","text":"Giải thích: Chủ ngữ ма́ма (giống cái) → đuôi -ла."},{"t":"para","text":"2. Я (пересе́чь) пересёк грани́цу без осо́бых хлопо́т.","b":1},{"t":"para","text":"Dịch: Tôi đã vượt biên giới mà không gặp phiền toái gì đặc biệt."},{"t":"example","text":"Giải thích: Chủ ngữ Я (thường mặc định là nam trong bài tập ngữ pháp nếu không có ngữ cảnh khác, hoặc theo người nói) → giống đực của -чь mất đuôi -л → пересёк."},{"t":"para","text":"3. Я (произвести́) произвёл не́которые подсчёты и вы́яснил, что среднегодова́я температу́ра в э́той ме́стности не превыша́ет 10 гра́дусов.","b":1},{"t":"para","text":"Dịch: Tôi đã thực hiện một vài tính toán và làm rõ rằng nhiệt độ trung bình năm ở vùng này không vượt quá 10 độ."},{"t":"example","text":"Giải thích: Động từ выяснил ở vế sau là giống đực → chủ ngữ Я là nam → произвёл."},{"t":"para","text":"4. На́ша библиоте́ка (приобрести́) приобрела́ но́вую литерату́ру по ва́шей специа́льности.","b":1},{"t":"para","text":"Dịch: Thư viện của chúng tôi đã mua (nhập) tài liệu mới về chuyên ngành của bạn."},{"t":"example","text":"Giải thích: Chủ ngữ библиоте́ка (giống cái) → приобрела́."},{"t":"para","text":"5. Он о́чень (помо́чь) помо́г мне в мои́х иссле́дованиях.","b":1},{"t":"para","text":"Dịch: Anh ấy đã giúp tôi rất nhiều trong các nghiên cứu của tôi."},{"t":"example","text":"Giải thích: Chủ ngữ Он (giống đực) → помо́г (không có -л)."},{"t":"para","text":"6. Я (подмести́) подмёл пол, и (вы́трясти) вы́тряс все ковры́ в до́ме.","b":1},{"t":"para","text":"Dịch: Tôi đã quét sàn và giũ sạch tất cả thảm trong nhà."},{"t":"example","text":"Giải thích: Я (giống đực). Подмести́ → подмёл. Вы́трясти (từ gốc трясти) → вы́тряс (không có -л)."},{"t":"para","text":"7. Он (убере́чь) уберёг меня́ от оши́бки гора́здо бо́лее стра́шной, чем легкомы́слие.","b":1},{"t":"para","text":"Dịch: Ông ấy đã bảo vệ (cứu) tôi khỏi một sai lầm còn đáng sợ hơn nhiều so với sự nông nổi."},{"t":"example","text":"Giải thích: Chủ ngữ Он (giống đực) → уберёг."},{"t":"para","text":"8. Э́та исто́рия всех нас немно́го (развле́чь) развлекла́.","b":1},{"t":"para","text":"Dịch: Câu chuyện này đã làm tất cả chúng tôi giải trí (vui vẻ) một chút."},{"t":"example","text":"Giải thích: Chủ ngữ исто́рия (giống cái) → развлекла́."},{"t":"para","text":"9. Поли́ция (пресе́чь) пресекла́ незако́нный ввоз в страну́ па́ртии антиквариа́та.","b":1},{"t":"para","text":"Dịch: Cảnh sát đã ngăn chặn vụ nhập khẩu trái phép lô hàng cổ vật vào trong nước."},{"t":"example","text":"Giải thích: Chủ ngữ Поли́ция (giống cái) → пресекла́."},{"t":"para","text":"10. Свои́м гро́мким го́лосом и необы́чной вне́шностью он (привле́чь) привлёк внима́ние всех прису́тствующих.","b":1},{"t":"para","text":"Dịch: Bằng giọng nói to và ngoại hình khác thường, anh ấy đã thu hút sự chú ý của tất cả những người có mặt."},{"t":"example","text":"Giải thích: Chủ ngữ он (giống đực) → привлёк."},{"t":"para","text":"11. Она́ (превозмо́чь) превозмогла́ боль и вста́ла с крова́ти.","b":1},{"t":"para","text":"Dịch: Cô ấy đã nén (vượt qua) nỗi đau và bước xuống giường."},{"t":"example","text":"Giải thích: Chủ ngữ Она (giống cái) → превозмогла́."},{"t":"para","text":"12. Неуже́ли никто́ не (предостере́чь) предостерёг тебя́ от э́того необду́манного ша́га?","b":1},{"t":"para","text":"Dịch: Chẳng lẽ không ai cảnh báo cậu về bước đi thiếu suy nghĩ này sao?"},{"t":"example","text":"Giải thích: Chủ ngữ никто đi với động từ giống đực số ít → предостерёг."},{"t":"para","text":"13. Под со́лнцем ткань (вы́цвести) вы́цвела и потеря́ла свою́ бы́лую я́ркость.","b":1},{"t":"para","text":"Dịch: Dưới ánh mặt trời, vải đã bị bạc màu và mất đi độ rực rỡ ban đầu."},{"t":"example","text":"Giải thích: Chủ ngữ ткань (giống cái) → вы́цвела."},{"t":"para","text":"14. Де́ти давно́ (вы́расти) вы́росли и уе́хали из до́ма.","b":1},{"t":"para","text":"Dịch: Lũ trẻ đã lớn từ lâu và rời khỏi nhà."},{"t":"example","text":"Giải thích: Chủ ngữ Де́ти (số nhiều) → вы́росли (gốc рос)."},{"t":"para","text":"15. Что он вам про меня́ тут (наплести́) наплёл? Не ве́рьте ни одному́ его́ сло́ву!","b":1},{"t":"para","text":"Dịch: Hắn ta đã bịa đặt (nói hươu nói vượn) gì về tôi ở đây thế? Đừng tin một lời nào của hắn!"},{"t":"example","text":"Giải thích: Chủ ngữ он (giống đực) → наплёл."},{"t":"para","text":"16. Он разыгра́л меня́, (провести́) провёл меня́, как мальчи́шку.","b":1},{"t":"para","text":"Dịch: Hắn đã chơi khăm tôi, đã lừa (xỏ mũi) tôi như một thằng nhóc."},{"t":"example","text":"Giải thích: Chủ ngữ Он → провёл."},{"t":"para","text":"17. Она́ не растеря́лась, тут же (приже́чь) прижгла́ ра́ну и перевяза́ла её.","b":1},{"t":"para","text":"Dịch: Cô ấy không hề bối rối, đã sát trùng (đốt cháy bề mặt để cầm máu/khử trùng) vết thương ngay và băng bó lại."},{"t":"example","text":"Giải thích: Chủ ngữ Она → прижгла́."},{"t":"para","text":"18. Я на мину́тку (приле́чь) прилёг на крова́ть и не заме́тил, как усну́л.","b":1},{"t":"para","text":"Dịch: Tôi đã ngả lưng xuống giường một chút và không để ý là mình đã ngủ thiếp đi lúc nào."},{"t":"example","text":"Giải thích: Động từ уснул là giống đực → прилёг."}]},{"id":"07-s022","type":"exercise","title":"BÀI TẬP 519 (Trang 265)","num":519,"blocks":[{"t":"instruction","text":"Yêu cầu: Tạo các hình thức quá khứ (đực, cái, trung, nhiều) từ các động từ cho trước."},{"t":"para","text":"a) Nhóm động từ có đuôi -сть, -зть (giữ nguyên hoặc rụng -л ở giống đực tùy gốc):","b":1},{"t":"vocab","ru":"Упа́сть (ngã)","vi":"упа́л, упа́ла, упа́ло, упа́ли.","g":null},{"t":"vocab","ru":"Сесть (ngồi)","vi":"сел, се́ла, се́ло, се́ли.","g":null},{"t":"vocab","ru":"Класть (đặt/để)","vi":"клал, кла́ла, кла́ло, кла́ли.","g":null},{"t":"vocab","ru":"Есть (ăn)","vi":"ел, е́ла, е́ло, е́ли.","g":null},{"t":"vocab","ru":"Пропа́сть (mất tích/tiêu tùng)","vi":"пропа́л, пропа́ла, пропа́ло, пропа́ли.","g":null},{"t":"vocab","ru":"Укра́сть (ăn trộm)","vi":"укра́л, укра́ла, укра́ло, укра́ли.","g":null},{"t":"vocab","ru":"Уче́сть (tính đến/lưu ý)","vi":"учёл, учла́, учло́, учли́.","g":null},{"t":"vocab","ru":"Ле́зть (leo/chui)","vi":"лез, ле́зла, ле́зло, ле́зли (Giống đực không có -л).","g":null},{"t":"subhead","text":"б) Nhóm động từ gốc \"идти\":","b":1},{"t":"vocab","ru":"Идти́ (đi)","vi":"шёл, шла, шло, шли. (Động từ bất quy tắc hoàn toàn).","g":null},{"t":"vocab","ru":"Найти́ (tìm thấy)","vi":"нашёл, нашла́, нашло́, нашли́.","g":null},{"t":"vocab","ru":"Вы́йти (ra ngoài)","vi":"вы́шел, вы́шла, вы́шло, вы́шли.","g":null},{"t":"subhead","text":"в) Nhóm động từ -ереть (Giống đực mất -ере- và -л):","b":1},{"t":"vocab","ru":"Умере́ть (chết)","vi":"у́мер, умерла́, у́мерло, у́мерли.","g":null},{"t":"vocab","ru":"Запере́ть (khóa)","vi":"за́пер, заперла́, за́перло, за́перли.","g":null},{"t":"vocab","ru":"Тере́ть (cọ/xát)","vi":"тёр, тёрла, тёрло, тёрли.","g":null},{"t":"vocab","ru":"Стере́ть (xóa/tẩy)","vi":"стёр, стёрла, стёрло, стёрли.","g":null},{"t":"vocab","ru":"Вы́тереть (lau khô)","vi":"вы́тер, вы́терла, вы́терло, вы́терли.","g":null}]},{"id":"07-s023","type":"exercise","title":"BÀI TẬP 520 (Trang 265)","num":520,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì quá khứ."},{"t":"para","text":"1. Знал бы, где (упа́сть) упа́сть, соло́мки б подостла́л (tục ngữ).","b":1},{"t":"note","text":"Lưu ý: Câu này là tục ngữ, động từ trong ngoặc упасть ở đây giữ nguyên dạng nguyên thể (infinitive) trong cấu trúc câu điều kiện giả định \"Znal by, gde upast'...\" (Nếu biết ngã ở đâu...). Tuy nhiên, nếu đề bài bắt buộc chia quá khứ thì phải là một câu tường thuật. Nhưng trong ngữ cảnh bài 520, có thể tác giả muốn học sinh nhận diện dạng quá khứ trong câu điều kiện hoặc đơn giản là điền dạng quá khứ của упасть nếu câu là Знал бы, где (он) упал...."},{"t":"example","text":"Tuy nhiên, câu tục ngữ gốc chính xác là: Знал бы, где упасть, соломки бы подстелил. (Ở đây dùng nguyên thể)."},{"t":"example","text":"Nếu bắt buộc chia thì quá khứ theo yêu cầu chung của bài: упа́л (nếu chủ ngữ ẩn là \"tôi/anh\")."},{"t":"para","text":"Dịch: Nếu biết mình sẽ ngã ở đâu, thì đã trải rơm sẵn rồi. (Phòng bệnh hơn chữa bệnh)."},{"t":"para","text":"2. Он (сесть) сел за стол и улыбну́лся.","b":1},{"t":"para","text":"Dịch: Anh ấy đã ngồi vào bàn và mỉm cười."},{"t":"example","text":"Giải thích: Он → сел."},{"t":"para","text":"3. Что на тебя́ сего́дня (найти́) нашло́, почему́ ты себя́ так ведёшь?","b":1},{"t":"example","text":"Dịch: Hôm nay có chuyện gì xảy ra với cậu thế (Cái gì đã nhập vào cậu), tại sao cậu lại cư xử như vậy?"},{"t":"example","text":"Giải thích: Chủ ngữ Что (giống trung) → нашло́."},{"t":"para","text":"4. Я (пройти́) прошёл с доско́й и откры́л фо́рточку в аудито́рии.","b":1},{"t":"para","text":"Dịch: Tôi đã đi qua (cùng) với cái bảng và mở ô thông gió trong giảng đường."},{"t":"example","text":"Giải thích: Chủ ngữ Я là nam (vì открыл) → прошёл."},{"t":"para","text":"5. Ду́маю, мы уже́ (пройти́) прошли́ дом, кото́рый нам ну́жен.","b":1},{"t":"para","text":"Dịch: Tôi nghĩ chúng ta đã đi qua ngôi nhà mà chúng ta cần tìm rồi."},{"t":"example","text":"Giải thích: Chủ ngữ мы (số nhiều) → прошли́."},{"t":"para","text":"6. Ты не (уче́сть) учёл дополни́тельные расхо́ды, кото́рые у нас мо́гут возни́кнуть.","b":1},{"t":"para","text":"Dịch: Cậu đã không tính đến các chi phí phát sinh mà chúng ta có thể gặp phải."},{"t":"example","text":"Giải thích: Chủ ngữ Ты (giả định nam) → учёл."},{"t":"para","text":"7. Она́ (вы́йти) вы́шла из до́ма два часа́ наза́д, сказа́ла, что вернётся че́рез полчаса́, и (пропа́сть) пропа́ла: её до сих пор нет.","b":1},{"t":"para","text":"Dịch: Cô ấy đã ra khỏi nhà hai tiếng trước, nói là sẽ quay lại sau nửa tiếng, và đã biến mất (bặt vô âm tín): đến giờ vẫn chưa thấy đâu."},{"t":"example","text":"Giải thích: Она → вы́шла, пропа́ла."},{"t":"para","text":"8. Ты (запере́ть) за́пер дверь? Бою́сь, что у меня́ нет ключе́й.","b":1},{"t":"para","text":"Dịch: Cậu đã khóa cửa chưa? Tớ sợ là tớ không mang chìa khóa."},{"t":"example","text":"Giải thích: Ты (nam, trong hội thoại thường nhật) → за́пер. (Nếu nữ: заперла́)."},{"t":"para","text":"9. Вся́кая чепуха́ (лезть) ле́зла мне в го́лову.","b":1},{"t":"para","text":"Dịch: Đủ thứ chuyện vớ vẩn cứ chui/len vào đầu tôi."},{"t":"example","text":"Giải thích: Chủ ngữ чепуха (giống cái) → ле́зла."},{"t":"para","text":"10. Для всех он (умере́ть) у́мер, но то́лько не для меня́.","b":1},{"t":"para","text":"Dịch: Với tất cả mọi người, anh ấy đã chết, nhưng với tôi thì không."},{"t":"example","text":"Giải thích: Chủ ngữ он → у́мер."},{"t":"para","text":"11. Он (есть) ел неторопли́во, ни на кого́ не обраща́я внима́ния.","b":1},{"t":"para","text":"Dịch: Anh ấy ăn một cách từ tốn, không chú ý đến ai cả."},{"t":"example","text":"Giải thích: Он → ел."},{"t":"para","text":"12. Он по́днял ру́ку и (вы́тереть) вы́тер пот со лба.","b":1},{"t":"para","text":"Dịch: Anh ấy giơ tay lên và lau mồ hôi trên trán."},{"t":"example","text":"Giải thích: Он → вы́тер."},{"t":"para","text":"13. Мне бы не хоте́лось, что́бы э́ту иде́ю у меня́ кто-нибу́дь (укра́сть) укра́л.","b":1},{"t":"para","text":"Dịch: Tôi không muốn ai đó đánh cắp ý tưởng này của tôi."},{"t":"example","text":"Giải thích: Chủ ngữ кто-нибудь (đi với động từ giống đực số ít) → укра́л."},{"t":"para","text":"14. Всё (идти́) шло к тому́, что́бы я оста́лся в го́роде.","b":1},{"t":"para","text":"Dịch: Mọi chuyện diễn ra (đi đến kết cục) theo hướng là tôi phải ở lại thành phố."},{"t":"example","text":"Giải thích: Chủ ngữ Всё (giống trung) → шло."},{"t":"para","text":"15. Она́ сиде́ла, опусти́в го́лову, и стара́тельно (тере́ть) тёрла виски́ рука́ми.","b":1},{"t":"para","text":"Dịch: Cô ấy ngồi cúi đầu và xoa/day thái dương bằng tay một cách cố gắng."},{"t":"example","text":"Giải thích: Chủ ngữ Она → тёрла."},{"t":"para","text":"Chào em, dưới đây là phần giải thích ngữ pháp, viết lại câu và dịch nghĩa chi tiết cho các bài tập từ 521 đến 525 trong sách giáo khoa."},{"t":"example","text":"Các bài tập này tập trung vào cách chia thì quá khứ của các động từ đặc biệt (động từ có đuôi -ти, -сть, -зть) và các động từ có hậu tố -ну-."}]},{"id":"07-s024","type":"exercise","title":"BÀI TẬP 521 (Trang 266)","num":521,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì quá khứ."},{"t":"para","text":"Giải thích ngữ pháp: Các động từ trong bài này thuộc nhóm đặc biệt khi chuyển sang thì quá khứ:"},{"t":"vocab","ru":"Động từ gốc -йти (đi)","vi":"перейти́ (đi qua) → перешёл (đực), перешла́ (cái).","g":null},{"t":"subhead","text":"Động từ gốc -сть/-зть:"},{"t":"example","text":"кра́сться (lẻn) → кра́лся."},{"t":"example","text":"вы́пасть (rơi ra) → вы́пал."},{"t":"example","text":"изобрести́ (phát minh) → изобрёл (lưu ý âm е biến thành ё ở giống đực và mất đuôi л nếu gốc từ kết thúc bằng phụ âm)."},{"t":"example","text":"произнести́ (phát âm) → произнёс."},{"t":"vocab","ru":"Động từ gốc -ереть","vi":"замере́ть (đứng tim, sững lại), протере́ть (lau) → mất hậu tố -е- và -л ở giống đực (за́мер, проте́р), nhưng giữ nguyên ở các giống khác (замерла́, проте́рла).","g":null},{"t":"para","text":"Bài làm chi tiết:","b":1},{"t":"para","text":"Он перешёл на другу́ю сто́рону у́лицы и скры́лся в подъе́зде пятиэта́жного до́ма."},{"t":"para","text":"Dịch: Anh ấy đã đi sang phía bên kia đường và biến mất vào lối cổng của tòa nhà 5 tầng."},{"t":"para","text":"Я уви́дел, как в темноте́ кто́-то кра́лся на цы́почках к до́му."},{"t":"para","text":"Dịch: Tôi đã nhìn thấy ai đó đang rón rén lẻn về phía ngôi nhà trong bóng tối."},{"t":"para","text":"Моне́та вы́пала из мои́х рук и закати́лась под шкаф."},{"t":"para","text":"Dịch: Đồng xu đã rơi khỏi tay tôi và lăn xuống gầm tủ."},{"t":"para","text":"В э́тот дом, на маши́не напёрли?"},{"t":"note","text":"Lưu ý: Động từ напере́ть trong ngữ cảnh này mang nghĩa thông tục là \"đâm vào/húc vào\" hoặc \"lao vào\"."},{"t":"para","text":"Dịch: Các người đã húc xe vào ngôi nhà này à?"},{"t":"para","text":"Он о́чень упря́мый, е́сли во что́-нибудь упёрся, то его́ ни за что не уда́стся разубеди́ть."},{"t":"note","text":"Lưu ý: Ở đây dùng упёрся (quá khứ) mang nghĩa \"đã quyết tâm/đã khăng khăng\" (trạng thái đã hình thành)."},{"t":"para","text":"Dịch: Cậu ta rất bướng bỉnh, nếu cậu ta đã khăng khăng vào việc gì, thì không đời nào thuyết phục được cậu ta đâu."},{"t":"para","text":"Он изобрёл велосипе́д."},{"t":"para","text":"Dịch: Anh ấy đã phát minh ra chiếc xe đạp. (Thành ngữ: \"Phát minh lại cái bánh xe\" - làm điều thừa thãi, nhưng ở đây dịch nghĩa đen)."},{"t":"example","text":"Он произнёс две ло́жки су́па. (Có lẽ sách in nhầm từ пронёс - mang qua/làm đổ, hoặc съел - ăn. Tuy nhiên, nếu bắt buộc chia произнести́ thì là произнёс, nhưng nghĩa \"phát âm 2 thìa súp\" rất vô lý. Nếu động từ là поднёс (đưa lên miệng) thì hợp lý hơn. Giả sử theo đúng động từ trong ngoặc произнести)."},{"t":"example","text":"Sửa lại theo ngữ cảnh hợp lý: Có thể là пронёс (mang qua miệng/làm đổ) -> пронёс. Nếu giữ nguyên произнести:"},{"t":"para","text":"Dịch (theo từ gốc): Anh ấy đã phát âm hai thìa súp (vô nghĩa)."},{"t":"vocab","ru":"Dịch (giả định пронёс)","vi":"Anh ấy đã đưa trượt 2 thìa súp (đổ ra ngoài).","g":null},{"t":"para","text":"Из 96 я вы́чел 57 и получи́л 39."},{"t":"example","text":"Ngữ pháp: Вы́честь (trừ) → giống đực вы́чел."},{"t":"para","text":"Dịch: Tôi đã lấy 96 trừ đi 57 và được kết quả là 39."},{"t":"para","text":"К сожале́нию, я не прочёл (hoặc прочита́л) ни одного́ рома́на э́того писа́теля."},{"t":"example","text":"Ngữ pháp: Проче́сть có 2 dạng quá khứ: прочёл (văn phong sách vở) và прочита́л (thông dụng)."},{"t":"para","text":"Dịch: Thật đáng tiếc, tôi đã không đọc một cuốn tiểu thuyết nào của nhà văn này."},{"t":"para","text":"Я предпочёл бы, что́бы мне никто́ не меша́л."},{"t":"example","text":"Ngữ pháp: Предпоче́сть → предпочёл."},{"t":"para","text":"Dịch: Tôi thà rằng không có ai làm phiền tôi."},{"t":"para","text":"Хочу́, что́бы ты присе́л на дива́н и вы́слушал меня́ внима́тельно."},{"t":"para","text":"Dịch: Tôi muốn bạn ngồi xuống ghế sô pha và lắng nghe tôi thật kỹ."},{"t":"para","text":"Ему́ ужа́сно надое́ло э́то со́лнце, и э́то мо́ре, и стра́шно хоте́лось домо́й."},{"t":"example","text":"Ngữ pháp: Chủ ngữ là солнце (giống trung) và море, nhưng động từ thường chia theo chủ ngữ gần nhất hoặc theo ý nghĩa chung \"việc đó\". Ở đây надое́ло (nó - việc đó - đã gây chán ngán)."},{"t":"para","text":"Dịch: Cậu ấy đã chán ngấy mặt trời này, và biển này, và muốn về nhà kinh khủng."},{"t":"para","text":"Услы́шав шаги́, я за́мер, трево́жно вгля́дываясь в темноту́."},{"t":"example","text":"Ngữ pháp: Замере́ть → за́мер (giống đực)."},{"t":"para","text":"Dịch: Nghe thấy tiếng bước chân, tôi chết lặng (đứng tim), lo lắng nhìn vào bóng tối."},{"t":"para","text":"Она́ вы́мыла ра́мы, протёрла стёкла, и в ко́мнате ста́ло светле́е."},{"t":"para","text":"Dịch: Cô ấy đã rửa khung cửa sổ, lau kính, và căn phòng trở nên sáng sủa hơn."},{"t":"para","text":"По доро́ге на рабо́ту я зашёл в магази́н и купи́л цветы́."},{"t":"para","text":"Dịch: Trên đường đi làm, tôi đã ghé vào cửa hàng và mua hoa."}]},{"id":"07-s025","type":"grammar","title":"PHẦN NGỮ PHÁP: Động từ với hậu tố -ну- (Trang 266)","num":null,"blocks":[{"t":"para","text":"Lý thuyết:","b":1},{"t":"example","text":"Hành động tức thời (đơn nhất): Các động từ chỉ hành động xảy ra 1 lần duy nhất, rất nhanh (ví dụ: кри́кнуть - hét lên 1 tiếng, мигну́ть - nháy mắt)."},{"t":"para","text":"Ở thì quá khứ, các động từ này GIỮ LẠI hậu tố -ну-."},{"t":"example","text":"Ví dụ: кри́кнул, мигну́л."},{"t":"example","text":"Hành động chỉ kết quả/trạng thái (biến đổi): Các động từ chỉ sự thay đổi trạng thái hoặc đạt được kết quả (ví dụ: пога́снуть - tắt ngấm, исче́знуть - biến mất)."},{"t":"example","text":"Ở thì quá khứ Giống đực: Hậu tố -ну- thường BIẾN MẤT. (Ví dụ: пога́с, исче́з)."},{"t":"example","text":"Ở các giống khác và số nhiều: Có thể giữ hoặc bỏ, nhưng thường bỏ -ну- nếu gốc từ có phụ âm. (Ví dụ: пога́сла, исче́зли)."}]},{"id":"07-s026","type":"exercise","title":"BÀI TẬP 522 (Trang 266)","num":522,"blocks":[{"t":"instruction","text":"Yêu cầu: Xác định xem trong những động từ nào nghĩa của hành động tức thời (ngắn, một lần) được thể hiện rõ, và trong những động từ nào là nghĩa đạt được kết quả. Phân loại các động từ tương ứng với ý nghĩa của chúng."},{"t":"para","text":"Phân loại:","b":1},{"t":"subhead","text":"Nhóm chỉ hành động tức thời/đơn nhất (giữ -ну- trong quá khứ):","b":1},{"t":"example","text":"Пры́гнуть (nhảy lên)"},{"t":"example","text":"Мигну́ть (nháy mắt)"},{"t":"example","text":"Щёлкнуть (búng, tách lưỡi)"},{"t":"example","text":"Тро́нуть (chạm vào)"},{"t":"example","text":"Толкну́ть (đẩy)"},{"t":"example","text":"Мяу́кнуть (kêu meo 1 tiếng)"},{"t":"example","text":"Кольну́ть (châm, chích)"},{"t":"example","text":"Махну́ть (vẫy tay)"},{"t":"example","text":"Дви́нуть (di chuyển/đẩy mạnh)"},{"t":"example","text":"Кри́кнуть (hét lên)"},{"t":"example","text":"Дохну́ть (thở hắt ra/hít vào 1 hơi)"},{"t":"example","text":"Хло́пнуть (vỗ tay/đập mạnh)"},{"t":"subhead","text":"Nhóm chỉ kết quả/trạng thái (thường mất -ну- trong quá khứ giống đực):","b":1},{"t":"example","text":"Привы́кнуть (quen) → привы́к."},{"t":"example","text":"Дости́гнуть (đạt được) → дости́г."},{"t":"example","text":"Окре́пнуть (trở nên khỏe mạnh/cứng cáp) → окре́п."},{"t":"example","text":"Пога́снуть (tắt) → пога́с."},{"t":"example","text":"Осле́пнуть (bị mù) → осле́п."},{"t":"example","text":"Подро́гнуть (run lên vì lạnh - đôi khi có thể coi là tức thời, nhưng thường dùng продро́гнуть chỉ trạng thái lạnh cóng → продро́г)."},{"t":"example","text":"Умо́лкнуть (im bặt) → умо́лк."},{"t":"example","text":"Исче́знуть (biến mất) → исче́з."},{"t":"example","text":"Прони́кнуть (thâm nhập) → прони́к."},{"t":"example","text":"Воздви́гнуть (dựng lên) → воздви́г."},{"t":"vocab","ru":"Верну́ть (trả lại/quay lại - Lưu ý","vi":"từ này đặc biệt, luôn giữ -ну- là верну́л dù chỉ kết quả).","g":null},{"t":"example","text":"Исся́кнуть (cạn kiệt) → исся́к."},{"t":"example","text":"Све́ргнуть (lật đổ) → све́рг."}]},{"id":"07-s027","type":"exercise","title":"BÀI TẬP 523 (Trang 266)","num":523,"blocks":[{"t":"instruction","text":"Yêu cầu: Từ các động từ (ở bài 522), hãy tạo thành các dạng của thì quá khứ. Xác định xem trong trường hợp nào hậu tố -ну- được giữ lại trong các dạng quá khứ."},{"t":"subhead","text":"a) Nhóm giữ lại -ну- (Hành động tức thời):","b":1},{"t":"vocab","ru":"Мину́ть (trôi qua)","vi":"ми́нул, ми́нула, ми́нуло, ми́нули.","g":null},{"t":"vocab","ru":"Пры́гнуть","vi":"пры́гнул, пры́гнула...","g":null},{"t":"vocab","ru":"Кри́кнуть","vi":"кри́кнул, кри́кнула...","g":null},{"t":"vocab","ru":"Мяу́кнуть","vi":"мяу́кнул...","g":null},{"t":"vocab","ru":"Дви́нуть","vi":"дви́нул...","g":null},{"t":"vocab","ru":"Хло́пнуть","vi":"хло́пнул...","g":null},{"t":"vocab","ru":"Щёлкнуть","vi":"щёлкнул...","g":null},{"t":"vocab","ru":"Тро́нуть","vi":"тро́нул...","g":null},{"t":"subhead","text":"b) Nhóm mất -ну- ở giống đực (Hành động kết quả):","b":1},{"t":"vocab","ru":"Привы́кнуть","vi":"привы́к, привы́кла, привы́кло, привы́кли.","g":null},{"t":"vocab","ru":"Дости́гнуть","vi":"дости́г, дости́гла...","g":null},{"t":"vocab","ru":"Окре́пнуть","vi":"окре́п, окре́пла...","g":null},{"t":"vocab","ru":"Све́ргнуть","vi":"све́рг, све́ргла...","g":null},{"t":"vocab","ru":"Воздви́гнуть","vi":"воздви́г, воздви́гла...","g":null},{"t":"vocab","ru":"Исся́кнуть","vi":"исся́к, исся́кла...","g":null}]},{"id":"07-s028","type":"exercise","title":"BÀI TẬP 524 (Trang 267)","num":524,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì quá khứ."},{"t":"para","text":"1. Я бы́стро (привы́кнуть) к но́вой обстано́вке.","b":1},{"t":"para","text":"Viết lại: Я бы́стро привы́к к но́вой обстано́вке."},{"t":"para","text":"Dịch: Tôi đã nhanh chóng làm quen với hoàn cảnh mới."},{"t":"para","text":"2. Не выво́ди меня́ из себя́, моё терпе́ние (исся́кнуть).","b":1},{"t":"para","text":"Viết lại: ..., моё терпе́ние исся́кло."},{"t":"example","text":"Dịch: Đừng làm tôi nổi điên, sự kiên nhẫn của tôi đã cạn kiệt rồi. (Chủ ngữ терпение - giống trung)."},{"t":"para","text":"3. Она́ реши́тельно (толкну́ть) дверь и вошла́ в ко́мнату.","b":1},{"t":"para","text":"Viết lại: Она́ реши́тельно толкну́ла дверь..."},{"t":"example","text":"Dịch: Cô ấy dứt khoát đẩy cửa và bước vào phòng. (Hành động tức thời, giữ -ну-)."},{"t":"para","text":"4. За ле́то он (окре́пнуть) и попра́вился.","b":1},{"t":"para","text":"Viết lại: За ле́то он окре́п и попра́вился."},{"t":"example","text":"Dịch: Qua mùa hè, cậu ấy đã khỏe mạnh và bình phục. (Chỉ kết quả, mất -ну-)."},{"t":"para","text":"5. В октябре́ 1917 го́да солда́ты и матро́сы под руково́дством большевико́в (све́ргнуть) Вре́менное прави́тельство.","b":1},{"t":"para","text":"Viết lại: ..., све́ргли Вре́менное прави́тельство."},{"t":"example","text":"Dịch: Vào tháng 10 năm 1917, binh lính và thủy thủ dưới sự lãnh đạo của những người Bolshevism đã lật đổ Chính phủ Lâm thời. (Mất -ну- ở số nhiều)."},{"t":"vocab","ru":"Что-то (кольнуть) у меня́ в боку́","vi":"я останови́лся.","g":null},{"t":"para","text":"Viết lại: Что-то кольну́ло у меня́ в боку́..."},{"t":"example","text":"Dịch: Có cái gì đó nhói lên ở bên sườn tôi: tôi dừng lại. (Tức thời, giữ -ну-)."},{"t":"para","text":"7. Огни́ (пога́снуть), и в ко́мнате ста́ло темно́.","b":1},{"t":"para","text":"Viết lại: Огни́ пога́сли, и в ко́мнате ста́ло темно́."},{"t":"para","text":"Dịch: Những ngọn đèn đã tắt, và trong phòng trở nên tối tăm."},{"t":"vocab","ru":"Спуская́сь по ле́стнице, она́ (кри́кнуть) мне","vi":"\"Береги́ себя́!\".","g":null},{"t":"para","text":"Viết lại: ..., она́ кри́кнула мне: \"Береги́ себя́!\"."},{"t":"para","text":"Dịch: Khi đi xuống cầu thang, cô ấy đã hét với tôi: \"Bảo trọng nhé!\"."},{"t":"para","text":"9. Я (махну́ть) руко́й на все неприя́тности и продолжа́л де́лать своё де́ло.","b":1},{"t":"para","text":"Viết lại: Я махну́л руко́й..."},{"t":"para","text":"Dịch: Tôi đã phớt lờ (vẫy tay cho qua) mọi chuyện khó chịu và tiếp tục làm việc của mình."},{"t":"para","text":"10. Котёнок жа́лобно (мяу́кнуть) и вы́лез из корзи́ны.","b":1},{"t":"para","text":"Viết lại: Котёнок жа́лобно мяу́кнул..."},{"t":"para","text":"Dịch: Con mèo con kêu meo một tiếng thảm thiết và trèo ra khỏi giỏ."},{"t":"para","text":"11. Ты что, (осле́пнуть)? Не ви́дишь, что на тебя́ е́дет маши́на?","b":1},{"t":"para","text":"Viết lại: Ты что, осле́п? Не ви́дишь...?"},{"t":"para","text":"Dịch: Cậu bị mù à? Không thấy ô tô đang lao vào cậu sao?"},{"t":"para","text":"12. Мы все (продро́гнуть) и ужа́сно уста́ли.","b":1},{"t":"para","text":"Viết lại: Мы все продро́гли и ужа́сно уста́ли."},{"t":"para","text":"Dịch: Tất cả chúng tôi đều lạnh cóng và mệt lử."},{"t":"para","text":"13. За э́то вре́мя мы (дости́гнуть) неплохи́х результа́тов.","b":1},{"t":"para","text":"Viết lại: ..., мы дости́гли неплохи́х результа́тов."},{"t":"para","text":"Dịch: Trong thời gian này chúng tôi đã đạt được những kết quả không tồi."},{"t":"para","text":"14. На ходу́ он (спры́гнуть) с подно́жки трамва́я и (исче́знуть) в толпе́.","b":1},{"t":"para","text":"Viết lại: На ходу́ он спры́гнул с подно́жки трамва́я и исче́з в толпе́."},{"t":"example","text":"Dịch: Khi xe đang chạy, anh ấy đã nhảy xuống khỏi bậc lên xuống tàu điện và biến mất trong đám đông. (Спрыгнул - tức thời, исчез - kết quả)."},{"t":"para","text":"15. Меня́ о́чень (тро́нуть) его́ слова́ о справедли́вости.","b":1},{"t":"para","text":"Viết lại: Меня́ о́чень тро́нули его́ слова́ о справедли́вости."},{"t":"example","text":"Dịch: Những lời nói của anh ấy về công lý đã làm tôi rất cảm động. (Chủ ngữ là слова - số nhiều)."},{"t":"para","text":"16. Как э́тот челове́к (прони́кнуть) в за́пертую ко́мнату?","b":1},{"t":"para","text":"Viết lại: Как э́тот челове́к прони́к в за́пертую ко́мнату?"},{"t":"para","text":"Dịch: Làm thế nào người này đã thâm nhập được vào căn phòng bị khóa?"},{"t":"para","text":"17. На мину́ту она́ (умо́лкнуть), заду́мчиво гля́дя пе́ред собо́й, а зате́м вновь продо́лжила свой расска́з.","b":1},{"t":"para","text":"Viết lại: На мину́ту она́ умо́лкла..."},{"t":"para","text":"Dịch: Cô ấy im lặng một phút, đăm chiêu nhìn về phía trước, rồi lại tiếp tục câu chuyện của mình."},{"t":"para","text":"18. Э́тот монуме́нт (воздви́гнуть) в 1947 году́.","b":1},{"t":"para","text":"Viết lại: Э́тот монуме́нт воздви́гли в 1947 году́."},{"t":"example","text":"Dịch: Người ta đã dựng lên đài tưởng niệm này vào năm 1947. (Câu vô nhân xưng số nhiều, hoặc người ta dựng). Lưu ý: Nếu chủ ngữ là monument (bị động) thì phải dùng был воздвигнут. Ở đây ngữ cảnh chủ động (ẩn chủ ngữ \"người ta\") -> воздвигли."},{"t":"para","text":"19. Все уче́бники я (верну́ть) в библиоте́ку.","b":1},{"t":"para","text":"Viết lại: Все уче́бники я верну́л в библиоте́ку."},{"t":"para","text":"Dịch: Tôi đã trả lại tất cả sách giáo khoa cho thư viện."},{"t":"para","text":"20. Он (хло́пнуть) в ладо́ши, и свет (пога́снуть).","b":1},{"t":"para","text":"Viết lại: Он хло́пнул в ладо́ши, и свет пога́с."},{"t":"example","text":"Dịch: Anh ấy vỗ tay một cái, và đèn tắt ngấm. (Хлопнул - tức thời, погас - kết quả)."}]},{"id":"07-s029","type":"exercise","title":"BÀI TẬP 525 (Trang 267)","num":525,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì quá khứ."},{"t":"subhead","text":"Gợi ý từ khung ngữ pháp (Trang 267):","b":1},{"t":"example","text":"Trong thì quá khứ của các động từ có nghĩa đạt được kết quả (hậu tố -ну-), theo quy tắc, hậu tố này bị lược bỏ; ở động từ chỉ hành động tức thời/một lần, hậu tố -ну- được giữ lại."},{"t":"para","text":"1. Они́ (отве́ргнуть) все на́ши предложе́ния.","b":1},{"t":"para","text":"Viết lại: Они́ отве́ргли все на́ши предложе́ния."},{"t":"example","text":"Dịch: Họ đã bác bỏ tất cả các đề xuất của chúng tôi. (Kết quả -> mất ну)."},{"t":"vocab","ru":"Он (улыбну́ться), (подмигну́ть) мне и сказа́л","vi":"\"Смотри́ веселе́й!\".","g":null},{"t":"para","text":"Viết lại: Он улыбну́лся, подмигну́л мне и сказа́л..."},{"t":"example","text":"Dịch: Anh ấy đã mỉm cười, nháy mắt với tôi và nói: \"Nhìn vui lên nào!\". (Tức thời -> giữ ну)."},{"t":"para","text":"3. Из-за жары́, все цветы́ в саду́ (засо́хнуть).","b":1},{"t":"para","text":"Viết lại: ..., все цветы́ в саду́ засо́хли."},{"t":"example","text":"Dịch: Do nắng nóng, tất cả hoa trong vườn đã khô héo. (Kết quả -> mất ну)."},{"t":"para","text":"4. Она́ (подви́нуть) к себе́ стака́н с ча́ем и положи́ла в него́ са́хар.","b":1},{"t":"para","text":"Viết lại: Она́ подви́нула к себе́ стака́н..."},{"t":"example","text":"Dịch: Cô ấy đã đẩy cốc trà về phía mình và bỏ đường vào đó. (Hành động cụ thể 1 lần -> giữ ну)."},{"t":"para","text":"5. От неожи́данности я (вздра́гнуть) и (огляну́ться).","b":1},{"t":"para","text":"Viết lại: От неожи́данности я вздра́гнул и огляну́лся."},{"t":"example","text":"Dịch: Vì bất ngờ, tôi đã giật mình và ngoảnh lại. (Tức thời -> giữ ну)."},{"t":"para","text":"6. К ве́черу молоко́ (ски́снуть).","b":1},{"t":"para","text":"Viết lại: К ве́черу молоко́ ски́сло."},{"t":"example","text":"Dịch: Đến chiều thì sữa đã bị chua. (Kết quả -> mất ну)."},{"t":"para","text":"7. Он (стегну́ть) ло́шадь, и теле́га тро́нулась с ме́ста.","b":1},{"t":"para","text":"Viết lại: Он стегну́л ло́шадь, и теле́га тро́нулась с ме́ста."},{"t":"example","text":"Dịch: Ông ấy quất ngựa một cái, và chiếc xe bắt đầu lăn bánh. (Tức thời -> giữ ну)."},{"t":"para","text":"8. По́сле мои́х слов её лицо́ (вспы́хнуть), она́ останови́лась и замолча́ла.","b":1},{"t":"para","text":"Viết lại: ... её лицо́ вспы́хнуло..."},{"t":"example","text":"Dịch: Sau những lời của tôi, mặt cô ấy đỏ bừng lên (bùng cháy), cô ấy dừng lại và im lặng. (Nghĩa chuyển của вспыхнуть - bùng lên tức thì -> giữ ну)."},{"t":"para","text":"9. От дождя́ на́ша оде́жда (намо́кнуть) и меша́ла идти́.","b":1},{"t":"para","text":"Viết lại: ... на́ша оде́жда намо́кла..."},{"t":"example","text":"Dịch: Do mưa, quần áo chúng tôi đã bị ướt sũng và gây khó khăn khi di chuyển. (Kết quả -> mất ну)."},{"t":"para","text":"10. На не́бе (сверкну́ть) мо́лния, послы́шались далёкие раска́ты гро́ма.","b":1},{"t":"para","text":"Viết lại: На не́бе сверкну́ла мо́лния..."},{"t":"example","text":"Dịch: Trên trời một tia chớp lóe lên, nghe thấy tiếng sấm rền từ xa. (Tức thời -> giữ ну)."},{"t":"para","text":"11. На мгнове́ние мне показа́лось, что го́лос его́ (дро́гнуть), но он бы́стро взял себя́ в ру́ки.","b":1},{"t":"para","text":"Viết lại: ..., что го́лос его́ дро́гнул..."},{"t":"example","text":"Dịch: Trong một khoảnh khắc tôi thấy dường như giọng anh ấy đã run lên, nhưng anh ấy nhanh chóng trấn tĩnh lại. (Tức thời -> giữ ну)."}]},{"id":"07-s030","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 268 - Trước bài 526)","num":null,"blocks":[{"t":"subhead","text":"Gợi ý trong khung:","b":1},{"t":"subhead","text":"Quy tắc về chữ \"н\" trong gốc từ: Nếu chữ -н- nằm trong thành phần của gốc từ (chứ không phải là hậu tố), thì nó sẽ được giữ nguyên trong các dạng của thì quá khứ và trong các động từ được tạo thành nhờ tiền tố."}]},{"id":"07-s031","type":"exercise","title":"BÀI TẬP 526 (Trang 268)","num":526,"blocks":[{"t":"instruction","text":"Yêu cầu: Tìm các từ cùng gốc (cognate words) cho các động từ sau. Lưu ý xem chữ -н- có nằm trong gốc từ hay không."},{"t":"para","text":"Giải thích và đáp án: Để làm bài này, chúng ta cần tìm từ cùng gốc để xem chữ \"н\" có biến mất không. Nếu nó biến mất hoặc biến đổi, thì \"н\" là hậu tố. Nếu nó giữ nguyên, \"н\" là gốc từ."},{"t":"para","text":"Гнуть (uốn cong) → согну́ть (uốn lại), ги́бкий (dẻo - mất \"н\")."},{"t":"example","text":"Kết luận: Gốc là г- / гиб-. Chữ \"н\" là hậu tố."},{"t":"para","text":"Тону́ть (chìm/đuối nước) → утопа́ть (chìm ngập), то́нет (đang chìm - giữ \"н\")."},{"t":"example","text":"Kết luận: Gốc là тон-. Chữ \"н\" thuộc gốc từ."},{"t":"para","text":"Тяну́ть (kéo) → растя́гивать (kéo dãn - mất \"н\")."},{"t":"example","text":"Kết luận: Gốc là тяг- / тян-. Chữ \"н\" là biến thể hoặc hậu tố tạo dạng."},{"t":"para","text":"Льнуть (bám lấy, nép vào) → прилипа́ть (dính vào - mất \"н\")."},{"t":"example","text":"Kết luận: Gốc là лип- / ль-."},{"t":"para","text":"Хлы́нуть (tuôn ra, ùa tới) → нахлы́нуть (ùa về)."},{"t":"para","text":"Усну́ть (ngủ thiếp đi) → сон (giấc ngủ - giữ \"н\")."},{"t":"example","text":"Kết luận: Gốc là сн- / сон-. Chữ \"н\" thuộc gốc từ."},{"t":"para","text":"Обману́ть (lừa dối) → обма́н (sự lừa dối - giữ \"н\")."},{"t":"example","text":"Kết luận: Gốc là ман-. Chữ \"н\" thuộc gốc từ."},{"t":"para","text":"Мину́ть (trôi qua) → минова́ть (trôi qua - giữ \"н\")."},{"t":"example","text":"Kết luận: Gốc là мин-. Chữ \"н\" thuộc gốc từ."},{"t":"para","text":"Вы́нуть (lấy ra) → вынима́ть (lấy ra)."},{"t":"example","text":"Ка́нуть (chìm vào, biến mất) → thường dùng trong cụm ка́нуть в ле́ту (chìm vào quên lãng). Gốc кан-."},{"t":"para","text":"Гря́нуть (nổ ra, vang lên) → греме́ть (vang rền), гром (sấm). \"Н\" là hậu tố chỉ hành động tức thời."}]},{"id":"07-s032","type":"exercise","title":"BÀI TẬP 527 (Trang 268)","num":527,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào hình thức thì quá khứ. Giải thích sự lựa chọn của bạn."},{"t":"para","text":"1. Пальто́ он (застегну́ть) на все пу́говицы, наде́л шарф, шля́пу и вы́шел.","b":1},{"t":"para","text":"Viết lại: Пальто́ он застегну́л на все пу́говицы..."},{"t":"para","text":"Dịch: Ông ấy đã cài tất cả các cúc áo khoác, quàng khăn, đội mũ và đi ra ngoài."},{"t":"example","text":"Giải thích: Động từ hoàn thành, giữ hậu tố -ну- vì chỉ hành động cụ thể một lần."},{"t":"para","text":"2. Ты сказа́л, что не хо́чешь е́хать с на́ми, и я (вы́черкнуть) твою́ фами́лию из спи́ска уча́стников экспеди́ции.","b":1},{"t":"para","text":"Viết lại: ..., и я вы́черкнул твою́ фами́лию..."},{"t":"para","text":"Dịch: Cậu đã nói là không muốn đi cùng chúng tớ, nên tớ đã gạch họ tên cậu khỏi danh sách thành viên đoàn thám hiểm."},{"t":"para","text":"3. Она́ (загляну́ть) к нам то́лько на мину́ту и вско́ре ушла́.","b":1},{"t":"para","text":"Viết lại: Она́ загляну́ла к нам..."},{"t":"para","text":"Dịch: Cô ấy đã ghé qua chỗ chúng tôi chỉ một phút rồi đi ngay."},{"t":"para","text":"4. Неуже́ли ты (обману́ть) меня́? Как ты мог?","b":1},{"t":"para","text":"Viết lại: Неуже́ли ты обману́л меня́?"},{"t":"para","text":"Dịch: Chẳng lẽ cậu đã lừa tôi sao? Sao cậu có thể làm thế?"},{"t":"example","text":"Giải thích: Gốc từ ман- (như bài 526), giữ nguyên -ну- (thực ra là -н-у-)."},{"t":"para","text":"5. Неожи́данно (замо́лкнуть) пти́цы в лесу́, уда́рил гром, (сверкну́ть) мо́лния и вслед за ней пошёл дождь.","b":1},{"t":"para","text":"Viết lại: Неожи́данно замо́лкли (hoặc умо́лкли) пти́цы в лесу́, уда́рил гром, сверкну́ла мо́лния..."},{"t":"para","text":"Dịch: Bất ngờ lũ chim trong rừng im bặt, sấm rền, chớp lóe lên và ngay sau đó mưa trút xuống."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Замолкнуть/Умолкнуть (im bặt) chỉ sự thay đổi trạng thái → mất hậu tố -ну- ở số nhiều (замолкли)."},{"t":"example","text":"Сверкнуть (lóe lên) chỉ hành động tức thời → giữ -ну- (сверкнула)."},{"t":"para","text":"6. Он попра́вил су́мку на плече́, (затяну́ть) по́туже по́яс и (улыбну́ться).","b":1},{"t":"para","text":"Viết lại: ..., затяну́л по́туже по́яс и улыбну́лся."},{"t":"para","text":"Dịch: Anh ấy chỉnh lại cái túi trên vai, thắt chặt thắt lưng và mỉm cười."},{"t":"para","text":"7. С э́того дня он пропа́л, как в во́ду (ка́нуть), о нём больше ничего́ не слы́шно.","b":1},{"t":"para","text":"Viết lại: ..., как в во́ду ка́нул..."},{"t":"para","text":"Dịch: Từ ngày đó hắn biến mất, như thể đã chìm/tan biến vào trong nước, không còn nghe tin gì về hắn nữa."},{"t":"para","text":"8. Всё (зати́хнуть) вокру́г, то́лько издалека́ доноси́лись зву́ки роя́ля.","b":1},{"t":"para","text":"Viết lại: Всё зати́хло вокру́г..."},{"t":"para","text":"Dịch: Mọi thứ xung quanh đã trở nên yên tĩnh, chỉ có tiếng đàn piano vọng lại từ xa."},{"t":"example","text":"Giải thích: Затихнуть chỉ trạng thái → giống trung mất -ну- → затихло."},{"t":"para","text":"9. Он (затро́нуть) о́чень ва́жную те́му, на́до бу́дет рассмотре́ть её подро́бнее.","b":1},{"t":"para","text":"Viết lại: Он затро́нул о́чень ва́жную те́му..."},{"t":"para","text":"Dịch: Anh ấy đã đụng chạm/đề cập đến một chủ đề rất quan trọng, sẽ cần phải xem xét nó chi tiết hơn."},{"t":"para","text":"10. Пробира́ясь че́рез гости́ную, он (опроки́нуть) стоя́щую на столе́ ва́зу и наступи́л кому́-то из госте́й на но́гу.","b":1},{"t":"para","text":"Viết lại: ..., он опроки́нул стоя́щую на столе́ ва́зу..."},{"t":"para","text":"Dịch: Khi len qua phòng khách, anh ta đã làm đổ cái bình hoa để trên bàn và giẫm vào chân một vị khách nào đó."},{"t":"para","text":"11. У нас (возни́кнуть) не́которые пробле́мы.","b":1},{"t":"para","text":"Viết lại: У нас возни́кли не́которые пробле́мы."},{"t":"para","text":"Dịch: Chúng tôi đã nảy sinh một vài vấn đề."},{"t":"example","text":"Giải thích: Возникнуть chỉ sự xuất hiện/trạng thái → mất -ну- → возникли."},{"t":"para","text":"12. Я уже́ (намекну́ть) тебе́, кто э́то был, попро́буй тепе́рь сам догада́ться.","b":1},{"t":"para","text":"Viết lại: Я уже́ намекну́л тебе́..."},{"t":"para","text":"Dịch: Tớ đã gợi ý/ám chỉ cho cậu đó là ai rồi, bây giờ cậu thử tự đoán xem."},{"t":"para","text":"13. Наступи́л октя́брь, (дохну́ть) хо́лодом, все цветы́ в саду́ (завя́нуть) за одну́ ночь.","b":1},{"t":"para","text":"Viết lại: ..., дохну́ло хо́лодом, все цветы́ в саду́ завя́ли..."},{"t":"para","text":"Dịch: Tháng mười đã đến, gió lạnh đã thổi qua, tất cả hoa trong vườn đã héo úa chỉ sau một đêm."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Дохнуть (thổi/thở) → hành động đơn nhất → giữ -ну- (дохнуло)."},{"t":"example","text":"Завянуть (héo) → kết quả trạng thái → mất -ну- (завяли)."}]},{"id":"07-s033","type":"exercise","title":"BÀI TẬP 528 (Trang 269)","num":528,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Chú ý rằng các động từ không có tiền tố với hậu tố -ну- có thể có hai hình thức thì quá khứ. Gọi tên động từ nguyên thể (infinitive) của các hình thức quá khứ này."},{"t":"subhead","text":"Gợi ý trong khung (Trang 269):","b":1},{"t":"example","text":"Đối với các động từ không có tiền tố với hậu tố -ну-, có thể hình thành hai dạng thì quá khứ. Dạng phổ biến hơn là dạng không có -ну-."},{"t":"para","text":"Dịch và xác định nguyên thể:","b":1},{"t":"para","text":"Доро́ги бы́ли ужа́сные, мото́р помину́тно глох (гло́хнул), приходи́лось выходи́ть и толка́ть маши́ну.","b":1},{"t":"para","text":"Dịch: Đường xá thật khủng khiếp, động cơ cứ chốc chốc lại chết máy, phải xuống xe và đẩy."},{"t":"para","text":"Nguyên thể: Гло́хнуть."},{"t":"para","text":"Он уме́л расска́зывать ра́зные удиви́тельные исто́рии, и де́ти ли́пли (ли́пнули) к нему́, как му́хи.","b":1},{"t":"para","text":"Dịch: Ông ấy biết kể nhiều câu chuyện kỳ lạ khác nhau, và lũ trẻ bám chặt lấy ông như ruồi."},{"t":"para","text":"Nguyên thể: Ли́пнуть."},{"t":"para","text":"День за днём расте́ние ча́хло (ча́хнуло) всё бо́льше, и ско́ро уже́ не́ было наде́жды на то, что оно́ распу́стится вновь.","b":1},{"t":"para","text":"Dịch: Ngày qua ngày cái cây héo mòn/úa tàn dần, và chẳng bao lâu không còn hy vọng nó sẽ đâm chồi trở lại."},{"t":"para","text":"Nguyên thể: Ча́хнуть."},{"t":"para","text":"Бы́ло невыноси́мо жа́рко, беспреста́нно со́хли (со́хнули) потре́скавшиеся от со́лнца гу́бы, ужа́сно хоте́лось пить.","b":1},{"t":"para","text":"Dịch: Trời nóng không chịu nổi, đôi môi nứt nẻ vì nắng cứ khô khốc liên tục, khát nước kinh khủng."},{"t":"para","text":"Nguyên thể: Со́хнуть."},{"t":"para","text":"Цвето́к о́чень прия́тно пах (па́хнул), и вся ко́мната в одно́ мгнове́ние напо́лнилась его́ арома́том.","b":1},{"t":"para","text":"Dịch: Bông hoa tỏa hương rất dễ chịu, và cả căn phòng trong nháy mắt tràn ngập hương thơm của nó."},{"t":"para","text":"Nguyên thể: Па́хнуть."},{"t":"para","text":"В па́рке никого́ не́ было, доро́жки бы́ли пусты́нны, под дождём мо́кли (мо́кнули) забы́тые в песо́чнице де́тские игру́шки.","b":1},{"t":"para","text":"Dịch: Trong công viên không một bóng người, các lối đi vắng tanh, những món đồ chơi trẻ em bị bỏ quên trong hố cát đang bị ướt sũng dưới mưa."},{"t":"para","text":"Nguyên thể: Мо́кнуть."},{"t":"para","text":"Времена́ми свет мерк (ме́ркнул) в его́ глаза́х, ему́ станови́лось не по себе́.","b":1},{"t":"para","text":"Dịch: Thi thoảng ánh sáng mờ đi/tối sầm trong mắt anh ấy, anh ấy cảm thấy không khỏe."},{"t":"para","text":"Nguyên thể: Ме́ркнуть."},{"t":"para","text":"Ребёнок не хоте́л идти́ сам, с трудо́м перебира́л нога́ми, постоя́нно вис (ви́снул) на руке́ ма́тери.","b":1},{"t":"para","text":"Dịch: Đứa bé không muốn tự đi, lê bước khó nhọc, liên tục đu/bám vào tay mẹ."},{"t":"para","text":"Nguyên thể: Ви́снуть."},{"t":"para","text":"Ему́ бы́ло хо́лодно, зя́бло (зя́бнуло) лицо́ и сты́ли (сты́нули) ру́ки без перча́ток.","b":1},{"t":"para","text":"Dịch: Anh ấy thấy lạnh, mặt rét run và đôi tay không đeo găng lạnh cóng."},{"t":"para","text":"Nguyên thể: Зя́бнуть và Сты́нуть."},{"t":"vocab","ru":"Трава́ в степи́ вя́ла (вя́нула) и желте́ла","vi":"приближа́лась о́сень.","g":null},{"t":"para","text":"Dịch: Cỏ trên thảo nguyên đang héo và úa vàng: mùa thu đang đến gần."},{"t":"para","text":"Nguyên thể: Вя́нуть."},{"t":"para","text":"Ка́ждый раз к ве́черу молоко́ ки́сло (ки́снуло) и годи́лось ра́зве то́лько на простоква́шу.","b":1},{"t":"para","text":"Dịch: Lần nào cũng thế, cứ đến chiều là sữa lại bị chua, và chỉ còn dùng làm sữa đông được thôi."},{"t":"para","text":"Nguyên thể: Ки́снуть."}]},{"id":"07-s034","type":"grammar","title":"PHẦN NGỮ PHÁP: Động từ với hậu tố -ова-, -ева-, -ва- (Trang 270)","num":null,"blocks":[{"t":"vocab","ru":"Hậu tố -ова- / -ева-","vi":"Các động từ có hậu tố này ở dạng nguyên thể (như рисовать, танцевать) sẽ biến đổi hậu tố thành -у- hoặc -ю- khi chia ở thì hiện tại hoặc tương lai đơn.","g":null},{"t":"example","text":"Ví dụ: Рисовать → рисую (Tôi vẽ). Танцевать → танцую (Tôi nhảy)."},{"t":"vocab","ru":"Hậu tố -ва- (Đặc biệt)","vi":"Các động từ được tạo từ các gốc -да-, -ста-, -зна- đi kèm hậu tố -ва- (như давать, вставать, узнавать) sẽ mất hậu tố -ва- khi chia ở thì hiện tại.","g":null},{"t":"example","text":"Ví dụ: Дава́ть → даю́. Встава́ть → встаю́. Узнава́ть → узнаю́."},{"t":"note","text":"Lưu ý: Các động từ khác có đuôi -вать nhưng không thuộc nhóm trên (như открывать, надевать) thì vẫn giữ nguyên -ва- khi chia (ví dụ: открываю, надеваю)."}]},{"id":"07-s035","type":"exercise","title":"BÀI TẬP 529 (Trang 270)","num":529,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu. So sánh dạng nguyên thể và thì hiện tại. Xác định các động từ thay đổi như thế nào ở thì hiện tại hoặc tương lai tùy thuộc vào hậu tố."},{"t":"subhead","text":"a) Nhóm biến đổi -ова-/-ева- → -у-/-ю-:","b":1},{"t":"para","text":"При э́той рабо́те необходи́мо испо́льзовать сре́дства... В на́ших иссле́дованиях мы испо́льзуем...","b":1},{"t":"example","text":"Dịch: Trong công việc này cần sử dụng các phương tiện... Trong các nghiên cứu của mình, chúng tôi sử dụng..."},{"t":"example","text":"Biến đổi: Использовать → Используем."},{"t":"para","text":"Иску́сство невозмо́жно поня́ть, его́ на́до чу́вствовать. Я чу́вствую то же, что и вы...","b":1},{"t":"example","text":"Dịch: Nghệ thuật không thể hiểu được (bằng lý trí), cần phải cảm nhận nó. Tôi cảm thấy giống như bạn..."},{"t":"example","text":"Biến đổi: Чувствовать → Чувствую."},{"t":"para","text":"Легко́ сове́товать, гора́здо трудне́е сле́довать э́тим сове́там. Я сове́тую тебе́ пое́хать отдохну́ть...","b":1},{"t":"example","text":"Dịch: Khuyên bảo thì dễ, làm theo lời khuyên mới khó. Tớ khuyên cậu nên đi nghỉ ngơi..."},{"t":"example","text":"Biến đổi: Советовать → Советую."},{"t":"para","text":"Тру́дно интересо́ваться всем сра́зу... Прия́тно встре́тить челове́ка, кото́рый то́же интересу́ется жи́вописью.","b":1},{"t":"example","text":"Dịch: Thật khó để quan tâm đến mọi thứ cùng lúc... Thật vui khi gặp một người cũng quan tâm đến hội họa."},{"t":"example","text":"Biến đổi: Интересоваться → Интересуется."},{"t":"subhead","text":"б) Nhóm giữ nguyên -ва- (không phải gốc да/ста/зна):","b":1},{"t":"para","text":"Лу́чше надева́ть снача́ла боти́нки... Я надева́ю пальто́...","b":1},{"t":"example","text":"Dịch: Tốt hơn là đi giày trước... Tôi đang mặc áo khoác..."},{"t":"example","text":"Nhận xét: Надевать → Надеваю (Giữ nguyên)."},{"t":"para","text":"Ча́йник бы́стро остыва́ет, его́ прихо́дится ча́сто подогрева́ть. Оби́лие информа́ции подогрева́ет мой интере́с...","b":1},{"t":"example","text":"Dịch: Ấm nước nguội nhanh, phải hâm nóng thường xuyên. Sự phong phú của thông tin đang hâm nóng sự quan tâm của tôi..."},{"t":"example","text":"Nhận xét: Подогревать → Подогревает (Giữ nguyên)."},{"t":"vocab","ru":"Не сто́ит сомнева́ться","vi":"нас ждёт успе́х. Я сомнева́юсь...","g":null},{"t":"example","text":"Dịch: Không nên nghi ngờ: thành công đang chờ chúng ta. Tôi nghi ngờ..."},{"t":"example","text":"Nhận xét: Сомневаться → Сомневаюсь (Giữ nguyên)."},{"t":"subhead","text":"в) Nhóm mất -ва- (gốc да/ста/зна):","b":1},{"t":"para","text":"Не сто́ит никому́ дава́ть по́вод... Я даю́ вам полчаса́...","b":1},{"t":"example","text":"Dịch: Không nên đưa/tạo cớ cho ai cả... Tôi cho các bạn nửa tiếng..."},{"t":"example","text":"Biến đổi: Давать → Даю́ (Mất -ва-)."},{"t":"para","text":"Она́ лю́бит встава́ть у́тром... За́втра мы встаём в семь часо́в...","b":1},{"t":"example","text":"Dịch: Cô ấy thích dậy sớm... Ngày mai chúng tôi dậy lúc 7 giờ..."},{"t":"example","text":"Biến đổi: Вставать → Встаём (Mất -ва-)."},{"t":"para","text":"Узнава́ть прогно́з пого́ды... Неуже́ли он всегда́ узнаёт все но́вости пе́рвым?","b":1},{"t":"example","text":"Dịch: Biết/Tìm hiểu dự báo thời tiết... Chẳng lẽ lúc nào cậu ta cũng biết mọi tin tức đầu tiên?"},{"t":"example","text":"Biến đổi: Узнавать → Узнаёт (Mất -ва-)."}]},{"id":"07-s036","type":"exercise","title":"BÀI TẬP 530 (Trang 270)","num":530,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì hiện tại hoặc tương lai đơn. (Áp dụng quy tắc -ова-/-ева- biến thành -у-/-ю-*)."},{"t":"para","text":"1. Показа́тели прибо́ра не (соотве́тствовать) тому́, что напи́сано в инстру́кции.","b":1},{"t":"para","text":"Viết lại: ... не соотве́тствуют..."},{"t":"para","text":"Dịch: Các chỉ số của thiết bị không tương ứng/khớp với những gì ghi trong hướng dẫn."},{"t":"para","text":"2. Сего́дня ты ка́к-то стра́нно (реаги́ровать) на мои́ слова́.","b":1},{"t":"para","text":"Viết lại: ... реаги́руешь..."},{"t":"para","text":"Dịch: Hôm nay cậu phản ứng lạ thế nào ấy với lời nói của tớ."},{"t":"para","text":"3. Мы (приве́тствовать) вас в на́шем институ́те.","b":1},{"t":"para","text":"Viết lại: Мы приве́тствуем вас..."},{"t":"para","text":"Dịch: Chúng tôi chào mừng các bạn đến với học viện của chúng tôi."},{"t":"para","text":"4. Он (сформули́ровать) свой вопро́с по́зже.","b":1},{"t":"para","text":"Viết lại: Он сформули́рует..."},{"t":"para","text":"Dịch: Anh ấy sẽ diễn đạt/đặt câu hỏi của mình sau. (Động từ hoàn thành → tương lai)."},{"t":"para","text":"5. На на́шем ве́чере (прису́тствовать) студе́нты из ра́зных ву́зов го́рода.","b":1},{"t":"para","text":"Viết lại: ... прису́тствуют..."},{"t":"para","text":"Dịch: Tại buổi dạ hội của chúng ta có mặt các sinh viên từ nhiều trường đại học trong thành phố."},{"t":"para","text":"6. Я (гаранти́ровать) вам безопа́сность.","b":1},{"t":"para","text":"Viết lại: Я гаранти́рую..."},{"t":"para","text":"Dịch: Tôi đảm bảo an toàn cho các bạn."},{"t":"para","text":"7. Твоё поведе́ние не (спосо́бствовать) нала́живанию отноше́ний ме́жду на́ми.","b":1},{"t":"para","text":"Viết lại: ... не спосо́бствует..."},{"t":"para","text":"Dịch: Hành vi của cậu không giúp ích/tạo điều kiện cho việc hàn gắn quan hệ giữa chúng ta."},{"t":"para","text":"8. Кому́ вы (адресова́ть) свой вопро́с?","b":1},{"t":"para","text":"Viết lại: ... адресу́ете..."},{"t":"para","text":"Dịch: Các bạn đặt (gửi) câu hỏi của mình cho ai?"},{"t":"para","text":"9. Сего́дня мы (пра́здновать) день рожде́ния на́шего дру́га.","b":1},{"t":"para","text":"Viết lại: ... пра́зднуем..."},{"t":"para","text":"Dịch: Hôm nay chúng tớ ăn mừng sinh nhật của bạn tớ."},{"t":"para","text":"10. Я (побесе́довать) с твои́м клие́нтом, пока́ ты не принесёшь все необходи́мые бума́ги.","b":1},{"t":"para","text":"Viết lại: Я побесе́дую..."},{"t":"para","text":"Dịch: Tôi sẽ trò chuyện với khách hàng của cậu trong khi cậu đi lấy giấy tờ cần thiết."},{"t":"example","text":"11. На э́тот счёт суще́ствуют не́сколько вариа́нтов отве́тов. (Câu này không có động từ trong ngoặc để chia, có lẽ là câu dẫn hoặc bị in thiếu. Động từ существуют đã chia sẵn)."},{"t":"para","text":"12. Я (сове́товать) тебе́ заня́ться де́лом.","b":1},{"t":"para","text":"Viết lại: Я сове́тую (hoặc посове́тую)..."},{"t":"para","text":"Dịch: Tôi khuyên bạn nên bắt tay vào việc đi."},{"t":"para","text":"13. Вы (путеше́ствовать) оди́н и́ли с компа́нией?","b":1},{"t":"para","text":"Viết lại: Вы путеше́ствуете..."},{"t":"para","text":"Dịch: Bạn đi du lịch một mình hay đi cùng nhóm?"},{"t":"para","text":"14. В э́той мастерско́й я обы́чно (ремонти́ровать) свою́ маши́ну.","b":1},{"t":"para","text":"Viết lại: ... ремонти́рую..."},{"t":"para","text":"Dịch: Tôi thường sửa xe của mình ở xưởng này."},{"t":"para","text":"15. \"Прилета́ю 2-го в 19 часо́в. Встреча́йте. (Целова́ть). Ни́на\".","b":1},{"t":"para","text":"Viết lại: ... Целу́ю."},{"t":"para","text":"Dịch: \"Tớ bay đến vào 19h ngày mùng 2. Đón tớ nhé. Hôn cậu. Nina\"."},{"t":"para","text":"16. Мы (голосова́ть) за са́мого молодо́го кандида́та в президе́нты.","b":1},{"t":"para","text":"Viết lại: Мы голосу́ем..."},{"t":"para","text":"Dịch: Chúng tôi bỏ phiếu cho ứng cử viên tổng thống trẻ nhất."},{"t":"para","text":"17. Выку́ривая па́чку сигаре́т в день, ты (рискова́ть) свои́м здоро́вьем.","b":1},{"t":"para","text":"Viết lại: ..., ты риску́ешь..."},{"t":"para","text":"Dịch: Hút một gói thuốc mỗi ngày, cậu đang đánh cược/gây nguy hiểm cho sức khỏe của mình đấy."},{"t":"para","text":"18. Он всегда́ (критикова́ть) рабо́ту други́х, но сам ничего́ не де́лает.","b":1},{"t":"para","text":"Viết lại: Он всегда́ критику́ет..."},{"t":"para","text":"Dịch: Hắn ta lúc nào cũng chỉ trích công việc của người khác, nhưng bản thân thì chẳng làm gì cả."},{"t":"para","text":"19. Э́та рабо́та (тре́бовать) от меня́ мно́го свобо́дного вре́мени.","b":1},{"t":"para","text":"Viết lại: ... тре́бует..."},{"t":"para","text":"Dịch: Công việc này đòi hỏi ở tôi rất nhiều thời gian rảnh."},{"t":"para","text":"20. Обы́чно он (де́йствовать) о́чень осторо́жно и обду́манно.","b":1},{"t":"para","text":"Viết lại: ... де́йствует..."},{"t":"para","text":"Dịch: Thường thì anh ấy hành động rất thận trọng và cân nhắc."},{"t":"para","text":"21. Роди́тели сли́шком (балова́ть) свое́го ребёнка.","b":1},{"t":"example","text":"Viết lại: ... балу́ют... (Lưu ý trọng âm: балова́ть -> балу́ю, балу́ет, балу́ют)."},{"t":"para","text":"Dịch: Bố mẹ quá nuông chiều con cái."},{"t":"example","text":"22. Она́ ве́чно (сова́ть) нос не в чужи́е дела́. (Sách in nhầm не в чужие, đúng ra là в чужие - vào chuyện người khác)."},{"t":"para","text":"Viết lại: Она́ ве́чно суёт нос..."},{"t":"para","text":"Dịch: Cô ta lúc nào cũng chĩa mũi vào chuyện người khác."},{"t":"para","text":"32. В э́том отде́ле не (торгова́ть) канцеля́рскими това́рами.","b":1},{"t":"para","text":"Viết lại: ... не торгу́ют..."},{"t":"para","text":"Dịch: Ở gian hàng này người ta không bán văn phòng phẩm."},{"t":"para","text":"Chào em, đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 531 đến 535 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 271-273."}]},{"id":"07-s037","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 270 - 272)","num":null,"blocks":[{"t":"para","text":"Trước khi làm bài, em cần nắm vững quy tắc chia động từ ở thì hiện tại/tương lai với các hậu tố đặc biệt:"},{"t":"subhead","text":"Nhóm động từ có hậu tố -ВА- đi sau các gốc ДА-, СТА-, ЗНА-:","b":1},{"t":"example","text":"Các động từ như дава́ть (đưa), встава́ть (đứng dậy), узнава́ть (nhận ra)..."},{"t":"subhead","text":"Quy tắc: Khi chia ở thì hiện tại, hậu tố -ва- sẽ bị lược bỏ."},{"t":"example","text":"Ví dụ: Давать → Даю (bỏ -ва-, thêm đuôi)."},{"t":"note","text":"Lưu ý: Ở thể mệnh lệnh (hãy...), hậu tố -ва- được giữ lại (Давай!)."},{"t":"subhead","text":"Nhóm động từ có hậu tố -ОВА- / -ЕВА-:","b":1},{"t":"example","text":"Các động từ như рисовать (vẽ), танцевать (nhảy), горевать (đau buồn)..."},{"t":"subhead","text":"Quy tắc: Khi chia thì hiện tại/tương lai, hậu tố -ова-/-ева- biến đổi thành -у- hoặc -ю-."},{"t":"example","text":"Ví dụ: Рисовать → Рисую. Горевать → Горюю."},{"t":"subhead","text":"Nhóm động từ có hậu tố -ВА- nhưng KHÔNG thuộc nhóm 1:","b":1},{"t":"example","text":"Thường là các động từ chưa hoàn thành (НСВ) được tạo từ động từ hoàn thành (СВ) bằng cách thêm -ва- (ví dụ: заболе́ть → заболевать)."},{"t":"subhead","text":"Quy tắc: Hậu tố -ва- được giữ nguyên khi chia thì hiện tại."},{"t":"example","text":"Ví dụ: Заболева́ть → Заболеваю."}]},{"id":"07-s038","type":"exercise","title":"BÀI TẬP 531 (Trang 271)","num":531,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, chia động từ ở thì hiện tại. (Áp dụng quy tắc nhóm 1: bỏ -ва-)."},{"t":"para","text":"1. Ты (задава́ть) задаёшь сли́шком мно́го вопро́сов.","b":1},{"t":"para","text":"Dịch: Cậu đặt quá nhiều câu hỏi đấy."},{"t":"example","text":"Giải thích: Задавать (gốc да) → bỏ -ва- → задаёшь."},{"t":"para","text":"2. Вы (отдава́ть) отдаёте себе́ отчёт в том, что произошло́?","b":1},{"t":"para","text":"Dịch: Các ông có nhận thức được (tự báo cáo cho mình) về những gì đã xảy ra không?"},{"t":"example","text":"Giải thích: Отдавать → отдаёте."},{"t":"para","text":"3. Вре́мя от вре́мени я (перестава́ть) перестаю́ вас понима́ть.","b":1},{"t":"para","text":"Dịch: Thi thoảng tôi chẳng hiểu nổi bạn nữa (ngừng hiểu)."},{"t":"example","text":"Giải thích: Переставать (gốc ста) → перестаю́."},{"t":"para","text":"4. Мы не (вдава́ться) вдаёмся в подро́бности, так как у нас ма́ло вре́мени.","b":1},{"t":"para","text":"Dịch: Chúng tôi không đi sâu vào chi tiết vì chúng tôi có ít thời gian."},{"t":"example","text":"Giải thích: Вдаваться (gốc да) → вдаёмся."},{"t":"para","text":"5. Обы́чно за день она́ о́чень (устава́ть) устаёт.","b":1},{"t":"para","text":"Dịch: Thường thì sau một ngày cô ấy rất mệt."},{"t":"example","text":"Giải thích: Уставать (gốc ста) → устаёт."},{"t":"para","text":"6. Свои́м поведе́ние́м он (выдава́ть) выдаёт себя́ с голово́й.","b":1},{"t":"para","text":"Dịch: Bằng hành vi của mình, hắn ta đang tự tố cáo/làm lộ tẩy bản thân hoàn toàn."},{"t":"example","text":"Giải thích: Выдавать → выдаёт."},{"t":"para","text":"7. Ему́ (недоставать) недостаёт здра́вого смы́сла.","b":1},{"t":"para","text":"Dịch: Cậu ta thiếu sự tỉnh táo/lý trí thông thường."},{"t":"example","text":"Giải thích: Недоставать → недостаёт."},{"t":"para","text":"8. Хара́ктер челове́ка он (распознава́ть) распознаёт по его́ по́черку.","b":1},{"t":"para","text":"Dịch: Ông ấy nhận biết tính cách con người qua chữ viết tay."},{"t":"example","text":"Giải thích: Распознавать (gốc зна) → распознаёт."},{"t":"para","text":"9. Я не де́лаю вам комплиме́нты, я то́лько (отдава́ть) отдаю́ до́лжное ва́шей проница́тельности.","b":1},{"t":"para","text":"Dịch: Tôi không khen ngợi bạn đâu, tôi chỉ đang công nhận/trả lại sự công bằng cho khả năng sắc sảo của bạn thôi."},{"t":"example","text":"Giải thích: Отдавать → отдаю́."},{"t":"para","text":"10. Он о́чень огорчён, но не (подава́ть) подаёт ви́ду.","b":1},{"t":"para","text":"Dịch: Anh ấy rất buồn nhưng không để lộ ra ngoài (không tỏ vẻ)."},{"t":"example","text":"Giải thích: Подавать → подаёт."},{"t":"para","text":"11. В на́шем институ́те (преподава́ть) преподаю́т класси́ческую литерату́ру.","b":1},{"t":"para","text":"Dịch: Ở trường chúng tôi người ta giảng dạy văn học cổ điển."},{"t":"example","text":"Giải thích: Преподавать → преподаю́т."},{"t":"para","text":"12. В на́шем институ́те (издава́ть) издаю́т уче́бную и методи́ческую литерату́ру.","b":1},{"t":"para","text":"Dịch: Ở viện chúng tôi người ta xuất bản tài liệu giáo khoa và phương pháp."},{"t":"example","text":"Giải thích: Издавать → издаю́т."},{"t":"para","text":"13. Он до́лго боле́л и тепе́рь по оце́нкам значи́тельно (отстава́ть) отстаёт от други́х ученико́в в кла́ссе.","b":1},{"t":"para","text":"Dịch: Cậu ấy ốm lâu và giờ về mặt điểm số đang tụt hậu đáng kể so với các học sinh khác."},{"t":"example","text":"Giải thích: Отставать → отстаёт."},{"t":"para","text":"14. Я (признава́ть) признаю́ ва́ше пра́во на со́бственное мне́ние по любо́му вопро́су.","b":1},{"t":"para","text":"Dịch: Tôi thừa nhận/công nhận quyền có ý kiến riêng của bạn về bất kỳ vấn đề nào."},{"t":"example","text":"Giải thích: Признавать → признаю́."},{"t":"para","text":"15. Отсу́тствие моде́ма и фа́кса (создава́ть) создаёт дополни́тельные сло́жности в на́шей рабо́те.","b":1},{"t":"para","text":"Dịch: Việc thiếu modem và máy fax gây ra/tạo ra những khó khăn thêm trong công việc của chúng tôi."},{"t":"example","text":"Giải thích: Создавать → создаёт."},{"t":"para","text":"16. Он (пристава́ть) пристаёт ко мне со вся́кой ерундо́й, и я до́лжен отвеча́ть на его́ вопро́сы.","b":1},{"t":"para","text":"Dịch: Nó cứ bám lấy/làm phiền tôi với đủ thứ chuyện vớ vẩn, và tôi cứ phải trả lời các câu hỏi của nó."},{"t":"example","text":"Giải thích: Приставать → пристаёт."}]},{"id":"07-s039","type":"exercise","title":"BÀI TẬP 532 (Trang 272)","num":532,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, chia động từ ở thì hiện tại. Xác định gốc từ (nhóm này giữ nguyên -ва-)."},{"t":"subhead","text":"Quy tắc: Các động từ này giữ lại hậu tố -ва- khi chia, vì chúng không thuộc nhóm да/ста/зна mà thường là dạng chưa hoàn thành của các động từ như заболеть, задеть, продлить..."},{"t":"para","text":"1. В э́то вре́мя го́да гри́ппом (заболева́ть) заболева́ет треть населе́ния страны́.","b":1},{"t":"para","text":"Dịch: Vào thời điểm này trong năm, một phần ba dân số cả nước bị mắc cúm."},{"t":"example","text":"Giải thích: Заболевать → заболева́ет."},{"t":"example","text":"2. Наве́рное, твоя́ слова́ (задева́ть) задева́ют его́ самолю́бие. (Hoặc số ít задевает nếu слова là danh từ tập hợp, nhưng thường là số nhiều). Sách in твоя слова là sai ngữ pháp (lỗi in ấn), đúng phải là твои́ слова́ (số nhiều) hoặc твоё сло́во (số ít)."},{"t":"example","text":"Giả sử số nhiều: задева́ют."},{"t":"para","text":"Dịch: Có lẽ những lời của bạn đang chạm tự ái cậu ấy."},{"t":"para","text":"3. Ты напра́сно (подозрева́ть) подозрева́ешь его́ во всех сме́ртных греха́х, на са́мом де́ле он неплохо́й челове́к.","b":1},{"t":"para","text":"Dịch: Cậu nghi ngờ cậu ấy đủ mọi tội lỗi là sai rồi (vô ích), thực ra cậu ấy là người không tệ."},{"t":"example","text":"Giải thích: Подозревать → подозрева́ешь."},{"t":"para","text":"4. Вода́ (затвердева́ть) затвердева́ет и превраща́ется в лёд при температу́ре ноль гра́дусов.","b":1},{"t":"para","text":"Dịch: Nước đông cứng và biến thành băng ở nhiệt độ 0 độ."},{"t":"example","text":"Giải thích: Затвердевать → затвердева́ет."},{"t":"para","text":"5. Ви́зу (продлева́ть) продлева́ют в ко́нсульстве и́ли посо́льстве по ва́шему пи́сьменному заявле́нию.","b":1},{"t":"para","text":"Dịch: Người ta gia hạn visa tại lãnh sự quán hoặc đại sứ quán theo đơn văn bản của bạn."},{"t":"example","text":"Giải thích: Продлевать → продлева́ют (số nhiều vô nhân xưng)."},{"t":"para","text":"6. Что вы (подразумева́ть) подразумева́ете под сло́вом \"социа́л-демокра́тия\"?","b":1},{"t":"para","text":"Dịch: Các ngài ngụ ý/hiểu gì dưới từ \"dân chủ xã hội\"?"},{"t":"example","text":"Giải thích: Подразумевать → подразумева́ете."},{"t":"para","text":"7. В усло́виях холо́дного кли́мата о́вощи и фру́кты не (созрева́ть) созрева́ют по́лностью.","b":1},{"t":"para","text":"Dịch: Trong điều kiện khí hậu lạnh, rau quả không chín hoàn toàn được."},{"t":"example","text":"Giải thích: Созревать → созрева́ют."},{"t":"para","text":"8. В настоя́щее вре́мя его́ фи́рма (преуспева́ть).","b":1},{"t":"para","text":"Dịch: Hiện nay công ty của ông ấy đang làm ăn phát đạt."},{"t":"example","text":"Giải thích: Преуспевать → преуспева́ет."},{"t":"para","text":"9. Стёкла в маши́не (запотева́ть) запотева́ют, и их всё вре́мя прихо́дится протира́ть.","b":1},{"t":"para","text":"Dịch: Kính xe ô tô bị mờ hơi nước, và cứ phải lau liên tục."},{"t":"example","text":"Giải thích: Запотевать → запотева́ют."},{"t":"para","text":"10. Свои́м уме́нием танцева́ть он (затмева́ть) затмева́ет всех.","b":1},{"t":"para","text":"Dịch: Bằng kỹ năng nhảy của mình, anh ấy làm lu mờ tất cả mọi người."},{"t":"example","text":"Giải thích: Затмевать → затмева́ет."},{"t":"vocab","ru":"Посмотри́","vi":"она́ кру́жится по ко́мнате и (напева́ть) напева́ет про себя́ каку́ю-то мело́дию.","g":null},{"t":"para","text":"Dịch: Nhìn kìa: cô ấy đang xoay tròn trong phòng và ngân nga một giai điệu nào đó."},{"t":"example","text":"Giải thích: Напевать → напева́ет."}]},{"id":"07-s040","type":"exercise","title":"BÀI TẬP 533 (Trang 272)","num":533,"blocks":[{"t":"instruction","text":"Yêu cầu: Chia động từ theo mẫu (áp dụng quy tắc -ева-/-ова- → -у-/-ю-)."},{"t":"para","text":"1. Танцева́ть — танцу́ю, танцу́ешь... (Mẫu)."},{"t":"vocab","ru":"Ночева́ть (ngủ qua đêm)","vi":"ночу́ю, ночу́ешь, ночу́ет, ночу́ем, ночу́ете, ночу́ют.","g":null},{"t":"vocab","ru":"Горева́ть (đau buồn)","vi":"горю́ю, горю́ешь, горю́ет...","g":null},{"t":"vocab","ru":"Воева́ть (chiến đấu)","vi":"вою́ю, вою́ешь...","g":null},{"t":"vocab","ru":"Жева́ть (nhai)","vi":"жую́, жуёшь, жуёт, жуём, жуёте, жую́т.","g":null},{"t":"vocab","ru":"Плева́ть (nhổ)","vi":"плюю́, плюёшь, плюёт, плюём, плюёте, плюю́т. (Lưu ý: trong văn nói hay dùng cụm мне плевать - tôi cóc quan tâm).","g":null},{"t":"vocab","ru":"Клева́ть (mổ - chim)","vi":"клюю́, клюёшь, клюёт...","g":null}]},{"id":"07-s041","type":"exercise","title":"BÀI TẬP 534 (Trang 272)","num":534,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, đặt động từ vào thì tương lai đơn (với động từ hoàn thành - СВ) hoặc hiện tại (với động từ chưa hoàn thành - НСВ)."},{"t":"para","text":"1. Он о́чень (обра́доваться) обра́дуется ва́шему прие́зду, ведь он так (тоскова́ть) тоску́ет по свое́й семье́.","b":1},{"t":"para","text":"Dịch: Anh ấy sẽ rất vui mừng khi bạn đến, vì anh ấy nhớ gia đình mình lắm."},{"t":"example","text":"Giải thích: Обрадоваться (СВ) → tương lai обрадуется (bỏ -ova-). Тосковать (НСВ) → hiện tại тоскует."},{"t":"para","text":"2. Урага́н (бушева́ть) бушу́ет второ́й день подря́д.","b":1},{"t":"para","text":"Dịch: Cơn bão đang hoành hành/gào thét sang ngày thứ hai liên tiếp."},{"t":"example","text":"Giải thích: Бушевать → бушует."},{"t":"para","text":"3. Я ни на что не (претендова́ть) претенду́ю .","b":1},{"t":"para","text":"Dịch: Tôi không đòi hỏi/tranh giành cái gì cả."},{"t":"example","text":"Giải thích: Претендовать → претендую."},{"t":"para","text":"4. (Попро́бовать) Попро́бую э́то блю́до, его́ в э́том рестора́не (подава́ть) подаю́т с удиви́тельным со́усом.","b":1},{"t":"para","text":"Dịch: Tôi sẽ thử món này, ở nhà hàng này người ta phục vụ nó với loại sốt tuyệt vời."},{"t":"example","text":"Giải thích: Попробовать (СВ) → tương lai попробую. Подавать (НСВ, gốc да) → hiện tại подают (mất -ва-)."},{"t":"para","text":"5. Я (расхо́довать) расхо́дую то́лько те де́ньги, кото́рые принадле́жат мне.","b":1},{"t":"para","text":"Dịch: Tôi chỉ chi tiêu số tiền thuộc về tôi."},{"t":"example","text":"Giải thích: Расходовать → расходую."},{"t":"para","text":"6. Мы (заночева́ть) заночу́ем в э́той гости́нице, а за́втра у́тром продо́лжим путь.","b":1},{"t":"para","text":"Dịch: Chúng ta sẽ ngủ lại ở khách sạn này, sáng mai đi tiếp."},{"t":"example","text":"Giải thích: Заночевать (СВ) → tương lai заночуем."},{"t":"example","text":"7. (Проинформи́ровать) Проинформи́рую меня́ о мале́йших измене́ниях в прое́кте. (Lưu ý: Ngữ cảnh này giống mệnh lệnh \"Hãy thông báo\", nhưng bài yêu cầu thì tương lai/hiện tại. Nếu là câu kể \"Tôi sẽ thông báo\": Проинформирую. Nếu là câu cầu khiến lịch sự dùng tương lai ngôi 2: Проинформируешь. Nhưng câu gốc không có chủ ngữ, có thể là mệnh lệnh Проинформируй? Tuy nhiên, theo yêu cầu bài là thì tương lai, nên có thể hiểu là \"Tôi sẽ thông báo\": Проинформи́рую hoặc câu hỏi Проинформи́руете?)."},{"t":"subhead","text":"Đáp án an toàn theo ngôi 1: Проинформи́рую (Tôi sẽ thông báo...)."},{"t":"subhead","text":"Đáp án theo nghĩa mệnh lệnh (nếu cho phép): Проинформи́руйте."},{"t":"para","text":"8. Э́та мело́дия (навева́ть) навева́ет на меня́ прия́тные воспомина́ния.","b":1},{"t":"para","text":"Dịch: Giai điệu này gợi lên trong tôi những kỷ niệm dễ chịu."},{"t":"example","text":"Giải thích: Навевать (giữ -ва-) → навевает."},{"t":"para","text":"9. У него́ нет делово́й хва́тки, и в би́знесе он всегда́ (остава́ться) остаётся с но́сом.","b":1},{"t":"example","text":"Dịch: Anh ta không có sự nhạy bén kinh doanh, và trong làm ăn anh ta luôn bị bỏ lại với cái mũi (Thành ngữ: остаться с носом = bị lừa, thất bại, trắng tay)."},{"t":"example","text":"Giải thích: Оставаться (gốc ста) → остаётся (mất -ва-)."},{"t":"para","text":"10. Вы не (разочарова́ться) разочару́етесь в на́ших ку́рсах.","b":1},{"t":"para","text":"Dịch: Các bạn sẽ không thất vọng về các khóa học của chúng tôi đâu."},{"t":"example","text":"Giải thích: Разочароваться (СВ) → tương lai разочаруетесь."},{"t":"example","text":"11. По́сле сме́рти свое́й тёти он (унасле́довать) унасле́дует всё её состоя́ние. (Hoặc quá khứ унаследовал nếu bà cô đã mất rồi. Nhưng bài yêu cầu Tương lai/Hiện tại → Tương lai: Sau khi cô mất (trong tương lai), anh ấy sẽ thừa kế)."},{"t":"para","text":"Dịch: Sau cái chết của dì, anh ấy sẽ thừa kế toàn bộ tài sản."},{"t":"example","text":"Giải thích: Унаследовать (СВ) → унаследует."},{"t":"para","text":"12. Напра́сно ты (горева́ть) горю́ешь по пустяка́м.","b":1},{"t":"para","text":"Dịch: Cậu buồn phiền vì những chuyện vặt vãnh thật vô ích."},{"t":"example","text":"Giải thích: Горевать → горюешь."},{"t":"para","text":"13. Его́ появле́ние всегда́ (предше́ствовать) предше́ствует лёгкое пока́шливание и стук деревя́нной па́лки. (Có lẽ ý là \"Trước sự xuất hiện của ông ấy luôn có tiếng ho...\")."},{"t":"example","text":"Sửa lại chủ ngữ: Sự xuất hiện của ông ấy luôn được báo trước bởi tiếng ho... -> Động từ предшествовать chia theo chủ ngữ покашливание и стук (số nhiều) hoặc появление (số ít, đóng vai trò tân ngữ gián tiếp?)."},{"t":"subhead","text":"Cấu trúc: Chemu (D.p) predshestvuet chto (N.p). (Cái gì đi trước cái gì)."},{"t":"example","text":"Ở đây: Tiếng ho (N.p) đi trước sự xuất hiện (D.p)."},{"t":"subhead","text":"Đáp án: предше́ствуют (số nhiều, vì chủ ngữ là tiếng ho và tiếng gậy)."},{"t":"para","text":"Dịch: Đi trước sự xuất hiện của ông ấy luôn là tiếng ho nhẹ và tiếng gậy gỗ."},{"t":"para","text":"14. Его́ интере́с к поли́тике не (ослабева́ть) ослабева́ет с тече́нием вре́мени.","b":1},{"t":"para","text":"Dịch: Sự quan tâm chính trị của ông ấy không suy giảm theo thời gian."},{"t":"example","text":"Giải thích: Ослабевать (giữ -ва-) → ослабевает."},{"t":"vocab","ru":"Я (гостеприи́мство)","vi":"по́льзуюсь ва́шим гостеприи́мством. (Sách in thiếu động từ gốc, nhưng trong ngoặc là гостеприимство. Động từ thường đi kèm là пользоваться hoặc злоупотреблять. Giả sử là пользоваться).","g":null},{"t":"example","text":"Hoặc câu tiếp theo: 16. Не (плева́ть) в коло́дец: пригоди́тся воды́ напи́ться. (Tục ngữ)."},{"t":"subhead","text":"Đáp án (câu 16): Не плюй (Mệnh lệnh - Đừng nhổ). Tuy nhiên nếu bắt buộc chia hiện tại/tương lai theo đề bài thì Не плюй là ngoại lệ (vì tục ngữ cố định). Nếu là câu trần thuật: Ты (плевать) → плюёшь."},{"t":"para","text":"Dịch: Đừng nhổ nước bọt xuống giếng: sẽ có lúc cần nước uống."},{"t":"para","text":"17. — Зна́ешь, экза́мен я вчера́ не сдал, о́чень тру́дный вопро́с попа́лся. — (Сочу́вствовать) Сочу́вствую!","b":1},{"t":"para","text":"Dịch: — Biết không, hôm qua tớ trượt thi, vớ phải câu khó quá. — Xin chia buồn/Thông cảm nhé!"},{"t":"example","text":"Giải thích: Сочувствовать → сочувствую."},{"t":"para","text":"18. Он великоле́пно (пла́вать) пла́вает, как ры́ба в воде́.","b":1},{"t":"para","text":"Dịch: Cậu ấy bơi tuyệt vời, như cá trong nước."},{"t":"example","text":"Giải thích: Плавать → плавает."},{"t":"para","text":"19. Мы (намерева́ться) провести́ конфере́нцию до нача́ла ма́я.","b":1},{"t":"para","text":"Dịch: Chúng tôi dự định tổ chức hội nghị trước đầu tháng Năm."},{"t":"example","text":"Giải thích: Намереваться (giữ -ва-) → намереваемся."},{"t":"para","text":"20. Ты всегда́ всех во всём (подозрева́ть), так нельзя́!","b":1},{"t":"para","text":"Dịch: Lúc nào cậu cũng nghi ngờ tất cả mọi người, không được thế!"},{"t":"example","text":"Giải thích: Подозревать (giữ -ва-) → подозреваешь."},{"t":"para","text":"21. Меня́ (волнова́ть) её здоро́вье.","b":1},{"t":"para","text":"Dịch: Sức khỏe của cô ấy làm tôi lo lắng."},{"t":"example","text":"Giải thích: Волновать → волнует."},{"t":"para","text":"22. Я (отдава́ть) до́лжное ва́шему уме́нию вести́ диску́ссию.","b":1},{"t":"para","text":"Dịch: Tôi công nhận/khâm phục khả năng dẫn dắt thảo luận của bạn."},{"t":"example","text":"Giải thích: Отдавать → отдаю."},{"t":"para","text":"23. На по́чте пи́сьма (сортирова́ть) и отправля́ют по ука́занному а́дресу.","b":1},{"t":"para","text":"Dịch: Ở bưu điện người ta phân loại thư và gửi theo địa chỉ."},{"t":"example","text":"Giải thích: Сортировать → сортируют."},{"t":"para","text":"24. Э́ти стра́ны ме́жду собо́й не (воева́ть).","b":1},{"t":"para","text":"Dịch: Các nước này không chiến tranh với nhau."},{"t":"example","text":"Giải thích: Воевать → воюют."},{"t":"para","text":"25. Сейча́с нам то́лько но́вых неприя́тностей (недоставать).","b":1},{"t":"para","text":"Dịch: Bây giờ chúng ta chỉ còn thiếu mỗi mấy chuyện khó chịu mới này nữa thôi (ý mỉa mai: đủ rắc rối rồi)."},{"t":"example","text":"Giải thích: Недоставать → недостаёт."},{"t":"para","text":"26. (Диктова́ть), ме́дленнее, я не успева́ю запи́сывать. (Đây là ngữ cảnh mệnh lệnh: \"Hãy đọc chính tả chậm thôi\")."},{"t":"example","text":"Nếu bắt buộc chia hiện tại: Дикту́ете (Thầy đọc chậm quá? Không hợp)."},{"t":"subhead","text":"Đáp án hợp lý nhất: Дикту́йте (Mệnh lệnh)."},{"t":"example","text":"Nếu là câu hỏi: Вы (диктовать) слишком быстро? -> Диктуете."},{"t":"example","text":"Dịch (theo mệnh lệnh): Hãy đọc chậm hơn, tôi không ghi kịp."}]},{"id":"07-s042","type":"exercise","title":"BÀI TẬP 535 (Trang 273)","num":535,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc câu. Xác định ý nghĩa của hậu tố phản thân -ся trong các động từ in đậm/nghiêng."},{"t":"subhead","text":"Các nhóm ý nghĩa của -ся:","b":1},{"t":"vocab","ru":"Phản thân thực sự (Возвратное)","vi":"Hành động tác động lên chính chủ thể (tự mình làm cho mình). Ví dụ: умываться (rửa mặt cho mình).","g":null},{"t":"vocab","ru":"Tương hỗ (Взаимное)","vi":"Các chủ thể thực hiện hành động lên nhau. Ví dụ: встречаться (gặp nhau).","g":null},{"t":"vocab","ru":"Bị động (Страдательное)","vi":"Hành động được thực hiện bởi ai đó lên chủ ngữ. Ví dụ: дом строится (nhà được xây).","g":null},{"t":"example","text":"Trung gian/Trạng thái/Nội động từ (Общевозвратное/Безобъектное): Chỉ trạng thái, cảm xúc, tính chất, hoặc hành động tập trung vào chủ thể mà không có đối tượng. Ví dụ: смеяться (cười), кусаться (hay cắn - tính chất chó), сердиться (giận)."},{"t":"para","text":"Phân tích câu:","b":1},{"t":"para","text":"а) 1. Сейча́с мне не́когда, я до́лжен разобра́ть свои́ ве́щи. Я до́лжен сам во всём разобра́ться.","b":1},{"t":"vocab","ru":"Разобраться","vi":"Tự mình hiểu rõ/giải quyết vấn đề. (Ý nghĩa chủ động, tự thân - Nội động từ/Phản thân nghĩa bóng).","g":null},{"t":"para","text":"2. Он взял инициати́ву в свои́ ру́ки. Понача́лу мы с энтузиа́змом взяли́сь за де́ло.","b":1},{"t":"vocab","ru":"Взялись","vi":"Bắt tay vào việc. (Ý nghĩa tập trung hành động vào chủ thể - Trung gian/Nội động từ).","g":null},{"t":"para","text":"3. Ты до́лжен реша́ть свои́ пробле́мы сам. Он ни на что не мо́жет реши́ться.","b":1},{"t":"vocab","ru":"Решиться","vi":"Quyết tâm/dám làm gì. (Trạng thái tâm lý - Trung gian).","g":null},{"t":"para","text":"4. Его́ поведе́ние удивля́ет меня́. Я не перестаю́ удивля́ться твои́м вопро́сам.","b":1},{"t":"vocab","ru":"Удивляться","vi":"Ngạc nhiên (Cảm xúc - Trung gian).","g":null},{"t":"para","text":"б) 1. Я познако́мил его со свое́й сестро́й. Мы познако́мились с ва́ми в про́шлом году́.","b":1},{"t":"vocab","ru":"Познакомились","vi":"Làm quen với nhau. (Tương hỗ).","g":null},{"t":"para","text":"2. Во вто́рник он встреча́ет свои́х роди́телей. Нам с ва́ми лу́чше встре́титься, что́бы обсуди́ть все дета́ли путеше́ствия.","b":1},{"t":"vocab","ru":"Встретиться","vi":"Gặp nhau. (Tương hỗ).","g":null},{"t":"para","text":"3. Я сове́тую тебе́ приня́ть уча́стие в э́том прое́кте. Пре́жде чем приня́ть оконча́тельное реше́ние, мы должны́ посове́товаться.","b":1},{"t":"vocab","ru":"Посоветоваться","vi":"Hội ý/thảo luận với nhau. (Tương hỗ).","g":null},{"t":"para","text":"4. Моё вмеша́тельство в э́то де́ло в любо́й моме́нт мо́жет поссо́рить меня́ с мои́ми друзья́ми. Не на́до ссо́риться!","b":1},{"t":"vocab","ru":"Ссориться","vi":"Cãi nhau. (Tương hỗ).","g":null},{"t":"para","text":"в) 1. Преподава́тель выставля́ет оце́нки в конце́ го́да. Оце́нки выставля́ются преподава́телем в конце́ го́да.","b":1},{"t":"vocab","ru":"Выставляются","vi":"Được đưa ra/được chấm. (Bị động).","g":null},{"t":"para","text":"2. На́ша лаборато́рия иссле́дует биохими́ческие проце́ссы кле́тки. На́шей лаборато́рией (в на́шей лаборато́рии) иссле́дуются биохими́ческие проце́ссы кле́тки.","b":1},{"t":"vocab","ru":"Исследуются","vi":"Được nghiên cứu. (Bị động).","g":null},{"t":"para","text":"3. На пустыре́ стро́ят но́вый дом. На пустыре́ стро́ится но́вый дом.","b":1},{"t":"vocab","ru":"Строится","vi":"Đang được xây. (Bị động).","g":null},{"t":"example","text":"4. Заво́ду тре́буются рабо́чие ра́зных специа́льностей. (Gốc требовать)."},{"t":"vocab","ru":"Требуются","vi":"Được cần đến / Cần tuyển. (Bị động).","g":null},{"t":"para","text":"г) 1. Я не люблю́ занима́ть де́ньги да́же у свои́х ро́дственников. Сего́дня мне на́до занима́ться: 2. В любо́м ме́сте он сра́зу нахо́дит себе́ но́вых знако́мых. Мой дом нахо́дится недале́ко отсю́да.","b":1},{"t":"vocab","ru":"Находится","vi":"Tọa lạc/nằm ở. (Trạng thái vị trí - Trung gian).","g":null},{"t":"para","text":"3. Обы́чно он прихо́дит са́мым после́дним. Мне прихо́дится встава́ть в семь утра́.","b":1},{"t":"vocab","ru":"Приходится","vi":"Phải/bắt buộc (Vô nhân xưng). (Trạng thái).","g":null},{"t":"example","text":"4. Я не о́чень хорошо́ гото́влю, все блю́да у меня́ получа́ются на оди́н вкус. (Gốc получать)."},{"t":"vocab","ru":"Получаются","vi":"Thành ra/có kết quả là. (Kết quả tự phát - Trung gian/Bị động hóa).","g":null},{"t":"para","text":"5. К экза́менам на́до обстоя́тельно гото́виться.","b":1},{"t":"vocab","ru":"Готовиться","vi":"Chuẩn bị (cho bản thân). (Phản thân/Trung gian).","g":null},{"t":"para","text":"д) 1. Я предпочита́ю обща́ться со свои́ми друзья́ми.","b":1},{"t":"vocab","ru":"Общаться","vi":"Giao tiếp (với nhau). (Tương hỗ).","g":null},{"t":"para","text":"2. Э́то случи́лось в про́шлом году́ весно́й.","b":1},{"t":"vocab","ru":"Случилось","vi":"Xảy ra. (Sự việc tự diễn ra - Trung gian).","g":null},{"t":"para","text":"3. Мне нра́вится, когда́ ты улыба́ешься.","b":1},{"t":"vocab","ru":"Нравится","vi":"Được yêu thích/Gây thích thú. (Trung gian/Cảm xúc).","g":null},{"t":"vocab","ru":"Улыбаешься","vi":"Mỉm cười. (Trung gian/Hành động cơ thể).","g":null},{"t":"para","text":"4. Я могу́ ошиба́ться.","b":1},{"t":"vocab","ru":"Ошибаться","vi":"Phạm sai lầm. (Trung gian).","g":null},{"t":"para","text":"5. Не сто́ит отча́иваться!","b":1},{"t":"vocab","ru":"Отчаиваться","vi":"Tuyệt vọng. (Trung gian/Cảm xúc).","g":null},{"t":"para","text":"6. Попро́буй сам обо всём догада́ться.","b":1},{"t":"vocab","ru":"Догадаться","vi":"Suy đoán/nghiệm ra. (Trung gian/Tư duy).","g":null},{"t":"para","text":"Chào em, đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 536 đến 540 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 274-277."},{"t":"para","text":"Nội dung chính của các bài tập này là phân biệt và sử dụng đúng các động từ phản thân (có đuôi -ся) và động từ không phản thân, cũng như cách quản lý cách (padiez) và giới từ đi kèm với chúng."}]},{"id":"07-s043","type":"exercise","title":"BÀI TẬP 536 (Trang 274)","num":536,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền động từ thích hợp vào chỗ trống (dạng có -ся hoặc không có -ся). Giải thích sự lựa chọn của em."},{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"vocab","ru":"Động từ không có -ся (Ngoại động từ)","vi":"Hành động tác động lên một đối tượng khác (cần bổ ngữ trực tiếp ở cách 4 - Vin.p). Ví dụ: Я мою машину (Tôi rửa xe).","g":null},{"t":"vocab","ru":"Động từ có -ся (Nội động từ/Phản thân)","vi":"Hành động quay lại chủ thể, hoặc tương tác qua lại, hoặc bị động. Ví dụ: Я моюсь (Tôi tự rửa mình/tắm).","g":null},{"t":"para","text":"1. Ты до́лжен меня́ ..., я э́то сде́лал ненаро́чно. Мы ..., и он уе́хал (прости́ть, прости́ться).","b":1},{"t":"para","text":"Điền: Ты до́лжен меня́ прости́ть... Мы прости́лись..."},{"t":"para","text":"Dịch: Cậu phải tha thứ cho tớ, tớ không cố ý làm vậy đâu. Chúng tôi đã chia tay nhau/tạm biệt nhau, và anh ấy đã rời đi."},{"t":"example","text":"Giải thích: Прости́ть (tha thứ) cần bổ ngữ (tôi). Прости́ться (chia tay) là hành động tương hỗ giữa hai bên."},{"t":"para","text":"2. К ве́черу дождь ... . Встре́ча с э́тим челове́ком ещё бо́льше ... мой страх пе́ред ним (уси́лить, уси́литься).","b":1},{"t":"para","text":"Điền: ...дождь уси́лился. ...ещё бо́льше уси́лила мой страх..."},{"t":"para","text":"Dịch: Về chiều mưa nặng hạt hơn/mạnh lên. Cuộc gặp với người này càng làm tăng thêm nỗi sợ hãi của tôi trước ông ta."},{"t":"example","text":"Giải thích: Mưa tự mạnh lên (phản thân - уси́лился). Cuộc gặp tác động làm tăng nỗi sợ (ngoại động từ - уси́лила)."},{"t":"para","text":"3. Я так ... в э́том де́ле, что вряд ли кому́-нибу́дь уда́стся с ним спра́виться. Он соверше́нно ... в свои́х дела́х и не знал, что предприня́ть (запу́тать, запу́таться).","b":1},{"t":"example","text":"Điền: Я так запу́тал... (Sách gốc có thể in nhầm chủ ngữ hoặc cấu trúc, nhưng nếu ý là \"Tôi đã làm rối tung vụ này\" thì dùng запутал. Nếu ý là \"Tôi bị rối trí\" thì запутался. Câu 1: \"...vряд ли кому-нибудь удастся с ним справиться\" - khó ai giải quyết được nó → Tôi đã làm rối nó → запу́тал). Câu 2: Он соверше́нно запу́тался..."},{"t":"para","text":"Dịch: Tôi đã làm rối vụ này đến mức khó ai mà giải quyết nổi. Anh ấy hoàn toàn bị rối trí/mắc mớ trong công việc của mình và không biết phải làm gì."},{"t":"para","text":"4. Вошёл Андре́й и всех нас ... . Я ... то́лько к ве́черу (успоко́ить, успоко́иться).","b":1},{"t":"para","text":"Điền: ...всех нас успоко́ил. Я успоко́ился..."},{"t":"para","text":"Dịch: Andrey bước vào và trấn an/làm dịu tất cả chúng tôi. Tôi chỉ bình tâm lại vào buổi chiều."},{"t":"para","text":"5. Безусло́вно, меня́ ... ва́ше мне́ние по э́тому вопро́су. Я ... вопро́сами, свя́занными с экономи́ческим разви́тием Росси́и (интересова́ть, интересова́ться).","b":1},{"t":"para","text":"Điền: ...меня́ интересу́ет... Я интересу́юсь..."},{"t":"para","text":"Dịch: Chắc chắn là ý kiến của bạn về vấn đề này làm tôi quan tâm (thu hút tôi). Tôi quan tâm đến các vấn đề liên quan đến sự phát triển kinh tế Nga."},{"t":"example","text":"Giải thích: Интересовать (cái gì làm ai quan tâm). Интересоваться (ai quan tâm đến cái gì)."},{"t":"para","text":"6. Мне ка́жется, не сто́ит ... в э́то де́ло посторо́нних. Ты ... в чужи́е дела́, тебе́ сто́ит поду́мать об э́том (вме́шивать, вме́шиваться).","b":1},{"t":"para","text":"Điền: ...не сто́ит вме́шивать... Ты вме́шиваешься..."},{"t":"para","text":"Dịch: Tôi nghĩ không nên lôi kéo/kéo người ngoài vào việc này. Cậu đang can thiệp/xen vào chuyện người khác đấy, cậu nên suy nghĩ về điều đó."},{"t":"para","text":"7. Она́ всегда́ стара́ется ... на себя́ внима́ние. По э́тому вопро́су вам сто́ит ... в суд (обрати́ть, обрати́ться).","b":1},{"t":"para","text":"Điền: ...обрати́ть на себя́... ...вам сто́ит обрати́ться..."},{"t":"para","text":"Dịch: Cô ấy luôn cố gắng thu hút (hướng) sự chú ý về phía mình. Về vấn đề này bạn nên khiếu nại/nhờ cậy đến tòa án."},{"t":"para","text":"8. Ты прерыва́ешь меня́ на полусло́ве, не даёшь мне ... . Тебе́ бу́дет тру́дно с ним ... (договори́ть, договори́ться).","b":1},{"t":"para","text":"Điền: ...не даёшь мне договори́ть. ...с ним договори́ться."},{"t":"para","text":"Dịch: Cậu ngắt lời tớ giữa chừng, không để tớ nói hết câu. Cậu sẽ khó mà thỏa thuận/đàm phán được với anh ta."},{"t":"para","text":"9. Я вас бо́льше не ... . На э́той неде́ле он ча́сто ... на рабо́те (заде́рживать, заде́рживаться).","b":1},{"t":"para","text":"Điền: ...не заде́рживаю. ...ча́сто заде́рживается..."},{"t":"para","text":"Dịch: Tôi không giữ/làm mất thời gian của các bạn nữa. Tuần này anh ấy thường xuyên ở lại muộn tại cơ quan."},{"t":"para","text":"10. Нельзя́ ... на слу́чай. Я ..., мы зако́нчили на́ши дела́ (полага́ть, полага́ться).","b":1},{"t":"para","text":"Điền: Нельзя́ полага́ться... Я полага́ю..."},{"t":"para","text":"Dịch: Không được dựa dẫm/trông chờ vào sự may mắn ngẫu nhiên. Tôi cho rằng/nghĩ rằng, chúng ta đã xong việc rồi."},{"t":"para","text":"11. Тебе́ сто́ит ... о своём поведе́нии. Мне ка́жется, он ... что́-то стра́шное (заду́мать, заду́маться).","b":1},{"t":"para","text":"Điền: ...сто́ит заду́маться... ...он заду́мал..."},{"t":"para","text":"Dịch: Cậu nên suy ngẫm về hành vi của mình. Tôi thấy hình như hắn ta đã toan tính/ủ mưu điều gì đó khủng khiếp."},{"t":"para","text":"12. И сего́дня он не перестаёт ... свои́х друзе́й. Я не перестаю́ ... красоте́ приро́ды (удивля́ть, удивля́ться).","b":1},{"t":"para","text":"Điền: ...удивля́ть... ...удивля́ться..."},{"t":"para","text":"Dịch: Và hôm nay cậu ấy vẫn không ngừng làm bạn bè ngạc nhiên. Tôi không ngừng ngạc nhiên/trầm trồ trước vẻ đẹp của thiên nhiên."},{"t":"para","text":"13. Де́вочка родила́сь в ию́ле, и её ... Ве́рой (назва́ть, назва́ться).","b":1},{"t":"para","text":"Điền: ...её назва́ли... (Dùng động từ chủ động ở ngôi thứ 3 số nhiều mang nghĩa bị động \"người ta đặt tên\")."},{"t":"para","text":"Dịch: Cô bé sinh vào tháng 7, và người ta đặt tên cho cô là Vera."}]},{"id":"07-s044","type":"exercise","title":"BÀI TẬP 537 (Trang 275)","num":537,"blocks":[{"t":"instruction","text":"Yêu cầu: Đặt câu với các động từ cho sẵn, chú ý đến cách (padiez) đi sau chúng."},{"t":"subhead","text":"a) Nhóm yêu cầu Cách 2 (Родительный падеж):","b":1},{"t":"vocab","ru":"Набира́ться/набра́ться (чего?)","vi":"о́пыта, терпе́ния (tích lũy kinh nghiệm, kiên nhẫn).","g":null},{"t":"vocab","ru":"Каса́ться/косну́ться (чего?)","vi":"руки́, те́мы (chạm vào tay, đề cập đến chủ đề).","g":null},{"t":"vocab","ru":"Лиша́ться/лиши́ться (чего?)","vi":"пра́ва, да́ра ре́чи (mất quyền, mất khả năng nói).","g":null},{"t":"vocab","ru":"Добива́ться/доби́ться (чего?)","vi":"успе́ха, це́ли (đạt được thành công, mục đích).","g":null},{"t":"vocab","ru":"Боя́ться/испуга́ться (чего?)","vi":"темноты́, соба́ки (sợ bóng tối, sợ chó).","g":null},{"t":"vocab","ru":"Приде́рживаться (чего?)","vi":"пра́вил, мне́ния (tuân thủ quy tắc, giữ ý kiến).","g":null},{"t":"vocab","ru":"Стыди́ться (чего?)","vi":"своего́ посту́пка (xấu hổ về hành động của mình).","g":null},{"t":"vocab","ru":"Избавля́ться/изба́виться (от чего?)","vi":"от боле́зни, от хла́ма (thoát khỏi bệnh tật, đồ cũ).","g":null},{"t":"vocab","ru":"Отка́зываться/отказа́ться (от чего?)","vi":"от по́мощи (từ chối sự giúp đỡ).","g":null},{"t":"vocab","ru":"Отлича́ться (от чего/кого?)","vi":"от други́х (khác biệt với những người khác).","g":null},{"t":"vocab","ru":"Отклоня́ться/отклони́ться (от чего?)","vi":"от ку́рса, от те́мы (lệch hướng, lạc đề).","g":null},{"t":"subhead","text":"б) Nhóm yêu cầu Cách 3 (Дательный падеж):","b":1},{"t":"vocab","ru":"Подверга́ться/подве́ргнуться (чему?)","vi":"опа́сности, кри́тике (gặp nguy hiểm, bị chỉ trích).","g":null},{"t":"vocab","ru":"Удивля́ться/удиви́ться (чему?)","vi":"но́вости (ngạc nhiên trước tin tức).","g":null},{"t":"vocab","ru":"Улыба́ться/улыбну́ться (кому?)","vi":"де́вушке (mỉm cười với cô gái).","g":null},{"t":"vocab","ru":"Научи́ться (чему?)","vi":"рисова́нию, пла́вать (học vẽ, học bơi).","g":null},{"t":"vocab","ru":"Подчиня́ться/подчини́ться (кому/чему?)","vi":"прика́зу, нача́льнику (tuân lệnh, phục tùng sếp).","g":null},{"t":"vocab","ru":"Ра́доваться/обра́доваться (чему?)","vi":"пода́рку (vui mừng vì món quà).","g":null},{"t":"vocab","ru":"Сопротивля́ться (чему?)","vi":"давле́нию (kháng cự lại áp lực).","g":null},{"t":"vocab","ru":"Подгото́виться (к чему?)","vi":"к экза́мену (chuẩn bị cho kỳ thi).","g":null},{"t":"vocab","ru":"Приближа́ться/прибли́зиться (к чему?)","vi":"к до́му (tiến lại gần nhà).","g":null},{"t":"vocab","ru":"Относи́ться/отнести́сь (к кому/чему?)","vi":"к э́тому серьёзно (có thái độ nghiêm túc với việc này).","g":null},{"t":"subhead","text":"в) Nhóm yêu cầu Cách 4 (Винительный падеж) với giới từ:","b":1},{"t":"vocab","ru":"Вдава́ться (во что?)","vi":"в подро́бности (đi sâu vào chi tiết).","g":null},{"t":"vocab","ru":"Влюбля́ться/влюби́ться (в кого/что?)","vi":"в неё (yêu cô ấy).","g":null},{"t":"vocab","ru":"Переодева́ться/переоде́ться (во что?)","vi":"в костю́м (thay đồ vest).","g":null},{"t":"vocab","ru":"Превраща́ться/преврати́ться (во что?)","vi":"в лёд (biến thành băng).","g":null},{"t":"vocab","ru":"Обижа́ться/оби́деться (на кого/что?)","vi":"на шу́тку (giận vì câu đùa).","g":null},{"t":"vocab","ru":"Серди́ться/рассерди́ться (на кого?)","vi":"на бра́та (giận anh trai).","g":null},{"t":"vocab","ru":"Полага́ться/положи́ться (на кого?)","vi":"на друга (dựa dẫm vào bạn).","g":null},{"t":"vocab","ru":"Набра́сываться/набро́ситься (на кого?)","vi":"на врага́ (lao vào kẻ thù).","g":null},{"t":"vocab","ru":"Бра́ться/взя́ться (за что?)","vi":"за рабо́ту (bắt tay vào việc).","g":null},{"t":"vocab","ru":"Боро́ться (за что?)","vi":"за мир (đấu tranh vì hòa bình).","g":null},{"t":"vocab","ru":"Руча́ться/поручи́ться (за кого?)","vi":"за сотру́дника (bảo lãnh cho nhân viên).","g":null},{"t":"vocab","ru":"Пробира́ться/пробра́ться (сквозь что?)","vi":"сквозь ча́щу (len qua bụi rậm).","g":null},{"t":"vocab","ru":"Выса́живаться/вы́садиться (куда?)","vi":"на бе́рег (đổ bộ lên bờ).","g":null},{"t":"vocab","ru":"Приземля́ться/приземли́ться (куда?)","vi":"на по́ле (hạ cánh xuống cánh đồng).","g":null},{"t":"vocab","ru":"Обраща́ться/обрати́ться (в/к?)","vi":"к врачу́ (đến bác sĩ), в слух (biến thành thính giác - lắng nghe chăm chú).","g":null},{"t":"vocab","ru":"Снижа́ться/сни́зиться","vi":"Температу́ра сни́зилась (Nhiệt độ giảm).","g":null},{"t":"vocab","ru":"Повыша́ться/повы́ситься (на сколько?)","vi":"на 5 гра́дусов (tăng thêm 5 độ).","g":null},{"t":"subhead","text":"г) Nhóm yêu cầu Cách 5 (Творительный падеж):","b":1},{"t":"vocab","ru":"По́льзоваться/воспо́льзоваться (чем?)","vi":"слу́чаем (tận dụng cơ hội).","g":null},{"t":"vocab","ru":"Станови́ться/стать (кем?)","vi":"врачо́м (trở thành bác sĩ).","g":null},{"t":"vocab","ru":"Увлека́ться/увле́чься (чем?)","vi":"му́зыкой (say mê âm nhạc).","g":null},{"t":"vocab","ru":"Возмуща́ться/возмути́ться (чем?)","vi":"поведе́нием (phẫn nộ với hành vi).","g":null},{"t":"vocab","ru":"Восхища́ться/восхити́ться (кем/чем?)","vi":"актёром (ngưỡng mộ diễn viên).","g":null},{"t":"vocab","ru":"Любова́ться/полюбова́ться (чем?)","vi":"зака́том (ngắm hoàng hôn).","g":null},{"t":"vocab","ru":"Горди́ться (кем/чем?)","vi":"сы́ном (tự hào về con trai).","g":null},{"t":"vocab","ru":"Запаса́ться/запасти́сь (чем?)","vi":"едо́й (dự trữ đồ ăn).","g":null},{"t":"vocab","ru":"Каза́ться/показа́ться (кем/чем?)","vi":"стра́нным (có vẻ kỳ lạ).","g":null},{"t":"vocab","ru":"Называ́ться/назва́ться (кем?)","vi":"гру́здем (xưng là nấm - tục ngữ).","g":null},{"t":"vocab","ru":"Представля́ться/предста́виться (кем?)","vi":"дире́ктором (tự giới thiệu là giám đốc).","g":null},{"t":"vocab","ru":"Отлича́ться (чем?)","vi":"умо́м (khác biệt ở trí thông minh).","g":null},{"t":"vocab","ru":"Дели́ться/подели́ться (с кем?)","vi":"с дру́гом (chia sẻ với bạn).","g":null},{"t":"vocab","ru":"Обща́ться/пообща́ться (с кем?)","vi":"с колле́гами (giao tiếp với đồng nghiệp).","g":null},{"t":"vocab","ru":"Объединя́ться/объедини́ться (с кем?)","vi":"с партнёрами (liên kết với đối tác).","g":null},{"t":"vocab","ru":"Свя́зываться/связа́ться (с кем?)","vi":"с родны́ми (liên lạc với người thân).","g":null},{"t":"vocab","ru":"Извиня́ться/извини́ться (пе́ред кем?)","vi":"пе́ред учи́телем (xin lỗi giáo viên).","g":null},{"t":"vocab","ru":"Смея́ться/посмея́ться (над кем/чем?)","vi":"над шу́ткой (cười vì câu đùa).","g":null},{"t":"subhead","text":"д) Nhóm yêu cầu Cách 6 (Предложный падеж):","b":1},{"t":"vocab","ru":"Кля́сться/покля́сться (в чём?)","vi":"в ве́рности (thề chung thủy).","g":null},{"t":"vocab","ru":"Заключа́ться (в чём?)","vi":"в сле́дующем (bao gồm ở chỗ sau đây).","g":null},{"t":"vocab","ru":"Раска́иваться/раска́яться (в чём?)","vi":"в греха́х (hối hận về tội lỗi).","g":null},{"t":"vocab","ru":"Расходи́ться/разойти́сь (в чём?)","vi":"в мне́ниях (bất đồng quan điểm).","g":null},{"t":"vocab","ru":"Сомнева́ться (в чём?)","vi":"в успе́хе (nghi ngờ sự thành công).","g":null},{"t":"vocab","ru":"Убежда́ться/убеди́ться (в чём?)","vi":"в правоте́ (tin chắc vào sự đúng đắn).","g":null},{"t":"vocab","ru":"Жени́ться (на ком?)","vi":"на одноку́рснице (cưới bạn cùng khóa - dùng cho nam).","g":null},{"t":"vocab","ru":"Беспоко́иться/побеспоко́иться (о чём/ком?)","vi":"о здоро́вье (lo lắng cho sức khỏe).","g":null},{"t":"vocab","ru":"Волнова́ться (о чём?)","vi":"о результа́тах (hồi hộp về kết quả).","g":null},{"t":"vocab","ru":"Забо́титься/позабо́титься (о ком?)","vi":"о де́тях (chăm sóc trẻ em).","g":null},{"t":"vocab","ru":"Дога́дываться/догада́ться (о чём?)","vi":"о сюрпри́зе (đoán ra điều bất ngờ).","g":null},{"t":"vocab","ru":"Догова́риваться/договори́ться (о чём?)","vi":"о встре́че (thỏa thuận về cuộc gặp).","g":null},{"t":"vocab","ru":"Заде́рживаться/задержа́ться (где?)","vi":"на рабо́те (ở lại muộn tại chỗ làm).","g":null},{"t":"vocab","ru":"Скрыва́ться/скры́ться (где?)","vi":"в лесу́ (trốn trong rừng).","g":null},{"t":"vocab","ru":"Устра́иваться/устро́иться (где?)","vi":"в гости́нице (ổn định chỗ ở trong khách sạn).","g":null},{"t":"vocab","ru":"Распи́сываться/расписа́ться (где?)","vi":"в ве́домости (ký tên vào danh sách).","g":null}]},{"id":"07-s045","type":"exercise","title":"BÀI TẬP 538 (Trang 276)","num":538,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng dạng đúng của từ (chọn giới từ và cách phù hợp)."},{"t":"para","text":"1. Не сто́ит удивля́ться (тако́е стече́ние обстоя́тельств).","b":1},{"t":"subhead","text":"Đáp án: ...тако́му стече́нию обстоя́тельств. (Cách 3)"},{"t":"para","text":"Dịch: Không nên ngạc nhiên trước sự trùng hợp của các tình huống như vậy."},{"t":"para","text":"2. Мне ка́жется, мы с ва́ми суще́ственно расхо́димся (мне́ние).","b":1},{"t":"subhead","text":"Đáp án: ...во мне́нии (hoặc во мне́ниях). (Cách 6 + в)"},{"t":"para","text":"Dịch: Tôi cảm thấy tôi và bạn bất đồng đáng kể về quan điểm."},{"t":"para","text":"3. В любо́м слу́чае тебе́ сто́ит добива́ться (своя́ цель).","b":1},{"t":"subhead","text":"Đáp án: ...свое́й це́ли. (Cách 2)"},{"t":"para","text":"Dịch: Trong bất kỳ trường hợp nào bạn cũng nên nỗ lực đạt được mục đích của mình."},{"t":"para","text":"4. Мы с ва́ми приблизи́лись вплотну́ю (коне́ц уче́бного го́да).","b":1},{"t":"subhead","text":"Đáp án: ...к концу́ уче́бного го́да. (Cách 3 + к)"},{"t":"para","text":"Dịch: Chúng ta đã tiến rất sát đến kết thúc năm học."},{"t":"para","text":"5. Я не нужда́юсь (ва́ше реше́ние).","b":1},{"t":"subhead","text":"Đáp án: ...в ва́шем реше́нии. (Cách 6 + в)"},{"t":"para","text":"Dịch: Tôi không cần quyết định của bạn."},{"t":"para","text":"6. Ты никогда́ не заду́мывалась (свои́ недоста́тки)?","b":1},{"t":"subhead","text":"Đáp án: ...о свои́х недоста́тках. (Cách 6 + о)"},{"t":"para","text":"Dịch: Cậu chưa bao giờ suy ngẫm về những khuyết điểm của mình sao?"},{"t":"para","text":"7. Инфля́ция сни́зилась (два́дцать проце́нтов).","b":1},{"t":"subhead","text":"Đáp án: ...на два́дцать проце́нтов. (Cách 4 + на: giảm đi một lượng) hoặc до двадцати процентов (Cách 2 + до: giảm xuống mức). Thường dùng на với con số cụ thể trong ngữ cảnh này."},{"t":"para","text":"Dịch: Lạm phát đã giảm (đi) 20 phần trăm."},{"t":"para","text":"8. Я могу́ (он) поручи́ться.","b":1},{"t":"subhead","text":"Đáp án: ...за него́ поручи́ться. (Cách 4 + за)"},{"t":"para","text":"Dịch: Tôi có thể bảo lãnh cho anh ấy."},{"t":"para","text":"9. Зда́ния постро́ены в одно́ вре́мя, но отлича́ются (архитекту́рное реше́ние).","b":1},{"t":"subhead","text":"Đáp án: ...архитекту́рным реше́нием. (Cách 5: khác nhau ở điểm gì)."},{"t":"para","text":"Dịch: Các tòa nhà được xây cùng thời điểm, nhưng khác nhau về giải pháp kiến trúc."},{"t":"para","text":"10. Мы с ва́ми косну́лись (о́чень ва́жный вопро́с).","b":1},{"t":"subhead","text":"Đáp án: ...о́чень ва́жного вопро́са. (Cách 2)"},{"t":"para","text":"Dịch: Chúng ta đã chạm đến một vấn đề rất quan trọng."},{"t":"para","text":"11. Мы приближа́емся (основна́я те́ма).","b":1},{"t":"subhead","text":"Đáp án: ...к основно́й те́ме. (Cách 3 + к)"},{"t":"para","text":"Dịch: Chúng ta đang đến gần chủ đề chính."},{"t":"para","text":"12. Я ниско́лько не сомнева́юсь (ва́ше уме́ние вести́ перегово́ры).","b":1},{"t":"subhead","text":"Đáp án: ...в ва́шем уме́нии вести́ перегово́ры. (Cách 6 + в)"},{"t":"para","text":"Dịch: Tôi không hề nghi ngờ khả năng đàm phán của bạn."},{"t":"example","text":"13. Вы всегда́ мо́жете положи́ться (свой друг - số nhiều hoặc ít?). Sách in свой друзья là sai, phải là своих друзей hoặc своего друга. Giả sử số ít: своего друга."},{"t":"subhead","text":"Đáp án: ...на своего́ дру́га (hoặc на свои́х друзе́й). (Cách 4 + на)"},{"t":"para","text":"Dịch: Bạn luôn có thể dựa cậy vào bạn (bè) của mình."},{"t":"example","text":"14. Неуже́ли ты (я) рассерди́лся (подро́бности), продо́лжим разгово́р по́зже. (Lưu ý: Có thể sách in lỗi, động từ nên là зациклился hoặc остановился. Nhưng nếu theo Key trong sách là из-за, thì ý là \"giận vì chuyện vặt\")."},{"t":"subhead","text":"Đáp án: ...рассердился из-за подро́бностей... (Cách 2 + из-за)"},{"t":"para","text":"Dịch: Chẳng lẽ cậu giận vì mấy chi tiết vặt sao, chúng ta sẽ nói chuyện sau."},{"t":"para","text":"15. Не бу́дем сейча́с каса́ться (э́тот вопро́с). (Câu gốc trong sách bị in thiếu, đây là câu bổ sung theo ngữ cảnh bài học)."},{"t":"subhead","text":"Đáp án: ...э́того вопро́са. (Cách 2)"},{"t":"para","text":"Dịch: Chúng ta sẽ không đề cập đến vấn đề này bây giờ."},{"t":"para","text":"16. Я могу́ покля́сться (его́ невино́вность).","b":1},{"t":"subhead","text":"Đáp án: ...в его́ невино́вности. (Cách 6 + в)"},{"t":"para","text":"Dịch: Tôi có thể thề về sự vô tội của anh ấy."},{"t":"para","text":"17. По э́тому вопро́су я приде́рживаюсь (друго́е мне́ние).","b":1},{"t":"subhead","text":"Đáp án: ...друго́го мне́ния. (Cách 2)"},{"t":"para","text":"Dịch: Về vấn đề này tôi giữ ý kiến khác."},{"t":"para","text":"18. Мы должны́ изба́виться (нену́жные ве́щи).","b":1},{"t":"subhead","text":"Đáp án: ...от нену́жных веще́й. (Cách 2 + от)"},{"t":"para","text":"Dịch: Chúng ta cần tống khứ những đồ vật không cần thiết."},{"t":"para","text":"19. Я вы́нужден подчини́ться (реше́ние большинства́).","b":1},{"t":"subhead","text":"Đáp án: ...реше́нию большинства́. (Cách 3)"},{"t":"para","text":"Dịch: Tôi buộc phải phục tùng quyết định của đa số."},{"t":"para","text":"20. Не могу́ поже́ртвовать (своя́ жизнь).","b":1},{"t":"subhead","text":"Đáp án: ...свое́й жи́знью. (Cách 5)"},{"t":"para","text":"Dịch: Tôi không thể hy sinh mạng sống của mình."},{"t":"para","text":"21. Распиши́тесь, пожа́луйста, (э́тот докуме́нт).","b":1},{"t":"subhead","text":"Đáp án: ...в э́том докуме́нте. (Cách 6 + в)"},{"t":"para","text":"Dịch: Làm ơn ký tên vào tài liệu này."},{"t":"para","text":"22. Он о́чень отлича́лся (свои́ све́рстники), каза́лся (тако́й заду́мчивый и серьёзный).","b":1},{"t":"subhead","text":"Đáp án: ...от свои́х све́рстников... таки́м заду́мчивым и серьёзным. (Cách 2 + от; Cách 5)"},{"t":"para","text":"Dịch: Cậu ấy rất khác biệt so với bạn bè đồng trang lứa, có vẻ trầm tư và nghiêm túc như vậy."},{"t":"para","text":"23. (Что) ты испуга́лся?","b":1},{"t":"subhead","text":"Đáp án: Чего́... (Cách 2)"},{"t":"para","text":"Dịch: Cậu sợ cái gì thế?"},{"t":"para","text":"24. Мы отклони́лись (те́ма на́шего разгово́ра).","b":1},{"t":"subhead","text":"Đáp án: ...от те́мы на́шего разгово́ра. (Cách 2 + от)"},{"t":"para","text":"Dịch: Chúng ta đã lạc khỏi chủ đề cuộc nói chuyện."},{"t":"para","text":"25. Я не могу́ (она́) до́лго серди́ться.","b":1},{"t":"subhead","text":"Đáp án: ...на неё... (Cách 4 + на)"},{"t":"para","text":"Dịch: Tôi không thể giận cô ấy lâu được."},{"t":"para","text":"26. Мы с трудо́м пробра́лись (толпа́).","b":1},{"t":"subhead","text":"Đáp án: ...сквозь толпу́. (Cách 4 + сквозь)"},{"t":"para","text":"Dịch: Chúng tôi khó khăn lắm mới len qua được đám đông."},{"t":"para","text":"27. Как ты отно́сишься (моё предложе́ние)?","b":1},{"t":"subhead","text":"Đáp án: ...к мое́му предложе́нию? (Cách 3 + к)"},{"t":"para","text":"Dịch: Cậu thấy sao (có thái độ thế nào) về đề nghị của tớ?"},{"t":"para","text":"28. Все мы в ра́вной сте́пени подверга́емся (опа́сность).","b":1},{"t":"subhead","text":"Đáp án: ...опа́сности. (Cách 3)"},{"t":"para","text":"Dịch: Tất cả chúng ta đều gặp nguy hiểm ở mức độ như nhau."},{"t":"para","text":"29. В про́шлом году́ он жени́лся (моя́ сестра́).","b":1},{"t":"subhead","text":"Đáp án: ...на мое́й сестре́. (Cách 6 + на)"},{"t":"para","text":"Dịch: Năm ngoái anh ấy đã cưới em gái tôi."},{"t":"para","text":"30. Я (никто́) не хочу́ дели́ться.","b":1},{"t":"subhead","text":"Đáp án: Я ни с кем... (Cách 5 + с)"},{"t":"para","text":"Dịch: Tôi không muốn chia sẻ với ai cả."}]},{"id":"07-s046","type":"exercise","title":"BÀI TẬP 539 (Trang 277)","num":539,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng dạng đúng của động từ (chủ động hoặc phản thân -ся)."},{"t":"para","text":"1. Мно́жество проже́кторов (освети́ть) освети́ли зал.","b":1},{"t":"para","text":"Dịch: Rất nhiều đèn pha đã chiếu sáng hội trường. (Đèn chiếu sáng vật khác → chủ động)."},{"t":"para","text":"2. На́ше путеше́ствие (приближа́ть) приближа́лось к концу́.","b":1},{"t":"para","text":"Dịch: Chuyến đi của chúng tôi đang dần đi đến hồi kết. (Tự tiến gần → phản thân)."},{"t":"para","text":"3. Вам ещё на́до рабо́тать самостоя́тельно, ну́жно (набра́ть) набра́ться о́пыта.","b":1},{"t":"example","text":"Dịch: Bạn còn cần làm việc độc lập, cần tích lũy kinh nghiệm. (Tích lũy cho bản thân → phản thân набраться + Gen)."},{"t":"para","text":"4. Я не хочу́ (отка́зывать) отка́зываться от свои́х слов.","b":1},{"t":"para","text":"Dịch: Tôi không muốn rút lại (từ bỏ) lời nói của mình. (Tự từ bỏ → phản thân)."},{"t":"para","text":"5. Мы хоти́м (изба́вить) изба́виться от ли́шних хлопо́т.","b":1},{"t":"para","text":"Dịch: Chúng tôi muốn thoát khỏi những phiền toái thừa thãi. (Tự thoát → phản thân)."},{"t":"para","text":"6. Ну́жно уме́ть (отлича́ть) отлича́ть хоро́шее от плохо́го.","b":1},{"t":"para","text":"Dịch: Cần phải biết phân biệt cái tốt với cái xấu. (Phân biệt cái này với cái kia → chủ động)."},{"t":"para","text":"7. Че́рез не́сколько лет он (преврати́ть) преврати́лся в высо́кого молодо́го челове́ка.","b":1},{"t":"para","text":"Dịch: Sau vài năm cậu ấy đã biến thành một chàng trai cao lớn. (Tự biến đổi → phản thân)."},{"t":"para","text":"8. Я собира́юсь (устро́ить) устро́ить вечери́нку.","b":1},{"t":"para","text":"Dịch: Tôi định tổ chức một bữa tiệc. (Làm ra cái gì đó → chủ động)."},{"t":"example","text":"9. Дай мне (договори́ть) вы́говориться (hoặc договори́ть), я ещё не зако́нчил. (Sách in договорить trong ngoặc thì dùng договорить. Nếu ngữ cảnh là \"trút bầu tâm sự\" thì выговориться)."},{"t":"subhead","text":"Đáp án: ...договори́ть..."},{"t":"para","text":"Dịch: Để tôi nói hết đã, tôi vẫn chưa xong."},{"t":"para","text":"10. Я (восхища́ть) восхища́юсь ва́шей вы́держкой.","b":1},{"t":"para","text":"Dịch: Tôi ngưỡng mộ sự điềm tĩnh của bạn. (Cảm xúc hướng vào đối tượng → phản thân + Instr)."},{"t":"para","text":"11. Всегда́ на́до наде́яться на лу́чшее, а (гото́вить) гото́виться к ху́дшему.","b":1},{"t":"para","text":"Dịch: Luôn phải hy vọng vào điều tốt nhất, nhưng chuẩn bị cho điều xấu nhất. (Chuẩn bị bản thân → phản thân)."},{"t":"example","text":"12. Не сто́ит (повыша́ть) повыша́ть це́ны. (Hoặc Цены повышаются - giá tăng. Ở đây chủ ngữ ẩn là người -> повышать)."},{"t":"subhead","text":"Đáp án: ...повыша́ть..."},{"t":"para","text":"Dịch: Không nên tăng giá."},{"t":"para","text":"13. Что (свя́зывать) свя́зывает тебя́ с э́тим челове́ком?","b":1},{"t":"para","text":"Dịch: Điều gì liên kết/gắn bó cậu với người này? (Cái gì tác động lên cậu → chủ động)."},{"t":"para","text":"14. Наве́рное, он (оби́деть) оби́делся на твой слова́.","b":1},{"t":"para","text":"Dịch: Có lẽ cậu ấy đã giận/tủi thân vì lời nói của bạn. (Cảm xúc tự thân → phản thân)."},{"t":"para","text":"15. Мы (отклони́ть) отклони́лись от маршру́та.","b":1},{"t":"para","text":"Dịch: Chúng tôi đã đi chệch khỏi lộ trình. (Tự lệch → phản thân)."},{"t":"para","text":"16. Я (полага́ть) полага́юсь на ваш о́пыт.","b":1},{"t":"para","text":"Dịch: Tôi tin cậy/dựa vào kinh nghiệm của ông. (Tin tưởng → phản thân)."},{"t":"para","text":"17. Нам не́чего не ну́жно, мы хорошо́ (устро́ить) устро́ились.","b":1},{"t":"para","text":"Dịch: Chúng tôi không cần gì cả, chúng tôi đã ổn định chỗ ở/sắp xếp ổn thỏa rồi. (Tự ổn định → phản thân)."},{"t":"para","text":"18. Не сто́ит (обижа́ть) обижа́ться на него́, он не хоте́л поста́вить вас в неудо́бное положе́ние.","b":1},{"t":"para","text":"Dịch: Không nên giận anh ấy, anh ấy không muốn đẩy bạn vào tình huống khó xử đâu."},{"t":"para","text":"19. По э́тому вопро́су я (приде́рживать) приде́рживаюсь друго́го мне́ния.","b":1},{"t":"para","text":"Dịch: Về vấn đề này tôi giữ (theo) ý kiến khác."},{"t":"para","text":"20. Вы всегда́ мо́жете (обрати́ть) обрати́ться ко мне за сове́том.","b":1},{"t":"para","text":"Dịch: Bạn luôn có thể tìm đến (hỏi) tôi để xin lời khuyên."}]},{"id":"07-s047","type":"exercise","title":"BÀI TẬP 540 (Trang 277)","num":540,"blocks":[{"t":"instruction","text":"Yêu cầu: Tìm từ đồng nghĩa có đuôi -ся cho các cụm từ in nghiêng."},{"t":"example","text":"1. Каждый может быть неправым.","b":1},{"t":"para","text":"Đồng nghĩa: ошиба́ться."},{"t":"para","text":"Dịch: Ai cũng có thể phạm sai lầm."},{"t":"example","text":"2. Ты можешь разговаривать с кем угодно.","b":1},{"t":"para","text":"Đồng nghĩa: обща́ться."},{"t":"para","text":"Dịch: Bạn có thể giao tiếp với bất kỳ ai."},{"t":"example","text":"3. Думаю, стоит попробовать разрешить этот конфликт мирным путём.","b":1},{"t":"para","text":"Đồng nghĩa: договори́ться."},{"t":"para","text":"Dịch: Tôi nghĩ nên thử thỏa thuận/dàn xếp xung đột này bằng con đường hòa bình."},{"t":"example","text":"4. Он обязательно выздоровеет.","b":1},{"t":"para","text":"Đồng nghĩa: попра́вится."},{"t":"para","text":"Dịch: Anh ấy chắc chắn sẽ bình phục."},{"t":"example","text":"5. Всё произошло очень неожиданно.","b":1},{"t":"para","text":"Đồng nghĩa: случи́лось."},{"t":"para","text":"Dịch: Mọi chuyện đã xảy ra rất bất ngờ."},{"t":"example","text":"6. Вы можете брать мой инструменты.","b":1},{"t":"para","text":"Đồng nghĩa: по́льзоваться (мои́ми инструме́нтами)."},{"t":"para","text":"Dịch: Bạn có thể sử dụng dụng cụ của tôi."},{"t":"example","text":"7. Тебе стоит попросить прощения у своих друзей.","b":1},{"t":"para","text":"Đồng nghĩa: извини́ться (перед друзья́ми)."},{"t":"para","text":"Dịch: Cậu nên xin lỗi bạn bè đi."},{"t":"example","text":"8. Он очень напуган этим человеком.","b":1},{"t":"para","text":"Đồng nghĩa: бои́тся (э́того челове́ка) / опаса́ется."},{"t":"para","text":"Dịch: Anh ta rất sợ người này."},{"t":"example","text":"9. Нам будет нужен рюкзак.","b":1},{"t":"para","text":"Đồng nghĩa: пона́добится."},{"t":"para","text":"Dịch: Chúng ta sẽ cần cái ba lô."},{"t":"example","text":"10. Он достаточно хорошо знает эти проблемы.","b":1},{"t":"para","text":"Đồng nghĩa: разбира́ется (в э́тих пробле́мах)."},{"t":"para","text":"Dịch: Anh ấy am hiểu khá rõ các vấn đề này."},{"t":"example","text":"11. Наше путешествие подходит к концу.","b":1},{"t":"para","text":"Đồng nghĩa: зака́нчивается / конча́ется / заверша́ется."},{"t":"para","text":"Dịch: Chuyến đi của chúng ta đang kết thúc."},{"t":"example","text":"12. Тебе стоит принять его предложение.","b":1},{"t":"para","text":"Đồng nghĩa: согласи́ться (с его́ предложе́нием / на его́ предложе́ние)."},{"t":"para","text":"Dịch: Cậu nên đồng ý với đề nghị của anh ấy."},{"t":"example","text":"13. Обычно она выглядит такой спокойной.","b":1},{"t":"example","text":"Đồng nghĩa: ка́жется / де́ржится. (Thường выглядит $\\approx$ смотрится nhưng ít dùng trong ngữ cảnh tính cách. Ở đây держится - giữ phong thái, hoặc кажется - có vẻ)."},{"t":"subhead","text":"Đáp án tốt nhất: де́ржится."},{"t":"para","text":"Dịch: Thường thì cô ấy giữ vẻ/tỏ ra bình tĩnh như vậy."},{"t":"example","text":"14. Я прихожу в изумление от вашей настойчивости.","b":1},{"t":"para","text":"Đồng nghĩa: удивля́юсь."},{"t":"para","text":"Dịch: Tôi ngạc nhiên về sự kiên trì của bạn."},{"t":"example","text":"15. Он просто пошутил, а ты воспринял это всерьез.","b":1},{"t":"para","text":"Đồng nghĩa: оби́делся. (Ngữ cảnh: coi là thật và giận)."},{"t":"para","text":"Dịch: Cậu ấy chỉ đùa thôi, thế mà cậu lại giận/tự ái (coi là thật)."}]},{"id":"07-s048","type":"grammar","title":"PHẦN NGỮ PHÁP (Trang 278)","num":null,"blocks":[{"t":"para","text":"1. Khung ngữ pháp 1 (Góc trái):","b":1},{"t":"vocab","ru":"Động từ chưa hoàn thành (НСВ)","vi":"Diễn tả hành động đang diễn ra, lặp đi lặp lại hoặc chỉ gọi tên hành động.","g":null},{"t":"vocab","ru":"Động từ hoàn thành (СВ)","vi":"Diễn tả hành động đã hoàn tất, có kết quả, xảy ra một lần hoặc bắt đầu/kết thúc.","g":null},{"t":"para","text":"Cách tạo thể:","b":1},{"t":"vocab","ru":"Thêm tiền tố (prefix) vào động từ НСВ → СВ (ví dụ","vi":"делать → сделать).","g":null},{"t":"vocab","ru":"Dùng hậu tố (suffix) để biến đổi động từ СВ → НСВ (ví dụ","vi":"спросить → спрашивать).","g":null},{"t":"para","text":"2. Khung ngữ pháp 2 (Góc phải):","b":1},{"t":"para","text":"Từ các động từ hoàn thành có tiền tố, ta tạo ra động từ chưa hoàn thành bằng các hậu tố -ива-, -ыва-, -ва- để diễn tả tính lặp lại của hành động."},{"t":"para","text":"3. Khung ngữ pháp 3 (Dưới cùng):","b":1},{"t":"para","text":"Từ các động từ có tiền tố mang nghĩa hoàn thành (gốc phụ âm), ta tạo động từ chưa hoàn thành bằng hậu tố -а-."}]},{"id":"07-s049","type":"exercise","title":"BÀI TẬP 541 (Trang 278)","num":541,"blocks":[{"t":"instruction","text":"Yêu cầu: Từ các động từ đã cho, hãy tạo cặp động từ khác thể hoặc động từ cùng thể nhưng khác nghĩa. Gọi tên các tiền tố và hậu tố tham gia vào việc cấu tạo động từ."},{"t":"para","text":"Giải thích & Đáp án:","b":1},{"t":"para","text":"а) Де́лать (làm - НСВ) — переде́лать (làm lại - СВ), ...","b":1},{"t":"para","text":"Писа́ть (viết - НСВ) → написа́ть (viết xong - СВ), списа́ть (chép - СВ) → спи́сывать (chép - НСВ)."},{"t":"para","text":"Спроси́ть (hỏi - СВ) → спра́шивать (НСВ)."},{"t":"para","text":"Расти́ть (nuôi nấng/trồng - НСВ) → вы́растить (СВ) → выра́щивать (НСВ)."},{"t":"para","text":"Игра́ть (chơi - НСВ) → сыгра́ть (СВ), проигра́ть (thua - СВ) → прои́грывать (НСВ)."},{"t":"para","text":"Гуля́ть (đi dạo - НСВ) → погуля́ть (СВ)."},{"t":"para","text":"Бить (đánh - НСВ) → поби́ть (СВ), разби́ть (làm vỡ - СВ) → разбива́ть (НСВ)."},{"t":"para","text":"Смотре́ть (nhìn/xem - НСВ) → посмотре́ть (СВ), рассмотре́ть (xem xét - СВ) → рассма́тривать (НСВ)."},{"t":"para","text":"Смеши́ть (làm gây cười - НСВ) → рассмеши́ть (СВ)."},{"t":"para","text":"Ста́вить (đặt/để đứng - НСВ) → поста́вить (СВ)."},{"t":"para","text":"Держа́ть (giữ - НСВ) → подержа́ть (СВ), задержа́ть (hoãn/bắt giữ - СВ) → заде́рживать (НСВ)."},{"t":"para","text":"Крепи́ть (làm chắc - НСВ) → укрепи́ть (củng cố - СВ)."},{"t":"para","text":"Крыть (lợp/che - НСВ) → покры́ть (СВ), закры́ть (đóng - СВ) → закрыва́ть (НСВ)."},{"t":"para","text":"Стро́ить (xây - НСВ) → постро́ить (СВ), устро́ить (tổ chức - СВ) → устра́ивать (НСВ)."},{"t":"para","text":"Пакова́ть (đóng gói - НСВ) → упакова́ть (СВ)."},{"t":"para","text":"Вя́нуть (héo - НСВ) → завя́нуть (СВ)."},{"t":"para","text":"Быть (thì/là/ở - НСВ) → побы́ть (ở một lúc - СВ), прибы́ть (đến - СВ) → прибыва́ть (НСВ)."},{"t":"para","text":"Ду́мать (nghĩ - НСВ) → поду́мать (СВ), приду́мать (nghĩ ra - СВ) → приду́мывать (НСВ)."},{"t":"para","text":"Сесть (ngồi xuống - СВ) → сади́ться (НСВ)."},{"t":"para","text":"б) Ки́нуть (ném - СВ) — кида́ть (НСВ), ...","b":1},{"t":"para","text":"Бро́сить (ném/bỏ - СВ) → броса́ть (НСВ)."},{"t":"para","text":"Подбро́сить (tung lên/ném thêm - СВ) → подбра́сывать (НСВ)."},{"t":"para","text":"Толкну́ть (đẩy - СВ) → толка́ть (НСВ)."},{"t":"para","text":"Нырну́ть (lặn - СВ) → ныря́ть (НСВ)."},{"t":"para","text":"Пусти́ть (thả/cho phép - СВ) → пуска́ть (НСВ)."},{"t":"para","text":"Отпусти́ть (tha/thả ra - СВ) → отпуска́ть (НСВ)."},{"t":"para","text":"Пугну́ть (dọa - СВ) → пуга́ть (НСВ)."},{"t":"para","text":"Соедини́ть (nối - СВ) → соединя́ть (НСВ)."},{"t":"para","text":"Реши́ть (quyết định/giải - СВ) → реша́ть (НСВ)."},{"t":"para","text":"Разреши́ть (cho phép - СВ) → разреша́ть (НСВ)."},{"t":"para","text":"Дать (đưa - СВ) → дава́ть (НСВ)."},{"t":"para","text":"Купи́ть (mua - СВ) → покупа́ть (НСВ)."},{"t":"para","text":"Раскупи́ть (mua sạch - СВ) → раскупа́ть (НСВ)."},{"t":"para","text":"Спроси́ть (hỏi - СВ) → спра́шивать (НСВ)."},{"t":"para","text":"в) Отказа́ть (từ chối - СВ) — отка́зывать (НСВ), ...","b":1},{"t":"para","text":"Оправда́ть (biện hộ/tha bổng - СВ) → опра́вдывать (НСВ)."},{"t":"para","text":"Согласова́ть (thỏa thuận/phối hợp - СВ) → согласо́вывать (НСВ)."},{"t":"para","text":"Дорисова́ть (vẽ nốt - СВ) → дорисо́вывать (НСВ)."},{"t":"para","text":"Вы́играть (thắng - СВ) → выи́грывать (НСВ)."},{"t":"para","text":"Вы́писать (kê đơn/viết ra - СВ) → выпи́сывать (НСВ)."},{"t":"para","text":"Задержа́ть (làm chậm/giữ lại - СВ) → заде́рживать (НСВ)."},{"t":"para","text":"Замани́ть (dụ dỗ - СВ) → зама́нивать (НСВ)."},{"t":"para","text":"Оцени́ть (đánh giá - СВ) → оце́нивать (НСВ)."},{"t":"para","text":"Отстоя́ть (bảo vệ/đứng xong - СВ) → отста́ивать (НСВ)."},{"t":"para","text":"Осмотре́ть (khám/xem xét - СВ) → осма́тривать (НСВ)."},{"t":"para","text":"Заговори́ть (bắt chuyện - СВ) → загова́ривать (НСВ)."},{"t":"para","text":"Устро́ить (tổ chức/sắp xếp - СВ) → устра́ивать (НСВ)."},{"t":"para","text":"Успоко́ить (trấn an - СВ) → успока́ивать (НСВ)."},{"t":"para","text":"Осво́ить (làm chủ/tiếp thu - СВ) → осва́ивать (НСВ)."},{"t":"para","text":"г) Вы́лить (đổ ra - СВ) — вылива́ть (НСВ), ...","b":1},{"t":"para","text":"Прожи́ть (sống - СВ) → прожива́ть (НСВ)."},{"t":"para","text":"Вбить (đóng vào - СВ) → вбива́ть (НСВ)."},{"t":"para","text":"Переплы́ть (bơi qua - СВ) → переплыва́ть (НСВ)."},{"t":"para","text":"Забы́ть (quên - СВ) → забыва́ть (НСВ)."},{"t":"para","text":"Откры́ть (mở - СВ) → открыва́ть (НСВ)."},{"t":"para","text":"Разда́ть (phân phát - СВ) → раздава́ть (НСВ)."},{"t":"para","text":"Призна́ть (thừa nhận - СВ) → признава́ть (НСВ)."},{"t":"para","text":"Отста́ть (tụt hậu - СВ) → отстава́ть (НСВ)."},{"t":"para","text":"д) Толка́ть (đẩy - НСВ) — толкну́ть (СВ), ...","b":1},{"t":"para","text":"Кива́ть (gật đầu - НСВ) → кивну́ть (СВ)."},{"t":"para","text":"Маха́ть (vẫy - НСВ) → махну́ть (СВ)."},{"t":"para","text":"Достига́ть (đạt được - НСВ) → дости́гнуть (СВ)."},{"t":"para","text":"Исчеза́ть (biến mất - НСВ) → исче́знуть (СВ)."},{"t":"para","text":"Отвыка́ть (cai/bỏ thói quen - НСВ) → отвы́кнуть (СВ)."},{"t":"para","text":"Отверга́ть (bác bỏ - НСВ) → отве́ргнуть (СВ)."},{"t":"para","text":"Мёрзнуть (lạnh/rét - НСВ) → замёрзнуть (đóng băng/chết rét - СВ)."},{"t":"para","text":"Гло́хнуть (chết máy/điếc - НСВ) → огло́хнуть (bị điếc - СВ)."},{"t":"para","text":"Со́хнуть (khô - НСВ) → засо́хнуть (khô héo - СВ)."},{"t":"para","text":"Кре́пнуть (mạnh lên - НСВ) → окре́пнуть (СВ)."},{"t":"para","text":"Сле́пнуть (mù đi - НСВ) → осле́пнуть (СВ)."},{"t":"para","text":"е) Вы́расти (lớn lên - СВ) — выраста́ть (НСВ)...","b":1},{"t":"para","text":"Отцвести́ (tàn hoa - СВ) → отцвета́ть (НСВ)."},{"t":"para","text":"Сбере́чь (tiết kiệm/giữ - СВ) → сберега́ть (НСВ)."},{"t":"para","text":"Предостере́чь (cảnh báo - СВ) → предостерега́ть (НСВ)."},{"t":"example","text":"Подже́чь (châm lửa - СВ) → поджига́ть (НСВ). (Lưu ý biến đổi е → и)."},{"t":"para","text":"Сжечь (đốt trụi - СВ) → сжига́ть (НСВ)."},{"t":"para","text":"Отвле́чь (làm xao lãng - СВ) → отвлека́ть (НСВ)."},{"t":"para","text":"Развле́чь (giải trí - СВ) → развлека́ть (НСВ)."},{"t":"para","text":"Зале́зть (leo vào - СВ) → зале́зать (НСВ)."},{"t":"para","text":"Проле́зть (chui qua - СВ) → проле́зать (НСВ)."},{"t":"para","text":"Помо́чь (giúp - СВ) → помога́ть (НСВ)."},{"t":"para","text":"Изнемо́чь (kiệt sức - СВ) → изнемога́ть (НСВ)."},{"t":"para","text":"ж) Реши́ть (quyết định - СВ) — реша́ть (НСВ)...","b":1},{"t":"para","text":"Внуши́ть (gợi ý/ám thị - СВ) → внуша́ть (НСВ)."},{"t":"para","text":"Лиши́ть (tước đoạt - СВ) → лиша́ть (НСВ)."},{"t":"para","text":"Изучи́ть (nghiên cứu kỹ - СВ) → изуча́ть (НСВ)."},{"t":"para","text":"Бро́сить (ném/bỏ - СВ) → броса́ть (НСВ)."},{"t":"para","text":"Ко́нчить (kết thúc - СВ) → конча́ть (НСВ)."},{"t":"para","text":"Прове́рить (kiểm tra - СВ) → проверя́ть (НСВ)."},{"t":"para","text":"Расши́рить (mở rộng - СВ) → расширя́ть (НСВ)."},{"t":"para","text":"Позво́лить (cho phép - СВ) → позволя́ть (НСВ)."},{"t":"para","text":"Одо́брить (tán thành - СВ) → одобря́ть (НСВ)."},{"t":"para","text":"Изобрази́ть (thể hiện/vẽ - СВ) → изобража́ть (НСВ)."},{"t":"para","text":"Убеди́ть (thuyết phục - СВ) → убежда́ть (НСВ)."},{"t":"para","text":"Победи́ть (chiến thắng - СВ) → побежда́ть (НСВ)."},{"t":"para","text":"Защити́ть (bảo vệ - СВ) → защища́ть (НСВ)."},{"t":"para","text":"Посети́ть (thăm - СВ) → посеща́ть (НСВ)."},{"t":"para","text":"Прости́ть (tha thứ - СВ) → проща́ть (НСВ)."},{"t":"para","text":"Пусти́ть (thả - СВ) → пуска́ть (НСВ)."},{"t":"para","text":"Оскорби́ть (xúc phạm - СВ) → оскорбля́ть (НСВ)."},{"t":"para","text":"Укрепи́ть (củng cố - СВ) → укрепля́ть (НСВ)."},{"t":"para","text":"Вы́прямить (làm thẳng - СВ) → выпрямля́ть (НСВ)."},{"t":"para","text":"Отве́тить (trả lời - СВ) → отвеча́ть (НСВ)."},{"t":"para","text":"Заме́тить (nhận thấy - СВ) → замеча́ть (НСВ)."},{"t":"para","text":"з) Обнима́ть (ôm - НСВ) — обня́ть (СВ)...","b":1},{"t":"para","text":"Отнима́ть (lấy đi - НСВ) → отня́ть (СВ)."},{"t":"para","text":"Пожима́ть (bắt tay/nhún vai - НСВ) → пожа́ть (СВ)."},{"t":"para","text":"Принима́ть (tiếp nhận - НСВ) → приня́ть (СВ)."},{"t":"example","text":"Натира́ть (xát/lau - НСВ) → натере́ть (СВ). (Biến đổi ира/ере)."},{"t":"para","text":"Запира́ть (khóa - НСВ) → запере́ть (СВ)."},{"t":"para","text":"Растира́ть (xoa bóp/nghiền - НСВ) → растере́ть (СВ)."},{"t":"para","text":"Стира́ть (giặt/xóa - НСВ) → стере́ть (xóa - СВ) hoặc постира́ть (giặt - СВ)."},{"t":"para","text":"Умира́ть (chết - НСВ) → умере́ть (СВ)."},{"t":"para","text":"Вызыва́ть (gọi - НСВ) → вы́звать (СВ)."},{"t":"para","text":"Называ́ть (gọi tên - НСВ) → назва́ть (СВ)."},{"t":"para","text":"Призыва́ть (kêu gọi - НСВ) → призва́ть (СВ)."},{"t":"para","text":"и) Станови́ться (trở nên - НСВ) — стать (СВ)...","b":1},{"t":"para","text":"Ложи́ться (nằm xuống - НСВ) → лечь (СВ)."},{"t":"para","text":"Находи́ть (tìm thấy - НСВ) → найти́ (СВ)."},{"t":"para","text":"Класть (đặt/để - НСВ) → положи́ть (СВ)."},{"t":"para","text":"Брать (lấy - НСВ) → взять (СВ)."},{"t":"para","text":"Говори́ть (nói - НСВ) → сказа́ть (СВ)."},{"t":"para","text":"Лови́ть (bắt - НСВ) → пойма́ть (СВ)."},{"t":"para","text":"Иска́ть (tìm kiếm - НСВ) → найти́ (tìm thấy - СВ) hoặc поиска́ть (tìm một lúc - СВ)."}]},{"id":"07-s050","type":"exercise","title":"BÀI TẬP 542 (Trang 279)","num":542,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc câu. Xác định thể của các động từ in đậm. Gọi tên động từ nguyên thể và cho biết chúng được tạo thành từ thể nào."},{"t":"subhead","text":"Gợi ý khung ngữ pháp (Trang 279):","b":1},{"t":"example","text":"Trong tiếng Nga có các động từ \"lưỡng thể\" (двувидовые) kết thúc bằng -овать, -ировать, -изовать, thể của chúng được xác định theo ngữ cảnh."},{"t":"para","text":"1. Учёные иссле́довали о́зеро Байка́л... Когда́ иссле́довали Байка́л, применя́ли аппарату́ру...","b":1},{"t":"para","text":"Viết lại & Dịch:","b":1},{"t":"para","text":"Các nhà khoa học đã nghiên cứu (hoàn thành) hồ Baikal và đi đến kết luận..."},{"t":"para","text":"Khi nghiên cứu (chưa hoàn thành - quá trình) hồ Baikal, họ đã áp dụng các thiết bị..."},{"t":"example","text":"Giải thích: Иссле́довать là động từ lưỡng thể. Câu 1 chỉ kết quả (đi đến kết luận) → Hoàn thành. Câu 2 chỉ quá trình (khi đang làm thì dùng thiết bị) → Chưa hoàn thành. Применя́ли (dùng) là НСВ. Разрабо́танную (được thiết kế) từ разрабо́тать (СВ)."},{"t":"para","text":"2. Они́ мно́го раз обсле́довали э́тот объе́кт, пре́жде чем пришли́ к вы́воду... Специали́сты обсле́довали э́тот объе́кт и пришли́ к вы́воду...","b":1},{"t":"para","text":"Viết lại & Dịch:","b":1},{"t":"para","text":"Họ đã khảo sát (lặp lại nhiều lần - НСВ) đối tượng này nhiều lần trước khi đi đến kết luận..."},{"t":"para","text":"Các chuyên gia đã khảo sát (một lần/kết quả - СВ) đối tượng này và đi đến kết luận..."},{"t":"example","text":"Giải thích: Обсле́довать là động từ lưỡng thể. Câu 1 có много раз → НСВ. Câu 2 chỉ chuỗi hành động kế tiếp → СВ."},{"t":"para","text":"3. В э́тот раз мы испо́льзовали тот же ме́тод доказа́тельства, что и в предыду́щей зада́че. Мы постоя́нно испо́льзовали в на́шей рабо́те показа́ния прибо́ров.","b":1},{"t":"para","text":"Viết lại & Dịch:","b":1},{"t":"para","text":"Lần này chúng tôi đã sử dụng (một lần - СВ) cùng một phương pháp chứng minh..."},{"t":"para","text":"Chúng tôi thường xuyên sử dụng (lặp lại - НСВ) các chỉ số thiết bị trong công việc."},{"t":"example","text":"Giải thích: Испо́льзовать là động từ lưỡng thể."},{"t":"para","text":"4. В суббо́ту мы организова́ли для студе́нтов экску́рсию в Коло́менское. Обы́чно мы организу́ем конфере́нцию в нача́ле ма́я.","b":1},{"t":"para","text":"Viết lại & Dịch:","b":1},{"t":"para","text":"Vào thứ Bảy chúng tôi đã tổ chức (СВ - quá khứ cụ thể) một chuyến tham quan cho sinh viên..."},{"t":"para","text":"Thường thì chúng tôi tổ chức (НСВ - hiện tại lặp lại) hội nghị vào đầu tháng Năm."},{"t":"example","text":"Giải thích: Организова́ть là động từ lưỡng thể."},{"t":"para","text":"5. В сре́дние века́ люде́й казни́ли без суда́ и сле́дствия. Его́ казни́ли, но де́ло его́ продолжа́ло жить.","b":1},{"t":"para","text":"Viết lại & Dịch:","b":1},{"t":"para","text":"Thời trung cổ người ta hành quyết (thường xuyên - НСВ) người không cần xét xử."},{"t":"para","text":"Ông ấy đã bị hành quyết (một lần - СВ), nhưng sự nghiệp của ông vẫn tiếp tục sống."},{"t":"example","text":"Giải thích: Казни́ть là động từ lưỡng thể."}]},{"id":"07-s051","type":"exercise","title":"BÀI TẬP 543 (Trang 279)","num":543,"blocks":[{"t":"instruction","text":"Yêu cầu: Từ các động từ cho sẵn, dùng các tiền tố để tạo ra tất cả các động từ hoàn thành có thể. Kiểm tra bằng từ điển."},{"t":"vocab","ru":"Тра́тить (tiêu)","vi":"потра́тить (tiêu xài), истра́тить (tiêu hết), растра́тить (phung phí).","g":null},{"t":"vocab","ru":"Звони́ть (gọi điện)","vi":"позвони́ть (gọi), перезвони́ть (gọi lại), дозвони́ться (gọi được), созвони́ться (liên lạc với nhau).","g":null},{"t":"vocab","ru":"Крыть (lợp/che)","vi":"покры́ть, закры́ть, откры́ть, накры́ть, скрыть.","g":null},{"t":"vocab","ru":"Бить (đánh)","vi":"поби́ть, разби́ть, уби́ть, сбить, вы́бить, заби́ть.","g":null},{"t":"vocab","ru":"Мыть (rửa)","vi":"помы́ть, вы́мыть, отмы́ть.","g":null},{"t":"vocab","ru":"Чита́ть (đọc)","vi":"прочита́ть, почита́ть, дочита́ть, перечита́ть.","g":null},{"t":"vocab","ru":"Брать (lấy)","vi":"вы́брать, собра́ть, убра́ть, забра́ть, набра́ть. (Gốc thay đổi thành брать → -брать).","g":null},{"t":"vocab","ru":"Смотре́ть (nhìn)","vi":"посмотре́ть, усмотре́ть, рассмотре́ть, осмотре́ть, пересмотре́ть.","g":null},{"t":"vocab","ru":"Бро́сить (ném)","vi":"вы́бросить, забро́сить, набро́сить, сбро́сить.","g":null},{"t":"vocab","ru":"Лить (rót)","vi":"нали́ть, вы́лить, проли́ть, разли́ть.","g":null},{"t":"vocab","ru":"Учи́ть (học/dạy)","vi":"вы́учить, научи́ть, обучи́ть, изучи́ть.","g":null},{"t":"vocab","ru":"Люби́ть (yêu)","vi":"полюби́ть, разлюби́ть.","g":null},{"t":"vocab","ru":"Шить (may)","vi":"сшить, приши́ть, заши́ть, вы́шить.","g":null},{"t":"vocab","ru":"Меша́ть (làm phiền/trộn)","vi":"помеша́ть (làm phiền), размеша́ть (khuấy), смеша́ть (trộn).","g":null},{"t":"vocab","ru":"Счита́ть (đếm/coi là)","vi":"посчита́ть, сосчита́ть, рассчита́ть.","g":null},{"t":"vocab","ru":"Проси́ть (xin)","vi":"попроси́ть, вы́просить.","g":null},{"t":"vocab","ru":"Мочь (có thể)","vi":"смочь, помо́чь (giúp).","g":null},{"t":"vocab","ru":"Писа́ть (viết)","vi":"написа́ть, записа́ть, вы́писать, переписа́ть, дописа́ть.","g":null},{"t":"vocab","ru":"Ду́мать (nghĩ)","vi":"поду́мать, приду́мать, заду́мать, переду́мать.","g":null}]},{"id":"07-s052","type":"exercise","title":"BÀI TẬP 544 (Trang 279-280)","num":544,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền động từ hoàn thành (được tạo từ động từ gốc + tiền tố) vào chỗ trống. Xác định ý nghĩa của tiền tố."},{"t":"para","text":"а) игра́ть (chơi)","b":1},{"t":"example","text":"Актри́са прекра́сно сыгра́ла роль Ранёвской... (Tiền tố с- mang nghĩa hoàn thành hành động biểu diễn)."},{"t":"para","text":"Dịch: Nữ diễn viên đã đóng vai Ranevskaya tuyệt vời..."},{"t":"example","text":"На э́тот раз тебе́ не повезло́, ты проигра́л, а мог бы вы́играть... (Про- = thua, Вы- = thắng)."},{"t":"para","text":"Dịch: Lần này bạn không may mắn, bạn đã thua, lẽ ra có thể thắng..."},{"t":"example","text":"Ты допусти́л оши́бку... дава́й переигра́ем э́ту па́ртию. (Пере- = làm lại). (Hoặc доиграем - chơi nốt, nhưng ngữ cảnh \"mắc lỗi, bị phân tâm\" thì thường xin chơi lại)."},{"t":"para","text":"Dịch: Cậu mắc lỗi... thôi chơi lại ván này đi."},{"t":"vocab","ru":"Ты мо́жешь немно́го, а пото́м сади́сь де́лать уро́ки","vi":"поигра́ть... (По- = làm một chút).","g":null},{"t":"para","text":"Dịch: Con có thể chơi một chút, rồi ngồi vào làm bài tập."},{"t":"example","text":"Ты всегда́ ду́маю, на э́тот раз мне уда́стся тебя́ обыгра́ть... (Об- = thắng ai đó)."},{"t":"para","text":"Dịch: Cậu luôn nghĩ lần này tớ sẽ thắng được cậu..."},{"t":"para","text":"б) де́лать (làm)","b":1},{"t":"example","text":"Мы должны́ сде́лать э́ту рабо́ту во́время. (С- = hoàn thành)."},{"t":"para","text":"Dịch: Chúng ta phải làm xong việc này đúng hạn."},{"t":"example","text":"Тебе́ прихо́дится переде́лывать э́ту рабо́ту, так как ты сде́лал в ней не́сколько оши́бок. (Пере- = làm lại)."},{"t":"para","text":"Dịch: Cậu phải làm lại việc này vì cậu mắc vài lỗi."},{"t":"example","text":"Ещё мину́ту, мне на́до доде́лать ды́рку... (До- = làm nốt/làm thêm cho xong). (Hoặc сделать). Ngữ cảnh \"khoan lỗ\" → проделать (khoan thủng) hoặc сделать."},{"t":"para","text":"Dịch: Chờ một phút, tớ cần làm/khoan cái lỗ..."},{"t":"example","text":"Я ... э́ту рабо́ту до конца́ и бу́ду свобо́ден. → доде́лаю. (До- = làm đến cùng)."},{"t":"para","text":"Dịch: Tôi sẽ làm xong việc này đến cùng rồi sẽ rảnh."},{"t":"example","text":"К э́тому сто́лику на́до бу́дет приде́лать но́вые но́жки. (При- = gắn thêm vào)."},{"t":"para","text":"Dịch: Sẽ cần gắn thêm chân mới cho cái bàn này."},{"t":"para","text":"в) смотре́ть (nhìn/xem)","b":1},{"t":"example","text":"Пре́жде всего́ на́до внима́тельно осмотре́ть ме́сто происше́ствия. (О- = quan sát xung quanh/khám nghiệm)."},{"t":"para","text":"Dịch: Trước hết cần khám nghiệm kỹ hiện trường vụ việc."},{"t":"example","text":"Пе́ред выступле́нием я хочу́ ещё раз просмотре́ть свой докла́д. (Про- = xem lướt qua/ôn lại)."},{"t":"para","text":"Dịch: Trước khi thuyết trình tôi muốn xem lại bài báo cáo một lần nữa."},{"t":"example","text":"Как ты ду́маешь, поче́му он так внима́тельно нас рассма́тривал? (Ở đây dùng quá khứ chưa hoàn thành рассматривал hay hoàn thành рассмотрел? Câu hỏi \"tại sao anh ấy nhìn kỹ thế\" thường dùng рассматривал. Nếu buộc phải dùng hoàn thành: осмотрел? Nhưng рассматривать hợp hơn. Sách yêu cầu dùng hoàn thành từ смотреть. Có thể là посмотре́л (nhìn) nhưng \"chăm chú\" thì là quá trình. Nếu ý là \"đã nhìn ra/soi kỹ\": рассмотре́л)."},{"t":"subhead","text":"Đáp án: рассмотре́л (nhìn kỹ/soi xét)."},{"t":"para","text":"Dịch: Cậu nghĩ xem tại sao hắn soi bọn mình kỹ thế?"},{"t":"example","text":"Ситуа́ция измени́лась, и мы должны́ пересмотре́ть на́ши взгля́ды... (Пере- = xem xét lại/thay đổi)."},{"t":"para","text":"Dịch: Tình hình đã thay đổi, và chúng ta cần xem xét lại quan điểm..."},{"t":"example","text":"Она́ посмотре́ла на меня́ и улыбну́лась. (По- = nhìn một cái)."},{"t":"para","text":"Dịch: Cô ấy nhìn tôi và mỉm cười."},{"t":"para","text":"г) ду́мать (nghĩ)","b":1},{"t":"example","text":"Пре́жде чем нача́ть рабо́ту, ты до́лжен проду́мать всё до мельча́йших дета́лей. (Про- = nghĩ thông suốt/kỹ lưỡng)."},{"t":"para","text":"Dịch: Trước khi bắt đầu, cậu phải suy tính mọi thứ đến từng chi tiết nhỏ nhất."},{"t":"example","text":"Зна́ешь, я переду́мал е́хать с тобо́й за го́род. (Пере- = đổi ý)."},{"t":"para","text":"Dịch: Biết không, tớ đổi ý không đi ngoại ô với cậu nữa."},{"t":"example","text":"Поче́му у тебя́ тако́й хи́трый вид? Что ты там заду́мал? (За- = ủ mưu/toan tính)."},{"t":"para","text":"Dịch: Sao trông cậu gian thế? Cậu đang tính toán/ủ mưu gì đấy?"},{"t":"example","text":"Я приду́мал, как нам вы́йти из э́той ситуа́ции. (При- = nghĩ ra/phát minh)."},{"t":"para","text":"Dịch: Tớ đã nghĩ ra cách chúng ta thoát khỏi tình huống này."},{"t":"example","text":"Никто́ тебе́ не меша́л рабо́тать. Что ты там наду́мал?! (На- = suy diễn/nghĩ ra nhiều thứ (thường là tiêu cực hoặc vớ vẩn))."},{"t":"para","text":"Dịch: Không ai làm phiền cậu làm việc cả. Cậu lại suy diễn/tưởng tượng ra cái gì thế?!"}]},{"id":"07-s053","type":"exercise","title":"BÀI TẬP 545 (Trang 280)","num":545,"blocks":[{"t":"instruction","text":"Yêu cầu: Xác định thể của động từ và tìm cặp thể cho mỗi động từ. Sử dụng các động từ đã cho và từ дава́й(те) để đặt câu."},{"t":"para","text":"Cặp thể:","b":1},{"t":"para","text":"Принима́ть (НСВ) — приня́ть (СВ)."},{"t":"para","text":"Позвони́ть (СВ) — звони́ть (НСВ)."},{"t":"para","text":"Разреши́ть (СВ) — разреша́ть (НСВ)."},{"t":"para","text":"Перечи́тывать (НСВ) — перечита́ть (СВ)."},{"t":"para","text":"Ви́деть (НСВ) — уви́деть (СВ)."},{"t":"para","text":"Помога́ть (НСВ) — помо́чь (СВ)."},{"t":"para","text":"Лечь (СВ) — ложи́ться (НСВ)."},{"t":"para","text":"Находи́ть (НСВ) — найти́ (СВ)."},{"t":"para","text":"Обме́ниваться (НСВ) — обменя́ться (СВ)."},{"t":"para","text":"Подожда́ть (СВ) — ждать (НСВ)."},{"t":"para","text":"Дотро́нуться (СВ) — дотра́гиваться (НСВ)."},{"t":"para","text":"Передава́ть (НСВ) — переда́ть (СВ)."},{"t":"para","text":"Доплати́ть (СВ) — допла́чивать (НСВ)."},{"t":"para","text":"Подчёркивать (НСВ) — подчеркну́ть (СВ)."},{"t":"para","text":"Призна́ть (СВ) — признава́ть (НСВ)."},{"t":"para","text":"Смея́ться (НСВ) — засмея́ться/посмея́ться (СВ)."},{"t":"para","text":"Нра́виться (НСВ) — понра́виться (СВ)."},{"t":"para","text":"Достига́ть (НСВ) — дости́гнуть/дости́чь (СВ)."},{"t":"para","text":"Замеча́ть (НСВ) — заме́тить (СВ)."},{"t":"para","text":"Отправля́ть (НСВ) — отпра́вить (СВ)."},{"t":"para","text":"Сади́ться (НСВ) — сесть (СВ)."},{"t":"para","text":"Положи́ть (СВ) — класть (НСВ)."},{"t":"para","text":"Обсле́довать (Cả 2 thể)."},{"t":"para","text":"Осво́ить (СВ) — осва́ивать (НСВ)."},{"t":"para","text":"Отмени́ть (СВ) — отменя́ть (НСВ)."},{"t":"para","text":"Призна́ть (СВ) — признава́ть (НСВ)."},{"t":"para","text":"Кре́пнуть (НСВ) — окре́пнуть (СВ)."},{"t":"para","text":"Смеши́ть (НСВ) — рассмеши́ть (СВ)."},{"t":"para","text":"Залеза́ть (НСВ) — зале́зть (СВ)."},{"t":"para","text":"Прики́нуть (СВ) — прики́дывать (НСВ)."},{"t":"para","text":"Растира́ть (НСВ) — растере́ть (СВ)."},{"t":"para","text":"Захоте́ть (СВ) — хоте́ть (НСВ)."},{"t":"para","text":"Убеди́ть (СВ) — убежда́ть (НСВ)."},{"t":"para","text":"Посеща́ть (НСВ) — посети́ть (СВ)."},{"t":"para","text":"Выпря́мить (СВ) — выпрямля́ть (НСВ)."},{"t":"para","text":"Отвле́чь (СВ) — отвлека́ть (НСВ)."},{"t":"para","text":"Пакова́ть (НСВ) — упакова́ть (СВ)."},{"t":"para","text":"Отцвести́ (СВ) — отцвета́ть (НСВ)."},{"t":"para","text":"Взять (СВ) — брать (НСВ)."},{"t":"para","text":"Толка́ть (НСВ) — толкну́ть (СВ)."},{"t":"para","text":"Отста́ть (СВ) — отстава́ть (НСВ)."},{"t":"para","text":"Укрепи́ть (СВ) — укрепля́ть (НСВ)."},{"t":"para","text":"Сообщи́ть (СВ) — сообща́ть (НСВ)."},{"t":"para","text":"Предложи́ть (СВ) — предлага́ть (НСВ)."},{"t":"para","text":"Де́лать (НСВ) — сде́лать (СВ)."},{"t":"para","text":"Пообе́дать (СВ) — обе́дать (НСВ)."},{"t":"para","text":"Черти́ть (НСВ) — начерти́ть (СВ)."},{"t":"para","text":"Откры́ть (СВ) — открыва́ть (НСВ)."},{"t":"para","text":"Купи́ть (СВ) — покупа́ть (НСВ)."},{"t":"para","text":"Разби́ть (СВ) — разбива́ть (НСВ)."},{"t":"para","text":"Сове́товать (НСВ) — посове́товать (СВ)."},{"t":"para","text":"Говори́ть (НСВ) — сказа́ть (СВ)."},{"t":"para","text":"Записа́ть (СВ) — запи́сывать (НСВ)."},{"t":"para","text":"Пересе́сть (СВ) — переса́живаться (НСВ)."},{"t":"vocab","ru":"Sử dụng với \"Давай(те)\" (Hãy/Chúng ta hãy)","vi":"Quy tắc:","g":null},{"t":"vocab","ru":"Дава́й(те) + Động từ nguyên thể НСВ","vi":"Mời mọc làm gì (nhấn mạnh hành động) hoặc bắt đầu làm gì.","g":null},{"t":"example","text":"Ví dụ: Давай игра́ть! (Chơi đi! - bắt đầu chơi). Давай обе́дать. (Ăn trưa thôi)."},{"t":"vocab","ru":"Дава́й(те) + Động từ tương lai СВ (ngôi 1 số nhiều - мы)","vi":"Đề nghị hoàn thành một việc cụ thể.","g":null},{"t":"example","text":"Ví dụ: Давай пообе́даем. (Cùng ăn trưa nhé). Давай ку́пим хлеб. (Mua bánh mì đi)."},{"t":"example","text":"Ví dụ đặt câu:","b":1},{"t":"para","text":"Дава́й пообе́даем вме́сте. (Chúng ta hãy cùng ăn trưa nhé)."},{"t":"para","text":"Дава́йте говори́ть по-ру́сски. (Chúng ta hãy nói tiếng Nga đi)."},{"t":"para","text":"Дава́й ку́пим моро́женое. (Mua kem đi)."},{"t":"example","text":"Дава́йте встре́тимся за́втра. (Hãy gặp nhau ngày mai - встретиться là СВ của встречаться)."},{"t":"para","text":"Дава́й посмотре́ть фи́льм? No, Дава́й посмо́трим фильм. (Xem phim nhé)."},{"t":"para","text":"Дава́йте не бу́дем со́рриться. (Chúng ta đừng cãi nhau nữa)."},{"t":"para","text":"Chào em, đây là phần giải thích chi tiết, dịch thuật và hướng dẫn làm bài tập từ 546 đến 550 trong sách \"Грамматика русского языка в упражнениях и комментариях. Морфология\" (O. I. Glazunova), trang 280-283."},{"t":"para","text":"Phần này tập trung vào Thể của động từ trong động từ nguyên thể (Виды глаголов в инфинитиве), đặc biệt là khi đi kèm với các từ chỉ sự cần thiết, mong muốn, hoặc phủ định."}]},{"id":"07-s054","type":"exercise","title":"BÀI TẬP 546 (Trang 280-281)","num":546,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng tiểu từ не (không) và động từ chưa hoàn thành (Imperfective - НСВ), hãy đưa ra dạng phủ định cho các câu sau."},{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"example","text":"Khi chuyển một câu khẳng định dùng từ на́до, ну́жно, сто́ит, до́лжен + Động từ hoàn thành (СВ) sang dạng phủ định (không cần, không nên), ta thường dùng: Не на́до, не ну́жно, не сто́ит + Động từ chưa hoàn thành (НСВ)."},{"t":"example","text":"Ví dụ: На́до откры́ть (Cần mở) → Не на́до открыва́ть (Không cần mở)."},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"1. На́до сде́лать э́ту рабо́ту. (Cần làm xong việc này)."},{"t":"para","text":"Viết lại: Не на́до де́лать э́ту рабо́ту."},{"t":"para","text":"Dịch: Không cần làm việc này."},{"t":"para","text":"2. Письмо́ сто́ит переписа́ть. (Lá thư đáng để viết lại)."},{"t":"para","text":"Viết lại: Письмо́ не сто́ит перепи́сывать."},{"t":"para","text":"Dịch: Lá thư không đáng/không cần viết lại."},{"t":"para","text":"3. Тебе́ на́до укрепи́ть свой авторите́т. (Bạn cần củng cố uy tín của mình)."},{"t":"para","text":"Viết lại: Тебе́ не на́до укрепля́ть свой авторите́т."},{"t":"para","text":"Dịch: Bạn không cần củng cố uy tín của mình."},{"t":"para","text":"4. Сто́ит привле́чь внима́ние всех прису́тствующих к э́тому вопро́су. (Đáng để thu hút sự chú ý của mọi người vào vấn đề này)."},{"t":"para","text":"Viết lại: Не сто́ит привлека́ть внима́ние..."},{"t":"para","text":"Dịch: Không nên thu hút sự chú ý..."},{"t":"para","text":"5. Сто́ит подро́бнее освети́ть э́ти вопро́сы. (Nên làm sáng tỏ các vấn đề này chi tiết hơn)."},{"t":"para","text":"Viết lại: Не сто́ит подро́бнее освеща́ть..."},{"t":"para","text":"Dịch: Không cần làm sáng tỏ..."},{"t":"para","text":"6. На́до найти́ вы́ход из созда́вшегося положе́ния. (Cần tìm lối thoát khỏi tình huống đã xảy ra)."},{"t":"para","text":"Viết lại: Не на́до иска́ть вы́ход..."},{"t":"para","text":"Dịch: Không cần tìm lối thoát..."},{"t":"para","text":"7. Ну́жно внима́тельно обсле́довать э́тот райо́n. (Cần khảo sát kỹ khu vực này)."},{"t":"para","text":"Viết lại: Не ну́жно внима́тельно обсле́довать..."},{"t":"example","text":"Dịch: Không cần khảo sát kỹ... (Lưu ý: обследовать là động từ lưỡng thể, hình thức không đổi)."},{"t":"para","text":"8. Ты до́лжен кивну́ть голово́й, е́сли ты с на́ми согла́сен. (Bạn phải gật đầu nếu đồng ý với chúng tôi)."},{"t":"para","text":"Viết lại: Ты не до́лжен кива́ть голово́й..."},{"t":"para","text":"Dịch: Bạn không được/không cần gật đầu..."},{"t":"para","text":"9. Ты до́лжен позво́лить ему́ приня́ть реше́ние самостоя́тельно. (Bạn phải cho phép cậu ấy tự quyết định)."},{"t":"para","text":"Viết lại: Ты не до́лжен позволя́ть ему́..."},{"t":"para","text":"Dịch: Bạn không nên cho phép cậu ấy..."},{"t":"para","text":"10. Сто́ит исключи́ть тако́го разви́тия собы́тий. (Nên loại trừ diễn biến sự kiện như vậy)."},{"t":"para","text":"Viết lại: Не сто́ит исключа́ть..."},{"t":"para","text":"Dịch: Không nên loại trừ..."},{"t":"para","text":"11. Сто́ит положи́ть его́ ве́щи на ме́сто. (Nên đặt đồ của anh ấy vào chỗ cũ)."},{"t":"para","text":"Viết lại: Не сто́ит класть его́ ве́щи..."},{"t":"example","text":"Dịch: Không nên đặt/để đồ của anh ấy... (Lưu ý cặp: положи́ть (СВ) - класть (НСВ))."},{"t":"para","text":"12. На́до запере́ть дверь. (Cần khóa cửa lại)."},{"t":"para","text":"Viết lại: Не на́до запира́ть дверь."},{"t":"para","text":"Dịch: Không cần khóa cửa."},{"t":"para","text":"13. Э́то лека́рство должно́ помо́чь. (Thuốc này chắc sẽ giúp ích)."},{"t":"example","text":"Viết lại: Э́то лека́рство не должно́ помога́ть. (Hoặc giữ помочь nếu ý là \"không chắc sẽ có kết quả\", nhưng theo yêu cầu bài là НСВ thì dùng помогать)."},{"t":"para","text":"Dịch: Thuốc này không được/không có nhiệm vụ giúp đỡ."},{"t":"para","text":"14. На́до обеспе́чить их всем необходи́мым материа́лами. (Cần cung cấp cho họ mọi vật liệu cần thiết)."},{"t":"para","text":"Viết lại: Не на́до обеспе́чивать их..."},{"t":"para","text":"Dịch: Không cần cung cấp cho họ..."},{"t":"para","text":"15. Сто́ит вы́звать врача́. (Nên gọi bác sĩ)."},{"t":"para","text":"Viết lại: Не сто́ит вызыва́ть врача́."},{"t":"para","text":"Dịch: Không cần gọi bác sĩ."},{"t":"example","text":"16. На́до обеща́ть ему́ всю пра́вду. (Sách in nhầm обещать? Ngữ cảnh всю правду thường là сказать. Nếu là сказать: Не на́до говори́ть). Giả sử động từ là сказать."},{"t":"para","text":"Viết lại: Не на́до говори́ть ему́ всю пра́вду."},{"t":"para","text":"Dịch: Đừng nói cho anh ta biết toàn bộ sự thật."},{"t":"para","text":"17. Необходимо́ вы́ключить свет. (Cần tắt đèn)."},{"t":"para","text":"Viết lại: Не ну́жно/необход́имо выключа́ть свет."},{"t":"para","text":"Dịch: Không cần tắt đèn."},{"t":"para","text":"18. На́до сказа́ть ему́ всю пра́вду. (Câu này lặp ý câu 16)."},{"t":"para","text":"Viết lại: Не на́до говори́ть..."},{"t":"para","text":"19. Ты до́лжен стере́ть с доски́. (Em phải xóa bảng)."},{"t":"para","text":"Viết lại: Ты не до́лжен стира́ть с доски́."},{"t":"para","text":"Dịch: Em không cần/không được xóa bảng."},{"t":"para","text":"20. Ты до́лжен поднять э́тот вопро́с. (Bạn phải nêu vấn đề này ra)."},{"t":"para","text":"Viết lại: Ты не до́лжен поднима́ть э́тот вопро́с."},{"t":"para","text":"Dịch: Bạn không nên nêu vấn đề này ra."},{"t":"para","text":"21. Нам придётся его́ прости́ть. (Chúng ta sẽ phải tha thứ cho nó)."},{"t":"para","text":"Viết lại: Нам не придётся его́ проща́ть."},{"t":"para","text":"Dịch: Chúng ta sẽ không phải tha thứ cho nó."},{"t":"para","text":"22. Нам придётся согласи́ться. (Chúng ta đành phải đồng ý)."},{"t":"para","text":"Viết lại: Нам не придётся соглаша́ться."},{"t":"para","text":"Dịch: Chúng ta sẽ không phải đồng ý."},{"t":"para","text":"23. Он до́лжен призна́ть свои́ оши́бки. (Anh ta phải thừa nhận sai lầm)."},{"t":"para","text":"Viết lại: Он не до́лжен признава́ть свои́ оши́бки."},{"t":"para","text":"Dịch: Anh ta không cần thừa nhận sai lầm."},{"t":"para","text":"24. Сто́ит оцени́ть на́ши возмо́жности. (Nên đánh giá khả năng của chúng ta)."},{"t":"para","text":"Viết lại: Не сто́ит оце́нивать..."},{"t":"para","text":"Dịch: Không cần đánh giá..."},{"t":"example","text":"25. Ты до́лжен по́мнить об э́том. (Помнить là НСВ sẵn)."},{"t":"example","text":"Viết lại: Ты не до́лжен по́мнить об э́том. (Hoặc dùng забывать nếu muốn đổi nghĩa, nhưng bài yêu cầu phủ định động từ: Bạn không cần nhớ)."},{"t":"para","text":"Dịch: Bạn không cần nhớ về điều đó."},{"t":"para","text":"26. Вам сто́ит испо́льзовать э́тот шанс. (Bạn nên tận dụng cơ hội này)."},{"t":"para","text":"Viết lại: Вам не сто́ит испо́льзовать э́тот шанс."},{"t":"para","text":"Dịch: Bạn không nên tận dụng cơ hội này."},{"t":"para","text":"27. На́до бро́сить э́ту привы́чку. (Phải bỏ thói quen này)."},{"t":"para","text":"Viết lại: Не на́до броса́ть э́ту привы́чку."},{"t":"para","text":"Dịch: Không cần bỏ thói quen này."},{"t":"para","text":"28. Его́ на́до отвле́чь от его́ мы́слей. (Cần làm cậu ấy xao lãng khỏi suy nghĩ của mình)."},{"t":"para","text":"Viết lại: Его́ не на́до отвлека́ть..."},{"t":"para","text":"Dịch: Không cần làm cậu ấy xao lãng..."},{"t":"para","text":"29. Ты до́лжен помо́чь ему́ сде́лать дома́шнее зада́ние. (Con phải giúp bạn ấy làm bài tập)."},{"t":"para","text":"Viết lại: Ты не до́лжен помога́ть ему́ де́лать..."},{"t":"para","text":"Dịch: Con không cần giúp bạn ấy làm..."},{"t":"note","text":"Lưu ý:","b":1},{"t":"para","text":"Trong các cấu trúc phủ định, động từ nguyên thể (infinitive) thường dùng ở thể chưa hoàn thành (НСВ)."}]},{"id":"07-s055","type":"exercise","title":"BÀI TẬP 547 (Trang 281)","num":547,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc câu. Xác định sự khác biệt về ý nghĩa của các động từ in đậm (hoàn thành/chưa hoàn thành). Chọn động từ nguyên thể phù hợp trong ngoặc."},{"t":"subhead","text":"a) Câu với до́лжен (phải/có bổn phận) và обя́зан (có nghĩa vụ):","b":1},{"t":"para","text":"Любо́й челове́к до́лжен (отвеча́ть/отве́тить) за свои́ посту́пки."},{"t":"para","text":"Chọn: отвеча́ть."},{"t":"para","text":"Dịch: Bất kỳ ai cũng phải chịu trách nhiệm (luôn luôn - quy tắc chung) về hành động của mình."},{"t":"para","text":"Вы должны́ (отве́тить/отвеча́ть) на все вопро́сы."},{"t":"para","text":"Chọn: отве́тить."},{"t":"para","text":"Dịch: Các bạn phải trả lời (hoàn thành xong) tất cả các câu hỏi."},{"t":"para","text":"Мы ра́ды вас (ви́деть/уви́деть)."},{"t":"para","text":"Chọn: ви́деть."},{"t":"para","text":"Dịch: Chúng tôi rất vui được gặp (trạng thái) các bạn."},{"t":"para","text":"Мы ра́ды (уви́деть/ви́деть) карти́ну знамени́того худо́жника."},{"t":"para","text":"Chọn: уви́деть."},{"t":"para","text":"Dịch: Chúng tôi vui mừng vì đã được chiêm ngưỡng (sự kiện cụ thể) bức tranh của họa sĩ nổi tiếng."},{"t":"para","text":"Студе́нты обя́заны во́время (сдава́ть/сдать) курсовы́е рабо́ты."},{"t":"para","text":"Chọn: сдава́ть."},{"t":"para","text":"Dịch: Sinh viên có nghĩa vụ nộp (lặp lại, quy định chung) bài tập lớn đúng hạn."},{"t":"para","text":"Что́бы перейти́ на сле́дующий курс, студе́нты обя́заны (сдава́ть/сдать) все экза́мены."},{"t":"para","text":"Chọn: сдать."},{"t":"para","text":"Dịch: Để lên lớp, sinh viên bắt buộc phải thi đỗ (hoàn thành kết quả) tất cả các môn."},{"t":"subhead","text":"б) Câu chỉ mục đích hoặc mong muốn:","b":1},{"t":"para","text":"Мы прие́хали в Санкт-Петербу́рг (учи́ться/научи́ться)."},{"t":"para","text":"Chọn: учи́ться."},{"t":"para","text":"Dịch: Chúng tôi đến SPb để học tập (quá trình)."},{"t":"para","text":"Мы прие́хали (сообща́ть/сообщи́ть) о своём реше́нии."},{"t":"para","text":"Chọn: сообщи́ть."},{"t":"para","text":"Dịch: Chúng tôi đến để thông báo (một lần/kết quả) về quyết định của mình."},{"t":"para","text":"Он хо́чет (изуча́ть/изучи́ть) ру́сский язы́к."},{"t":"para","text":"Chọn: изуча́ть."},{"t":"para","text":"Dịch: Anh ấy muốn học/nghiên cứu tiếng Nga (quá trình)."},{"t":"para","text":"Он хо́чет (извиня́ться/извини́ться) пе́ред ва́ми."},{"t":"para","text":"Chọn: извини́ться."},{"t":"para","text":"Dịch: Anh ấy muốn xin lỗi (hành động cụ thể) bạn."},{"t":"para","text":"Я могу́ по́сле рабо́ты (относи́ть/отнести́) твоё письмо́ на по́чту."},{"t":"para","text":"Chọn: отнести́."},{"t":"para","text":"Dịch: Tan làm tớ có thể mang (cụ thể một lần) thư của cậu ra bưu điện."},{"t":"subhead","text":"в) Câu với мо́жно, нельзя, ну́жно:","b":1},{"t":"para","text":"На заня́тиях мо́жно (задава́ть/зада́ть) вопро́с?"},{"t":"para","text":"Chọn: зада́ть."},{"t":"example","text":"Dịch: Trong giờ học có thể đặt (một) câu hỏi được không? (Nếu hỏi về quy tắc chung \"được phép đặt câu hỏi không\" thì dùng задавать. Nhưng thường học sinh giơ tay xin hỏi 1 câu cụ thể → задать). Tuy nhiên, sách ngữ pháp thường dạy: Được phép (chung) → НСВ (Можно задавать вопросы). Để thực hiện 1 hành động → СВ (Можно задать вопрос?)."},{"t":"para","text":"Во вре́мя экза́мена нельзя́ (входи́ть/войти́) в аудито́рию."},{"t":"para","text":"Chọn: входи́ть."},{"t":"para","text":"Dịch: Trong giờ thi không được phép vào phòng thi (Cấm đoán → НСВ)."},{"t":"para","text":"В аудито́рию нельзя́ (войти́/входи́ть), поте́рян ключ."},{"t":"para","text":"Chọn: войти́."},{"t":"para","text":"Dịch: Không thể vào phòng được (Không có khả năng thực hiện → СВ), chìa khóa bị mất rồi."},{"t":"para","text":"Вам ну́жно бо́льше (рабо́тать/порабо́тать) в библиоте́ке."},{"t":"para","text":"Chọn: рабо́тать."},{"t":"para","text":"Dịch: Bạn cần làm việc (quá trình lâu dài) nhiều hơn ở thư viện."},{"t":"para","text":"Вам ну́жно бы́ло (написа́ть/писа́ть) о своём прие́зде."},{"t":"para","text":"Chọn: написа́ть."},{"t":"para","text":"Dịch: Lẽ ra bạn cần phải viết thư báo (kết quả đã không làm) về việc bạn đến."},{"t":"para","text":"Сего́дня я оста́вил до́ма ключ, придётся (ждать/подожда́ть) до пяти́ часо́в..."},{"t":"para","text":"Chọn: ждать."},{"t":"para","text":"Dịch: ... đành phải chờ (quá trình) đến 5 giờ..."}]},{"id":"07-s056","type":"exercise","title":"BÀI TẬP 548 (Trang 282)","num":548,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng dạng đúng của động từ nguyên thể (chọn thể). Giải thích sự lựa chọn."},{"t":"para","text":"1. Я гото́в ... с ва́ми за́втра у́тром. Мы гото́вы ... два ра́за (встреча́ться/встре́титься).","b":1},{"t":"subhead","text":"Đáp án: ...встре́титься... ...встреча́ться."},{"t":"para","text":"Dịch: Tôi sẵn sàng gặp bạn sáng mai (1 lần cụ thể → СВ). Chúng tôi sẵn sàng gặp nhau hai lần (lặp lại → НСВ)."},{"t":"para","text":"2. Осо́бо тру́дные пра́вила преподава́тель до́лжен ... два ра́за (объясня́ть/объясни́ть).","b":1},{"t":"subhead","text":"Đáp án: ...объясни́ть. (Hoặc объяснять nếu nhấn mạnh quy tắc lặp lại). Tuy nhiên, \"phải giải thích được\" (kết quả) 2 lần cho hiểu → thường dùng СВ với số lượng cụ thể trong ngữ cảnh đạt kết quả. Nhưng nếu là quy định chung của giáo viên thì объяснять."},{"t":"example","text":"Lựa chọn an toàn: объясни́ть (thực hiện hành động cụ thể 2 lần)."},{"t":"para","text":"3. У нас есть свобо́дное вре́мя, мы согла́сны ... ва́ше мне́ние (обсужда́ть/обсуди́ть).","b":1},{"t":"subhead","text":"Đáp án: ...обсуди́ть."},{"t":"para","text":"Dịch: Chúng tôi có thời gian rảnh, chúng tôi đồng ý thảo luận (giải quyết xong) ý kiến của bạn."},{"t":"para","text":"4. Не́сколько раз я начина́л ... ку́рсы... (броса́ть/бро́сить). (Sách in lỗi, câu gốc có thể là \"Tôi bắt đầu học rồi lại bỏ\")."},{"t":"subhead","text":"Cấu trúc: начинал + НСВ."},{"t":"example","text":"Sửa: Несколько раз я начинал ходить..."},{"t":"example","text":"Câu 2: ...но приходилось броса́ть (phải bỏ - lặp lại nhiều lần). Hoặc nếu một lần cụ thể: пришлось бросить. Với несколько раз (nhiều lần) → броса́ть (НСВ)."},{"t":"para","text":"5. Она́ о́чень упо́рный челове́к и спосо́бна часа́ми ... одну́ и ту же зада́чу (реша́ть/реши́ть).","b":1},{"t":"subhead","text":"Đáp án: ...реша́ть."},{"t":"para","text":"Dịch: Cô ấy rất kiên trì và có khả năng giải (ngồi làm - quá trình) một bài toán hàng giờ liền."},{"t":"para","text":"6. Э́то де́ло я наме́рен ... до конца́ (доводи́ть/довести́).","b":1},{"t":"subhead","text":"Đáp án: ...довести́."},{"t":"para","text":"Dịch: Vụ này tôi định làm cho tới nơi tới chốn (kết quả)."},{"t":"para","text":"7. В э́том слу́чае вы должны́ со мной ... (соглаша́ться/согласи́ться).","b":1},{"t":"subhead","text":"Đáp án: ...согласи́ться."},{"t":"para","text":"Dịch: Trong trường hợp này bạn phải đồng ý (1 lần cụ thể) với tôi."},{"t":"para","text":"8. Мы бу́дем ра́ды вам ... в э́той тру́дной ситуа́ции (помога́ть/помо́чь).","b":1},{"t":"subhead","text":"Đáp án: ...помо́чь."},{"t":"para","text":"Dịch: Chúng tôi sẽ rất vui được giúp bạn (cụ thể) trong tình huống khó khăn này."},{"t":"para","text":"9. Ребёнок уже́ доста́точно взро́слый и спосо́бен ... са́мые элемента́рные доказа́тельства (воспринима́ть/восприня́ть).","b":1},{"t":"subhead","text":"Đáp án: ...воспринима́ть."},{"t":"para","text":"Dịch: Đứa bé đã đủ lớn và có khả năng tiếp thu/hiểu (năng lực chung → НСВ) những chứng minh cơ bản nhất."}]},{"id":"07-s057","type":"exercise","title":"BÀI TẬP 549 (Trang 282)","num":549,"blocks":[{"t":"instruction","text":"Yêu cầu: Với các tính từ ngắn cho sẵn (скло́нен, спосо́бен, рад, обя́зан, располо́жен, гото́в, согла́сен, досто́ин, свобо́ден, до́лжен, наме́рен), hãy đặt câu sử dụng động từ nguyên thể (chú ý chọn thể hoàn thành/chưa hoàn thành)."},{"t":"example","text":"Ví dụ:","b":1},{"t":"vocab","ru":"Скло́нен","vi":"Он скло́нен преувели́чивать (НСВ) свои́ заслу́ги. (Anh ta có khuynh hướng phóng đại công lao - thói quen).","g":null},{"t":"vocab","ru":"Спосо́бен","vi":"Он спосо́бен реши́ть (СВ) э́ту зада́чу. (Anh ta có khả năng giải được bài này - kết quả).","g":null},{"t":"vocab","ru":"Рад","vi":"Я рад ви́деть (НСВ) вас. (Tôi vui khi gặp bạn - trạng thái). Я рад познако́миться (СВ). (Vui được làm quen - sự kiện).","g":null},{"t":"vocab","ru":"Обя́зан","vi":"Ты обя́зан соблюда́ть (НСВ) пра́вила. (Bạn có nghĩa vụ tuân thủ quy tắc - luôn luôn).","g":null},{"t":"vocab","ru":"Гото́в","vi":"У́жин гото́в. Я гото́в вы́слушать (СВ) тебя́. (Tôi sẵn sàng lắng nghe bạn).","g":null},{"t":"vocab","ru":"Согла́сен","vi":"Я согла́сен подожда́ть (СВ). (Tôi đồng ý chờ).","g":null},{"t":"vocab","ru":"До́лжен","vi":"Ты до́лжен уйти́ (СВ). (Bạn phải đi ngay). Ты до́лжен учи́ться (НСВ). (Bạn phải học tập - quá trình).","g":null},{"t":"vocab","ru":"Наме́рен","vi":"Я наме́рен купи́ть (СВ) э́ту кни́гу. (Tôi định mua cuốn sách này).","g":null}]},{"id":"07-s058","type":"exercise","title":"BÀI TẬP 550 (Trang 282)","num":550,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng dạng đúng của động từ nguyên thể."},{"t":"para","text":"1. Он реши́л (остава́ться/оста́ться) с на́ми на всё ле́то. Я реши́л всегда́ (сле́довать/после́довать) ва́шим сове́там.","b":1},{"t":"subhead","text":"Đáp án: ...оста́ться... ...сле́довать."},{"t":"para","text":"Dịch: Anh ấy đã quyết định ở lại (kết quả) với chúng tôi cả mùa hè. Tôi đã quyết định sẽ luôn làm theo (luôn luôn → НСВ) lời khuyên của bạn."},{"t":"para","text":"2. Мы оста́лись (помога́ть/помо́чь) вам с убо́ркой кварти́ры. Они́ оста́лись (рабо́тать/порабо́тать) на се́вере.","b":1},{"t":"subhead","text":"Đáp án: ...помо́чь (hoặc помогать)... ...рабо́тать (hoặc поработать)."},{"t":"example","text":"Giải thích:"},{"t":"para","text":"Ở lại để giúp dọn dẹp (cụ thể 1 lần) → помо́чь."},{"t":"para","text":"Ở lại miền Bắc để làm việc (lâu dài) → рабо́тать. (Nếu làm việc một thời gian ngắn rồi về → порабо́тать). Ngữ cảnh \"ở lại miền Bắc\" thường là lâu dài → рабо́тать."},{"t":"para","text":"3. Всё ле́то я собира́юсь (сдава́ть/сдать) экза́мены в институ́т. Я собира́юсь наконе́ц (говори́ть/сказа́ть) ему́ всё, что я о нём ду́маю.","b":1},{"t":"subhead","text":"Đáp án: ...сдава́ть... ...сказа́ть."},{"t":"para","text":"Dịch: Cả mùa hè tôi định thi (quá trình thi cử kéo dài) vào đại học. Cuối cùng tôi cũng định nói (1 lần dứt khoát) cho nó biết hết những gì tôi nghĩ."},{"t":"para","text":"4. Администра́ция институ́та собира́ется (разреша́ть/разреши́ть) вам проводи́ть свои́ иссле́дования.","b":1},{"t":"subhead","text":"Đáp án: ...разреши́ть."},{"t":"para","text":"Dịch: Ban giám hiệu định cho phép (cấp phép 1 lần) bạn tiến hành nghiên cứu."},{"t":"para","text":"Администра́ция институ́та собира́ется (устра́ивать/устро́ить) таки́е вы́ставки ка́ждый год.","b":1},{"t":"subhead","text":"Đáp án: ...устра́ивать."},{"t":"para","text":"Dịch: ... định tổ chức (lặp lại hàng năm) những triển lãm như thế."},{"t":"para","text":"Я предполага́ю (зака́нчивать/зако́нчить) ста́тью че́рез ме́сяц.","b":1},{"t":"subhead","text":"Đáp án: ...зако́нчить."},{"t":"para","text":"Dịch: Tôi dự định hoàn thành (kết quả) bài báo sau một tháng."},{"t":"para","text":"Таки́е отчёты я предполага́ю (составля́ть/соста́вить) регуля́рно.","b":1},{"t":"subhead","text":"Đáp án: ...составля́ть."},{"t":"para","text":"Dịch: Những báo cáo như thế tôi dự định lập (thường xuyên) đều đặn."},{"t":"para","text":"6. На э́тот раз он попроси́л нас (вычёркивать/вы́черкнуть) из спи́ска его́ фами́лию.","b":1},{"t":"subhead","text":"Đáp án: ...вы́черкнуть."},{"t":"para","text":"Dịch: Lần này ông ấy yêu cầu chúng tôi gạch (1 lần) tên ông ấy khỏi danh sách."},{"t":"para","text":"Он попроси́л (согласо́вывать/согласова́ть) с ним ка́ждый прое́кт.","b":1},{"t":"subhead","text":"Đáp án: ...согласо́вывать."},{"t":"para","text":"Dịch: Ông ấy yêu cầu thông qua/thảo luận (lặp lại với từng dự án) với ông ấy mỗi dự án."},{"t":"para","text":"7. Он мечта́ет (уезжа́ть/уе́хать) из э́того го́рода.","b":1},{"t":"subhead","text":"Đáp án: ...уе́хать."},{"t":"para","text":"Dịch: Cậu ấy mơ ước rời khỏi (dứt khoát đi hẳn) thành phố này."},{"t":"para","text":"Он мечта́ет (проводи́ть/провести́) с семьёй бо́льше вре́мени.","b":1},{"t":"subhead","text":"Đáp án: ...проводи́ть."},{"t":"para","text":"Dịch: Anh ấy mơ ước dành (thói quen/quá trình) nhiều thời gian hơn cho gia đình."},{"t":"para","text":"8. Он момента́льно согласи́лся (отвеча́ть/отве́тить) на на́ши вопро́сы.","b":1},{"t":"subhead","text":"Đáp án: ...отве́тить."},{"t":"para","text":"Dịch: Anh ấy lập tức đồng ý trả lời (ngay lúc đó) các câu hỏi của chúng tôi."},{"t":"para","text":"Он согласи́лся (быть/побыва́ть) руководи́телем прое́кта.","b":1},{"t":"subhead","text":"Đáp án: ...быть."},{"t":"para","text":"Dịch: Ông ấy đã đồng ý làm/giữ chức (trạng thái kéo dài) chủ nhiệm dự án."}]},{"id":"07-s059","type":"grammar","title":"PHẦN NGỮ PHÁP (Gợi ý trong khung trang 283)","num":null,"blocks":[{"t":"subhead","text":"Quy tắc về \"động từ chỉ hành động tiềm năng đơn lẻ\" (единично-потенциальное действие):","b":1},{"t":"para","text":"Với các từ như всегда (luôn luôn), в любой момент (vào bất cứ lúc nào) và các từ tương tự, khi muốn diễn tả một hành động có khả năng xảy ra một lần cụ thể (đạt kết quả), người ta sử dụng động từ nguyên thể ở thể hoàn thành (СВ)."},{"t":"example","text":"Ví dụ: Вы всегда можете обратиться к врачу. (Bạn luôn có thể tìm đến/hỏi bác sĩ - hành động cụ thể khi cần)."},{"t":"example","text":"So sánh:"},{"t":"example","text":"Можно брать (НСВ) бланк? (Được phép lấy mẫu đơn không? - Xin phép chung chung)."},{"t":"example","text":"Берите (они для этого здесь и лежат). (Cứ lấy đi)."}]},{"id":"07-s060","type":"exercise","title":"BÀI TẬP 551 (Trang 283)","num":551,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, sử dụng động từ ở thể hoàn thành hoặc chưa hoàn thành. Giải thích sự lựa chọn của bạn."},{"t":"example","text":"Giải thích: Ở bài này, hầu hết các câu đều chứa các cụm từ như в любой момент, всегда, если... chỉ khả năng thực hiện một hành động cụ thể để giải quyết vấn đề. Do đó, ta thường dùng thể hoàn thành (СВ) để chỉ kết quả tiềm năng."},{"t":"para","text":"1. Если оценка вас не устраивает, вы всегда можете (переписывать/переписать) контрольную работу.","b":1},{"t":"subhead","text":"Đáp án: переписа́ть (СВ)."},{"t":"para","text":"Dịch: Nếu bạn không hài lòng với điểm số, bạn luôn có thể viết lại bài kiểm tra."},{"t":"para","text":"Giải thích: Khả năng thực hiện lại hành động để đạt kết quả mới."},{"t":"para","text":"2. Вы можете (думать/подумать) обо мне, что хотите, но я не подпишу этот договор.","b":1},{"t":"subhead","text":"Đáp án: ду́мать (НСВ)."},{"t":"para","text":"Dịch: Các anh có thể nghĩ về tôi thế nào tùy thích, nhưng tôi sẽ không ký hợp đồng này."},{"t":"para","text":"Giải thích: \"Nghĩ\" ở đây là một quá trình tư duy/trạng thái kéo dài, không phải một kết quả cụ thể trong khoảnh khắc."},{"t":"para","text":"3. Если вы задерживаетесь на работе, вы можете (обедать/пообедать) в столовой.","b":1},{"t":"subhead","text":"Đáp án: пообе́дать (СВ)."},{"t":"para","text":"Dịch: Nếu bạn ở lại làm muộn, bạn có thể ăn trưa/ăn tối ở nhà ăn."},{"t":"para","text":"Giải thích: Thực hiện trọn vẹn bữa ăn một lần."},{"t":"para","text":"4. Боюсь, они могут неправильно нас (понимать/понять).","b":1},{"t":"subhead","text":"Đáp án: поня́ть (СВ)."},{"t":"para","text":"Dịch: Tôi sợ họ có thể hiểu lầm chúng ta."},{"t":"para","text":"Giải thích: Kết quả của việc hiểu (hiểu ra sai vấn đề)."},{"t":"para","text":"5. Вы можете в любое время (просить/попросить) меня о помощи.","b":1},{"t":"subhead","text":"Đáp án: попроси́ть (СВ)."},{"t":"para","text":"Dịch: Bạn có thể nhờ/xin tôi giúp đỡ bất cứ lúc nào."},{"t":"para","text":"Giải thích: Hành động cụ thể xảy ra một lần khi cần."},{"t":"para","text":"6. Я могу часами (рассказывать/рассказать) вам, но вряд ли поможет (решать/решить) ваши проблемы.","b":1},{"t":"subhead","text":"Đáp án: расска́зывать (НСВ) ... реши́ть (СВ)."},{"t":"para","text":"Dịch: Tôi có thể kể cho bạn nghe hàng giờ liền (quá trình), nhưng điều đó khó mà giúp giải quyết (kết quả) được vấn đề của bạn."},{"t":"para","text":"7. Он может (выслушивать/выслушать) вас, но вряд ли поможет (решать/решить) ваши проблемы. (Câu gốc trong sách hơi khác câu 6 một chút ở vế đầu)."},{"t":"subhead","text":"Đáp án: вы́слушать (СВ) ... реши́ть (СВ)."},{"t":"para","text":"Dịch: Ông ấy có thể lắng nghe bạn (nghe xong hết), nhưng khó mà giúp giải quyết được vấn đề."},{"t":"para","text":"8. Не беспокойтесь, мы подождём или можем (приходить/прийти) завтра.","b":1},{"t":"subhead","text":"Đáp án: прийти́ (СВ)."},{"t":"para","text":"Dịch: Đừng lo, chúng tôi sẽ đợi hoặc có thể đến vào ngày mai."},{"t":"para","text":"Giải thích: Hành động đến cụ thể vào ngày mai."},{"t":"para","text":"9. В нашем магазине вы всегда можете (покупать/купить) кондитерские изделия.","b":1},{"t":"subhead","text":"Đáp án: купи́ть (СВ)."},{"t":"para","text":"Dịch: Tại cửa hàng chúng tôi, quý khách luôn có thể mua được các sản phẩm bánh kẹo."},{"t":"para","text":"Giải thích: Nhấn mạnh khả năng mua được hàng (kết quả) bất cứ lúc nào."},{"t":"para","text":"10. Вы можете (обращаться/обратиться) ко мне на “ты”, ведь мы с вами приблизительно одного возраста.","b":1},{"t":"subhead","text":"Đáp án: обраща́ться (НСВ)."},{"t":"para","text":"Dịch: Bạn có thể xưng hô với tôi bằng \"ty\" (cậu/mày - ngôi thứ 2 số ít thân mật), vì chúng ta trạc tuổi nhau."},{"t":"para","text":"Giải thích: Đây là sự cho phép về một thói quen/cách cư xử chung lâu dài, không phải một hành động duy nhất."},{"t":"vocab","ru":"Положение очень серьёзное","vi":"в любое время на корабле может (происходить/произойти) взрыв.","g":null},{"t":"subhead","text":"Đáp án: произойти́ (СВ)."},{"t":"para","text":"Dịch: Tình hình rất nghiêm trọng: một vụ nổ có thể xảy ra trên tàu bất cứ lúc nào."},{"t":"para","text":"Giải thích: Sự kiện đơn lẻ, kết quả tức thì."},{"t":"para","text":"12. О вкусах можно (спорить/поспорить) бесконечно.","b":1},{"t":"subhead","text":"Đáp án: спо́рить (НСВ)."},{"t":"para","text":"Dịch: Về sở thích thì có thể tranh luận mãi không thôi."},{"t":"example","text":"Giải thích: Quá trình kéo dài vô tận (бесконечно)."},{"t":"para","text":"13. Если вас что-то не устраивает, вы всегда можете (говорить/сказать) мне об этом.","b":1},{"t":"subhead","text":"Đáp án: сказа́ть (СВ)."},{"t":"para","text":"Dịch: Nếu bạn không hài lòng điều gì, bạn luôn có thể nói với tôi về điều đó."},{"t":"para","text":"Giải thích: Hành động nói ra cụ thể."},{"t":"para","text":"14. Ты в любой момент можешь (возвращать/вернуть) билет в кассу.","b":1},{"t":"subhead","text":"Đáp án: верну́ть (СВ)."},{"t":"para","text":"Dịch: Cậu có thể trả lại vé tại quầy bất cứ lúc nào."},{"t":"para","text":"Giải thích: Hành động hoàn tất trả vé."},{"t":"para","text":"15. Если у вас есть читательский билет, вы можете (брать/взять) книги в библиотеке.","b":1},{"t":"subhead","text":"Đáp án: брать (НСВ)."},{"t":"para","text":"Dịch: Nếu bạn có thẻ độc giả, bạn có thể mượn sách ở thư viện."},{"t":"example","text":"Giải thích: Chỉ quyền hạn chung, hành động lặp đi lặp lại thường xuyên (брать thường dùng cho việc mượn sách thư viện nói chung). Tuy nhiên, nếu ý là \"mượn cuốn này ngay bây giờ\" thì dùng взять. Trong ngữ cảnh quy định chung \"có thẻ thì được mượn\", dùng брать phổ biến hơn."},{"t":"para","text":"16. Можно (убегать/убежать) от других, но не от самого себя.","b":1},{"t":"subhead","text":"Đáp án: убежа́ть (СВ)."},{"t":"para","text":"Dịch: Có thể chạy trốn khỏi người khác, nhưng không thể trốn khỏi chính mình."},{"t":"para","text":"Giải thích: Nhấn mạnh khả năng thực hiện thành công hành động (chạy thoát)."}]},{"id":"07-s061","type":"exercise","title":"BÀI TẬP 552 (Trang 284)","num":552,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu. Xác định sự khác biệt về ý nghĩa của các cấu trúc in đậm. Chú ý đến việc sử dụng thể động từ."},{"t":"example","text":"Giải thích: Bài tập này so sánh cấu trúc phủ định với động từ мочь."},{"t":"para","text":"a) 1. Он может не переводить этот текст, его перевод у меня уже есть.","b":1},{"t":"example","text":"Ý nghĩa: Anh ấy không cần phải dịch văn bản này (có quyền không làm - не đi với động từ chính переводить НСВ)."},{"t":"para","text":"Dịch: Anh ấy có thể không dịch văn bản này, tôi đã có bản dịch rồi."},{"t":"para","text":"2. Он не знает немецкого языка и не (сможет) может перевести этот текст.","b":1},{"t":"example","text":"Ý nghĩa: Anh ấy không có khả năng dịch (bất lực - не đi với может + СВ перевести)."},{"t":"para","text":"Dịch: Anh ấy không biết tiếng Đức và không thể dịch văn bản này."},{"t":"para","text":"б) 1. Вы могли не делать письменно все упражнения, а выбрать из них только самые сложные.","b":1},{"t":"example","text":"Ý nghĩa: Bạn lẽ ra không cần làm (đã có quyền không làm - могли не + НСВ)."},{"t":"para","text":"Dịch: Lẽ ra các bạn không cần làm viết tất cả các bài tập, mà chỉ cần chọn những bài khó nhất."},{"t":"para","text":"2. Ты мог не прощать его, предательство не прощают.","b":1},{"t":"para","text":"Ý nghĩa: Lẽ ra cậu có thể không tha thứ (lời khuyên/nhận định về khả năng không thực hiện hành động)."},{"t":"para","text":"Dịch: Cậu lẽ ra có thể không tha thứ cho nó, sự phản bội thì không tha thứ được."},{"t":"para","text":"3. Я так и не (с)мог его простить. Он очень хорошо к тебе относится, но может не простить тебя за то, что ты сделал.","b":1},{"t":"example","text":"Ý nghĩa: Tôi đã không thể tha thứ (bất lực - не смог + СВ). Cậu ấy có thể sẽ không tha thứ (khả năng xảy ra kết quả tiêu cực - может не + СВ)."},{"t":"para","text":"Dịch: Tôi mãi vẫn không thể tha thứ cho nó... nhưng cậu ấy có thể sẽ không tha thứ cho cậu vì những gì cậu đã làm."}]},{"id":"07-s062","type":"exercise","title":"BÀI TẬP 553 (Trang 284)","num":553,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền cấu trúc với động từ мочь/смочь ở dạng cần thiết cùng với động từ chính ở thể phù hợp."},{"t":"subhead","text":"Quy tắc (Khung trang 284):","b":1},{"t":"example","text":"Không thể làm gì (do năng lực/hoàn cảnh): не + мочь/смочь + Động từ Hoàn thành (СВ). (Ví dụ: Я не могу решить - Tôi không thể giải được)."},{"t":"example","text":"Có thể không làm gì (được phép/khả năng không xảy ra): мочь/смочь + не + Động từ Chưa hoàn thành (НСВ) hoặc Hoàn thành (СВ) tùy ngữ cảnh."},{"t":"para","text":"1. Вы уже написали контрольную работу и завтра (писать/написать) можете не писать её.","b":1},{"t":"example","text":"Dịch: Bạn đã viết bài kiểm tra rồi nên ngày mai có thể không cần viết nó nữa. (Được phép không làm → можете не + НСВ)."},{"t":"para","text":"2. Я ... (объяснять/объяснить) своего взгляда на вещи, боюсь, он ... (соглашаться/согласиться) с нами.","b":1},{"t":"subhead","text":"Đáp án: Я не могу объяснить... он не может/сможет согласиться."},{"t":"example","text":"Dịch: Tôi không thể giải thích quan điểm của mình... tôi sợ anh ấy không thể đồng ý với chúng ta. (Bất lực → не могу + СВ)."},{"t":"para","text":"3. У него всегда был свой взгляд на вещи, боюсь, он ... (соглашаться/согласиться) с нами. (Câu này lặp ý câu 2)."},{"t":"subhead","text":"Đáp án: ... он может не согласиться (có khả năng anh ấy sẽ không đồng ý - phỏng đoán) hoặc не сможет согласиться (không thể đồng ý - khẳng định). Ngữ cảnh \"sợ rằng\" thường dùng не согласится hoặc может не согласиться."},{"t":"para","text":"4. Многого я не знаю и поэтому ... (отвечать/ответить) на все ваши вопросы.","b":1},{"t":"subhead","text":"Đáp án: ... не могу ответить."},{"t":"para","text":"Dịch: Tôi không biết nhiều thứ nên không thể trả lời hết câu hỏi của các bạn."},{"t":"para","text":"5. Если ты не хочешь, ... (доедать/доесть) суп.","b":1},{"t":"subhead","text":"Đáp án: ... можешь не доедать."},{"t":"para","text":"Dịch: Nếu con không muốn, con có thể không cần ăn hết súp. (Cho phép không làm → НСВ)."},{"t":"para","text":"6. В нашем деле он человек новый и ... (справляться/справиться) с этим заданием.","b":1},{"t":"subhead","text":"Đáp án: ... может не справиться (có thể sẽ không làm được) hoặc не сможет справиться (sẽ không thể làm được)."},{"t":"para","text":"Dịch: Trong lĩnh vực của chúng ta cậu ta là người mới và có thể sẽ không hoàn thành được nhiệm vụ này."},{"t":"para","text":"7. Вадим ... (читать/прочитать) всю монографию, а выбрать только те главы, которые касаются его дипломной работы.","b":1},{"t":"subhead","text":"Đáp án: Вадим может не читать."},{"t":"para","text":"Dịch: Vadim có thể không cần đọc cả cuốn chuyên khảo, mà chỉ chọn những chương liên quan..."},{"t":"para","text":"8. Почему он должен начать курить, если ему это не нравится? Он человек самостоятельный ... (курить/закурить).","b":1},{"t":"subhead","text":"Đáp án: ... может не закурить (có thể không bắt đầu hút) hoặc может не курить (có thể không hút)."},{"t":"para","text":"Dịch: Tại sao nó phải bắt đầu hút... Nó là người độc lập, nó có thể không hút."},{"t":"para","text":"9. Тебе не стоит кричать, ... (слышать/услышать) твой слова.","b":1},{"t":"subhead","text":"Đáp án: ... я могу услышать (tôi có thể nghe thấy - không cần phủ định) hoặc nếu ý là \"dù cậu không hét tôi vẫn nghe thấy\": я и так могу услышать. Sách có thể yêu cầu: я не могу не услышать (tôi không thể không nghe - chắc chắn nghe thấy)?"},{"t":"subhead","text":"Đáp án hợp lý nhất: я и так слышу / могу услышать. Nhưng nếu theo mẫu не могу: Я не могу не услышать (Tôi chắc chắn nghe thấy)."},{"t":"para","text":"10. Он ... (опровергать/опровергнуть) мои слова, потому что его там не будет.","b":1},{"t":"subhead","text":"Đáp án: Он не сможет опровергнуть."},{"t":"para","text":"Dịch: Anh ta sẽ không thể bác bỏ lời tôi, vì anh ta sẽ không có mặt ở đó."},{"t":"para","text":"11. Контрольная работа очень сложная, и те из вас, кто недостаточно к ней готов, ... (справляться/справиться) с некоторыми заданиями.","b":1},{"t":"subhead","text":"Đáp án: ... могут не справиться."},{"t":"para","text":"Dịch: Bài kiểm tra rất khó... các bạn có thể sẽ không làm được một số bài."},{"t":"para","text":"12. Я заканчиваю работу в пять часов и ... (успевать/успеть) вовремя приехать на встречу с тобой.","b":1},{"t":"subhead","text":"Đáp án: ... могу не успеть."},{"t":"para","text":"Dịch: Tớ tan làm lúc 5 giờ và có thể sẽ không kịp đến gặp cậu đúng giờ."},{"t":"para","text":"13. Не надо думать, что она специально не выполнила твою просьбу, она ведь просто ... (вспоминать/вспомнить) о ней.","b":1},{"t":"subhead","text":"Đáp án: ... могла не вспомнить."},{"t":"para","text":"Dịch: Đừng nghĩ cô ấy cố tình... cô ấy đơn giản là có thể đã không nhớ (quên) về nó."},{"t":"para","text":"14. Вы ... (записывать/записать) мои слова, достаточно просто прослушать эту информацию.","b":1},{"t":"subhead","text":"Đáp án: Вы можете не записывать."},{"t":"para","text":"Dịch: Các bạn có thể không cần ghi chép lời tôi..."},{"t":"para","text":"15. Он плохо подготовлен и ... (сдавать/сдать) экзамены.","b":1},{"t":"subhead","text":"Đáp án: ... может не сдать."},{"t":"para","text":"Dịch: Cậu ấy chuẩn bị kém và có thể sẽ không thi đỗ."},{"t":"para","text":"16. Мы ... (встречаться/встретиться) с вами. 17. Я вряд ли узнаю этого человека, вчера на вечере было много народу, я ... (обращать/обратить) на него внимания.","b":1},{"t":"subhead","text":"Đáp án: 16. не сможем встретиться (không thể gặp). 17. мог не обратить (có thể đã không chú ý)."},{"t":"para","text":"Dịch: 16. Chúng tôi không thể gặp bạn. 17. Tôi khó mà nhận ra người này... hôm qua tôi có thể đã không chú ý đến anh ta."}]},{"id":"07-s063","type":"exercise","title":"BÀI TẬP 554 (Trang 285)","num":554,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng cấu trúc với мочь/смочь ở dạng cần thiết với động từ hoàn thành hoặc chưa hoàn thành. Viết câu trả lời cho các tình huống."},{"t":"subhead","text":"Gợi ý: Đây là dạng câu dùng hai lần phủ định (не + мочь + не + động từ) để tạo thành nghĩa khẳng định mạnh (chắc chắn là...)."},{"t":"example","text":"Ví dụ: Он не мог не знать. (Anh ta không thể không biết = Anh ta chắc chắn biết)."},{"t":"para","text":"1. Ваш друг боится, что вы не вспомните о его просьбе, вы говорите, что этого не произойдёт, так как вы записали её в блокнот.","b":1},{"t":"para","text":"Trả lời: Я не могу не вспомнить о твоей просьбе."},{"t":"para","text":"Dịch: Tớ không thể nào quên (không nhớ) lời nhờ của cậu được."},{"t":"para","text":"2. Ваш друг вчера плохо себя чувствовал, вас спрашивают, придёт ли он в институт. Вы точно не знаете?","b":1},{"t":"para","text":"Trả lời: Он может не прийти."},{"t":"para","text":"Dịch: Cậu ấy có thể sẽ không đến."},{"t":"para","text":"3. Ваш друг сдавал сегодня экзамен, ваши знакомые предполагают, что он не сдал его и поэтому не звонит.","b":1},{"t":"para","text":"Trả lời: Он не мог не сдать. (Anh ấy giỏi, chắc chắn đỗ). Hoặc nếu đồng tình: Он мог не сдать. (Có thể đã trượt). Tùy ngữ cảnh tin tưởng hay lo lắng."},{"t":"para","text":"Dịch: Cậu ấy không thể nào trượt được (chắc chắn đỗ)."},{"t":"para","text":"4. У вашего знакомого есть ваш адрес, но вы предполагаете, что он не найдёт ваш дом.","b":1},{"t":"para","text":"Trả lời: Он может не найти наш дом."},{"t":"para","text":"Dịch: Cậu ấy có thể sẽ không tìm thấy nhà chúng ta."},{"t":"para","text":"5. Все вокруг говорят, что человек, которому вы безгранично доверяли, обманул вас. Вы не верите.","b":1},{"t":"para","text":"Trả lời: Он не мог меня обмануть."},{"t":"para","text":"Dịch: Anh ấy không thể lừa dối tôi được."},{"t":"para","text":"6. Ваш студент не допи́сал контрольную работу и просит разрешения уйти, так как у него на это время есть талон к врачу.","b":1},{"t":"para","text":"Trả lời: Вы можете не дописывать."},{"t":"para","text":"Dịch: Em có thể không cần viết nốt (được phép đi)."},{"t":"para","text":"7. Разрешите ему это сделать?","b":1},{"t":"para","text":"Trả lời: Я не могу не разрешить. (Tôi buộc phải cho phép/Tôi không thể từ chối)."},{"t":"para","text":"8. Вам предлагают взять с собой в горы вашего знакомого, а другого, более надёжного человека. Вы говорите, что ваш знакомый вас не подведёт.","b":1},{"t":"para","text":"Trả lời: Он не может меня подвести."},{"t":"para","text":"Dịch: Cậu ấy không thể làm tôi thất vọng (không thể phản bội) được."}]},{"id":"07-s064","type":"exercise","title":"BÀI TẬP 555 (Trang 285)","num":555,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền động từ ở thể hoàn thành hoặc chưa hoàn thành. Giải thích sự lựa chọn."},{"t":"para","text":"1. Его́ мо́жно ... часа́ми. Всегда́ мо́жно ... то́чку зре́ния челове́ка, но необяза́тельно с ней соглаша́ться (слу́шать/вы́слушать).","b":1},{"t":"subhead","text":"Đáp án: ... слу́шать ... вы́слушать."},{"t":"para","text":"Dịch: Có thể nghe anh ấy hàng giờ (quá trình). Luôn có thể lắng nghe (nghe cho hết) quan điểm của một người, nhưng không nhất thiết phải đồng ý."},{"t":"para","text":"2. Будь осторо́жен, его́ легко́ мо́жно ... . Мо́жно ... челове́ка, но нельзя́ его́ унижа́ть (обижа́ть/оби́деть).","b":1},{"t":"subhead","text":"Đáp án: ... оби́деть ... оби́деть (hoặc обижать nếu nói chung chung, nhưng thường \"có thể làm tổn thương\" là kết quả → обидеть). Sách: оби́деть ... оби́деть."},{"t":"para","text":"Dịch: Cẩn thận, rất dễ làm anh ấy tổn thương. Có thể làm tổn thương một người (do vô tình), nhưng không được phép hạ nhục họ."},{"t":"para","text":"3. В проце́ссе рабо́ты мо́жно ... э́ти два предложе́ния и вы́брать лу́чшее. Э́ти два предложе́ния ещё мо́жно ..., но после́днее предложе́ние никуда́ не годи́тся (сра́внивать/сравни́ть).","b":1},{"t":"subhead","text":"Đáp án: ... сра́внивать ... сравни́ть."},{"t":"para","text":"Dịch: Trong quá trình làm việc có thể so sánh (thực hiện hành động so sánh) hai câu này... Hai câu này còn có thể so sánh được (có điểm chung - kết quả), nhưng câu cuối thì không dùng được."},{"t":"para","text":"4. Мо́жно с ва́ми ... ? По любо́му вопро́су мо́жно ... с други́ми лю́дьми, но реше́ние всегда́ ну́жно принима́ть самому́ (сове́товаться/посове́товаться).","b":1},{"t":"subhead","text":"Đáp án: ... посове́товаться ... сове́товаться."},{"t":"para","text":"Dịch: Tôi có thể hỏi ý kiến (một lần) bạn được không? Về bất kỳ vấn đề nào cũng có thể tham khảo ý kiến (chung chung) người khác, nhưng phải tự quyết định."},{"t":"para","text":"5. При реше́нии э́той зада́чи мо́жно после́довательно ... разли́чные спо́собы. Како́й ме́тод лу́чше ... при реше́нии э́той зада́чи? (применя́ть/примени́ть).","b":1},{"t":"subhead","text":"Đáp án: ... применя́ть ... примени́ть."},{"t":"para","text":"Dịch: Khi giải bài này có thể áp dụng lần lượt các cách khác nhau (lặp lại). Cách nào tốt nhất để áp dụng (một lần cụ thể) cho bài này?"},{"t":"para","text":"6. Ва́ше предложе́ние мо́жно ... на одно́й страни́це. Мо́жно до хрипоты́ ... свою́ то́чку зре́ния, но е́сли она́ не соотве́тствует действи́тельности, в неё вряд ли кто-нибу́дь пове́рит (излага́ть/изложи́ть).","b":1},{"t":"subhead","text":"Đáp án: ... изложи́ть ... излага́ть."},{"t":"para","text":"Dịch: Đề nghị của bạn có thể trình bày (gọn lại - kết quả) trên một trang giấy. Có thể trình bày/thuyết trình quan điểm đến khản cả cổ (quá trình), nhưng nếu nó không đúng sự thật..."},{"t":"para","text":"7. Мо́жно бесконе́чно ... разли́чные вариа́нты вы́хода из кри́зиса, но ни оди́н из них не бу́дет безболе́зненным. Мо́жно ... не́сколько вариа́нтов вы́хода из э́той ситуа́ции (приду́мывать/приду́мать).","b":1},{"t":"subhead","text":"Đáp án: ... приду́мывать ... приду́мать."},{"t":"para","text":"Dịch: Có thể nghĩ ra/đề xuất mãi (quá trình vô tận) các phương án... Có thể nghĩ ra (kết quả cụ thể) vài phương án thoát khỏi tình huống này."}]},{"id":"07-s065","type":"exercise","title":"Bài 556 (Trang 286)","num":556,"blocks":[{"t":"para","text":"Lý thuyết (trong khung hình chữ nhật):","b":1},{"t":"para","text":"! В сочета́нии со сло́вом нельзя́ глаго́лы несоверше́нного ви́да име́ют значе́ние запреще́ния де́йствия, глаго́лы соверше́нного ви́да — значе́ние невозмо́жности де́йствия.","b":1},{"t":"subhead","text":"Dịch: Khi kết hợp với từ нельзя́ (không được/không thể):"},{"t":"para","text":"Động từ thể chưa hoàn thành (НСВ - несовершенный вид) mang ý nghĩa cấm đoán hành động (không được làm gì)."},{"t":"para","text":"Động từ thể hoàn thành (СВ - совершенный вид) mang ý nghĩa không thể thực hiện hành động (bất khả thi)."},{"t":"instruction","text":"Yêu cầu bài tập: Điền động từ thể hoàn thành hoặc chưa hoàn thành vào chỗ trống. Giải thích sự lựa chọn."},{"t":"para","text":"1. Вблизи́ от бензоколо́нки нельзя́ разжига́ть ого́нь. Спи́чки отсыре́ли и нельзя́ разже́чь ого́нь.","b":1},{"t":"para","text":"(разжига́ть/разже́чь)"},{"t":"para","text":"Dịch: Ở gần cây xăng không được đốt lửa. Diêm bị ẩm rồi và không thể châm lửa được."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Cấm đoán (nguy hiểm) → Dùng НСВ (разжига́ть)."},{"t":"example","text":"Vế 2: Bất khả thi (diêm ẩm) → Dùng СВ (разже́чь)."},{"t":"para","text":"2. В таку́ю холо́дную пого́ду нельзя́ выходи́ть на у́лицу, мо́жно простуди́ться. Из до́ма нельзя́ вы́йти, дверь не открыва́ется.","b":1},{"t":"para","text":"(выходи́ть/вы́йти)"},{"t":"para","text":"Dịch: Trong thời tiết lạnh thế này không được/không nên đi ra đường, có thể bị cảm lạnh. Không thể đi ra khỏi nhà được, cửa không mở ra."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Khuyên ngăn/Cấm đoán → НСВ (выходи́ть)."},{"t":"example","text":"Vế 2: Bất khả thi (cửa hỏng) → СВ (вы́йти)."},{"t":"para","text":"3. В ко́мнате нельзя́ говори́ть гро́мко, за стено́й спит ребёнок. Когда́ он вернётся, то́чно нельзя́ сказа́ть.","b":1},{"t":"para","text":"(говори́ть/сказа́ть)"},{"t":"para","text":"Dịch: Trong phòng không được nói chuyện to, sau bức tường có em bé đang ngủ. Bao giờ anh ấy quay lại thì không thể nói chính xác được."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Cấm đoán → НСВ (говори́ть)."},{"t":"example","text":"Vế 2: Bất khả thi (không biết chắc) → СВ (сказа́ть)."},{"t":"para","text":"4. Нельзя́ безоши́бочно оцени́ть возмо́жности человека по́сле пе́рвой встречи. Нельзя́ челове́ка по его́ слова́м, сле́дует проверя́ть его́ в де́ле.","b":1},{"t":"para","text":"(оце́нивать/оцени́ть)"},{"t":"para","text":"Dịch: Không thể đánh giá chính xác khả năng của con người sau lần gặp đầu tiên. Không được đánh giá con người qua lời nói của họ, cần phải kiểm tra qua việc làm."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Bất khả thi → СВ (оцени́ть)."},{"t":"example","text":"Vế 2: Khuyên ngăn/Cấm đoán → НСВ (оце́нивать)."},{"t":"para","text":"5. На слу́чай нельзя́ полага́ться. Мне не нужны́ таки́е друзья́, на кото́рых в тру́дную мину́ту нельзя́ положи́ться.","b":1},{"t":"para","text":"(полага́ться/положи́ться)"},{"t":"para","text":"Dịch: Không được dựa dẫm vào sự may mắn. Tôi không cần những người bạn mà trong lúc khó khăn không thể dựa cậy vào họ."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Khuyên răn/Cấm đoán → НСВ (полага́ться)."},{"t":"example","text":"Vế 2: Bất khả thi (họ không đáng tin) → СВ (положи́ться)."},{"t":"para","text":"6. Нельзя́ его́ обижа́ть, он слу́шает то́лько себя́ и на мне́ние други́х люде́й не обраща́ет внима́ния. Челове́ка без причи́ны нельзя́ оби́деть.","b":1},{"t":"para","text":"(обижа́ть/оби́деть)"},{"t":"para","text":"Dịch: Không thể làm phật lòng anh ta được (đâu), anh ta chỉ nghe bản thân mình và không để ý đến ý kiến người khác. Không được làm tổn thương người khác mà không có lý do."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Bất khả thi (anh ta trơ lì, không biết giận/không quan tâm) → Ở đây sách có thể có ý \"Không thể xúc phạm\" (СВ) hoặc \"Không nên xúc phạm\" (НСВ). Tuy nhiên, dựa vào ngữ cảnh \"anh ta chỉ nghe mình\", ý là bạn có muốn làm anh ta giận cũng không được/không tác dụng → СВ (оби́деть - sách Glazunova đôi khi đảo vị trí trong bài tập, nhưng theo ngữ cảnh này thì vế 1 mang tính bất khả thi về kết quả tác động tâm lý, còn vế 2 là đạo đức)."},{"t":"note","text":"Lưu ý: Tuy nhiên, đáp án thông thường cho đạo đức là НСВ. Vế 2: \"Không được xúc phạm người khác vô cớ\" → Cấm đoán → НСВ (обижа́ть)."},{"t":"example","text":"Sửa lại cho chuẩn đáp án sách (thường logic đảo chiều):"},{"t":"example","text":"Vế 1: Ngữ cảnh là bất khả thi để làm anh ta thấy bị xúc phạm → оби́деть."},{"t":"example","text":"Vế 2: Ngữ cảnh là đạo đức cấm đoán → обижа́ть."},{"t":"example","text":"Tuy nhiên, trong thực tế câu 1 cũng có thể dùng НСВ nếu mang nghĩa \"Đừng xúc phạm anh ấy, vô ích thôi\". Nhưng để đối lập rõ ràng:"},{"t":"example","text":"Câu 1: Нельзя оби́деть (Không thể làm nó giận được đâu)."},{"t":"example","text":"Câu 2: Нельзя обижа́ть (Không được phép làm tổn thương người ta)."},{"t":"para","text":"7. Нельзя́ прое́хать по э́той доро́ге, она́ размы́та дождём. Нельзя́ е́хать на кра́сный свет, лу́чше подожда́ть зелёного.","b":1},{"t":"para","text":"(е́хать/прое́хать)"},{"t":"para","text":"Dịch: Không thể đi qua con đường này, nó bị mưa làm lầy lội rồi. Không được đi khi đèn đỏ, tốt hơn là đợi đèn xanh."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Bất khả thi (đường hỏng) → СВ (прое́хать)."},{"t":"example","text":"Vế 2: Cấm đoán (luật) → НСВ (е́хать)."},{"t":"para","text":"8. Никому́ и никогда́ нельзя́ крича́ть на себя́. В э́том коллекти́ве нельзя́ себе́ да́же чуть-чуть рассла́биться и отдохну́ть, все сра́зу начина́ют упрека́ть тебя́ в безде́йствии.","b":1},{"t":"para","text":"(позволя́ть/позво́лить)"},{"t":"para","text":"Dịch: Không bao giờ và không ai được phép cho (người khác) hét vào mặt mình. Trong tập thể này không thể cho phép bản thân thư giãn và nghỉ ngơi dù chỉ một chút, mọi người sẽ bắt đầu trách móc bạn lười biếng ngay."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Cấm đoán (nguyên tắc sống) → НСВ (позволя́ть)."},{"t":"example","text":"Vế 2: Bất khả thi (hoàn cảnh không cho phép) → СВ (позво́лить)."}]},{"id":"07-s066","type":"exercise","title":"Bài 557 (Trang 286-287)","num":557,"blocks":[{"t":"para","text":"Lý thuyết (trong khung hình chữ nhật):","b":1},{"t":"para","text":"! На́до + глаго́л несоверше́нного ви́да ука́зывает на приглаше́ние нача́ть де́йствие; на́до + глаго́л соверше́нного ви́да — на необходи́мость достиже́ния результа́та.","b":1},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"На́до + động từ thể chưa hoàn thành (НСВ) chỉ sự mời gọi/nhắc nhở bắt đầu hành động (hoặc hành động cần làm như một quy trình)."},{"t":"para","text":"На́до + động từ thể hoàn thành (СВ) chỉ sự cần thiết phải đạt được kết quả."},{"t":"instruction","text":"Yêu cầu: Mở ngoặc, chọn thể động từ đúng."},{"t":"para","text":"1. Ско́ро коне́ц рабо́чего дня, на́до зака́нчивать рабо́ту.","b":1},{"t":"para","text":"(зака́нчивать/зако́нчить)"},{"t":"para","text":"Dịch: Sắp hết ngày làm việc rồi, cần phải kết thúc công việc thôi (bắt đầu quy trình kết thúc)."},{"t":"example","text":"Giải thích: Ngữ cảnh \"sắp hết giờ\", nhắc nhở bắt đầu thu xếp để nghỉ → НСВ (зака́нчивать). Lưu ý: Nếu muốn nhấn mạnh \"phải làm xong ngay\" thì dùng СВ, nhưng \"skoro konets\" thường gợi ý bắt đầu dọn dẹp."},{"t":"para","text":"2. Я не смогу́ пойти́ с тобо́й, мне на́до сего́дня сочине́ние, ина́че получу́ дво́йку.","b":1},{"t":"para","text":"(писа́ть/написа́ть)"},{"t":"para","text":"Dịch: Tớ không đi với cậu được, hôm nay tớ cần phải viết xong bài luận, nếu không sẽ bị điểm 2."},{"t":"example","text":"Giải thích: Cần kết quả (để không bị điểm kém) → СВ (написа́ть)."},{"t":"para","text":"3. На у́лице дождь, на́до взять зо́нтик. Не на́до брать зо́нтик, сего́дня он нам не пона́добится.","b":1},{"t":"para","text":"(брать/взять)"},{"t":"para","text":"Dịch: Ngoài trời đang mưa, cần phải cầm ô theo. Không cần mang ô đâu, hôm nay chúng ta không cần đến nó."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Cần kết quả (có ô để che) → СВ (взять)."},{"t":"example","text":"Vế 2: Не надо + НСВ (không cần thiết làm gì) → (брать)."},{"t":"para","text":"4. На́до да́льше от родны́х, что́бы поня́ть, как мно́го ты поте́рял.","b":1},{"t":"para","text":"(уезжа́ть/уе́хать)"},{"t":"para","text":"Dịch: Cần phải đi xa khỏi người thân thì mới hiểu được bạn đã mất mát nhiều thế nào."},{"t":"example","text":"Giải thích: Nhấn mạnh kết quả của việc đi xa → СВ (уе́хать)."},{"t":"para","text":"5. Уже́ во́семь часо́в ве́чера, на́до е́хать домо́й.","b":1},{"t":"para","text":"(е́хать/уе́хать)"},{"t":"para","text":"Dịch: Đã 8 giờ tối rồi, cần phải đi về nhà thôi (bắt đầu di chuyển)."},{"t":"example","text":"Giải thích: Lời nhắc nhở bắt đầu hành động → НСВ (е́хать)."},{"t":"para","text":"6. Пре́жде чем принима́ть оконча́тельное реше́ние, на́до посове́товаться с друзья́ми.","b":1},{"t":"para","text":"(сове́товаться/посове́товаться)"},{"t":"para","text":"Dịch: Trước khi đưa ra quyết định cuối cùng, cần phải tham khảo ý kiến/hội ý với bạn bè."},{"t":"example","text":"Giải thích: Cần đạt được kết quả là có lời khuyên → СВ (посове́товаться)."},{"t":"para","text":"7. Всегда́ на́до извиня́ться с други́ми людьми́, что́бы избега́ть оши́бок.","b":1},{"t":"vocab","ru":"(извиня́ться/извини́ться) - Lỗi trong sách gốc","vi":"Câu này văn cảnh có vẻ là \"считаться\" (tính đến/quan tâm) hoặc động từ khác. Nhưng nếu đề bài bắt chọn từ извиня́ться (xin lỗi) thì không hợp lý với \"để tránh sai lầm\".","g":null},{"t":"example","text":"Phân tích lại: Có thể sách in nhầm từ советоваться (hội ý) ở câu trước? Hay là считаться?"},{"t":"para","text":"Tuy nhiên, nếu nhìn vào danh sách động từ ở cuối câu trong ngoặc đơn ở bản gốc (nếu có), ta mới biết chính xác. Dựa vào ngữ cảnh \"để tránh sai lầm\", động từ phù hợp là считаться (tính đến ý kiến). Nếu bắt buộc dùng từ trong bài, ta hãy xem câu 7."},{"t":"example","text":"Correction: Nhìn vào trang 287, câu 7 bài 557 gốc là: \"Всегда́ на́до ... с други́ми людьми́, что́бы избега́ть оши́бок\". Động từ gợi ý là: (счита́ться/посчита́ться)."},{"t":"para","text":"Dịch: Luôn cần phải tính đến/tôn trọng người khác để tránh sai lầm."},{"t":"example","text":"Giải thích: \"Luôn luôn\" (quy tắc chung) → НСВ (счита́ться)."},{"t":"para","text":"8. На́до извини́ться пе́ред ни́ми.","b":1},{"t":"para","text":"(извиня́ться/извини́ться)"},{"t":"para","text":"Dịch: Cần phải xin lỗi họ (kết quả cụ thể)."},{"t":"example","text":"Giải thích: Cần thực hiện hành động để đạt kết quả hòa giải → СВ (извини́ться)."},{"t":"para","text":"9. Ско́ро у меня́ день рожде́ния, на́до пригласи́ть госте́й.","b":1},{"t":"para","text":"(приглаша́ть/пригласи́ть)"},{"t":"para","text":"Dịch: Sắp đến sinh nhật tôi, cần phải mời khách."},{"t":"example","text":"Giải thích: Cần kết quả (khách được mời) → СВ (пригласи́ть)."},{"t":"para","text":"10. Тебе́ на́до отдохну́ть от тако́го мно́го вре́мени.","b":1},{"t":"example","text":"Lỗi sách gốc: \"от такого много времени\" không có nghĩa. Có lẽ là \"так много\"."},{"t":"para","text":"Động từ gợi ý: (отдыха́ть/отдохну́ть)."},{"t":"para","text":"Dịch: Bạn cần nghỉ ngơi sau chừng ấy thời gian."},{"t":"example","text":"Giải thích: Cần kết quả hồi phục sức khỏe → СВ (отдохну́ть)."},{"t":"para","text":"11. Хо́чешь не хо́чешь, а на́до кварти́ру убра́ть.","b":1},{"t":"para","text":"(убира́ть/убра́ть)"},{"t":"para","text":"Dịch: Muốn hay không thì cũng phải dọn xong cái nhà."},{"t":"example","text":"Giải thích: Cần hoàn thành công việc (kết quả) → СВ (убра́ть)."},{"t":"vocab","ru":"На́до ремо́нт","vi":"чем ра́ньше мы его́ начнём, тем быстре́е зако́нчим.","g":null},{"t":"para","text":"(де́лать/сде́лать)"},{"t":"para","text":"Dịch: Cần phải làm sửa chữa: chúng ta bắt đầu càng sớm thì xong càng nhanh."},{"t":"example","text":"Giải thích: Nhấn mạnh vào việc bắt đầu thực hiện quá trình → НСВ (де́лать)."},{"t":"para","text":"13. На́до ремо́нт до прие́зда роди́телей.","b":1},{"t":"para","text":"(де́лать/сде́лать)"},{"t":"para","text":"Dịch: Cần phải làm xong việc sửa chữa trước khi bố mẹ đến."},{"t":"example","text":"Giải thích: Cần kết quả hoàn tất → СВ (сде́лать)."},{"t":"para","text":"14. Мой друг заболе́л, на́до врачу́ позвони́ть.","b":1},{"t":"para","text":"(звони́ть/позвони́ть)"},{"t":"para","text":"Dịch: Bạn tôi bị ốm, cần phải gọi cho bác sĩ."},{"t":"example","text":"Giải thích: Hành động cụ thể cần kết quả (bác sĩ đến) → СВ (позвони́ть)."},{"t":"para","text":"15. У него́ подняла́сь температу́ра, ждать бо́льше нельзя́, на́до врачу́ позвони́ть.","b":1},{"t":"para","text":"(звони́ть/позвони́ть)"},{"t":"para","text":"Dịch: Nhiệt độ cậu ấy tăng cao, không thể đợi thêm nữa, cần phải gọi bác sĩ ngay."},{"t":"example","text":"Giải thích: Tương tự, cần kết quả cấp bách → СВ (позвони́ть)."}]},{"id":"07-s067","type":"exercise","title":"Bài 558 (Trang 287)","num":558,"blocks":[{"t":"para","text":"Lý thuyết (trong khung hình chữ nhật):","b":1},{"t":"para","text":"! С глаго́лами прихо́дится, приходи́лось то́лько глаго́лы несоверше́нного ви́да. С глаго́лами придётся, пришло́сь — глаго́лы несоверше́нного и совершенного ви́да.","b":1},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Với các động từ прихо́дится (đành phải - hiện tại), приходи́лось (đã đành phải - quá khứ, lặp lại): chỉ dùng động từ thể chưa hoàn thành (НСВ)."},{"t":"para","text":"Với các động từ придётся (sẽ phải - tương lai), пришло́сь (đã phải - quá khứ, 1 lần): dùng được cả НСВ và СВ."},{"t":"instruction","text":"Yêu cầu: Chọn từ trong ngoặc (chú ý thể động từ) để điền vào chỗ trống."},{"t":"para","text":"1. Я уезжа́ю в Новосиби́рск двадца́того сентября́, мне прихо́дится покупа́ть биле́т зара́нее.","b":1},{"t":"para","text":"(покупа́ть/купи́ть)"},{"t":"para","text":"Dịch: Tôi đi Novosibirsk vào ngày 20 tháng 9, tôi đành phải mua vé trước."},{"t":"example","text":"Giải thích: Приходится + НСВ → покупа́ть."},{"t":"para","text":"2. До конца́ рабо́чего дня я не успе́ю всё зако́нчить, придётся заде́рживаться/задержа́ться.","b":1},{"t":"para","text":"(заде́рживаться/задержа́ться)"},{"t":"para","text":"Dịch: Đến cuối ngày làm việc tôi không kịp làm xong hết, sẽ phải ở lại muộn."},{"t":"example","text":"Giải thích: Придётся có thể đi với cả 2 thể. Ở đây nói về một tình huống cụ thể sắp tới → СВ (задержа́ться) là tự nhiên nhất. Nhưng НСВ cũng không sai nếu nhấn mạnh quá trình \"phải ở lại\". Đáp án ưu tiên: задержа́ться."},{"t":"para","text":"3. В ко́мнате ду́шно, пришло́сь откры́ть фо́рточку.","b":1},{"t":"para","text":"(открыва́ть/откры́ть)"},{"t":"para","text":"Dịch: Trong phòng bí hơi, đã phải mở cửa thông gió."},{"t":"example","text":"Giải thích: Hành động 1 lần, kết quả cụ thể trong quá khứ → СВ (откры́ть)."},{"t":"para","text":"4. До отхо́да по́езда оста́лось де́сять мину́т, пришло́сь поспеши́ть.","b":1},{"t":"para","text":"(спеши́ть/поспеши́ть)"},{"t":"para","text":"Dịch: Chỉ còn 10 phút nữa là tàu chạy, đã phải nhanh chân/vội vàng lên."},{"t":"example","text":"Giải thích: Kết quả, hành động dứt khoát → СВ (поспеши́ть)."},{"t":"para","text":"5. Ему́ бы́ло тру́дно идти́, и нам приходи́лось остана́вливаться и отдыха́ть.","b":1},{"t":"para","text":"(остана́вливаться/останови́ться)"},{"t":"para","text":"Dịch: Anh ấy đi lại khó khăn, và chúng tôi đã (liên tục) phải dừng lại và nghỉ ngơi."},{"t":"example","text":"Giải thích: Приходилось (quá khứ lặp lại/kéo dài) + НСВ → остана́вливаться."},{"t":"para","text":"6. Вчера́ я пло́хо себя́ чу́вствовал, и мне пришло́сь пропусти́ть заня́тия.","b":1},{"t":"para","text":"(пропуска́ть/пропусти́ть)"},{"t":"para","text":"Dịch: Hôm qua tôi cảm thấy không khỏe, và tôi đã phải nghỉ học."},{"t":"example","text":"Giải thích: Sự kiện 1 lần trong quá khứ, kết quả → СВ (пропусти́ть)."},{"t":"para","text":"7. На ваш докуме́нт на́до поста́вить печа́ть, ина́че он недействи́телен.","b":1},{"t":"para","text":"(ста́вить/поста́вить)"},{"t":"para","text":"Dịch: Cần phải đóng dấu vào tài liệu của ông, nếu không nó không có giá trị."},{"t":"example","text":"Giải thích: Cần kết quả (con dấu nằm trên giấy) → СВ (поста́вить)."},{"t":"para","text":"8. Тебе́ пришло́сь отложи́ть все развлече́ния и занима́ться то́лько дела́ми.","b":1},{"t":"para","text":"(откла́дывать/отложи́ть); (занима́ться/заня́ться)"},{"t":"para","text":"Dịch: Bạn đã phải gác lại mọi thú vui và chỉ tập trung làm việc."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Gác lại: Kết quả dứt khoát → СВ (отложи́ть)."},{"t":"example","text":"Làm việc: Quá trình kéo dài → НСВ (занима́ться)."},{"t":"para","text":"9. К телефо́ну никто́ не подхо́дит, на́до прове́рить, пра́вильно ли я записа́л но́мер.","b":1},{"t":"para","text":"(проверя́ть/прове́рить)"},{"t":"para","text":"Dịch: Không ai bắt máy cả, cần phải kiểm tra xem tôi ghi số có đúng không."},{"t":"example","text":"Giải thích: Cần kết quả kiểm tra → СВ (прове́рить)."},{"t":"para","text":"10. Извини́те, я до́лжен идти́, придётся отложи́ть на́шу бесе́ду.","b":1},{"t":"para","text":"(откла́дывать/отложи́ть)"},{"t":"para","text":"Dịch: Xin lỗi, tôi phải đi rồi, sẽ phải hoãn cuộc trò chuyện của chúng ta lại."},{"t":"example","text":"Giải thích: Kết quả cụ thể trong tương lai → СВ (отложи́ть)."},{"t":"para","text":"11. На́до позвони́ть твоему́ дру́гу и пригласи́ть его́ за́втра к нам в го́сти.","b":1},{"t":"para","text":"(звони́ть/позвони́ть); (приглаша́ть/пригласи́ть)"},{"t":"para","text":"Dịch: Cần phải gọi điện cho bạn của cậu và mời cậu ấy ngày mai đến nhà mình chơi."},{"t":"example","text":"Giải thích: Cần thực hiện hành động để có kết quả → Cả hai đều СВ (позвони́ть, пригласи́ть)."},{"t":"para","text":"12. Сне́гу бы́ло по коле́но, и приходи́лось ступа́ть след в след, что́бы не тра́тить си́лы.","b":1},{"t":"para","text":"(ступа́ть/ступи́ть)"},{"t":"para","text":"Dịch: Tuyết dày đến đầu gối, và đành phải bước theo dấu chân người trước để không mất sức."},{"t":"example","text":"Giải thích: Приходилось (lặp đi lặp lại hành động bước) + НСВ → ступа́ть."},{"t":"para","text":"13. Так хо́чется пое́хать с друзья́ми за́ город, но на́до гото́виться к экза́менам.","b":1},{"t":"para","text":"(гото́виться/подгото́виться)"},{"t":"para","text":"Dịch: Rất muốn đi ngoại ô với bạn bè, nhưng cần phải ôn thi."},{"t":"example","text":"Giải thích: Ôn thi là một quá trình dài → НСВ (гото́виться)."},{"t":"para","text":"14. Нам на́до сесть и обсуди́ть пла́ны на ле́то.","b":1},{"t":"para","text":"(сади́ться/сесть); (обсужда́ть/обсуди́ть)"},{"t":"para","text":"Dịch: Chúng ta cần phải ngồi xuống và thảo luận kế hoạch hè."},{"t":"example","text":"Giải thích: Cần hành động cụ thể để ra kết quả → СВ (сесть, обсуди́ть)."},{"t":"para","text":"15. Он мой мла́дший брат, и мне придётся ему́ уступи́ть.","b":1},{"t":"para","text":"(уступа́ть/уступи́ть)"},{"t":"para","text":"Dịch: Nó là em trai tôi, và tôi sẽ phải nhường nó thôi."},{"t":"example","text":"Giải thích: Kết quả của sự nhượng bộ → СВ (уступи́ть)."}]},{"id":"07-s068","type":"exercise","title":"Bài 559 (Trang 288)","num":559,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng cấu trúc где? (не) при́нято что де́лать? (Ở đâu? (không) có thói quen/quy tắc làm gì?), hãy kể về gia đình bạn hoặc đất nước bạn. (Bài tập này yêu cầu viết lại câu dựa trên gợi ý)."},{"t":"model","text":"Mẫu: В не́которых се́мьях обе́дают ве́чером. (Ở một số gia đình người ta ăn tối vào buổi chiều muộn). → В на́шей семье́ (Среди́ чле́нов на́шей семьи́) при́нято обе́дать днём. (Trong gia đình tôi / Giữa các thành viên gia đình tôi, có thói quen ăn bữa chính vào ban ngày)."},{"t":"para","text":"Chuyển đổi các câu sau:","b":1},{"t":"para","text":"1. В Росси́и к незнако́мым лю́дям обраща́ются на “вы”.","b":1},{"t":"para","text":"Viết lại: В Росси́и при́нято обраща́ться к незнако́мым лю́дям на “вы”."},{"t":"para","text":"Dịch: Ở Nga, người ta có quy tắc xưng hô \"ngài/ông/bà\" (Ngôi \"Vy\" lịch sự) với người lạ."},{"t":"para","text":"2. Мой друзья́ обы́чно не звоня́т нам пе́ред тем, как зайти́.","b":1},{"t":"para","text":"Viết lại: У мои́х друзе́й не при́нято звони́ть пе́ред тем, как зайти́."},{"t":"para","text":"Dịch: Bạn bè tôi thường không có thói quen gọi điện trước khi ghé chơi."},{"t":"para","text":"3. Колле́ги по рабо́те не звоня́т мне домо́й по́сле десяти́ часо́в ве́чера.","b":1},{"t":"para","text":"Viết lại: Среди́ колле́г по рабо́те не при́нято звони́ть домо́й по́сле десяти́ часо́в ве́чера."},{"t":"para","text":"Dịch: Giữa các đồng nghiệp, không có thói quen gọi về nhà sau 10 giờ tối."},{"t":"para","text":"4. В на́шей семье́ отмеча́ют все пра́здники до́ма.","b":1},{"t":"para","text":"Viết lại: В на́шей семье́ при́нято отмеча́ть все пра́здники до́ма."},{"t":"para","text":"Dịch: Trong gia đình tôi, có truyền thống tổ chức mọi ngày lễ tại nhà."},{"t":"para","text":"5. В осо́бо торже́ственных слу́чаях мы хо́дим в рестора́ны.","b":1},{"t":"para","text":"Viết lại: В осо́бо торже́ственных слу́чаях у нас при́нято ходи́ть в рестора́ны."},{"t":"para","text":"Dịch: Vào những dịp đặc biệt trang trọng, chúng tôi thường có thói quen đi nhà hàng."},{"t":"para","text":"6. Мужчи́ны обы́чно снима́ют голово́й убо́р в помеще́нии, а же́нщины мо́гут остава́ться в шля́пах.","b":1},{"t":"para","text":"Viết lại: У мужчи́н при́нято снима́ть голово́й убо́р в помеще́нии, а же́нщинам разрешено́ остава́ться в шля́пах (hoặc: у же́нщин не при́нято снима́ть...)."},{"t":"para","text":"Dịch: Đàn ông có quy tắc phải bỏ mũ khi ở trong nhà, còn phụ nữ thì có thể vẫn đội mũ."},{"t":"para","text":"7. У не́которых мои́х знако́мых есть привы́чка снача́ла сказа́ть, а пото́м поду́мать о том, что они́ сказа́ли.","b":1},{"t":"para","text":"Viết lại: У не́которых мои́х знако́мых при́нято снача́ла сказа́ть, а пото́м ду́мать."},{"t":"para","text":"Dịch: Một số người quen của tôi có thói quen nói trước rồi mới nghĩ sau."},{"t":"para","text":"8. В на́шей гру́ппе не пропуска́ют заня́тия без уважи́тельной причи́ны.","b":1},{"t":"para","text":"Viết lại: В на́шей гру́ппе не при́нято пропуска́ть заня́тия без уважи́тельной причи́ны."},{"t":"para","text":"Dịch: Trong nhóm (lớp) của tôi, không có thói quen nghỉ học mà không có lý do chính đáng."},{"t":"example","text":"(Lưu ý: \"при́нято\" đi với động từ НСВ nếu chỉ thói quen lặp lại, nhưng ngữ cảnh này là quy tắc chung)."}]},{"id":"07-s069","type":"exercise","title":"Bài 560 (Trang 288)","num":560,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc và ghi nhớ các động từ yêu cầu theo sau là động từ nguyên thể НСВ hoặc СВ. Đặt câu với chúng."},{"t":"para","text":"Bảng ngữ pháp:","b":1},{"t":"table","rows":[["Động từ yêu cầu theo sau là НСВ","Dịch nghĩa","Động từ yêu cầu theo sau là СВ","Dịch nghĩa"],["1) начина́ть/нача́ть","bắt đầu","1) остава́ться/оста́ться","còn lại (phải làm gì)"],["продолжа́ть/продо́лжить","tiếp tục","(Мне оста́лось...)","(Tôi còn phải...)"],["конча́ть/ко́нчить","kết thúc","",""],["2) перестава́ть/переста́ть","ngừng, thôi","2) успева́ть/успе́ть","kịp làm gì"],["3) привыка́ть/привы́кнуть","quen với","",""],["отвыка́ть/отвы́кнуть","bỏ thói quen","3) удава́ться/уда́ться","thành công/làm được"],["4) учи́ться/научи́ться","học làm gì","(Мне удало́сь...)","(Tôi đã làm được...)"],["5) нра́виться/понра́виться","thích làm gì","",""],["(Мне нра́вится...)","(Tôi thích...)","4) забыва́ть/забы́ть","quên (làm gì đó - kết quả)"],["надоеда́ть/надое́сть","chán ngấy","",""],["(Мне надое́ло...)","(Tôi chán...)","",""],["6) устава́ть/уста́ть","mệt mỏi khi làm gì","",""],["7) уме́ть","biết (kỹ năng)","",""]]},{"t":"para","text":"Đặt câu ví dụ (theo yêu cầu \"làm bài tập\"):","b":1},{"t":"para","text":"Nhóm 1: Yêu cầu НСВ (Chỉ quá trình, thói quen, giai đoạn)","b":1},{"t":"subhead","text":"начина́ть/нача́ть:","b":1},{"t":"para","text":"Мы нача́ли изуча́ть ру́сский язы́к два го́да наза́д."},{"t":"para","text":"(Chúng tôi đã bắt đầu học tiếng Nga hai năm trước.)"},{"t":"subhead","text":"продолжа́ть/продо́лжить:","b":1},{"t":"para","text":"Они́ продолжа́ют спо́рить о поли́тике."},{"t":"para","text":"(Họ vẫn tiếp tục tranh luận về chính trị.)"},{"t":"subhead","text":"конча́ть/ко́нчить:","b":1},{"t":"para","text":"Я ко́нчил чита́ть э́ту кни́гу вчера́."},{"t":"para","text":"(Tôi đã đọc xong cuốn sách này hôm qua.)"},{"t":"subhead","text":"перестава́ть/переста́ть:","b":1},{"t":"para","text":"Дождь переста́л идти́."},{"t":"para","text":"(Mưa đã ngừng rơi.)"},{"t":"subhead","text":"привыка́ть/привы́кнуть:","b":1},{"t":"para","text":"Я уже́ привы́к встава́ть ра́но."},{"t":"para","text":"(Tôi đã quen dậy sớm.)"},{"t":"subhead","text":"учи́ться/научи́ться:","b":1},{"t":"para","text":"Мой брат у́чится води́ть маши́ну."},{"t":"para","text":"(Em trai tôi đang học lái xe.)"},{"t":"subhead","text":"нра́виться/понра́виться:","b":1},{"t":"para","text":"Мне нра́вится гуля́ть в па́рке."},{"t":"para","text":"(Tôi thích đi dạo trong công viên.)"},{"t":"subhead","text":"надоеда́ть/надое́сть:","b":1},{"t":"para","text":"Ему́ надое́ло сиде́ть до́ма."},{"t":"para","text":"(Anh ấy đã chán ngấy việc ngồi ở nhà.)"},{"t":"subhead","text":"устава́ть/уста́ть:","b":1},{"t":"para","text":"Ба́бушка бы́стро устаёт ходи́ть."},{"t":"para","text":"(Bà tôi rất nhanh mệt khi đi bộ.)"},{"t":"subhead","text":"уме́ть:","b":1},{"t":"para","text":"Ты уме́ешь пла́вать?"},{"t":"para","text":"(Bạn có biết bơi không?)"},{"t":"para","text":"Nhóm 2: Yêu cầu СВ (Chỉ kết quả, sự việc cụ thể)","b":1},{"t":"subhead","text":"остава́ться/оста́ться:","b":1},{"t":"para","text":"Нам оста́лось купи́ть то́лько хлеб."},{"t":"para","text":"(Chúng tôi chỉ còn phải mua mỗi bánh mì nữa thôi.)"},{"t":"subhead","text":"успева́ть/успе́ть:","b":1},{"t":"para","text":"Мы успе́ли сде́лать зада́ние во́время."},{"t":"para","text":"(Chúng tôi đã kịp làm xong bài tập đúng hạn.)"},{"t":"subhead","text":"удава́ться/уда́ться:","b":1},{"t":"para","text":"Мне не удало́сь дозвони́ться до него́."},{"t":"para","text":"(Tôi đã không thể (không thành công) gọi điện được cho anh ấy.)"},{"t":"subhead","text":"забыва́ть/забы́ть:","b":1},{"t":"para","text":"Он забы́л закры́ть дверь."},{"t":"para","text":"(Anh ấy đã quên đóng cửa.)"},{"t":"note","text":"Lưu ý: Забывать (НСВ) có thể đi với НСВ nếu là thói quen (Он часто забывает закрывать дверь - Anh ấy hay quên đóng cửa). Nhưng \"Забыть\" (СВ) thường đi với СВ (quên làm một việc cụ thể)."}]},{"id":"07-s070","type":"exercise","title":"Bài 561 (Trang 289)","num":561,"blocks":[{"t":"para","text":"Chủ điểm ngữ pháp: Thể động từ trong câu nguyên mẫu (Инфинитив)."},{"t":"vocab","ru":"СВ (Thể hoàn thành)","vi":"Dùng để chỉ hành động đạt được kết quả cụ thể, hành động xảy ra một lần, hoặc sự bất khả thi (khi đi với нельзя).","g":null},{"t":"vocab","ru":"НСВ (Thể chưa hoàn thành)","vi":"Dùng để chỉ hành động như một quá trình, hành động lặp lại, sự cho phép/cấm đoán (khi đi với можно/нельзя), hoặc không cần thiết phải làm (khi đi với не надо/не обязательно).","g":null},{"t":"instruction","text":"Yêu cầu: Mở ngoặc, sử dụng động từ nguyên mẫu ở thể hoàn thành (СВ) hoặc chưa hoàn thành (НСВ). Giải thích sự lựa chọn."},{"t":"para","text":"1. Мо́жно (брать/взять) ключ от аудито́рии?","b":1},{"t":"subhead","text":"Đáp án: взять","b":1},{"t":"para","text":"Dịch: Em có thể lấy chìa khóa giảng đường được không ạ?"},{"t":"para","text":"Giải thích: Đây là câu xin phép thực hiện một hành động cụ thể một lần để đạt kết quả (lấy được chìa khóa) → Dùng СВ (взять)."},{"t":"para","text":"2. Мы должны́ сего́дня (принима́ть/приня́ть) реше́ние.","b":1},{"t":"subhead","text":"Đáp án: приня́ть","b":1},{"t":"para","text":"Dịch: Hôm nay chúng ta phải đưa ra (được) quyết định."},{"t":"para","text":"Giải thích: Cần đạt được kết quả là \"có quyết định\" trong hôm nay → Dùng СВ (приня́ть)."},{"t":"para","text":"3. Нельзя́ (позволя́ть/позво́лить) ему́ де́лать всё, что ему́ взду́мается.","b":1},{"t":"subhead","text":"Đáp án: позволя́ть","b":1},{"t":"para","text":"Dịch: Không được cho phép nó làm tất cả những gì nó muốn."},{"t":"example","text":"Giải thích: Нельзя + НСВ mang nghĩa cấm đoán chung (nguyên tắc không được làm thế) → Dùng НСВ (позволя́ть)."},{"t":"para","text":"4. Он гото́в (выполня́ть/вы́полнить) са́мую чёрную рабо́ту, что́бы получи́ть хоро́ший результа́т.","b":1},{"t":"subhead","text":"Đáp án: выполня́ть (hoặc вы́полнить tùy nhấn mạnh, nhưng ở đây nhấn mạnh sự sẵn sàng làm việc vất vả)."},{"t":"note","text":"Lưu ý: Tuy nhiên, ngữ cảnh \"để đạt kết quả tốt\" thường hướng tới việc hoàn thành công việc. Nhưng cụm \"самую черную работу\" (công việc đen tối/vất vả nhất) thường nói về tính chất công việc (quá trình)."},{"t":"subhead","text":"Đáp án tối ưu: выполня́ть (nhấn mạnh anh ta sẵn sàng làm loại công việc đó). Nếu nhấn mạnh \"làm cho xong\" thì dùng вы́полнить. Sách bài tập thường ưu tiên выполня́ть (sẵn sàng tham gia quá trình)."},{"t":"para","text":"Dịch: Anh ấy sẵn sàng làm những công việc vất vả nhất để đạt được kết quả tốt."},{"t":"para","text":"5. Мо́жно (сомнева́ться/усомни́ться) в том, что он спра́вится с э́той рабо́той.","b":1},{"t":"subhead","text":"Đáp án: сомнева́ться","b":1},{"t":"para","text":"Dịch: Có thể nghi ngờ việc anh ấy sẽ xoay xở được với công việc này."},{"t":"para","text":"Giải thích: \"Nghi ngờ\" là một trạng thái tâm lý kéo dài → Dùng НСВ (сомнева́ться)."},{"t":"para","text":"6. Ско́ро приду́т го́сти, на́до (накрыва́ть/накры́ть) стол.","b":1},{"t":"subhead","text":"Đáp án: накры́ть (hoặc накрыва́ть với nghĩa bắt đầu)."},{"t":"example","text":"Giải thích: Vì khách \"sắp đến\" (kết quả sắp xảy ra), ta cần hoàn tất việc dọn bàn → Ưu tiên СВ (накры́ть). Tuy nhiên, надо + НСВ cũng dùng để giục giã \"bắt đầu làm đi\". Trong ngữ cảnh thi cử/bài tập, накры́ть (để có bàn ăn sẵn sàng) thường được chọn."},{"t":"para","text":"Dịch: Khách sắp đến rồi, cần phải dọn bàn ăn thôi."},{"t":"para","text":"7. Коне́чно, мо́жно (говори́ть/сказа́ть) открове́нно всё, что ты ду́маешь, но нельзя́ (говори́ть/сказа́ть) гру́бости.","b":1},{"t":"subhead","text":"Đáp án: говори́ть / говори́ть"},{"t":"para","text":"Dịch: Tất nhiên, có thể nói thẳng thắn mọi điều bạn nghĩ (cho phép một cách cư xử), nhưng không được nói những lời thô lỗ (cấm đoán)."},{"t":"para","text":"Giải thích: Cả hai vế đều chỉ quy tắc ứng xử chung → Dùng НСВ (говори́ть)."},{"t":"para","text":"8. Э́ту зада́чу ты мо́жешь не (реша́ть/реши́ть), но ты до́лжен её (спи́сывать/списа́ть) у сосе́да, ина́че получи́шь “два”.","b":1},{"t":"subhead","text":"Đáp án: реша́ть / списа́ть"},{"t":"para","text":"Dịch: Bài toán này em có thể không cần giải (không cần thực hiện hành động - НСВ), nhưng em phải chép nó từ bạn bên cạnh (cần kết quả có bài - СВ), nếu không sẽ bị điểm 2."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Можешь не + НСВ","vi":"Không bắt buộc làm gì.","g":null},{"t":"vocab","ru":"Должен + СВ","vi":"Bắt buộc phải có kết quả.","g":null},{"t":"para","text":"9. Нельзя́ (тра́тить/потра́тить) вре́мя на пустяки́.","b":1},{"t":"subhead","text":"Đáp án: тра́тить","b":1},{"t":"para","text":"Dịch: Không được lãng phí thời gian vào những chuyện vặt vãnh."},{"t":"para","text":"Giải thích: Cấm đoán, khuyên răn chung → Dùng НСВ (тра́тить)."},{"t":"para","text":"10. Я наме́рен (доводи́ть/довести́) э́то де́ло до конца́.","b":1},{"t":"subhead","text":"Đáp án: довести́","b":1},{"t":"para","text":"Dịch: Tôi dự định đưa vụ việc này đến cùng (hoàn thành nó)."},{"t":"para","text":"Giải thích: Ý định đạt được kết quả cuối cùng → Dùng СВ (довести́)."},{"t":"para","text":"11. На э́тот спекта́кль нельзя́ (достава́ть/доста́ть) биле́ты.","b":1},{"t":"subhead","text":"Đáp án: доста́ть","b":1},{"t":"para","text":"Dịch: Vở kịch này không thể kiếm được vé đâu (bất khả thi)."},{"t":"example","text":"Giải thích: Нельзя + СВ mang nghĩa \"không thể\" (impossibility) → (доста́ть)."},{"t":"para","text":"12. Пожа́луй, я скло́нен (принима́ть/приня́ть) ва́ше предложе́ние.","b":1},{"t":"subhead","text":"Đáp án: приня́ть","b":1},{"t":"para","text":"Dịch: Có lẽ tôi nghiêng về việc chấp nhận lời đề nghị của ông."},{"t":"para","text":"Giải thích: Quyết định thực hiện hành động dứt điểm (chốt đơn) → Dùng СВ (приня́ть)."},{"t":"para","text":"13. Мы пришли́ (проверя́ть/прове́рить) ва́шу рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: прове́рить","b":1},{"t":"para","text":"Dịch: Chúng tôi đến để kiểm tra công việc của các bạn (đến để hoàn thành việc kiểm tra)."},{"t":"example","text":"Giải thích: Mục đích của việc đến là đạt kết quả kiểm tra → Dùng СВ (прове́рить). (Dùng проверять nếu muốn nói \"chúng tôi đến và sẽ ngồi kiểm tra suốt\")."},{"t":"para","text":"14. На на́шем предприя́тии мо́жно (рабо́тать/порабо́тать) без переры́ва и уйти́ домо́й на час ра́ньше.","b":1},{"t":"subhead","text":"Đáp án: рабо́тать","b":1},{"t":"para","text":"Dịch: Ở xí nghiệp chúng tôi, có thể làm việc không nghỉ và về nhà sớm một tiếng."},{"t":"para","text":"Giải thích: Chỉ quy định, chế độ làm việc (quá trình) → Dùng НСВ (рабо́тать)."},{"t":"para","text":"15. С на́ми всегда́ мо́жно (обсужда́ть/обсуди́ть) все ва́ши пробле́мы.","b":1},{"t":"subhead","text":"Đáp án: обсужда́ть","b":1},{"t":"para","text":"Dịch: Với chúng tôi, lúc nào cũng có thể thảo luận mọi vấn đề của bạn."},{"t":"example","text":"Giải thích: Từ всегда (luôn luôn) gợi ý tính lặp lại/thường xuyên → Dùng НСВ (обсужда́ть)."},{"t":"para","text":"16. Мо́жете не (сообща́ть/сообщи́ть) мне о ва́шем реше́нии, я его́ уже́ зна́ю.","b":1},{"t":"subhead","text":"Đáp án: сообща́ть","b":1},{"t":"para","text":"Dịch: Bạn có thể không cần thông báo cho tôi về quyết định của bạn, tôi biết rồi."},{"t":"example","text":"Giải thích: Можете не + НСВ = Không cần thiết phải làm gì."},{"t":"para","text":"17. Ду́маю, не сто́ит бо́льше (занима́ться/заня́ться) фоне́тикой.","b":1},{"t":"subhead","text":"Đáp án: занима́ться","b":1},{"t":"para","text":"Dịch: Tôi nghĩ không đáng để tập trung/học ngữ âm nữa."},{"t":"example","text":"Giải thích: Не стоит + НСВ = Không nên/không đáng làm (khuyên ngăn)."},{"t":"para","text":"18. Я всегда́ рад (встреча́ть/встре́тить) земляка́.","b":1},{"t":"subhead","text":"Đáp án: встреча́ть","b":1},{"t":"para","text":"Dịch: Tôi luôn vui mừng khi gặp đồng hương."},{"t":"example","text":"Giải thích: Всегда (luôn luôn) chỉ sự lặp lại → Dùng НСВ (встреча́ть)."},{"t":"para","text":"19. Достопримеча́тельности Петербу́рга нельзя́ (осма́тривать/осмотре́ть) за оди́н день.","b":1},{"t":"subhead","text":"Đáp án: осмотре́ть","b":1},{"t":"para","text":"Dịch: Các danh thắng của Petersburg thì không thể xem hết trong một ngày được."},{"t":"para","text":"Giải thích: Bất khả thi để hoàn thành việc xem → Dùng СВ (осмотре́ть)."},{"t":"para","text":"20. Она́ согласи́лась (принима́ть/приня́ть) уча́стие в нового́днем ве́чере.","b":1},{"t":"subhead","text":"Đáp án: приня́ть","b":1},{"t":"para","text":"Dịch: Cô ấy đã đồng ý tham gia vào đêm tiệc năm mới."},{"t":"example","text":"Giải thích: Đồng ý thực hiện một hành động cụ thể (cụm cố định принять участие) → Dùng СВ (приня́ть)."}]},{"id":"07-s071","type":"exercise","title":"Bài 562 (Trang 289)","num":562,"blocks":[{"t":"para","text":"Chủ điểm ngữ pháp: Sự khác biệt giữa НСВ và СВ ở quá khứ và tương lai."},{"t":"vocab","ru":"НСВ","vi":"Quá trình, lặp lại, đồng thời.","g":null},{"t":"vocab","ru":"СВ","vi":"Kết quả, hành động một lần, chuỗi hành động kế tiếp nhau.","g":null},{"t":"instruction","text":"Yêu cầu: Đọc câu, xác định sự khác biệt về nghĩa của các động từ được in đậm. Gọi tên các động từ nguyên mẫu."},{"t":"para","text":"a) Quá khứ:","b":1},{"t":"para","text":"Обы́чно я засыпа́л о́чень по́здно. Вчера́ я засну́л в 2 часа́ но́чи."},{"t":"para","text":"Dịch: Thông thường tôi hay ngủ (засыпа́ть - НСВ: thói quen) rất muộn. Hôm qua tôi đã ngủ (засну́ть - СВ: kết quả 1 lần) lúc 2 giờ sáng."},{"t":"para","text":"Вчера́ це́лый день мы гото́вились к контро́льной рабо́те. Я уве́рен, ты хорошо́ подгото́вился к контро́льной рабо́те."},{"t":"para","text":"Dịch: Hôm qua cả ngày chúng tớ đã ôn thi (гото́виться - НСВ: quá trình kéo dài). Tớ tin là cậu đã ôn xong/chuẩn bị kỹ (подгото́виться - СВ: kết quả hoàn tất) cho bài kiểm tra."},{"t":"para","text":"К сожале́нию, э́той кни́ги у него́ нет, он брал её в библиоте́ке. Он взял в библиоте́ке не́сколько книг."},{"t":"para","text":"Dịch: Tiếc là cậu ấy không có cuốn sách này, cậu ấy đã mượn (брат - НСВ: sự kiện đã xảy ra nhưng không nhấn mạnh việc sách còn đó hay không, hoặc chỉ hành động mượn nói chung) nó ở thư viện. Anh ấy đã lấy (взять - СВ: kết quả, sách đang cầm) vài cuốn ở thư viện."},{"t":"para","text":"Когда́ я де́лал дома́шнее зада́ние, я слу́шал му́зыку. Я сде́лал дома́шнее зада́ние и послу́шал му́зыку."},{"t":"para","text":"Dịch: Khi tôi đang làm (де́лать - НСВ: quá trình đồng thời) bài tập, tôi nghe nhạc. Tôi đã làm xong (сде́лать - СВ: kết quả xong rồi) bài tập và (sau đó) nghe nhạc."},{"t":"vocab","ru":"Когда́ мы гуля́ли по ле́су, мы встре́тили оле́ня. (Lỗi sách","vi":"đáng lẽ phải so sánh với встречали).","g":null},{"t":"para","text":"Dịch: Khi đi dạo trong rừng, chúng tôi đã gặp (встре́тить - СВ: kết quả bất ngờ) một chú hươu."},{"t":"para","text":"b) Tương lai:","b":1},{"t":"para","text":"Ле́том мы бу́дем купа́ться, загора́ть, ходи́ть в лес за гриба́ми. Че́рез неде́лю мы загори́м и смо́жем находи́ться на со́лнце бо́лее продолжи́тельное вре́мя."},{"t":"para","text":"Dịch: Mùa hè chúng tôi sẽ tắm, tắm nắng, đi rừng hái nấm (НСВ: các hoạt động lặp lại/kéo dài). Một tuần nữa chúng tôi sẽ rám nắng (СВ: kết quả) và sẽ có thể (СВ) ở ngoài nắng lâu hơn."},{"t":"para","text":"В ию́не я бу́ду сдава́ть экза́мены. К пе́рвому ию́ля я уже́ сдам все экза́мены."},{"t":"para","text":"Dịch: Tháng 6 tớ sẽ thi (НСВ: tham gia kỳ thi/quá trình). Trước mùng 1 tháng 7 tớ sẽ thi xong (СВ: hoàn tất) tất cả các môn."},{"t":"para","text":"Когда́ я бу́ду писа́ть письмо́, я бу́ду ду́мать о тебе́. Когда́ я напишу́ письмо́, я отнесу́ его́ на по́чту."},{"t":"para","text":"Dịch: Khi tớ viết (НСВ: đang viết) thư, tớ sẽ nghĩ (НСВ: đồng thời) về cậu. Khi tớ viết xong (СВ: kết quả), tớ sẽ mang (СВ: hành động kế tiếp) nó ra bưu điện."},{"t":"para","text":"В суббо́ту, когда́ мы бу́дем отмеча́ть мой день рожде́ния, соберу́тся не́сколько мои́х друзе́й."},{"t":"para","text":"Dịch: Vào thứ bảy, khi chúng tớ tổ chức (НСВ: quá trình tiệc tùng) sinh nhật, vài người bạn sẽ tụ tập (СВ: kết quả của việc đến) đông đủ."}]},{"id":"07-s072","type":"exercise","title":"Bài 563 (Trang 290)","num":563,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền động từ ở thì quá khứ (СВ hoặc НСВ)."},{"t":"para","text":"1. Что ты вчера́ ... ? Что ты ... за вчера́шний день?","b":1},{"t":"para","text":"(де́лать/сде́лать)"},{"t":"subhead","text":"Đáp án: де́лал / сде́лал"},{"t":"para","text":"Dịch: Hôm qua cậu đã làm gì (hỏi về hoạt động chung)? Cậu đã làm được (những) gì trong ngày hôm qua (hỏi về kết quả cụ thể)?"},{"t":"para","text":"2. Я ... с ним, что сдам экза́мен на “отли́чно”. Мы ... с ним по любо́му по́воду.","b":1},{"t":"para","text":"(спо́рить/поспо́рить)"},{"t":"subhead","text":"Đáp án: поспо́рил / спо́рили"},{"t":"para","text":"Dịch: Tớ đã cá (kết quả hành động cá cược 1 lần) với cậu ấy là tớ sẽ thi được điểm xuất sắc. Chúng tớ đã tranh luận (quá trình lặp lại/kéo dài) với nhau về bất cứ lý do gì."},{"t":"para","text":"3. Он ... позвони́ть тебе́, но почему́-то не сде́лал э́того. Мы с трудо́м ... убеди́ть его́ принима́ть поспе́шных реше́ний.","b":1},{"t":"example","text":"(обеща́ть/пообеща́ть) - Sách in nhầm động từ gợi ý? Câu 3 ngữ cảnh là \"Hứa\" hoặc \"Muốn\". Nhưng câu sau lại là \"thuyết phục\"."},{"t":"example","text":"Check lại: Có vẻ câu 3 dùng động từ (хоте́ть/захоте́ть) hoặc (обеща́ть/пообеща́ть). Nhưng nhìn vào danh sách gợi ý cuối bài (nếu có) hoặc logic:"},{"t":"para","text":"Vế 1: Anh ấy đã hứa (пообеща́л - СВ) gọi cho bạn... hoặc Anh ấy muốn (хотел - НСВ). Logic nhất: хоте́л (định gọi nhưng không làm) hoặc обещал (đã hứa)."},{"t":"example","text":"Vế 2: Chúng tôi chật vật mãi mới thuyết phục được (убеди́ли - СВ) anh ấy... (từ с трудом thường đi với СВ để chỉ đạt được kết quả khó khăn)."},{"t":"example","text":"Correction: Động từ gợi ý trong sách có thể nằm ở cuối dòng. Ở đây không thấy. Dựa vào bài tập tương tự, vế 2 chắc chắn là убеди́ли (thuyết phục được) hoặc уговори́ли. Vế 1 có thể là хоте́л (muốn) hoặc собира́лся (định)."},{"t":"vocab","ru":"Nếu đề bài cho cặp (мочь/смочь)","vi":"Vế 2: Chúng tôi khó khăn lắm mới có thể (смогли) thuyết phục...","g":null},{"t":"para","text":"4. Мы ... собра́ние раз ... собра́ние.","b":1},{"t":"para","text":"(переноси́ть/перенести́)"},{"t":"subhead","text":"Đáp án: переноси́ли / перенесли́"},{"t":"para","text":"Dịch: Chúng tôi đã hoãn cuộc họp nhiều lần (lặp lại - НСВ). Chúng tôi đã hoãn cuộc họp (một lần cụ thể/kết quả - СВ)."},{"t":"para","text":"5. Зри́тели до́лго ... восхище́ние игро́й муз́ыка́нта. Ты ... свою́ то́чку зре́ния, дай и други́м сказа́ть то, что они́ ду́мают.","b":1},{"t":"para","text":"(выража́ть/вы́разить)"},{"t":"subhead","text":"Đáp án: выража́ли / вы́разил"},{"t":"para","text":"Dịch: Khán giả đã bày tỏ (quá trình kéo dài) sự ngưỡng mộ với lối chơi của nhạc sĩ rất lâu. Bạn đã bày tỏ (kết quả xong rồi) quan điểm của mình rồi, hãy để người khác nói điều họ nghĩ."},{"t":"para","text":"6. Зна́ешь, я ... пое́хать с тобо́й в Севасто́поль. Ты всегда́ ... за меня́, что для меня́ лу́чше, а что ху́же.","b":1},{"t":"para","text":"(реша́ть/реши́ть)"},{"t":"subhead","text":"Đáp án: реши́л / реша́л"},{"t":"para","text":"Dịch: Biết không, tớ đã quyết định (kết quả) đi Sevastopol với cậu. Cậu luôn quyết định (thói quen lặp lại) thay tớ xem cái gì tốt, cái gì xấu."},{"t":"para","text":"7. Он ... два часа́ наза́д. С ка́ждым днём он ... всё вчера́ в теа́тре. Я ... с ним мно́го раз, но никогда́ не спра́шивала его́ об э́том.","b":1},{"t":"para","text":"(встреча́ться/встре́титься)"},{"t":"subhead","text":"Đáp án: встре́тился (hoặc появился? Ngữ cảnh \"gặp\"). Nhưng câu 7 có 3 vế."},{"t":"para","text":"Vế 1: Anh ấy đã gặp (đã đến?) 2 tiếng trước."},{"t":"para","text":"Vế 2: Càng ngày anh ấy càng... (trở nên thế nào đó?)."},{"t":"para","text":"Vế 3: Tôi ... với anh ấy nhiều lần."},{"t":"example","text":"Correction: Có vẻ như các câu trong sách bị dồn. Hãy nhìn kỹ câu 7 và 8."},{"t":"example","text":"Câu 7: Он ... два часа назад. (Có thể là вернулся/пришел)."},{"t":"example","text":"Câu 8: Я случайно ... с ним вчера в театре (Tôi tình cờ gặp - встретилась). Я ... с ним много раз (Tôi gặp nhiều lần - встречалась)."},{"t":"para","text":"8. Я случа́йно ... с ним вчера́ в теа́тре. Я ... с ним мно́го раз, но никогда́ не спра́шивала его́ об э́том.","b":1},{"t":"para","text":"(встреча́ться/встре́титься)"},{"t":"subhead","text":"Đáp án: встре́тилась / встреча́лась"},{"t":"para","text":"Dịch: Hôm qua tôi tình cờ đã gặp anh ấy ở nhà hát (1 lần). Tôi đã gặp anh ấy nhiều lần (lặp lại), nhưng chưa bao giờ hỏi chuyện đó."},{"t":"para","text":"9. Во вре́мя экску́рсии посети́тели внима́тельно ... экспона́ты музе́я. Я хорошо́ ... его́ и могу́ тебе́ его́ описа́ть.","b":1},{"t":"para","text":"(рассма́тривать/рассмотре́ть)"},{"t":"subhead","text":"Đáp án: рассма́тривали / рассмотре́л"},{"t":"para","text":"Dịch: Trong chuyến tham quan, du khách đã ngắm nghía/xem xét (quá trình) các hiện vật chăm chú. Tớ đã nhìn kỹ/xem xét kỹ (kết quả) hắn ta và có thể tả lại cho cậu."},{"t":"para","text":"10. В сочине́нии он ... три оши́бки. Он постоя́нно ... оши́бки в контро́льной рабо́те.","b":1},{"t":"para","text":"(де́лать/сде́лать)"},{"t":"subhead","text":"Đáp án: сде́лал / де́лал"},{"t":"para","text":"Dịch: Trong bài luận, cậu ấy đã mắc (làm ra kết quả) 3 lỗi. Cậu ấy liên tục mắc (lặp lại) lỗi trong bài kiểm tra."}]},{"id":"07-s073","type":"exercise","title":"Bài 564 (Trang 290)","num":564,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền động từ ở thì tương lai (СВ hoặc НСВ)."},{"t":"note","text":"Lưu ý: Tương lai НСВ = буду/будешь... + động từ nguyên mẫu. Tương lai СВ = động từ biến đổi đuôi."},{"t":"para","text":"1. Не волну́йся, я ... ему́ из аэропо́рта. Не волну́йся, я ... ему́ че́рез ка́ждые пять мину́т.","b":1},{"t":"para","text":"(звони́ть/позвони́ть)"},{"t":"subhead","text":"Đáp án: позвоню́ / бу́ду звони́ть"},{"t":"para","text":"Dịch: Đừng lo, tớ sẽ gọi (1 lần/kết quả) cho anh ấy từ sân bay. Đừng lo, tớ sẽ gọi (lặp lại) cho anh ấy mỗi 5 phút."},{"t":"para","text":"2. — Передава́й ей приве́т. (Câu này không có chỗ trống, có thể là lời dẫn).","b":1},{"t":"para","text":"3. Врач ... больны́х по́сле обе́да. Уве́рен, что на э́тот раз ты ... пра́вильное реше́ние.","b":1},{"t":"para","text":"(принима́ть/приня́ть)"},{"t":"subhead","text":"Đáp án: бу́дет принима́ть / при́мешь"},{"t":"para","text":"Dịch: Bác sĩ sẽ tiếp (quá trình/lịch trình) bệnh nhân sau giờ ăn trưa. Tin rằng lần này bạn sẽ đưa ra (kết quả) quyết định đúng."},{"t":"para","text":"4. Я ча́сто ... в э́тот го́род. К обе́ду я обяза́тельно ...","b":1},{"t":"para","text":"(возвраща́ться/верну́ться)"},{"t":"subhead","text":"Đáp án: бу́ду возвраща́ться / верну́сь"},{"t":"para","text":"Dịch: Tôi sẽ thường xuyên trở lại thành phố này. Trước bữa trưa tôi nhất định sẽ về (kết quả)."},{"t":"para","text":"5. Коне́чно, мы ... тебя́, не торопи́сь. Мы ... вас в воскресе́нье.","b":1},{"t":"para","text":"(жда́ть/подожда́ть)"},{"t":"subhead","text":"Đáp án: подождём (hoặc будем ждать) / бу́дем жда́ть"},{"t":"para","text":"Dịch: Tất nhiên, chúng tớ sẽ đợi (một chút - kết quả/giới hạn) cậu, đừng vội. Chúng tớ sẽ đợi/chờ (quá trình/kế hoạch) các bạn vào chủ nhật."},{"t":"note","text":"Lưu ý: Vế 1 dùng подождём (đợi một lát cho cậu đến) tự nhiên hơn. Vế 2 dùng будем ждать (mong chờ)."},{"t":"para","text":"6. Я ... тебе́, когда́ бу́ду гото́в. Я ... тебе́ на́ши координа́ты на протяже́нии всего́ пути́.","b":1},{"t":"para","text":"(сообща́ть/сообщи́ть)"},{"t":"subhead","text":"Đáp án: сообщу́ / бу́ду сообща́ть"},{"t":"para","text":"Dịch: Tớ sẽ báo (1 lần) cho cậu khi tớ sẵn sàng. Tớ sẽ thông báo (liên tục/lặp lại) tọa độ của bọn tớ trong suốt hành trình."},{"t":"para","text":"7. Наде́юсь, он ... мой звоно́к. В сосе́дней ко́мнате я ... весь ваш разгово́р.","b":1},{"t":"para","text":"(слы́шать/услы́шать)"},{"t":"subhead","text":"Đáp án: услы́шит / бу́ду слы́шать (hoặc услы́шу)"},{"t":"para","text":"Dịch: Hy vọng anh ấy sẽ nghe thấy (kết quả) tiếng chuông của tôi. Ở phòng bên cạnh tôi sẽ nghe được (quá trình/khả năng) toàn bộ cuộc trò chuyện của các bạn."},{"t":"para","text":"8. В пя́тницу я ... с ва́ми встре́титься. Наде́юсь, они́ ... на́ши усло́вия.","b":1},{"t":"vocab","ru":"(принима́ть/приня́ть) - Lỗi sách","vi":"Động từ phải là хотеть hoặc планировать? À không, câu 8 là về принимать.","g":null},{"t":"example","text":"Correction: Câu gốc sách: \"В пятницу я ... (принимать/принять) с вами встретиться\" là vô nghĩa. Có lẽ là \"В пятницу я смогу (có thể) ...\"."},{"t":"example","text":"Nhưng nếu dùng từ gợi ý cuối câu (nếu có), hãy xem câu 9. Câu 9 là решать."},{"t":"example","text":"Dịch đoán: Có lẽ sách muốn nói: \"Tôi sẽ tiếp bạn\" (принимать). \"Vào thứ 6 tôi sẽ tiếp (буду принимать) bạn\". Vế 2: \"Họ sẽ chấp nhận (примут) điều kiện của chúng tôi\"."},{"t":"para","text":"9. Обеща́ю, я ... то́лько пра́вду. Я ... ему́ о на́шем реше́нии по́зже.","b":1},{"t":"para","text":"(говори́ть/сказа́ть)"},{"t":"subhead","text":"Đáp án: бу́ду говори́ть / скажу́"},{"t":"para","text":"Dịch: Tôi hứa, tôi sẽ (chỉ) nói (quá trình/thói quen) sự thật. Tôi sẽ nói (1 lần) cho anh ấy về quyết định của chúng ta sau."},{"t":"para","text":"10. Я ... вам в э́том де́ле, мо́жете на меня́ положи́ться. Я ... тебе́ гото́виться к контро́льным рабо́там.","b":1},{"t":"para","text":"(помога́ть/помо́чь)"},{"t":"subhead","text":"Đáp án: помогу́ / бу́ду помога́ть"},{"t":"para","text":"Dịch: Tôi sẽ giúp (kết quả/cam kết) bạn việc này, bạn có thể dựa vào tôi. Tôi sẽ giúp (thường xuyên/quá trình) bạn ôn thi kiểm tra."}]},{"id":"07-s074","type":"exercise","title":"Bài 565 (Trang 291)","num":565,"blocks":[{"t":"para","text":"Chủ điểm ngữ pháp: Phủ định với động từ (Отрицание с глаголом)."},{"t":"vocab","ru":"Не + НСВ","vi":"Không cần thiết phải làm (không có nghĩa vụ), hoặc không làm (như một thói quen/quá trình), hoặc cấm đoán (với mệnh lệnh thức).","g":null},{"t":"vocab","ru":"Не + СВ","vi":"Cảnh báo không làm được (bất khả thi), hoặc cảnh báo coi chừng lỡ xảy ra kết quả xấu (với mệnh lệnh thức), hoặc sự thất bại trong quá khứ (đã không làm được).","g":null},{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng dạng quá khứ hoặc tương lai."},{"t":"para","text":"a) Quá khứ:","b":1},{"t":"para","text":"Он так и не (зака́нчивать/зако́нчить) свою́ рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: зако́нчил","b":1},{"t":"para","text":"Dịch: Anh ấy rốt cuộc vẫn chưa hoàn thành (không đạt kết quả) công việc của mình."},{"t":"example","text":"Giải thích: Так и не + СВ = Mãi mà không xong (nhấn mạnh thất bại về kết quả)."},{"t":"para","text":"Я не (сомнева́ться/засомнева́ться) в том, что он спра́вится с э́тим зада́нием.","b":1},{"t":"subhead","text":"Đáp án: сомнева́лся","b":1},{"t":"para","text":"Dịch: Tôi đã không nghi ngờ (trạng thái) việc cậu ấy sẽ làm được nhiệm vụ."},{"t":"para","text":"Бою́сь, в тако́м сло́жном де́ле никто́ не (мочь/смочь) ему́ помо́чь.","b":1},{"t":"subhead","text":"Đáp án: смог","b":1},{"t":"para","text":"Dịch: Tôi e là trong việc khó thế này, đã chẳng ai có thể (kết quả/khả năng) giúp được anh ấy."},{"t":"para","text":"Я не (проси́ть/попроси́ть) его́ помога́ть тебе́; 5. На про́шлой неде́ле она́ не (посеща́ть/посети́ть) заня́тия.","b":1},{"t":"subhead","text":"Đáp án: проси́л / посеща́ла"},{"t":"para","text":"Dịch: Tôi đã không nhờ (không thực hiện hành động - НСВ) anh ta giúp bạn. Tuần trước cô ấy đã không đi (vắng mặt - НСВ) học."},{"t":"para","text":"(Câu 6): Извини́, я не (писа́ть/записа́ть) расписа́ние на за́втра.","b":1},{"t":"subhead","text":"Đáp án: записа́л","b":1},{"t":"para","text":"Dịch: Xin lỗi, tớ đã không ghi (quên làm/không có kết quả) thời khóa biểu ngày mai."},{"t":"para","text":"b) Tương lai:","b":1},{"t":"para","text":"Ничего́ не (случа́ться/случи́ться), е́сли ты опозда́ешь на пять мину́т на рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: случи́тся","b":1},{"t":"para","text":"Dịch: Chẳng có chuyện gì xảy ra (kết quả) đâu nếu bạn đi làm muộn 5 phút."},{"t":"para","text":"За́втра я не (де́лать/сде́лать) э́ту рабо́ту, у меня́ и без неё мно́го дел.","b":1},{"t":"subhead","text":"Đáp án: бу́ду де́лать (hoặc сде́лаю tùy ý)."},{"t":"para","text":"Giải thích: Nếu ý là \"tôi sẽ không đụng vào nó\" → бу́ду де́лать. Nếu ý là \"tôi sẽ không làm xong được\" → сде́лаю. Ngữ cảnh \"tôi bận việc khác\" thường hàm ý tôi sẽ không dành thời gian cho nó → НСВ: не бу́ду де́лать."},{"t":"para","text":"Ду́маю, я не (хоте́ть/захоте́ть) прие́хать в э́тот го́род ещё раз.","b":1},{"t":"subhead","text":"Đáp án: захочу́","b":1},{"t":"para","text":"Dịch: Tôi nghĩ tôi sẽ không nảy sinh ý muốn (kết quả cảm xúc) đến thành phố này lần nữa."},{"t":"para","text":"Я не (проща́ть/прости́ть) ему́ его́ преда́тельства.","b":1},{"t":"subhead","text":"Đáp án: прощу́","b":1},{"t":"para","text":"Dịch: Tôi sẽ không tha thứ (kết quả) cho sự phản bội của hắn."},{"t":"para","text":"Мы не (помога́ть/помо́чь) ему́, он до́лжен сде́лать всё сам.","b":1},{"t":"subhead","text":"Đáp án: помо́жем (từ chối giúp để đạt kết quả) hoặc бу́дем помога́ть (sẽ không tham gia giúp)."},{"t":"para","text":"Chọn: не бу́дем помога́ть (Chúng tôi sẽ không giúp - từ chối hành động). Hoặc не поможем (Chúng tôi sẽ không giúp được đâu - bất khả thi). Ngữ cảnh \"anh ta phải tự làm\" → Chúng tôi chủ động không giúp → не бу́дем помога́ть."}]},{"id":"07-s075","type":"exercise","title":"Bài 566 (Trang 292)","num":566,"blocks":[{"t":"para","text":"Chủ điểm ngữ pháp: Sự đối lập giữa Thể chưa hoàn thành (НСВ) và Thể hoàn thành (СВ) trong câu hỏi và trả lời."},{"t":"vocab","ru":"НСВ (Несовершенный вид)","vi":"Dùng để chỉ một hành động không xảy ra (như một sự kiện chung), phủ định chính việc thực hiện hành động đó.","g":null},{"t":"vocab","ru":"СВ (Совершенный вид)","vi":"Dùng để chỉ hành động đã xảy ra nhưng không đạt được kết quả mong muốn, hoặc kết quả bị hủy bỏ.","g":null},{"t":"instruction","text":"Yêu cầu: Trả lời các câu hỏi, sử dụng dữ kiện trong ngoặc với thể động từ thích hợp."},{"t":"para","text":"1. У тебя́ бы́ло вре́мя сде́лать дома́шнее зада́ние? — Нет, пока́ я его́ (де́лать/сде́лать).","b":1},{"t":"subhead","text":"Đáp án: не сде́лал (hoặc не де́лал)."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Nếu muốn nói \"Vẫn chưa làm xong (chưa có kết quả)\": dùng не сде́лал."},{"t":"para","text":"Nếu muốn nói \"Chưa đụng vào, chưa thực hiện hành động\": dùng не де́лал."},{"t":"example","text":"Ngữ cảnh: \"Có thời gian làm chưa?\" -> \"Chưa, tôi chưa làm xong/chưa làm\". Đáp án tự nhiên: не сде́лал (chưa hoàn thành)."},{"t":"para","text":"Dịch: Bạn có thời gian làm bài tập về nhà chưa? — Chưa, tớ vẫn chưa làm xong nó."},{"t":"para","text":"2. Он получи́л оце́нку за контро́льную рабо́ту? — Нет, он заболе́л и (писа́ть/написа́ть) её.","b":1},{"t":"subhead","text":"Đáp án: не писа́л","b":1},{"t":"para","text":"Giải thích: Anh ấy bị ốm nên không tham gia vào quá trình viết bài kiểm tra (phủ định sự việc xảy ra) → Dùng НСВ."},{"t":"para","text":"Dịch: Cậu ấy đã nhận điểm bài kiểm tra chưa? — Chưa, cậu ấy bị ốm và đã không viết bài đó."},{"t":"para","text":"3. Тебе́ холо́дно? — Нет, я ... (замерза́ть/замёрзнуть).","b":1},{"t":"subhead","text":"Đáp án: не замёрз","b":1},{"t":"para","text":"Giải thích: Hỏi về kết quả (có bị lạnh cóng không?) → Phủ định kết quả: Dùng СВ."},{"t":"para","text":"Dịch: Bạn có lạnh không? — Không, tớ không bị lạnh (không bị đóng băng)."},{"t":"para","text":"4. Поче́му он упа́л в костёр? — Не зна́ю, никто́ ... (толка́ть/толкну́ть) его́.","b":1},{"t":"subhead","text":"Đáp án: не толка́л","b":1},{"t":"para","text":"Giải thích: Phủ định hành động xảy ra (không ai thực hiện hành động đẩy) → Dùng НСВ."},{"t":"para","text":"Dịch: Tại sao anh ta lại ngã vào đống lửa? — Không biết, không có ai đẩy anh ta cả."},{"t":"para","text":"5. Отку́да здесь костёр? — Не зна́ем, мы ... (разжига́ть/разже́чь) его́.","b":1},{"t":"subhead","text":"Đáp án: не разжига́ли","b":1},{"t":"para","text":"Giải thích: Phủ định việc thực hiện hành động đốt lửa (chúng tôi không làm việc đó) → Dùng НСВ."},{"t":"para","text":"Dịch: Đống lửa ở đâu ra thế này? — Không biết, chúng tôi không đốt nó."},{"t":"para","text":"6. Поче́му ты не здоро́ваешься? — Извини́, я ... (замеча́ть/заме́тить) тебя́.","b":1},{"t":"subhead","text":"Đáp án: не заме́тил","b":1},{"t":"para","text":"Giải thích: Phủ định kết quả (không nhìn thấy/không nhận ra) tại một thời điểm cụ thể → Dùng СВ."},{"t":"para","text":"Dịch: Sao cậu không chào tớ? — Xin lỗi, tớ đã không nhìn thấy cậu."},{"t":"para","text":"7. — Э́то твой по́черк? — Нет, я ... (писа́ть/написа́ть) э́ту запи́ску.","b":1},{"t":"subhead","text":"Đáp án: не писа́л","b":1},{"t":"para","text":"Giải thích: Phủ định quyền tác giả (tôi không thực hiện hành động viết này) → Dùng НСВ."},{"t":"para","text":"Dịch: — Đây là chữ viết của cậu à? — Không, tớ không viết mảnh giấy này."},{"t":"para","text":"8. Ты сказа́л ему́, что́бы он пришёл? — Нет, я ... (проси́ть/попроси́ть) его́ об э́том.","b":1},{"t":"subhead","text":"Đáp án: не проси́л","b":1},{"t":"para","text":"Giải thích: Phủ định sự việc (tôi không hề nhờ/yêu cầu) → Dùng НСВ."},{"t":"para","text":"Dịch: Cậu đã bảo anh ấy đến chưa? — Chưa, tớ không hề nhờ anh ấy việc đó."},{"t":"para","text":"9. — Э́та карти́на по-пре́жнему у тебя́? — Нет, к сожале́нию, я ... (бере́чь/ сбере́чь) её.","b":1},{"t":"subhead","text":"Đáp án: не сберёг","b":1},{"t":"para","text":"Giải thích: Phủ định kết quả (không giữ được, đã làm mất/hỏng) → Dùng СВ."},{"t":"para","text":"Dịch: — Bức tranh này vẫn ở chỗ cậu chứ? — Không, tiếc là tớ đã không giữ được nó."},{"t":"para","text":"10. — У тебя́ был день рожде́ния в суббо́ту? — Да, но я ... (отмеча́ть/отме́тить) его́ в э́тот день.","b":1},{"t":"subhead","text":"Đáp án: не отмеча́л","b":1},{"t":"para","text":"Giải thích: Phủ định sự việc tổ chức (không làm hành động đó) → Dùng НСВ."},{"t":"para","text":"Dịch: — Sinh nhật cậu vào thứ bảy à? — Ừ, nhưng tớ đã không tổ chức vào ngày hôm đó."},{"t":"para","text":"11. — Э́то ты говори́л с ним по телефо́ну? — Нет, я ... (звони́ть/позвони́ть) ему́.","b":1},{"t":"subhead","text":"Đáp án: не звони́л","b":1},{"t":"para","text":"Giải thích: Phủ định việc thực hiện cuộc gọi → Dùng НСВ."},{"t":"para","text":"Dịch: — Cậu là người đã nói chuyện điện thoại với anh ấy à? — Không, tớ không gọi cho anh ấy."},{"t":"para","text":"12. — Ты принёс все проду́кты? — Нет, я ... (покупа́ть/купи́ть) молоко́.","b":1},{"t":"subhead","text":"Đáp án: не купи́л","b":1},{"t":"para","text":"Giải thích: Đi mua rồi nhưng thiếu (không đạt kết quả mua được sữa) → Dùng СВ."},{"t":"para","text":"Dịch: — Cậu mang hết thực phẩm về chưa? — Chưa, tớ đã không mua được sữa (quên/hết hàng)."},{"t":"para","text":"13. — Я слы́шал твой гро́мкий го́лос? — Нет, я ... (крича́ть/закрича́ть).","b":1},{"t":"subhead","text":"Đáp án: не крича́л","b":1},{"t":"para","text":"Giải thích: Phủ định hành động (tôi không hét) → Dùng НСВ."},{"t":"para","text":"Dịch: — Tớ đã nghe thấy giọng cậu rất to? — Không, tớ đâu có hét."},{"t":"para","text":"14. — Я слы́шал, он пло́хо себя́ чу́вствовал? — Нет, он ... (боле́ть/заболе́ть).","b":1},{"t":"subhead","text":"Đáp án: не боле́л (hoặc не заболе́л tùy ngữ cảnh)."},{"t":"example","text":"Giải thích: Nếu ý là \"anh ấy không hề bị ốm\" (phủ định quá trình/trạng thái) -> не боле́л. Nếu ý là \"anh ấy không bị mắc bệnh\" (phủ định kết quả thay đổi trạng thái) -> не заболе́л. Ngữ cảnh này dùng не боле́л (không ốm đau gì cả) phổ biến hơn."},{"t":"para","text":"Dịch: — Tớ nghe nói cậu ấy cảm thấy không khỏe? — Không, cậu ấy không bị ốm đâu."},{"t":"para","text":"15. — Ты ви́дел, как он ушёл? — Нет, я ... (замеча́ть/заме́тить).","b":1},{"t":"subhead","text":"Đáp án: не заме́тил","b":1},{"t":"para","text":"Giải thích: Không nhận ra khoảnh khắc đó (phủ định kết quả tri giác) → Dùng СВ."},{"t":"para","text":"Dịch: — Cậu có thấy cậu ta rời đi thế nào không? — Không, tớ không để ý."},{"t":"para","text":"16. — Вы сказа́ли им ещё раз о за́втрашней пое́здке? — Нет, мы ... (напомина́ть/напо́мнить) им.","b":1},{"t":"subhead","text":"Đáp án: не напомина́ли","b":1},{"t":"para","text":"Giải thích: Phủ định việc thực hiện hành động nhắc nhở → Dùng НСВ."},{"t":"para","text":"Dịch: — Các bạn đã nói với họ lần nữa về chuyến đi ngày mai chưa? — Chưa, chúng tôi không nhắc họ."}]},{"id":"07-s076","type":"exercise","title":"Bài 567 (Trang 292)","num":567,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung):","b":1},{"t":"para","text":"! Глаго́лы несоверше́нного ви́да ука́зывают на одновреме́нное протека́ние де́йствия (действия происходят параллельно), глаго́лы соверше́нного ви́да — на после́довательное (одно действие за другим). Е́сли в моме́нт протека́ния де́йствия-проце́сса име́ет ме́сто то́чечное де́йствие, употребля́ются глаго́лы ра́зных ви́дов.","b":1},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Động từ thể chưa hoàn thành (НСВ) chỉ sự diễn ra đồng thời của hành động (các hành động xảy ra song song)."},{"t":"para","text":"Động từ thể hoàn thành (СВ) chỉ sự nối tiếp (hành động này xong đến hành động khác)."},{"t":"para","text":"Nếu tại thời điểm một hành động-quá trình đang diễn ra mà có một hành động-tức thời xảy ra, thì dùng kết hợp cả hai thể (НСВ cho quá trình, СВ cho tức thời)."},{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng động từ ở thì quá khứ hoặc tương lai."},{"t":"para","text":"1. Когда́ он (чита́ть/прочита́ть) литерату́ру по специа́льности, он (выпи́сывать/вы́писать) незнако́мые слова́ в отде́льную тетра́дь.","b":1},{"t":"subhead","text":"Đáp án: чита́л / выпи́сывал","b":1},{"t":"para","text":"Giải thích: Hai hành động xảy ra đồng thời và lặp đi lặp lại trong quá khứ → Cả hai dùng НСВ."},{"t":"para","text":"Dịch: Khi anh ấy đọc tài liệu chuyên ngành, anh ấy thường chép những từ mới ra một cuốn vở riêng."},{"t":"para","text":"2. Он (предлага́ть/предложи́ть) нам свою́ по́мощь, когда́ мы (иска́ть/найти́) рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: предложи́л / иска́ли","b":1},{"t":"para","text":"Giải thích: Hành động \"đề nghị\" xảy ra 1 lần (СВ) trong khi hành động \"tìm việc\" đang diễn ra (НСВ)."},{"t":"para","text":"Dịch: Anh ấy đã đề nghị giúp đỡ khi chúng tôi đang tìm việc làm."},{"t":"para","text":"3. Когда́ я (выраста́ть/вы́расти), я (быть/побыва́ть) пожа́рным.","b":1},{"t":"subhead","text":"Đáp án: вы́расту / бу́ду","b":1},{"t":"para","text":"Giải thích: \"Lớn lên\" là kết quả đạt được trong tương lai (СВ), \"làm lính cứu hỏa\" là trạng thái nghề nghiệp (НСВ)."},{"t":"para","text":"Dịch: Khi nào lớn lên, con sẽ là lính cứu hỏa."},{"t":"para","text":"4. Э́тим ле́том, когда́ он (зака́нчивать/зако́нчить) шко́лу, он (поступа́ть/поступи́ть) в институ́т.","b":1},{"t":"subhead","text":"Đáp án: зако́нчит / посту́пит","b":1},{"t":"para","text":"Giải thích: Chuỗi hành động nối tiếp trong tương lai: Xong trường học → Thi đỗ đại học. Dùng СВ cho cả hai."},{"t":"para","text":"Dịch: Mùa hè này, khi cậu ấy tốt nghiệp phổ thông, cậu ấy sẽ thi đỗ vào đại học."},{"t":"para","text":"5. Когда́ я (просыпа́ться/просну́ться), дождь (лить/поли́ть) как из ведра́.","b":1},{"t":"subhead","text":"Đáp án: просну́лся / лил","b":1},{"t":"para","text":"Giải thích: \"Tỉnh dậy\" là hành động tức thời (СВ), \"mưa rơi\" là bối cảnh đang diễn ra (НСВ)."},{"t":"para","text":"Dịch: Khi tôi tỉnh dậy, trời đang mưa như trút nước."},{"t":"para","text":"6. Мы (возвраща́ться/верну́ться) домо́й, когда́ (зака́нчивать/зако́нчить) все свой дела́ в го́роде.","b":1},{"t":"subhead","text":"Đáp án: вернёмся / зако́нчим","b":1},{"t":"para","text":"Giải thích: Tương lai nối tiếp: Xong việc thì sẽ về. Dùng СВ."},{"t":"para","text":"Dịch: Chúng tôi sẽ về nhà khi làm xong mọi việc trên thành phố."},{"t":"para","text":"7. За́втра, когда́ ты (говори́ть/сказа́ть) с ним, (напомина́ть/напо́мнить) ему́ о его́ обеща́нии.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь говори́ть / напо́мни","b":1},{"t":"para","text":"Giải thích: \"Nói chuyện\" là quá trình (НСВ), \"nhắc\" là hành động cụ thể cần làm (СВ - mệnh lệnh thức)."},{"t":"para","text":"Dịch: Ngày mai, khi cậu nói chuyện với anh ấy, hãy nhắc anh ấy về lời hứa nhé."},{"t":"para","text":"8. Когда́ он (расска́зывать/рассказа́ть) о свои́х путеше́ствиях, все (слу́шать/послу́шать) его́ затаи́в дыха́ние.","b":1},{"t":"subhead","text":"Đáp án: расска́зывал / слу́шали","b":1},{"t":"para","text":"Giải thích: Hai hành động diễn ra đồng thời kéo dài trong quá khứ → Cả hai dùng НСВ."},{"t":"para","text":"Dịch: Khi ông ấy kể về những chuyến du lịch của mình, mọi người đều lắng nghe nín thở."},{"t":"para","text":"9. Все о́чень (ра́доваться/обра́доваться), когда́ (узнава́ть/узна́ть) о его́ реше́нии приня́ть уча́стие в экспеди́ции.","b":1},{"t":"subhead","text":"Đáp án: обра́довались / узна́ли","b":1},{"t":"para","text":"Giải thích: Chuỗi hành động cảm xúc nối tiếp: Biết tin → Vui mừng. Dùng СВ."},{"t":"para","text":"Dịch: Mọi người đã rất vui mừng khi biết tin anh ấy quyết định tham gia đoàn thám hiểm."},{"t":"para","text":"10. Мы (отдыха́ть/отдохну́ть), когда́ (зака́нчивать/зако́нчить) рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: отдохнём / зако́нчим (Tương lai) hoặc отдохну́ли / зако́нчили (Quá khứ)."},{"t":"example","text":"Giải thích: Hành động nghỉ ngơi xảy ra sau khi xong việc (kết quả). Dùng СВ cho cả hai để chỉ sự nối tiếp."},{"t":"para","text":"Dịch: Chúng tôi sẽ nghỉ ngơi khi làm xong việc."},{"t":"para","text":"11. Когда́ она́ (смея́ться/рассмея́ться), никто́ не (мочь/смочь) ей дать бо́льше двадцати́ лет.","b":1},{"t":"subhead","text":"Đáp án: смея́лась / мог","b":1},{"t":"para","text":"Giải thích: Khi cô ấy \"đang cười\" (quá trình - НСВ), không ai \"có thể\" (trạng thái/khả năng - НСВ) đoán đúng tuổi."},{"t":"para","text":"Dịch: Khi cô ấy cười, không ai có thể đoán cô ấy hơn 20 tuổi."},{"t":"para","text":"12. Врач вы́писал больно́му лека́рство, и че́рез не́сколько часо́в, когда́ (де́йствовать/поде́йствовать) температу́ра, он (чу́вствовать/ почу́вствовать) себя́ значи́тельно лу́чше.","b":1},{"t":"example","text":"Lỗi sách: Cấu trúc câu hơi lộn xộn. Ý là \"khi thuốc có tác dụng/nhiệt độ giảm\"."},{"t":"example","text":"Sửa: ...когда́ (поде́йствовало) лека́рство / (спала́) температу́ра..."},{"t":"subhead","text":"Gợi ý trong bài: (почу́вствовал)."},{"t":"subhead","text":"Đáp án: почу́вствовал","b":1},{"t":"para","text":"Giải thích: Kết quả thay đổi trạng thái sức khỏe → Dùng СВ."},{"t":"para","text":"Dịch: Bác sĩ kê thuốc cho bệnh nhân, và vài giờ sau, ... anh ấy đã cảm thấy khá hơn nhiều."},{"t":"para","text":"13. Я (покупа́ть/купи́ть) проду́кты на обра́тном пути́, когда́ (возвраща́ться/возврати́ться) домо́й.","b":1},{"t":"subhead","text":"Đáp án: куплю́ / бу́ду возвраща́ться","b":1},{"t":"para","text":"Giải thích: Tôi sẽ thực hiện một hành động (mua - СВ) trong quá trình đi về (đang về - НСВ)."},{"t":"para","text":"Dịch: Tớ sẽ mua thức ăn trên đường về, lúc đang đi về nhà."},{"t":"para","text":"14. Я (надева́ть/наде́ть) пальто́ и (собира́ться/собра́ться) уходи́ть домо́й, когда́ (раздава́ться/разда́ться) телефо́нный звоно́к.","b":1},{"t":"subhead","text":"Đáp án: надева́л / собира́лся / разда́лся","b":1},{"t":"para","text":"Giải thích: Khi tôi đang mặc áo, đang chuẩn bị (quá trình - НСВ) thì bỗng nhiên chuông reo (hành động tức thời cắt ngang - СВ)."},{"t":"para","text":"Dịch: Tôi đang mặc áo khoác và chuẩn bị về nhà thì chuông điện thoại reo vang."}]},{"id":"07-s077","type":"exercise","title":"Bài 568 (Trang 293)","num":568,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"para","text":"! С глаго́лами восприя́тия наблюда́ть, чу́вствовать, знать и други́ми при описа́нии де́йствий-проце́ссов возмо́жно употребле́ние глаго́лов настоя́щего вре́мени.","b":1},{"t":"example","text":"Dịch: Với các động từ chỉ sự tri giác như quan sát, cảm thấy, biết và các động từ khác, khi mô tả hành động-quá trình, có thể dùng động từ (mang ý nghĩa) hiện tại (trong văn cảnh quá khứ để diễn tả sự việc đang diễn ra trước mắt - người dịch chú thích thêm: bài này yêu cầu điền quá khứ/tương lai, nhưng lưu ý các động từ tri giác thường dùng НСВ để chỉ trạng thái)."},{"t":"para","text":"1. Вчера́ он (убежда́ться/убеди́ться) в том, что никто́ не (хоте́ть/ захоте́ть) его́ оби́деть.","b":1},{"t":"subhead","text":"Đáp án: убеди́лся / хо́чет (hoặc хоте́л)"},{"t":"para","text":"Giải thích: Hôm qua anh ấy đã tin chắc/xác nhận (kết quả - СВ) rằng không ai muốn (trạng thái tâm lý - НСВ) xúc phạm anh ấy."},{"t":"para","text":"Dịch: Hôm qua anh ấy đã tin chắc rằng không ai muốn làm anh ấy giận."},{"t":"para","text":"2. Я (слу́шать/послу́шать) его́ и (ду́мать/поду́мать), когда́ же всё э́то (зака́нчиваться/зако́нчиться).","b":1},{"t":"subhead","text":"Đáp án: слу́шал / ду́мал / зако́нчится","b":1},{"t":"para","text":"Giải thích: Tôi đang nghe và đang nghĩ (quá trình - НСВ) xem bao giờ thì chuyện này sẽ kết thúc (kết quả tương lai - СВ)."},{"t":"para","text":"Dịch: Tôi cứ nghe anh ta nói và nghĩ bụng, bao giờ thì chuyện này mới xong đây."},{"t":"para","text":"3. Во вре́мя на́шей после́дней встре́чи я (стара́ться/постара́ться) убеди́ть его́ в том, что он (заблужда́ться).","b":1},{"t":"subhead","text":"Đáp án: стара́лся / заблужда́ется","b":1},{"t":"para","text":"Giải thích: Tôi đã cố gắng (quá trình nỗ lực - НСВ) thuyết phục rằng anh ấy đang sai lầm (trạng thái - НСВ)."},{"t":"para","text":"Dịch: Trong lần gặp cuối, tôi đã cố thuyết phục anh ấy rằng anh ấy đang lầm đường lạc lối."},{"t":"para","text":"4. Я и не (наде́яться/понаде́яться), на то, что ты когда́-нибудь (звони́ть/позвони́ть) мне.","b":1},{"t":"subhead","text":"Đáp án: наде́ялся / позвони́шь","b":1},{"t":"para","text":"Giải thích: Tôi đã không hy vọng (trạng thái kéo dài - НСВ) rằng bạn sẽ gọi (hành động cụ thể - СВ)."},{"t":"para","text":"Dịch: Tôi thậm chí đã chẳng hy vọng rằng có ngày bạn sẽ gọi cho tôi."},{"t":"para","text":"5. Пока́ он (ду́мать/поду́мать) обо мне, я (чу́вствовать/почу́вствовать) э́то о́чень хорошо́.","b":1},{"t":"subhead","text":"Đáp án: ду́мал / чу́вствовала","b":1},{"t":"para","text":"Giải thích: Trong khi anh ấy nghĩ (quá trình), tôi cảm thấy (trạng thái song song) điều đó."},{"t":"para","text":"Dịch: Chừng nào anh ấy còn nghĩ đến tôi, tôi đều cảm nhận được rất rõ."},{"t":"para","text":"6. Я не (слы́шать/услы́шать), как он (входи́ть/войти́) в ко́мнату.","b":1},{"t":"subhead","text":"Đáp án: слы́шала / вошёл","b":1},{"t":"para","text":"Giải thích: Tôi không nghe thấy (trạng thái/tri giác - НСВ) lúc anh ấy bước vào (hành động tức thời - СВ)."},{"t":"para","text":"Dịch: Tôi không nghe thấy tiếng anh ấy bước vào phòng."},{"t":"para","text":"7. Я так (хоте́ть/захоте́ть) спать, что не (слы́шать/услы́шать), как он (начина́ть/нача́ть) мне о чём-то расска́зывать.","b":1},{"t":"subhead","text":"Đáp án: хоте́л / слы́шал / на́чал","b":1},{"t":"para","text":"Giải thích: Tôi buồn ngủ (trạng thái - НСВ) đến mức không nghe (НСВ) lúc anh ấy bắt đầu (kết quả - СВ) kể."},{"t":"para","text":"Dịch: Tôi buồn ngủ đến mức chả nghe thấy anh ấy bắt đầu kể lể cái gì."},{"t":"para","text":"8. Е́сли (начина́ться/нача́ться) дождь, мы все (промока́ть/промо́кнуть).","b":1},{"t":"subhead","text":"Đáp án: начнётся / промо́кнем","b":1},{"t":"para","text":"Giải thích: Câu điều kiện tương lai: Nếu trời đổ mưa (kết quả bắt đầu - СВ), chúng ta sẽ bị ướt (kết quả - СВ)."},{"t":"para","text":"Dịch: Nếu trời đổ mưa, chúng ta sẽ ướt sũng hết."},{"t":"para","text":"9. Я (рабо́тать/порабо́тать) и не (слы́шать/услы́шать), как он (входи́ть/ войти́).","b":1},{"t":"subhead","text":"Đáp án: рабо́тал / слы́шал / вошёл","b":1},{"t":"para","text":"Giải thích: Tương tự câu 6. Tôi đang làm việc (НСВ) và không nghe thấy (НСВ) anh ta vào (СВ)."},{"t":"para","text":"Dịch: Tôi đang làm việc nên không nghe thấy anh ta đi vào."},{"t":"para","text":"10. Мы (замеча́ть/заме́тить), как он (передава́ть/переда́ть) э́ту запи́ску;","b":1},{"t":"subhead","text":"Đáp án: заме́тили / передава́л (hoặc переда́л)"},{"t":"example","text":"Giải thích: Chúng tôi đã nhận thấy (kết quả tri giác - СВ) cảnh anh ấy đang chuyền/đã chuyền tờ giấy. Thường dùng передавал để miêu tả hành động lén lút đang diễn ra."},{"t":"para","text":"Dịch: Chúng tôi đã nhìn thấy cảnh cậu ta chuyền mảnh giấy này."},{"t":"para","text":"11. Я (ви́деть/уви́деть), как (происходи́ть/произойти́) э́та ава́рия;","b":1},{"t":"subhead","text":"Đáp án: ви́дел / произошла́","b":1},{"t":"example","text":"Giải thích: Tôi đã chứng kiến (quá trình quan sát - НСВ видел) tai nạn xảy ra (kết quả - СВ). Nếu dùng увидел (nhìn thấy khoảnh khắc) cũng được."},{"t":"para","text":"Dịch: Tôi đã tận mắt thấy vụ tai nạn đó xảy ra."},{"t":"para","text":"12. С тех пор как он (появля́ться/появи́ться) в на́шем го́роде, я не (дава́ть/дать) ему́ по́вода усомни́ться в моём хоро́шем отноше́нии;","b":1},{"t":"subhead","text":"Đáp án: появи́лся / дава́л","b":1},{"t":"para","text":"Giải thích: Từ khi anh ấy xuất hiện (sự kiện mốc - СВ), tôi chưa bao giờ tạo (liên tục không làm - НСВ) cớ để anh ấy nghi ngờ."},{"t":"para","text":"Dịch: Từ lúc anh ấy xuất hiện ở thành phố này, tôi chưa từng làm gì để anh ấy nghi ngờ thiện chí của tôi."},{"t":"para","text":"13. Я (расска́зывать/рассказа́ть) вам об э́том то́лько для того́, что́бы вы не (волнова́ться/разволнова́ться).","b":1},{"t":"subhead","text":"Đáp án: расска́зываю / волнова́лись","b":1},{"t":"para","text":"Giải thích: Tôi kể (đang kể - НСВ) để bạn không lo lắng (trạng thái - НСВ)."},{"t":"para","text":"Dịch: Tôi kể cho bạn nghe chuyện này chỉ để bạn đỡ lo thôi."}]},{"id":"07-s078","type":"exercise","title":"Bài 569 (Trang 294)","num":569,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"para","text":"! В проше́дшем вре́мени глаго́лы несоверше́нного ви́да обозна́чают де́йствие, кото́рое име́ло ме́сто в про́шлом, нали́чие фа́кта де́йствия (общефактическое значение). Глаго́лы соверше́нного ви́да обознача́ют де́йствие, име́ющее результа́т в моме́нт ре́чи.","b":1},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Ở thì quá khứ, động từ НСВ chỉ hành động đã từng xảy ra, nhấn mạnh vào sự thật/thực tế là có hành động đó (ý nghĩa sự kiện chung)."},{"t":"para","text":"Động từ СВ chỉ hành động có kết quả lưu lại đến thời điểm nói."},{"t":"instruction","text":"Yêu cầu: Điền vào chỗ trống động từ quá khứ (НСВ hoặc СВ)."},{"t":"para","text":"1. Мне ... э́та кни́га, я хочу́ име́ть её в дома́шней библиоте́ке.","b":1},{"t":"para","text":"(нра́виться/понра́виться)"},{"t":"subhead","text":"Đáp án: понра́вилась","b":1},{"t":"para","text":"Giải thích: Kết quả là bây giờ tôi thích nó và muốn giữ nó."},{"t":"para","text":"Dịch: Tôi đã thích cuốn sách này, tôi muốn có nó trong tủ sách gia đình."},{"t":"para","text":"2. В де́тстве мне о́чень ... э́та кни́га.","b":1},{"t":"para","text":"(нра́виться/понра́виться)"},{"t":"subhead","text":"Đáp án: нра́вилась","b":1},{"t":"para","text":"Giải thích: Trạng thái yêu thích kéo dài trong quá khứ (hồi nhỏ)."},{"t":"para","text":"Dịch: Hồi nhỏ tôi đã rất thích cuốn sách này."},{"t":"para","text":"3. Она́ ... на про́шлой неде́ле к свои́м роди́телям.","b":1},{"t":"para","text":"(е́здить/съе́здить)"},{"t":"subhead","text":"Đáp án: е́здила","b":1},{"t":"para","text":"Giải thích: Đã đi và đã về (sự kiện khứ hồi trong quá khứ)."},{"t":"para","text":"Dịch: Tuần trước cô ấy đã về thăm bố mẹ."},{"t":"para","text":"4. Он до́лжен тебе́ написа́ть, наве́рное, он ... твой а́дрес.","b":1},{"t":"para","text":"(теря́ть/потеря́ть)"},{"t":"subhead","text":"Đáp án: потеря́л","b":1},{"t":"para","text":"Giải thích: Kết quả: giờ không còn địa chỉ nữa nên không viết được."},{"t":"para","text":"Dịch: Hẳn là cậu ấy phải viết cho bạn chứ, chắc là cậu ấy đã làm mất địa chỉ của bạn rồi."},{"t":"para","text":"5. Я ... ку́ртку в гардеро́бе, но гардеро́б рабо́тает то́лько до семи́ часо́в, и мне пришло́сь забра́ть её отту́да.","b":1},{"t":"example","text":"Lỗi logic sách: Nếu \"phải lấy ra\" thì tức là chưa để lại lâu? Hay là \"đã để\" (оставил) nhưng phải lấy về?"},{"t":"example","text":"Ngữ cảnh: Có lẽ câu này là: \"Tôi đã để (оставил - kết quả) áo ở đó, nhưng... tôi phải lấy về (ngay/sớm/muộn)\". Hoặc dùng НСВ оставлял (tôi đã gửi áo ở đó - sự kiện)."},{"t":"subhead","text":"Đáp án sách thường chọn: оста́вил. (Tôi đã gửi áo, nhưng vì đóng cửa sớm nên phải lấy về)."},{"t":"para","text":"Dịch: Tôi đã gửi áo khoác ở phòng giữ đồ, nhưng phòng chỉ làm việc đến 7 giờ nên tôi đã phải lấy về."},{"t":"para","text":"6. Он вошёл в ко́мнату, ... свет и подошёл к пи́сьменному столу́.","b":1},{"t":"para","text":"(включа́ть/включи́ть)"},{"t":"subhead","text":"Đáp án: включи́л","b":1},{"t":"para","text":"Giải thích: Chuỗi hành động nối tiếp: Vào → Bật đèn → Đi tới bàn."},{"t":"para","text":"Dịch: Anh ấy bước vào phòng, bật đèn và đi tới bàn viết."},{"t":"para","text":"7. В про́шлом году́ он ... кури́ть и с тех пор не вы́курил ни одно́й сигаре́ты.","b":1},{"t":"para","text":"(броса́ть/бро́сить)"},{"t":"subhead","text":"Đáp án: бро́сил","b":1},{"t":"para","text":"Giải thích: Kết quả dứt điểm (bỏ hẳn)."},{"t":"para","text":"Dịch: Năm ngoái anh ấy đã bỏ thuốc lá và từ đó đến nay không hút điếu nào."},{"t":"para","text":"8. Заче́м ты ... окно́ и ушёл? Заче́м ты ... окно́, ду́маешь, я не заме́тила, что окно́ бы́ло откры́то?","b":1},{"t":"para","text":"(открыва́ть/откры́ть)"},{"t":"subhead","text":"Đáp án: откры́л / открыва́л","b":1},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Vế 1: Tại sao mở rồi bỏ đi (kết quả cửa đang mở) → откры́л."},{"t":"para","text":"Vế 2: Tại sao lại thực hiện hành động mở cửa (dù ai đó có thể đã đóng lại, hoặc nhấn mạnh vào hành vi) → открыва́л."},{"t":"para","text":"Dịch: Sao anh lại mở cửa sổ rồi bỏ đi thế? / Sao anh lại mở cửa sổ làm gì (hành động), anh tưởng tôi không nhận ra là cửa đã bị mở à?"},{"t":"para","text":"9. Я ... спать, но не смог усну́ть и опять сел рабо́тать.","b":1},{"t":"para","text":"(ложи́ться/лечь)"},{"t":"subhead","text":"Đáp án: ложи́лся (hoặc лёг)."},{"t":"example","text":"Phân tích: Nếu лёг (đã nằm xuống rồi) nhưng không ngủ được -> Hợp lý. Nếu ложился (đang định đi ngủ/thực hiện quy trình đi ngủ) -> Cũng được. Với vế sau \"lại ngồi dậy làm việc\", лёг (kết quả hành động nằm) phổ biến hơn. Tuy nhiên, nếu nhấn mạnh \"tôi đã thử đi ngủ\" thì là ложился. Sách thường dùng лёг cho hành động nằm xuống cụ thể. Nhưng vì có \"không ngủ được\", nên ложился (đã đi nằm - sự kiện) cũng rất đúng."},{"t":"example","text":"Glazunova hay dùng: ложи́лся (đã đi nằm - fact) trong trường hợp không ngủ được."},{"t":"para","text":"Dịch: Tôi đã đi nằm, nhưng không ngủ được nên lại ngồi dậy làm việc."},{"t":"para","text":"10. Э́то не я ... твою́ ру́чку, она́ у кого́-нибу́дь друго́го. Э́то не я ... твою́ ру́чку, я никогда́ бы не верну́л её тебе́ сло́манной.","b":1},{"t":"para","text":"(брать/взять)"},{"t":"subhead","text":"Đáp án: брал / взял (hoặc брал cả hai)."},{"t":"para","text":"Vế 1: Tôi không cầm (không giữ nó - kết quả hiện tại) -> взял. Hoặc tôi không thực hiện hành động lấy -> брал. Với \"nó đang ở chỗ người khác\", ý là tôi không phải người lấy -> брал."},{"t":"para","text":"Vế 2: Tôi không lấy (để làm hỏng) -> брал."},{"t":"subhead","text":"Quy tắc phủ định: Thường dùng не брал (НСВ) để chối bỏ hoàn toàn việc thực hiện hành động."},{"t":"subhead","text":"Đáp án: брал / брал. (Cả hai đều phủ định sự kiện)."},{"t":"para","text":"Dịch: Không phải tớ lấy bút của cậu đâu, ai đó cầm đấy. / Không phải tớ lấy bút cậu đâu, tớ đời nào lại trả lại nó trong tình trạng bị gãy như thế."}]},{"id":"07-s079","type":"exercise","title":"Bài 570 (Trang 294)","num":570,"blocks":[{"t":"instruction","text":"Yêu cầu: Hoàn thành câu theo mẫu, sử dụng thông tin phù hợp. Mẫu: Я позвони́л ему́ ... . → Я позвони́л ему́ и сообщи́л о твоём прие́зде (kết quả thành công). Я позвони́л ему́, но его́ не́ бы́ло до́ма (kết quả thất bại/trái ngược)."},{"t":"para","text":"Làm bài:","b":1},{"t":"para","text":"1. Мы встре́тились с ним ... .","b":1},{"t":"para","text":"Vế 1 (Thành công): ...и обсуди́ли все вопро́сы. (...và đã thảo luận mọi vấn đề)."},{"t":"para","text":"Vế 2 (Trái ngược): ...но не успе́ли поговори́ть. (...nhưng không kịp nói chuyện)."},{"t":"para","text":"2. Я уви́дел её в институ́те ... .","b":1},{"t":"para","text":"Vế 1: ...и переда́л ей твою́ кни́гу. (...và đưa cho cô ấy cuốn sách của bạn)."},{"t":"para","text":"Vế 2: ...но она́ меня́ не заме́тила. (...nhưng cô ấy không nhìn thấy tôi)."},{"t":"para","text":"3. Он записа́л но́мер упражне́ний ... .","b":1},{"t":"para","text":"Vế 1: ...и вы́полнил их до́ма. (...và đã làm chúng ở nhà)."},{"t":"para","text":"Vế 2: ...но потеря́л листо́к. (...nhưng đã làm mất tờ giấy)."},{"t":"para","text":"4. Я постара́лся успе́ть всё сде́лать к прихо́ду госте́й ... .","b":1},{"t":"para","text":"Vế 1: ...и у меня́ всё получи́лось. (...và tôi đã làm được tất cả)."},{"t":"para","text":"Vế 2: ...но вре́мени не хва́тило. (...nhưng không đủ thời gian)."},{"t":"para","text":"5. Мы возврати́лись за кни́гой ... .","b":1},{"t":"para","text":"Vế 1: ...и нашли́ её на столе́. (...và tìm thấy nó trên bàn)."},{"t":"para","text":"Vế 2: ...но её уже́ там не́ было. (...nhưng nó không còn ở đó nữa)."},{"t":"para","text":"6. Я собра́лся идти́ к тебе́ ... .","b":1},{"t":"para","text":"Vế 1: ...и вы́шел из до́ма по-ра́ньше. (...và đã ra khỏi nhà sớm hơn)."},{"t":"para","text":"Vế 2: ...но ко мне пришли́ друзья́. (...nhưng bạn bè lại đến nhà tôi)."},{"t":"para","text":"7. Я напо́мнил ему́ о консульта́ции ... .","b":1},{"t":"para","text":"Vế 1: ...и он пришёл во́время. (...và cậu ấy đã đến đúng giờ)."},{"t":"para","text":"Vế 2: ...но он всё равно́ забы́л. (...nhưng cậu ấy vẫn quên)."}]},{"id":"07-s080","type":"exercise","title":"Bài 571 (Trang 295)","num":571,"blocks":[{"t":"example","text":"Chủ điểm ngữ pháp: Thể động từ trong quá khứ với các trạng từ chỉ thời gian уже́ (đã... rồi), ещё (vẫn/còn), ещё не (vẫn chưa)."},{"t":"vocab","ru":"Уже́ + СВ (Thể hoàn thành)","vi":"Chỉ hành động đã hoàn tất, có kết quả (Đã làm xong rồi).","g":null},{"t":"vocab","ru":"Уже́ + НСВ (Thể chưa hoàn thành)","vi":"Chỉ hành động đã bắt đầu và đang diễn ra, hoặc trạng thái đã thay đổi và kéo dài (Đã đang làm gì/Đã không còn làm gì).","g":null},{"t":"vocab","ru":"Ещё + НСВ","vi":"Hành động vẫn đang tiếp diễn (Vẫn đang làm).","g":null},{"t":"vocab","ru":"Ещё не + НСВ","vi":"Vẫn chưa thực hiện hành động (như một sự kiện), hoặc chưa bắt đầu.","g":null},{"t":"vocab","ru":"Ещё не + СВ","vi":"Vẫn chưa đạt được kết quả (nhưng hướng tới kết quả đó).","g":null},{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng dạng đúng của động từ (НСВ hoặc СВ)."},{"t":"para","text":"1. Когда́ мы пришли́, он ещё (спать/поспа́ть), и нам пришло́сь до́лго его́ буди́ть.","b":1},{"t":"subhead","text":"Đáp án: спал (НСВ)"},{"t":"para","text":"Dịch: Khi chúng tôi đến, anh ấy vẫn đang ngủ, và chúng tôi đã phải gọi anh ấy dậy rất lâu."},{"t":"example","text":"Giải thích: Ещё (vẫn) + hành động đang diễn ra (ngủ) → НСВ."},{"t":"para","text":"2. Могу́ я идти́, я уже́ (де́лать/сде́лать) всё, о чём вы меня́ проси́ли?","b":1},{"t":"subhead","text":"Đáp án: сде́лал (СВ)"},{"t":"para","text":"Dịch: Tôi có thể đi được chưa, tôi đã làm xong tất cả những gì ông nhờ rồi chứ?"},{"t":"example","text":"Giải thích: Уже + kết quả hoàn tất (làm xong) để xin phép đi → СВ."},{"t":"para","text":"3. Он был совсе́м мо́лод и ещё (учи́ться/вы́учиться) в университе́те, когда́ получи́л свою́ пе́рвую пре́мию.","b":1},{"t":"subhead","text":"Đáp án: учи́лся (НСВ)"},{"t":"para","text":"Dịch: Anh ấy còn rất trẻ và vẫn đang học đại học khi nhận được giải thưởng đầu tiên."},{"t":"example","text":"Giải thích: Ещё + quá trình đang diễn ra (đang học) → НСВ."},{"t":"para","text":"4. Я уже́ (уходи́ть/уйти́), когда́ разда́лся телефо́нный звоно́к.","b":1},{"t":"subhead","text":"Đáp án: уходи́л (НСВ)"},{"t":"para","text":"Dịch: Tôi đang đi ra/chuẩn bị đi (đã bắt đầu quá trình rời đi) thì chuông điện thoại reo."},{"t":"example","text":"Giải thích: Hành động đang diễn ra (chưa hoàn tất việc rời khỏi hẳn) thì hành động khác cắt ngang. Nếu dùng ушёл (đã đi rồi) thì sẽ không nghe thấy chuông hoặc không quay lại nghe được."},{"t":"para","text":"5. Вы ещё не (узнава́ть/узна́ть) его́ но́вый а́дрес?","b":1},{"t":"subhead","text":"Đáp án: узна́ли (СВ)"},{"t":"para","text":"Dịch: Các bạn vẫn chưa biết được/tìm ra địa chỉ mới của anh ấy à?"},{"t":"example","text":"Giải thích: Hỏi về kết quả (đã biết chưa?) → Phủ định kết quả dùng ещё не + СВ."},{"t":"para","text":"6. Ду́маю, об э́том я уже́ никогда́ не (забыва́ть/забы́ть).","b":1},{"t":"subhead","text":"Đáp án: забу́ду (СВ)"},{"t":"para","text":"Dịch: Tôi nghĩ rằng tôi sẽ không bao giờ quên được chuyện này nữa."},{"t":"example","text":"Giải thích: Никогда не + СВ (tương lai) = Không bao giờ xảy ra kết quả đó (quên)."},{"t":"para","text":"7. — Ты уже́ (чита́ть/прочита́ть) э́ту статью́? — Нет, я ещё не (чита́ть/прочита́ть), нигде́ не могу́ её доста́ть.","b":1},{"t":"subhead","text":"Đáp án: чита́л / чита́л (hoặc прочита́л / чита́л)"},{"t":"example","text":"Phân tích: Câu hỏi \"Đã đọc chưa?\" có thể hỏi về kết quả (прочитал) hoặc sự kiện (читал). Câu trả lời \"Chưa, tôi chưa đọc (chưa hề đọc)\" vì \"không tìm thấy nó ở đâu\"."},{"t":"para","text":"Nếu không có sách thì không thể thực hiện hành động → Phủ định sự kiện."},{"t":"subhead","text":"Đáp án tối ưu: чита́л / чита́л (Bạn đã đọc bài này chưa? - Chưa, tớ chưa đọc, tớ không kiếm đâu ra mà đọc)."},{"t":"para","text":"8. К э́тому моме́нту я уже́ (учи́ться/проучи́ться) в институ́те.","b":1},{"t":"subhead","text":"Đáp án: учи́лся (НСВ)"},{"t":"para","text":"Dịch: Vào thời điểm đó tôi đã đang học ở học viện rồi."},{"t":"example","text":"Giải thích: Уже + trạng thái/quá trình đang diễn ra tại mốc thời gian quá khứ."},{"t":"para","text":"9. Вы ещё не (обе́дать/пообе́дать)? Мы хоти́м пригласи́ть вас (обе́дать/пообе́дать) с на́ми.","b":1},{"t":"subhead","text":"Đáp án: обе́дали / пообе́дать","b":1},{"t":"para","text":"Dịch: Các bạn vẫn chưa ăn trưa à? Chúng tôi muốn mời các bạn dùng bữa trưa với chúng tôi."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Ещё не + НСВ (chưa thực hiện hành động ăn - sự kiện)."},{"t":"example","text":"Vế 2: Mời làm gì đó (đạt kết quả ăn uống cùng nhau) → СВ пообедать (hoặc обедать cũng được, nhưng пообедать nghe cụ thể cho một lần mời hơn)."},{"t":"para","text":"10. Извини́те, я ещё не (выполня́ть/вы́полнить) ва́шу про́сьбу, не успе́л.","b":1},{"t":"subhead","text":"Đáp án: вы́полнил (СВ)"},{"t":"para","text":"Dịch: Xin lỗi, tôi vẫn chưa thực hiện xong (kết quả) yêu cầu của bạn, tôi không kịp."},{"t":"example","text":"Giải thích: Vì có \"không kịp\" (не успел - СВ), tức là muốn nói đến việc hoàn thành kết quả → Dùng СВ выполнил."},{"t":"para","text":"11. К сожале́нию, он у нас уже́ не (рабо́тать/порабо́тать).","b":1},{"t":"subhead","text":"Đáp án: рабо́тает (Hiện tại) hoặc рабо́тал (Quá khứ - ý nói lúc đó)."},{"t":"example","text":"Ngữ cảnh: \"Anh ấy không còn làm việc ở đây nữa\". Đây là sự chấm dứt một trạng thái."},{"t":"subhead","text":"Đáp án: рабо́тает (nếu câu trực tiếp hiện tại) hoặc рабо́тал (nếu kể lại). Thường trong bài tập quá khứ sẽ là: Он у нас уже не работал (Lúc đó anh ấy đã nghỉ làm rồi)."},{"t":"para","text":"Dịch: Tiếc là anh ấy đã không còn làm việc ở chỗ chúng tôi nữa."},{"t":"para","text":"12. Наде́юсь, я уже́ (отвеча́ть/отве́тить) на ваш вопро́с.","b":1},{"t":"subhead","text":"Đáp án: отве́тил (СВ)"},{"t":"para","text":"Dịch: Hy vọng là tôi đã trả lời (xong/được) câu hỏi của bạn."},{"t":"para","text":"Giải thích: Kết quả đã đạt được."},{"t":"para","text":"13. Мы ещё не (смотре́ть/посмотре́ть) э́тот спекта́кль.","b":1},{"t":"subhead","text":"Đáp án: смотре́ли (НСВ)"},{"t":"para","text":"Dịch: Chúng tôi vẫn chưa xem vở kịch này (chưa từng xem)."},{"t":"para","text":"Giải thích: Phủ định sự trải nghiệm/sự kiện → НСВ."},{"t":"para","text":"14. Я уже́ (спра́шивать/спроси́ть) его́ об э́том, но не получи́л никако́го отве́та.","b":1},{"t":"subhead","text":"Đáp án: спра́шивал (НСВ)"},{"t":"para","text":"Dịch: Tôi đã hỏi anh ấy về việc này rồi (sự kiện đã xảy ra), nhưng không nhận được câu trả lời."},{"t":"para","text":"Giải thích: Dùng НСВ để chỉ việc \"đã từng hỏi\", nhấn mạnh sự việc đã diễn ra nhưng kết quả (câu trả lời) thì không có."},{"t":"para","text":"15. Мы ещё (одева́ться/оде́ться), когда́ он пришёл.","b":1},{"t":"subhead","text":"Đáp án: одева́лись (НСВ)"},{"t":"para","text":"Dịch: Chúng tôi vẫn đang thay đồ thì anh ấy đến."},{"t":"example","text":"Giải thích: Hành động đang diễn ra (ещё + НСВ) bị hành động khác cắt ngang."},{"t":"para","text":"16. Я уже́ (напомина́ть/напо́мнить) вам об э́том, но могу́ повтори́ть ещё раз.","b":1},{"t":"subhead","text":"Đáp án: напомина́л (НСВ)"},{"t":"para","text":"Dịch: Tôi đã nhắc bạn về việc này rồi (sự kiện), nhưng tôi có thể nhắc lại lần nữa."},{"t":"para","text":"Giải thích: Nhấn mạnh sự kiện đã từng làm (fact)."},{"t":"para","text":"17. Когда́ он вошёл, я уже́ (зака́нчивать/зако́нчить) писа́ть письмо́...","b":1},{"t":"subhead","text":"Đáp án: зака́нчивал (НСВ)"},{"t":"para","text":"Dịch: Khi anh ấy bước vào, tôi đang viết nốt/đang hoàn thành bức thư."},{"t":"example","text":"Giải thích: Уже + quá trình đang ở giai đoạn cuối (đang kết thúc) → НСВ. Nếu dùng закончил thì là \"tôi đã viết xong rồi\". Ngữ cảnh này thường là hành động song song: anh vào thì tôi đang ở đoạn kết."}]},{"id":"07-s081","type":"exercise","title":"Bài 572 (Trang 296)","num":572,"blocks":[{"t":"para","text":"Chủ điểm: Sử dụng thể động từ trong văn kể chuyện (quá khứ)."},{"t":"vocab","ru":"СВ","vi":"Dùng cho chuỗi hành động xảy ra nối tiếp nhau (hành động này xong đến hành động kia).","g":null},{"t":"vocab","ru":"НСВ","vi":"Dùng để miêu tả bối cảnh, hành động lặp lại, hoặc hành động kéo dài.","g":null},{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng thể thích hợp (có thể là quá khứ, hiện tại hoặc tương lai tùy ngữ cảnh trích dẫn)."},{"t":"para","text":"a) Câu chuyện về tác giả kịch:","b":1},{"t":"example","text":"По́сле оконча́ния пе́рвого а́кта к актёру, кото́рый из рук вон пло́хо (исполня́ть/испо́лнить) одну́ из гла́вных роле́й, (подбега́ть/подбежа́ть) а́втор пье́сы и (заявля́ть/заяви́ть):"},{"t":"subhead","text":"Đáp án: исполня́л (НСВ) — подбежа́л (СВ) — заяви́л (СВ)."},{"t":"para","text":"Dịch: Sau khi kết thúc màn một, tác giả vở kịch chạy tới (hành động nối tiếp - СВ) chỗ nam diễn viên, người mà đang/đã đóng (quá trình biểu diễn tệ hại - НСВ) một vai chính rất tồi, và tuyên bố (СВ):"},{"t":"vocab","ru":"— Я сро́чно изменя́ю сюже́т","vi":"вы (умира́ть/умере́ть) в нача́ле второ́го а́кта, а не в конце́ тре́тьего.","g":null},{"t":"subhead","text":"Đáp án: умрёте (СВ - Tương lai)."},{"t":"para","text":"Dịch: — Tôi thay đổi cốt truyện khẩn cấp: anh sẽ chết (kết quả) ngay đầu màn hai, chứ không phải cuối màn ba."},{"t":"example","text":"Лу́чше вам (погиба́ть/поги́бнуть) по моему́ за́мыслу, чем от рук зри́телей."},{"t":"subhead","text":"Đáp án: поги́бнуть (СВ)."},{"t":"para","text":"Dịch: Thà anh chết/bị giết (kết quả) theo ý đồ của tôi còn tốt hơn là chết dưới tay khán giả."},{"t":"para","text":"b) Câu chuyện trên tàu:","b":1},{"t":"example","text":"Одна́жды я (наблюда́ть/понаблюда́ть), как изве́стная писа́тельница (дискути́ровать/продискути́ровать) в по́езде с па́стором о свяще́нном писа́нии."},{"t":"subhead","text":"Đáp án: наблюда́л (НСВ) — дискути́ровала (НСВ)."},{"t":"para","text":"Dịch: Có lần tôi đã quan sát (quá trình) một nữ nhà văn nổi tiếng tranh luận (quá trình) trên tàu với một mục sư về Kinh thánh."},{"t":"example","text":"— Вы должны́ призна́ть, — (обраща́ться/обрати́ться) к ней па́стор, — что бог созда́л мужчи́ну ра́ньше же́нщины."},{"t":"subhead","text":"Đáp án: обрати́лся (СВ)."},{"t":"para","text":"Dịch: — Bà phải thừa nhận rằng, — vị mục sư quay sang nói (hành động cụ thể 1 lần) với bà ấy, — là Chúa tạo ra đàn ông trước phụ nữ."},{"t":"example","text":"— Не возража́ю, — невозмути́мо (отвеча́ть/отве́тить) писа́тельница. — Я и сама́ (по́льзоваться/воспо́льзоваться) тем же ме́тодом: когда́ (писа́ть/написа́ть) кни́гу, снача́ла (де́лать/сде́лать) чернови́к..."},{"t":"subhead","text":"Đáp án: отве́тила (СВ) — по́льзуюсь (НСВ - Hiện tại/thói quen) — пишу́ (НСВ) — де́лаю (НСВ)."},{"t":"para","text":"Dịch: — Tôi không phản đối, — nữ nhà văn đáp (kết quả) bình thản. — Bản thân tôi cũng thường dùng phương pháp đó: khi viết sách, đầu tiên tôi làm bản nháp (trước)..."},{"t":"para","text":"c) Câu chuyện chú chó:","b":1},{"t":"example","text":"Оди́н студе́нт (заявля́ть/заяви́ть), что зарабо́тает миллио́н, когда́ (учи́ть/научи́ть) своего́ пса (говори́ть/сказа́ть)."},{"t":"subhead","text":"Đáp án: заяви́л (СВ) — нау́чит (СВ) — говори́ть (НСВ - kỹ năng)."},{"t":"para","text":"Dịch: Một sinh viên đã tuyên bố rằng cậu ta sẽ kiếm được triệu đô khi dạy được (kết quả) con chó của mình biết nói (kỹ năng)."},{"t":"example","text":"— Ну кто тебе́ (дава́ть/дать) миллио́н за говоря́щего пса? — (удивля́ться/удиви́ться) его́ прия́тели."},{"t":"subhead","text":"Đáp án: даст (СВ) — удиви́лись (СВ)."},{"t":"para","text":"Dịch: — Ai mà sẽ cho (kết quả) cậu một triệu vì con chó biết nói chứ? — bạn bè cậu ta ngạc nhiên (phản ứng tức thời)."},{"t":"example","text":"— Из обы́чных люде́й — никто́, — (признава́ться/призна́ться) студе́нт. — Но производи́тели соба́чьих консе́рвов (плати́ть/заплати́ть) бы и бо́льше миллио́на, лишь бы заста́вить его́ (молча́ть/замолча́ть)..."},{"t":"subhead","text":"Đáp án: призна́лся (СВ) — заплати́ли (СВ) — молча́ть (НСВ)."},{"t":"para","text":"Dịch: — Người thường thì không ai cho đâu, — cậu sinh viên thú nhận. — Nhưng các nhà sản xuất thức ăn cho chó sẽ trả (kết quả giả định) thậm chí hơn một triệu, chỉ để bắt nó im lặng/câm miệng (trạng thái kéo dài, không nói ra sự thật về thức ăn dở)."}]},{"id":"07-s082","type":"exercise","title":"Bài 573 (Trang 296-297)","num":573,"blocks":[{"t":"para","text":"Chủ điểm: Sử dụng thể động từ trong văn kể chuyện (thì quá khứ)."},{"t":"vocab","ru":"СВ (Thể hoàn thành)","vi":"Dùng cho chuỗi các hành động xảy ra nối tiếp nhau (hành động này xong đến hành động kia), hoặc một hành động xảy ra tức thời đạt kết quả.","g":null},{"t":"vocab","ru":"НСВ (Thể chưa hoàn thành)","vi":"Dùng để miêu tả bối cảnh, quá trình, hoặc hành động lặp lại.","g":null},{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng thể động từ quá khứ (СВ hoặc НСВ)."},{"t":"para","text":"(Câu chuyện cậu bé và vết thương)","b":1},{"t":"para","text":"1. Ма́ленький ма́льчик прибежа́л к ма́тери с разби́тым коле́ном и (попроси́л) сма́зать его́ йо́дом.","b":1},{"t":"para","text":"(проси́ть/попроси́ть)"},{"t":"para","text":"Dịch: Một cậu bé chạy đến chỗ mẹ với cái đầu gối bị vỡ và đã nhờ (bà) bôi i-ốt cho mình."},{"t":"example","text":"Giải thích: Đây là một hành động cụ thể xảy ra nối tiếp sau khi \"chạy đến\" (прибежал - СВ) → Dùng СВ (попроси́л)."},{"t":"para","text":"2. — Что (произошло́)? — (спроси́ла) его́ мать.","b":1},{"t":"para","text":"(происходи́ть/произойти́); (спра́шивать/спроси́ть)"},{"t":"para","text":"Dịch: — Chuyện gì đã xảy ra vậy? — người mẹ đã hỏi."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Hỏi về kết quả sự việc (một sự kiện đã hoàn tất) → СВ (произошло́)."},{"t":"para","text":"Hành động \"hỏi\" xảy ra 1 lần trong chuỗi hội thoại → СВ (спроси́ла)."},{"t":"para","text":"3. — Я по́лез в шкаф на ве́рхнюю по́лку, она́ (оторва́лась), я (упа́л) и (уда́рил) коле́но о ни́жнюю по́лку.","b":1},{"t":"para","text":"(отрыва́ться/оторва́ться); (па́дать/упа́сть); (ударя́ть/уда́рить)"},{"t":"para","text":"Dịch: — Con leo lên ngăn trên cùng của cái tủ, nó bị bung ra, con bị ngã và đập đầu gối vào ngăn dưới."},{"t":"para","text":"Giải thích: Chuỗi hành động nhân quả nối tiếp nhau: Tủ bung → Ngã → Đập chân. Tất cả đều dùng СВ để chỉ sự việc xảy ra dứt điểm (оторва́лась, упа́л, уда́рил)."},{"t":"para","text":"4. — Бо́же мой! — (воскли́кнула) мать, — Но что тебе́ на́до бы́ло в шкафу́?","b":1},{"t":"para","text":"(восклица́ть/воскли́кнуть)"},{"t":"para","text":"Dịch: — Trời ơi! — người mẹ thốt lên, — Nhưng con cần gì trong tủ chứ?"},{"t":"para","text":"Giải thích: Hành động thốt lên một lần (phản ứng tức thì) → СВ (воскли́кнула)."},{"t":"para","text":"5. — Я хоте́л (доста́ть) клей, что́бы (скле́ить) большу́ю ва́зу, кото́рая (стоя́ла) в гости́ной.","b":1},{"t":"para","text":"(достава́ть/доста́ть); (кле́ить/скле́ить); (стоя́ть/постоя́ть)"},{"t":"para","text":"Dịch: — Con định lấy keo để dán lại cái bình lớn mà đã đứng/để trong phòng khách."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"доста́ть (lấy được - kết quả mục tiêu) → СВ."},{"t":"example","text":"скле́ить (dán xong - kết quả mục tiêu) → СВ."},{"t":"example","text":"стоя́ла (miêu tả vị trí/trạng thái kéo dài trong quá khứ của cái bình) → НСВ."},{"t":"para","text":"6. — Понима́ешь, ма́мочка, я (игра́л) в гольф. Когда́ я (уда́рил) по мячу́, он (попа́л) в зе́ркало над ками́ном, (разби́л) его́, (отскочи́л) к ва́зе и (свали́л) её на пол.","b":1},{"t":"para","text":"(игра́ть/сыгра́ть); (ударя́ть/уда́рить); (попада́ть/попа́сть); (разбива́ть/разби́ть); (отска́кивать/отскочи́ть); (вали́ть/свали́ть)"},{"t":"para","text":"Dịch: — Mẹ hiểu không, con đang chơi gôn. Khi con đánh vào bóng, nó trúng vào cái gương trên lò sưởi, làm vỡ gương, nảy vào cái bình và làm đổ nó xuống sàn."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"игра́л","vi":"Quá trình/hoàn cảnh lúc đó (đang chơi) → НСВ.","g":null},{"t":"example","text":"Các động từ còn lại là chuỗi sự kiện xảy ra nhanh, nối tiếp nhau dẫn đến hậu quả: уда́рил (đánh 1 phát), попа́л (trúng), разби́л (vỡ), отскочи́л (nảy ra), свали́л (làm đổ) → Tất cả dùng СВ."},{"t":"para","text":"7. — Но поче́му ты (игра́л) в гольф до́ма?","b":1},{"t":"para","text":"(игра́ть/сыгра́ть)"},{"t":"para","text":"Dịch: — Nhưng tại sao con lại chơi gôn trong nhà?"},{"t":"para","text":"Giải thích: Mẹ hỏi về hành động/quá trình chơi (tại sao lại diễn ra việc đó) → НСВ (игра́л)."},{"t":"para","text":"8. — Нет, ма́ма, я был во дворе́, но когда́ мяч (влете́л) в гости́ную, он (разби́л) окно́, кото́рое (выхо́дит/выходи́ло) во двор...","b":1},{"t":"para","text":"(влета́ть/влете́ть); (разбива́ть/разби́ть); (выходи́ть/вы́йти)"},{"t":"para","text":"Dịch: — Không mẹ, con ở ngoài sân, nhưng khi quả bóng bay vào phòng khách, nó đã làm vỡ cái cửa sổ trông ra sân..."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"влете́л, разби́л","vi":"Các sự kiện xảy ra tức thời, có kết quả → СВ.","g":null},{"t":"vocab","ru":"выходи́ло (hoặc выхо́дит)","vi":"Miêu tả đặc điểm cố định của cái cửa sổ (hướng ra sân) → НСВ.","g":null}]},{"id":"07-s083","type":"exercise","title":"Bài 574 (Trang 297)","num":574,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc câu, xác định sự khác biệt về nghĩa của các động từ mệnh lệnh thức (Imperative). Gọi tên động từ nguyên mẫu gốc."},{"t":"subhead","text":"Lý thuyết mệnh lệnh thức (Императив):","b":1},{"t":"subhead","text":"НСВ (Chưa hoàn thành):","b":1},{"t":"instruction","text":"Yêu cầu thực hiện hành động như một thói quen/lặp lại (Пиши мне - Hãy viết cho tôi thường xuyên)."},{"t":"example","text":"Mời mọc, cho phép (Входите - Mời vào)."},{"t":"example","text":"Bắt đầu thực hiện hành động đi (thúc giục quá trình) (Читай! - Đọc đi!)."},{"t":"example","text":"Cấm đoán (với не) (Не забывайте - Đừng quên)."},{"t":"subhead","text":"СВ (Hoàn thành):","b":1},{"t":"instruction","text":"Yêu cầu thực hiện một hành động cụ thể, một lần (Напиши мне - Hãy viết cho tôi khi nào đến nơi)."},{"t":"example","text":"Cảnh báo coi chừng lỡ xảy ra kết quả xấu (với не) (Не упади - Coi chừng ngã)."},{"t":"para","text":"Giải thích chi tiết:","b":1},{"t":"example","text":"a) 1. Пиши́ мне как мо́жно ча́ще. (Hành động lặp lại - НСВ писа́ть). Напиши́ мне, как то́лько прие́дешь домо́й. (Hành động 1 lần cụ thể - СВ написа́ть).","b":1},{"t":"para","text":"Dịch: Hãy viết cho tớ càng thường xuyên càng tốt. Hãy viết (một bức thư) cho tớ ngay khi cậu về đến nhà."},{"t":"example","text":"a) 2. Внима́тельно проверя́йте все свой рабо́ты. (Quy tắc chung - НСВ проверя́ть). Прове́рьте, пожа́луйства, мою́ рабо́ту. (Yêu cầu cụ thể 1 lần - СВ прове́рить).","b":1},{"t":"para","text":"Dịch: Hãy kiểm tra kỹ tất cả bài làm của mình. Làm ơn hãy kiểm tra bài của em (ngay bây giờ)."},{"t":"example","text":"a) 3. Чита́йте не спеша́, обраща́я внима́ние на произноше́ние. (Khuyên về cách thức thực hiện hành động - НСВ чита́ть). Прочита́йте э́тот текст и отве́тьте на вопро́сы. (Yêu cầu hoàn thành kết quả - СВ прочита́ть).","b":1},{"t":"para","text":"Dịch: Hãy đọc từ từ, chú ý đến phát âm. Hãy đọc xong bài khóa này và trả lời câu hỏi."},{"t":"example","text":"a) 4. Поче́му вы замолча́ли? Говори́те! (Thúc giục tiếp tục hành động - НСВ говори́ть). Скажи́те, пожа́луйства, кото́рый час? (Hỏi lấy thông tin cụ thể - СВ сказа́ть).","b":1},{"t":"para","text":"Dịch: Sao bạn lại im lặng? Nói đi chứ! Làm ơn cho biết/nói bây giờ là mấy giờ?"},{"t":"example","text":"b) 1. — Мо́жно войти́? — Входи́те, пожа́луйства! (Lời mời lịch sự - НСВ входи́ть). — Мо́жно войти́? — Да, войди́те! (Cho phép cụ thể/lệnh - СВ войти́).","b":1},{"t":"para","text":"Dịch: — Vào được không ạ? — Mời vào! / — Vào được không? — Được, vào đi (ngay)."},{"t":"example","text":"b) 2. — Мо́жно пройти́? — Проходи́те, пожа́луйства! (Mời mọc - НСВ проходи́ть). — Мо́жно пройти́? — Коне́чно, пройди́те! (Cho phép cụ thể - СВ пройти́).","b":1},{"t":"para","text":"Dịch: — Tôi đi qua được không? — Mời qua! / — Tất nhiên, anh qua đi! (Nhưng câu sau \"Không lẽ đứng mãi ở cửa\" hàm ý giục giã)."},{"t":"example","text":"b) 3. Встава́й, тебе́ пора́ идти́ в шко́лу. (Giục giã quy trình dậy - НСВ встава́ть). Встань сейча́с же! Ско́лько мо́жно лежа́ть в посте́ли! (Ra lệnh dứt khoát - СВ встать).","b":1},{"t":"para","text":"Dịch: Dậy đi, đến giờ đi học rồi. Đứng dậy/Dậy ngay lập tức! Nằm mãi trên giường thế à!"},{"t":"example","text":"c) 1. Не забыва́йте свой ве́щи в ваго́нах метро́! (Cấm đoán/nhắc nhở chung - НСВ забыва́ть). Смотри́, не забу́дь принести́ мне за́втра мою́ кни́гу! (Cảnh báo coi chừng quên 1 việc cụ thể - СВ забы́ть).","b":1},{"t":"para","text":"Dịch: Đừng quên đồ trong toa tàu điện ngầm! Nhìn kìa, đừng có quên mang sách cho tớ ngày mai đấy!"},{"t":"example","text":"c) 2. Не роня́й свой ве́щи! (Cấm đoán hành vi - НСВ роня́ть). Не урони́ коро́бку, там стекло́! (Cảnh báo kết quả xấu - СВ урони́ть).","b":1},{"t":"para","text":"Dịch: Đừng có làm rơi đồ đạc của mình! Coi chừng làm rơi cái hộp đấy, trong đó có thủy tinh!"},{"t":"example","text":"c) 3. Не па́дай, стой на нога́х кре́пче. (Khuyên bảo chung - НСВ па́дать). Будь осторо́жен, не упади́, здесь о́чень ско́льзко. (Cảnh báo nguy hiểm cụ thể - СВ упа́сть).","b":1},{"t":"para","text":"Dịch: Đừng ngã, đứng cho vững vào. Cẩn thận, coi chừng ngã đấy, ở đây trơn lắm."}]},{"id":"07-s084","type":"exercise","title":"Bài 575 (Trang 298)","num":575,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung):","b":1},{"t":"example","text":"! В императи́ве глаго́лы несоверше́нного ви́да выража́ют приглаше́ние к де́йствию и́ли про́сьбу; глаго́лы соверше́нного ви́да выража́ют прика́з. Lưu ý: Ngoài ra, НСВ dùng cho hành động lặp lại, СВ dùng cho hành động 1 lần. Dịch: Ở mệnh lệnh thức, động từ thể chưa hoàn thành (НСВ) diễn tả lời mời thực hiện hành động hoặc lời yêu cầu (nhẹ nhàng/bắt đầu quá trình); động từ thể hoàn thành (СВ) diễn tả mệnh lệnh (dứt khoát) hoặc kết quả cần đạt được."},{"t":"instruction","text":"Yêu cầu: Điền động từ mệnh lệnh thức vào chỗ trống."},{"t":"para","text":"1. Регуля́рно (чита́йте) газе́ты, что́бы быть в ку́рсе собы́тий.","b":1},{"t":"para","text":"(чита́ть/прочита́ть) - chọn чита́йте (НСВ)."},{"t":"para","text":"Dịch: Hãy đọc báo thường xuyên để nắm bắt sự kiện."},{"t":"para","text":"Giải thích: Từ \"thường xuyên\" (регулярно) chỉ sự lặp lại → НСВ."},{"t":"para","text":"2. (Просмотри́те) э́ту статью́ и скажи́те, что вы о ней ду́маете.","b":1},{"t":"para","text":"(просма́тривать/просмотре́ть) - chọn просмотри́те (СВ)."},{"t":"para","text":"Dịch: Hãy xem lướt qua bài báo này và cho tôi biết bạn nghĩ gì."},{"t":"para","text":"Giải thích: Cần thực hiện xong hành động (kết quả) để cho ý kiến → СВ."},{"t":"para","text":"3. Пожа́луйства, (посове́туйте) мне, куда́ лу́чше пое́хать ле́том. (Сове́туй) то́лько в том слу́чае, е́сли уве́рен, что твой сове́т бу́дет ну́жен.","b":1},{"t":"para","text":"(сове́товать/посове́товать) - chọn посове́туйте (СВ) và сове́туй (НСВ)."},{"t":"para","text":"Dịch: Làm ơn hãy khuyên (cho tôi một lời khuyên) nên đi đâu vào mùa hè. Hãy (chỉ) khuyên trong trường hợp cậu chắc chắn là lời khuyên đó cần thiết."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Vế 1: Xin một lời khuyên cụ thể → СВ."},{"t":"para","text":"Vế 2: Nguyên tắc chung (chỉ khuyên khi...) → НСВ."},{"t":"para","text":"4. (Прочита́йте) э́тот текст и отве́тьте на вопро́сы.","b":1},{"t":"para","text":"(чита́ть/прочита́ть) - chọn прочита́йте (СВ)."},{"t":"para","text":"Dịch: Hãy đọc (xong) bài khóa này và trả lời câu hỏi."},{"t":"para","text":"Giải thích: Cần hoàn tất việc đọc mới trả lời được → СВ."},{"t":"para","text":"5. (Жди́те) нас за́втра в во́семь часо́в на ста́нции метро́ “Пу́шкинская”. (Подожди́те) нас, пожа́луйства, мы бу́дем гото́вы че́рез не́сколько мину́т.","b":1},{"t":"para","text":"(жда́ть/подожда́ть) - chọn жди́те (НСВ) và подожди́те (СВ)."},{"t":"para","text":"Dịch: Hãy đợi (theo kế hoạch/lịch hẹn) chúng tôi ngày mai lúc 8 giờ ở ga Pushkinskaya. Làm ơn hãy đợi (một chút/nán lại), chúng tôi sẽ xong trong vài phút nữa."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Cuộc hẹn, quá trình chờ → НСВ (hoặc СВ подождите cũng được, nhưng ждите mang tính chất \"hãy ở đó chờ\")."},{"t":"para","text":"Vế 2: Xin chờ một lát (có giới hạn thời gian ngắn/kết quả) → СВ."},{"t":"para","text":"6. (Открыва́йте) шампа́нское ме́дленно, ина́че про́бка мо́жет вы́лететь.","b":1},{"t":"para","text":"(открыва́ть/откры́ть) - chọn открыва́йте (НСВ)."},{"t":"para","text":"Dịch: Hãy mở sâm-panh từ từ thôi, kẻo nút chai bắn ra đấy."},{"t":"example","text":"Giải thích: Chú trọng vào cách thức thực hiện hành động (mở từ từ/chậm rãi) → Dùng НСВ."},{"t":"para","text":"7. (Соста́вьте) диало́г на зада́нную те́му.","b":1},{"t":"para","text":"(составля́ть/соста́вить) - chọn соста́вьте (СВ)."},{"t":"para","text":"Dịch: Hãy soạn một đoạn hội thoại theo chủ đề đã cho."},{"t":"para","text":"Giải thích: Yêu cầu tạo ra sản phẩm/kết quả → СВ."},{"t":"para","text":"8. (Составля́йте) гра́фики дежу́рства на ка́ждый ме́сяц.","b":1},{"t":"para","text":"(составля́ть/соста́вить) - chọn составля́йте (НСВ)."},{"t":"para","text":"Dịch: Hãy lập lịch trực nhật cho mỗi tháng."},{"t":"para","text":"Giải thích: \"Mỗi tháng\" (lặp lại) → НСВ."},{"t":"para","text":"9. (Отремонти́руйте) мой утю́г, пожа́луйства. (Ремонти́руйте) электроприбо́ры то́лько в специализи́рованном ателье́ ремо́нта.","b":1},{"t":"para","text":"(ремонти́ровать/отремонти́ровать) - chọn отремонти́руйте (СВ) và ремонти́руйте (НСВ)."},{"t":"para","text":"Dịch: Làm ơn hãy sửa (xong) cho tôi cái bàn là. Hãy sửa chữa các thiết bị điện chỉ ở những tiệm chuyên dụng."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Vế 1: Yêu cầu cụ thể, cần kết quả → СВ."},{"t":"para","text":"Vế 2: Lời khuyên/quy tắc chung → НСВ."},{"t":"para","text":"10. (Продикту́йте) мне но́мер твоего́ телефо́на. Я гото́в записа́ть ваш а́дрес, (дикту́йте).","b":1},{"t":"para","text":"(диктова́ть/продиктова́ть) - chọn продикту́йте (СВ) và дикту́йте (НСВ)."},{"t":"para","text":"Dịch: Hãy đọc cho tôi số điện thoại của bạn (để tôi có được số). Tôi sẵn sàng ghi địa chỉ của ông rồi, đọc đi (bắt đầu đọc đi)."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Vế 1: Cần kết quả (số điện thoại) → СВ."},{"t":"para","text":"Vế 2: Mời bắt đầu thực hiện hành động (tôi đã sẵn sàng) → НСВ."},{"t":"para","text":"11. Извини́те, я не ме́стный... Е́сли у вас есть вопро́сы, не стесня́йтесь (спра́шивайте).","b":1},{"t":"para","text":"(спра́шивать/спроси́ть) - chọn спра́шивайте (НСВ)."},{"t":"para","text":"Dịch: Xin lỗi, tôi không phải người ở đây... Nếu bạn có câu hỏi, đừng ngại, cứ hỏi đi."},{"t":"example","text":"Giải thích: Не стесняйтесь (đừng ngại) là dấu hiệu cho phép/mời mọc thoải mái → НСВ."},{"t":"para","text":"12. (Отве́тьте), пожа́луйства, на не́сколько на́ших вопро́сов. Поче́му вы молчи́те? (Отвеча́йте)!","b":1},{"t":"para","text":"(отвеча́ть/отве́тить) - chọn отве́тьте (СВ) và отвеча́йте (НСВ)."},{"t":"para","text":"Dịch: Làm ơn hãy trả lời vài câu hỏi của chúng tôi (cần thông tin). Sao anh lại im lặng? Trả lời đi (thúc giục)!"},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Vế 1: Yêu cầu kết quả lịch sự/cụ thể → СВ."},{"t":"para","text":"Vế 2: Thúc giục thực hiện hành động ngay (khi đối phương đang im lặng) → НСВ."},{"t":"para","text":"13. Снача́ла внима́тельно (прослу́шайте) всю информа́цию, а пото́м мо́жете зада́ть вопро́сы. (Слу́шайте) меня́ внима́тельно!","b":1},{"t":"para","text":"(слу́шать/прослу́шать) - chọn прослу́шайте (СВ) và слу́шайте (НСВ)."},{"t":"para","text":"Dịch: Trước tiên hãy nghe hết toàn bộ thông tin, rồi sau đó có thể đặt câu hỏi. Hãy lắng nghe tôi thật kỹ đây!"},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Vế 1: Cần nghe xong trọn vẹn (kết quả) mới được hỏi → СВ."},{"t":"para","text":"Vế 2: Kêu gọi sự chú ý vào quá trình nghe → НСВ."}]},{"id":"07-s085","type":"exercise","title":"Bài 576 (Trang 299)","num":576,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, dùng động từ ở mệnh lệnh thức (Императив) thể hoàn thành (СВ) hoặc chưa hoàn thành (НСВ). Giải thích sự lựa chọn."},{"t":"para","text":"1. Кто-то идёт, (открыва́ть/откры́ть), пожа́луйства, дверь;","b":1},{"t":"subhead","text":"Đáp án: откро́йте (СВ)"},{"t":"para","text":"Dịch: Có ai đang đến kìa, làm ơn hãy mở cửa ra."},{"t":"example","text":"Giải thích: Yêu cầu thực hiện một hành động cụ thể, một lần, cần kết quả ngay → Dùng СВ (откры́ть)."},{"t":"para","text":"2. (Объясня́ть/Объясни́ть) мне, пожа́луйства, э́то пра́вило;","b":1},{"t":"subhead","text":"Đáp án: объясни́те (СВ)"},{"t":"para","text":"Dịch: Làm ơn hãy giải thích cho tôi quy tắc này."},{"t":"example","text":"Giải thích: Yêu cầu cụ thể, cần kết quả là sự hiểu biết → Dùng СВ (объясни́ть)."},{"t":"para","text":"3. Я начина́ю диктова́ть. (Запи́сывать/Записа́ть)!","b":1},{"t":"subhead","text":"Đáp án: Запи́сывайте (НСВ)"},{"t":"para","text":"Dịch: Tôi bắt đầu đọc chính tả đây. Hãy ghi/chép đi!"},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Giáo viên ra lệnh bắt đầu một quá trình hành động (bắt đầu viết đi) → Dùng НСВ (запи́сывать)."},{"t":"note","text":"Lưu ý: Nếu nói \"Запишите домашнее задание\" (Hãy ghi bài tập về nhà - cần kết quả ghi xong) thì dùng СВ. Nhưng ở đây là bắt đầu quá trình nghe-viết."},{"t":"para","text":"4. (Передвига́ть/Передви́нуть) э́тот шкаф осторо́жно, там бью́щиеся ве́щи;","b":1},{"t":"subhead","text":"Đáp án: Передвига́йте (НСВ) hoặc Передви́ньте (СВ)."},{"t":"example","text":"Phân tích: Vì có trạng từ \"cẩn thận\" (осторожно) miêu tả cách thức thực hiện hành động, người Nga thường dùng НСВ để nhấn mạnh vào quá trình thực hiện sao cho cẩn thận. Tuy nhiên, nếu nhấn mạnh kết quả \"hãy chuyển nó đi\", СВ vẫn đúng. Trong ngữ cảnh nhắc nhở sự cẩn trọng khi đang làm/sắp làm, НСВ thường được ưu tiên."},{"t":"subhead","text":"Đáp án sách thường chọn: Передвига́йте (Hãy di chuyển tủ cẩn thận nhé)."},{"t":"para","text":"Dịch: Hãy di chuyển cái tủ này cẩn thận, trong đó có đồ dễ vỡ đấy."},{"t":"para","text":"5. Чего́ вы ждёте?! (Продолжа́ть/Продо́лжить) рабо́тать;","b":1},{"t":"subhead","text":"Đáp án: Продолжа́йте (НСВ)"},{"t":"para","text":"Dịch: Các bạn còn chờ gì nữa?! Tiếp tục làm việc đi."},{"t":"example","text":"Giải thích: Động từ \"tiếp tục\" (продолжать) luôn yêu cầu theo sau là động từ nguyên thể НСВ, và bản thân lệnh \"tiếp tục\" cũng dùng НСВ để chỉ sự kéo dài của hành động."},{"t":"para","text":"6. (Замеча́ть/Заме́тить), я не зря останови́лся на э́том вопро́се;","b":1},{"t":"subhead","text":"Đáp án: Заме́тьте (СВ)"},{"t":"para","text":"Dịch: Hãy lưu ý/để ý rằng, không phải vô cớ mà tôi dừng lại ở câu hỏi này."},{"t":"example","text":"Giải thích: Yêu cầu một sự chú ý/nhận thức tức thời (kết quả tư duy) → Dùng СВ (заме́тить)."},{"t":"para","text":"7. Ничего́ стра́шного, (сохраня́ть/сохрани́ть) споко́йствие!","b":1},{"t":"subhead","text":"Đáp án: сохраня́йте (НСВ)"},{"t":"para","text":"Dịch: Không có gì đáng sợ đâu, hãy giữ bình tĩnh!"},{"t":"example","text":"Giải thích: Khuyên bảo duy trì một trạng thái (quá trình) → Dùng НСВ (сохраня́ть)."},{"t":"para","text":"8. Я прошу́ вас, (следи́ть/ проследи́ть), что́бы рабо́та была́ сдана́ во́время;","b":1},{"t":"subhead","text":"Đáp án: проследи́те (СВ)"},{"t":"para","text":"Dịch: Tôi nhờ ông, hãy theo dõi/đảm bảo để công việc được nộp đúng hạn."},{"t":"example","text":"Giải thích: Cần đạt được kết quả là công việc xong đúng giờ → Dùng СВ (проследи́ть)."},{"t":"para","text":"9. (Держа́ть/ Подержа́ть) го́лову пря́мо, снима́ю;","b":1},{"t":"subhead","text":"Đáp án: Держи́те (НСВ)"},{"t":"para","text":"Dịch: Hãy giữ đầu thẳng, tôi chụp đây (thợ ảnh nói)."},{"t":"example","text":"Giải thích: Yêu cầu duy trì tư thế trong một khoảng thời gian (quá trình) → Dùng НСВ (держа́ть)."},{"t":"para","text":"10. (Поднима́ть/Подня́ть) быстре́е!","b":1},{"t":"subhead","text":"Đáp án: Поднима́йте (НСВ) hoặc Подними́те (СВ)."},{"t":"example","text":"Phân tích: Có từ \"nhanh lên\" (быстрее). Khi thúc giục thực hiện hành động nhanh hơn (đang làm chậm → làm nhanh lên), thường dùng НСВ. Nếu ra lệnh nhấc lên 1 lần dứt khoát → СВ. Ngữ cảnh \"Nhanh lên!\" thường đi với НСВ thúc giục."},{"t":"subhead","text":"Đáp án ưu tiên: Поднима́йте (Nhấc nhanh lên nào! - thúc giục quá trình)."},{"t":"para","text":"Dịch: Nhấc/Nâng nhanh lên!"},{"t":"para","text":"11. (Говори́ть/Сказа́ть) ме́дленно, (следи́ть/проследи́ть) за свои́м произноше́нием;","b":1},{"t":"subhead","text":"Đáp án: Говори́те / следи́те (НСВ / НСВ)"},{"t":"para","text":"Dịch: Hãy nói chậm thôi, hãy để ý/theo dõi phát âm của mình."},{"t":"para","text":"Giải thích: Lời khuyên về cách thức thực hiện hành động (nói thế nào? nói chậm) và duy trì sự chú ý → Dùng НСВ."},{"t":"para","text":"12. Я о́чень уста́л, (оставля́ть/оста́вить) меня́ в поко́е, пожа́луйства;","b":1},{"t":"subhead","text":"Đáp án: оста́вьте (СВ)"},{"t":"para","text":"Dịch: Tôi mệt lắm rồi, làm ơn hãy để tôi yên."},{"t":"example","text":"Giải thích: Cụm từ cố định оставить в покое (để yên), yêu cầu kết quả thay đổi trạng thái ngay lập tức → Dùng СВ (оста́вить)."},{"t":"para","text":"13. Сего́дня на у́лице хо́лодно, (надева́ть/наде́ть) пальто́;","b":1},{"t":"subhead","text":"Đáp án: наде́нь (СВ) - Lưu ý: sách in nhầm động từ gợi ý là одевать, đúng ra phải là надевать/надеть khi mặc quần áo cho mình. Nếu dùng одевать là mặc cho người khác."},{"t":"subhead","text":"Đáp án: наде́нь (hoặc наде́ньте)."},{"t":"para","text":"Dịch: Hôm nay ngoài trời lạnh, hãy mặc áo khoác vào."},{"t":"example","text":"Giải thích: Yêu cầu thực hiện hành động cụ thể 1 lần để có kết quả (ấm) → СВ (наде́ть)."},{"t":"para","text":"14. (Смотре́ть/Посмотре́ть), пожа́луйства, его́ но́мер телефо́на в мое́й записно́й кни́жке;","b":1},{"t":"subhead","text":"Đáp án: Посмотри́те (СВ)"},{"t":"para","text":"Dịch: Làm ơn hãy xem/tra giúp số điện thoại của anh ấy trong sổ tay của tôi."},{"t":"example","text":"Giải thích: Nhờ vả làm một việc cụ thể → СВ (посмотре́ть)."},{"t":"para","text":"15. (Переходи́ть/Перейти́) у́лицу то́лько по зелёному сигна́лу светофо́ра;","b":1},{"t":"subhead","text":"Đáp án: Переходи́те (НСВ)"},{"t":"para","text":"Dịch: Hãy sang đường chỉ khi đèn xanh."},{"t":"example","text":"Giải thích: Quy tắc chung, lặp đi lặp lại → Dùng НСВ (переходи́ть)."},{"t":"para","text":"16. Е́сли ты берёшь мои́ ве́щи, (возвраща́ть/возврати́ть) их на ме́сто, пожа́луйства;","b":1},{"t":"subhead","text":"Đáp án: возвраща́й (НСВ)"},{"t":"para","text":"Dịch: Nếu em lấy đồ của anh, làm ơn hãy trả chúng về chỗ cũ (mỗi lần lấy)."},{"t":"example","text":"Giải thích: Hành động lặp lại (mỗi khi lấy thì phải trả) → Dùng НСВ (возвраща́ть)."},{"t":"para","text":"17. Я не хоте́л тебя́ оби́деть, (проща́ть/прости́ть) меня́, пожа́луйства;","b":1},{"t":"subhead","text":"Đáp án: прости́ (СВ)"},{"t":"para","text":"Dịch: Tớ không cố ý làm cậu giận, làm ơn hãy tha lỗi cho tớ."},{"t":"example","text":"Giải thích: Xin lỗi cho một sự việc cụ thể, cần kết quả hòa giải → СВ (прости́ть)."},{"t":"para","text":"18. (Класть/ Положи́ть) ру́ки на по́яс, (ста́вить/поста́вить) но́ги на ширину́ плеч и (начина́ть/нача́ть) выполня́ть пе́рвое упражне́ние.","b":1},{"t":"subhead","text":"Đáp án: Положи́те / поста́вьте / начина́йте (СВ / СВ / НСВ)"},{"t":"para","text":"Dịch: Hãy đặt tay lên hông, đặt chân rộng bằng vai và bắt đầu tập bài đầu tiên."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Положите, поставьте","vi":"Các động tác thiết lập tư thế ban đầu (cần làm xong, đạt kết quả vị trí) → СВ.","g":null},{"t":"vocab","ru":"Начинайте","vi":"Bắt đầu thực hiện quá trình tập (lệnh bắt đầu) → НСВ.","g":null}]},{"id":"07-s086","type":"exercise","title":"Bài 577 (Trang 299)","num":577,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng các động từ ở mệnh lệnh thức, hãy đưa ra câu trả lời khẳng định cho các câu hỏi sau. Giải thích sự lựa chọn."},{"t":"subhead","text":"Quy tắc:","b":1},{"t":"example","text":"Khi cho phép ai đó làm gì (trong câu hỏi xin phép dùng Можно...?), người Nga thường dùng mệnh lệnh thức НСВ để thể hiện sự cho phép lịch sự, mời mọc (mời làm đi)."},{"t":"para","text":"Tuy nhiên, nếu muốn nhấn mạnh kết quả hoặc sự dứt khoát, có thể dùng СВ."},{"t":"para","text":"1. — Мо́жно зада́ть вопро́с? (Tôi có thể đặt câu hỏi không?)"},{"t":"subhead","text":"Đáp án: — Коне́чно, задава́йте! (Tất nhiên, hỏi đi!)"},{"t":"example","text":"Giải thích: Cho phép/mời mọc → НСВ (задава́ть)."},{"t":"para","text":"2. — Могу́ я вам помо́чь? (Tôi có thể giúp bạn không?)"},{"t":"subhead","text":"Đáp án: — Помоги́те, пожа́луйства! (Làm ơn hãy giúp với!)"},{"t":"example","text":"Giải thích: Nhờ vả cụ thể cần kết quả giúp đỡ → СВ (помо́чь)."},{"t":"para","text":"3. — Могу́ я оста́вить здесь свою́ су́мку? (Tôi có thể để túi ở đây không?)"},{"t":"subhead","text":"Đáp án: — Оставля́йте / Оста́вьте."},{"t":"example","text":"Giải thích: Оставляйте (Cứ để đây - cho phép); Оставьте (Hãy để lại đó - chỉ dẫn cụ thể). Cả hai đều được."},{"t":"para","text":"4. — Мо́жно сесть за ваш сто́лик? (Tôi ngồi bàn ông được không?)"},{"t":"subhead","text":"Đáp án: — Сади́тесь, пожа́луйства. (Mời ngồi)."},{"t":"example","text":"Giải thích: Lời mời lịch sự → НСВ (сади́ться)."},{"t":"example","text":"5. — Мо́жно э́то ме́сто не заня́то? (Chỗ này chưa ai ngồi chứ? - Lỗi sách: Câu hỏi gốc hơi lạ, ý là \"Chỗ này trống chứ? Tôi chiếm chỗ này nhé?\")."},{"t":"para","text":"Giả định câu hỏi: — Мо́жно заня́ть э́то ме́сто? (Tôi lấy chỗ này nhé?)"},{"t":"subhead","text":"Đáp án: — Занима́йте. (Cứ lấy đi/Ngồi đi)."},{"t":"para","text":"6. — Мо́жно вас проводи́ть? (Tôi tiễn bạn nhé?)"},{"t":"subhead","text":"Đáp án: — Проводи́те (hoặc Провожа́йте)."},{"t":"example","text":"Giải thích: Đồng ý cho hành động xảy ra. Nếu muốn nói \"Hãy tiễn tôi\" (kết quả) -> Проводите."},{"t":"para","text":"7. — Е́сли у вас есть свобо́дное вре́мя, ... (Câu này không phải câu hỏi xin phép, là câu điều kiện)."},{"t":"para","text":"Ý bài tập: Có lẽ là \"Можно подвинуть?\" (Tôi dịch chuyển cái này nhé?) → Подвиньте/Подвигайте."},{"t":"example","text":"Sửa theo sách: Câu 7 trong bài là \"Nếu bạn có thời gian rảnh...\". Có thể yêu cầu điền: приходи́те (hãy đến chơi)."},{"t":"para","text":"8. — Мо́жно подви́нуть ваш стол? (Tôi dịch bàn của bạn nhé?)"},{"t":"subhead","text":"Đáp án: — Подви́ньте. (Dịch đi)."},{"t":"para","text":"9. — Мо́гу я записа́ться в библиоте́ку? (Tôi có thể đăng ký thư viện không?)"},{"t":"subhead","text":"Đáp án: — Запи́сывайтесь. (Mời đăng ký)."},{"t":"para","text":"10. — Мо́жно мне оста́ться и послу́шать ле́кцию? (Tôi ở lại nghe giảng được không?)"},{"t":"subhead","text":"Đáp án: — Остава́йтесь и слу́шайте. (Cứ ở lại và nghe đi)."},{"t":"para","text":"11. — Коне́чно, ... , в аудито́рии ещё мно́го свобо́дных мест. (Tất nhiên, vào đi, trong phòng còn nhiều chỗ)."},{"t":"subhead","text":"Đáp án: проходи́те / входи́те. (Mời vào)."},{"t":"para","text":"12. — Могу́ я пригласи́ть на та́нец ва́шу дочь? (Tôi mời con gái bà nhảy được không?)"},{"t":"subhead","text":"Đáp án: — Приглаша́йте. (Mời đi)."},{"t":"para","text":"13. — ... , я не возража́ю. (... , tôi không phản đối)."},{"t":"para","text":"Giả định: Câu hỏi xin phép làm gì đó. Đáp án dùng НСВ."},{"t":"para","text":"14. — Могу́ я за́втра напо́мнить вам о мое́й про́сьбе? (Mai tôi nhắc bạn về lời thỉnh cầu được không?)"},{"t":"subhead","text":"Đáp án: — Обяза́тельно напо́мните. (Nhất định hãy nhắc nhé - Cần kết quả nhắc nhở). Hoặc Напомина́йте (Cứ nhắc đi). Напомните tự nhiên hơn khi hẹn chắc chắn."},{"t":"para","text":"15. — Я могу́ о ней забы́ть; (Tôi có thể quên nó đấy)."},{"t":"subhead","text":"Đáp án: — Не забу́дьте! (Đừng quên nhé! - Cảnh báo, dùng СВ với Не)."},{"t":"para","text":"16. — Могу́ я сам вы́брать для себя́ кни́ги? (Tôi tự chọn sách được không?)"},{"t":"subhead","text":"Đáp án: — Выбира́йте. (Cứ chọn đi)."},{"t":"para","text":"17. — Могу́ я записа́ть ваш а́дрес? (Tôi ghi địa chỉ của bạn được không?)"},{"t":"subhead","text":"Đáp án: — Запи́сывайте (Cứ ghi đi) hoặc Запиши́те (Ghi lại đi này)."},{"t":"para","text":"18. — Лесно́й проспе́кт, дом 20, кварти́ра 276. (Đại lộ Lesnoy, nhà 20...)."},{"t":"para","text":"19. — Я могу́ заплати́ть за ваш ко́фе? (Tôi trả tiền cafe cho bạn nhé?)"},{"t":"subhead","text":"Đáp án: — Заплати́те (hoặc từ chối Не на́до). Nếu đồng ý: Заплати́те."},{"t":"para","text":"20. — Е́сли вам э́то не меша́ет. (Nếu việc đó không phiền bạn)."},{"t":"para","text":"21. — Здесь о́чень ду́шно. Могу́ я откры́ть окно́? (Ở đây bí quá. Tôi mở cửa sổ nhé?)"},{"t":"subhead","text":"Đáp án: — Откро́йте (hoặc Открыва́йте). Откро́йте (Mở đi - kết quả cụ thể)."},{"t":"para","text":"22. — ... , ду́маю, э́то никому́ не помеша́ет. (..., tôi nghĩ không phiền ai đâu)."},{"t":"para","text":"23. — Мо́жно посмотре́ть ва́шего котёнка? (Xem mèo con được không?)"},{"t":"subhead","text":"Đáp án: — Посмотри́те (hoặc Смотри́те)."},{"t":"para","text":"24. — ... , то́лько не бери́те его́ на ру́ки. (..., chỉ đừng bế nó lên tay)."},{"t":"para","text":"25. — Мо́жно воспо́льзоваться ва́шим со́товым телефо́ном? (Tôi dùng di động của bạn được không?)"},{"t":"subhead","text":"Đáp án: — Воспо́льзуйтесь (hoặc По́льзуйтесь)."},{"t":"para","text":"26. — ... .","b":1},{"t":"para","text":"27. — Вы стои́те в о́череди за мной? Могу́ я отойти́ на не́сколько мину́т? (Bà đứng sau tôi à? Tôi chạy ra ngoài vài phút được không?)"},{"t":"subhead","text":"Đáp án: — Отоди́те (Đi đi - kết quả ngắn) hoặc Иди́те (Cứ đi đi)."},{"t":"para","text":"28. — ... , я не возража́ю. (..., tôi không phản đối)."},{"t":"para","text":"29. — Могу́ я включи́ть ра́дио? (Tôi bật đài nhé?)"},{"t":"subhead","text":"Đáp án: — Включи́те (Bật đi)."},{"t":"para","text":"30. — ... , я, пра́вда, не зна́ю, рабо́тает ли оно́. (..., thật ra tôi không biết nó có chạy không)."},{"t":"para","text":"31. — Мо́жно пригласи́ть к себе́ в суббо́ту мои́х друзе́й? (Con mời bạn đến nhà thứ 7 nhé?)"},{"t":"subhead","text":"Đáp án: — Пригласи́ (hoặc Приглаша́й). Приглаша́й (Cứ mời đi - cho phép)."},{"t":"para","text":"32. — ... , в суббо́ту ба́бушка уе́дет на да́чу, вы никому́ не помеша́ете. (..., thứ 7 bà đi vắng, các con không làm phiền ai đâu)."},{"t":"para","text":"33. — Могу́ я купи́ть э́ту карти́ну? (Tôi mua bức tranh này được không?)"},{"t":"subhead","text":"Đáp án: — Купи́те (hoặc Покупа́йте). Покупа́йте (Mời mua)."},{"t":"para","text":"34. — ... , на на́шей вы́ставке вы мо́жете приобрести́ любу́ю карти́ну. (..., tại triển lãm chúng tôi ngài có thể mua bất cứ bức nào)."}]},{"id":"07-s087","type":"exercise","title":"Bài 578 (Trang 300)","num":578,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng động từ ở mệnh lệnh thức để tạo thành các lời đáp/lời khuyên phù hợp với tình huống."},{"t":"para","text":"1. Вы про́сите продавца́ взве́сить вам килогра́мм я́блок.","b":1},{"t":"para","text":"Câu nói: Взве́сьте, пожа́луйства, килогра́мм я́блок."},{"t":"para","text":"Dịch: Làm ơn hãy cân cho tôi một cân táo. (Cần kết quả cân xong → СВ)."},{"t":"para","text":"2. Вам не подойти́ к конду́ктору, вы про́сите сосе́да переда́ть де́ньги на биле́т.","b":1},{"t":"para","text":"Câu nói: Переда́йте, пожа́луйства, де́ньги на биле́т."},{"t":"para","text":"Dịch: Làm ơn hãy chuyển giúp tiền vé. (Hành động cụ thể 1 lần → СВ)."},{"t":"para","text":"3. Разреши́те ва́шему знако́мому оста́ться у вас на не́сколько дней.","b":1},{"t":"para","text":"Câu nói: Остава́йся у нас на не́сколько дней."},{"t":"para","text":"Dịch: Cứ ở lại nhà tớ vài hôm đi. (Cho phép/Mời mọc → НСВ)."},{"t":"para","text":"4. Прохо́жий обраща́ется к вам с вопро́сом, на кото́рый вы не мо́жете отве́тить. Посове́туйте ему́ спроси́ть кого́-нибу́дь друго́го.","b":1},{"t":"para","text":"Câu nói: Спроси́те кого́-нибу́дь друго́го."},{"t":"para","text":"Dịch: Ông hãy hỏi người khác xem. (Lời khuyên cho hành động cụ thể → СВ)."},{"t":"para","text":"5. Ваш друг о чём-то увлечённо расска́зывает, но у вас нет вре́мени его́ слу́шать. Попроси́те его́ продо́лжить расска́з в друго́й раз.","b":1},{"t":"para","text":"Câu nói: Извини́, мне не́когда. Продо́лжи (hoặc Продолжа́й) расска́з в друго́й раз."},{"t":"example","text":"Dịch: Xin lỗi tớ bận. Hãy tiếp tục câu chuyện vào lúc khác nhé. (Thường dùng продолжай - НСВ với ý \"kể tiếp\" quá trình, hoặc продолжи - СВ với ý \"nối lại\" vào lúc khác)."},{"t":"para","text":"6. Ва́ша знако́мая уезжа́ет в Смоле́нск. Попроси́те её переда́ть письмо́ ва́шим роди́телям.","b":1},{"t":"para","text":"Câu nói: Переда́й, пожа́луйства, письмо́ мои́м роди́телям."},{"t":"para","text":"Dịch: Làm ơn hãy chuyển thư cho bố mẹ tớ. (Nhờ vả cụ thể → СВ)."},{"t":"example","text":"7. Ва́шего знако́мого, кото́рый слома́л но́гу, хотя́т подня́ть и отнести́ в ма́шину. Попроси́те де́лать э́то ме́дленно и осторо́жно. (Sách in là: Попросите не делать это медленно - Ask not to do it slowly? Có lẽ sách in nhầm, logic phải là làm cẩn thận)."},{"t":"example","text":"Theo sách (trang 300 - mục 7): \"Попросите не делать это медленно\" -> Не де́лайте э́то ме́дленно! (Đừng làm chậm! - Vô lý với người gãy chân)."},{"t":"example","text":"Sửa lại cho hợp lý: \"Yêu cầu họ làm cẩn thận\" → Де́лайте э́то ме́дленно и осторо́жно! (Hãy làm từ từ và cẩn thận thôi! - Chú trọng cách thức → НСВ). Hoặc Не торопи́тесь! (Đừng vội!)."},{"t":"para","text":"8. Вы перечисля́ете, что ну́жно сде́лать в кварти́ре ва́шим родны́м к прихо́ду госте́й.","b":1},{"t":"para","text":"Câu nói: Убери́те кварти́ру, пригото́вьте у́жин..."},{"t":"para","text":"Dịch: Hãy dọn nhà, nấu bữa tối... (Liệt kê các việc cần hoàn thành → СВ)."},{"t":"para","text":"9. Вы получи́ли письмо́, напи́санное о́чень неразбо́рчивым по́черком. Попроси́те ва́шего знако́мого в сле́дующий раз писа́ть бо́лее аккура́тно.","b":1},{"t":"para","text":"Câu nói: В сле́дующий раз пиши́ бо́лее аккура́тно."},{"t":"para","text":"Dịch: Lần sau hãy viết nắn nót hơn nhé. (Khuyên về thói quen/cách thức → НСВ)."},{"t":"para","text":"10. Идёт экза́мен. Пригласи́те студе́нта войти́ в аудито́рию, подойти́ к столу́ и взять экзаменацио́нный биле́т.","b":1},{"t":"example","text":"Câu nói: Войди́те (hoặc Входи́те), подойди́те к столу́ и возьми́те биле́т."},{"t":"example","text":"Dịch: Mời vào, hãy đến bàn và lấy vé thi. (Chuỗi hành động cụ thể → СВ, riêng войдите/входите có thể dùng НСВ để mời)."},{"t":"para","text":"11. Попроси́те студе́нта нача́ть отвеча́ть по биле́ту.","b":1},{"t":"para","text":"Câu nói: Начина́йте отвеча́ть (hoặc Отвеча́йте)."},{"t":"para","text":"Dịch: Hãy bắt đầu trả lời đi. (Bắt đầu quá trình → НСВ)."},{"t":"para","text":"12. Вы прое́хали свою́ остано́вку. Попроси́те води́теля откры́ть дверь, что́бы вы могли́ вы́йти.","b":1},{"t":"para","text":"Câu nói: Откро́йте, пожа́луйства, дверь!"},{"t":"para","text":"Dịch: Làm ơn hãy mở cửa ra! (Cần kết quả ngay → СВ)."}]},{"id":"07-s088","type":"exercise","title":"Bài 579 (Trang 301)","num":579,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng hạt từ не và động từ thể hoàn thành (СВ) hoặc chưa hoàn thành (НСВ) để tạo câu phủ định."},{"t":"subhead","text":"Quy tắc:","b":1},{"t":"vocab","ru":"Cấm đoán/Khuyên không làm (Не + НСВ)","vi":"Đừng làm việc đó (nói chung hoặc ngay bây giờ). Не говори! (Đừng nói!).","g":null},{"t":"vocab","ru":"Cảnh báo/Coi chừng (Не + СВ)","vi":"Coi chừng lỡ xảy ra kết quả xấu. Смотри, не упади! (Coi chừng ngã đấy!).","g":null},{"t":"para","text":"1. Оста́вьте ребёнка одного́ до́ма. (Hãy để đứa trẻ ở nhà một mình)."},{"t":"para","text":"Phủ định: Не оставля́йте ребёнка одного́ до́ма."},{"t":"para","text":"Dịch: Đừng để trẻ con ở nhà một mình. (Cấm đoán → НСВ)."},{"t":"para","text":"2. Задержи́сь, пожа́луйста, ненадо́лго. (Hãy ở lại một lát)."},{"t":"para","text":"Phủ định: Не заде́рживайся, пожа́луйства."},{"t":"para","text":"Dịch: Làm ơn đừng ở lại muộn/đừng nán lại. (Khuyên → НСВ)."},{"t":"para","text":"3. Проводи́ меня́ до до́ма. (Hãy tiễn em về nhà)."},{"t":"para","text":"Phủ định: Не провожа́й меня́."},{"t":"para","text":"Dịch: Đừng tiễn em. (Không cần thiết/Từ chối → НСВ)."},{"t":"para","text":"4. Останови́те маши́ну. (Hãy dừng xe)."},{"t":"para","text":"Phủ định: Не остана́вливайте маши́ну."},{"t":"para","text":"Dịch: Đừng dừng xe. (Cấm/Không cần → НСВ)."},{"t":"para","text":"5. Отвлеки́ его́ на мину́ту. (Hãy làm nó xao nhãng một phút)."},{"t":"para","text":"Phủ định: Не отвлека́й его́."},{"t":"para","text":"Dịch: Đừng làm phiền/gây xao nhãng cho nó. (НСВ)."},{"t":"para","text":"6. Послу́шай его́, он жела́ет тебе́ добра́. (Hãy nghe anh ấy, anh ấy muốn tốt cho bạn)."},{"t":"para","text":"Phủ định: Не слу́шай его́."},{"t":"para","text":"Dịch: Đừng nghe anh ta. (Lời khuyên → НСВ)."},{"t":"para","text":"7. Запрети́те ему́ занима́ться хокке́ем. (Hãy cấm nó chơi khúc côn cầu)."},{"t":"para","text":"Phủ định: Не запреща́йте ему́..."},{"t":"para","text":"Dịch: Đừng cấm nó... (НСВ)."},{"t":"para","text":"8. Вы́пей холо́дной воды́. (Hãy uống nước lạnh)."},{"t":"para","text":"Phủ định: Не пей холо́дной воды́."},{"t":"para","text":"Dịch: Đừng uống nước lạnh. (НСВ)."},{"t":"para","text":"9. Позвони́ ей за́втра. (Hãy gọi cô ấy ngày mai)."},{"t":"para","text":"Phủ định: Не звони́ ей за́втра."},{"t":"para","text":"Dịch: Đừng gọi cho cô ấy. (НСВ)."},{"t":"para","text":"10. Купи́те биле́ты зара́нее. (Hãy mua vé trước)."},{"t":"para","text":"Phủ định: Не покупа́йте биле́ты зара́нее."},{"t":"para","text":"Dịch: Đừng mua vé trước. (Không cần thiết → НСВ)."},{"t":"para","text":"11. Начни́те де́йствовать! (Hãy bắt đầu hành động!)."},{"t":"para","text":"Phủ định: Не начина́йте де́йствовать!"},{"t":"para","text":"Dịch: Đừng bắt đầu hành động! (НСВ)."},{"t":"para","text":"12. Прекрати́те отста́ивать свою́ то́чку зре́ния. (Hãy thôi bảo vệ quan điểm của mình)."},{"t":"para","text":"Phủ định: Не прекраща́йте..."},{"t":"para","text":"Dịch: Đừng ngừng... (НСВ)."},{"t":"para","text":"13. Скажи́те пра́вду. (Hãy nói sự thật)."},{"t":"para","text":"Phủ định: Не говори́те пра́вду."},{"t":"para","text":"Dịch: Đừng nói sự thật. (НСВ)."},{"t":"para","text":"14. Прости́ его́, он не винова́т. (Hãy tha thứ cho nó, nó không có lỗi)."},{"t":"para","text":"Phủ định: Не проща́й его́."},{"t":"para","text":"Dịch: Đừng tha thứ cho nó. (НСВ)."},{"t":"para","text":"15. Объясни́те ему́ э́то пра́вило ещё раз. (Hãy giải thích quy tắc này cho nó lần nữa)."},{"t":"para","text":"Phủ định: Не объясня́йте ему́..."},{"t":"para","text":"Dịch: Đừng giải thích... (НСВ)."},{"t":"para","text":"16. Соста́вьте ему́ компа́нию. (Hãy đi cùng/tiếp chuyện anh ấy)."},{"t":"para","text":"Phủ định: Не составля́йте..."},{"t":"para","text":"Dịch: Đừng đi cùng... (НСВ)."},{"t":"para","text":"17. Разреши́те ему́ уйти́. (Hãy cho phép cậu ấy đi)."},{"t":"para","text":"Phủ định: Не разреша́йте..."},{"t":"para","text":"Dịch: Đừng cho phép... (НСВ)."},{"t":"para","text":"18. Оста́вьте его́ одного́. (Hãy để anh ấy một mình)."},{"t":"para","text":"Phủ định: Не оставля́йте его́..."},{"t":"para","text":"Dịch: Đừng để anh ấy... (НСВ)."},{"t":"para","text":"19. Сде́лайте ремо́нт в кварти́ре. (Hãy sửa nhà)."},{"t":"para","text":"Phủ định: Не де́лайте ремо́нт."},{"t":"para","text":"Dịch: Đừng sửa nhà. (НСВ)."},{"t":"para","text":"20. Переда́йте письмо́ мои́м друзья́м. (Hãy chuyển thư cho bạn tôi)."},{"t":"para","text":"Phủ định: Не передава́йте..."},{"t":"para","text":"Dịch: Đừng chuyển... (НСВ)."},{"t":"para","text":"21. Подними́те, пожа́луйства, э́тот листо́к. (Làm ơn nhặt tờ giấy này lên)."},{"t":"para","text":"Phủ định: Не поднима́йте..."},{"t":"para","text":"Dịch: Đừng nhặt... (НСВ)."},{"t":"para","text":"22. Сле́дуйте мое́му приме́ру. (Hãy noi gương tôi)."},{"t":"para","text":"Phủ định: Не сле́дуйте..."},{"t":"para","text":"Dịch: Đừng làm theo gương tôi. (НСВ)."},{"t":"para","text":"23. Соста́вьте расписа́ние на за́втра. (Hãy lập thời khóa biểu cho ngày mai)."},{"t":"para","text":"Phủ định: Не составля́йте..."},{"t":"para","text":"Dịch: Đừng lập... (НСВ)."},{"t":"para","text":"24. Вы́ясните но́мер его́ телефо́на. (Hãy tìm ra số điện thoại của anh ấy)."},{"t":"para","text":"Phủ định: Не выясня́йте..."},{"t":"para","text":"Dịch: Đừng tìm hiểu/dò hỏi... (НСВ)."}]},{"id":"07-s089","type":"exercise","title":"Bài 580 (Trang 301)","num":580,"blocks":[{"t":"para","text":"Lý thuyết (Khung ngữ pháp):","b":1},{"t":"example","text":"! Глаго́лы соверше́нного ви́да в императи́ве с отрица́тельной части́цей не употребля́ются при указа́нии на возмо́жность соверше́ния де́йствия в определённый моме́нт вре́мени. Значе́ние: Не получа́й плохи́х оце́нок. — Смотри́, не получи́ плоху́ю оце́нку сего́дня на экза́мене.","b":1},{"t":"para","text":"Dịch: Động từ thể hoàn thành (СВ) ở mệnh lệnh thức đi kèm từ phủ định не được dùng khi muốn chỉ ra khả năng xảy ra hành động (ngoài ý muốn) tại một thời điểm cụ thể (Cảnh báo)."},{"t":"example","text":"Ví dụ: Не получай плохих оценок (Đừng bao giờ bị điểm kém - lời khuyên chung - НСВ)."},{"t":"example","text":"Смотри, не получи плохую оценку... (Coi chừng, đừng để bị điểm kém hôm nay nhé - cảnh báo kết quả cụ thể - СВ)."},{"t":"instruction","text":"Yêu cầu: Điền động từ mệnh lệnh thức có phủ định (не + СВ) để diễn tả sự cảnh báo."},{"t":"para","text":"1. Ваш знако́мый пе́рвый раз в жи́зни взял в ру́ки молото́к, вы бои́тесь, что он мо́жет уда́рить себя́ по па́льцам.","b":1},{"t":"para","text":"(уда́рить) → Смотри́, не уда́рь себя́ по па́льцам!"},{"t":"para","text":"Dịch: Bạn của bạn lần đầu cầm búa, bạn sợ anh ấy đập vào tay. → Coi chừng, đừng để đập vào ngón tay đấy!"},{"t":"para","text":"2. Вы опаса́етесь, что ваш ма́ленький брат мо́жет слома́ть игру́шку, кото́рую он де́ржит в рука́х.","b":1},{"t":"para","text":"(слома́ть) → Смотри́, не слома́й игру́шку!"},{"t":"para","text":"Dịch: Bạn lo em trai làm hỏng đồ chơi. → Coi chừng, đừng làm gãy/hỏng đồ chơi đấy!"},{"t":"para","text":"3. Ваш знако́мый хо́чет разбуди́ть ва́шего дру́га. Попроси́те его́ не де́лать э́того.","b":1},{"t":"para","text":"(разбуди́ть) → Не разбуди́ его́!"},{"t":"example","text":"Dịch: Bạn quen muốn đánh thức bạn của bạn. Hãy bảo người đó đừng làm thế (vì sợ làm phiền giấc ngủ - cảnh báo kết quả). → Đừng đánh thức cậu ấy! (Lưu ý: Ở đây có thể dùng Не буди (НСВ - cấm đoán), nhưng sách đang luyện СВ cảnh báo làm thức giấc lỡ làng)."},{"t":"para","text":"4. Вы бои́тесь, что ребёнок, кото́рый сего́дня оста́нется оди́н до́ма, мо́жет откры́ть дверь незнако́мым лю́дям.","b":1},{"t":"para","text":"(откры́ть) → Смотри́, не откро́й дверь незнако́мым!"},{"t":"para","text":"Dịch: Bạn sợ đứa trẻ ở nhà một mình sẽ mở cửa cho người lạ. → Coi chừng, đừng có (lỡ) mở cửa cho người lạ đấy!"},{"t":"para","text":"5. Ва́ша знако́мая чи́стит карто́шку. Вы бои́тесь, что она́ мо́жет поре́зать себе́ па́лец.","b":1},{"t":"para","text":"(поре́зать) → Осторо́жно, не поре́жь па́лец!"},{"t":"para","text":"Dịch: Cô ấy đang gọt khoai. Bạn sợ cô ấy đứt tay. → Cẩn thận, đừng để bị đứt tay!"},{"t":"para","text":"6. Ва́ша сестра́ ча́сто кладёт свои́ ве́щи на ва́шу по́лку. Попроси́те её не де́лать э́того.","b":1},{"t":"para","text":"(класть/положи́ть) → Не клади́ (НСВ) / Не положи́ (СВ)."},{"t":"note","text":"Lưu ý: Câu 6 này ngữ cảnh là \"thường xuyên làm\" (thói quen), nên đúng ra phải dùng Не клади́ (НСВ - cấm đoán thói quen). Tuy nhiên, nếu đề bài bắt buộc dùng СВ theo mẫu \"Cảnh báo\" (ví dụ lần này cô ấy đang định đặt lên), thì là Не положи́ (Coi chừng đừng đặt nhầm lên đấy). Dựa vào ngữ cảnh \"часто\" (thường xuyên), đáp án tự nhiên là НСВ. Nhưng nếu sách luyện СВ cảnh báo: Смотри, не положи (lần này)."},{"t":"para","text":"7. Ваш кот стара́ется убежа́ть в откры́тую дверь. Попроси́те ва́шу сестру́ проследи́ть за тем, что́бы э́того не произошло́.","b":1},{"t":"para","text":"(вы́пустить) → Смотри́, не вы́пусти кота́!"},{"t":"para","text":"Dịch: Con mèo định chạy ra cửa. Bảo em gái trông chừng. → Coi chừng, đừng để (nó) chạy ra/đừng thả mèo ra!"},{"t":"para","text":"8. Ва́ша знако́мая сомнева́ется, что смо́жет сдать экза́мен.","b":1},{"t":"para","text":"(провали́ть/не сдать) → Смотри́, не провали́ экза́мен! / Не завали́!"},{"t":"para","text":"Dịch: Bạn quen lo không thi đỗ. → Coi chừng, đừng để trượt đấy nhé!"},{"t":"para","text":"9. Телефо́н пло́хо рабо́тает. Попроси́те ва́шего дру́га, кото́рый набира́ет но́мер, де́лать э́то ме́дленнее. (Câu này yêu cầu làm chậm lại chứ không phải cảnh báo?)."},{"t":"example","text":"Ý định: Có lẽ là \"đừng quay sai số\"."},{"t":"example","text":"Nếu cảnh báo quay sai: Смотри́, не набери́ непра́вильный но́мер! (Coi chừng đừng quay sai số)."},{"t":"para","text":"10. Вы не хоти́те, что́бы кто-нибу́дь узна́л о ва́шем прие́зде. Предупреди́те об э́том ва́ших друзе́й.","b":1},{"t":"para","text":"(сказа́ть/проговори́ться) → Смотри́те, не скажи́те никому́! / Не проговори́тесь!"},{"t":"para","text":"Dịch: Bạn không muốn ai biết. Dặn bạn bè. → Coi chừng đừng nói/đừng lỡ miệng với ai đấy!"},{"t":"para","text":"11. Ваш знако́мый стои́т под дождём. Попроси́те его́ войти́ в дом. (Câu này là mời mọc, không phải cảnh báo?)."},{"t":"example","text":"Có lẽ: Bạn sợ anh ấy bị ốm? → Смотри́, не простуди́сь! (Coi chừng đừng để bị cảm!)."},{"t":"para","text":"12. Вы о́тдали ва́шему дру́гу библиоте́чную кни́гу, а он ча́сто теря́ет свои́ ве́щи. Предупреди́те его́, что́бы э́того не произошло́.","b":1},{"t":"para","text":"(потеря́ть) → Смотри́, не потеря́й кни́гу!"},{"t":"para","text":"Dịch: Bạn đưa sách thư viện cho bạn mình, cậu ta hay làm mất đồ. Cảnh báo cậu ta. → Coi chừng, đừng làm mất sách đấy!"}]},{"id":"07-s090","type":"exercise","title":"Bài 581 (Trang 302-303)","num":581,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các truyện cổ tích dân gian Nga \"Cháo rìu\" và \"Cáo và Sói\", sử dụng dạng đúng của động từ trong ngoặc (chọn thể động từ). Giải thích sự lựa chọn của bạn."},{"t":"note","text":"Lưu ý ngữ pháp (Gợi ý trong bài)"},{"t":"example","text":"! В ска́зках ча́сто сме́шиваются глаго́льные фо́рмы проше́дшего и настоя́щего вре́мени. В пря́мой ре́чи обы́чно употребля́ются глаго́лы настоя́щего вре́мени несоверше́нного ви́да: говори́т, хва́лит, зовёт и други́е.","b":1},{"t":"example","text":"Dịch: Trong truyện cổ tích, các dạng động từ thời quá khứ và hiện tại thường được sử dụng xen kẽ nhau (để tạo cảm giác câu chuyện đang diễn ra sống động). Trong lời dẫn trực tiếp (lời kể của tác giả dẫn vào lời nói nhân vật), thường dùng các động từ thời hiện tại thể chưa hoàn thành (НСВ): nói, khen, gọi và các từ khác."},{"t":"para","text":"a) \"Ка́ша из топора́\" (Cháo rìu)","b":1},{"t":"para","text":"1. Шёл солда́т че́рез дере́вню, зашёл в одну́ избу́, (поздоро́вался) и говори́т хозя́йке:","b":1},{"t":"para","text":"(здоро́ваться/поздоро́ваться) → поздоро́вался (СВ - Quá khứ)."},{"t":"para","text":"Dịch: Một người lính đi qua ngôi làng, ghé vào một ngôi nhà, đã chào hỏi và nói với bà chủ nhà:"},{"t":"example","text":"Giải thích: Hành động chào hỏi xảy ra một lần, nối tiếp sau hành động \"ghé vào\" (зашёл) → Dùng thể hoàn thành (СВ) để chỉ chuỗi sự kiện."},{"t":"para","text":"2. — Хозя́юшка, (дай) мне чего́-нибу́дь пое́сть!","b":1},{"t":"para","text":"(дава́ть/дать) → дай (СВ - Mệnh lệnh thức)."},{"t":"para","text":"Dịch: — Bà chủ ơi, hãy cho tôi cái gì ăn với!"},{"t":"para","text":"Giải thích: Yêu cầu thực hiện một hành động cụ thể, một lần để đạt kết quả (có đồ ăn) → Dùng СВ."},{"t":"subhead","text":"3. У хозя́йки бы́ло мно́го вся́кой еды́, но она́ (говори́т):","b":1},{"t":"para","text":"(говори́ть/сказа́ть) → говори́т (НСВ - Hiện tại)."},{"t":"para","text":"Dịch: Bà chủ nhà có nhiều đồ ăn các loại, nhưng bà ta nói:"},{"t":"example","text":"Giải thích: Theo quy tắc truyện cổ tích (lời dẫn trực tiếp), dùng говорит (hiện tại, НСВ) để dẫn thoại sinh động."},{"t":"para","text":"4. — Нет у меня́ ничего́! Сама́ ещё ничего́ не (е́ла) сего́дня!","b":1},{"t":"para","text":"(есть/пое́сть) → е́ла (НСВ - Quá khứ)."},{"t":"para","text":"Dịch: — Tôi chẳng có gì cả! Bản thân tôi hôm nay vẫn chưa ăn gì đây này!"},{"t":"example","text":"Giải thích: Phủ định sự việc đã xảy ra (nhấn mạnh vào việc chưa thực hiện hành động nào cả - общефактическое значение) → Dùng НСВ."},{"t":"para","text":"5. — А ты (свари́) ка́шу.","b":1},{"t":"para","text":"(вари́ть/свари́ть) → свари́ (СВ - Mệnh lệnh thức)."},{"t":"para","text":"Dịch: — Thế thì bà hãy nấu cháo đi."},{"t":"para","text":"Giải thích: Người lính đề nghị bà già làm ra sản phẩm (kết quả là nồi cháo) → Dùng СВ."},{"t":"para","text":"6. — Не́ из чего, ми́лый.","b":1},{"t":"para","text":"Dịch: — Chẳng có gì mà nấu, anh bạn thân mến ạ."},{"t":"para","text":"7. — Е́сли так, (дай) мне топо́р, я из топора́ ка́шу (сварю́).","b":1},{"t":"example","text":"(дава́ть/дать); (де́лать/сде́лать) hoặc (вари́ть/свари́ть - theo ngữ cảnh câu trước)"},{"t":"note","text":"Lưu ý: Sách in gợi ý động từ cho câu cuối là (делать/сделать) hoặc (варить/сварить). Trong truyện gốc là \"nấu\" (сварю), nhưng nếu sách yêu cầu \"làm\" thì dùng \"сделаю\". Ở đây ta dùng theo mạch văn là nấu cháo."},{"t":"para","text":"→ дай (СВ - Mệnh lệnh); сварю́ (СВ - Tương lai)."},{"t":"para","text":"Dịch: — Nếu thế, hãy đưa cho tôi cái rìu, tôi sẽ nấu cháo từ cái rìu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Дай","vi":"Yêu cầu hành động cụ thể 1 lần (đưa rìu đây).","g":null},{"t":"vocab","ru":"Сварю","vi":"Cam kết sẽ đạt được kết quả (nấu xong cháo) trong tương lai.","g":null},{"t":"para","text":"8. Хозя́йка (принесла́) ему́ топо́р. Солда́т (взял) топо́р, (положи́л) его́ в горшо́к, (нали́л) воды́ и (поста́вил) горшо́к на ого́нь.","b":1},{"t":"para","text":"(приноси́ть/принести́); (брать/взять); (класть/положи́ть); (налива́ть/нали́ть); (ста́вить/поста́вить)."},{"t":"vocab","ru":"→ Tất cả dùng СВ - Quá khứ","vi":"принесла́, взял, положи́л, нали́л, поста́вил.","g":null},{"t":"para","text":"Dịch: Bà chủ đã mang cho anh ta cái rìu. Người lính đã cầm lấy rìu, bỏ nó vào nồi, rót nước vào và đặt nồi lên bếp."},{"t":"para","text":"Giải thích: Đây là một chuỗi các hành động xảy ra nối tiếp nhau, hành động này xong đến hành động khác → Dùng СВ."},{"t":"subhead","text":"9. (Ва́рит) солда́т ка́шу, (поме́шивает) и (про́бует) и говори́т:","b":1},{"t":"para","text":"(Вари́ть/Свари́ть); (про́бовать/попро́бовать)."},{"t":"note","text":"Lưu ý: Câu gốc trong sách có thể là: \"(Варит/Сварит) солдат кашу, (пробует/попробует) и говорит\"."},{"t":"para","text":"→ Ва́рит (НСВ - Hiện tại); про́бует (НСВ - Hiện tại)."},{"t":"example","text":"Hoặc theo phong cách kể chuyện: Ва́рит (đang nấu - quá trình), попро́бовал (nếm thử - kết quả 1 lần)."},{"t":"subhead","text":"Đáp án sách thường chọn cho văn kể chuyện: Ва́рит (đang nấu), попро́бовал (đã nếm - hành động xen vào)."},{"t":"example","text":"Sửa lại theo văn bản phổ biến: \"Варит солдат кашу, (помешивает), потом (попробовал) и говорит\"."},{"t":"para","text":"→ Ва́рит (НСВ - quá trình), попро́бовал (СВ - hành động đơn lẻ)."},{"t":"para","text":"Dịch: Người lính đang nấu cháo, (khuấy), rồi nếm thử và nói:"},{"t":"para","text":"10. — Вку́сная ка́ша получа́ется! На́до то́лько немно́го крупы́ (доба́вить).","b":1},{"t":"para","text":"(добавля́ть/доба́вить) → доба́вить (СВ - Nguyên thể)."},{"t":"para","text":"Dịch: — Cháo thành phẩm ngon đấy! Chỉ cần thêm một ít ngũ cốc nữa thôi."},{"t":"example","text":"Giải thích: Cần thực hiện hành động để đạt kết quả (cháo ngon hơn) → Надо + СВ."},{"t":"para","text":"11. (Принесла́) ему́ хозя́йка крупы́.","b":1},{"t":"para","text":"(Приноси́ть/Принести́) → Принесла́ (СВ - Quá khứ)."},{"t":"para","text":"Dịch: Bà chủ đã mang ngũ cốc cho anh ta."},{"t":"para","text":"Giải thích: Hành động cụ thể đã hoàn thành trong mạch truyện."},{"t":"para","text":"12. (Положи́л) солда́т крупу́ и опя́ть стал (вари́ть). Пото́м (попро́бовал) и говори́т:","b":1},{"t":"para","text":"(Класть/Положи́ть); (вари́ть/свари́ть); (про́бовать/попро́бовать)."},{"t":"para","text":"→ Положи́л (СВ); вари́ть (НСВ); попро́бовал (СВ)."},{"t":"para","text":"Dịch: Người lính đã bỏ ngũ cốc vào và lại bắt đầu nấu. Sau đó anh ta nếm thử và nói:"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Положил","vi":"Hành động bỏ vào xong rồi (СВ).","g":null},{"t":"vocab","ru":"Стал варить","vi":"Sau động từ стать/начать (bắt đầu) luôn dùng động từ nguyên thể НСВ (варить).","g":null},{"t":"vocab","ru":"Попробовал","vi":"Hành động nếm diễn ra 1 lần (СВ).","g":null},{"t":"para","text":"13. — Совсе́м уже́ гото́ва ка́ша. На́до то́лько ма́сла и немно́го со́ли (доба́вить).","b":1},{"t":"para","text":"(добавля́ть/доба́вить) → доба́вить (СВ)."},{"t":"para","text":"Dịch: — Cháo chín hẳn rồi. Chỉ cần thêm tí bơ và tí muối nữa."},{"t":"para","text":"Giải thích: Cần kết quả (thêm vào) → СВ."},{"t":"para","text":"14. (Принесла́) ему́ хозя́йка ма́сла и со́ли.","b":1},{"t":"para","text":"(Приноси́ть/Принести́) → Принесла́ (СВ)."},{"t":"para","text":"Dịch: Bà chủ đã mang bơ và muối đến."},{"t":"subhead","text":"15. (Свари́л) солда́т ка́шу и (зовёт) хозя́йку:","b":1},{"t":"para","text":"(Вари́ть/Свари́ть); (звать/позва́ть)."},{"t":"para","text":"→ Свари́л (СВ - Quá khứ); зовёт (НСВ - Hiện tại)."},{"t":"para","text":"Dịch: Người lính đã nấu xong cháo và gọi bà chủ:"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Сварил","vi":"Kết quả đã hoàn tất.","g":null},{"t":"vocab","ru":"Зовёт","vi":"Lời dẫn trực tiếp dùng hiện tại НСВ.","g":null},{"t":"vocab","ru":"— Ну, хозя́йка, (дава́й) тепе́рь хлеб да (бери́) ло́жку","vi":"бу́дем ка́шу (есть)!","g":null},{"t":"para","text":"(дава́ть/дать); (брать/взять); (есть/пое́сть)."},{"t":"para","text":"→ дава́й (НСВ); бери́ (НСВ); есть (НСВ)."},{"t":"para","text":"Dịch: — Nào bà chủ, đưa bánh mì đây và cầm thìa lên: chúng ta sẽ ăn cháo!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Давай","vi":"Trong ngữ cảnh mời mọc, rủ rê suồng sã, давай (НСВ) thường được dùng như một trợ từ hoặc lời giục giã bắt đầu hành động.","g":null},{"t":"vocab","ru":"Бери","vi":"Mời ai đó bắt đầu thực hiện hành động (cầm thìa) → Mệnh lệnh thức НСВ.","g":null},{"t":"vocab","ru":"Будем есть","vi":"Tương lai của động từ НСВ (sẽ thực hiện quá trình ăn).","g":null},{"t":"para","text":"17. Ста́ли они́ ка́шу (есть).","b":1},{"t":"para","text":"(есть/пое́сть) → есть (НСВ)."},{"t":"para","text":"Dịch: Họ bắt đầu ăn cháo."},{"t":"example","text":"Giải thích: Sau стали (bắt đầu) luôn dùng НСВ."},{"t":"para","text":"18. — Никогда́ не (ду́мала), что из топора́ таку́ю вку́сную ка́шу (свари́ть) мо́жно! — (хвали́ла) ка́шу хозя́йка.","b":1},{"t":"para","text":"(ду́мать/поду́мать); (вари́ть/свари́ть); (хвали́ть/похвали́ть)."},{"t":"example","text":"→ ду́мала (НСВ); свари́ть (СВ); хвали́ла (НСВ) [hoặc хвалит]."},{"t":"para","text":"Dịch: — Tôi chưa bao giờ nghĩ rằng có thể nấu được món cháo ngon thế này từ cái rìu! — bà chủ nhà khen (đã khen/khen mãi) món cháo."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не думала","vi":"Trạng thái suy nghĩ kéo dài trong quá khứ (chưa từng nghĩ) → НСВ.","g":null},{"t":"vocab","ru":"Сварить","vi":"Kết quả (nấu thành công) → СВ.","g":null},{"t":"vocab","ru":"Хвалила","vi":"Hành động khen diễn ra như một quá trình → НСВ.","g":null},{"t":"para","text":"19. А солда́т (ест) да (посме́ивается).","b":1},{"t":"para","text":"(есть/пое́сть); (посме́иваться/посмея́ться)."},{"t":"para","text":"→ ест (НСВ - Hiện tại); посме́ивается (НСВ - Hiện tại)."},{"t":"para","text":"Dịch: Còn người lính thì vừa ăn vừa cười tủm tỉm."},{"t":"para","text":"Giải thích: Mô tả hành động đang diễn ra đồng thời (ăn và cười) → Dùng hiện tại НСВ."},{"t":"para","text":"b) \"Лиса́ и волк\" (Cáo và Sói)","b":1},{"t":"subhead","text":"1. Жи́ли-бы́ли стари́к со стару́хой. Одна́жды стари́к говори́т:","b":1},{"t":"para","text":"Dịch: Ngày xửa ngày xưa có ông lão và bà lão. Một hôm ông lão nói:"},{"t":"para","text":"2. — Ты, стару́ха, пироги́ (пеки́), а я за ры́бой пое́ду.","b":1},{"t":"para","text":"(печь/испе́чь) → пеки́ (НСВ - Mệnh lệnh thức)."},{"t":"para","text":"Dịch: — Bà nó này, bà hãy nướng bánh đi (ở nhà lo việc nướng bánh), còn tôi sẽ đi kiếm cá."},{"t":"para","text":"Giải thích: Ông lão giao nhiệm vụ cho bà lão làm một công việc (hoạt động) trong khi ông đi vắng, không nhấn mạnh \"làm xong ngay\" mà nhấn mạnh vào việc thực hiện hành động đó → Dùng НСВ."},{"t":"para","text":"3. Пое́хал стари́к на ре́ку, (налови́л) ры́бы, (положи́л) её в са́ни и пое́хал домо́й. (Е́дет) домо́й и (ви́дит): лежи́т на доро́ге лиса́ и не (шеве́лится).","b":1},{"t":"para","text":"(лови́ть/налови́ть); (класть/положи́ть); (Е́хать/Пое́хать); (ви́деть/уви́деть); (шевели́ться/пошевели́ться)."},{"t":"para","text":"→ налови́л (СВ); положи́л (СВ); Е́дет (НСВ); ви́дит (НСВ); шеве́лится (НСВ)."},{"t":"para","text":"Dịch: Ông lão đi ra sông, đã bắt được một ít cá, bỏ vào xe trượt tuyết và đi về. Ông đang đi về nhà thì thấy: một con cáo nằm trên đường và không cử động."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Наловил, положил","vi":"Các hành động đã hoàn tất (kết quả) → СВ.","g":null},{"t":"vocab","ru":"Едет, видит","vi":"Chuyển sang thì hiện tại (Historic Present) để miêu tả cảnh đang diễn ra trước mắt → НСВ.","g":null},{"t":"vocab","ru":"Не шевелится","vi":"Mô tả trạng thái (không nhúc nhích) → НСВ.","g":null},{"t":"para","text":"4. — Вот хорошо́, — поду́мал стари́к. — (Возьму́) лису́ стару́хе на воротни́к.","b":1},{"t":"para","text":"(Брать/Взять) → Возьму́ (СВ - Tương lai)."},{"t":"para","text":"Dịch: — Tốt quá, — ông lão nghĩ. — Mình sẽ lấy con cáo này làm cổ áo cho bà nó."},{"t":"para","text":"Giải thích: Quyết định thực hiện hành động (lấy) để đạt kết quả → СВ."},{"t":"para","text":"5. (Положи́л) стари́к лису́ в са́ни, а лиса́ ста́ла по доро́ге из сане́й ры́бу (выбра́сывать). Всю ры́бу (вы́бросила) и сама́ убежа́ла.","b":1},{"t":"para","text":"(Класть/Положи́ть); (выбра́сывать/вы́бросить) x2."},{"t":"para","text":"→ Положи́л (СВ); выбра́сывать (НСВ); вы́бросила (СВ)."},{"t":"para","text":"Dịch: Ông lão đã đặt con cáo lên xe trượt, nhưng con cáo đi đường bắt đầu ném cá ra khỏi xe. Nó đã ném hết toàn bộ cá và tự mình chạy mất."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Положил","vi":"Hành động 1 lần (đặt lên) → СВ.","g":null},{"t":"vocab","ru":"Стала выбрасывать","vi":"Sau стала (bắt đầu) dùng НСВ. Hành động ném diễn ra lặp lại (từng con cá một).","g":null},{"t":"vocab","ru":"Выбросила","vi":"Kết quả cuối cùng (đã ném sạch sành sanh) → СВ.","g":null},{"t":"subhead","text":"6. Прие́хал стари́к домо́й и (зовёт) жену́:","b":1},{"t":"para","text":"(звать/позва́ть) → зовёт (НСВ - Hiện tại)."},{"t":"para","text":"Dịch: Ông lão về đến nhà và gọi vợ: (Lời dẫn truyện dùng hiện tại НСВ)."},{"t":"para","text":"7. — Ну, стару́ха, (смотри́/посмотри́), како́й я тебе́ воротни́к привёз.","b":1},{"t":"para","text":"(смотре́ть/посмотре́ть) → смотри́ (НСВ) hoặc посмотри́ (СВ)."},{"t":"note","text":"Lưu ý: Trong văn nói, \"Смотри, какой...\" (Nhìn kìa, cái... nào) thường dùng НСВ để thu hút sự chú ý. Nhưng \"Посмотри\" (Hãy nhìn xem) cũng đúng. Trong truyện gốc thường là: \"Смотри, какой воротник...\" (Nhìn xem này...)."},{"t":"para","text":"→ Chọn посмотри́ (Hãy nhìn đi - hành động cụ thể) hoặc смотри (Nhìn này). Sách Glazunova thường ưu tiên СВ cho yêu cầu cụ thể: Посмотри. Tuy nhiên, đáp án truyện cổ tích thường là Смотри."},{"t":"para","text":"Dịch: — Này bà lão, nhìn xem, tôi mang về cho bà cái cổ áo loại gì này."},{"t":"para","text":"8. Подошла́ стару́ха к саня́м, а там ни лисы́, ни ры́бы нет. (По́нял) тогда́ стари́к, что лиса́ жива́я была́. Но что тепе́рь (де́лать)!","b":1},{"t":"para","text":"(Понима́ть/Поня́ть); (де́лать/сде́лать)."},{"t":"para","text":"→ По́нял (СВ - Quá khứ); де́лать (НСВ - Nguyên thể)."},{"t":"para","text":"Dịch: Bà lão đi tới xe trượt, chẳng thấy cáo, cũng chẳng thấy cá đâu. Khi đó ông lão mới vỡ lẽ/hiểu ra là con cáo còn sống. Nhưng giờ biết làm sao!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Понял","vi":"Kết quả nhận thức tức thời (hiểu ra) → СВ.","g":null},{"t":"vocab","ru":"Что делать","vi":"Câu hỏi tu từ mang tính chung chung (làm gì bây giờ - quá trình/tình thế) → НСВ.","g":null},{"t":"para","text":"9. А лиса́ в э́то вре́мя (собрала́) всю ры́бу, (се́ла) недалеко́ от реки́ и на́чала (есть). Подхо́дит к ней волк:","b":1},{"t":"para","text":"(собира́ть/собра́ть); (сади́ться/сесть); (есть/съесть)."},{"t":"para","text":"→ собрала́ (СВ); се́ла (СВ); есть (НСВ)."},{"t":"para","text":"Dịch: Còn con cáo lúc đó đã gom hết cá lại, ngồi xuống cách sông không xa và bắt đầu ăn. Sói đi đến chỗ nó:"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Собрала, села","vi":"Chuỗi hành động hoàn tất → СВ.","g":null},{"t":"vocab","ru":"Начала есть","vi":"Sau начать dùng НСВ.","g":null},{"t":"para","text":"10. — Здра́вствуй, лиса́! (Дай) мне ры́бки!","b":1},{"t":"para","text":"(Дава́ть/Дать) → Дай (СВ)."},{"t":"para","text":"Dịch: — Chào Cáo! Cho tôi ít cá với! (Xin xỏ cụ thể → СВ)."},{"t":"para","text":"11. — Не дам, — отвеча́ет лиса́. — (Налови́) сам и (ешь).","b":1},{"t":"para","text":"(Лови́ть/Налови́ть); (есть/съесть)."},{"t":"para","text":"→ Налови́ (СВ); ешь (НСВ)."},{"t":"para","text":"Dịch: — Không cho đâu, — Cáo đáp. — Tự đi mà bắt lấy (kết quả) và mà ăn (quá trình thưởng thức)."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Налови","vi":"Cần đạt kết quả có cá trước → СВ.","g":null},{"t":"vocab","ru":"Ешь","vi":"Sau đó thì cứ việc ăn (quá trình) → НСВ.","g":null},{"t":"para","text":"12. — Я не (уме́ю/суме́ю).","b":1},{"t":"para","text":"(уме́ть/суме́ть) → уме́ю (НСВ)."},{"t":"para","text":"Dịch: — Tôi không biết (bắt)."},{"t":"example","text":"Giải thích: Уметь chỉ kỹ năng/khả năng tri thức, luôn dùng НСВ trong ngữ cảnh \"biết làm gì\"."},{"t":"para","text":"13. — А ты (сядь) на берегу́, (опусти́) хвост в во́ду и (повторя́й): “Лови́сь, ры́бка, больша́я и ма́ленькая!” Тогда́ ры́ба сама́ бу́дет тебя́ за хвост (хвата́ть).","b":1},{"t":"para","text":"(сади́ться/сесть); (опуска́ть/опусти́ть); (повторя́ть/повтори́ть); (хвата́ть/схвати́ть)."},{"t":"para","text":"→ сядь (СВ); опусти́ (СВ); повторя́й (НСВ); хвата́ть (НСВ)."},{"t":"para","text":"Dịch: — Thì anh hãy ngồi xuống bờ sông, thả đuôi xuống nước và nhắc đi nhắc lại: \"Bắt lấy, cá ơi, to và nhỏ!\". Khi đó cá sẽ tự cắn vào đuôi anh."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Сядь, опусти","vi":"Các hành động cụ thể cần thực hiện xong để chuẩn bị → СВ.","g":null},{"t":"vocab","ru":"Повторяй","vi":"Hành động lặp đi lặp lại câu thần chú → НСВ.","g":null},{"t":"vocab","ru":"Будет хватать","vi":"Hành động lặp lại (cá cắn liên tục) → Tương lai НСВ.","g":null},{"t":"para","text":"14. (Сиди́т) волк на берегу́, опусти́в хвост в во́ду, а лиса́ ря́дом хо́дит и (повторя́ет):","b":1},{"t":"para","text":"(Сиде́ть/Посиде́ть); (повторя́ть/повтори́ть)."},{"t":"para","text":"→ Сиди́т (НСВ - Hiện tại); повторя́ет (НСВ - Hiện tại)."},{"t":"para","text":"Dịch: Sói ngồi trên bờ, thả đuôi xuống nước, còn Cáo đi bên cạnh và nhắc lại:"},{"t":"para","text":"Giải thích: Dùng thì hiện tại НСВ để miêu tả cảnh đang diễn ra (Historic Present)."},{"t":"para","text":"15. — (Мёрзни), (мёрзни), во́лчий хвост!","b":1},{"t":"para","text":"(Мёрзнуть/Замёрзнуть) → Мёрзни, мёрзни (НСВ)."},{"t":"para","text":"Dịch: — Đông lại, đông lại đi, đuôi sói ơi!"},{"t":"para","text":"Giải thích: Cáo đang trù ếm, mong muốn quá trình đóng băng diễn ra từ từ → Dùng НСВ."},{"t":"para","text":"16. Всю ночь (сиде́л) волк на берегу́, хвост у него́ примёрз, не мо́жет он его́ из воды́ (вы́тащить). “Вот ско́лько ры́бы налови́л, — ду́мает волк, — да́же (подня́ть) не могу́”.","b":1},{"t":"para","text":"(сиде́ть/посиде́ть); (выта́скивать/вы́тащить); (поднима́ть/подня́ть)."},{"t":"para","text":"→ сиде́л (НСВ); вы́тащить (СВ); подня́ть (СВ)."},{"t":"para","text":"Dịch: Sói đã ngồi (suốt) cả đêm trên bờ, đuôi nó bị đông cứng, nó không thể kéo đuôi ra khỏi nước được. \"Bắt được nhiều cá thế này đây, — sói nghĩ, — đến nỗi không thể nhấc nổi\"."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Сидел","vi":"Quá trình kéo dài suốt đêm → НСВ.","g":null},{"t":"vocab","ru":"Вытащить, Поднять","vi":"Nỗ lực thực hiện hành động để đạt kết quả (nhưng không được) → СВ (đi với не может để chỉ sự bất khả thi).","g":null},{"t":"subhead","text":"17. В э́то вре́мя шла ми́мо во́лка ба́ба, (уви́дела) его́ и (закрича́ла):","b":1},{"t":"para","text":"(ви́деть/уви́деть); (крича́ть/закрича́ть)."},{"t":"para","text":"→ уви́дела (СВ); закрича́ла (СВ)."},{"t":"para","text":"Dịch: Lúc đó một bà nông dân đi qua chỗ sói, đã nhìn thấy nó và hét lên:"},{"t":"para","text":"Giải thích: Chuỗi hành động xảy ra tức thời, nối tiếp nhau."},{"t":"para","text":"18. — Волк! Волк! Скоре́е сюда́!","b":1},{"t":"para","text":"Dịch: — Sói! Sói! Nhanh lại đây!"},{"t":"para","text":"19. Волк (испуга́лся), (дёрнул), (оторва́л) себе́ хвост, и (убежа́л).","b":1},{"t":"para","text":"(пуга́ться/испуга́ться); (дёргать/дёрнуть); (отрыва́ть/оторва́ть); (бежа́ть/убежа́ть)."},{"t":"para","text":"→ испуга́лся (СВ); дёрнул (СВ); оторва́л (СВ); убежа́л (СВ)."},{"t":"para","text":"Dịch: Sói hoảng sợ, giật mạnh, làm đứt đuôi mình và chạy mất."},{"t":"para","text":"Giải thích: Chuỗi hành động dứt khoát, xảy ra nhanh và kết thúc → Dùng СВ."}]},{"id":"07-s091","type":"exercise","title":"Bài 582 (Trang 304)","num":582,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Xác định ý nghĩa của các động từ chuyển động được in đậm (nghiêng). Gọi tên các động từ nguyên mẫu mà từ đó chúng được tạo thành."},{"t":"para","text":"Phần Lý thuyết và Gợi ý ngữ pháp (Trong khung)"},{"t":"para","text":"Trước khi làm bài, chúng ta cần hiểu rõ các ghi chú ngữ pháp quan trọng xuất hiện trong bài 582:"},{"t":"para","text":"Khung ngữ pháp 1 (Phần a):","b":1},{"t":"example","text":"! В разгово́рной ре́чи глаго́лы однонапра́вленного движе́ния ча́сто употребля́ются в значе́нии настоя́щего вре́мени де́йствия, относя́щегося к бу́дущему: Я е́ду домо́й = Я собира́юсь е́хать домо́й.","b":1},{"t":"example","text":"Dịch: Trong văn nói, các động từ chuyển động một chiều (nhóm Идти) thường được sử dụng với ý nghĩa thì hiện tại nhưng chỉ hành động sẽ diễn ra trong tương lai (mang ý định): Tôi đang đi về nhà = Tôi định đi về nhà / Tôi sắp đi về nhà."},{"t":"para","text":"Khung ngữ pháp 2 (Phần a):","b":1},{"t":"example","text":"! В разгово́рной ре́чи в ка́честве вариа́нта глаго́ла ла́зить (ла́жу, ла́зишь, ла́зит...) употребля́ется глаго́л ла́зать (ла́заю, ла́заешь...), кото́рый име́ет фо́рмы повели́тельного наклоне́ния.","b":1},{"t":"example","text":"Dịch: Trong văn nói, như một biến thể của động từ ла́зить (leo trèo - chia: ла́жу, ла́зишь...), người ta dùng động từ ла́зать (chia: ла́заю, ла́заешь...), động từ này có các dạng của thức mệnh lệnh."},{"t":"para","text":"Quy ước chung:","b":1},{"t":"vocab","ru":"Nhóm 1 chiều (Однонаправленные)","vi":"Chỉ hành động đang diễn ra theo một hướng cụ thể tại thời điểm nói (идти, ехать, бежать...).","g":null},{"t":"vocab","ru":"Nhóm đa chiều (Разнонаправленные)","vi":"Chỉ hành động lặp đi lặp lại, đi và về, hoặc khả năng/kỹ năng (ходить, ездить, бегать...).","g":null},{"t":"subhead","text":"Phần a) Động từ chuyển động nội động (không tác động lên đối tượng khác)","b":1},{"t":"example","text":"1. Сейча́с я иду́ в магази́н (по магази́нам). Я хожу́ в магази́н (по магази́нам) ка́ждый день;","b":1},{"t":"para","text":"Dịch: Bây giờ tôi đang đi đến cửa hàng (đi mua sắm). Tôi đi đến cửa hàng (đi mua sắm) hàng ngày."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"иду́","vi":"Hành động đang diễn ra ngay lúc nói, theo một hướng cụ thể. → Nguyên mẫu: идти́ (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"хожу́","vi":"Hành động lặp đi lặp lại \"hàng ngày\". → Nguyên mẫu: ходи́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"2. Извини́, мы торо́пимся, бежи́м в университе́т. По утра́м мы бе́гаем по алле́ям па́рка;","b":1},{"t":"para","text":"Dịch: Xin lỗi, chúng tôi đang vội, chúng tôi đang chạy đến trường đại học. Vào các buổi sáng, chúng tôi thường chạy bộ dọc theo các con đường rợp bóng cây trong công viên."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бежи́м","vi":"Đang diễn ra lúc này vì \"đang vội\". → Nguyên mẫu: бежа́ть (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"бе́гаем","vi":"Thói quen lặp lại \"vào các buổi sáng\". → Nguyên mẫu: бе́гать (Nhóm đa chiều).","g":null},{"t":"example","text":"3. Вы е́дете на конфере́нцию в конце́ ме́сяца? Я живу́ за го́родом и поэ́тому ка́ждый день е́зжу на рабо́ту на электри́чке;","b":1},{"t":"para","text":"Dịch: Bạn (sẽ) đi dự hội nghị vào cuối tháng chứ? Tôi sống ở ngoại ô và vì thế hàng ngày tôi đi làm bằng tàu điện."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"е́дете","vi":"Dùng động từ 1 chiều để chỉ kế hoạch tương lai (như khung ngữ pháp 1). → Nguyên mẫu: е́хать (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"е́зжу","vi":"Hành động lặp lại \"hàng ngày\". → Nguyên mẫu: е́здить (Nhóm đa chiều).","g":null},{"t":"example","text":"4. На сле́дующей неде́ле он лети́т в Ло́ндон. В Копенга́ген самолёты лета́ют по вто́рникам и четверга́м;","b":1},{"t":"para","text":"Dịch: Vào tuần sau anh ấy (sẽ) bay đi Luân Đôn. Máy bay bay đến Copenhagen vào các ngày thứ Ba và thứ Năm."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"лети́т","vi":"Kế hoạch tương lai cụ thể (tuần sau). → Nguyên mẫu: лете́ть (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"лета́ют","vi":"Lịch trình lặp đi lặp lại. → Nguyên mẫu: лета́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"5. Спортсме́н плывёт к фи́нишу са́мым пе́рвым. Не разреша́й ей далеко́ заплыва́ть, она́ не о́чень хорошо́ пла́вает;","b":1},{"t":"para","text":"Dịch: Vận động viên đang bơi về đích đầu tiên. Đừng cho phép cô ấy bơi ra xa quá (động từ có tiền tố), cô ấy bơi không giỏi lắm đâu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"плывёт","vi":"Đang diễn ra, hướng về đích. → Nguyên mẫu: плыть (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"пла́вает","vi":"Chỉ khả năng/kỹ năng biết bơi. → Nguyên mẫu: пла́вать (Nhóm đa chiều).","g":null},{"t":"example","text":"(Lưu ý: заплыва́ть là động từ có tiền tố, không phải cặp cơ bản, nhưng gốc là плавать)."},{"t":"example","text":"6. Он бредёт, не разбира́я доро́ги. По вечера́м я брожу́ по у́лицам го́рода;","b":1},{"t":"para","text":"Dịch: Anh ấy đang lê bước, không nhìn đường. Vào các buổi tối, tôi thường lang thang trên các con phố của thành phố."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бредёт","vi":"Đang diễn ra một cách chậm chạp, nặng nề. → Nguyên mẫu: брести́ (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"брожу́","vi":"Hành động đi dạo không mục đích lặp lại vào các buổi tối. → Nguyên mẫu: броди́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"7. Капита́н приказа́л матро́су лезть на ма́чту. Медве́ди ла́зают по дере́вьям не ху́же ко́шек;","b":1},{"t":"para","text":"Dịch: Thuyền trưởng ra lệnh cho thủy thủ leo lên cột buồm. Gấu leo trèo cây không kém gì mèo."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"лезть","vi":"Hành động cụ thể theo một hướng (lên cột). → Nguyên mẫu: лезть (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"ла́зают","vi":"Chỉ khả năng chung của loài gấu (biến thể văn nói của лазят). → Nguyên mẫu: ла́зать (Nhóm đa chiều, biến thể của лазить như đã nêu trong khung ngữ pháp).","g":null},{"t":"example","text":"8. Смотри́, по цветку́ ползёт бо́жья коро́вка. Я с де́тства не люблю́ ничего́, что по земле́ по́лзает: ни змей, ни я́щериц.","b":1},{"t":"para","text":"Dịch: Nhìn kìa, con bọ rùa đang bò trên bông hoa. Từ nhỏ tôi đã không thích bất cứ thứ gì bò trên mặt đất: cả rắn lẫn thằn lằn."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"ползёт","vi":"Đang diễn ra trước mắt (nhìn kìa). → Nguyên mẫu: ползти́ (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"по́лзает","vi":"Chỉ đặc tính di chuyển chung của loài vật. → Nguyên mẫu: по́лзать (Nhóm đa chiều).","g":null},{"t":"subhead","text":"Phần b) Động từ chuyển động ngoại động (mang vác, chở, dẫn dắt đối tượng khác)","b":1},{"t":"example","text":"1. Что э́то ты несёшь тако́е тяжёлое? Обы́чно я ношу́ с собо́й записну́ю кни́жку, но сего́дня забы́л;","b":1},{"t":"para","text":"Dịch: Bạn đang mang cái gì nặng thế kia? Thông thường tôi mang theo sổ tay bên mình, nhưng hôm nay tôi quên mất."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"несёшь","vi":"Đang thực hiện hành động mang vác ngay lúc này. → Nguyên mẫu: нести́ (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"ношу́","vi":"Thói quen (thường mang). → Nguyên mẫu: носи́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"2. Ты до́лжен вести́ маши́ну осторо́жно, доро́га о́чень ско́льзкая. По утра́м он во́дит сы́на в шко́лу;","b":1},{"t":"para","text":"Dịch: Bạn phải lái xe cẩn thận, đường rất trơn. Vào các buổi sáng, anh ấy dẫn con trai đi học."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"вести́","vi":"Lái xe trong chuyến đi cụ thể này. → Nguyên mẫu: вести́ (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"во́дит","vi":"Hành động dẫn đi lặp lại hàng sáng. → Nguyên mẫu: води́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"3. Е́сли вы везёте с собо́й каки́е-либо це́нности, необходи́мо внести́ их в тамо́женную деклара́цию. Э́тот авто́бус обы́чно во́зит дете́й на экску́рсии;","b":1},{"t":"para","text":"Dịch: Nếu các bạn đang chở/mang theo (bằng phương tiện) những đồ vật có giá trị nào đó, cần phải khai báo vào tờ khai hải quan. Chiếc xe buýt này thường chở trẻ em đi tham quan."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"везёте","vi":"Hành động đang xảy ra trong chuyến đi cụ thể. → Nguyên mẫu: везти́ (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"во́зит","vi":"Chức năng thường xuyên của xe buýt. → Nguyên mẫu: вози́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"4. Ве́тер го́нит на нас клубы́ жёлтого ды́ма. В де́тстве я мог часа́ми гоня́ть голубе́й, заставля́я их взлета́ть, и наблюда́ть за ни́ми;","b":1},{"t":"para","text":"Dịch: Gió đang lùa/thổi những đám khói vàng về phía chúng ta. Hồi nhỏ tôi có thể đuổi chim bồ câu hàng giờ, bắt chúng bay lên, và quan sát chúng."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"го́нит","vi":"Gió đang thổi theo một hướng về phía người nói. → Nguyên mẫu: гнать (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"гоня́ть","vi":"Hành động đuổi bắt chạy lung tung (đa chiều) lặp lại. → Nguyên mẫu: гоня́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"5. Веще́й у меня́ мно́го, времена́ми приходи́лось не нести́, а тащи́ть чемода́ны по по́лу. Я таска́ю во́ду в двух больши́х вёдрах;","b":1},{"t":"para","text":"Dịch: Tôi có nhiều đồ đạc, đôi khi không phải là mang, mà phải kéo lê những chiếc vali trên sàn. Tôi đang xách/tha lôi nước trong hai cái xô lớn (hành động nặng nhọc, lặp lại hoặc kéo dài)."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"тащи́ть","vi":"Kéo lê theo một hướng cụ thể trong tình huống đó. → Nguyên mẫu: тащи́ть (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"таска́ю","vi":"Ở đây dùng động từ đa chiều để chỉ công việc nặng nhọc hoặc lặp đi lặp lại. → Nguyên mẫu: таска́ть (Nhóm đa chiều).","g":null},{"t":"example","text":"6. Тяжёлое бревно́ перенести́ тру́дно, но е́сли кати́ть его́ пе́ред собо́й, с э́тим мо́жет спра́виться любо́й. По воскресе́ньям в городско́м па́рке роди́тели ката́ют дете́й на карусе́лях.","b":1},{"t":"para","text":"Dịch: Chuyển một khúc gỗ nặng thì khó, nhưng nếu lăn nó ở phía trước mình, thì ai cũng có thể làm được. Vào các ngày chủ nhật trong công viên thành phố, các bậc cha mẹ cho con cái đi chơi (lăn bánh/cưỡi) đu quay."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"кати́ть","vi":"Lăn vật thể theo một hướng cụ thể. → Nguyên mẫu: кати́ть (Nhóm 1 chiều).","g":null},{"t":"vocab","ru":"ката́ют","vi":"Cho đi chơi (xe, ngựa, đu quay) lặp lại, không hướng cụ thể. → Nguyên mẫu: ката́ть (Nhóm đa chiều).","g":null}]},{"id":"07-s092","type":"exercise","title":"Bài 583 (Trang 305)","num":583,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền động từ chuyển động cần thiết theo ý nghĩa vào chỗ trống ở dạng thì hiện tại hoặc nguyên mẫu. Giải thích sự lựa chọn của bạn."},{"t":"subhead","text":"Gợi ý ngữ pháp (Khung hình chữ nhật trang 305)"},{"t":"para","text":"! Глаго́лы однонапра́вленного движе́ния обознача́ют движе́ние в одну́ сто́рону, на определённое расстоя́ние или в определённый моме́нт вре́мени (идти́, е́хать, бежа́ть...).","b":1},{"t":"para","text":"Глаго́лы разнонапра́вленного движе́ния обознача́ют движе́ние в ра́зные сто́роны или потенциа́льную спосо́бность к движе́нию (ходи́ть, е́здить, бе́гать...).","b":1},{"t":"para","text":"Dịch:","b":1},{"t":"example","text":"Động từ chuyển động một chiều (Nhóm 1): Chỉ sự chuyển động theo một hướng, đến một khoảng cách xác định hoặc tại một thời điểm cụ thể (đang diễn ra). Ví dụ: идти́ (đang đi), е́хать (đang đi xe), бежа́ть (đang chạy)..."},{"t":"example","text":"Động từ chuyển động đa chiều (Nhóm 2): Chỉ sự chuyển động theo nhiều hướng (đi đi lại lại), sự lặp lại, hoặc khả năng/kỹ năng thực hiện chuyển động. Ví dụ: ходи́ть (đi lại/hay đi), е́здить (hay đi xe), бе́гать (chạy bộ/biết chạy)..."},{"t":"para","text":"(Sử dụng các cặp động từ được gợi ý trong ngoặc cuối mỗi nhóm câu)","b":1},{"t":"para","text":"1. Когда́ я расска́зываю о чём-то, я име́ю привы́чку ... по ко́мнате. 2. Е́сли вы не хоти́те ..., мо́жете оста́ться (идти́/ходи́ть).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"ходи́ть","b":1},{"t":"para","text":"ходи́ть","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Когда́ я расска́зываю о чём-то, я име́ю привы́чку ходи́ть по ко́мнате."},{"t":"para","text":"Е́сли вы не хоти́те ходи́ть, мо́жете оста́ться."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Khi tôi kể về một điều gì đó, tôi có thói quen đi đi lại lại trong phòng."},{"t":"para","text":"Nếu bạn không muốn đi lại (đi dạo/tham gia việc đi lại đó), bạn có thể ở lại."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Câu 1: \"Đi trong phòng\" (по комнате) là chuyển động giới hạn trong không gian, không có hướng đích cụ thể, lặp đi lặp lại → Dùng động từ đa chiều ходи́ть."},{"t":"para","text":"Câu 2: Ám chỉ hành động đi lại nói chung hoặc tham gia vào quá trình đi dạo cùng người nói (như ở câu 1) → Dùng ходи́ть."},{"t":"para","text":"3. Почему́ ты ... так бы́стро, неуже́ли нельзя́ ... поме́дленнее? Ты всё вре́мя ... (бежа́ть/бе́гать)?","b":1},{"t":"para","text":"Điền:","b":1},{"t":"example","text":"идёшь (từ ngữ cảnh đi bộ) / бежи́шь (nếu ngữ cảnh chạy). Sách gợi ý cặp бежать/бегать, nên ta dùng cặp này. Tuy nhiên, vế đầu thường người ta hỏi \"Sao đi nhanh thế\" (идёшь), nhưng nếu bắt buộc dùng бежать thì là \"Sao chạy nhanh thế\"."},{"t":"example","text":"Giả sử dùng cặp đi bộ cho 2 chỗ trống đầu và cặp chạy cho chỗ trống cuối:"},{"t":"para","text":"идёшь (đang đi) ... идти́ (đi) ... бе́гаешь (hay chạy)."},{"t":"subhead","text":"Nếu tuân thủ gợi ý sách (chỉ có бежать/бегать ở cuối):"},{"t":"para","text":"Chỗ 1: бежи́шь (đang chạy)."},{"t":"para","text":"Chỗ 2: бежа́ть (chạy - nguyên mẫu)."},{"t":"para","text":"Chỗ 3: бе́гаешь (thói quen)."},{"t":"example","text":"Tuy nhiên, ngữ cảnh tự nhiên nhất: \"Sao bạn đi (идёшь - 1 chiều) nhanh thế, không thể đi (идти - nguyên mẫu) chậm hơn à? Lúc nào bạn cũng chạy (бе́гаешь - đa chiều/thói quen) à?\""},{"t":"subhead","text":"Đáp án theo sách (Dựa trên cặp từ gợi ý cuối câu):","b":1},{"t":"example","text":"Почему́ ты бежи́шь (hoặc идёшь) так бы́стро, неуже́ли нельзя́ бежа́ть (hoặc идти́) поме́дленнее? Ты всё вре́мя бе́гаешь?"},{"t":"para","text":"Dịch: Tại sao bạn đang chạy (hoặc đi) nhanh thế, chẳng lẽ không thể chạy (hoặc đi) chậm hơn được à? Lúc nào bạn cũng chạy thế à?"},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Chỗ 1: Hành động đang diễn ra trước mắt → 1 chiều (бежи́шь)."},{"t":"example","text":"Chỗ 2: Cách thức thực hiện hành động cụ thể lúc này → 1 chiều (бежа́ть)."},{"t":"example","text":"Chỗ 3: \"Lúc nào cũng\" (всё время) chỉ thói quen/đặc điểm → Đa chiều (бе́гаешь)."},{"t":"para","text":"4. Мы ... уже́ не́сколько часо́в, а ста́нции ни ви́дно. В де́тстве он учи́л меня́ ... верхо́м, и я запо́мнил э́то на всю жизнь (е́хать/е́здить).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"е́дем","b":1},{"t":"para","text":"е́здить","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Мы е́дем уже́ не́сколько часо́в, а ста́нции ни ви́дно."},{"t":"para","text":"В де́тстве он учи́л меня́ е́здить верхо́м, и я запо́мнил э́то на всю жизнь."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Chúng tôi đang đi (xe) đã vài tiếng rồi mà vẫn chưa thấy nhà ga đâu."},{"t":"para","text":"Hồi nhỏ ông ấy dạy tôi cưỡi ngựa, và tôi nhớ điều đó suốt đời."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Câu 1: Hành động đang diễn ra liên tục theo một hành trình cụ thể → 1 chiều (е́дем)."},{"t":"example","text":"Câu 2: Học một kỹ năng (учил...) → Đa chiều (е́здить)."},{"t":"para","text":"5. Она́ реаги́ровала на мои́ вопро́сы, продолжа́я заду́мчиво ... ло́жкой в стака́не. Э́та доро́га ... на са́мую верши́ну горы́ (вести́/води́ть).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"води́ть","b":1},{"t":"para","text":"ведёт","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Она́ реаги́ровала на мои́ вопро́сы, продолжа́я заду́мчиво води́ть ло́жкой в стака́не."},{"t":"para","text":"Э́та доро́га ведёт на са́мую верши́ну горы́."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Cô ấy phản ứng với các câu hỏi của tôi, trong khi vẫn tiếp tục đăm chiêu khuấy (dẫn cái thìa vòng quanh) thìa trong cốc."},{"t":"para","text":"Con đường này dẫn lên tận đỉnh núi."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Câu 1: Hành động khuấy là chuyển động tròn/qua lại trong không gian hạn hẹp (cái cốc) → Đa chiều (води́ть)."},{"t":"para","text":"Câu 2: Con đường dẫn đi theo một hướng xác định (từ dưới lên đỉnh) → 1 chiều (ведёт)."},{"t":"para","text":"6. Голова́ у него́ кру́жится, пе́ред глаза́ми ... разноцве́тные круги́. Мы ... уже́ вторы́е су́тки, а бе́рега всё не ви́дно (плыть/пла́вать).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"example","text":"пла́вают (hoặc плыву́т - tùy cảm nhận, nhưng thường ảo giác trôi nổi lung tung là плавают)."},{"t":"para","text":"плывём","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Голова́ у него́ кру́жится, пе́ред глаза́ми пла́вают (hoặc плыву́т) разноцве́тные круги́."},{"t":"para","text":"Мы плывём уже́ вторы́е су́тки, а бе́рега всё не ви́дно."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Đầu anh ấy quay cuồng, trước mắt lởn vởn/trôi nổi những vòng tròn nhiều màu."},{"t":"para","text":"Chúng tôi đang bơi/đi tàu đã sang ngày thứ hai rồi mà vẫn chưa thấy bờ đâu."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Câu 1: Các vòng tròn chuyển động không xác định hướng (do chóng mặt) → Đa chiều (пла́вают). (Tuy nhiên, nếu miêu tả chúng trôi qua trôi lại như dòng chảy, плывут cũng chấp nhận được, nhưng плавают phổ biến hơn cho ảo giác lơ lửng)."},{"t":"para","text":"Câu 2: Hành trình cụ thể đang diễn ra → 1 chiều (плывём)."},{"t":"para","text":"7. Вре́мя бы́ло по́зднее, на́до бы́ло ... спать. В её мане́ре ... , разгова́ривать бы́ло что́-то о́чень знако́мое (идти́/ходи́ть).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"идти́","b":1},{"t":"para","text":"ходи́ть","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Вре́мя бы́ло по́зднее, на́до бы́ло идти́ спать."},{"t":"para","text":"В её мане́ре ходи́ть, разгова́ривать бы́ло что́-то о́чень знако́мое."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Đã muộn rồi, cần phải đi ngủ thôi."},{"t":"para","text":"Trong dáng vẻ đi đứng, nói năng của cô ấy có cái gì đó rất quen thuộc."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Câu 1: Cụm cố định идти спать (đi ngủ - chuyển trạng thái/hướng tới giấc ngủ) → 1 chiều (идти́)."},{"t":"para","text":"Câu 2: Chỉ phong thái, cách đi đứng nói chung (đặc điểm) → Đa chiều (ходи́ть)."},{"t":"para","text":"8. Уважа́емые пассажи́ры! Мы ... на высоте́ де́сять ты́сяч ме́тров над у́ровнем мо́ря, температу́ра за бо́ртом самолёта ми́нус 50 гра́дусов по Це́льсию. Вы не зна́ете, при тако́й о́блачности самолёты ... ? (лете́ть/лета́ть).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"лети́м","b":1},{"t":"para","text":"лета́ют","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"... Мы лети́м на высоте́ де́сять ты́сяч ме́тров..."},{"t":"para","text":"Вы не зна́ете, при тако́й о́блачности самолёты лета́ют?"},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Thưa quý khách! Chúng ta đang bay ở độ cao 10.000 mét so với mực nước biển..."},{"t":"para","text":"Bạn có biết, khi trời nhiều mây thế này máy bay có bay (hoạt động) không?"},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Câu 1: Thông báo về chuyến bay cụ thể đang diễn ra → 1 chiều (лети́м)."},{"t":"para","text":"Câu 2: Hỏi về khả năng hoạt động/quy tắc chung trong điều kiện thời tiết → Đa chiều (лета́ют)."},{"t":"para","text":"9. Чита́ет он ме́дленно, при э́том стара́тельно ... па́льцем по стро́чкам. Ты не зна́ешь, кого́ э́то ... под ру́ку Па́вел Алекса́ндрович (вести́/води́ть)?","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"во́дит","b":1},{"t":"para","text":"ведёт","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Чита́ет он ме́дленно, при э́том стара́тельно во́дит па́льцем по стро́чкам."},{"t":"para","text":"Ты не зна́ешь, кого́ э́то ведёт под ру́ку Па́вел Алекса́ндрович?"},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Cậu ấy đọc chậm, đồng thời chăm chú di ngón tay theo các dòng chữ."},{"t":"para","text":"Cậu có biết Pavel Alexandrovich đang dẫn (khoác tay) ai kia không?"},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Câu 1: Di ngón tay qua lại trên giấy (động tác lặp lại/theo bề mặt) → Đa chiều (во́дит)."},{"t":"para","text":"Câu 2: Đang dẫn ai đi theo một hướng cụ thể ngay lúc nói → 1 chiều (ведёт)."},{"t":"para","text":"10. — Что ты повсю́ду ... за мной, как привя́занный? Дай мне отдохну́ть. — Андре́й, где ты? — Сейча́с ... (идти́/ходи́ть).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"хо́дишь","b":1},{"t":"para","text":"иду́","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"— Что ты повсю́ду хо́дишь за мной, как привя́занный?"},{"t":"para","text":"— Сейча́с иду́."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"— Sao lúc nào em cũng đi theo (bám theo) anh như bị buộc dây thế? Để anh nghỉ chút nào."},{"t":"para","text":"— Andrey, anh đâu rồi? — (Anh) đến ngay đây (đang đi tới đây)."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Ходишь за мной","vi":"Đi theo khắp nơi (vô định, lặp lại, bám đuôi) → Đa chiều (хо́дишь).","g":null},{"t":"vocab","ru":"Сейчас иду","vi":"Đang thực hiện hành động đi tới chỗ người gọi ngay lập tức → 1 chiều (иду́).","g":null},{"t":"para","text":"11. Напра́сно мы туда́ ... , то́лько вре́мя потеря́ем. Я не ... на метро́ уже́ не́сколько лет, предпочита́ю назе́мный тра́нспорт (е́хать/е́здить).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"е́дем","b":1},{"t":"para","text":"е́зжу","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Напра́сно мы туда́ е́дем, то́лько вре́мя потеря́ем."},{"t":"para","text":"Я не е́зжу на метро́ уже́ не́сколько лет, предпочита́ю назе́мный тра́нспорт."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Chúng ta đang đi đến đó thật vô ích, chỉ tổ mất thời gian."},{"t":"para","text":"Tôi không đi tàu điện ngầm đã vài năm nay rồi, tôi thích phương tiện mặt đất hơn."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Hành động đang diễn ra (đang trên đường đi) → 1 chiều (е́дем)."},{"t":"para","text":"Thói quen (hoặc sự vắng mặt của thói quen) trong thời gian dài → Đa chiều (е́зжу)."},{"t":"para","text":"12. Я лёг на спи́ну и стал наблюда́ть, как по не́бу ... облака́. Она́ хорошо́ ... (плыть/пла́вать).","b":1},{"t":"para","text":"Điền:","b":1},{"t":"para","text":"плыву́т","b":1},{"t":"para","text":"пла́вает","b":1},{"t":"para","text":"Câu hoàn chỉnh:","b":1},{"t":"para","text":"Я лёг на спи́ну и стал наблюда́ть, как по не́бу плыву́т облака́."},{"t":"para","text":"Она́ хорошо́ пла́вает."},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Tôi nằm ngửa ra và bắt đầu quan sát những đám mây trôi trên bầu trời."},{"t":"para","text":"Cô ấy bơi giỏi lắm."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Mây trôi theo chiều gió (một hướng cụ thể tại thời điểm quan sát) → 1 chiều (плыву́т)."},{"t":"para","text":"Chỉ kỹ năng/khả năng biết bơi → Đa chiều (пла́вает)."}]},{"id":"07-s093","type":"exercise","title":"Bài 584 (Trang 305)","num":584,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền động từ chuyển động cần thiết theo ý nghĩa vào chỗ trống ở dạng thì hiện tại hoặc nguyên mẫu (dựa trên các cặp từ gợi ý cuối mỗi câu hoặc theo ngữ cảnh). Giải thích sự lựa chọn của bạn."},{"t":"para","text":"1. Куда́ ты так го́нишь маши́ну? Сбрось ско́рость до 80 киломе́тров. (гнать/гоня́ть)","b":1},{"t":"para","text":"Dịch: Cậu lái (phi) xe đi đâu mà nhanh thế? Giảm tốc độ xuống 80 km đi."},{"t":"example","text":"Giải thích: Hành động đang diễn ra cụ thể ngay lúc nói theo một hướng → Động từ một chiều гнать (chia ngôi ты → го́нишь)."},{"t":"para","text":"2. Небольшо́й парохо́д ... за собо́й на букси́ре ба́ржу. Заче́м ты ... с собо́й все уче́бники? (тащи́ть/таска́ть)","b":1},{"t":"para","text":"Điền: та́щит / таска́ешь"},{"t":"para","text":"Viết lại: Небольшо́й парохо́д та́щит за собо́й на букси́ре ба́ржу. Заче́м ты таска́ешь с собо́й все уче́бники?"},{"t":"para","text":"Dịch: Một chiếc tàu thủy nhỏ đang kéo một chiếc sà lan theo sau bằng dây cáp. Tại sao lúc nào cậu cũng khuân/vác theo tất cả sách giáo khoa bên mình thế?"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"та́щит","vi":"Tàu đang kéo (hành động cụ thể, 1 chiều, hiện tại).","g":null},{"t":"vocab","ru":"таска́ешь","vi":"Thói quen lặp đi lặp lại (mang vác nặng nhọc không theo hướng cụ thể) → Đa chiều таска́ть.","g":null},{"t":"para","text":"3. Пу́говица куда́-то закати́лась, и мне пришло́сь до́лго ... по по́лу, что́бы её найти́. По го́рному скло́ну ме́дленно ... глы́бы льда (ползти́/по́лзать).","b":1},{"t":"para","text":"Điền: по́лзать / ползу́т"},{"t":"para","text":"Viết lại: Пу́говица куда́-то закати́лась, и мне пришло́сь до́лго по́лзать по по́лу, что́бы её найти́. По го́рному скло́ну ме́дленно ползу́т глы́бы льда."},{"t":"para","text":"Dịch: Cái khuy áo lăn đi đâu mất, và tôi đã phải bò trên sàn rất lâu để tìm nó. Những tảng băng đang trườn (trôi) chậm chạp xuống sườn núi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"по́лзать","vi":"Bò qua bò lại tìm kiếm (đa chiều/không hướng xác định).","g":null},{"t":"vocab","ru":"ползу́т","vi":"Băng trôi theo một hướng xuống dốc (1 chiều, đang diễn ra).","g":null},{"t":"para","text":"4. Впереди́ нас ма́льчик стара́тельно ... пе́ред собо́й о́бруч. Он мно́го вре́мени прово́дил с детьми́: люби́л де́лать для них игру́шки из де́рева, ... их на са́нках (кати́ть/ката́ть).","b":1},{"t":"para","text":"Điền: ка́тит / ката́ть"},{"t":"para","text":"Viết lại: Впереди́ нас ма́льчик стара́тельно ка́тит пе́ред собо́й о́бруч. Он мно́го вре́мени прово́дил с детьми́: люби́л де́лать для них игру́шки из де́рева, ката́ть их на са́нках."},{"t":"para","text":"Dịch: Phía trước chúng tôi, một cậu bé đang chăm chú lăn cái vòng trước mặt. Ông ấy dành nhiều thời gian cho bọn trẻ: thích làm đồ chơi bằng gỗ cho chúng, kéo chúng đi chơi trên xe trượt tuyết."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"ка́тит","vi":"Đang lăn cái vòng theo hướng đi (1 chiều).","g":null},{"t":"vocab","ru":"ката́ть","vi":"Chở đi chơi/kéo đi chơi (hoạt động lặp lại, đa chiều).","g":null},{"t":"para","text":"5. Когда́ соба́ка чу́вствует себя́ винова́той, она́ ... под стол и не выхо́дит отту́да, пока́ её не позову́т. Когда́ стреля́ли на боло́те дичь, ... за ней приходи́лось соба́кам (лезть/ла́зить).","b":1},{"t":"para","text":"Điền: ле́зет / ла́зить"},{"t":"para","text":"Viết lại: Когда́ соба́ка чу́вствует себя́ винова́той, она́ ле́зет под стол и не выхо́дит отту́да, пока́ её не позову́т. Когда́ стреля́ли на боло́те дичь, ла́зить за ней приходи́лось соба́кам."},{"t":"para","text":"Dịch: Khi con chó cảm thấy có lỗi, nó chui (leo) xuống gầm bàn và không ra khỏi đó cho đến khi được gọi. Khi người ta bắn chim ở đầm lầy, lũ chó đành phải leo trèo/lội (khắp nơi) để đi lấy con mồi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"ле́зет","vi":"Hành động chui vào một chỗ cụ thể (hướng vào trong) → 1 chiều.","g":null},{"t":"vocab","ru":"ла́зить","vi":"Hành động lặp lại, vất vả trong bụi rậm/đầm lầy → Đa chiều.","g":null},{"t":"para","text":"6. Теле́га дви́жется ме́дленно, за ней ... уста́лый ста́рик. Изму́ченный до́лгой боле́знью, я с трудо́м ... по ко́мнате (брести́/броди́ть).","b":1},{"t":"para","text":"Điền: бредёт / брожу́"},{"t":"para","text":"Viết lại: Теле́га дви́жется ме́дленно, за ней бредёт уста́лый ста́рик. Изму́ченный до́лгой боле́знью, я с трудо́м брожу́ по ко́мнате."},{"t":"para","text":"Dịch: Chiếc xe ngựa di chuyển chậm chạp, một ông già mệt mỏi đang lê bước theo sau. Kiệt sức vì căn bệnh dài ngày, tôi khó nhọc đi lại (lang thang) trong phòng."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бредёт","vi":"Lê bước theo xe (1 hướng cụ thể) → 1 chiều.","g":null},{"t":"vocab","ru":"брожу́","vi":"Đi lại loanh quanh trong phòng (không hướng đích) → Đa chiều.","g":null},{"t":"para","text":"7. Ве́тер ... на́шу сто́рону, наве́рное, бу́дет дождь. На экзáмене преподава́тель лю́бит ... нас по всему́ ку́рсу (гнать/гоня́ть).","b":1},{"t":"para","text":"Điền: го́нит / гоня́ть"},{"t":"para","text":"Viết lại: Ве́тер го́нит (тучи/облака) в на́шу сто́рону, наве́рное, бу́дет дождь. На экза́мене преподава́тель лю́бит гоня́ть нас по всему́ ку́рсу."},{"t":"para","text":"Dịch: Gió đang thổi (lùa) về phía chúng ta, chắc là trời sắp mưa. Trong kỳ thi, giảng viên thích xoay/hỏi vặn chúng tôi khắp toàn bộ giáo trình."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"го́нит","vi":"Gió thổi mây theo 1 hướng → 1 chiều.","g":null},{"t":"vocab","ru":"гоня́ть","vi":"\"Xoay\" sinh viên (hỏi chỗ này chỗ kia, lặp lại) → Đa chiều.","g":null},{"t":"para","text":"8. Заче́м ты так заи́скиваешь, на коле́нях ..., ра́зве он сто́ит того́? (ползти́/по́лзать).","b":1},{"t":"para","text":"Điền: по́лзаешь","b":1},{"t":"para","text":"Viết lại: Заче́м ты так заи́скиваешь, на коле́нях по́лзаешь, ра́зве он сто́ит того́?"},{"t":"para","text":"Dịch: Tại sao cậu lại luồn cúi, bò lê bò la trên đầu gối như vậy, hắn ta đáng để làm thế sao?"},{"t":"para","text":"Giải thích: Hành động mang tính khái quát, lặp lại (chỉ thái độ sống) → Đa chiều по́лзать."},{"t":"para","text":"9. По по́лю ме́дленно ... комба́йны, среза́я коло́сья спе́лой пшени́цы (ползти́/по́лзать).","b":1},{"t":"para","text":"Điền: ползу́т","b":1},{"t":"para","text":"Viết lại: По по́лю ме́дленно ползу́т комба́йны, среза́я коло́сья спе́лой пшени́цы."},{"t":"para","text":"Dịch: Những chiếc máy gặt đập liên hợp đang trườn (bò) chậm chạp trên cánh đồng, cắt những bông lúa mì chín."},{"t":"para","text":"Giải thích: Đang diễn ra trước mắt, di chuyển chậm theo hàng lối → 1 chiều ползти́."},{"t":"para","text":"10. По вечера́м во дворе́ на́шего до́ма ребя́та ... мяч. Пасту́х ... по доро́ге ста́до коро́в (гнать/гоня́ть).","b":1},{"t":"para","text":"Điền: гоня́ют / го́нит"},{"t":"para","text":"Viết lại: По вечера́м во дворе́ на́шего до́ма ребя́та гоня́ют мяч. Пасту́х го́нит по доро́ге ста́до коро́в."},{"t":"para","text":"Dịch: Vào các buổi tối, lũ trẻ đá (lùa) bóng trong sân nhà chúng tôi. Người chăn gia súc đang lùa đàn bò đi trên đường."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"гоня́ют","vi":"Đá bóng chạy qua chạy lại (đa chiều, lặp lại).","g":null},{"t":"vocab","ru":"го́нит","vi":"Lùa bò đi theo đường (1 chiều, cụ thể).","g":null},{"t":"para","text":"11. Заче́м ты ... по я́щикам мое́го пи́сьменного стола́, е́сли тебе́ чего́-нибу́дь на́до, спроси́ у меня́. Мы до́лго наблюда́ли, как по скло́ну горы́, цепля́ясь за вы́ступы и тре́щины в ка́мне, ... альпини́сты (лезть/ла́зить).","b":1},{"t":"para","text":"Điền: ла́зишь / ле́зут"},{"t":"para","text":"Viết lại: Заче́м ты ла́зишь по я́щикам мое́го пи́сьменного стола́...? Мы до́лго наблюда́ли, как по скло́ну горы́... ле́зут альпини́сты."},{"t":"para","text":"Dịch: Sao cậu lại lục lọi các ngăn bàn viết của tớ, nếu cần gì thì hỏi tớ chứ. Chúng tôi đã quan sát rất lâu cảnh các nhà leo núi đang leo trên sườn núi, bám vào các mỏm đá và khe nứt."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"ла́зишь","vi":"Lục lọi lung tung (đa chiều).","g":null},{"t":"vocab","ru":"ле́зут","vi":"Đang leo lên (hướng lên trên, cụ thể) → 1 chiều.","g":null}]},{"id":"07-s094","type":"exercise","title":"Bài 585 (Trang 306)","num":585,"blocks":[{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung hình chữ nhật trang 306):","b":1},{"t":"example","text":"! Со слова́ми, обознача́ющими мероприя́тия (юбиле́й, ве́чер, медици́нский осмо́тр), ме́сто их проведе́ния (теа́тр, рестора́н), люде́й, кото́рые их прово́дят (друзья́, роди́тели, врач), употребля́ются глаго́лы идти́/ходи́ть, е́сли речь идёт о продолжи́тельности вре́мени посеще́ния (пешко́м и́ли на тра́нспорте) в преде́лах одного́ го́рода. Сравни́те: За́втра мы идём в теа́тр (смотре́ть спекта́кль). — Снача́ла мы е́дем к Андре́ю, а пото́м — на вокза́л.","b":1},{"t":"example","text":"Dịch: Với các từ chỉ sự kiện (lễ kỷ niệm, buổi dạ hội, khám bệnh), nơi tổ chức (nhà hát, nhà hàng), người tổ chức/tiếp đón (bạn bè, bố mẹ, bác sĩ), ta dùng động từ идти́/ходи́ть (đi bộ), ngay cả khi đi bằng phương tiện, nếu nói về việc tham dự sự kiện đó trong phạm vi cùng một thành phố."},{"t":"example","text":"So sánh: Ngày mai chúng tôi đi (идём) nhà hát (để xem kịch - mục đích tham dự). — Đầu tiên chúng tôi đi (lái xe/ngồi xe) (едем) đến nhà Andrey, rồi sau đó ra nhà ga (nhấn mạnh việc di chuyển bằng phương tiện)."},{"t":"instruction","text":"Yêu cầu: Điền động từ идти/ходить hoặc ехать/ездить (thì hiện tại hoặc nguyên mẫu)."},{"t":"para","text":"1. За́втра мы ... в теа́тр.","b":1},{"t":"para","text":"Điền: идём","b":1},{"t":"example","text":"Dịch: Ngày mai chúng tôi đi nhà hát. (Sự kiện trong thành phố → идти)."},{"t":"para","text":"2. На сле́дующей неде́ле мы ... за́ город.","b":1},{"t":"para","text":"Điền: е́дем","b":1},{"t":"example","text":"Dịch: Tuần sau chúng tôi đi ngoại ô. (Ra khỏi thành phố, quãng đường xa → ехать)."},{"t":"para","text":"3. В воскресе́нье днём я не смогу́ соста́вить тебе́ компа́нию, так как ... на вы́ставку.","b":1},{"t":"para","text":"Điền: иду́","b":1},{"t":"example","text":"Dịch: Chiều chủ nhật tớ không đi cùng cậu được, vì tớ đi xem triển lãm. (Sự kiện → идти)."},{"t":"para","text":"4. Че́рез неде́лю я ... в Новосиби́рск.","b":1},{"t":"para","text":"Điền: е́ду","b":1},{"t":"example","text":"Dịch: Một tuần nữa tôi đi Novosibirsk. (Đi thành phố khác → ехать)."},{"t":"para","text":"5. Обы́чно мы ... в институ́т на метро́.","b":1},{"t":"example","text":"Điền: е́здим (hoặc е́дем nếu nói 1 lần, nhưng \"thường\" là ездим)."},{"t":"example","text":"Dịch: Thường thì chúng tôi đi đến trường bằng tàu điện ngầm. (Có phương tiện rõ ràng \"bằng metro\" và lặp lại → ездить)."},{"t":"para","text":"6. Собира́йся скоре́е, мы ... в Исаа́киевский собо́р.","b":1},{"t":"para","text":"Điền: идём","b":1},{"t":"example","text":"Dịch: Chuẩn bị nhanh lên, chúng ta đi nhà thờ thánh Isaac. (Đi tham quan trong phố → идти)."},{"t":"para","text":"7. В конце́ февраля́ он ... на конфере́нцию в Ки́ев.","b":1},{"t":"para","text":"Điền: е́дет","b":1},{"t":"example","text":"Dịch: Cuối tháng Hai anh ấy đi hội nghị ở Kiev. (Đi thành phố khác → ехать)."},{"t":"para","text":"8. Сего́дня мне не хо́чется ничего́ гото́вить, мы ... обе́дать в кафе́.","b":1},{"t":"para","text":"Điền: идём","b":1},{"t":"example","text":"Dịch: Hôm nay em không muốn nấu nướng gì cả, chúng ta đi ăn ở quán cà phê nhé. (Sự kiện ăn uống → идти)."},{"t":"para","text":"9. В суббо́ту мы с отцо́м ... на стадио́н смотре́ть футбо́льный матч.","b":1},{"t":"para","text":"Điền: идём","b":1},{"t":"example","text":"Dịch: Thứ bảy tôi và bố đi sân vận động xem bóng đá. (Sự kiện → идти)."},{"t":"para","text":"10. Ве́чером я ... в филармо́нию.","b":1},{"t":"para","text":"Điền: иду́","b":1},{"t":"example","text":"Dịch: Buổi tối tôi đi nhà hát giao hưởng. (Sự kiện → идти)."},{"t":"para","text":"11. Ка́ждый год мы ... на юг.","b":1},{"t":"para","text":"Điền: е́здим","b":1},{"t":"example","text":"Dịch: Năm nào chúng tôi cũng đi về phương Nam (nghỉ mát). (Lặp lại, đường xa → ездить)."},{"t":"para","text":"12. Нет, за́втра я не ... на заня́тия, пло́хо себя́ чу́вствую.","b":1},{"t":"example","text":"Điền: иду́ (hoặc пойду́)."},{"t":"example","text":"Dịch: Không, ngày mai tớ không đi học đâu, tớ thấy mệt. (Tham dự lớp học → идти)."},{"t":"para","text":"13. Вы ... в Москву́, захвати́те, пожа́луйста, письмо́ для мои́х роди́телей.","b":1},{"t":"para","text":"Điền: е́дете","b":1},{"t":"example","text":"Dịch: Các bạn đi Moscow phải không, làm ơn cầm giúp lá thư cho bố mẹ tôi. (Đi thành phố khác → ехать)."},{"t":"para","text":"14. Я о́чень ре́дко ... в го́сти.","b":1},{"t":"para","text":"Điền: хожу́","b":1},{"t":"example","text":"Dịch: Tôi rất hiếm khi đi làm khách. (Thói quen, sự kiện xã giao → ходить)."},{"t":"para","text":"15. По понеде́льникам по́сле рабо́ты я ... в бассе́йн.","b":1},{"t":"para","text":"Điền: хожу́","b":1},{"t":"example","text":"Dịch: Vào các ngày thứ Hai sau giờ làm tôi đi bơi (đến bể bơi). (Thói quen trong phố → ходить)."},{"t":"para","text":"16. В э́том году́ мы ... отдыха́ть в Болга́рию.","b":1},{"t":"para","text":"Điền: е́дем","b":1},{"t":"example","text":"Dịch: Năm nay chúng tôi đi nghỉ ở Bulgaria. (Đi nước ngoài → ехать)."},{"t":"para","text":"17. Боль не прохо́дит, ты до́лжен ... к врачу́.","b":1},{"t":"para","text":"Điền: идти́","b":1},{"t":"example","text":"Dịch: Đau không dứt, cậu phải đi bác sĩ thôi. (Đi khám bệnh → идти)."},{"t":"para","text":"18. Я люблю́ ... на да́чу.","b":1},{"t":"para","text":"Điền: е́здить","b":1},{"t":"example","text":"Dịch: Tôi thích đi ra nhà dã ngoại (nhà vườn). (Thói quen, đi xa/ngoại ô → ездить)."},{"t":"para","text":"19. Ты ... на вы́боры в воскресе́нье?","b":1},{"t":"para","text":"Điền: идёшь","b":1},{"t":"example","text":"Dịch: Chủ nhật cậu có đi bầu cử không? (Sự kiện → идти)."},{"t":"para","text":"20. Ка́ждое ле́то мы ... в дере́вню к ба́бушке.","b":1},{"t":"para","text":"Điền: е́здим","b":1},{"t":"example","text":"Dịch: Mùa hè nào chúng tôi cũng đi về quê thăm bà. (Lặp lại, đi xa → ездить)."},{"t":"para","text":"21. Я бы с удово́льствием отдохну́л под Москво́й на да́че, но врачи́ рекомендова́ли мне ... на юг.","b":1},{"t":"para","text":"Điền: е́хать","b":1},{"t":"example","text":"Dịch: Tôi rất muốn nghỉ ngơi ở ngoại ô Moscow, nhưng các bác sĩ khuyên tôi đi xuống phương Nam. (Đi xa → ехать)."},{"t":"para","text":"22. — Ты ... на день рожде́ния к Алексе́ю? — Коне́чно, ... .","b":1},{"t":"para","text":"Điền: идёшь ... иду́"},{"t":"example","text":"Dịch: — Cậu có đi sinh nhật Alexey không? — Tất nhiên là đi rồi. (Sự kiện → идти)."},{"t":"para","text":"23. За́втра ребёнок ... в шко́лу. Ты мо́жешь отвезти́ его́ туда́ у́тром?","b":1},{"t":"para","text":"Điền: идёт","b":1},{"t":"example","text":"Dịch: Ngày mai đứa bé đi học (bắt đầu đi học/đến trường). Anh có thể chở con đến đó buổi sáng không? (Tham dự việc học → идти)."},{"t":"para","text":"24. Мы ... в аэропо́рт к 10 часа́м.","b":1},{"t":"para","text":"Điền: е́дем","b":1},{"t":"example","text":"Dịch: Chúng tôi đi ra sân bay lúc 10 giờ. (Di chuyển bằng xe ra sân bay → ехать)."},{"t":"para","text":"25. С утра́ я ... в железнодоро́жные ка́ссы, а пото́м — на вокза́л.","b":1},{"t":"example","text":"Điền: е́ду (hoặc иду́ tùy khoảng cách, nhưng thường đi mua vé và ra ga là việc di chuyển cụ thể)."},{"t":"subhead","text":"Đáp án ưu tiên: е́ду","b":1},{"t":"para","text":"Dịch: Sáng ra tôi đi (xe) đến phòng vé tàu hỏa, rồi sau đó ra nhà ga."}]},{"id":"07-s095","type":"exercise","title":"Bài 586 (Trang 307)","num":586,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc, sử dụng động từ chuyển động cần thiết theo ý nghĩa ở thì hiện tại hoặc nguyên mẫu. Giải thích sự lựa chọn của bạn."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trong khung trang 307)"},{"t":"vocab","ru":"! С показа́телями вре́мени, отвеча́ющими на вопро́сы","vi":"ско́лько (раз)?, как ча́сто?, употребля́ются глаго́лы разнонапра́вленного движе́ния (значе́ние обы́чности, повторя́емости де́йствия).","g":null},{"t":"example","text":"! С показа́телями вре́мени, е́сли предика́т выража́ет друго́е де́йствие: Ка́ждое у́тро я е́ду на рабо́ту и по доро́ге покупа́ю газе́ту (де́йствие в разви́тии).","b":1},{"t":"para","text":"Dịch và giải thích:","b":1},{"t":"example","text":"Với các từ chỉ thời gian trả lời cho câu hỏi: bao nhiêu (lần)?, thường xuyên thế nào? (ví dụ: mỗi ngày, thường xuyên, hiếm khi...), ta dùng Động từ chuyển động đa chiều (nhóm ходи́ть, е́здить...)."},{"t":"example","text":"Ý nghĩa: Chỉ thói quen, sự lặp đi lặp lại của hành động."},{"t":"example","text":"Tuy nhiên, với các từ chỉ thời gian lặp lại (mỗi sáng, thường thì...), nếu vị ngữ diễn tả một chuỗi hành động nối tiếp hoặc mô tả quá trình đang diễn ra, ta có thể dùng Động từ chuyển động một chiều (nhóm идти́, е́хать...)."},{"t":"example","text":"Ví dụ: Mỗi sáng tôi đang đi (е́ду - 1 chiều) đến chỗ làm thì trên đường tôi mua báo. (Nhấn mạnh vào quá trình di chuyển cụ thể trong lộ trình đó)."},{"t":"para","text":"1. На сле́дующей неде́ле я (лечу́) во Владивосто́к на па́ру дней;","b":1},{"t":"para","text":"(лете́ть/лета́ть) → лечу́"},{"t":"para","text":"Dịch: Tuần sau tôi sẽ bay đến Vladivostok vài ngày."},{"t":"example","text":"Giải thích: Hành động đã được lên kế hoạch cụ thể trong tương lai gần. Trong tiếng Nga, động từ chuyển động 1 chiều (лете́ть) ở thì hiện tại thường dùng để chỉ tương lai (sắp bay/sẽ bay)."},{"t":"para","text":"2. Вы напра́сно беспоко́итесь, я всегда́ (е́зжу) всего́ неде́лю;","b":1},{"t":"para","text":"(е́хать/е́здить) → е́зжу"},{"t":"para","text":"Dịch: Bạn lo lắng vô ích thôi, tôi luôn đi (công tác/du lịch) trọn vẹn một tuần."},{"t":"example","text":"Giải thích: Từ \"luôn luôn\" (всегда) chỉ sự lặp lại, thói quen → Dùng động từ đa chiều (е́здить)."},{"t":"para","text":"3. Ты (пла́ваешь) на су́дне ка́ждый год в тече́ние не́скольких ме́сяцев;","b":1},{"t":"para","text":"(плыть/пла́вать) → пла́ваешь"},{"t":"para","text":"Dịch: Bạn đi tàu (đi biển) hàng năm trong vòng vài tháng."},{"t":"example","text":"Giải thích: Từ \"hàng năm\" (ка́ждый год) chỉ sự lặp lại → Dùng động từ đa chiều (пла́вать)."},{"t":"para","text":"4. Не грусти́, ты (е́дешь) в командиро́вку всего́ на не́сколько дней;","b":1},{"t":"para","text":"(е́хать/е́здить) → е́дешь"},{"t":"para","text":"Dịch: Đừng buồn, bạn sắp đi công tác chỉ vài ngày thôi mà."},{"t":"example","text":"Giải thích: Ám chỉ chuyến đi cụ thể sắp xảy ra trong tương lai gần (kế hoạch) → Dùng động từ 1 chiều (е́хать)."},{"t":"para","text":"5. Я (хожу́) в магази́н на хозя́йственный двор раз в день;","b":1},{"t":"para","text":"(идти́/ходи́ть) → хожу́"},{"t":"para","text":"Dịch: Tôi đi đến sân hậu cần của cửa hàng mỗi ngày một lần."},{"t":"example","text":"Giải thích: Từ \"mỗi ngày một lần\" (раз в день) chỉ tần suất lặp lại → Dùng động từ đa chiều (ходи́ть)."},{"t":"para","text":"6. Обы́чно с утра́ я (иду́) в магази́н, покупа́ю проду́кты, зате́м пью ко́фе в небольшо́м кафе́ недалеко́ от до́ма;","b":1},{"t":"para","text":"(идти́/ходи́ть) → иду́"},{"t":"para","text":"Dịch: Thường thì vào buổi sáng tôi đi đến cửa hàng, mua thực phẩm, sau đó uống cà phê ở một quán nhỏ gần nhà."},{"t":"example","text":"Giải thích: Mặc dù có \"thường thì\" (обы́чно), nhưng câu này liệt kê một chuỗi hành động theo trình tự (đi → mua → uống). Người nói hình dung lại quá trình di chuyển đang diễn ra trong lộ trình đó → Dùng động từ 1 chiều (идти́)."},{"t":"para","text":"7. Я (е́зжу) в командиро́вки два-три ра́за в год, не бо́льше;","b":1},{"t":"para","text":"(е́хать/е́здить) → е́зжу"},{"t":"para","text":"Dịch: Tôi đi công tác hai-ba lần một năm, không nhiều hơn."},{"t":"example","text":"Giải thích: Chỉ tần suất lặp lại (2-3 lần/năm) → Dùng động từ đa chiều (е́здить)."},{"t":"para","text":"8. Не волну́йся, я (лечу́) всего́ на па́ру дней;","b":1},{"t":"para","text":"(лете́ть/лета́ть) → лечу́"},{"t":"para","text":"Dịch: Đừng lo, tôi sẽ bay (sắp bay) chỉ vài ngày thôi."},{"t":"example","text":"Giải thích: Hành động cụ thể sắp diễn ra (tương lai gần) → Dùng động từ 1 chiều (лете́ть)."},{"t":"para","text":"9. Я ча́сто (е́зжу) в Но́вгород;","b":1},{"t":"para","text":"(е́хать/е́здить) → е́зжу"},{"t":"para","text":"Dịch: Tôi thường xuyên đi Novgorod."},{"t":"example","text":"Giải thích: Từ \"thường xuyên\" (ча́сто) chỉ thói quen lặp lại → Dùng động từ đa chiều (е́здить)."},{"t":"para","text":"10. Ка́ждое у́тро я (веду́) сы́на в шко́лу и по доро́ге домо́й захожу́ на ры́нок за проду́ктами;","b":1},{"t":"para","text":"(вести́/води́ть) → веду́"},{"t":"para","text":"Dịch: Sáng nào tôi cũng dẫn con trai đến trường và trên đường về nhà thì ghé vào chợ mua thực phẩm."},{"t":"example","text":"Giải thích: Tương tự câu 6, đây là mô tả một chuỗi hành động trong lộ trình buổi sáng (đang dẫn đi → rồi ghé qua...). Dùng động từ 1 chiều (вести́) để nhấn mạnh quá trình thực hiện hành động đó mỗi sáng."},{"t":"para","text":"11. Ты (е́здишь) на метро́ ка́ждый день, до́лжен бы уже́ привы́кнуть к эскала́торам;","b":1},{"t":"para","text":"(е́хать/е́здить) → е́здишь"},{"t":"para","text":"Dịch: Bạn đi tàu điện ngầm hàng ngày, lẽ ra phải quen với thang cuốn rồi chứ."},{"t":"example","text":"Giải thích: Chỉ thói quen, sự việc lặp lại hàng ngày (ка́ждый день) → Dùng động từ đa chiều (е́здить)."},{"t":"para","text":"12. По свое́й во́ле я никогда́ (не лета́ю) на самолёте;","b":1},{"t":"para","text":"(лете́ть/лета́ть) → (не) лета́ю"},{"t":"para","text":"Dịch: Nếu theo ý mình thì tôi không bao giờ đi (bay) máy bay."},{"t":"example","text":"Giải thích: Từ \"không bao giờ\" (никогда́) chỉ sự phủ định một thói quen/sở thích chung → Dùng động từ đa chiều (лета́ть)."},{"t":"para","text":"13. Я (хожу́) игра́ть в те́ннис два ра́за в неде́лю;","b":1},{"t":"para","text":"(идти́/ходи́ть) → хожу́"},{"t":"para","text":"Dịch: Tôi đi chơi quần vợt hai lần một tuần."},{"t":"example","text":"Giải thích: Chỉ tần suất (2 lần/tuần) → Dùng động từ đa chiều (ходи́ть)."},{"t":"para","text":"14. Ка́ждое ле́то мы (е́здим) на юг;","b":1},{"t":"para","text":"(е́хать/е́здить) → е́здим"},{"t":"para","text":"Dịch: Mùa hè nào chúng tôi cũng đi về phương Nam (nghỉ mát)."},{"t":"example","text":"Giải thích: Sự kiện lặp lại định kỳ (mỗi mùa hè) → Dùng động từ đa chiều (е́здить)."},{"t":"para","text":"15. Я (лечу́) на па́ру дней, меня́ не бу́дет до четверга́;","b":1},{"t":"para","text":"(лете́ть/лета́ть) → лечу́"},{"t":"para","text":"Dịch: Tôi sắp bay (đi vắng) vài ngày, tôi sẽ không có mặt cho đến thứ Năm."},{"t":"example","text":"Giải thích: Thông báo về kế hoạch cụ thể sắp tới → Dùng động từ 1 chiều (лете́ть)."},{"t":"para","text":"16. Моя́ ма́ма в после́днее вре́мя не о́чень хорошо́ себя́ чу́вствует, и обы́чно по́сле рабо́ты я (е́зжу) по магази́нам, покупа́ю проду́кты и (вожу́) их к ней домо́й;","b":1},{"t":"para","text":"(е́хать/е́здить); (везти́/вози́ть) → е́зжу; вожу́"},{"t":"para","text":"Dịch: Dạo này mẹ tôi cảm thấy không được khỏe lắm, và thường thì sau giờ làm tôi đi lòng vòng các cửa hàng, mua thực phẩm và chở đến nhà bà."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Е́зжу","vi":"Cụm từ \"по магазинам\" (đi các cửa hàng) hàm ý đi nhiều nơi, đi qua đi lại → Dùng đa chiều.","g":null},{"t":"vocab","ru":"Вожу́","vi":"Hành động chở đồ lặp lại thường xuyên (обы́чно) như một nhiệm vụ → Dùng đa chiều (вози́ть).","g":null},{"t":"note","text":"Lưu ý: Nếu muốn nhấn mạnh trình tự như câu 6, có thể dùng везу (chở), nhưng ở đây sắc thái \"thói quen/nhiệm vụ chăm sóc\" (đi chợ rồi chở đồ) dùng đa chiều nghe tự nhiên hơn cho việc vận chuyển lặp lại."},{"t":"para","text":"17. Два ра́за в день я (хожу́) к отцу́ на рабо́ту, (ношу́) ему́ еду́.","b":1},{"t":"para","text":"(идти́/ходи́ть); (нести́/носи́ть) → хожу́; ношу́"},{"t":"para","text":"Dịch: Hai lần một ngày tôi đi đến chỗ làm của bố, mang đồ ăn cho ông."},{"t":"example","text":"Giải thích: Tần suất rõ ràng (2 lần/ngày) → Dùng cặp động từ đa chiều (ходи́ть/носи́ть)."}]},{"id":"07-s096","type":"exercise","title":"Bài 587 (Trang 308)","num":587,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền vào chỗ trống động từ chuyển động cần thiết theo ý nghĩa ở dạng phù hợp."},{"t":"subhead","text":"Gợi ý ngữ pháp (Lý thuyết cần nhớ):","b":1},{"t":"example","text":"Đi bộ/Xe cộ: Идти́ (đi bộ/di chuyển nói chung của phương tiện theo lịch trình), Е́хать (đi bằng phương tiện)."},{"t":"example","text":"Dắt/Lái: Вести́/Води́ть (dắt ai đó, lái xe), Везти́/Вози́ть (chở ai/cái gì bằng xe), Нести́/Носи́ть (mang vác trên tay)."},{"t":"para","text":"Hiện tượng tự nhiên/Thành ngữ:","b":1},{"t":"para","text":"Mưa, tuyết, thời gian, phim ảnh, tàu xe (theo lịch) dùng: идти́."},{"t":"para","text":"Mây, khói, thuyền bè dùng: плыть."},{"t":"para","text":"Chim, máy bay dùng: лете́ть."},{"t":"para","text":"Giải chi tiết từng câu:","b":1},{"t":"para","text":"1. В на́шем го́роде мно́гие хозя́йки во́дят на поводке́ не то́лько соба́к, но и ко́шек.","b":1},{"t":"para","text":"Dịch: Ở thành phố của chúng tôi, nhiều bà chủ dắt không chỉ chó mà cả mèo đi dạo bằng dây xích."},{"t":"example","text":"Giải thích: Hành động \"dắt\" thú cưng đi dạo (lặp đi lặp lại, thói quen chung của nhiều người) → Dùng động từ đa chiều води́ть (chia ở số nhiều: во́дят)."},{"t":"para","text":"2. Я уви́дел, как спра́ва по бо́рту на наш кора́бль надвига́ется (или идёт) огро́мная волна́.","b":1},{"t":"para","text":"Dịch: Tôi nhìn thấy một con sóng khổng lồ đang tràn tới/lao tới tàu của chúng tôi từ phía mạn phải."},{"t":"example","text":"Giải thích: Với sóng nước (волна), người Nga hay dùng идёт (đang đi tới) hoặc надвига́ется (đang ập tới). Trong ngữ cảnh động từ chuyển động cơ bản, идёт là đáp án chấp nhận được, nhưng để miêu tả sự đe dọa của sóng lớn, надвига́ется (tiến lại gần) thường dùng hơn. Nếu bắt buộc dùng nhóm chuyển động gốc: идёт."},{"t":"para","text":"3. Где ты был? Я уже́ час хожу́ под твое́й две́рью.","b":1},{"t":"para","text":"Dịch: Cậu đã ở đâu thế? Tớ đi đi lại lại trước cửa nhà cậu cả tiếng đồng hồ rồi."},{"t":"example","text":"Giải thích: Hành động đi qua đi lại trong lúc chờ đợi (không có hướng cố định) → Dùng động từ đa chiều ходи́ть (chia: хожу́)."},{"t":"para","text":"4. Ры́ба пла́вает по дну водоёма, её пойма́ть не так про́сто.","b":1},{"t":"para","text":"Dịch: Cá bơi dưới đáy hồ, bắt nó không đơn giản đâu."},{"t":"example","text":"Giải thích: Cá bơi lội nói chung (hoạt động tự nhiên, không nhấn mạnh đang bơi về đâu) → Dùng động từ đa chiều пла́вать (chia: пла́вает)."},{"t":"para","text":"5. Что с ним случи́лось? — Не зна́ю, с утра́ хо́дит злой, ни с кем не разгова́ривает.","b":1},{"t":"para","text":"Dịch: Có chuyện gì với cậu ấy thế? — Không biết, từ sáng đến giờ cứ đi lại bực bội, chẳng nói chuyện với ai."},{"t":"example","text":"Giải thích: Mô tả trạng thái/hành động lặp lại trong một khoảng thời gian (từ sáng) → Dùng động từ đa chiều ходи́ть (chia: хо́дит)."},{"t":"para","text":"6. Куда́ ты нас ведёшь? Круго́м совсе́м незнако́мые места́.","b":1},{"t":"para","text":"Dịch: Cậu đang dẫn bọn tớ đi đâu thế? Xung quanh toàn những chỗ lạ hoắc."},{"t":"example","text":"Giải thích: Hành động dẫn đường đang diễn ra theo một hướng cụ thể (vào chỗ lạ) → Dùng động từ một chiều вести́ (chia: ведёшь)."},{"t":"para","text":"7. Уже́ по́здно, тебе́ на́до идти́ (или бежа́ть) домо́й.","b":1},{"t":"para","text":"Dịch: Muộn rồi, cậu cần phải đi (hoặc chạy) về nhà thôi."},{"t":"para","text":"Giải thích: Cần thực hiện hành động di chuyển về đích (nhà) → Dùng động từ một chiều nguyên mẫu идти́ (đi ngay) hoặc бежа́ть (chạy ngay cho kịp)."},{"t":"para","text":"8. Она́ прекра́сно во́дит маши́ну, но мотоци́кл я бы ей не дове́рил.","b":1},{"t":"para","text":"Dịch: Cô ấy lái ô tô rất giỏi, nhưng xe máy thì tôi sẽ không giao cho cô ấy đâu."},{"t":"example","text":"Giải thích: Chỉ kỹ năng lái xe (biết lái, lái thường xuyên) → Dùng động từ đa chiều води́ть (chia: во́дит)."},{"t":"para","text":"9. Он о́чень бы́стро научи́лся е́здить (или ката́ться) на велосипе́де.","b":1},{"t":"para","text":"Dịch: Cậu bé đã học đi (cưỡi) xe đạp rất nhanh."},{"t":"example","text":"Giải thích: Học một kỹ năng → Dùng động từ đa chiều е́здить (đi xe nói chung) hoặc ката́ться (đi chơi/lái xe đạp). Е́здить trang trọng hơn, ката́ться thông dụng cho xe đạp."},{"t":"para","text":"10. По о́зеру плыву́т жёлтые ли́стья.","b":1},{"t":"para","text":"Dịch: Những chiếc lá vàng đang trôi trên mặt hồ."},{"t":"example","text":"Giải thích: Lá trôi theo dòng nước (thụ động) hoặc đang diễn ra trước mắt → Dùng động từ một chiều плыть (chia: плыву́т)."},{"t":"para","text":"11. Поторопи́сь, идёт твой авто́бус.","b":1},{"t":"para","text":"Dịch: Nhanh lên, xe buýt của cậu đang tới (hoặc đang chạy) kìa."},{"t":"example","text":"Giải thích: Xe buýt di chuyển theo tuyến/đang đến → Dùng идти́ (chia: идёт)."},{"t":"para","text":"12. Высоко́ в не́бе плыву́т облака́.","b":1},{"t":"para","text":"Dịch: Những đám mây đang trôi tít trên cao."},{"t":"example","text":"Giải thích: Mây trôi (giống như bơi/nổi) → Dùng плыть (chia: плыву́т)."},{"t":"para","text":"13. Мно́гие де́ти лета́ют во сне, а вот со взро́слыми тако́е случа́ется ре́дко.","b":1},{"t":"para","text":"Dịch: Nhiều đứa trẻ bay trong giấc mơ, còn với người lớn thì chuyện đó hiếm khi xảy ra."},{"t":"example","text":"Giải thích: Hành động bay lượn không xác định hướng (trong mơ/lặp lại) → Dùng động từ đa chiều лета́ть (chia: лета́ют)."},{"t":"para","text":"14. Обы́чно я вожу́ (или беру́/ношу́) с собо́й два чемода́на и су́мку.","b":1},{"t":"para","text":"Dịch: Thường thì tôi mang theo (chở theo) hai cái vali và một cái túi."},{"t":"example","text":"Giải thích: \"Hai vali\" thường ám chỉ đi xa bằng phương tiện, nên dùng вози́ть (chở/mang bằng xe - chia: вожу́). Nếu xách tay thì dùng носи́ть (chia: ношу́)."},{"t":"para","text":"15. За́втра я иду́ на вечери́нку, е́сли хо́чешь — пойдём со мной.","b":1},{"t":"para","text":"Dịch: Mai tớ đi dự tiệc đấy, nếu thích thì đi cùng tớ."},{"t":"example","text":"Giải thích: Dự định tương lai gần (kế hoạch chắc chắn), tham gia sự kiện → Dùng động từ một chiều идти́ ở thì hiện tại (иду́)."},{"t":"para","text":"16. Я привы́к что-нибу́дь верте́ть (или носи́ть/держа́ть) в рука́х, е́сли я ничего́ не ..., я чу́вствую себя́ не в свое́й таре́лке.","b":1},{"t":"note","text":"Lưu ý: Câu này sách in thiếu động từ điền. Dựa vào ngữ cảnh \"tay chân thừa thãi\":"},{"t":"para","text":"Điền: держа́ть (cầm/giữ) hoặc верте́ть (xoay). Nhưng nếu phải dùng động từ chuyển động: носи́ть (mang). Tuy nhiên, ngữ cảnh tự nhiên nhất là \"cầm/nghịch cái gì đó\"."},{"t":"example","text":"Nếu bắt buộc dùng động từ chuyển động: носи́ть (mang theo)."},{"t":"para","text":"Dịch: Tôi quen cầm/mang cái gì đó trên tay, nếu tôi không mang/cầm gì, tôi cảm thấy không thoải mái (như không phải là mình)."},{"t":"para","text":"17. Е́сли вы везёте с собо́й соба́ку в обще́ственном тра́нспорте, необходи́мо наде́ть ей намо́рдник.","b":1},{"t":"para","text":"Dịch: Nếu bạn chở theo chó trên phương tiện công cộng, cần phải đeo rọ mõm cho nó."},{"t":"example","text":"Giải thích: Đi bằng phương tiện công cộng → Dùng везти́ (chở - chia: везёте)."},{"t":"para","text":"18. Я е́ду (или лечу́) в Пари́ж на неде́лю, верну́сь в пя́тницу.","b":1},{"t":"para","text":"Dịch: Tớ đi (hoặc bay) sang Paris một tuần, thứ sáu sẽ về."},{"t":"example","text":"Giải thích: Kế hoạch đi xa (thường là bay hoặc đi tàu/xe) → е́хать (е́ду) hoặc лете́ть (лечу́)."},{"t":"para","text":"19. Электри́чка идёт со все́ми остано́вками.","b":1},{"t":"para","text":"Dịch: Tàu điện chạy (đi) dừng ở tất cả các ga."},{"t":"example","text":"Giải thích: Tàu chạy theo lịch trình → Dùng идти́ (идёт)."},{"t":"para","text":"20. Они́ давно́ обеща́ли прие́хать, но всё не е́дут.","b":1},{"t":"para","text":"Dịch: Họ hứa đến từ lâu rồi mà mãi vẫn chưa đi (đến)."},{"t":"example","text":"Giải thích: Đang chờ đợi hành động diễn ra (họ đang trên đường hoặc khởi hành) bằng phương tiện → е́хать (е́дут)."},{"t":"para","text":"21. Посмотри́, кака́я чёрная ту́ча идёт (или надвига́ется) на нас.","b":1},{"t":"para","text":"Dịch: Nhìn kìa, đám mây đen sì đang kéo về phía chúng ta."},{"t":"example","text":"Giải thích: Mây đen kéo đến (đe dọa) dùng идти́ (идёт) hoặc надвига́ться."},{"t":"para","text":"22. В похо́де он всегда́ шёл во главе́ на́шего ма́ленького отря́да.","b":1},{"t":"para","text":"Dịch: Trong cuộc hành quân, anh ấy luôn đi dẫn đầu nhóm nhỏ của chúng tôi."},{"t":"example","text":"Giải thích: Ngữ cảnh quá khứ, mô tả vị trí khi di chuyển. Dù có \"luôn luôn\" (всегда), nhưng mô tả trạng thái liên tục trong quá trình đi (process) nên dùng шёл (quá khứ của идти) là phổ biến để chỉ vị trí \"đang đi đầu\". Hoặc dùng ходи́л nếu nhấn mạnh thói quen lặp lại nhiều lần. Tuy nhiên, \"đi đầu hàng\" thường dùng шёл."},{"t":"para","text":"23. Я хожу́ на ле́кции два ра́за в неде́лю.","b":1},{"t":"para","text":"Dịch: Tôi đi nghe giảng hai lần một tuần."},{"t":"example","text":"Giải thích: Tần suất lặp lại (hai lần một tuần) → Dùng động từ đa chiều ходи́ть (хожу́)."}]},{"id":"07-s097","type":"exercise","title":"Bài 588 (Trang 308)","num":588,"blocks":[{"t":"instruction","text":"Yêu cầu: Điền vào chỗ trống động từ nguyên mẫu (Infinitive) của động từ chuyển động phù hợp theo ý nghĩa."},{"t":"vocab","ru":"На самолёте значи́тельно удо́бнее, чем на по́езде","vi":"лете́ть ну́жно всего́ два часа́ (а не 14 часо́в).","g":null},{"t":"para","text":"Dịch: Đi máy bay tiện hơn tàu hỏa nhiều: chỉ cần bay có 2 tiếng thôi (chứ không phải 14 tiếng)."},{"t":"para","text":"Giải thích: Đi máy bay → лете́ть (bay)."},{"t":"para","text":"2. Я предпочита́ю е́хать на авто́бусе, сего́дня мне придётся е́хать на трамва́е.","b":1},{"t":"para","text":"Dịch: Tôi thích đi bằng xe buýt hơn, nhưng hôm nay tôi sẽ phải đi bằng tàu điện."},{"t":"para","text":"Giải thích: Đi bằng phương tiện mặt đất → е́хать."},{"t":"para","text":"3. В Москву́ нам лу́чше е́хать по́ездом, он прихо́дит в во́семь утра́.","b":1},{"t":"para","text":"Dịch: Lên Moscow chúng ta tốt nhất nên đi tàu hỏa, nó đến nơi lúc 8 giờ sáng."},{"t":"para","text":"Giải thích: Đi tàu → е́хать."},{"t":"para","text":"4. От авто́буса удо́бнее везти́ ве́щи на теле́жке, а не нести́ их в рука́х.","b":1},{"t":"para","text":"Dịch: Từ xe buýt, chở đồ bằng xe đẩy thì tiện hơn là xách trên tay."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Dùng xe đẩy (phương tiện) → везти́."},{"t":"para","text":"Dùng tay (sức người) → нести́."},{"t":"para","text":"5. Тебе́ сто́ит лете́ть на самолёте, сэкономишь вре́мя.","b":1},{"t":"para","text":"Dịch: Bạn nên bay bằng máy bay, sẽ tiết kiệm thời gian."},{"t":"para","text":"Giải thích: Máy bay → лете́ть."},{"t":"para","text":"6. Мне нра́вится е́хать на “Кра́сной стреле́”, но в э́тот раз биле́тов на э́тот по́езд не́ было.","b":1},{"t":"para","text":"Dịch: Tôi thích đi tàu \"Mũi tên đỏ\", nhưng lần này không còn vé tàu đó."},{"t":"para","text":"Giải thích: Tàu hỏa → е́хать."},{"t":"para","text":"7. Возьми́ с собо́й тёплые ве́щи, нельзя́ е́хать в командиро́вку без тёплых веще́й.","b":1},{"t":"para","text":"Dịch: Mang đồ ấm theo đi, không thể đi công tác mà không có đồ ấm được."},{"t":"para","text":"Giải thích: Đi công tác (di chuyển xa) → е́хать."},{"t":"para","text":"8. Я предпочита́ю лета́ть самолётами “Аэрофло́та”.","b":1},{"t":"para","text":"Dịch: Tôi thích bay (đi lại) bằng máy bay của hãng Aeroflot."},{"t":"para","text":"Giải thích: Sở thích chung, lặp lại nhiều lần → Dùng động từ đa chiều лета́ть."},{"t":"para","text":"9. Идти́ че́рез лес но́чью — заня́тие не из прия́тных.","b":1},{"t":"para","text":"Dịch: Đi bộ qua rừng vào ban đêm là một việc chẳng thú vị chút nào."},{"t":"example","text":"Giải thích: Đi bộ xuyên rừng → идти́ (hoặc брести́ - lê bước, пробира́ться - dò dẫm). Идти́ là trung tính nhất."},{"t":"para","text":"10. Тебе́ сто́ит вести́ маши́ну бо́лее осторо́жно, мне бы́ло стра́шно смотре́ть, как ты мча́лся, не разбира́я доро́ги.","b":1},{"t":"para","text":"Dịch: Cậu nên lái xe cẩn thận hơn, tớ thấy sợ khi nhìn cậu lao đi mà không nhìn đường."},{"t":"example","text":"Giải thích: Lái xe → вести́ (hoặc води́ть nếu nói chung, nhưng trong ngữ cảnh khuyên bảo cụ thể cho hành động đang xét thì вести cũng dùng được, hoặc води́ть cho kỹ năng. Ở đây khuyên về cách thức: вести)."},{"t":"para","text":"11. Тебе́ сто́ит вести́ маши́ну бо́лее осторо́жно и не отвлека́ться, ина́че мы мо́жем попа́сть в ава́рию.","b":1},{"t":"para","text":"Dịch: Cậu nên lái xe cẩn thận hơn và đừng mất tập trung, nếu không chúng ta có thể gặp tai nạn."},{"t":"para","text":"Giải thích: Tương tự câu 10 → вести́."},{"t":"para","text":"12. Ты мо́жешь идти́ (или е́хать) куда́ захо́чешь.","b":1},{"t":"para","text":"Dịch: Bạn có thể đi bất cứ đâu bạn muốn."},{"t":"example","text":"Giải thích: Tùy thuộc đi bộ (идти́) hay đi xe (е́хать)."},{"t":"para","text":"13. Врач сказа́л, что тебе́ до́лго не попра́вится; ходи́ть на́до понемно́гу. (Câu gốc sách có thể bị lỗi in, ý là \"chân lâu khỏi\")."},{"t":"example","text":"Sửa lại theo logic: Bác sĩ bảo chân lâu khỏi, cần phải đi lại ít thôi (hoặc tập đi dần dần)."},{"t":"para","text":"Dịch: Bác sĩ nói rằng cậu sẽ lâu bình phục; cần phải đi lại từng chút một thôi."},{"t":"para","text":"Giải thích: Hoạt động đi lại (khả năng vận động) → ходи́ть."},{"t":"para","text":"14. Удо́бно води́ть ребёнка в шко́лу, удо́бно переводи́ть нахо́дится че́рез доро́гу. (Câu sách in có vẻ lộn xộn)."},{"t":"example","text":"Dịch và chỉnh lý: Tiện đưa (dắt) con đi học... Tiện dắt qua đường."},{"t":"para","text":"Giải thích: Dắt trẻ đi bộ → води́ть / переводи́ть (qua đường). Nếu chở bằng xe → вози́ть."},{"t":"para","text":"15. Мне лу́чше е́хать на метро́, ина́че я могу́ опозда́ть.","b":1},{"t":"para","text":"Dịch: Tốt hơn là tôi nên đi bằng tàu điện ngầm, nếu không tôi có thể bị muộn."},{"t":"para","text":"Giải thích: Đi phương tiện → е́хать."},{"t":"para","text":"16. Пе́ред собо́й вести́ (или катить) коля́ску с ребёнком удо́бнее, чем нести́ её на рука́х.","b":1},{"t":"para","text":"Dịch: Đẩy (lăn) xe nôi có em bé phía trước thì tiện hơn là bế (mang) nó trên tay."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Xe nôi (có bánh xe) → кати́ть (lăn/đẩy) hoặc везти́ (chở/đẩy)."},{"t":"para","text":"Trên tay → нести́."},{"t":"para","text":"17. ... вперёд всех тру́дно, вот почему́ спортсме́ны стара́ются вы́рваться вперёд то́лько на после́дних ме́трах диста́нции.","b":1},{"t":"para","text":"Điền: Бежа́ть (hoặc Плыть/Е́хать tùy môn thể thao, thường là chạy)."},{"t":"para","text":"Dịch: Chạy dẫn đầu tất cả thì rất khó, đấy là lý do tại sao các vận động viên chỉ cố bứt phá lên trước ở những mét cuối cùng."},{"t":"para","text":"Giải thích: Đua chạy → бежа́ть."},{"t":"para","text":"18. ... по ле́су о́сенью — моё люби́мое заня́тие.","b":1},{"t":"para","text":"Điền: Броди́ть (hoặc Ходи́ть)."},{"t":"para","text":"Dịch: Lang thang (đi dạo) trong rừng vào mùa thu là thú vui yêu thích của tôi."},{"t":"para","text":"Giải thích: Đi dạo thư giãn, không hướng đích → Dùng động từ đa chiều броди́ть (lang thang) rất hợp ngữ cảnh."},{"t":"para","text":"19. Коне́чно, всегда́ прия́тнее ... по тече́нию, а не про́тив него́.","b":1},{"t":"para","text":"Điền: плыть."},{"t":"para","text":"Dịch: Tất nhiên, bơi (trôi) xuôi dòng bao giờ cũng dễ chịu hơn là ngược dòng."},{"t":"para","text":"Giải thích: Di chuyển trên nước → плыть."},{"t":"para","text":"20. Для писа́теля необходи́мо ... по стране́, знако́миться с людьми́.","b":1},{"t":"para","text":"Điền: е́здить."},{"t":"para","text":"Dịch: Đối với nhà văn, việc đi lại (du lịch) khắp đất nước, làm quen với mọi người là rất cần thiết."},{"t":"para","text":"Giải thích: Đi nhiều nơi, lặp lại → Dùng động từ đa chiều е́здить."}]},{"id":"07-s098","type":"exercise","title":"Bài 589 (Trang 309)","num":589,"blocks":[{"t":"para","text":"Chủ điểm ngữ pháp (Trong khung trang 309):","b":1},{"t":"para","text":"! В прида́точном вре́мени и́ли усло́вия, е́сли нет указа́ния на объе́кт, по направле́нию к кото́рому происхо́дит движе́ние, глаго́л однонапра́вленного движе́ния ука́зывает на движе́ние в одно́м направле́нии в значе́нии 'вся́кий раз, когда́ (е́сли)...'; глаго́л разнонапра́вленного движе́ния обознача́ет спосо́бность к движе́нию и́ли движе́ние в ра́зные сто́роны.","b":1},{"t":"para","text":"Dịch và giải thích: Trong mệnh đề chỉ thời gian hoặc điều kiện, nếu không có sự chỉ dẫn về đối tượng (đích đến) mà chuyển động hướng tới:"},{"t":"example","text":"Động từ chuyển động một chiều (идти́, е́хать, лете́ть...) chỉ chuyển động theo một hướng với ý nghĩa \"mỗi khi (nếu) đang đi...\" (nhấn mạnh vào quá trình thực hiện hành động mỗi lần đó)."},{"t":"example","text":"Động từ chuyển động đa chiều (ходи́ть, е́здить, пла́вать...) chỉ khả năng/kỹ năng thực hiện chuyển động hoặc chuyển động về nhiều phía."},{"t":"instruction","text":"Yêu cầu bài tập: Thay thế các dấu chấm bằng động từ chuyển động cần thiết theo ý nghĩa ở dạng thì hiện tại hoặc nguyên mẫu."},{"t":"para","text":"1. Когда́ ты е́дешь на маши́не, обяза́тельно пристёгивай ремни́ безопа́сности.","b":1},{"t":"para","text":"(Gốc: е́хать)"},{"t":"para","text":"Dịch: Khi bạn đi (lái) xe ô tô, nhất định phải thắt dây an toàn."},{"t":"example","text":"Giải thích: Dùng động từ một chiều (е́хать → е́дешь) vì ám chỉ \"mỗi lần bạn đang trong quá trình di chuyển bằng xe\"."},{"t":"para","text":"2. Е́сли вы пло́хо пла́ваете, не сто́ит далеко́ заплыва́ть.","b":1},{"t":"para","text":"(Gốc: пла́вать)"},{"t":"para","text":"Dịch: Nếu các bạn bơi kém, thì không nên bơi ra xa."},{"t":"example","text":"Giải thích: Nói về kỹ năng/khả năng bơi lội → Dùng động từ đa chiều (пла́вать → пла́ваете)."},{"t":"para","text":"3. Е́сли ты идёшь на охо́ту, на́до позабо́титься обо всём, что мо́жет тебе́ пона́добиться в лесу́;","b":1},{"t":"para","text":"(Gốc: идти́)"},{"t":"para","text":"Dịch: Nếu bạn đi săn, cần phải lo liệu mọi thứ có thể cần thiết trong rừng."},{"t":"example","text":"Giải thích: \"Nếu bạn đang đi (khởi hành) đi săn\" (hướng tới mục đích cụ thể mỗi lần) → Dùng động từ một chiều (идти́ → идёшь)."},{"t":"para","text":"4. Е́сли ты несёшь с собо́й все докуме́нты, их легко́ потеря́ть.","b":1},{"t":"para","text":"(Gốc: нести́)"},{"t":"para","text":"Dịch: Nếu bạn mang theo tất cả giấy tờ bên mình, rất dễ làm mất chúng."},{"t":"example","text":"Giải thích: Ám chỉ trạng thái đang mang vác trong một chuyến đi cụ thể (mỗi khi bạn đang cầm chúng đi) → Dùng động từ một chiều (нести́ → несёшь)."},{"t":"para","text":"5. Когда́ бежи́шь после́дние ме́тры distanции, ду́маешь то́лько о побе́де.","b":1},{"t":"para","text":"(Gốc: бежа́ть)"},{"t":"para","text":"Dịch: Khi đang chạy những mét cuối cùng của cự ly, bạn chỉ nghĩ về chiến thắng."},{"t":"example","text":"Giải thích: Hành động đang diễn ra theo một hướng về đích → Dùng động từ một chiều (бежа́ть → бежи́шь)."},{"t":"para","text":"6. Е́сли я е́ду в университе́т, я встаю́ в семь часо́в утра́, е́сли нет — в во́семь.","b":1},{"t":"para","text":"(Gốc: е́хать)"},{"t":"para","text":"Dịch: Nếu tôi đi đến trường đại học (bằng phương tiện), tôi dậy lúc 7 giờ sáng, nếu không — thì 8 giờ."},{"t":"example","text":"Giải thích: Di chuyển đến một địa điểm cụ thể (trường) → Dùng động từ một chiều (е́хать → е́ду)."},{"t":"para","text":"7. Е́сли вы везёте бага́ж, разме́р кото́рого превыша́ет допусти́мые но́рмы, вам сле́дует его́ оплати́ть;","b":1},{"t":"para","text":"(Gốc: везти́)"},{"t":"para","text":"Dịch: Nếu bạn chở/mang hành lý có kích thước vượt quá quy định cho phép, bạn cần phải trả tiền cho nó."},{"t":"example","text":"Giải thích: Hành động đang diễn ra (đang chở đi) trong chuyến đi → Dùng động từ một chiều (везти́ → везёте)."},{"t":"para","text":"8. Когда́ я веду́ маши́ну, я предпочита́ю, что́бы мне не меша́ли;","b":1},{"t":"para","text":"(Gốc: вести́)"},{"t":"para","text":"Dịch: Khi tôi đang lái xe, tôi muốn không bị ai làm phiền."},{"t":"example","text":"Giải thích: Điều khiển phương tiện đang di chuyển → Dùng động từ một chiều (вести́ → веду́)."},{"t":"para","text":"9. Когда́ обезья́на ла́зает по дере́вьям, в ка́честве упо́ра она́ испо́льзует свой хвост;","b":1},{"t":"para","text":"(Gốc: ла́зать - biến thể của ла́зить)"},{"t":"para","text":"Dịch: Khi con khỉ leo trèo trên cây, nó dùng đuôi làm điểm tựa."},{"t":"example","text":"Giải thích: Hành động leo trèo lung tung không hướng xác định hoặc chỉ khả năng của loài vật → Dùng động từ đa chiều (ла́зать → ла́зает)."},{"t":"para","text":"10. Я беру́ э́ту су́мку, когда́ несу́ ве́щи в пра́чечную.","b":1},{"t":"para","text":"(Gốc: нести́)"},{"t":"para","text":"Dịch: Tôi lấy cái túi này khi mang đồ đến tiệm giặt là."},{"t":"example","text":"Giải thích: Mang đồ đến một đích cụ thể (tiệm giặt) → Dùng động từ một chiều (нести́ → несу́)."},{"t":"para","text":"11. Когда́ я веду́ ребёнка в шко́лу, постоя́нно встреча́ю э́того челове́ка.","b":1},{"t":"para","text":"(Gốc: вести́)"},{"t":"para","text":"Dịch: Khi tôi dẫn con đến trường, tôi thường xuyên gặp người này."},{"t":"example","text":"Giải thích: Dẫn đi theo một hướng cụ thể (đến trường) → Dùng động từ một chiều (вести́ → веду́)."},{"t":"para","text":"12. Когда́ я брожу́ вечера́ми по го́роду, мне в го́лову прихо́дят ра́зные интере́сные мы́сли.","b":1},{"t":"para","text":"(Gốc: броди́ть)"},{"t":"para","text":"Dịch: Khi tôi lang thang quanh thành phố vào buổi tối, trong đầu tôi nảy ra nhiều ý nghĩ thú vị."},{"t":"example","text":"Giải thích: Đi dạo không mục đích, không hướng cụ thể → Dùng động từ đa chiều (броди́ть → брожу́)."},{"t":"para","text":"13. Е́сли вы го́ните маши́ну со ско́ростью сто два́дцать киломе́тров в час, вы мо́жете не спра́виться с управле́нием;","b":1},{"t":"para","text":"(Gốc: гнать)"},{"t":"para","text":"Dịch: Nếu bạn lái (phóng) xe với tốc độ 120 km/h, bạn có thể không kiểm soát được tay lái."},{"t":"example","text":"Giải thích: Hành động lái xe nhanh theo một hướng cụ thể → Dùng động từ một chiều (гнать → го́ните)."},{"t":"para","text":"14. Е́сли ве́чером мы идём в теа́тр и́ли в кино́, обы́чно возвраща́емся домо́й на такси́.","b":1},{"t":"para","text":"(Gốc: идти́)"},{"t":"para","text":"Dịch: Nếu buổi tối chúng tôi đi nhà hát hoặc đi xem phim, chúng tôi thường về nhà bằng taxi."},{"t":"example","text":"Giải thích: Đi đến địa điểm sự kiện cụ thể → Dùng động từ một chiều (идти́ → идём)."},{"t":"para","text":"15. Е́сли ребёнок хо́дит в бассе́йн, он растёт здоро́вым и си́льным;","b":1},{"t":"para","text":"(Gốc: ходи́ть)"},{"t":"para","text":"Dịch: Nếu đứa trẻ đi bơi (đến bể bơi thường xuyên), nó sẽ lớn lên khỏe mạnh và cường tráng."},{"t":"example","text":"Giải thích: Chỉ thói quen, việc tham gia hoạt động định kỳ → Dùng động từ đa chiều (ходи́ть → хо́дит)."},{"t":"para","text":"16. Когда́ мы е́дем на да́чу, не обхо́дится без происше́ствий.","b":1},{"t":"para","text":"(Gốc: е́хать)"},{"t":"para","text":"Dịch: Khi chúng tôi đi (xe) ra nhà vườn, không bao giờ tránh khỏi sự cố."},{"t":"example","text":"Giải thích: Quá trình di chuyển đến đích cụ thể (nhà vườn) → Dùng động từ một chiều (е́хать → е́дем)."},{"t":"para","text":"17. Е́сли малы́ш с удово́льствием по́лзает, он бы́стро вста́нет на но́ги и начнёт ходи́ть.","b":1},{"t":"para","text":"(Gốc: по́лзать, ходи́ть)"},{"t":"para","text":"Dịch: Nếu em bé bò một cách thích thú, bé sẽ nhanh chóng đứng dậy và bắt đầu đi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"по́лзает","vi":"Chỉ hoạt động bò chung (đa chiều/kỹ năng).","g":null},{"t":"vocab","ru":"ходи́ть","vi":"Chỉ kỹ năng biết đi (đa chiều, dùng nguyên mẫu sau начнёт).","g":null},{"t":"para","text":"18. Когда́ лети́шь на самолёте, мо́жно наблюда́ть за плыву́щими облака́ми;","b":1},{"t":"para","text":"(Gốc: лете́ть)"},{"t":"para","text":"Dịch: Khi bay trên máy bay, có thể quan sát những đám mây trôi."},{"t":"example","text":"Giải thích: Quá trình bay đang diễn ra → Dùng động từ một chiều (лете́ть → лети́шь - dạng ngôi thứ 2 số ít chỉ người nói chung)."},{"t":"para","text":"19. Е́сли ве́чером я иду́ на трениро́вку, ухожу́ с рабо́ты в три часа́.","b":1},{"t":"para","text":"(Gốc: идти́)"},{"t":"para","text":"Dịch: Nếu buổi tối tôi đi tập, tôi rời chỗ làm lúc 3 giờ."},{"t":"example","text":"Giải thích: Đi đến đích cụ thể (buổi tập) → Dùng động từ một chiều (идти́ → иду́)."}]},{"id":"07-s099","type":"exercise","title":"Bài 590 (Trang 310)","num":590,"blocks":[{"t":"instruction","text":"Yêu cầu: Sử dụng các động từ chuyển động, hãy đưa ra từ/cụm từ đồng nghĩa cho các từ và cụm từ được in nghiêng (được bôi đậm dưới đây)."},{"t":"para","text":"1. По́езд сле́дует со все́ми остано́вками;","b":1},{"t":"para","text":"Đồng nghĩa: идёт","b":1},{"t":"para","text":"Câu mới: По́езд идёт со все́ми остано́вками."},{"t":"para","text":"Dịch: Tàu hỏa chạy (đi) dừng ở tất cả các ga."},{"t":"example","text":"Giải thích: Với phương tiện giao thông theo lịch trình, dùng идти."},{"t":"para","text":"2. Кора́бль де́ржит курс на Му́рманск;","b":1},{"t":"example","text":"Đồng nghĩa: плывёт (hoặc идёт trong ngôn ngữ hàng hải chuyên nghiệp, nhưng плывёт phổ biến với người học)."},{"t":"para","text":"Câu mới: Кора́бль плывёт на Му́рманск."},{"t":"para","text":"Dịch: Con tàu đang bơi (đi) về hướng Murmansk."},{"t":"para","text":"3. В да́нный моме́нт я направля́юсь в декана́т;","b":1},{"t":"para","text":"Đồng nghĩa: иду́","b":1},{"t":"para","text":"Câu mới: В да́нный моме́нт я иду́ в декана́т."},{"t":"para","text":"Dịch: Vào thời điểm này tôi đang đi đến văn phòng khoa."},{"t":"para","text":"4. Куда́ ты так бы́стро мчи́шься?","b":1},{"t":"para","text":"Đồng nghĩa: бежи́шь (nếu chạy bộ) / лети́шь (nghĩa bóng: đi rất nhanh) / е́дешь (nếu đi xe)."},{"t":"para","text":"Câu mới: Куда́ ты так бы́стро бежи́шь / лети́шь?"},{"t":"para","text":"Dịch: Cậu chạy/bay (lao đi) đâu mà nhanh thế?"},{"t":"para","text":"5. Капита́н стои́т у штурва́ла корабля́;","b":1},{"t":"para","text":"Đồng nghĩa: ведёт","b":1},{"t":"para","text":"Câu mới: Капита́н ведёт кора́бль."},{"t":"para","text":"Dịch: Thuyền trưởng đang lái (dẫn dắt) con tàu."},{"t":"para","text":"6. Где ты так до́лго шата́ешься?","b":1},{"t":"example","text":"Đồng nghĩa: бро́дишь (hoặc хо́дишь)."},{"t":"para","text":"Câu mới: Где ты так до́лго бро́дишь?"},{"t":"para","text":"Dịch: Cậu lang thang ở đâu mà lâu thế? (Sắc thái không mục đích)."},{"t":"para","text":"7. Над на́шими голова́ми порха́ют ба́бочки;","b":1},{"t":"para","text":"Đồng nghĩa: лета́ют","b":1},{"t":"para","text":"Câu mới: Над на́шими голова́ми лета́ют ба́бочки."},{"t":"para","text":"Dịch: Những chú bướm đang bay (lượn) trên đầu chúng ta."},{"t":"para","text":"8. Куда́ де́ржишь путь?","b":1},{"t":"para","text":"Đồng nghĩa: идёшь (hoặc е́дешь)."},{"t":"para","text":"Câu mới: Куда́ идёшь?"},{"t":"para","text":"Dịch: Cậu đang đi đâu đấy? (Hỏi về hướng đi)."},{"t":"para","text":"9. Ты уме́ешь управля́ть тра́ктором?","b":1},{"t":"para","text":"Đồng nghĩa: води́ть","b":1},{"t":"para","text":"Câu mới: Ты уме́ешь води́ть тра́ктор?"},{"t":"para","text":"Dịch: Cậu có biết lái máy kéo không?"},{"t":"para","text":"10. Неза́чем шага́ть из угла́ в у́гол;","b":1},{"t":"para","text":"Đồng nghĩa: ходи́ть","b":1},{"t":"para","text":"Câu mới: Неза́чем ходи́ть из угла́ в у́гол."},{"t":"para","text":"Dịch: Chẳng việc gì phải đi đi lại lại từ góc này sang góc kia."},{"t":"para","text":"11. Уже́ во́семь ме́сяцев кора́бль борозди́т во́ды океа́на;","b":1},{"t":"example","text":"Đồng nghĩa: пла́вает (hoặc хо́дит)."},{"t":"para","text":"Câu mới: Уже́ во́семь ме́сяцев кора́бль пла́вает в океа́не."},{"t":"para","text":"Dịch: Đã tám tháng nay con tàu lênh đênh (bơi/đi lại) trên đại dương. (Dùng đa chiều vì thời gian dài, hành trình phức tạp)."},{"t":"para","text":"12. Куда́ э́то ты ше́ствуешь?","b":1},{"t":"para","text":"Đồng nghĩa: идёшь","b":1},{"t":"para","text":"Câu mới: Куда́ э́то ты идёшь?"},{"t":"para","text":"Dịch: Cậu đang đi (diễu/bước đi trịnh trọng) đâu đấy?"},{"t":"para","text":"13. Це́лый день мота́юсь по дела́м, ужа́сно уста́ла;","b":1},{"t":"example","text":"Đồng nghĩa: бе́гаю (hoặc е́зжу tùy phương tiện, nhưng бегаю hay dùng nghĩa bóng là chạy việc)."},{"t":"para","text":"Câu mới: Це́лый день бе́гаю по дела́м, ужа́сно уста́ла."},{"t":"para","text":"Dịch: Cả ngày chạy lo công việc, mệt kinh khủng."},{"t":"para","text":"14. Высоко́ в не́бе пари́т ма́ленький спорти́вный самолёт;","b":1},{"t":"example","text":"Đồng nghĩa: лети́т (hoặc лета́ет nếu nói chung, nhưng ngữ cảnh này là đang bay lơ lửng)."},{"t":"para","text":"Câu mới: Высоко́ в не́бе лети́т ма́ленький спорти́вный самолёт."},{"t":"para","text":"Dịch: Một chiếc máy bay thể thao nhỏ đang bay tít trên cao."},{"t":"para","text":"15. Что ты е́ле но́ги воло́чишь?","b":1},{"t":"example","text":"Đồng nghĩa: плетёшься (hoặc ползёшь, идёшь ме́дленно). Ползёшь (bò) dùng với nghĩa mỉa mai đi quá chậm. Идёшь là trung tính."},{"t":"para","text":"Câu mới: Что ты е́ле идёшь (hoặc ползёшь)?"},{"t":"para","text":"Dịch: Sao cậu lê bước/đi chậm rề rề thế?"},{"t":"subhead","text":"GỢI Ý NGỮ PHÁP (LÝ THUYẾT)","b":1},{"t":"para","text":"Trước khi làm bài, học sinh cần hiểu sự khác biệt giữa hai nhóm động từ chuyển động trong tiếng Nga:"},{"t":"example","text":"Nhóm một chiều (Unidirectional): Chỉ hành động diễn ra theo một hướng cụ thể, đang xảy ra tại thời điểm nói (идти́, е́хать, бежа́ть, лете́ть...)."},{"t":"example","text":"Nhóm đa chiều (Multidirectional): Chỉ hành động đi và về (khứ hồi), hành động lặp đi lặp lại, hành động không có hướng cụ thể, hoặc chỉ khả năng/kỹ năng (ходи́ть, е́здить, бе́гать, лета́ть...)."},{"t":"para","text":"Dưới đây là phần dịch các ô ngữ pháp xuất hiện trong bài hoặc liên quan trực tiếp:"},{"t":"para","text":"1. Ô ngữ pháp trang 304 (trong Bài 582):","b":1},{"t":"example","text":"Tiếng Nga: В разгово́рной ре́чи однонапра́вленного движе́ния настоя́щего вре́мени мо́гут обознача́ть де́йствия, относя́щиеся к бу́дущему: Я е́ду домо́й = Я собира́юсь е́хать домо́й."},{"t":"example","text":"Tiếng Việt: Trong văn nói, các động từ chuyển động một chiều ở thì hiện tại có thể chỉ các hành động thuộc về tương lai: Tôi đang về nhà = Tôi định về nhà (sắp về)."},{"t":"para","text":"2. Ô ngữ pháp trang 307 (trong Bài 586):","b":1},{"t":"para","text":"Tiếng Nga: С показа́телями вре́мени, отвеча́ющими на вопро́с: ско́лько (раз)?, как ча́сто?, употребля́ются глаго́лы разнонапра́вленного движе́ния (значе́ние обы́чного, повторя́ющегося де́йствия)."},{"t":"para","text":"Tiếng Việt: Với các từ chỉ thời gian trả lời cho câu hỏi: bao nhiêu (lần)?, thường xuyên thế nào?, ta sử dụng động từ chuyển động đa chiều (mang ý nghĩa hành động thông thường, lặp đi lặp lại)."}]},{"id":"07-s100","type":"exercise","title":"BÀI TẬP 591 (Trang 310-311)","num":591,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay dấu ba chấm bằng động từ chuyển động cần thiết ở thì hiện tại hoặc nguyên mẫu (infinitive). Giải thích lựa chọn của bạn."},{"t":"para","text":"Các cặp động từ sử dụng trong bài:"},{"t":"para","text":"кати́ться – ката́ться (lăn, trượt, đi chơi bằng phương tiện)"},{"t":"para","text":"гна́ться – гоня́ться (rượt đuổi, chạy theo)"},{"t":"para","text":"тащи́ться – таска́ться (lê bước, kéo lê, đi một cách khó nhọc)"},{"t":"para","text":"нести́сь – носи́ться (lao đi, chạy vội vã, lan truyền)"},{"t":"para","text":"Dịch và Giải chi tiết:","b":1},{"t":"para","text":"1. По её щека́м ... слёзы.","b":1},{"t":"subhead","text":"Đáp án: ка́тятся","b":1},{"t":"para","text":"Dịch: Những giọt nước mắt đang lăn trên má cô ấy."},{"t":"example","text":"Giải thích: Dùng động từ một chiều (кати́ться) vì hành động \"lăn\" của nước mắt đang diễn ra theo một hướng cụ thể (từ trên xuống dưới) ngay lúc này."},{"t":"para","text":"2. Мы собира́лись ... на ло́дке до са́мого ве́чера.","b":1},{"t":"subhead","text":"Đáp án: ката́ться","b":1},{"t":"para","text":"Dịch: Chúng tôi đã định đi chơi (chèo) thuyền đến tận tối muộn."},{"t":"example","text":"Giải thích: Dùng động từ đa chiều (ката́ться) ở dạng nguyên mẫu. \"Đi chơi thuyền\" là hành động chuyển động không có hướng cụ thể (đi vòng vòng để giải trí) và kéo dài trong một khoảng thời gian (đến tận tối)."},{"t":"vocab","ru":"В де́тской беготня́ и шум","vi":"Ко́ля ... за На́стей по ко́мнате, а На́стя стара́ется от него́ уверну́ться.","g":null},{"t":"subhead","text":"Đáp án: гоня́ется (hoặc го́нится)"},{"t":"para","text":"Dịch: Trong phòng trẻ con có tiếng chạy rầm rập và ồn ào: Kolya đang rượt đuổi Nastya quanh phòng, còn Nastya thì cố gắng né tránh cậu ấy."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Dùng гоня́ется (đa chiều) vì cụm từ \"по ко́мнате\" (quanh phòng) và \"беготня́\" (sự chạy rầm rập lăng xăng) chỉ hành động không theo một đường thẳng duy nhất mà chạy loạn xạ."},{"t":"example","text":"Tuy nhiên, nếu nhấn mạnh việc \"đang đuổi theo mục tiêu cụ thể\" ngay lúc này, го́нится (một chiều) cũng có thể chấp nhận được, nhưng гоня́ется phù hợp với ngữ cảnh vui chơi \"quanh phòng\" hơn."},{"t":"para","text":"4. По на́шему двору́ огро́мными прыжка́ми бежи́т кот, за кото́рым ... сосе́дская соба́ка.","b":1},{"t":"subhead","text":"Đáp án: го́нится","b":1},{"t":"para","text":"Dịch: Một con mèo đang chạy những bước nhảy rất lớn qua sân nhà chúng tôi, và con chó hàng xóm đang đuổi theo nó."},{"t":"example","text":"Giải thích: Dùng động từ một chiều (гна́ться -> го́нится) vì hành động rượt đuổi đang diễn ra theo một hướng cụ thể, bám sát theo con mèo (đang бежи́т - cũng là một chiều)."},{"t":"para","text":"5. Я заме́тил, что плащ упа́л с его́ плеча́ и ... за ним по земле́.","b":1},{"t":"subhead","text":"Đáp án: та́щится","b":1},{"t":"para","text":"Dịch: Tôi nhận thấy chiếc áo mưa đã rơi khỏi vai anh ấy và đang bị kéo lê theo anh ấy trên mặt đất."},{"t":"example","text":"Giải thích: Dùng động từ một chiều (тащи́ться) vì chiếc áo đang bị kéo theo một hướng cụ thể (theo người đi) ngay tại thời điểm quan sát."},{"t":"para","text":"6. За водо́й прихо́дилось ... вниз к реке́ за два киломе́тра.","b":1},{"t":"subhead","text":"Đáp án: тащи́ться (hoặc таска́ться)"},{"t":"para","text":"Dịch: Để lấy nước, (chúng tôi) đã phải lê bước (đi một cách vất vả) xuống tận bờ sông cách đó hai cây số."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Dùng тащи́ться (nguyên mẫu một chiều) để nhấn mạnh sự khó nhọc, mệt mỏi của quá trình đi đến đó (hướng cụ thể: xuống sông)."},{"t":"example","text":"Dùng таска́ться (nguyên mẫu đa chiều) nếu muốn nhấn mạnh sự lặp lại của việc phải đi đi về về vất vả này (приходилось chỉ sự lặp lại). Tuy nhiên, тащи́ться mang tính biểu cảm về sự \"lê bước\" mạnh hơn trong ngữ cảnh này."},{"t":"para","text":"7. Что ты постоя́нно ... с ним, как с ребёнком?","b":1},{"t":"subhead","text":"Đáp án: но́сишься","b":1},{"t":"para","text":"Dịch: Sao bạn cứ chăm bẵm/bận rộn với nó như với trẻ con thế?"},{"t":"example","text":"Giải thích: Dùng động từ đa chiều (носи́ться) với nghĩa bóng: bận rộn, lăng xăng, chăm chút quá mức. Từ постоя́нно (luôn luôn) cũng gợi ý dùng động từ đa chiều."},{"t":"vocab","ru":"О ко́мнату ... благоуха́ние сире́ни. (Lưu ý","vi":"Trong bản gốc sách bài tập câu này ở bài 591 phần 2 câu 6, ngữ cảnh hơi khác, tôi sẽ dịch theo bài tập trong ảnh số 311 mà bạn cung cấp - câu số 6 trong ảnh).","g":null},{"t":"example","text":"Chính xác từ ảnh 311: Из са́да ... благоуха́ние сире́ни."},{"t":"subhead","text":"Đáp án: несётся","b":1},{"t":"para","text":"Dịch: Hương thơm hoa tử đinh hương đang bay (lan tỏa) từ ngoài vườn vào."},{"t":"example","text":"Giải thích: Dùng động từ một chiều (нести́сь -> несётся) vì mùi hương đang di chuyển theo luồng gió từ vườn vào (hướng cụ thể)."},{"t":"para","text":"9. Во дворе́ ме́жду скаме́йками и маши́нами ... ребя́та, игра́я в каза́ки-разбо́йники.","b":1},{"t":"subhead","text":"Đáp án: но́сятся","b":1},{"t":"para","text":"Dịch: Ngoài sân, giữa những chiếc ghế băng và ô tô, lũ trẻ đang chạy nhảy (lao đi), chơi trò cảnh sát bắt cướp."},{"t":"example","text":"Giải thích: Dùng động từ đa chiều (носи́ться -> но́сятся) vì lũ trẻ chạy loạn xạ, không theo một hướng cố định (chơi đùa)."},{"t":"para","text":"10. Я не ... за успе́хом, для меня́ гла́вное, что́бы э́то де́ло бы́ло зако́нчено во́время.","b":1},{"t":"subhead","text":"Đáp án: гоню́сь","b":1},{"t":"para","text":"Dịch: Tôi không chạy theo thành công, đối với tôi điều chính là công việc này được hoàn thành đúng hạn."},{"t":"example","text":"Giải thích: Dùng động từ một chiều (гна́ться -> гоню́сь) trong nghĩa bóng \"theo đuổi mục tiêu\". (Lưu ý: Trong tiếng Nga, cụm \"chạy theo danh vọng/thành công\" thường dùng гна́ться để chỉ sự theo đuổi liên tục, miệt mài hướng tới mục đích)."},{"t":"para","text":"11. Це́лый день я ... за э́тим за́йцем по всему́ ле́су, а пойма́ть ника́к не могу́.","b":1},{"t":"subhead","text":"Đáp án: гоня́юсь","b":1},{"t":"para","text":"Dịch: Cả ngày nay tôi săn đuổi (chạy vòng vèo) con thỏ này khắp rừng mà mãi không bắt được."},{"t":"example","text":"Giải thích: Dùng động từ đa chiều (гоня́ться -> гоня́юсь) vì có cụm từ \"по всему́ ле́су\" (khắp rừng - không định hướng) và \"це́лый день\" (cả ngày - hành động lặp lại hoặc kéo dài liên tục nhiều hướng)."},{"t":"para","text":"12. Я ... за тобо́й по го́роду це́лый день, а ведь у меня́ и свои́ дела́ есть.","b":1},{"t":"subhead","text":"Đáp án: гоня́юсь","b":1},{"t":"para","text":"Dịch: Tôi chạy tìm (đuổi theo) bạn khắp thành phố cả ngày nay, mà tôi cũng có việc riêng của mình chứ."},{"t":"para","text":"Giải thích: Tương tự câu trên, \"по го́роду\" (khắp thành phố) và \"це́лый день\" yêu cầu động từ đa chiều."},{"t":"para","text":"13. Охо́та тебе́ ... бог зна́ет куда́! Сиде́л бы лу́чше до́ма.","b":1},{"t":"subhead","text":"Đáp án: тащи́ться","b":1},{"t":"para","text":"Dịch: Cậu thèm lê xác (đi) đến nơi khỉ ho cò gáy đấy làm gì! Thà ngồi nhà còn hơn."},{"t":"example","text":"Giải thích: Dùng nguyên mẫu một chiều (тащи́ться) để chỉ hành động đi đến một địa điểm cụ thể (dù xa xôi - бог знает куда). Từ này mang sắc thái biểu cảm: đi một cách vất vả, không muốn đi nhưng vẫn đi."}]},{"id":"07-s101","type":"exercise","title":"BÀI TẬP 592 (Trang 311)","num":592,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Xác định ý nghĩa của các động từ chuyển động được in đậm. Gọi tên động từ nguyên mẫu (infinitive) mà từ đó chúng được tạo thành."},{"t":"para","text":"Dịch và Giải chi tiết:","b":1},{"t":"para","text":"a) Câu 1:","b":1},{"t":"para","text":"Tiếng Nga: Когда́ я шёл домо́й, я встре́тил ста́рого дру́га. Вчера́ я ходи́л в теа́тр."},{"t":"example","text":"Tiếng Việt: Khi tôi đang đi (шёл) về nhà, tôi gặp một người bạn cũ. Hôm qua tôi đã đi (ходи́л) nhà hát."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"шёл (từ идти́ - một chiều)","vi":"Chỉ hành động đang diễn ra (quá trình) theo một hướng cụ thể (về nhà) thì có hành động khác xen vào.","g":null},{"t":"vocab","ru":"ходи́л (từ ходи́ть - đa chiều)","vi":"Chỉ hành động đã hoàn tất cả đi và về (khứ hồi) trong quá khứ.","g":null},{"t":"para","text":"a) Câu 2:","b":1},{"t":"para","text":"Tiếng Nga: Он бежа́л че́рез по́ле, не разбира́я доро́ги. Соба́ка бе́гала по двору́, пыта́ясь найти́ след хозя́ина."},{"t":"example","text":"Tiếng Việt: Anh ấy đã chạy (бежа́л) băng qua cánh đồng, không cần nhìn đường. Con chó đã chạy (бе́гала) quanh sân, cố gắng tìm dấu vết của chủ."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бежа́л (từ бежа́ть - một chiều)","vi":"Chạy theo một hướng (băng qua đồng).","g":null},{"t":"vocab","ru":"бе́гала (từ бе́гать - đa chiều)","vi":"Chạy lăng xăng, nhiều hướng (quanh sân).","g":null},{"t":"para","text":"a) Câu 3:","b":1},{"t":"para","text":"Tiếng Nga: Мы е́хали по шоссе́ на ю́го-за́пад. Ра́ньше я ча́сто е́здил в командиро́вки."},{"t":"example","text":"Tiếng Việt: Chúng tôi đang đi (xe) (е́хали) trên đường quốc lộ về hướng Tây Nam. Trước đây tôi thường xuyên đi (е́здил) công tác."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"е́хали (từ е́хать - một chiều)","vi":"Đang di chuyển theo một hướng cụ thể.","g":null},{"t":"vocab","ru":"е́здил (từ е́здить - đa chiều)","vi":"Hành động lặp lại nhiều lần trong quá khứ (ча́сто - thường xuyên).","g":null},{"t":"para","text":"a) Câu 4:","b":1},{"t":"para","text":"Tiếng Nga: Стра́нно, что мы не встре́тились, я лете́л э́тим же ре́йсом. В про́шлом году́ мы лета́ли в Испа́нию."},{"t":"example","text":"Tiếng Việt: Lạ thật, sao chúng ta không gặp nhau nhỉ, tôi đã bay (лете́л) cùng chuyến bay đó. Năm ngoái chúng tôi đã bay (đi) (лета́ли) Tây Ban Nha."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"лете́л (từ лете́ть - một chiều)","vi":"Chỉ việc di chuyển trên một chuyến bay cụ thể (một lần, một hướng).","g":null},{"t":"vocab","ru":"лета́ли (từ лета́ть - đa chiều)","vi":"Chỉ chuyến đi khứ hồi (đi rồi về) đã hoàn tất trong quá khứ.","g":null},{"t":"para","text":"a) Câu 5:","b":1},{"t":"para","text":"Tiếng Nga: Он плыл вперёд, не зна́я уста́лости. Год наза́д он пла́вал матро́сом на како́м-то торго́вом су́дне."},{"t":"example","text":"Tiếng Việt: Anh ấy đang bơi (плыл) về phía trước, không biết mệt mỏi. Một năm trước anh ấy đã đi tàu (làm thủy thủ) (пла́вал) trên một con tàu buôn nào đó."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"плыл (từ плыть - một chiều)","vi":"Đang bơi về một hướng (вперёд).","g":null},{"t":"vocab","ru":"пла́вал (từ пла́вать - đa chiều)","vi":"Chỉ hành động lặp lại, nghề nghiệp, hoặc đi lại nhiều lần trên biển.","g":null},{"t":"para","text":"a) Câu 6:","b":1},{"t":"para","text":"Tiếng Nga: Изря́дно уста́в, я брёл по доро́ге, не замеча́я ничего́ вокру́г. Ле́том мы ча́сто броди́ли по ле́су, собира́я грибы́ и я́годы."},{"t":"example","text":"Tiếng Việt: Mệt rã rời, tôi lê bước (брёл) trên đường, chẳng buồn để ý xung quanh. Mùa hè chúng tôi thường lang thang (броди́ли) trong rừng hái nấm và quả mọng."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"брёл (từ брести́ - một chiều)","vi":"Đi chậm chạp, mệt mỏi theo một hướng trên đường.","g":null},{"t":"vocab","ru":"броди́ли (từ броди́ть - đa chiều)","vi":"Đi lang thang không định hướng cụ thể trong rừng, lặp lại nhiều lần.","g":null},{"t":"para","text":"a) Câu 7:","b":1},{"t":"para","text":"Tiếng Nga: Ды́рка образова́лась, когда́ я лез че́рез забо́р и зацепи́лся за гвоздь. Обезья́нка ло́вко ла́зала по дере́вьям."},{"t":"example","text":"Tiếng Việt: Cái lỗ thủng xuất hiện khi tôi đang trèo (лез) qua hàng rào và bị móc vào cái đinh. Con khỉ leo trèo (ла́зала) thoăn thoắt trên cây."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"лез (từ лезть - một chiều)","vi":"Hành động leo qua một vật cản cụ thể tại một thời điểm.","g":null},{"t":"vocab","ru":"ла́зала (từ ла́зить - đa chiều)","vi":"Khả năng leo trèo hoặc hành động leo qua lại nhiều lần trên cây.","g":null},{"t":"para","text":"a) Câu 8:","b":1},{"t":"para","text":"Tiếng Nga: Я огляну́лся: ме́жду камня́ми бесшу́мно ползла́ змея́. Мы по́лзали по боло́ту среди́ высо́кой травы́, собира́я клю́кву."},{"t":"example","text":"Tiếng Việt: Tôi ngoảnh lại: một con rắn đang bò (ползла́) không tiếng động giữa những tảng đá. Chúng tôi đã bò (lê la) (по́лзали) trong đầm lầy giữa đám cỏ cao để hái nam việt quất."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"ползла́ (từ ползти́ - một chiều)","vi":"Con rắn đang di chuyển (bò) theo một hướng tại thời điểm nhìn thấy.","g":null},{"t":"vocab","ru":"по́лзали (từ по́лзать - đa chiều)","vi":"Hành động di chuyển chậm chạp, bò qua bò lại nhiều hướng trong khu vực đầm lầy.","g":null},{"t":"para","text":"b) Câu 1:","b":1},{"t":"para","text":"Tiếng Nga: В одно́й руке́ я нёс чемода́н, в друго́й — су́мку. Ве́тер носи́л тополи́ный пух по всему́ го́роду."},{"t":"example","text":"Tiếng Việt: Một tay tôi đang xách (нёс) vali, tay kia xách túi. Gió thổi bay (cuốn) (носи́л) hoa bồ công anh (phấn hoa dương) khắp thành phố."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"нёс (từ нести́ - một chiều)","vi":"Đang mang/xách vật đi theo một hướng.","g":null},{"t":"vocab","ru":"носи́л (từ носи́ть - đa chiều)","vi":"Gió cuốn đồ vật bay lung tung khắp nơi (по всему городу).","g":null},{"t":"para","text":"b) Câu 2:","b":1},{"t":"para","text":"Tiếng Nga: Он вёл её под ру́ку, отвеча́я на приве́тствия госте́й. Ле́том она́ рабо́тала в Городско́м экскурсио́нном бюро́, води́ла экску́рсии по Петропа́вловской кре́пости."},{"t":"example","text":"Tiếng Việt: Anh ấy đang dẫn (вёл) cô ấy (khoác tay) và đáp lại lời chào của khách. Mùa hè cô ấy làm việc ở Phòng du lịch thành phố, dẫn (води́ла) các đoàn tham quan pháo đài Peter và Paul."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"вёл (từ вести́ - một chiều)","vi":"Đang dẫn đi tại một thời điểm cụ thể.","g":null},{"t":"vocab","ru":"води́ла (từ води́ть - đa chiều)","vi":"Làm công việc dẫn tour, lặp đi lặp lại nhiều lần.","g":null},{"t":"para","text":"b) Câu 3:","b":1},{"t":"para","text":"Tiếng Nga: Парохо́д вёз груз для металлурги́ческого заво́да. Че́рез ре́ку мо́жно бы́ло перепра́виться на паро́ме, кото́рый ка́ждый час вози́л жи́телей дере́вни с одного́ бе́рега на друго́й."},{"t":"example","text":"Tiếng Việt: Con tàu đang chở (вёз) hàng cho nhà máy luyện kim. Có thể qua sông bằng phà, chiếc phà này chở (вози́л) dân làng từ bờ này sang bờ kia mỗi giờ."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"вёз (từ везти́ - một chiều)","vi":"Đang trong quá trình vận chuyển hàng (một chuyến).","g":null},{"t":"vocab","ru":"вози́л (từ вози́ть - đa chiều)","vi":"Chở đi chở lại lặp đi lặp lại theo lịch trình (mỗi giờ).","g":null},{"t":"para","text":"b) Câu 4:","b":1},{"t":"para","text":"Tiếng Nga: Ве́тер гнал ту́чи с мо́ря. За огоро́дом уха́живали всей семьёй: полива́ли его́, пропа́лывали, гоня́ли с него́ сосе́дских кур."},{"t":"example","text":"Tiếng Việt: Gió đang lùa/thổi (гнал) mây từ biển vào. Cả nhà cùng chăm sóc vườn rau: tưới nước, làm cỏ, đuổi (гоня́ли) gà hàng xóm ra khỏi đó."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"гнал (từ гнать - một chiều)","vi":"Gió lùa mây theo một hướng nhất định.","g":null},{"t":"vocab","ru":"гоня́ли (từ гоня́ть - đa chiều)","vi":"Đuổi gà (hành động lặp lại nhiều lần, hoặc đuổi chạy lung tung).","g":null},{"t":"para","text":"b) Câu 5:","b":1},{"t":"para","text":"Tiếng Nga: Чемода́н был тяжёлый, и я с трудо́м тащи́л его́ по ле́стнице на пя́тый эта́ж. По хозя́йству он де́лал всё, что прика́жут: руби́л дрова́, убира́л двор, таска́л во́ду из коло́дца."},{"t":"example","text":"Tiếng Việt: Cái vali nặng quá, và tôi vất vả lôi/kéo (тащи́л) nó lên cầu thang tầng 5. Anh ấy làm mọi việc nhà được sai bảo: chặt củi, dọn sân, xách/gánh (таска́л) nước từ giếng."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"тащи́л (từ тащи́ть - một chiều)","vi":"Đang lôi cái vali lên (hành động cụ thể, hướng lên trên).","g":null},{"t":"vocab","ru":"таска́л (từ таска́ть - đa chiều)","vi":"Xách nước (công việc lặp lại, đi từ giếng về nhà nhiều lần).","g":null},{"t":"para","text":"b) Câu 6:","b":1},{"t":"para","text":"Tiếng Nga: Впереди́ всех шёл малы́ш лет пяти́ с больши́м пластма́ссовым грузовико́м, кото́рый он кати́л за собо́й на верёвочке. Я хорошо́ по́мню, как в де́тстве оте́ц ката́л меня́ на ло́дке по о́зеру."},{"t":"example","text":"Tiếng Việt: Đi trước mọi người là một cậu bé khoảng 5 tuổi với chiếc xe tải nhựa lớn mà cậu đang kéo (lăn bánh) (кати́л) theo sau bằng sợi dây. Tôi nhớ rất rõ hồi nhỏ bố hay chở (ката́л) tôi đi thuyền trên hồ."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"кати́л (từ кати́ть - một chiều)","vi":"Đang kéo xe lăn bánh theo một hướng cụ thể (theo sau cậu bé).","g":null},{"t":"vocab","ru":"ката́л (từ ката́ть - đa chiều)","vi":"Chở đi chơi (hành động lặp lại trong quá khứ, đi vòng vòng trên hồ).","g":null},{"t":"para","text":"LÝ THUYẾT VÀ GỢI Ý NGỮ PHÁP (TRANG 312)","b":1},{"t":"para","text":"Trước khi vào bài 593, có một ô kiến thức quan trọng về cách dùng động từ chuyển động với các từ chỉ số lượng lần."},{"t":"example","text":"Nội dung trong khung (Tiếng Nga): С показа́телями кра́тности, отвеча́ющими на вопро́с ско́лько (раз)?: оди́н раз, не́сколько раз, два (три) ра́за, употребля́ются глаго́лы разнонапра́вленного движе́ния."},{"t":"example","text":"Dịch và giải thích (Tiếng Việt): Với các từ chỉ tần suất/số lần trả lời cho câu hỏi bao nhiêu (lần)?: một lần, vài lần, hai (ba) lần, ta sử dụng các động từ chuyển động đa chiều (nhóm ходи́ть, е́здить, носи́ть...)."},{"t":"example","text":"Lý do: Khi nói \"đi 2 lần\", nghĩa là đã có sự đi và về (khứ hồi) hoặc hành động đã lặp lại, nên phải dùng nhóm đa chiều."}]},{"id":"07-s179","type":"exercise","title":"BÀI TẬP 593 (TRANG 312)","num":593,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay dấu ba chấm bằng động từ chuyển động cần thiết ở thì quá khứ. Giải thích sự lựa chọn của bạn."},{"t":"para","text":"1. Когда́ я ... в руке́ большо́й паке́т, я встре́тил ста́рого дру́га.","b":1},{"t":"subhead","text":"Đáp án: нёс (từ нести́)"},{"t":"para","text":"Dịch: Khi tôi đang xách một cái túi lớn trên tay, tôi đã gặp một người bạn cũ."},{"t":"example","text":"Giải thích: Dùng động từ một chiều (нести́ → нёс) vì hành động \"xách\" đang diễn ra tại một thời điểm cụ thể (lúc gặp bạn) và theo một hướng."},{"t":"para","text":"2. Ка́ждый год я ... к роди́телям в Оренбу́рг. Не́которое вре́мя мы ... пря́мо, пото́м поверну́ли нале́во.","b":1},{"t":"subhead","text":"Đáp án: е́здил (từ е́здить); е́хали (từ е́хать)"},{"t":"para","text":"Dịch: Hàng năm tôi (thường) đi thăm bố mẹ ở Orenburg. (Lần đó), chúng tôi đang đi thẳng một lúc, sau đó rẽ trái."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Dùng е́здил (đa chiều) vì có từ ка́ждый год (hàng năm) chỉ sự lặp lại."},{"t":"example","text":"Vế 2: Dùng е́хали (một chiều) vì miêu tả quá trình di chuyển liên tục theo một hướng (thẳng) trước khi chuyển hướng."},{"t":"para","text":"3. Когда́ мы ... маши́ну осторо́жно, постоя́нно прислу́шиваясь к рабо́те мото́ра.","b":1},{"t":"subhead","text":"Đáp án: вели́ (từ вести́)"},{"t":"para","text":"Dịch: Khi đó chúng tôi đang lái xe một cách thận trọng, liên tục lắng nghe tiếng động cơ."},{"t":"example","text":"Giải thích: Dùng вели́ (một chiều) để miêu tả quá trình lái xe đang diễn ra tại thời điểm đó."},{"t":"para","text":"4. Когда́ де́ти бы́ли ещё ма́ленькими, я ча́сто ... их в зоопа́рк.","b":1},{"t":"subhead","text":"Đáp án: води́л (từ води́ть)"},{"t":"para","text":"Dịch: Khi lũ trẻ còn nhỏ, tôi thường xuyên dẫn chúng đi sở thú."},{"t":"example","text":"Giải thích: Dùng води́л (đa chiều) vì có từ ча́сто (thường xuyên) chỉ hành động lặp lại trong quá khứ."},{"t":"para","text":"5. Я уже́ два ра́за ... туда́ докуме́нты, и всё вре́мя мне говоря́т, что чего́-то в них хвата́ет.","b":1},{"t":"subhead","text":"Đáp án: носи́л (từ носи́ть)"},{"t":"para","text":"Dịch: Tôi đã mang hồ sơ đến đó hai lần rồi, và lần nào họ cũng bảo tôi là còn thiếu cái gì đó."},{"t":"example","text":"Giải thích: Dùng носи́л (đa chiều) vì có từ chỉ số lượng два ра́за (hai lần) – quy tắc trong khung ngữ pháp."},{"t":"para","text":"6. По коридо́рам из одно́й две́ри в другу́ю ... запыха́вшиеся сотру́дники.","b":1},{"t":"subhead","text":"Đáp án: бе́гали (từ бе́гать)"},{"t":"para","text":"Dịch: Các nhân viên hổ hển chạy đi chạy lại dọc theo hành lang từ cửa này sang cửa khác."},{"t":"example","text":"Giải thích: Dùng бе́гали (đa chiều) vì hành động chạy qua chạy lại, lăng xăng, không theo một đường thẳng duy nhất."},{"t":"para","text":"7. В про́шлом ме́сяце по́чту ... два ра́за в день, а в э́том ме́сяце — то́лько оди́н.","b":1},{"t":"subhead","text":"Đáp án: носи́ли (từ носи́ть)"},{"t":"para","text":"Dịch: Tháng trước người ta phát (mang) thư hai lần một ngày, còn tháng này – chỉ một lần."},{"t":"example","text":"Giải thích: Dùng носи́ли (đa chiều) vì hành động lặp lại theo lịch trình (hai lần một ngày)."},{"t":"para","text":"8. Ка́ждый раз, когда́ я её встреча́л, она́ ... за ру́ку де́вочку лет шести́.","b":1},{"t":"subhead","text":"Đáp án: вела́ (từ вести́)"},{"t":"para","text":"Dịch: Lần nào tôi gặp cô ấy, cô ấy cũng đang dắt một bé gái khoảng sáu tuổi."},{"t":"example","text":"Giải thích: Mặc dù có \"mỗi lần\", nhưng hành động \"dắt\" được miêu tả là đang diễn ra ngay tại khoảnh khắc \"tôi gặp\". Nó là bức tranh của thời điểm đó → dùng một chiều вела́. (Lưu ý: Nếu dùng водила thì mang nghĩa kể lại thói quen chung chung, nhưng trong ngữ cảnh \"gặp là thấy đang dắt\" thì вела chính xác hơn về mặt hình ảnh)."},{"t":"para","text":"9. Я два ра́за ... по э́той доро́ге, но не замеча́л э́того зна́ка.","b":1},{"t":"subhead","text":"Đáp án: е́здил (từ е́здить)"},{"t":"para","text":"Dịch: Tôi đã đi (xe) trên con đường này hai lần rồi, nhưng không để ý cái biển báo này."},{"t":"example","text":"Giải thích: Có từ два ра́за (hai lần) → dùng đa chiều е́здил."},{"t":"para","text":"10. Я бо́лее двадцати́ лет ... тури́стов на экскурсио́нном авто́бусе.","b":1},{"t":"subhead","text":"Đáp án: вози́л (từ вози́ть)"},{"t":"para","text":"Dịch: Tôi đã chở khách du lịch trên xe buýt tham quan hơn hai mươi năm rồi."},{"t":"example","text":"Giải thích: Chỉ nghề nghiệp, hành động lặp đi lặp lại trong thời gian dài → dùng đa chiều вози́л."},{"t":"para","text":"11. Мы ... по на́бережной, зате́м поверну́ли к университе́ту.","b":1},{"t":"subhead","text":"Đáp án: шли (từ идти́)"},{"t":"para","text":"Dịch: Chúng tôi đang đi (bộ) dọc bờ sông, sau đó rẽ về phía trường đại học."},{"t":"example","text":"Giải thích: Miêu tả quá trình đi theo một hướng trước khi rẽ → dùng một chiều шли."},{"t":"para","text":"12. На “Жигуля́х” я ... дово́льно до́лго и по́этому привы́к к э́той маши́не.","b":1},{"t":"subhead","text":"Đáp án: е́здил (từ е́здить)"},{"t":"para","text":"Dịch: Tôi đã đi (lái) chiếc \"Zhiguli\" khá lâu rồi nên quen với chiếc xe này."},{"t":"example","text":"Giải thích: Chỉ kinh nghiệm, quá trình tích lũy trong quá khứ, không phải một chuyến đi cụ thể → dùng đa chiều е́здил."}]},{"id":"07-s180","type":"exercise","title":"BÀI TẬP 594 (TRANG 313)","num":594,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay dấu ba chấm bằng động từ chuyển động cần thiết ở thì quá khứ. Giải thích sự lựa chọn của bạn."},{"t":"para","text":"1. Води́тель ... маши́ну на большо́й ско́рости, и её заноси́ло на поворо́тах.","b":1},{"t":"subhead","text":"Đáp án: вёл (từ вести́)"},{"t":"para","text":"Dịch: Người tài xế đang lái xe ở tốc độ cao, và xe bị trượt bánh ở các khúc cua."},{"t":"example","text":"Giải thích: Miêu tả hành động đang diễn ra cụ thể, liên tục điều khiển xe → dùng một chiều вёл."},{"t":"para","text":"2. Ве́тер ... по па́рку осе́нние ли́стья.","b":1},{"t":"subhead","text":"Đáp án: гоня́л (từ гоня́ть)"},{"t":"para","text":"Dịch: Gió thổi bay (lùa) lá thu khắp công viên."},{"t":"example","text":"Giải thích: Gió thổi lá bay tứ tung, không theo một hướng cố định (cụm từ по па́рку - quanh công viên) → dùng đa chiều гоня́л."},{"t":"para","text":"3. Зря ты волну́ешься, я ... на э́ти ска́лы уже́ не́сколько раз.","b":1},{"t":"subhead","text":"Đáp án: ла́зил (từ ла́зить)"},{"t":"para","text":"Dịch: Bạn lo lắng vô ích thôi, tôi đã leo lên những vách đá này vài lần rồi."},{"t":"example","text":"Giải thích: Có từ не́сколько раз (vài lần) → dùng đa chiều ла́зил."},{"t":"para","text":"4. В похо́де мой друг слома́л но́гу, и я ... его́ на себе́ не́сколько киломе́тров.","b":1},{"t":"subhead","text":"Đáp án: тащи́л (từ тащи́ть)"},{"t":"para","text":"Dịch: Trong chuyến dã ngoại bạn tôi bị gãy chân, và tôi đã cõng (lôi/kéo) cậu ấy trên lưng vài cây số."},{"t":"example","text":"Giải thích: Đây là một hành động cụ thể, diễn ra một lần, vất vả di chuyển từ điểm này đến điểm kia (dù khoảng cách dài) → dùng một chiều тащи́л."},{"t":"para","text":"5. Он до́лго боле́л и так обесси́лел, что е́ле но́ги ...","b":1},{"t":"subhead","text":"Đáp án: таска́л (từ таска́ть)"},{"t":"para","text":"Dịch: Anh ấy ốm lâu ngày và yếu đến mức lê bước không nổi (nghĩa đen: lê chân không nổi)."},{"t":"example","text":"Giải thích: Đây là thành ngữ \"еле ноги таскать\" (đi lại khó khăn, lặp đi lặp lại khả năng đi lại kém) → dùng đa chiều таска́л."},{"t":"para","text":"6. Авто́бус уже́ ... в сто́рону райце́нтра.","b":1},{"t":"subhead","text":"Đáp án: шёл (từ идти́)"},{"t":"para","text":"Dịch: Chiếc xe buýt đã đang đi về phía trung tâm huyện."},{"t":"example","text":"Giải thích: Xe buýt đang di chuyển theo một hướng xác định (в сто́рону...) → dùng một chiều шёл."},{"t":"para","text":"7. Он сиде́л за столо́м и ... ша́рики из хле́ба.","b":1},{"t":"subhead","text":"Đáp án: ката́л (từ ката́ть)"},{"t":"para","text":"Dịch: Anh ta ngồi bên bàn và vo (lăn) những viên bi từ ruột bánh mì."},{"t":"example","text":"Giải thích: Hành động vo tròn là chuyển động xoay tròn, không có hướng tịnh tiến cụ thể → dùng đa chiều ката́л."},{"t":"para","text":"8. Он до́лго ... в потёмках, пыта́ясь найти́ поте́рянную иго́лку.","b":1},{"t":"subhead","text":"Đáp án: по́лзал (từ по́лзать)"},{"t":"para","text":"Dịch: Anh ấy đã bò rất lâu trong bóng tối, cố gắng tìm cây kim bị mất."},{"t":"example","text":"Giải thích: Bò tìm kiếm lung tung khắp sàn nhà, không theo một đường thẳng → dùng đa chiều по́лзал."},{"t":"para","text":"9. Волна́ нака́тывала на бе́рег, омыва́я песо́к и ка́мни, и ме́дленно ... наза́д.","b":1},{"t":"subhead","text":"Đáp án: ползла́ (từ ползти́)"},{"t":"para","text":"Dịch: Sóng xô vào bờ, gột rửa cát và đá, rồi chầm chậm trườn (bò) trở lại."},{"t":"example","text":"Giải thích: Sóng rút về theo một hướng (ra biển) ngay lúc đó → dùng một chiều ползла́."},{"t":"para","text":"10. Он ... среди́ разва́лин до́ма, пыта́ясь отыска́ть хоть что́-нибудь, напомина́вшее о его́ пре́жней жи́зни.","b":1},{"t":"subhead","text":"Đáp án: броди́л (từ броди́ть)"},{"t":"para","text":"Dịch: Anh ấy lang thang giữa đống đổ nát của ngôi nhà, cố gắng tìm kiếm bất cứ thứ gì gợi nhớ về cuộc sống trước kia."},{"t":"example","text":"Giải thích: Đi lại không định hướng cụ thể trong một khu vực (среди́ разва́лин) → dùng đa chiều броди́л."},{"t":"para","text":"11. Весь день мы ... по доро́ге, наде́ясь, что нам встре́тится попу́тная маши́на.","b":1},{"t":"subhead","text":"Đáp án: брели́ (từ брести́)"},{"t":"para","text":"Dịch: Suốt cả ngày chúng tôi lê bước (đi rệu rã) trên đường, hy vọng sẽ gặp một chiếc xe đi cùng chiều."},{"t":"example","text":"Giải thích: Nhấn mạnh vào quá trình đi mệt mỏi, kéo dài theo con đường (hướng đi nhất định để mong gặp xe) → dùng một chiều брели́."},{"t":"para","text":"12. В го́лову мне ... ра́зные мы́сли.","b":1},{"t":"subhead","text":"Đáp án: ле́зли (từ лезть)"},{"t":"para","text":"Dịch: Những suy nghĩ khác nhau cứ len lỏi (chui) vào đầu tôi."},{"t":"example","text":"Giải thích: Đây là cách dùng nghĩa bóng. Suy nghĩ ập đến, đi vào đầu (hướng vào trong) → dùng một chiều ле́зли."},{"t":"para","text":"13. Со мной ничего́ не могло́ случи́ться, так как в пеще́ру я ... не оди́н, а со свои́ми друзья́ми-спелео́логами.","b":1},{"t":"subhead","text":"Đáp án: ла́зил (từ ла́зить)"},{"t":"para","text":"Dịch: Không thể có chuyện gì xảy ra với tôi được, vì tôi đã leo (đi thám hiểm) hang động không phải một mình, mà với các bạn là nhà hang động học."},{"t":"example","text":"Giải thích: Kể lại một sự kiện đã hoàn tất trong quá khứ (đã đi và đã về), mang tính trải nghiệm → dùng đa chiều ла́зил."},{"t":"para","text":"14. В де́тстве мы ча́сто игра́ли на стройплоща́дке, с кото́рой нас ... рабо́чие.","b":1},{"t":"subhead","text":"Đáp án: гоня́ли (từ гоня́ть)"},{"t":"para","text":"Dịch: Hồi nhỏ chúng tôi thường chơi ở công trường xây dựng, nơi mà các công nhân hay đuổi chúng tôi đi."},{"t":"example","text":"Giải thích: Hành động lặp lại nhiều lần trong quá khứ (thường chơi... hay đuổi) → dùng đa chiều гоня́ли."},{"t":"para","text":"15. Ты не ду́май, я его́ не ... , он сам ушёл.","b":1},{"t":"subhead","text":"Đáp án: гнал (từ гнать)"},{"t":"para","text":"Dịch: Bạn đừng nghĩ thế, tôi không hề đuổi nó, nó tự đi đấy chứ."},{"t":"example","text":"Giải thích: Phủ định hành động đuổi (cụ thể, cưỡng ép ai đó đi theo hướng khác ngay lúc đó) → dùng một chiều гнал (ý nói: tôi không thực hiện hành động xua đuổi đó)."},{"t":"vocab","ru":"В де́тстве я был таки́м же, как все мальчи́шки","vi":"... по забо́рам, ... голубе́й, ... я́блоки из сосе́дского са́да.","g":null},{"t":"subhead","text":"Đáp án: ла́зил (leo trèo); гоня́л (đuổi); таска́л (trộm/lôi)."},{"t":"para","text":"Dịch: Hồi nhỏ tôi cũng giống như bao thằng con trai khác: leo trèo hàng rào, đuổi chim bồ câu, trộm (hái trộm) táo trong vườn hàng xóm."},{"t":"example","text":"Giải thích: Tất cả đều là thói quen, sở thích lặp đi lặp lại trong thời thơ ấu → dùng nhóm đa chiều (ла́зить, гоня́ть, таска́ть)."},{"t":"vocab","ru":"Я ... на верши́ну горы́ и ду́мал","vi":"“Ну кто меня́ ... в таку́ю даль, заче́м я сюда́ прие́хал, заче́м ... деся́тки киломе́тров тяжёлый рюкза́к”.","g":null},{"t":"subhead","text":"Đáp án: лез (từ лезть); гнал (từ гнать); тащи́л (từ тащи́ть)."},{"t":"para","text":"Dịch: Tôi đang leo lên đỉnh núi và nghĩ: \"Ai đã xua (bắt) tôi đến nơi xa xôi thế này, tại sao tôi lại đến đây, tại sao tôi lại lôi (đeo) cái ba lô nặng trịch này suốt hàng chục cây số chứ\"."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"лез","vi":"Đang trong quá trình leo lên (một chiều).","g":null},{"t":"vocab","ru":"гнал","vi":"Nghĩa bóng (ai xui khiến/thúc ép), mang tính một chiều hướng tới đích đến này.","g":null},{"t":"vocab","ru":"тащи́л","vi":"Đang phải mang vác nặng nhọc trên đường đi (một chiều).","g":null},{"t":"subhead","text":"GỢI Ý NGỮ PHÁP (LÝ THUYẾT)","b":1},{"t":"para","text":"Trước khi làm bài 595, sách đưa ra một ô lưu ý ngữ pháp quan trọng ở trang 313 (ngay cạnh bài tập). Dưới đây là dịch và giải thích ô này:"},{"t":"example","text":"Tiếng Nga: В прида́точном вре́мени употребля́ются глаго́лы однонапра́вленного движе́ния, е́сли де́йствие гла́вной ча́сти происхо́дит в моме́нт э́того движе́ния: Когда́ мы е́хали в Москву́, мы встре́тили в по́езде знако́мого."},{"t":"example","text":"Глаголы разнонапра́вленного движе́ния, е́сли де́йствие гла́вной ча́сти охва́тывает бо́лее широ́кий промежу́ток вре́мени (ме́жду и́ли по́сле движе́ния): Когда́ мы е́здили в Москву́, мы покупа́ли биле́ты зара́нее."},{"t":"para","text":"Dịch & Giải thích:","b":1},{"t":"example","text":"Trong mệnh đề chỉ thời gian, ta dùng động từ chuyển động một chiều (идти́, е́хать, лете́ть...) nếu hành động của mệnh đề chính xảy ra ngay trong lúc quá trình di chuyển đó đang diễn ra (cắt ngang quá trình)."},{"t":"example","text":"Ví dụ: Khi chúng tôi đang đi (trên đường) đến Moscow (е́хали - một chiều), chúng tôi đã gặp người quen trên tàu."},{"t":"example","text":"Ta dùng động từ chuyển động đa chiều (ходи́ть, е́здить, лета́ть...) nếu hành động của mệnh đề chính bao trùm một khoảng thời gian rộng hơn (xảy ra giữa các chuyến đi hoặc là kết quả của cả chuyến đi đã hoàn tất)."},{"t":"example","text":"Ví dụ: Khi chúng tôi đi (đã từng đi) Moscow (е́здили - đa chiều, chỉ cả chuyến đi khứ hồi), chúng tôi đã mua vé trước."}]},{"id":"07-s102","type":"exercise","title":"BÀI TẬP 595 (Trang 313-314)","num":595,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay dấu ba chấm bằng động từ chuyển động cần thiết ở thì quá khứ. Giải thích lựa chọn của bạn."},{"t":"para","text":"1. Ава́рия произошла́ но́чью, когда́ он ... груз по го́рной доро́ге.","b":1},{"t":"subhead","text":"Đáp án: вёз (từ везти́)"},{"t":"para","text":"Dịch: Tai nạn đã xảy ra vào ban đêm, khi anh ấy đang chở hàng trên đường núi."},{"t":"example","text":"Giải thích: Tai nạn xảy ra cắt ngang quá trình vận chuyển đang diễn ra → Dùng động từ một chiều (везти́ → вёз)."},{"t":"para","text":"2. Он ..., и бы́ло заме́тно, что он слегка́ прихра́мывает на ле́вую но́гу. Когда́ он ... в бассе́йн, он встава́л в семь утра́ (идти́/ходи́ть).","b":1},{"t":"subhead","text":"Đáp án: шёл; ходи́л"},{"t":"para","text":"Dịch: Anh ấy đang đi, và có thể thấy rõ là anh ấy hơi khập khiễng chân trái. Khi anh ấy đi (thường đi) bơi, anh ấy thường dậy lúc bảy giờ sáng."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Miêu tả dáng đi cụ thể ngay tại thời điểm quan sát → Một chiều (шёл)."},{"t":"example","text":"Vế 2: Kể về thói quen lặp đi lặp lại trong quá khứ → Đa chiều (ходи́л)."},{"t":"para","text":"3. Когда́ в после́дний раз они ... в э́ту пеще́ру, они́ чуть не заблуди́лись. Он повреди́л себе́ но́гу, когда́ ... на де́рево (лезть/ла́зить).","b":1},{"t":"subhead","text":"Đáp án: ла́зили; лез"},{"t":"para","text":"Dịch: Lần cuối cùng họ leo (thám hiểm) cái hang này, họ suýt nữa thì bị lạc. Anh ấy đã làm đau chân mình khi đang leo lên cây."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: \"Lần cuối cùng\" nói về một sự kiện/chuyến đi đã hoàn thành (có đi có về) → Đa chiều (ла́зили)."},{"t":"example","text":"Vế 2: Tai nạn xảy ra trong quá trình đang leo lên (hành động cụ thể, hướng lên trên) → Một chiều (лез)."},{"t":"para","text":"4. Е́сли он когда́-нибудь ... маши́ну, ду́маю, он смо́жет бы́стро всё вспо́мнить. Е́сли он ... маши́ну в нетре́звом состоя́нии, неудиви́тельно, что его́ останови́л милиционе́р (вести́/води́ть).","b":1},{"t":"subhead","text":"Đáp án: води́л; вёл"},{"t":"para","text":"Dịch: Nếu anh ấy đã từng lái xe bao giờ (có kinh nghiệm), tôi nghĩ anh ấy sẽ nhớ lại nhanh thôi. Nếu anh ấy (lúc đó) đang lái xe trong tình trạng không tỉnh táo, thì chẳng ngạc nhiên khi cảnh sát chặn anh ấy lại."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Nói về kinh nghiệm chung chung, kỹ năng trong quá khứ → Đa chiều (води́л)."},{"t":"example","text":"Vế 2: Nói về hành động cụ thể đang diễn ra lúc bị cảnh sát chặn → Một chiều (вёл)."},{"t":"para","text":"5. Я вспо́мнил о твое́й про́сьбе, когда́ ... с рабо́ты. Когда́ я ... на рабо́ту, я возвраща́лся не ра́ньше семи́ часо́в (идти́/ходи́ть).","b":1},{"t":"subhead","text":"Đáp án: шёл; ходи́л"},{"t":"para","text":"Dịch: Tôi nhớ ra lời thỉnh cầu của bạn khi đang đi (bộ) từ chỗ làm về. (Hồi đó) khi tôi đi (đi làm), tôi thường trở về không sớm hơn bảy giờ."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Nhớ ra trong lúc đang đi (quá trình) → Một chiều (шёл)."},{"t":"example","text":"Vế 2: Chỉ thói quen, lặp đi lặp lại hàng ngày trong một giai đoạn → Đa chiều (ходи́л)."},{"t":"para","text":"6. Когда́ мы ... в Novosibírsk, мы сде́лали переса́дку в Минера́льных Во́дах. Когда́ мы ... в Novosibírsk с переса́дкой, мы никогда́ не остана́вливались в Минера́льных Во́дах бо́льше, чем на два часа́ (лете́ть/лета́ть).","b":1},{"t":"subhead","text":"Đáp án: лете́ли; лета́ли"},{"t":"para","text":"Dịch: Khi chúng tôi đang bay đến Novosibirsk (lần đó), chúng tôi đã quá cảnh ở Mineralnye Vody. (Thường thì) khi chúng tôi bay đến Novosibirsk có quá cảnh, chúng tôi chưa bao giờ dừng lại ở Mineralnye Vody quá hai tiếng."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Kể lại diễn biến của một chuyến đi cụ thể (quá trình) → Một chiều (лете́ли)."},{"t":"example","text":"Vế 2: Kể về kinh nghiệm/thói quen lặp lại nhiều lần (\"chưa bao giờ...\" ám chỉ nhiều lần bay) → Đa chiều (лета́ли)."},{"t":"para","text":"7. Е́сли я ... тяжёлые чемода́ны, я име́ю пра́во хотя́ бы на кратковре́менный о́тдых (нести́/носи́ть).","b":1},{"t":"subhead","text":"Đáp án: нёс (hoặc носил tùy ngữ cảnh, nhưng нёс phổ biến hơn ở đây)."},{"t":"para","text":"Dịch: Nếu tôi đã (vừa phải) xách những chiếc vali nặng, tôi có quyền nghỉ ngơi chốc lát chứ."},{"t":"example","text":"Giải thích: Nhấn mạnh vào quá trình mệt nhọc vừa diễn ra (một lần cụ thể) để đòi quyền nghỉ ngơi → Một chiều (нёс). (Nếu dùng носил sẽ mang nghĩa: Nếu tôi làm công việc khuân vác vali thường xuyên)."},{"t":"para","text":"8. Когда́ я ..., мне приходи́лось тренирова́ться по шесть часо́в в су́тки (бежа́ть/бе́гать).","b":1},{"t":"subhead","text":"Đáp án: бе́гал","b":1},{"t":"para","text":"Dịch: Khi tôi chạy (là vận động viên chạy), tôi đã phải tập luyện sáu tiếng một ngày."},{"t":"example","text":"Giải thích: Chỉ một giai đoạn dài trong quá khứ, hoạt động lặp đi lặp lại → Đa chiều (бе́гал)."},{"t":"para","text":"9. Когда́ мы ... в Бату́ми, я предвкуша́л экску́рсию в знамени́тый Ботани́ческий сад. Когда́ мы ... на о́стров Валаа́м, мы чуде́сно проводи́ли вре́мя (плыть/пла́вать).","b":1},{"t":"subhead","text":"Đáp án: плы́ли; пла́вали"},{"t":"para","text":"Dịch: Khi chúng tôi đang bơi (đi tàu) đến Batumi, tôi đã háo hức chờ đợi chuyến tham quan Vườn Bách thảo nổi tiếng. Khi chúng tôi đi (du lịch) đảo Valaam, chúng tôi đã có khoảng thời gian tuyệt vời."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Cảm giác háo hức xảy ra trong lúc đang đi trên tàu → Một chiều (плы́ли)."},{"t":"example","text":"Vế 2: Tổng kết lại cả chuyến đi (đã đi và tận hưởng) → Đa chiều (пла́вали)."},{"t":"para","text":"10. В про́шлый раз, когда́ мы ... по го́рной доро́ге, кому́-то из пассажи́ров ста́ло пло́хо. Когда́ мы ... в Крым про́шлым ле́том, мы хорошо́ отдохну́ли (е́хать/е́здить).","b":1},{"t":"subhead","text":"Đáp án: е́хали; е́здили"},{"t":"para","text":"Dịch: Lần trước, khi chúng tôi đang đi trên đường núi, có hành khách đã bị mệt. Khi chúng tôi đi (nghỉ mát) ở Crimea hè năm ngoái, chúng tôi đã nghỉ ngơi rất tốt."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Sự việc \"bị mệt\" xảy ra trong lúc xe đang chạy → Một chiều (е́хали)."},{"t":"example","text":"Vế 2: Kể về trọn vẹn chuyến đi đã qua → Đa chiều (е́здили)."},{"t":"para","text":"11. Е́сли я ... в магази́н и убира́л кварти́ру, ты до́лжен пригото́вить обе́д и вы́мыть посу́ду. Е́сли мы ... стро́го на ю́го-за́пад, как мы могли́ оказа́ться в э́том ме́сте (идти́/ходи́ть).","b":1},{"t":"subhead","text":"Đáp án: ходи́л; шли"},{"t":"para","text":"Dịch: Nếu tôi đã đi chợ và dọn nhà (làm xong rồi), thì bạn phải nấu cơm và rửa bát. Nếu chúng tôi đang đi chính xác về hướng Tây Nam, thì sao chúng tôi lại có thể lạc vào chỗ này được?"},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Đã đi và đã về (hoàn thành việc đi chợ) → Đa chiều (ходи́л)."},{"t":"example","text":"Vế 2: Nhấn mạnh hướng di chuyển trong quá trình đi → Một chiều (шли)."}]},{"id":"07-s103","type":"exercise","title":"BÀI TẬP 596 (Trang 314-315)","num":596,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay dấu ba chấm bằng động từ chuyển động cần thiết ở thì quá khứ. Giải thích lựa chọn của bạn."},{"t":"para","text":"1. Тебя́ останови́ли, потому́ что ты ... на кра́сный свет.","b":1},{"t":"subhead","text":"Đáp án: шёл (từ идти́)"},{"t":"para","text":"Dịch: Bạn bị chặn lại vì bạn đang đi (băng qua đường) khi đèn đỏ."},{"t":"para","text":"Giải thích: Hành động vi phạm xảy ra trong quá trình di chuyển cụ thể → Một chiều."},{"t":"para","text":"2. Когда́ я ... дете́й гуля́ть, мы ча́сто заходи́ли в кафе́-моро́женое.","b":1},{"t":"subhead","text":"Đáp án: води́л (từ води́ть)"},{"t":"para","text":"Dịch: Khi tôi dẫn bọn trẻ đi dạo, chúng tôi thường ghé vào quán kem."},{"t":"example","text":"Giải thích: Có từ ча́сто (thường xuyên) chỉ hành động lặp lại → Đa chiều."},{"t":"para","text":"3. Когда́ он ..., он имел привы́чку разма́хивать рука́ми.","b":1},{"t":"subhead","text":"Đáp án: ходи́л (từ ходи́ть)"},{"t":"para","text":"Dịch: Khi anh ấy đi lại/bước đi, anh ấy có thói quen vung tay."},{"t":"para","text":"Giải thích: Nói về thói quen, dáng đi chung chung của một người → Đa chiều."},{"t":"para","text":"4. Е́сли в тот ве́чер он ... маши́ну осторо́жно, с ним ничего́ не могло́ случи́ться.","b":1},{"t":"subhead","text":"Đáp án: вёл (từ вести́)"},{"t":"para","text":"Dịch: Nếu tối hôm đó anh ấy lái xe cẩn thận, thì đã chẳng có chuyện gì xảy ra với anh ấy."},{"t":"example","text":"Giải thích: Nói về một lần cụ thể (tối hôm đó) và quá trình điều khiển xe → Một chiều."},{"t":"para","text":"5. В про́шлом году́, когда́ мы ... с ю́га, мы познако́мились с о́чень интере́сными людьми́.","b":1},{"t":"subhead","text":"Đáp án: е́хали (từ е́хать)"},{"t":"para","text":"Dịch: Năm ngoái, khi chúng tôi đang đi (trở về) từ phương Nam, chúng tôi đã làm quen với những người rất thú vị."},{"t":"example","text":"Giải thích: Làm quen trong lúc đang đi trên tàu/xe → Một chiều."},{"t":"para","text":"6. Нам помо́г води́тель маши́ны, кото́рая ... за на́ми.","b":1},{"t":"subhead","text":"Đáp án: е́хала (từ е́хать)"},{"t":"para","text":"Dịch: Người tài xế của chiếc xe đang chạy phía sau chúng tôi đã giúp chúng tôi."},{"t":"para","text":"Giải thích: Chiếc xe đang di chuyển cùng chiều tại thời điểm đó → Một chiều."},{"t":"para","text":"7. Я задержа́лся, потому́ что ... на ры́нок пешко́м.","b":1},{"t":"subhead","text":"Đáp án: ходи́л (từ ходи́ть)"},{"t":"para","text":"Dịch: Tôi bị muộn vì tôi đã đi (bộ) ra chợ."},{"t":"para","text":"Giải thích: Nghĩa là tôi đã đi đến chợ và đã quay lại (khứ hồi) nên mới mất thời gian → Đa chiều."},{"t":"para","text":"8. Е́сли вы ... сюда́ на по́езде, у вас должны́ сохрани́ться биле́ты.","b":1},{"t":"subhead","text":"Đáp án: е́хали (từ е́хать)"},{"t":"para","text":"Dịch: Nếu các bạn đã đi (đến đây) bằng tàu hỏa, các bạn chắc vẫn còn giữ vé."},{"t":"example","text":"Giải thích: Mặc dù đã đến nơi, nhưng câu này nhấn mạnh vào phương thức di chuyển của chuyến đi cụ thể đó (\"đi bằng tàu\" chứ không phải bay). Trong ngữ cảnh \"nếu bạn đã dùng tàu để đến đây\", người Nga thường dùng ехали để chỉ chuyến đi một chiều tới đích. (Tuy nhiên, ездили cũng không sai hoàn toàn nếu ý là \"đã thực hiện chuyến đi\", nhưng ехали tự nhiên hơn khi nói về phương tiện cho chuyến đi tới hiện tại)."},{"t":"para","text":"9. У меня́ не́ было морско́й боле́зни, так как к э́тому вре́мени я уже́ давно́ ... на корабле́.","b":1},{"t":"subhead","text":"Đáp án: пла́вал (từ пла́вать)"},{"t":"para","text":"Dịch: Tôi không bị say sóng, vì tính đến lúc đó tôi đã đi tàu (hoạt động hàng hải) từ lâu rồi (quen rồi)."},{"t":"para","text":"Giải thích: Chỉ kinh nghiệm, thói quen tích lũy lâu dài → Đa chiều."},{"t":"para","text":"10. Е́сли ты ... кота́ в корзи́нке, накры́той се́ткой, он не мог убежа́ть.","b":1},{"t":"subhead","text":"Đáp án: вёз (từ везти́)"},{"t":"para","text":"Dịch: Nếu bạn đang chở con mèo trong cái giỏ đậy lưới, thì nó không thể chạy thoát được."},{"t":"para","text":"Giải thích: Giả định về tình trạng vận chuyển cụ thể tại thời điểm đó → Một chiều."},{"t":"para","text":"11. Пока́ ты ... в университе́т, тебе́ звони́ли.","b":1},{"t":"subhead","text":"Đáp án: шёл (từ идти́)"},{"t":"para","text":"Dịch: Trong lúc bạn đang đi đến trường đại học, có người gọi cho bạn đấy."},{"t":"para","text":"Giải thích: Hành động gọi điện xảy ra song song với quá trình đi → Một chiều."},{"t":"para","text":"12. Такси́ст, кото́рый ... меня́ в аэропо́рт, рассказа́л мне о́чень интере́сную исто́рию.","b":1},{"t":"subhead","text":"Đáp án: вёз (từ везти́)"},{"t":"para","text":"Dịch: Người tài xế taxi, người đang chở tôi ra sân bay, đã kể cho tôi một câu chuyện rất thú vị."},{"t":"para","text":"Giải thích: Kể chuyện trong lúc đang chở (quá trình) → Một chiều."},{"t":"para","text":"13. Ви́димо, я урони́л записну́ю кни́жку, когда́ ... ве́щи до маши́ны.","b":1},{"t":"subhead","text":"Đáp án: нёс (từ нести́)"},{"t":"para","text":"Dịch: Có lẽ tôi đã đánh rơi cuốn sổ tay khi đang xách đồ ra xe."},{"t":"para","text":"Giải thích: Đánh rơi trong quá trình mang vác cụ thể → Một chiều."},{"t":"para","text":"14. Е́сли ты ... по доро́ге и Андре́й то́же, как же ты с ним не встре́тился?","b":1},{"t":"subhead","text":"Đáp án: шёл (từ идти́)"},{"t":"para","text":"Dịch: Nếu bạn đang đi trên đường và Andrey cũng thế, thì sao bạn lại không gặp cậu ấy nhỉ?"},{"t":"para","text":"Giải thích: Cả hai cùng đang di chuyển trên một con đường (quá trình) → Một chiều."},{"t":"para","text":"15. Когда́ я ... в шко́лу, я занима́лся те́ннисом.","b":1},{"t":"subhead","text":"Đáp án: ходи́л (từ ходи́ть)"},{"t":"para","text":"Dịch: Hồi tôi đi học (thời đi học), tôi có chơi quần vợt."},{"t":"para","text":"Giải thích: \"Đi học\" ở đây chỉ một giai đoạn dài trong cuộc đời, hành động lặp lại hàng ngày → Đa chiều."},{"t":"para","text":"16. Коне́чно, он уста́л, е́сли ... сюда́ всю ночь на маши́не.","b":1},{"t":"subhead","text":"Đáp án: е́хал (từ е́хать)"},{"t":"para","text":"Dịch: Đương nhiên là anh ấy mệt rồi, nếu anh ấy đã lái xe/đi xe đến đây suốt cả đêm."},{"t":"example","text":"Giải thích: Nhấn mạnh quá trình di chuyển kéo dài liên tục (suốt cả đêm) theo một hướng đến đích → Một chiều."},{"t":"para","text":"17. Когда́ я ... из магази́на, я встре́тил на́шего сосе́да из пя́той кварти́ры.","b":1},{"t":"subhead","text":"Đáp án: шёл (từ идти́)"},{"t":"para","text":"Dịch: Khi tôi đang đi từ cửa hàng ra, tôi gặp ông hàng xóm ở căn hộ số 5."},{"t":"para","text":"Giải thích: Gặp nhau giữa đường (quá trình) → Một chiều."},{"t":"para","text":"18. Мы опозда́ли из-за того́, что ты ... о́чень ме́дленно.","b":1},{"t":"subhead","text":"Đáp án: шёл (từ идти́)"},{"t":"para","text":"Dịch: Chúng ta bị muộn là do bạn đã đi chậm quá đấy."},{"t":"para","text":"Giải thích: Nhấn mạnh tốc độ của quá trình di chuyển cụ thể vừa diễn ra → Một chiều."},{"t":"para","text":"19. Пока́ ты ... на заня́тия, я успе́л съе́здить на вокза́л и купи́ть биле́ты.","b":1},{"t":"subhead","text":"Đáp án: ходи́л (từ ходи́ть) hoặc был (đã ở)."},{"t":"para","text":"Dịch: Trong lúc bạn đi học (đi đến trường, học, rồi về hoặc đang ở trường), tôi đã kịp chạy ra ga mua vé."},{"t":"example","text":"Giải thích: Ở đây dùng ходи́л với ý nghĩa \"vắng mặt vì đi đâu đó\". Nghĩa là trong khoảng thời gian bạn \"đi học\" (bao gồm cả đi, ở đó, và có thể là về), tôi đã làm được việc khác. (Nếu dùng шёл thì chỉ là trong mấy chục phút bạn đi bộ đến trường thôi, thường không đủ để tôi làm việc khác)."},{"t":"para","text":"20. Я не смог с ней поговори́ть, так как в э́то вре́мя она́ ... экску́рсию.","b":1},{"t":"subhead","text":"Đáp án: вела́ (từ вести́)"},{"t":"para","text":"Dịch: Tôi không thể nói chuyện với cô ấy, vì lúc đó cô ấy đang dẫn đoàn tham quan."},{"t":"para","text":"Giải thích: Cô ấy đang bận rộn với hành động dẫn tour ngay lúc đó → Một chiều."},{"t":"subhead","text":"GỢI Ý NGỮ PHÁP (LÝ THUYẾT VỀ TƯƠNG LAI)","b":1},{"t":"para","text":"Phần này dựa trên nội dung ngữ pháp trang 315 (phía trên bài 597) về Động từ chuyển động ở thì Tương lai."},{"t":"para","text":"Để làm đúng hai bài này, học sinh cần phân biệt được 3 dạng tương lai của động từ chuyển động:"},{"t":"example","text":"1. Tương lai đơn (Simple Future) - Nhóm một chiều có tiền tố по-","b":1},{"t":"subhead","text":"Cấu trúc: пойду́, пое́ду, полечу́..."},{"t":"para","text":"Ý nghĩa: Chỉ một hành động cụ thể sẽ xảy ra, nhấn mạnh vào kết quả hoặc sự khởi hành (bắt đầu đi)."},{"t":"example","text":"Ví dụ: За́втра я пое́ду в Москву́. (Ngày mai tôi sẽ đi Moscow - đi cụ thể 1 lần)."},{"t":"example","text":"2. Tương lai phức (Compound Future) - Nhóm một chiều (идти́, е́хать...)","b":1},{"t":"subhead","text":"Cấu trúc: бу́ду + Động từ nguyên mẫu một chiều (бу́ду идти́, бу́ду е́хать...)"},{"t":"para","text":"Ý nghĩa: Nhấn mạnh vào quá trình di chuyển sẽ đang diễn ra tại một thời điểm trong tương lai."},{"t":"example","text":"Ví dụ: В 5 часо́в я бу́ду е́хать в по́езде. (Lúc 5 giờ tôi sẽ đang đi trên tàu)."},{"t":"example","text":"3. Tương lai phức (Compound Future) - Nhóm đa chiều (ходи́ть, е́здить...)","b":1},{"t":"subhead","text":"Cấu trúc: бу́ду + Động từ nguyên mẫu đa chiều (бу́ду ходи́ть, бу́ду е́здить...)"},{"t":"para","text":"Ý nghĩa: Chỉ hành động lặp đi lặp lại, thói quen, hoặc đi khứ hồi trong tương lai."},{"t":"example","text":"Ví dụ: Ле́том я бу́ду е́здить на да́чу ка́ждый день. (Mùa hè ngày nào tôi cũng sẽ đi ra nhà dã ngoại)."}]},{"id":"07-s104","type":"exercise","title":"BÀI TẬP 597 (Trang 315)","num":597,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Xác định ý nghĩa của các động từ chuyển động trong thì tương lai. Gọi tên động từ nguyên mẫu mà từ đó chúng được tạo thành."},{"t":"para","text":"Giải thích và Dịch chi tiết:","b":1},{"t":"para","text":"a) Câu 1:","b":1},{"t":"para","text":"Tiếng Nga: Когда́ я бу́ду идти́ домо́й, я постара́юсь зайти́ на по́чту. Когда́ я бу́ду ходи́ть на рабо́ту, у меня́ совсе́м не оста́нется вре́мени на баскетбо́л."},{"t":"example","text":"Tiếng Việt: Khi tôi đang đi (бу́ду идти́) về nhà, tôi sẽ cố gắng ghé vào bưu điện. (Sau này) khi tôi đi (бу́ду ходи́ть) làm, tôi sẽ chẳng còn tí thời gian nào cho bóng rổ nữa."},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́ду идти́ (từ идти́)","vi":"Nhấn mạnh quá trình đang diễn ra trên đường về nhà (một lần cụ thể) thì ghé bưu điện.","g":null},{"t":"vocab","ru":"бу́ду ходи́ть (từ ходи́ть)","vi":"Chỉ thói quen/lặp lại hàng ngày trong tương lai (khi bắt đầu đi làm thường xuyên).","g":null},{"t":"para","text":"a) Câu 2:","b":1},{"t":"para","text":"Tiếng Nga: Не беспоко́йся, я бу́ду бежа́ть о́чень бы́стро и успе́ю во́время. Ты бу́дешь бе́гать по утра́м?"},{"t":"example","text":"Tiếng Việt: Đừng lo, tôi sẽ chạy (бу́ду бежа́ть) rất nhanh (đang trong quá trình chạy) và sẽ kịp giờ. Bạn sẽ (có) chạy bộ (бу́дешь бе́гать) vào các buổi sáng không?"},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́ду бежа́ть (từ бежа́ть)","vi":"Nhấn mạnh quá trình di chuyển cụ thể sắp tới để đạt mục đích kịp giờ.","g":null},{"t":"vocab","ru":"бу́дешь бе́гать (từ бе́гать)","vi":"Hỏi về thói quen lặp lại (vào các buổi sáng).","g":null},{"t":"para","text":"a) Câu 3:","b":1},{"t":"example","text":"Tiếng Nga: Ле́том мы ча́сто бу́дем броди́ть по ле́су. 7. Не беспоко́йся, я бу́ду лезть осторо́жно. Заче́м я бу́ду ла́зать по дере́вьям? Lưu ý: Sách gốc có thể đánh số nhảy hoặc gộp câu, mình dịch theo mạch văn."},{"t":"example","text":"Tiếng Việt: Mùa hè chúng tôi sẽ thường xuyên lang thang (бу́дем броди́ть) trong rừng. Đừng lo, tôi sẽ leo (бу́ду лезть) một cách cẩn thận. Tôi leo trèo (бу́ду ла́зать) cây làm cái gì chứ?"},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́дем броди́ть (từ броди́ть - đa chiều)","vi":"Đi lang thang không định hướng, lặp lại nhiều lần (thường xuyên).","g":null},{"t":"vocab","ru":"бу́ду лезть (từ лезть - một chiều)","vi":"Nhấn mạnh quá trình leo cụ thể đang diễn ra (để trấn an người khác là sẽ cẩn thận).","g":null},{"t":"vocab","ru":"бу́ду ла́зать (từ ла́зить - đa chiều)","vi":"Nói về hành động leo trèo nói chung, sở thích hoặc thói quen.","g":null},{"t":"para","text":"b) Câu 1:","b":1},{"t":"para","text":"Tiếng Nga: Вы меня́ сра́зу узна́ете: в одно́й руке́ я бу́ду нести́ газе́ту. Со сле́дующей неде́ли почтальо́н бу́дет носи́ть по́чту два ра́за в день."},{"t":"example","text":"Tiếng Việt: Bạn sẽ nhận ra tôi ngay: (lúc đó) một tay tôi sẽ đang cầm/xách (бу́ду нести́) tờ báo. Từ tuần sau người đưa thư sẽ mang (бу́дет носи́ть) thư hai lần một ngày."},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́ду нести́ (từ нести́)","vi":"Miêu tả trạng thái/quá trình cụ thể tại thời điểm gặp mặt.","g":null},{"t":"vocab","ru":"бу́дет носи́ть (từ носи́ть)","vi":"Hành động lặp lại theo lịch trình (hai lần một ngày).","g":null},{"t":"para","text":"b) Câu 2:","b":1},{"t":"para","text":"Tiếng Nga: Бою́сь, что не смогу́ приня́ть уча́стие в ва́шем ве́чере, так как в э́то вре́мя ко мне должны́ прие́хать го́сти, кото́рых я бу́ду води́ть по музе́ям."},{"t":"example","text":"Tiếng Việt: E là tôi không thể tham gia buổi tiệc của các bạn, vì lúc đó khách khứa sẽ đến chỗ tôi, những người mà tôi sẽ dẫn (бу́ду води́ть) đi các bảo tàng."},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́ду води́ть (từ води́ть - đa chiều)","vi":"Dẫn đi tham quan nhiều nơi, đi vòng vòng (hành động hướng dẫn viên du lịch hoặc chủ nhà dẫn khách đi chơi).","g":null},{"t":"para","text":"b) Câu 3:","b":1},{"t":"para","text":"Tiếng Nga: Не беспоко́йся, бью́щиеся предме́ты я не бу́ду везти́ в бага́жнике. Что́бы успе́ть во́время, я бу́ду гнать маши́ну без остано́вок."},{"t":"example","text":"Tiếng Việt: Đừng lo, đồ dễ vỡ tôi sẽ không chở (не бу́ду везти́) trong cốp xe đâu. Để kịp giờ, tôi sẽ lái (phi) (бу́ду гнать) xe không nghỉ."},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́ду везти́ (từ везти́)","vi":"Nói về quá trình vận chuyển cụ thể của chuyến đi đó.","g":null},{"t":"vocab","ru":"бу́ду гнать (từ гнать)","vi":"Nhấn mạnh cường độ/quá trình lái xe nhanh, liên tục theo một hướng về đích.","g":null},{"t":"para","text":"b) Câu 4:","b":1},{"t":"para","text":"Tiếng Nga: Ле́том я пое́ду к ба́бушке в дере́вню, бу́ду гоня́ть на велосипе́де. Чемода́н тяжёлый, я бу́ду тащи́ть его́ по земле́."},{"t":"example","text":"Tiếng Việt: Mùa hè tôi sẽ về quê thăm bà, tôi sẽ chạy (đua/lượn) (бу́ду гоня́ть) xe đạp. Cái vali nặng quá, tôi sẽ (phải) kéo lê (бу́ду тащи́ть) nó trên mặt đất."},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́ду гоня́ть (từ гоня́ть)","vi":"Chạy xe đạp chơi bời, lượn lờ (không hướng cụ thể, lặp lại).","g":null},{"t":"vocab","ru":"бу́ду тащи́ть (từ тащи́ть)","vi":"Nhấn mạnh sự vất vả của quá trình di chuyển cái vali ngay lúc đó.","g":null},{"t":"para","text":"b) Câu 5:","b":1},{"t":"para","text":"Tiếng Nga: Дава́й сде́лаем так: снача́ла я ся́ду на вёсла и бу́ду ката́ть тебя́ на ло́дке, а пото́м ты."},{"t":"example","text":"Tiếng Việt: Chúng ta làm thế này nhé: đầu tiên tớ sẽ ngồi chèo và sẽ chở (бу́ду ката́ть) cậu đi thuyền, sau đó đến lượt cậu."},{"t":"para","text":"Phân tích:","b":1},{"t":"vocab","ru":"бу́ду ката́ть (từ ката́ть)","vi":"Chở đi chơi, đi vòng vòng trên mặt nước (không phải đi từ A đến B để vận chuyển).","g":null}]},{"id":"07-s105","type":"exercise","title":"BÀI TẬP 598 (Trang 316)","num":598,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay thế dấu ba chấm bằng động từ chuyển động cần thiết ở thì tương lai. Giải thích lựa chọn của bạn."},{"t":"para","text":"1. Бою́сь, я ... до́лго и не успе́ю верну́ться до 7 часо́в.","b":1},{"t":"subhead","text":"Đáp án: бу́ду идти́ (hoặc бу́ду е́хать tùy phương tiện, nhưng ngữ cảnh đi lâu thường dùng идти)."},{"t":"para","text":"Dịch: E là tôi sẽ đi (đang đi) lâu và không kịp về trước 7 giờ."},{"t":"example","text":"Giải thích: Từ до́лго (lâu) chỉ độ dài thời gian của quá trình di chuyển → dùng Tương lai phức của động từ một chiều (идти́) để nhấn mạnh quá trình kéo dài gây muộn giờ."},{"t":"para","text":"2. Не волну́йся, я ... её о́чень осторо́жно.","b":1},{"t":"subhead","text":"Đáp án: бу́ду вести́ (lái xe/dắt tay)."},{"t":"para","text":"Dịch: Đừng lo, tôi sẽ lái/dắt nó rất cẩn thận."},{"t":"example","text":"Giải thích: Осторо́жно (cẩn thận) miêu tả cách thức thực hiện hành động trong suốt quá trình di chuyển → dùng Tương lai phức một chiều (вести́) để nhấn mạnh vào quá trình lái/dắt."},{"t":"para","text":"3. Тот, кто ... на́шу делега́цию, ещё не прие́хал.","b":1},{"t":"subhead","text":"Đáp án: бу́дет возглавля́ть (sẽ dẫn đầu/lãnh đạo - nghĩa bóng) hoặc бу́дет вести́ (sẽ dẫn đường)."},{"t":"note","text":"Lưu ý: Trong ngữ cảnh bài tập về động từ chuyển động, nếu ý là \"dẫn đoàn\" đi lại, dùng бу́дет води́ть (nhiệm vụ xuyên suốt) hoặc поведёт (hành động cụ thể). Tuy nhiên, câu này có vẻ nằm trong ngữ cảnh một người chịu trách nhiệm. Nếu xét về động từ chuyển động thuần túy: \"Người mà sẽ dẫn (бу́дет вести́ / поведёт) đoàn chúng ta...\". Nếu là nhiệm vụ lâu dài trong chuyến đi: бу́дет води́ть."},{"t":"para","text":"Giải thích: Dựa vào các câu khác, có lẽ đáp án mong đợi là бу́дет вести́ (người sẽ phụ trách dẫn đi - quá trình hoặc tương lai gần) hoặc бу́дет води́ть (nếu là hướng dẫn viên trong nhiều ngày)."},{"t":"para","text":"4. До по́чты я ... мину́т пятна́дцать.","b":1},{"t":"subhead","text":"Đáp án: бу́ду идти́","b":1},{"t":"para","text":"Dịch: Tôi sẽ đi (mất) khoảng 15 phút để đến bưu điện."},{"t":"example","text":"Giải thích: Chỉ khoảng thời gian (15 phút) để thực hiện quá trình di chuyển một chiều đến đích → бу́ду идти́."},{"t":"para","text":"5. Ты ... ещё не́сколько мину́т, пока́ не раскро́ется парашю́т.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь лете́ть","b":1},{"t":"para","text":"Dịch: Bạn sẽ bay (rơi) thêm vài phút nữa cho đến khi dù mở."},{"t":"example","text":"Giải thích: Chỉ quá trình rơi tự do/bay đang diễn ra trong một khoảng thời gian (несколько минут) → Tương lai phức một chiều (лете́ть)."},{"t":"para","text":"6. За́втра с десяти́ до ча́су я ... экску́рсии по па́рку.","b":1},{"t":"subhead","text":"Đáp án: бу́ду води́ть","b":1},{"t":"para","text":"Dịch: Ngày mai từ 10 giờ đến 1 giờ tôi sẽ dẫn các đoàn tham quan quanh công viên."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Thứ 1: Có khoảng thời gian dài (từ 10h đến 1h)."},{"t":"example","text":"Thứ 2: \"Các đoàn tham quan\" (số nhiều) và \"quanh công viên\" (по парку - không định hướng thẳng)."},{"t":"example","text":"→ Dùng động từ đa chiều (води́ть) ở tương lai phức."},{"t":"para","text":"7. Мы ... ме́дленно, что́бы ты смогла́ нас догна́ть.","b":1},{"t":"subhead","text":"Đáp án: бу́дем идти́","b":1},{"t":"para","text":"Dịch: Chúng tôi sẽ đi chậm thôi để bạn có thể đuổi kịp."},{"t":"example","text":"Giải thích: Ме́дленно (chậm) chỉ tốc độ của quá trình di chuyển đang diễn ra → Tương lai phức một chiều (идти́)."},{"t":"para","text":"8. Про́сто не ве́рится, что за́втра мы ... за ва́шим су́дном (плыть/пла́вать).","b":1},{"t":"subhead","text":"Đáp án: бу́дем плыть","b":1},{"t":"para","text":"Dịch: Thật không thể tin là ngày mai chúng tôi sẽ đang bơi/đi tàu theo sau con tàu của các bạn."},{"t":"example","text":"Giải thích: За вашим судном (theo sau tàu của bạn) là di chuyển theo một hướng cụ thể, bám sát → Tương lai phức một chiều (плыть)."},{"t":"para","text":"9. По́сле обе́да я не смогу́ прие́хать, ... студе́нтов по университе́ту.","b":1},{"t":"subhead","text":"Đáp án: бу́ду води́ть","b":1},{"t":"para","text":"Dịch: Sau bữa trưa tôi không thể đến được, (vì lúc đó) tôi sẽ dẫn sinh viên đi quanh trường đại học."},{"t":"example","text":"Giải thích: По университету (quanh trường) chỉ chuyển động nhiều hướng/tham quan → Đa chiều (води́ть)."},{"t":"para","text":"10. Не волну́йтесь, он ... ваш чемода́н аккура́тно, с ним ничего́ не случи́ться.","b":1},{"t":"subhead","text":"Đáp án: бу́дет нести́ (hoặc понесёт)."},{"t":"para","text":"Dịch: Đừng lo, cậu ấy sẽ mang/xách vali của ông cẩn thận, sẽ không có chuyện gì xảy ra đâu."},{"t":"example","text":"Giải thích: Аккуратно (cẩn thận) nhấn mạnh vào cách thức thực hiện trong quá trình di chuyển → dùng Tương lai phức một chiều (нести́) để đảm bảo về quá trình đó."},{"t":"para","text":"11. Я ... ве́щи в маши́не, а ты в э́то вре́мя постара́йся дозвони́ться.","b":1},{"t":"subhead","text":"Đáp án: бу́ду везти́","b":1},{"t":"para","text":"Dịch: Tớ sẽ chở/đang chở đồ trong xe, còn cậu trong lúc đó hãy cố gọi điện nhé."},{"t":"example","text":"Giải thích: Cụm từ в это время (trong lúc đó) chỉ hai hành động diễn ra song song. Hành động chở đồ là một quá trình → Tương lai phức một chiều (везти́)."},{"t":"para","text":"Глаго́лы движе́ния в бу́дущем вре́мени (Động từ chuyển động ở thì tương lai)","b":1},{"t":"subhead","text":"Gợi ý ngữ pháp (Lý thuyết chung cho bài 599-600):","b":1},{"t":"para","text":"Trong tiếng Nga, để diễn đạt hành động chuyển động trong tương lai với cấu trúc \"бу́ду + động từ nguyên mẫu\" (Tương lai phức), chúng ta cần phân biệt hai nhóm động từ:"},{"t":"subhead","text":"Nhóm một chiều (Unidirectional - идти́, е́хать, лете́ть...):","b":1},{"t":"example","text":"Dùng cấu trúc бу́ду идти́ / бу́ду е́хать... khi muốn nhấn mạnh vào quá trình di chuyển đang diễn ra tại một thời điểm cụ thể trong tương lai, hoặc di chuyển theo một hướng xác định (đang trên đường đi)."},{"t":"example","text":"Ví dụ: В 5 часо́в я бу́ду е́хать в по́езде (Lúc 5 giờ tôi sẽ đang đi trên tàu - nhấn mạnh quá trình)."},{"t":"subhead","text":"Nhóm đa chiều (Multidirectional - ходи́ть, е́здить, лета́ть...):","b":1},{"t":"subhead","text":"Dùng cấu trúc бу́ду ходи́ть / бу́ду е́здить... khi nói về:"},{"t":"para","text":"Hành động lặp đi lặp lại (thường xuyên, hàng ngày)."},{"t":"para","text":"Hành động đi và về (khứ hồi)."},{"t":"para","text":"Chuyển động không có hướng xác định (đi lung tung, đi dạo)."},{"t":"para","text":"Khả năng hoặc sở thích."},{"t":"para","text":"599. Вме́сто то́чек вста́вьте необходи́мый по смы́слу глаго́л движе́ния в фо́рме бу́дущего вре́мени. Объясни́те ваш вы́бор. Укажи́те вариа́нты.","b":1},{"t":"example","text":"(Thay dấu ba chấm bằng động từ chuyển động cần thiết theo ý nghĩa ở thì tương lai. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"1. Я не ... в э́ту ды́рку, мне она́ не нра́вится. И че́рез забо́р я то́же никогда́ не ... (лезть/ла́зить).","b":1},{"t":"subhead","text":"Đáp án: бу́ду лезть; бу́ду ла́зить"},{"t":"para","text":"Dịch: Tôi sẽ không chui vào cái lỗ này đâu (ngay lúc này), tôi không thích nó. Và tôi cũng sẽ không bao giờ leo qua hàng rào nữa."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́ду лезть (Một chiều)","vi":"Từ chối thực hiện một hành động cụ thể vào một địa điểm cụ thể (в э́ту ды́рку) ngay tại thời điểm nói.","g":null},{"t":"vocab","ru":"бу́ду ла́зить (Đa chiều)","vi":"Có từ никогда́ (không bao giờ) chỉ sự phủ định hoàn toàn thói quen hoặc hành động lặp lại trong tương lai.","g":null},{"t":"para","text":"2. Пока́ ты не прие́дешь, я ... по окре́стным гора́м в одино́честве (брести́/броди́ть).","b":1},{"t":"subhead","text":"Đáp án: бу́ду броди́ть","b":1},{"t":"para","text":"Dịch: Chừng nào bạn chưa đến, tôi sẽ lang thang một mình trên những ngọn núi quanh đây."},{"t":"example","text":"Giải thích: Cụm từ по гора́м (quanh núi) và động từ броди́ть mang ý nghĩa đi dạo không có đích đến cụ thể, đi vòng quanh → Dùng động từ đa chiều."},{"t":"para","text":"3. Коне́чно, я ... маши́ну изо всех сил, но вряд ли успе́ю во́время (гнать/гоня́ть).","b":1},{"t":"subhead","text":"Đáp án: бу́ду гнать","b":1},{"t":"para","text":"Dịch: Tất nhiên, tôi sẽ lái (phi/đạp) xe hết tốc lực, nhưng khó mà kịp giờ được."},{"t":"example","text":"Giải thích: Nhấn mạnh vào quá trình lái xe nhanh, căng thẳng đang diễn ra trên đường đi đến đích cụ thể để kịp giờ → Dùng động từ một chiều (гнать)."},{"t":"para","text":"4. Нам на́до в не́скольких места́х установи́ть специа́льные трещо́тки, они́ ... птиц с поле́й (гнать/гоня́ть).","b":1},{"t":"subhead","text":"Đáp án: бу́дут гоня́ть","b":1},{"t":"para","text":"Dịch: Chúng ta cần đặt mấy cái máy gây tiếng động lách cách ở vài chỗ, chúng sẽ xua đuổi chim chóc khỏi ruộng đồng."},{"t":"example","text":"Giải thích: Hành động xua đuổi này là chức năng của cái máy, sẽ diễn ra lặp đi lặp lại mỗi khi có chim đến → Dùng động từ đa chiều (гоня́ть)."},{"t":"para","text":"5. Под го́рку мы ... э́то бревно́, а вот при подъёме придётся тру́дно. Мы ... коля́ску до ве́чера и́ли, мо́жет быть, вернёмся домо́й, что́бы покорми́ть ребёнка (кати́ть/ката́ть).","b":1},{"t":"subhead","text":"Đáp án: бу́дем кати́ть; бу́дем ката́ть"},{"t":"para","text":"Dịch: Xuống dốc thì chúng tôi sẽ lăn khúc gỗ này, nhưng lúc lên dốc thì sẽ vất vả đấy. Chúng tôi sẽ đẩy xe (đi dạo) đến tối, hoặc có lẽ sẽ về nhà để cho bé ăn."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дем кати́ть","vi":"Hành động lăn khúc gỗ theo một hướng cụ thể (xuống dốc) → Một chiều.","g":null},{"t":"vocab","ru":"бу́дем ката́ть","vi":"Đẩy xe nôi đi dạo chơi (hành động đi vòng vòng thư giãn, kéo dài thời gian đến tối) → Đa chiều.","g":null},{"t":"para","text":"6. Я не ... по боло́ту, собира́я клю́кву, лу́чше куплю́ её в магази́не. Посмотри́, он ещё дви́гается, ... до ве́чера (ползти́/по́лзать).","b":1},{"t":"subhead","text":"Đáp án: бу́ду по́лзать; бу́дет ползти́"},{"t":"para","text":"Dịch: Tôi sẽ không bò (lê la) trong đầm lầy để hái nam việt quất đâu, thà mua ở cửa hàng còn hơn. Nhìn kìa, nó (con vật/ai đó) vẫn còn cử động, nó sẽ (còn) bò đến tận tối đấy."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́ду по́лзать","vi":"Hành động bò qua bò lại tìm kiếm (thu hoạch) trong một khu vực rộng (по болоту) → Đa chiều.","g":null},{"t":"vocab","ru":"бу́дет ползти́","vi":"Nhấn mạnh quá trình di chuyển chậm chạp, vất vả đang tiếp diễn liên tục về phía trước (nỗ lực bò đi) → Một chiều.","g":null},{"t":"para","text":"7. Что де́лать, е́сли у нас за́втра четы́ре па́ры в институ́те, ... с собо́й все уче́бники. Е́сли он не захо́чет пойти́ сам, я ... его́ за́ руку (тащи́ть/таска́ть).","b":1},{"t":"subhead","text":"Đáp án: бу́дем таска́ть; бу́ду тащи́ть"},{"t":"para","text":"Dịch: Biết làm sao đây nếu mai chúng ta có 4 tiết ở trường, (chúng ta) sẽ phải mang vác tất cả sách giáo khoa theo. Nếu nó không chịu tự đi, tôi sẽ lôi/kéo tay nó đi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дем таска́ть","vi":"Mang nghĩa phàn nàn về việc phải mang vác nặng nề đi lại (có thể đi rồi mang về, đi nhiều nơi) → Đa chiều.","g":null},{"t":"vocab","ru":"бу́ду тащи́ть","vi":"Hành động lôi/kéo cụ thể theo một hướng (ép buộc đi) ngay lúc đó → Một chiều.","g":null},{"t":"vocab","ru":"Пока́ тебя́ не бу́дет, ... бо́роться с чёрными мы́слями","vi":"... их прочь от себя́. Что я бу́ду де́лать? ... мяч во дворе́ вме́сте с ребя́тами (гнать/гоня́ть).","g":null},{"t":"subhead","text":"Đáp án: бу́ду гнать; бу́ду гоня́ть"},{"t":"para","text":"Dịch: Trong lúc bạn vắng mặt, tôi sẽ đấu tranh với những suy nghĩ đen tối: (tôi) sẽ xua chúng ra khỏi đầu. Tôi sẽ làm gì ư? (Tôi) sẽ đá (đuổi) bóng ngoài sân cùng bọn trẻ."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́ду гнать","vi":"Xua đuổi ý nghĩ (nghĩa bóng) đi ra xa theo một hướng cho khuất mắt → Một chiều.","g":null},{"t":"vocab","ru":"бу́ду гоня́ть","vi":"Đá bóng/rượt bóng là trò chơi vận động chạy nhiều hướng → Đa chiều.","g":null},{"t":"para","text":"600. Вме́сто то́чек вста́вьте необходи́мый по смы́слу глаго́л движе́ния в фо́рме бу́дущего вре́мени. Объясни́те ваш вы́бор. Укажи́те вариа́нты.","b":1},{"t":"example","text":"(Thay dấu ba chấm bằng động từ chuyển động cần thiết theo ý nghĩa ở thì tương lai. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"1. Е́сли ты ... стро́го на се́вер, к обе́ду вы́йдешь к мо́рю. Е́сли ты ... за овоща́ми два с полови́ной часа́, мы не успе́ем пригото́вить обе́д.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь идти́; бу́дешь ходи́ть"},{"t":"para","text":"Dịch: Nếu bạn (sẽ) đi thẳng về hướng Bắc, đến trưa bạn sẽ ra tới biển. Nếu bạn đi mua rau mất tận hai tiếng rưỡi (đi rồi về), chúng ta sẽ không kịp nấu bữa trưa đâu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дешь идти́","vi":"Di chuyển theo một hướng xác định (стро́го на се́вер) → Một chiều.","g":null},{"t":"vocab","ru":"бу́дешь ходи́ть","vi":"Hành động đi và về (khứ hồi) mất nhiều thời gian → Đa chiều.","g":null},{"t":"para","text":"2. Когда́ ты ... самостоя́тельно без инстру́ктора, тебе́ бу́дет сложне́е, так как всё придётся реша́ть самому́. Когда́ мы ... ми́мо канцеля́рского магази́на, напо́мни мне купи́ть тетра́ди.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь е́здить; бу́дем идти́ (hoặc проходи́ть)."},{"t":"para","text":"Dịch: Khi bạn (tự) lái xe/đi một mình không có hướng dẫn viên, sẽ khó khăn hơn vì bạn phải tự quyết định mọi thứ. Khi chúng ta đi (ngang) qua cửa hàng văn phòng phẩm, hãy nhắc tôi mua vở nhé."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дешь е́здить","vi":"Chỉ khả năng/kỹ năng lái xe hoặc thói quen đi lại trong tương lai → Đa chiều.","g":null},{"t":"vocab","ru":"бу́дем идти́","vi":"Quá trình đi ngang qua một điểm cụ thể trên đường đi → Một chiều.","g":null},{"t":"para","text":"3. Е́сли ты ка́ждую мину́ту ... в ба́нку с варе́ньем, там ничего́ не оста́нется. Е́сли ты ... на де́рево полчаса́, то ско́лько же вре́мени ты бу́дешь с него́ спуска́ться?","b":1},{"t":"subhead","text":"Đáp án: бу́дешь ла́зить; бу́дешь лезть"},{"t":"para","text":"Dịch: Nếu phút nào con cũng thò tay (leo) vào lọ mứt, thì chẳng còn gì đâu. Nếu cậu leo lên cây mất nửa tiếng (quá trình leo lên), thì cậu sẽ xuống mất bao lâu?"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дешь ла́зить","vi":"Hành động lặp đi lặp lại nhiều lần (ка́ждую мину́ту) → Đa chiều.","g":null},{"t":"vocab","ru":"бу́дешь лезть","vi":"Nhấn mạnh thời gian của quá trình leo lên (một chiều) → Một chiều.","g":null},{"t":"para","text":"4. Когда́ ... над Тибе́том, обяза́тельно посмотри́те в иллюмина́тор. Когда́ лю́ди ... на рабо́ту, а не е́здить на тра́нспорте, пробле́ма доро́жных про́бок исче́знет сама́ собо́й.","b":1},{"t":"subhead","text":"Đáp án: бу́дем лете́ть; бу́дут ходи́ть"},{"t":"para","text":"Dịch: Khi (chúng ta) bay qua Tây Tạng, nhất định hãy nhìn qua cửa sổ máy bay nhé. Khi mọi người đi (bộ) đi làm chứ không đi xe, vấn nạn tắc đường sẽ tự biến mất."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дем лете́ть","vi":"Quá trình bay qua một địa điểm cụ thể (Tây Tạng) → Một chiều.","g":null},{"t":"vocab","ru":"бу́дут ходи́ть","vi":"Thay đổi thói quen di chuyển hàng ngày → Đa chiều.","g":null},{"t":"para","text":"5. Е́сли вы ... ребёнка че́рез у́лицу, его́ на́до держа́ть за́ руку. Е́сли ... соба́ку на поводке́, она́ не потеря́ется.","b":1},{"t":"subhead","text":"Đáp án: бу́дете вести́; бу́дете води́ть"},{"t":"para","text":"Dịch: Nếu bạn dắt trẻ qua đường, phải nắm tay nó. Nếu bạn dắt chó bằng dây xích (thường xuyên/khi đi dạo), nó sẽ không bị lạc."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дете вести́","vi":"Hành động cụ thể băng qua đường (từ bên này sang bên kia) → Một chiều.","g":null},{"t":"vocab","ru":"бу́дете води́ть","vi":"Hành động dắt đi dạo nói chung, lặp lại hoặc không hướng cụ thể → Đa chiều.","g":null},{"t":"para","text":"6. Когда́ ку́пишь свою́ маши́ну и ... на ней, мо́жешь рискова́ть, а мою́ маши́ну води́ осторо́жно. Когда́ ... че́рез мост, не остана́вливайся.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь гоня́ть; бу́дешь е́хать"},{"t":"para","text":"Dịch: Khi nào cậu mua xe riêng và phóng nhanh/đua trên đó thì cứ việc liều, còn xe tớ thì lái cẩn thận vào. Khi đi (xe) qua cầu, đừng dừng lại."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дешь гоня́ть","vi":"Chỉ thói quen lái ẩu, phóng nhanh lạng lách (đa chiều/lặp lại).","g":null},{"t":"vocab","ru":"бу́дешь е́хать","vi":"Quá trình di chuyển qua một đoạn đường cụ thể (cầu) → Một chiều.","g":null},{"t":"para","text":"7. Когда́ ... че́рез зали́в, полюбу́йся ви́дом на го́род с мо́ря. Когда́ ... капита́ном, мо́жешь принима́ть любы́е реше́ния, а на э́том су́дне ты до́лжен подчиня́ться мне.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь плыть; бу́дешь пла́вать"},{"t":"para","text":"Dịch: Khi bơi/đi tàu qua vịnh, hãy ngắm cảnh thành phố từ biển nhé. Khi nào cậu đi tàu (làm thuyền trưởng), cậu có thể ra bất cứ quyết định nào, còn trên tàu này cậu phải phục tùng tôi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дешь плыть","vi":"Di chuyển theo lộ trình cụ thể qua vịnh (quá trình) → Một chiều.","g":null},{"t":"vocab","ru":"бу́дешь пла́вать","vi":"Chỉ nghề nghiệp, hoạt động hàng hải lâu dài → Đa chiều.","g":null},{"t":"para","text":"8. Е́сли до Га́мбурга ты ... э́тот груз по мо́рю, бу́дет деше́вле. На э́том су́дне компа́ния ... пшени́цу.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь везти́; бу́дет вози́ть"},{"t":"para","text":"Dịch: Nếu bạn chở lô hàng này đến Hamburg bằng đường biển, sẽ rẻ hơn đấy. Công ty sẽ chở (vận chuyển) lúa mì trên con tàu này (thường xuyên)."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дешь везти́","vi":"Chuyến hàng cụ thể đến đích (Hamburg) → Một chiều.","g":null},{"t":"vocab","ru":"бу́дет вози́ть","vi":"Hoạt động kinh doanh vận tải lặp đi lặp lại của công ty → Đa chiều.","g":null},{"t":"para","text":"9. Е́сли ... за ка́ждой ме́лочью отде́льно, у нас уйдёт на э́то це́лый день. Е́сли ... ве́чером по пло́хо освещённой доро́ге, обяза́тельно включа́й фа́ры.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь е́здить; бу́дешь е́хать"},{"t":"para","text":"Dịch: Nếu cứ đi (xe) mua từng thứ lặt vặt một (đi rồi về rồi lại đi), chúng ta sẽ mất cả ngày đấy. Nếu lái xe buổi tối trên đường tối, nhớ bật đèn pha lên."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"бу́дешь е́здить","vi":"Đi đi lại lại nhiều lần (lặp lại) → Đa chiều.","g":null},{"t":"vocab","ru":"бу́дешь е́хать","vi":"Quá trình di chuyển trên đường vào buổi tối (đang đi) → Một chiều.","g":null},{"t":"para","text":"601. Вме́сто то́чек вста́вьте необходи́мый по смыслу глаго́л движе́ния в фо́рме бу́дущего вре́мени. Объясни́те ваш вы́бор. Укажи́те вариа́нты.","b":1},{"t":"example","text":"(Thay dấu ba chấm bằng động từ chuyển động cần thiết theo ý nghĩa ở thì tương lai. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"note","text":"Lưu ý ngữ pháp: Bài tập này tập trung vào thì tương lai của động từ chuyển động."},{"t":"example","text":"Dùng cấu trúc бу́ду + động từ một chiều (идти́, е́хать, вести́...) để diễn tả một quá trình di chuyển cụ thể sẽ diễn ra trong tương lai (đang trên đường đi)."},{"t":"example","text":"Dùng cấu trúc бу́ду + động từ đa chiều (ходи́ть, е́здить, води́ть...) để diễn tả hành động lặp đi lặp lại hoặc khả năng, thói quen trong tương lai."},{"t":"para","text":"1. В э́тот раз, е́сли я ... маши́ну, а ты бу́дешь ука́зывать доро́гу, мы не заблу́димся.","b":1},{"t":"subhead","text":"Đáp án: бу́ду вести́ (từ вести́)"},{"t":"para","text":"Dịch: Lần này, nếu tôi (sẽ) lái xe, còn bạn chỉ đường, thì chúng ta sẽ không bị lạc."},{"t":"example","text":"Giải thích: Mặc dù có \"lần này\" (в э́тот раз), nhưng câu văn nhấn mạnh vào sự phân công nhiệm vụ trong suốt quá trình di chuyển (tôi thì lái, bạn thì chỉ), nên dùng tương lai phức của động từ một chiều вести́ (буду вести)."},{"t":"para","text":"2. Нам обяза́тельно на́до быть там сего́дня, е́сли не смо́жем бежа́ть, ..., е́сли не смо́жем идти́, ...","b":1},{"t":"subhead","text":"Đáp án: бу́дем идти́; бу́дем ползти́"},{"t":"para","text":"Dịch: Chúng ta nhất định phải có mặt ở đó hôm nay, nếu không thể chạy, (chúng ta) sẽ đi, nếu không thể đi, (chúng ta) sẽ bò."},{"t":"example","text":"Giải thích: Đây là câu nói nhấn mạnh vào nỗ lực tiếp diễn để đạt được mục đích. Dùng tương lai phức của động từ một chiều (идти́ và ползти́) để chỉ quá trình di chuyển tịnh tiến về phía trước dù khó khăn."},{"t":"para","text":"3. Так как мы ... в Се́верном Ледови́том океа́не, сове́тую вам взять с собо́й побо́льше тёплых веще́й.","b":1},{"t":"subhead","text":"Đáp án: бу́дем плыть (hoặc бу́дем идти́ - ngôn ngữ hàng hải)"},{"t":"para","text":"Dịch: Vì chúng ta sẽ bơi/đi tàu ở Bắc Băng Dương, tôi khuyên các bạn nên mang theo nhiều đồ ấm."},{"t":"example","text":"Giải thích: Diễn tả quá trình di chuyển cụ thể của con tàu trong chuyến đi sắp tới → dùng tương lai của động từ một chiều (плыть)."},{"t":"para","text":"4. Когда́ ... ми́мо кио́ска, не забу́дь купи́ть для меня́ конве́рт.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь проходи́ть (hoặc бу́дешь идти́)"},{"t":"para","text":"Dịch: Khi bạn đi (ngang) qua ki-ốt, đừng quên mua cho tôi cái phong bì nhé."},{"t":"example","text":"Giải thích: Hành động mua phong bì xảy ra trong lúc đang di chuyển ngang qua (quá trình) → dùng tương lai động từ một chiều (идти) hoặc động từ có tiền tố chỉ sự băng qua (проходить)."},{"t":"para","text":"5. Е́сли ты ... , мо́жет быть, тебя́ и не заме́тят; а ма́шину своего́ отца́ без дове́ренности, ра́но и́ли по́здно тебя́ остано́вят и оштрафу́ют.","b":1},{"t":"example","text":"(Lưu ý: Câu này trong sách gốc có vẻ là sự ghép nối của 2 ý khác nhau hoặc in thiếu, tôi sẽ giải thích dựa trên ngữ cảnh hợp lý nhất)."},{"t":"subhead","text":"Đáp án: бу́дешь ползти́ (vế 1); бу́дешь вести́ (vế 2 - lái xe)."},{"t":"para","text":"Dịch: Nếu cậu bò (lén lút), có lẽ người ta sẽ không thấy cậu đâu; [nhưng nếu cậu lái] xe của bố cậu mà không có giấy ủy quyền, sớm hay muộn cậu cũng sẽ bị chặn lại và phạt tiền."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: будешь ползти (bò) để trốn tránh, miêu tả cách thức di chuyển cụ thể."},{"t":"example","text":"Vế 2: будешь вести (lái xe) miêu tả hành động điều khiển phương tiện (một chiều) đang diễn ra khi bị cảnh sát bắt."},{"t":"para","text":"6. Е́сли ... су́мки в двух рука́х, как же ты смо́жешь оплати́ть прое́зд в тра́нспорте?","b":1},{"t":"subhead","text":"Đáp án: бу́дешь нести́","b":1},{"t":"para","text":"Dịch: Nếu tay nào bạn cũng đang xách túi, thì làm sao bạn trả tiền vé xe được?"},{"t":"example","text":"Giải thích: Nhấn mạnh trạng thái/quá trình \"tay đang bận xách đồ\" tại thời điểm trả tiền → dùng tương lai một chiều (нести)."},{"t":"para","text":"7. Е́сли из-за мале́йшей ерунды́ ты бу́дешь не́рвничать и ... на сте́ну, нам бу́дет тру́дно рабо́тать вме́сте.","b":1},{"t":"subhead","text":"Đáp án: (бу́дешь) лезть","b":1},{"t":"example","text":"Dịch: Nếu chỉ vì chuyện vặt vãnh mà cậu cũng lo lắng và leo lên tường (thành ngữ: phát điên/phản ứng thái quá), thì chúng ta sẽ khó làm việc cùng nhau đấy."},{"t":"example","text":"Giải thích: Thành ngữ лезть на стену (leo lên tường) dùng động từ một chiều лезть. Ở đây dùng chung với trợ động từ будешь ở vế trước."},{"t":"para","text":"8. Е́сли до шко́лы ты ... по тротуа́ру, с тобо́й ничего́ не случи́ться, гла́вное — держи́сь пода́льше от доро́ги.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь идти́","b":1},{"t":"para","text":"Dịch: Nếu cậu đi (bộ) đến trường trên vỉa hè, sẽ không có chuyện gì xảy ra đâu, quan trọng là tránh xa lòng đường ra."},{"t":"example","text":"Giải thích: Chỉ dẫn về lộ trình/cách thức di chuyển cụ thể trong tương lai → dùng tương lai một chiều (идти)."},{"t":"para","text":"9. Соба́ка никого́ ... , положи́те в рот конфе́ту, что́бы при взлёте не закла́дывало у́ши.","b":1},{"t":"example","text":"(Lưu ý: Đây là 2 câu riêng biệt bị dính vào nhau trong bản in hoặc bài tập. Tôi sẽ tách ra làm 2 câu 9a và 9b)."},{"t":"para","text":"9a. Соба́ка никого́ ...","b":1},{"t":"subhead","text":"Đáp án: не тро́нет (sẽ không động vào - phổ biến nhất) hoặc не бу́дет куса́ть (sẽ không cắn). Nếu bắt buộc dùng động từ chuyển động: не бу́дет броса́ться (sẽ không lao vào)."},{"t":"para","text":"Dịch: Con chó sẽ không lao vào/cắn ai đâu."},{"t":"para","text":"9b. ... (Когда вы) ... , положи́те в рот конфе́ту...","b":1},{"t":"subhead","text":"Đáp án: бу́дете лете́ть","b":1},{"t":"para","text":"Dịch: (Khi các bạn) bay / đang bay, hãy ngậm kẹo để khi cất cánh không bị ù tai."},{"t":"example","text":"Giải thích: при взлёте (khi cất cánh) là một phần của quá trình bay (лететь)."},{"t":"para","text":"10. Е́сли э́тот чемода́н вы всё вре́мя ... по земле́, от него́ ско́ро ничего́ не оста́нется.","b":1},{"t":"subhead","text":"Đáp án: бу́дете тащи́ть","b":1},{"t":"para","text":"Dịch: Nếu các bạn cứ kéo lê cái vali này trên mặt đất suốt, thì chẳng mấy chốc nó sẽ hỏng hết (không còn lại gì)."},{"t":"example","text":"Giải thích: Nhấn mạnh quá trình kéo lê (тащить) gây hại cho vali."},{"t":"para","text":"11. Е́сли ты ... без де́ла це́лыми дня́ми и не ... к экза́мену, тебе́ вряд ли уда́стся получи́ть хоро́шую оце́нку.","b":1},{"t":"subhead","text":"Đáp án: бу́дешь ходи́ть (hoặc броди́ть/болта́ться); бу́дешь гото́виться (động từ thường)."},{"t":"para","text":"Dịch: Nếu cậu cứ đi lại/lang thang lêu lổng suốt ngày và không ôn thi, thì khó mà đạt điểm cao được."},{"t":"example","text":"Giải thích: Целыми днями (suốt ngày) chỉ hành động lặp đi lặp lại, không mục đích → dùng động từ đa chiều (ходить/бродить)."},{"t":"para","text":"12. Е́сли ты ... в океа́не, остерега́йся аку́л; 16. Осо́бенно будь осторо́жен, когда́ ... груз по го́рной доро́ге; 17. Е́сли ... по го́роду без ка́рты, мо́жешь заблуди́ться.","b":1},{"t":"subhead","text":"Đáp án:","b":1},{"t":"example","text":"12: бу́дешь пла́вать (bơi lội nói chung) hoặc бу́дешь плыть (bơi theo lộ trình). Ngữ cảnh \"coi chừng cá mập\" thường ám chỉ khi đang bơi lội chung chung → бу́дешь пла́вать."},{"t":"para","text":"16: бу́дешь везти́ (chở hàng). Nhấn mạnh quá trình vận chuyển trên đường núi nguy hiểm → một chiều."},{"t":"para","text":"17: бу́дешь ходи́ть (đi lại). Đi trong thành phố không có bản đồ, đi lung tung → đa chiều."},{"t":"para","text":"602. Испо́льзуя свой о́пыт жи́зни в Росси́и и́ли в любо́й друго́й стране́, продо́лжите письмо́ и да́йте не́сколько сове́тов ва́шему дру́гу. В письме́ употреби́те все возмо́жные глаго́лы движе́ния в бу́дущем вре́мени.","b":1},{"t":"example","text":"(Sử dụng kinh nghiệm sống của bạn ở Nga hoặc bất kỳ quốc gia nào khác, hãy viết tiếp bức thư và đưa ra vài lời khuyên cho bạn của bạn. Trong thư hãy sử dụng tất cả các động từ chuyển động có thể ở thì tương lai)."},{"t":"para","text":"Đoạn mở đầu (trong sách):","b":1},{"t":"para","text":"Дорого́й друг! Я слы́шал, что ты собира́ешься е́хать в Росси́ю (в Аме́рику, в Герма́нию...). Наско́лько я зна́ю, э́то твоя́ пе́рвая пое́здка в э́ту стра́ну, поэ́тому хочу́ тебе́ дать не́сколько сове́тов..."},{"t":"example","text":"(Bạn thân mến! Tớ nghe nói cậu định đi Nga (Mỹ, Đức...). Theo tớ biết thì đây là chuyến đi đầu tiên của cậu đến nước này, vì vậy tớ muốn cho cậu vài lời khuyên...)"},{"t":"para","text":"Bài giải gợi ý (viết tiếp):","b":1},{"t":"example","text":"Когда́ ты бу́дешь лете́ть в самолёте, не забу́дь заполни́ть миграцио́нную ка́рту. (Khi cậu đang bay (ngồi trên máy bay), đừng quên điền tờ khai nhập cảnh.)"},{"t":"example","text":"Giải thích: бу́дешь лете́ть - quá trình di chuyển một chiều."},{"t":"example","text":"Из аэропо́рта до го́рода ты пое́дешь на авто́бусе и́ли на такси́. Е́сли ты бу́дешь е́хать на авто́бусе, следи́ за свои́ми веща́ми. (Từ sân bay về thành phố cậu sẽ đi bằng xe buýt hoặc taxi. Nếu cậu đi (đang đi) bằng xe buýt, hãy trông chừng hành lý.)"},{"t":"example","text":"Giải thích: пое́дешь - hành động di chuyển cụ thể (tương lai đơn); бу́дешь е́хать - nhấn mạnh quá trình ngồi trên xe."},{"t":"example","text":"В Москве́ ты бу́дешь мно́го ходи́ть пешко́м, поэ́тому возьми́ удо́бную о́бувь. (Ở Moscow cậu sẽ đi (bộ) rất nhiều, nên hãy mang giày thoải mái nhé.)"},{"t":"example","text":"Giải thích: бу́дешь ходи́ть - hành động đi lại nhiều nơi, lặp lại (đa chiều)."},{"t":"example","text":"Когда́ ты бу́дешь переходи́ть у́лицу, будь осторо́жен. (Khi cậu băng qua đường, hãy cẩn thận.)"},{"t":"example","text":"Giải thích: бу́дешь переходи́ть - quá trình đi từ bên này sang bên kia."},{"t":"example","text":"Е́сли ты бу́дешь е́здить на метро́, покупа́й проездно́й биле́т на не́сколько пое́здок. (Nếu cậu đi tàu điện ngầm (thường xuyên/nhiều lần), hãy mua vé tháng/vé nhiều lượt.)"},{"t":"example","text":"Giải thích: бу́дешь е́здить - sử dụng phương tiện nhiều lần (đa chiều)."},{"t":"example","text":"Наде́юсь, ты бу́дешь ча́сто води́ть свои́х но́вых друзе́й в рестора́ны и музе́и. (Hy vọng cậu sẽ thường xuyên dẫn những người bạn mới đi nhà hàng và bảo tàng.)"},{"t":"example","text":"Giải thích: бу́дешь води́ть - dẫn đi chơi nhiều nơi (đa chiều)."},{"t":"example","text":"Счастли́вого пути́! (Thượng lộ bình an!)"},{"t":"para","text":"Глаго́лы движе́ния в императи́ве (Động từ chuyển động ở thể mệnh lệnh)","b":1},{"t":"para","text":"PHẦN 1: GỢI Ý NGỮ PHÁP (Lý thuyết trang 318-319)","b":1},{"t":"para","text":"Trước khi làm bài, bạn cần nắm vững các quy tắc sau được sách đưa ra trong các khung ngữ pháp:"},{"t":"para","text":"1. Khung ngữ pháp trang 318:","b":1},{"t":"example","text":"Tiếng Nga: От глаго́лов е́хать/е́здить образу́ется фо́рма императи́ва поезжа́йте, не на́до е́хать (е́здить). Все остальные вариа́нты в литерату́рном языке́ не употребля́ются. От глаго́ла брести́ императи́в не употребля́ется."},{"t":"para","text":"Dịch & Giải thích:","b":1},{"t":"example","text":"Từ động từ е́хать/е́здить (đi bằng phương tiện), hình thức mệnh lệnh thức được tạo thành là поезжа́йте (hãy đi đi - dạng lịch sự/số nhiều) hoặc поезжа́й (số ít)."},{"t":"para","text":"Để diễn đạt ý phủ định, dùng cấu trúc не на́до е́хать (е́здить) (không cần/đừng đi)."},{"t":"example","text":"Tất cả các biến thể khác (như едь, ехай...) không được dùng trong ngôn ngữ văn học chuẩn mực."},{"t":"example","text":"Động từ брести́ (lê bước) không có hình thức mệnh lệnh."},{"t":"para","text":"2. Khung ngữ pháp trang 319:","b":1},{"t":"example","text":"Tiếng Nga: При указа́нии на объе́кт едини́чного движе́ния употребля́ются императи́вы глаго́лов однонапра́вленного движе́ния. В сочета́нии с отрица́тельной части́цей не ча́ще употребля́ются императи́вы глаго́лов разнонапра́вленного движе́ния. Сравни́те: иди́ в теа́тр — не ходи́ в теа́тр."},{"t":"para","text":"Dịch & Giải thích:","b":1},{"t":"example","text":"Khi chỉ hành động di chuyển cụ thể (một lần) hướng tới một đối tượng/đích đến, ta dùng mệnh lệnh thức của động từ một chiều (идти́, бежа́ть, плыть...)."},{"t":"example","text":"Ví dụ: Иди́ сюда́! (Lại đây!)"},{"t":"example","text":"Khi kết hợp với từ phủ định не (đừng), ta thường dùng mệnh lệnh thức của động từ đa chiều (ходи́ть, бе́гать, пла́вать...)."},{"t":"example","text":"Ví dụ: Не ходи́ туда́! (Đừng đi đến đó!)"}]},{"id":"07-s106","type":"exercise","title":"Bài 603 (Trang 318-319)","num":603,"blocks":[{"t":"instruction","text":"Yêu cầu: Đọc các câu văn. Xác định ý nghĩa của các động từ chuyển động được in đậm. Gọi tên động từ nguyên mẫu (infinitive) mà từ đó chúng được tạo thành."},{"t":"para","text":"a) 1. Иди́ быстре́е, мы опа́здываем. Не ходи́ сего́дня на заня́тия, у тебя́ температу́ра.","b":1},{"t":"vocab","ru":"Иди́ (từ идти́ - một chiều)","vi":"Mệnh lệnh thúc giục thực hiện hành động cụ thể ngay lúc này. (Dịch: Đi nhanh lên, chúng ta muộn rồi.)","g":null},{"t":"vocab","ru":"Не ходи́ (từ ходи́ть - đa chiều)","vi":"Mệnh lệnh phủ định (khuyên can), không thực hiện hành động đi. (Dịch: Hôm nay đừng đi học, bạn đang sốt đấy.)","g":null},{"t":"para","text":"2. Беги́ осторо́жно, ты мо́жешь упа́сть. Не бе́гайте по ко́мнате: ба́бушка спит.","b":1},{"t":"vocab","ru":"Беги́ (từ бежа́ть - một chiều)","vi":"Nhắc nhở về cách thức thực hiện hành động đang diễn ra hoặc sắp diễn ra theo một hướng. (Dịch: Chạy cẩn thận nhé, bạn có thể bị ngã đấy.)","g":null},{"t":"vocab","ru":"Не бе́гайте (từ бе́гать - đa chiều)","vi":"Cấm đoán hành động chạy lung tung, lặp lại trong không gian phòng. (Dịch: Đừng có chạy (loạn) trong phòng: bà đang ngủ.)","g":null},{"t":"vocab","ru":"Поезжа́йте за э́той кра́сной маши́ной.* (Chú giải trong sách","vi":"Từ động từ ехать/ездить tạo thành mệnh lệnh cách поезжайте (ездить). Các dạng khác không dùng trong văn học. Từ động từ брести không dùng mệnh lệnh cách.)","g":null},{"t":"vocab","ru":"Поезжа́йте (hình thức mệnh lệnh của е́хать - một chiều)","vi":"Yêu cầu di chuyển theo một hướng cụ thể ngay lập tức. (Dịch: Hãy đi (lái xe) theo chiếc xe đỏ kia.)","g":null},{"t":"para","text":"4. Е́сли нет пря́мого ре́йса, лети́те че́рез Ло́ндон и́ли че́рез Га́мбург. Лета́йте самолётами Аэрофло́та!","b":1},{"t":"vocab","ru":"Лети́те (từ лете́ть - một chiều)","vi":"Hướng dẫn cho một chuyến đi cụ thể. (Dịch: Nếu không có chuyến bay thẳng, hãy bay qua London hoặc Hamburg.)","g":null},{"t":"vocab","ru":"Лета́йте (từ лета́ть - đa chiều)","vi":"Lời kêu gọi, quảng cáo cho thói quen/hành động lặp lại nhiều lần. (Dịch: Hãy bay (thường xuyên) với các máy bay của Aeroflot!)","g":null},{"t":"para","text":"5. Плыви́ к бе́регу. Бо́льше пла́вайте, э́то поле́зно.","b":1},{"t":"vocab","ru":"Плыви́ (từ плыть - một chiều)","vi":"Mệnh lệnh bơi về một hướng cụ thể (bờ). (Dịch: Hãy bơi vào bờ đi.)","g":null},{"t":"vocab","ru":"Пла́вайте (từ пла́вать - đa chiều)","vi":"Khuyên nên thực hiện môn thể thao/hoạt động này thường xuyên. (Dịch: Hãy bơi lội nhiều hơn, điều đó rất tốt cho sức khỏe.)","g":null},{"t":"para","text":"6. Не броди́ по ко́мнате, как тень, лу́чше сядь.","b":1},{"t":"vocab","ru":"Не броди́ (từ броди́ть - đa chiều)","vi":"Cấm hành động đi lang thang vô định trong phòng. (Dịch: Đừng có đi vật vờ trong phòng như cái bóng thế, thà ngồi xuống đi.)","g":null},{"t":"para","text":"7. Не лезь в чужи́е дела́, занима́йся свои́ми. Не ла́зай на де́рево, ты мо́жешь упа́сть.","b":1},{"t":"vocab","ru":"Не лезь (từ лезть - một chiều)","vi":"Đây là thành ngữ (nghĩa bóng), cấm can thiệp vào chuyện người khác ngay lúc này hoặc nói chung. (Dịch: Đừng xía vào chuyện người khác, hãy lo chuyện của mình đi.)","g":null},{"t":"vocab","ru":"Не ла́зай (từ ла́зить - đa chiều)","vi":"Cấm hành động leo trèo (như một trò chơi/thói quen) nguy hiểm. (Dịch: Đừng leo trèo lên cây, con có thể bị ngã đấy.)","g":null},{"t":"para","text":"8. Ползи́ осторо́жно! Не по́лзай на коле́нях, испа́чкаешься!","b":1},{"t":"vocab","ru":"Ползи́ (từ ползти́ - một chiều)","vi":"Hướng dẫn bò đi theo hướng cụ thể. (Dịch: Bò cẩn thận vào!)","g":null},{"t":"vocab","ru":"Не по́лзай (từ по́лзать - đa chiều)","vi":"Cấm hành động bò lê la (không hướng). (Dịch: Đừng có bò lê trên đầu gối, bẩn đấy!)","g":null},{"t":"para","text":"b) (Trang 319) 1. Е́сли ты нашёл мою́ ру́чку, неси́ её сюда́. Не носи́те мне докуме́нты на по́дпись, я сам к вам зайду́.","b":1},{"t":"vocab","ru":"Неси́ (từ нести́ - một chiều)","vi":"Mang vật cụ thể đến địa điểm cụ thể ngay. (Dịch: Nếu bạn tìm thấy bút của tôi, hãy mang nó lại đây.)","g":null},{"t":"vocab","ru":"Не носи́те (từ носи́ть - đa chiều)","vi":"Cấm hành động mang vác lặp đi lặp lại hoặc theo thói quen. (Dịch: Đừng (thường xuyên) mang tài liệu đến cho tôi ký, tôi sẽ tự qua chỗ các bạn.)","g":null},{"t":"para","text":"2. Веди́ маши́ну осторо́жно. Не води́ соба́ку на коро́тком поводке́, ей на́до погуля́ть.","b":1},{"t":"vocab","ru":"Веди́ (từ вести́ - một chiều)","vi":"Lái xe (điều khiển) trong chuyến đi cụ thể này. (Dịch: Hãy lái xe cẩn thận.)","g":null},{"t":"vocab","ru":"Не води́ (từ води́ть - đa chiều)","vi":"Đừng dắt chó (thói quen dắt). (Dịch: Đừng dắt chó bằng dây xích ngắn, nó cần được đi dạo thoải mái.)","g":null},{"t":"para","text":"3. Вези́ коля́ску по тротуа́ру, а не по доро́ге.","b":1},{"t":"vocab","ru":"Вези́ (từ везти́ - một chiều)","vi":"Đẩy/chở xe nôi đi theo hướng cụ thể. (Dịch: Hãy đẩy xe nôi trên vỉa hè chứ đừng đi dưới lòng đường.)","g":null},{"t":"para","text":"4. Не тащи́ по земле́ су́мку.","b":1},{"t":"vocab","ru":"Не тащи́ (từ тащи́ть - một chiều)","vi":"Cấm hành động đang diễn ra hoặc hành động cụ thể làm hỏng đồ vật. Lưu ý: Ở đây dùng một chiều тащи dù có не, vì nhấn mạnh vào việc \"ngừng ngay hành động kéo lê cụ thể này\". (Dịch: Đừng có kéo lê cái túi trên mặt đất (nhấc lên đi).)","g":null},{"t":"para","text":"5. Не гоня́й ко́шку на у́лицу, дай ей снача́ла пое́сть. Не гоня́й мяч це́лый день, займи́сь де́лом!","b":1},{"t":"subhead","text":"Не гоня́й (từ гоня́ть - đa chiều):"},{"t":"example","text":"Vế 1: Đừng xua đuổi. (Dịch: Đừng đuổi con mèo ra đường, cho nó ăn trước đã.)"},{"t":"example","text":"Vế 2: Đừng chơi (đuổi) bóng. (Dịch: Đừng có đá bóng suốt ngày thế, lo làm việc đi!)"},{"t":"para","text":"6. Не тащи́ по земле́ су́мку, а кати́ её на колёсах! Не ката́й по столу́ ша́рики из хле́ба, э́то плоха́я привы́чка!","b":1},{"t":"vocab","ru":"Не тащи́ (một chiều)","vi":"Đừng kéo lê (như câu 4).","g":null},{"t":"vocab","ru":"Кати́ (một chiều)","vi":"Hãy lăn (kéo cho nó lăn bánh) theo hướng đi. (Dịch: Đừng kéo lê túi trên đất, mà hãy lăn nó bằng bánh xe!)","g":null},{"t":"vocab","ru":"Не ката́й (đa chiều)","vi":"Cấm hành động nghịch ngợm vê tròn/lăn qua lại. (Dịch: Đừng có vê/lăn những viên bánh mì trên bàn, đó là thói quen xấu!)","g":null}]},{"id":"07-s107","type":"exercise","title":"Bài 604 (Trang 319)","num":604,"blocks":[{"t":"instruction","text":"Yêu cầu: Thay dấu ba chấm bằng động từ chuyển động cần thiết ở dạng mệnh lệnh (Imperative). Giải thích lựa chọn của bạn."},{"t":"para","text":"1. Не ... во́ду в желе́зном ведре́, возьми́ лу́чше пластма́ссовое, оно́ ле́гче. ... мне свою́ тетра́дь, я прове́рю твоё дома́шнее зада́ние.","b":1},{"t":"subhead","text":"Đáp án: носи́ (từ носи́ть); Неси́ (từ нести́)."},{"t":"para","text":"Dịch: Đừng xách/mang nước bằng xô sắt, thà lấy cái xô nhựa đi, nó nhẹ hơn. Hãy mang quyển vở của em lại đây, tôi sẽ kiểm tra bài tập về nhà."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не носи́","vi":"Phủ định + Đa chiều (носи́ть) → Khuyên can chung chung hoặc cấm thực hiện hành động này (đừng dùng xô sắt để mang).","g":null},{"t":"vocab","ru":"Неси́","vi":"Mệnh lệnh khẳng định + Một chiều (нести́) → Yêu cầu mang vật đến một địa điểm cụ thể ngay lúc này.","g":null},{"t":"para","text":"2. Че́рез у́лицу ... осторо́жно, не попади́ под маши́ну. Не ... одна́ ве́чером по у́лице, в на́шем го́роде э́то небезопа́сно.","b":1},{"t":"subhead","text":"Đáp án: иди́ (hoặc переходи́); ходи́."},{"t":"para","text":"Dịch: Đi (băng qua) đường thì cẩn thận, kẻo bị xe tông. Đừng đi (lại) một mình buổi tối trên phố, ở thành phố chúng ta điều đó không an toàn đâu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Иди́ (Một chiều)","vi":"Chỉ dẫn cho hành động cụ thể đang/sắp thực hiện (băng qua đường).","g":null},{"t":"vocab","ru":"Не ходи́ (Đa chiều)","vi":"Phủ định, cấm đoán một thói quen/hành động chung chung.","g":null},{"t":"vocab","ru":"Не ... под дождём","vi":"промо́кнешь. Не ... о́чень бы́стро, я не успева́ю.","g":null},{"t":"subhead","text":"Đáp án: ходи́ (hoặc гуля́й); беги́ (hoặc иди́)."},{"t":"para","text":"Dịch: Đừng đi dưới mưa: ướt đấy. Đừng chạy/đi nhanh quá, tôi không theo kịp."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не ходи́ (Đa chiều)","vi":"Cấm đoán chung (đừng đi vào vùng có mưa).","g":null},{"t":"vocab","ru":"Не беги́ (Một chiều)","vi":"Ở đây dùng dạng phủ định của động từ một chiều (бежа́ть) để yêu cầu ngừng hoặc giảm cường độ của hành động đang diễn ra cụ thể (bạn đang chạy nhanh quá → đừng chạy nhanh thế nữa). Đây là trường hợp đặc biệt: cấm hành động đang diễn ra trước mắt.","g":null},{"t":"para","text":"4. Что происхо́дит вокру́г тебя́. ... изо всех сил и предупреди́ его́!","b":1},{"t":"subhead","text":"Đáp án: Лети́ (từ лете́ть)."},{"t":"para","text":"Dịch: (Hãy xem) chuyện gì đang xảy ra quanh bạn kìa. Hãy bay (lao đi) hết sức bình sinh và cảnh báo cậu ấy!"},{"t":"example","text":"Giải thích: Лети́ (nghĩa bóng: chạy thật nhanh như bay) → Mệnh lệnh khẳng định, hành động cấp bách hướng tới mục tiêu → Một chiều."},{"t":"vocab","ru":"... на метро́","vi":"так быстре́е. Не ... на по́езде, вы потеря́ете мно́го вре́мени.","g":null},{"t":"subhead","text":"Đáp án: Поезжа́й (từ е́хать); е́зди (từ е́здить)."},{"t":"para","text":"Dịch: Hãy đi bằng tàu điện ngầm: thế nhanh hơn. Đừng đi bằng tàu hỏa, các bạn sẽ mất nhiều thời gian đấy."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Поезжа́й","vi":"Mệnh lệnh khẳng định của е́хать (dùng dạng thay thế поезжай). Chỉ dẫn cho chuyến đi cụ thể.","g":null},{"t":"vocab","ru":"Не е́зди (hoặc не е́здите)","vi":"Phủ định + Đa chiều. Khuyên không nên chọn phương tiện đó.","g":null},{"t":"vocab","ru":"Лу́чше ты ... маши́ну","vi":"я что-то уста́л сего́дня. Не ... дете́й в музе́й, в кото́рых они́ всё равно́ ничего́ не пойму́т.","g":null},{"t":"subhead","text":"Đáp án: веди́; води́."},{"t":"para","text":"Dịch: Tốt nhất bạn hãy lái xe đi: hôm nay tôi hơi mệt. Đừng dẫn trẻ con vào những bảo tàng mà đằng nào chúng cũng chẳng hiểu gì."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Веди́ (Một chiều)","vi":"Yêu cầu thực hiện hành động lái xe cụ thể ngay lúc này.","g":null},{"t":"vocab","ru":"Не води́ (Đa chiều)","vi":"Phủ định, khuyên không nên dẫn đi (nói chung).","g":null},{"t":"para","text":"7. Бо́льше ... на спине́, врачи́ сказали, что тебе́ э́то поле́зно. ... вон за той ло́дкой: в ней оста́вила наш мяч.","b":1},{"t":"subhead","text":"Đáp án: пла́вай; плыви́."},{"t":"para","text":"Dịch: Hãy bơi ngửa nhiều hơn, bác sĩ bảo điều đó tốt cho bạn. Hãy bơi theo chiếc thuyền kia kìa: trong đó có quả bóng của chúng ta."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Пла́вай (Đa chiều)","vi":"Khuyên tập luyện thường xuyên.","g":null},{"t":"vocab","ru":"Плыви́ (Một chiều)","vi":"Bơi về hướng mục tiêu cụ thể.","g":null},{"t":"para","text":"8. Ма́ленькие ве́щи ... с собо́й в сало́н самолёта, а больши́е сда́йте в бага́ж. Никогда́ не ... с собо́й сли́шком мно́го веще́й.","b":1},{"t":"subhead","text":"Đáp án: бери́те (lấy/cầm) hoặc неси́те (xách); вози́те (chở/mang theo xe/tàu)."},{"t":"note","text":"Lưu ý: Sách yêu cầu động từ chuyển động."},{"t":"para","text":"Vế 1: Неси́те (Hãy xách/mang - một chiều) vào trong cabin."},{"t":"example","text":"Vế 2: Не вози́те (Đừng mang/chở theo - đa chiều) mỗi khi đi du lịch. (Dịch: Những đồ nhỏ thì hãy xách theo vào khoang máy bay, còn đồ to thì ký gửi. Đừng bao giờ mang (chở) theo quá nhiều đồ.)"},{"t":"para","text":"9. Никогда́ не ... ко мне в стол и не тро́гай мои́ бума́ги. Стой! Не ... в э́ту пеще́ру, ты мо́жешь заблуди́ться.","b":1},{"t":"subhead","text":"Đáp án: ла́зай; лезь."},{"t":"para","text":"Dịch: Đừng bao giờ lục lọi (leo/thò tay) vào bàn của tôi và đừng động vào giấy tờ. Đứng lại! Đừng chui (leo) vào cái hang đó, bạn có thể bị lạc đấy."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не ла́зай (Đa chiều)","vi":"Cấm hành động lặp lại (Nikogda - không bao giờ).","g":null},{"t":"vocab","ru":"Не лезь (Một chiều)","vi":"Ngăn chặn hành động nguy hiểm sắp xảy ra ngay trước mắt (Cấm chỉ định).","g":null},{"t":"para","text":"10. Не ... по бе́регу, собира́я раку́шки, мы смо́жем купи́ть их в магази́не. Ложи́сь на живо́т и ..., мо́жет быть, в высо́кой траве́ тебя́ не заме́тят.","b":1},{"t":"subhead","text":"Đáp án: по́лзай; ползи́."},{"t":"para","text":"Dịch: Đừng bò (lê la) trên bờ biển nhặt vỏ ốc nữa, chúng ta có thể mua ở cửa hàng mà. Nằm sấp xuống và bò đi, có lẽ trong đám cỏ cao người ta sẽ không thấy bạn đâu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не по́лзай (Đa chiều)","vi":"Cấm hành động lê la mất thời gian.","g":null},{"t":"vocab","ru":"Ползи́ (Một chiều)","vi":"Hướng dẫn phương thức di chuyển cụ thể để ẩn nấp.","g":null}]},{"id":"07-s108","type":"exercise","title":"Bài 605 (Trang 319-320)","num":605,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте необходи́мые по смы́слу глаго́лы движе́ния в фо́рме императи́ва. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Thay dấu ba chấm bằng các động từ chuyển động cần thiết theo ý nghĩa ở dạng mệnh lệnh. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"subhead","text":"Gợi ý ngữ pháp:","b":1},{"t":"para","text":"Mệnh lệnh khẳng định (Hãy làm gì):","b":1},{"t":"example","text":"Dùng động từ một chiều (иди́, беги́, плыви́...) cho hành động cụ thể, diễn ra một lần, hướng tới mục tiêu xác định."},{"t":"example","text":"Dùng động từ đa chiều (ходи́, бе́гай, пла́вай...) cho hành động lặp đi lặp lại, thói quen, hoặc khả năng."},{"t":"para","text":"Mệnh lệnh phủ định (Đừng làm gì):","b":1},{"t":"example","text":"Thường dùng động từ đa chiều (не ходи́, не бе́гай...) để cấm đoán chung chung hoặc khuyên không nên làm."},{"t":"example","text":"Dùng động từ một chiều (не иди́, не беги́...) khi muốn ngăn chặn một hành động cụ thể đang diễn ra (ví dụ: не беги так быстро - đừng chạy nhanh thế [ngay lúc này]) hoặc cảnh báo nguy hiểm tức thì (не лезь!)."},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"1. Не ... по по́лу, у тебя́ все коле́ни уже́ гря́зные.","b":1},{"t":"subhead","text":"Đáp án: по́лзай (từ по́лзать - đa chiều)."},{"t":"para","text":"Dịch: Đừng bò (lê la) trên sàn nhà, đầu gối con bẩn hết rồi kìa."},{"t":"para","text":"Giải thích: Cấm hành động bò qua bò lại (chơi đùa) trên sàn nói chung → Dùng đa chiều."},{"t":"para","text":"2. Не ... меня́ за́ руку, я сам пойду́.","b":1},{"t":"subhead","text":"Đáp án: тащи́ / тяни́ (từ тащи́ть - một chiều)."},{"t":"para","text":"Dịch: Đừng lôi/kéo tay tôi, tôi tự đi được."},{"t":"para","text":"Giải thích: Ngăn chặn hành động đang diễn ra cụ thể ngay lúc đó (bạn đang kéo tôi → đừng kéo nữa). Dùng một chiều để chỉ sự tác động trực tiếp vào đối tượng theo một hướng."},{"t":"para","text":"3. Не ... по газо́нам на велосипе́де!","b":1},{"t":"subhead","text":"Đáp án: ката́йся / е́зди (từ ката́ться / е́здить - đa chiều)."},{"t":"para","text":"Dịch: Đừng đạp xe / đi xe trên bãi cỏ!"},{"t":"para","text":"Giải thích: Cấm hành động đi lại (chơi bời) trong khu vực bãi cỏ."},{"t":"para","text":"4. Не ... сли́шком тяжёлые су́мки.","b":1},{"t":"subhead","text":"Đáp án: носи́ (từ носи́ть - đa chiều)."},{"t":"para","text":"Dịch: Đừng mang/xách những chiếc túi quá nặng."},{"t":"para","text":"Giải thích: Lời khuyên chung chung, áp dụng cho nhiều lần (đừng có thói quen xách nặng)."},{"t":"para","text":"5. Бо́льше ... пешко́м.","b":1},{"t":"subhead","text":"Đáp án: ходи́ / ходи́те (từ ходи́ть - đa chiều)."},{"t":"para","text":"Dịch: Hãy đi bộ nhiều hơn."},{"t":"para","text":"Giải thích: Khuyên về thói quen, hoạt động lặp lại để tốt cho sức khỏe."},{"t":"para","text":"6. Не ... меня́ от себя́, я могу́ тебе́ помо́чь.","b":1},{"t":"subhead","text":"Đáp án: гони́ (từ гнать - một chiều)."},{"t":"para","text":"Dịch: Đừng xua đuổi tôi, tôi có thể giúp bạn mà."},{"t":"example","text":"Giải thích: Гнать ở nghĩa bóng (đuổi đi). Dùng một chiều để ngăn chặn hành động cự tuyệt đang diễn ra hoặc sắp xảy ra với người nói."},{"t":"para","text":"7. Не ... че́рез пери́ла балко́на, э́то опа́сно.","b":1},{"t":"subhead","text":"Đáp án: лезь (từ лезть - một chiều)."},{"t":"para","text":"Dịch: Đừng leo qua lan can ban công, nguy hiểm đấy."},{"t":"example","text":"Giải thích: Cảnh báo nguy hiểm cho một hành động cụ thể (leo qua). Với лезть, dạng phủ định một chiều не лезь rất phổ biến để cấm hành động nguy hiểm tức thì."},{"t":"para","text":"8. Не ... бли́зко от теплохо́да.","b":1},{"t":"subhead","text":"Đáp án: пла́вай / подплыва́й (từ пла́вать - đa chiều hoặc подплыва́ть)."},{"t":"para","text":"Dịch: Đừng bơi gần tàu thủy."},{"t":"example","text":"Giải thích: Quy tắc an toàn chung chung → Dùng đa chiều не плавай."},{"t":"para","text":"9. Не ... ша́рики из хле́ба.","b":1},{"t":"subhead","text":"Đáp án: ката́й (từ ката́ть - đa chiều)."},{"t":"para","text":"Dịch: Đừng vo những viên bi từ ruột bánh mì."},{"t":"para","text":"Giải thích: Cấm hành động nghịch ngợm lặp đi lặp lại (vo tròn)."},{"t":"para","text":"10. Не ... в темноте́, включи́ свет.","b":1},{"t":"subhead","text":"Đáp án: ходи́ / броди́ / сиди́ (từ ходи́ть - đa chiều)."},{"t":"para","text":"Dịch: Đừng đi lại trong bóng tối, bật đèn lên đi."},{"t":"example","text":"Giải thích: Cấm hành động đi lại trong hoàn cảnh cụ thể (tối), nhưng hành động đi không có hướng nhất định → Dùng đa chiều ходи."},{"t":"para","text":"11. ... в пя́тницу, как раз есть подходя́щий рейс на пять часо́в ве́чера.","b":1},{"t":"subhead","text":"Đáp án: Лети́те (từ лете́ть - một chiều)."},{"t":"para","text":"Dịch: Hãy bay vào thứ sáu đi, vừa khéo có chuyến bay thích hợp lúc 5 giờ chiều."},{"t":"para","text":"Giải thích: Khuyên thực hiện một chuyến đi cụ thể."},{"t":"para","text":"12. ... на авто́бусе, так быстре́е.","b":1},{"t":"subhead","text":"Đáp án: Поезжа́йте (hình thức mệnh lệnh của е́хать)."},{"t":"para","text":"Dịch: Hãy đi bằng xe buýt, thế nhanh hơn."},{"t":"para","text":"Giải thích: Chỉ dẫn cho một chuyến đi cụ thể."},{"t":"para","text":"13. ... мотоци́кл осторо́жно.","b":1},{"t":"subhead","text":"Đáp án: Веди́ (từ вести́ - một chiều)."},{"t":"para","text":"Dịch: Hãy lái xe máy cẩn thận."},{"t":"para","text":"Giải thích: Nhắc nhở về cách thức thực hiện hành động điều khiển xe."},{"t":"para","text":"14. ... с собо́й на заня́тия все тетра́ди.","b":1},{"t":"subhead","text":"Đáp án: Носи́ / Бери́ (từ носи́ть - đa chiều hoặc брать)."},{"t":"para","text":"Dịch: Hãy mang theo tất cả vở khi đi học."},{"t":"example","text":"Giải thích: \"На занятия\" (đến các buổi học) hàm ý nhiều lần/thường xuyên → Dùng đa chiều носи. Nếu ý là \"hôm nay hãy mang\" thì dùng неси. Tuy nhiên, ngữ cảnh thường là lời nhắc chung."},{"t":"para","text":"15. Не ... по доро́ге, мо́жешь попа́сть под маши́ну.","b":1},{"t":"subhead","text":"Đáp án: бе́гай (từ бе́гать - đa chiều)."},{"t":"para","text":"Dịch: Đừng chạy (nhảy) dưới lòng đường, có thể bị xe tông đấy."},{"t":"para","text":"Giải thích: Cấm hành động chơi đùa, chạy lung tung trên đường."},{"t":"para","text":"16. Бо́льше никогда́ не ... э́той авиакомпа́нией.","b":1},{"t":"subhead","text":"Đáp án: лета́й / лета́йте (từ лета́ть - đa chiều)."},{"t":"para","text":"Dịch: Đừng bao giờ bay hãng hàng không này nữa."},{"t":"example","text":"Giải thích: Никогда (không bao giờ) + Phủ định → Luôn dùng động từ đa chiều."},{"t":"vocab","ru":"Не ... с собо́й бе́рега! (Lưu ý","vi":"Câu này trong sách gốc có thể là \"Не бери с собой берега\" - Đừng mang bờ theo, nhưng đây là câu vô nghĩa hoặc thành ngữ hiếm. Có khả năng sách in là \"Не плыви с (от) берега\" hoặc \"Не уходи с берега\". Tuy nhiên, dựa trên các bản in phổ biến, câu này thường là Не тащи с собой... (đồ vật). Nếu từ cuối là берега, có thể là lỗi in của багажа?","g":null},{"t":"example","text":"Giả định hợp lý nhất: Не тащи/носи с собой багажа/вещей."},{"t":"example","text":"Nếu giữ nguyên văn bản (có thể là lỗi): Tôi sẽ dùng Не бери (Đừng lấy/mang)."},{"t":"para","text":"18. Е́сли ве́чером мы ... в теа́тр и́ли в бассе́йн, он растёт здоро́вым и си́льным.","b":1},{"t":"example","text":"(Câu này thuộc bài khác hoặc bị nhảy số trong bản in. Tôi sẽ giải tiếp theo mạch các câu mệnh lệnh trong bài 605)."},{"t":"para","text":"18. Е́сли ве́чером мы... (Đây là câu trần thuật, không phải mệnh lệnh. Có lẽ thuộc bài 590/591? Nhưng nếu là bài 605, ta tiếp tục các câu mệnh lệnh bên dưới)."},{"t":"example","text":"(Tiếp tục các câu mệnh lệnh trong bài 605 thực tế): 19. Не ... так бы́стро, я уста́ла."},{"t":"subhead","text":"Đáp án: беги́ / иди́ (từ бежа́ть/идти́ - một chiều)."},{"t":"para","text":"Dịch: Đừng chạy/đi nhanh thế, tôi mệt rồi."},{"t":"para","text":"Giải thích: Yêu cầu ngừng/giảm tốc độ của hành động đang diễn ra ngay lúc đó."},{"t":"para","text":"20. Не ... по ко́мнатам, как тень.","b":1},{"t":"subhead","text":"Đáp án: броди́ / ходи́ (từ броди́ть - đa chiều)."},{"t":"para","text":"Dịch: Đừng đi lang thang qua các phòng như cái bóng thế."},{"t":"para","text":"Giải thích: Đi không mục đích, lặp lại."},{"t":"para","text":"21. ..., на светофо́ре гори́т зелёный свет.","b":1},{"t":"subhead","text":"Đáp án: Иди́ / Проходи́ / Поезжа́й (Một chiều)."},{"t":"para","text":"Dịch: Đi đi, đèn xanh rồi kìa."},{"t":"para","text":"Giải thích: Thúc giục thực hiện hành động ngay lập tức."},{"t":"para","text":"22. Е́сли не мо́жешь подня́ть э́тот чемода́н, ... его́ по земле́.","b":1},{"t":"subhead","text":"Đáp án: тащи́ (từ тащи́ть - một chiều)."},{"t":"para","text":"Dịch: Nếu không nhấc nổi cái vali này, thì hãy kéo lê nó trên mặt đất."},{"t":"para","text":"Giải thích: Hướng dẫn phương thức di chuyển cụ thể cho tình huống này."},{"t":"para","text":"23. Пры́гай в во́ду и ... к бе́регу.","b":1},{"t":"subhead","text":"Đáp án: плыви́ (từ плыть - một chiều)."},{"t":"para","text":"Dịch: Nhảy xuống nước và bơi vào bờ đi."},{"t":"para","text":"Giải thích: Bơi về hướng mục tiêu cụ thể."},{"t":"para","text":"24. ... отсю́да э́того кота́, он утащи́л у нас кусо́к мя́са.","b":1},{"t":"subhead","text":"Đáp án: Гони́ (từ гнать - một chiều)."},{"t":"para","text":"Dịch: Đuổi con mèo này đi ngay, nó tha mất miếng thịt của chúng ta rồi."},{"t":"para","text":"Giải thích: Hành động xua đuổi cụ thể ngay lập tức."},{"t":"para","text":"25. Су́мка у тебя́ тяжёлая, не ... её в руке́, а ... на колёсиках.","b":1},{"t":"subhead","text":"Đáp án: неси́; вези́ (hoặc кати́)."},{"t":"para","text":"Dịch: Túi của bạn nặng đấy, đừng xách trên tay, mà hãy chở/đẩy bằng bánh xe."},{"t":"example","text":"Giải thích: Не неси (Đừng xách - ngay lúc này, thay đổi cách thức), вези (hãy chở - thực hiện ngay)."}]},{"id":"07-s109","type":"exercise","title":"Bài 606 (Trang 320)","num":606,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя глаго́лы движе́ния, да́йте синоними́чный вариа́нт вы́деленных слов и словосочета́ний. Определи́те их стилеву́ю принадле́жность. (Sử dụng động từ chuyển động, hãy đưa ra phương án đồng nghĩa cho các từ và cụm từ được in đậm. Xác định phong cách của chúng)."},{"t":"para","text":"1. Сле́дуйте за мной!","b":1},{"t":"para","text":"Đồng nghĩa: Иди́те за мной! (Hãy đi theo tôi!)"},{"t":"example","text":"Phong cách: Сле́дуйте mang sắc thái trang trọng, chính thức (official/bookish). Идите là trung tính."},{"t":"para","text":"2. Держи́те курс на юг.","b":1},{"t":"example","text":"Đồng nghĩa: Плыви́те (hoặc Лети́те/Иди́те) на юг. (Hãy bơi/bay về hướng Nam)."},{"t":"example","text":"Phong cách: Держите курс là thuật ngữ hàng hải/hàng không (chuyên ngành), mang sắc thái sách vở."},{"t":"para","text":"3. Направля́йтесь на лече́ние.","b":1},{"t":"para","text":"Đồng nghĩa: Езжа́йте / Иди́те на лечение. (Hãy đi chữa bệnh)."},{"t":"example","text":"Phong cách: Направляйтесь là văn phong hành chính, trang trọng."},{"t":"para","text":"4. Мчи́тесь изо всех сил!","b":1},{"t":"para","text":"Đồng nghĩa: Беги́те / Неси́тесь изо всех сил! (Hãy chạy hết sức!)"},{"t":"example","text":"Phong cách: Мчитесь mang sắc thái biểu cảm mạnh, văn chương (expressive/literary)."},{"t":"para","text":"5. Сто́йте у штурва́ла до обе́да.","b":1},{"t":"para","text":"Đồng nghĩa: Веди́те (су́дно/кора́бль). (Hãy lái tàu)."},{"t":"example","text":"Phong cách: Стоять у штурвала là cụm từ chuyên ngành hoặc văn chương. Вести là trung tính."},{"t":"para","text":"6. Не шата́йся по у́лицам без де́ла!","b":1},{"t":"para","text":"Đồng nghĩa: Не ходи́ / броди́ без дела. (Đừng đi lang thang vô công rồi nghề)."},{"t":"example","text":"Phong cách: Шатайся là văn phong khẩu ngữ (colloquial), có ý chê bai."},{"t":"para","text":"7. Держи́те путь на се́вер.","b":1},{"t":"para","text":"Đồng nghĩa: Иди́те / Езжа́йте на север. (Hãy đi về phương Bắc)."},{"t":"example","text":"Phong cách: Держать путь là văn phong sách vở, hơi cổ hoặc thi ca (bookish/poetic)."},{"t":"para","text":"8. Управля́й ка́тером так же внима́тельно, как маши́ной.","b":1},{"t":"para","text":"Đồng nghĩa: Веди́ катер... (Hãy lái cano...)"},{"t":"example","text":"Phong cách: Управляй là từ chung (kỹ thuật), веди là động từ chuyển động đặc thù cho phương tiện."},{"t":"para","text":"9. Не шага́й у меня́ пе́ред но́сом из угла́ в у́гол.","b":1},{"t":"para","text":"Đồng nghĩa: Не ходи́... (Đừng đi qua đi lại...)"},{"t":"example","text":"Phong cách: Шагай nhấn mạnh vào bước chân, hơi mang sắc thái mệnh lệnh thô hoặc miêu tả cụ thể dáng đi."},{"t":"para","text":"10. Не ше́ствуй так го́рдо, как бу́дто ты царь.","b":1},{"t":"para","text":"Đồng nghĩa: Не иди́... (Đừng đi...)"},{"t":"example","text":"Phong cách: Шествуй mang sắc thái mỉa mai hoặc trang trọng quá mức (đi oai vệ, diễu hành)."},{"t":"para","text":"11. Не мота́йся це́лыми дня́ми по магази́нам.","b":1},{"t":"para","text":"Đồng nghĩa: Не бе́гай / ходи́ / е́зди. (Đừng chạy/lượn lờ các cửa hàng)."},{"t":"example","text":"Phong cách: Мотайся là từ lóng/khẩu ngữ (colloquial), chỉ sự di chuyển vất vả hoặc lăng xăng."},{"t":"para","text":"12. Ступа́й в свою́ ко́мнату!","b":1},{"t":"para","text":"Đồng nghĩa: Иди́... (Đi về phòng!)"},{"t":"example","text":"Phong cách: Ступай là từ hơi cổ hoặc mang sắc thái ra lệnh gia trưởng/thân mật (colloquial/dated)."},{"t":"para","text":"13. Здесь тебе́ де́лать не́чего! (Hàm ý đuổi đi).","b":1},{"t":"para","text":"Đồng nghĩa: Уходи́ / Иди́ отсюда! (Đi khỏi đây!)"},{"t":"para","text":"Phong cách: Câu gốc là câu trần thuật dùng như mệnh lệnh."},{"t":"para","text":"14. Не волочи́ по земле́ но́ги.","b":1},{"t":"para","text":"Đồng nghĩa: Не тащи́... (Đừng lê chân)."},{"t":"example","text":"Phong cách: Волочи là khẩu ngữ."},{"t":"para","text":"15. Марш на ку́хню мыть посу́ду!","b":1},{"t":"para","text":"Đồng nghĩa: Иди́ / Беги́... (Đi rửa bát ngay!)"},{"t":"example","text":"Phong cách: Марш là khẩu lệnh quân đội dùng trong đời sống, mang tính bắt buộc mạnh mẽ (colloquial command)."},{"t":"para","text":"16. Не вме́шивайся в мои́ дела́!","b":1},{"t":"para","text":"Đồng nghĩa: Не лезь в мои дела. (Đừng xía vào chuyện của tôi)."},{"t":"example","text":"Phong cách: Вмешивайся là trung tính/trang trọng. Лезь (nghĩa bóng) là khẩu ngữ suồng sã."}]},{"id":"07-s110","type":"exercise","title":"Bài 607 (Trang 320-321)","num":607,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя глаго́лы движе́ния в фо́рме императи́ва с части́цей не и́ли без части́цы, да́йте ре́плику на предло́женные ситуа́ции. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Sử dụng động từ chuyển động ở dạng mệnh lệnh có hoặc không có tiểu từ \"не\", hãy đưa ra lời đáp cho các tình huống được đề xuất. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"subhead","text":"Gợi ý ngữ pháp cần nhớ:","b":1},{"t":"example","text":"Mệnh lệnh khẳng định (Làm đi): Dùng động từ một chiều (иди́, беги́, вези́...) cho hành động cụ thể diễn ra ngay lúc đó."},{"t":"para","text":"Mệnh lệnh phủ định (Đừng làm):","b":1},{"t":"example","text":"Dùng động từ đa chiều (не ходи́, не бе́гай, не вози́...) để khuyên ngăn chung chung hoặc cấm thực hiện hành động."},{"t":"example","text":"Dùng động từ một chiều (не беги́, не иди́...) khi muốn ngừng một hành động đang diễn ra cụ thể (ví dụ: đang chạy nhanh quá thì bảo \"đừng chạy [nhanh thế]\")."},{"t":"vocab","ru":"Động từ Ехать","vi":"Mệnh lệnh khẳng định là Поезжа́й(те). Phủ định thường dùng Не е́зди(те) hoặc cấu trúc Не на́до е́хать.","g":null},{"t":"para","text":"Giải chi tiết từng câu:","b":1},{"t":"para","text":"1. Ваш друг собира́ется идти́ в теа́тр на спекта́кль, кото́рый вы уже́ посмотре́ли и кото́рый вам не понра́вился.","b":1},{"t":"example","text":"(Bạn của bạn định đi xem kịch, vở mà bạn đã xem và không thích.)"},{"t":"subhead","text":"Đáp án: Не ходи́.","b":1},{"t":"para","text":"Dịch: Đừng đi."},{"t":"para","text":"Giải thích: Khuyên ngăn không nên thực hiện hành động đó (phủ định + đa chiều)."},{"t":"para","text":"2. Ва́ша знако́мая о́чень торо́пится, а вы за ней не успева́ете.","b":1},{"t":"example","text":"(Người quen của bạn đang rất vội [đi/chạy nhanh], còn bạn thì không theo kịp cô ấy.)"},{"t":"subhead","text":"Đáp án: Не беги́ (так бы́стро)! / Не иди́ (так бы́стро)!","b":1},{"t":"para","text":"Dịch: Đừng chạy (nhanh thế)! / Đừng đi (nhanh thế)!"},{"t":"example","text":"Giải thích: Yêu cầu ngừng hoặc giảm cường độ của hành động đang diễn ra ngay trước mắt → Dùng phủ định của động từ một chiều (беги́/иди́)."},{"t":"para","text":"3. На по́езде биле́тов нет, но ваш друг мо́жет добра́ться до ме́ста на авто́бусе.","b":1},{"t":"example","text":"(Tàu hỏa hết vé, nhưng bạn của bạn có thể đến nơi bằng xe buýt.)"},{"t":"subhead","text":"Đáp án: Поезжа́й на авто́бусе.","b":1},{"t":"para","text":"Dịch: Hãy đi bằng xe buýt đi."},{"t":"example","text":"Giải thích: Chỉ dẫn cho một chuyến đi cụ thể bằng phương tiện → Dùng Поезжа́й (dạng mệnh lệnh của е́хать)."},{"t":"para","text":"4. Ва́ша знако́мая собира́ется в магази́н и тя́нет вас за́ руку с собо́й, а вы не хоти́те туда́ идти́.","b":1},{"t":"example","text":"(Người quen của bạn định đi cửa hàng và đang lôi tay bạn đi theo, nhưng bạn không muốn đi.)"},{"t":"subhead","text":"Đáp án: Не тяни́ / Не тащи́ (меня́).","b":1},{"t":"para","text":"Dịch: Đừng lôi / Đừng kéo (tôi)."},{"t":"example","text":"Giải thích: Yêu cầu chấm dứt hành động cưỡng ép đang tác động trực tiếp lên người nói → Dùng phủ định động từ một chiều (тяни́ hoặc тащи́ - lôi/kéo)."},{"t":"para","text":"5. У ва́шего дру́га, кото́рый собира́ется лете́ть на самолёте, бага́ж превыша́ет 20 килогра́ммов.","b":1},{"t":"example","text":"(Bạn của bạn định đi máy bay, nhưng hành lý vượt quá 20kg.)"},{"t":"subhead","text":"Đáp án: Не бери́ (с собо́й сто́лько) / Не вези́ (сто́лько).","b":1},{"t":"para","text":"Dịch: Đừng mang (theo nhiều thế) / Đừng chở (nhiều thế)."},{"t":"example","text":"Giải thích: Khuyên bớt đồ lại cho chuyến đi này. Dùng не вези (đừng vận chuyển - một chiều, ám chỉ chuyến đi cụ thể này) hoặc не бери (đừng cầm/lấy - động từ thường)."},{"t":"para","text":"6. Ваш знако́мый отплы́л далеко́ от бе́рега, а вы за него́ беспоко́итесь.","b":1},{"t":"example","text":"(Người quen của bạn đã bơi ra xa bờ, và bạn lo lắng cho anh ấy.)"},{"t":"subhead","text":"Đáp án: Не заплыва́й (так далеко́)! / Плыви́ наза́д (сюда́)!","b":1},{"t":"para","text":"Dịch: Đừng bơi ra (xa thế)! / Bơi quay lại (đây) đi!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не заплыва́й","vi":"Động từ có tiền tố, cấm vượt quá giới hạn.","g":null},{"t":"vocab","ru":"Плыви́","vi":"Mệnh lệnh khẳng định, yêu cầu bơi về hướng cụ thể (một chiều).","g":null},{"t":"para","text":"7. Ваш друг не наде́л тёплые носки́, а на у́лице хо́лодно.","b":1},{"t":"example","text":"(Bạn của bạn không đi tất ấm, mà ngoài trời thì lạnh.)"},{"t":"subhead","text":"Đáp án: Не ходи́ (так). / Иди́ наде́нь.","b":1},{"t":"para","text":"Dịch: Đừng đi (như thế). / Đi mặc vào đi."},{"t":"example","text":"Giải thích: Не ходи (cấm đi ra ngoài trong tình trạng đó - đa chiều). Иди (sai khiến đi làm việc gì đó ngay - một chiều)."},{"t":"para","text":"8. Вы встре́тили почтальо́на, кото́рый нерегуля́рно доставля́ет вам по́чту.","b":1},{"t":"example","text":"(Bạn gặp người đưa thư, người mà chuyển thư cho bạn rất thất thường.)"},{"t":"subhead","text":"Đáp án: Носи́те по́чту во́время!","b":1},{"t":"para","text":"Dịch: Hãy mang thư đúng giờ/đều đặn nhé!"},{"t":"example","text":"Giải thích: Yêu cầu về một hành động lặp đi lặp lại (công việc hàng ngày) → Dùng động từ đa chiều (носи́те)."},{"t":"para","text":"9. Полуторагодова́лый ребёнок, кото́рый уже́ хо́дит, предпочита́ет передвига́ться, не поднима́ясь на́ ноги.","b":1},{"t":"example","text":"(Đứa trẻ 1 tuổi rưỡi đã biết đi, nhưng lại thích di chuyển mà không chịu đứng dậy [tức là bò].)"},{"t":"subhead","text":"Đáp án: Не по́лзай! / Иди́ (ножка́ми)!","b":1},{"t":"para","text":"Dịch: Đừng bò nữa! / Đi (bằng chân) đi!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не по́лзай","vi":"Cấm thói quen/hành động lê la (đa chiều).","g":null},{"t":"vocab","ru":"Иди́","vi":"Khuyến khích thực hiện hành động đi cụ thể ngay lúc đó (một chiều).","g":null},{"t":"para","text":"10. Вы ви́дите, как по ку́хне в темноте́ дви́гается ваш брат.","b":1},{"t":"example","text":"(Bạn thấy em trai đang di chuyển trong bếp trong bóng tối.)"},{"t":"subhead","text":"Đáp án: Не ходи́ в темноте́!","b":1},{"t":"para","text":"Dịch: Đừng đi lại trong bóng tối!"},{"t":"example","text":"Giải thích: Cấm hành động đi lại trong hoàn cảnh cụ thể (đa chiều ходи vì đi trong không gian hẹp, không hướng cụ thể)."},{"t":"para","text":"11. Де́ти игра́ют в пятна́шки на доро́ге, где мо́гут появи́ться маши́ны.","b":1},{"t":"example","text":"(Lũ trẻ chơi đuổi bắt trên đường, nơi ô tô có thể xuất hiện.)"},{"t":"subhead","text":"Đáp án: Не бе́гайте (здесь / по доро́ге)!","b":1},{"t":"para","text":"Dịch: Đừng chạy nhảy (ở đây / trên đường)!"},{"t":"example","text":"Giải thích: Cấm hành động chạy chơi, lăng xăng (đa chiều бе́гать)."},{"t":"para","text":"12. Вы хоти́те предупреди́ть води́теля, что в конце́ доро́ги, на кото́рую он хо́чет сверну́ть, тупи́к.","b":1},{"t":"example","text":"(Bạn muốn cảnh báo tài xế rằng cuối con đường anh ta định rẽ vào là ngõ cụt.)"},{"t":"subhead","text":"Đáp án: Не езди́ (туда́)! / Не на́до туда́ е́хать!","b":1},{"t":"para","text":"Dịch: Đừng đi (vào đó)! / Không nên đi vào đó đâu!"},{"t":"example","text":"Giải thích: Với ехать, để cấm đoán, người Nga thường dùng Не на́до е́хать hoặc Не езди (đa chiều dùng cho cấm đoán chung). (Lưu ý: Dạng \"не едь\" là sai ngữ pháp chuẩn mực)."},{"t":"para","text":"13. Вы замеча́ете, что у тяжёлой су́мки, кото́рую ва́ша знако́мая де́ржит в руке́, есть колёсики.","b":1},{"t":"example","text":"(Bạn nhận thấy chiếc túi nặng mà người quen đang xách trên tay có bánh xe.)"},{"t":"subhead","text":"Đáp án: Не неси́, а вези́ (её)!","b":1},{"t":"para","text":"Dịch: Đừng xách, hãy kéo (chở) nó đi!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не неси́","vi":"Ngừng hành động xách đang diễn ra (một chiều phủ định).","g":null},{"t":"vocab","ru":"Вези́","vi":"Hãy thực hiện hành động kéo/chở ngay lúc này (một chiều khẳng định).","g":null},{"t":"para","text":"14. Зубно́й врач не мо́жет вы́рвать вам зуб, вы хоти́те, что́бы он э́то сде́лал быстре́е.","b":1},{"t":"example","text":"(Nha sĩ không nhổ được răng cho bạn, bạn muốn ông ấy làm nhanh lên.)"},{"t":"subhead","text":"Đáp án: Тащи́ (быстре́е)! / Тяни́!","b":1},{"t":"para","text":"Dịch: Lôi / Kéo (mạnh/nhanh) lên!"},{"t":"example","text":"Giải thích: Thúc giục thực hiện hành động dùng sức theo một hướng cụ thể → Dùng тащи́ (từ тащи́ть)."},{"t":"para","text":"15. Ваш сын идёт в магази́н, вы хоти́те, что́бы он поторопи́лся и возвраща́лся быстре́е.","b":1},{"t":"example","text":"(Con trai bạn đi ra cửa hàng, bạn muốn nó nhanh chân lên để về sớm.)"},{"t":"subhead","text":"Đáp án: Беги́! / Сбе́гай!","b":1},{"t":"para","text":"Dịch: Chạy đi! / Chạy ù ra đó (rồi về)!"},{"t":"example","text":"Giải thích: Беги́ (chạy đi - một chiều) hoặc Сбе́гай (động từ hoàn thành: chạy đi rồi về nhanh)."},{"t":"para","text":"16. Ва́шему знако́мому ну́жно в Ри́о-де-Жане́йро, но прямо́го ре́йса нет, а есть то́лько с переса́дкой в Ло́ндоне.","b":1},{"t":"example","text":"(Người quen cần đi Rio, nhưng không có bay thẳng mà phải quá cảnh London.)"},{"t":"subhead","text":"Đáp án: Лети́ че́рез Ло́ндон.","b":1},{"t":"para","text":"Dịch: Hãy bay qua London đi."},{"t":"example","text":"Giải thích: Chỉ dẫn lộ trình cho một chuyến đi cụ thể → Dùng Лети́ (một chiều)."},{"t":"para","text":"17. Вы отвеча́ете прохо́жему, что ему́ на́до сесть на трамва́й.","b":1},{"t":"example","text":"(Bạn trả lời người qua đường là anh ta cần đi tàu điện.)"},{"t":"subhead","text":"Đáp án: Поезжа́йте на трамва́е.","b":1},{"t":"para","text":"Dịch: Ông/Anh hãy đi bằng tàu điện."},{"t":"example","text":"Giải thích: Mệnh lệnh thức chuẩn mực của е́хать là поезжа́йте."},{"t":"para","text":"18. Вам сообща́ют, что посети́тель ждёт вас на пе́рвом этаже́, вы про́сите проводи́ть его́ в ваш кабине́т на второ́й этаж.","b":1},{"t":"example","text":"(Người ta báo có khách đợi ở tầng 1, bạn yêu cầu dẫn khách lên phòng bạn ở tầng 2.)"},{"t":"subhead","text":"Đáp án: Веди́те его́ (сюда́ / на второ́й эта́ж).","b":1},{"t":"para","text":"Dịch: Hãy dẫn ông ấy (lên đây / lên tầng 2)."},{"t":"example","text":"Giải thích: Yêu cầu thực hiện hành động dẫn người đến đích cụ thể → Dùng веди́те (một chiều)."},{"t":"para","text":"19. Ва́ши друзья́, отдыха́ющие на ю́ге, звоня́т вам и спра́шивают, каки́х фру́ктов захвати́ть с собо́й.","b":1},{"t":"example","text":"(Bạn bè đang nghỉ mát ở phương Nam gọi hỏi cần mang hoa quả gì về.)"},{"t":"subhead","text":"Đáp án: Вези́те (любы́е / виногра́д...)!","b":1},{"t":"para","text":"Dịch: Hãy chở/mang (bất cứ loại nào / nho...) về nhé!"},{"t":"example","text":"Giải thích: Yêu cầu vận chuyển hàng hóa bằng phương tiện trong chuyến đi cụ thể sắp tới → Dùng вези́те (một chiều)."},{"t":"para","text":"20. Вы сообща́ете прохо́жему, что тролле́йбус, кото́рый ему́ ну́жен, как раз стои́т на остано́вке и что е́сли он поторо́пится, то ещё на него́ успе́ет.","b":1},{"t":"example","text":"(Bạn bảo người qua đường là xe buýt điện anh ta cần đang ở bến, nếu nhanh chân thì kịp.)"},{"t":"subhead","text":"Đáp án: Беги́те!","b":1},{"t":"para","text":"Dịch: Chạy đi!"},{"t":"example","text":"Giải thích: Thúc giục hành động di chuyển nhanh về phía mục tiêu → Dùng беги́те (một chiều)."},{"t":"para","text":"21. Ва́ша знако́мая обща́ется с людьми́, в че́стности кото́рых она́ сомнева́ется. Вы сове́туете ей от них изба́виться.","b":1},{"t":"example","text":"(Người quen giao du với những kẻ không trung thực. Bạn khuyên cô ấy tống khứ họ đi.)"},{"t":"subhead","text":"Đáp án: Гони́ их!","b":1},{"t":"para","text":"Dịch: Đuổi cổ họ đi!"},{"t":"example","text":"Giải thích: Гнать (đuổi) dùng ở nghĩa bóng. Mệnh lệnh quyết liệt, hướng đối tượng ra xa → Dùng гони́ (một chiều)."},{"t":"para","text":"22. Вы хоти́те, что́бы ваш друг, кото́рый пла́вает неподалёку, прибли́зился к вам.","b":1},{"t":"example","text":"(Bạn muốn người bạn đang bơi gần đó tiến lại gần bạn.)"},{"t":"subhead","text":"Đáp án: Плыви́ сюда́ (ко мне)!","b":1},{"t":"para","text":"Dịch: Bơi lại đây (với tớ)!"},{"t":"example","text":"Giải thích: Yêu cầu di chuyển tới mục tiêu cụ thể → Dùng плыви́ (một chiều)."}]},{"id":"07-s111","type":"exercise","title":"Bài 608 (Trang 321)","num":608,"blocks":[{"t":"instruction","text":"Yêu cầu: В соста́вленных ва́ми предложе́ниях из упражне́ния 602 замени́те глаго́лы движе́ния в бу́дущем вре́мени фо́рмой повели́тельного наклоне́ния. (Trong các câu bạn đã đặt ở bài tập 602, hãy thay thế các động từ chuyển động ở thì tương lai bằng dạng mệnh lệnh)."},{"t":"example","text":"Nhắc lại nội dung bài 602 (Viết thư khuyên bạn sắp sang Nga): Câu gốc (Tương lai) → Chuyển sang Mệnh lệnh (Lời khuyên trực tiếp)."},{"t":"example","text":"1. Tương lai: Когда́ ты бу́дешь лете́ть в самолёте, не забу́дь заполни́ть миграцио́нную ка́рту. (Khi bạn bay trên máy bay, đừng quên điền tờ khai...)"},{"t":"para","text":"Mệnh lệnh (Bài 608): Когда́ бу́дешь лете́ть... (Vẫn giữ nguyên vì đây là mệnh đề thời gian, không thể chuyển thành mệnh lệnh trong cấu trúc \"Khi...\")."},{"t":"example","text":"Tuy nhiên, nếu sách yêu cầu chuyển ý chính thành mệnh lệnh: Лети́ самолётом Аэрофло́та. (Hãy bay bằng máy bay Aeroflot)."},{"t":"example","text":"Hoặc chuyển đổi câu: Бу́дучи в самолёте... (Khi ở trên máy bay...). Nhưng đề bài yêu cầu thay động từ tương lai thành mệnh lệnh, điều này thường áp dụng cho mệnh đề chính."},{"t":"example","text":"Giả sử câu gốc là: \"Ты полетишь...\" → Лети́... (Hãy bay...)."},{"t":"example","text":"2. Tương lai: Из аэропо́рта до го́рода ты пое́дешь на авто́бусе. (Từ sân bay về phố bạn sẽ đi xe buýt)."},{"t":"para","text":"Mệnh lệnh: Из аэропо́рта до го́рода поезжа́й на авто́бусе."},{"t":"para","text":"Dịch: Từ sân bay về phố hãy đi bằng xe buýt."},{"t":"example","text":"3. Tương lai: В Москве́ ты бу́дешь мно́го ходи́ть пешко́м. (Ở Moscow bạn sẽ đi bộ nhiều)."},{"t":"para","text":"Mệnh lệnh: В Москве́ мно́го ходи́ пешко́м."},{"t":"para","text":"Dịch: Ở Moscow hãy đi bộ nhiều vào."},{"t":"example","text":"4. Tương lai: Е́сли ты бу́дешь е́хать на авто́бусе, следи́ за веща́ми. (Nếu bạn đi xe buýt, hãy trông đồ)."},{"t":"para","text":"Mệnh lệnh: Khi chuyển sang mệnh lệnh, ta thường bỏ \"nếu/khi\": Поезжа́й на авто́бусе и следи́ за веща́ми. (Hãy đi xe buýt và trông đồ)."},{"t":"example","text":"5. Tương lai: Ты бу́дешь е́здить на метро́. (Bạn sẽ đi tàu điện ngầm - thường xuyên)."},{"t":"para","text":"Mệnh lệnh: Е́зди на метро́, э́то удо́бно."},{"t":"para","text":"Dịch: Hãy đi (lại) bằng tàu điện ngầm, tiện lắm."},{"t":"example","text":"6. Tương lai: Ты бу́дешь води́ть друзе́й в музе́и. (Bạn sẽ dẫn bạn bè đi bảo tàng)."},{"t":"para","text":"Mệnh lệnh: Води́ друзе́й в музе́и."},{"t":"para","text":"Dịch: Hãy dẫn bạn bè đi bảo tàng nhé."},{"t":"para","text":"Глаго́лы движе́ния в переносном значении","b":1},{"t":"example","text":"(Động từ chuyển động ở nghĩa bóng)"},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 321):","b":1},{"t":"para","text":"Tiếng Nga: Глаго́лы движе́ния в переносном значении обычно не образу́ют пары в зави́симости от однонапра́вленного или разнонапра́вленного хара́ктера движе́ния."},{"t":"example","text":"Dịch & Giải thích: Các động từ chuyển động khi dùng ở nghĩa bóng thường không tạo thành cặp (một chiều/đa chiều) dựa trên tính chất hướng của chuyển động như nghĩa đen. Thay vào đó, mỗi ý nghĩa bóng thường gắn cố định với một dạng động từ cụ thể (ví dụ: вре́мя идёт - thời gian trôi [chỉ dùng идти], носи́ть очки́ - đeo kính [chỉ dùng носить])."}]},{"id":"07-s112","type":"exercise","title":"Bài 609 (Trang 321)","num":609,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочитайте предложения. Определите значение выделенных глаголов движения. Назовите инфинитивы, от которых они образованы. (Đọc các câu văn. Xác định ý nghĩa của các động từ chuyển động được in đậm. Gọi tên động từ nguyên mẫu mà từ đó chúng được tạo thành)."},{"t":"example","text":"a) 1. Тебе́ идёт э́тот костю́м. В институ́т он хо́дит в джи́нсах.","b":1},{"t":"vocab","ru":"идёт (từ идти́)","vi":"Nghĩa là phù hợp, hợp (về kiểu dáng, màu sắc). Dịch: Bộ vest này hợp với bạn.","g":null},{"t":"vocab","ru":"хо́дит (từ ходи́ть)","vi":"Nghĩa là mặc (thói quen, thường xuyên mặc). Dịch: Đến trường đại học cậu ấy thường mặc quần jean.","g":null},{"t":"example","text":"2. Под горо́й бежи́т руче́й. Она́ не отве́тила, глаза́ её бе́гали по стра́ницам пись́ма, кото́рое она́ то́лько что получи́ла.","b":1},{"t":"vocab","ru":"бежи́т (từ бежа́ть)","vi":"Nghĩa là chảy, tuôn (dòng nước). Dịch: Dưới chân núi có con suối chảy.","g":null},{"t":"vocab","ru":"бе́гали (từ бе́гать)","vi":"Nghĩa là lướt nhanh, đảo mắt (ánh mắt di chuyển nhanh qua lại). Dịch: Cô ấy không trả lời, đôi mắt cô lướt nhanh trên những trang thư vừa mới nhận.","g":null},{"t":"example","text":"3. Це́ны на проду́кты стреми́тельно е́дут вверх. Су́мка у него́ болта́лась на по́ясе, её реме́нь е́здил по плечу́.","b":1},{"t":"vocab","ru":"е́дут (từ е́хать)","vi":"Nghĩa là tăng lên, leo thang (nói về giá cả, mang sắc thái nhanh). Dịch: Giá thực phẩm đang leo thang chóng mặt.","g":null},{"t":"vocab","ru":"е́здил (từ е́здить)","vi":"Nghĩa là trượt qua trượt lại, xộc xệch. Dịch: Cái túi lủng lẳng ở thắt lưng anh ta, còn cái dây đeo thì cứ trượt qua lại trên vai.","g":null},{"t":"example","text":"4. Де́ньги у него́ так и летя́т, то́лько полу́чит — и уже́ ничего́ нет. Ру́ки дирижёра пла́вно лета́ли в такт му́зыке.","b":1},{"t":"vocab","ru":"летя́т (từ лете́ть)","vi":"Nghĩa là tiêu tan, bay biến (tiêu tiền rất nhanh). Dịch: Tiền bạc của anh ta cứ đội nón ra đi (bay mất), vừa mới nhận xong là đã chẳng còn gì.","g":null},{"t":"vocab","ru":"лета́ли (từ лета́ть)","vi":"Nghĩa là bay lượn, chuyển động nhẹ nhàng trong không khí. Dịch: Đôi tay người nhạc trưởng lướt (bay) uyển chuyển theo nhịp nhạc.","g":null},{"t":"vocab","ru":"Он счастливчик","vi":"уда́ча так и плывёт к нему́ в ру́ки. Получи́в э́то изве́стие, я пла́вал от восто́рга, жизнь каза́лась мне неиссяка́емым исто́чником ра́дости.","g":null},{"t":"vocab","ru":"плывёт (từ плыть)","vi":"Nghĩa là tự tìm đến (trôi đến) một cách dễ dàng. Dịch: Cậu ta là người may mắn: vận may cứ tự trôi vào tay cậu ấy.","g":null},{"t":"vocab","ru":"пла́вал (từ пла́вать)","vi":"Nghĩa là chìm đắm, lâng lâng (trong cảm xúc). Dịch: Nhận được tin này, tôi lâng lâng trong sung sướng, cuộc đời đối với tôi dường như là nguồn vui vô tận.","g":null},{"t":"example","text":"6. Не име́я то́чной информа́ции о де́йствиях мои́х конкуре́нтов, я брёл в потёмках, пыта́ясь найти́ вы́ход из созда́вшегося положе́ния.","b":1},{"t":"vocab","ru":"брёл (từ брести́)","vi":"Nghĩa là mò mẫm, hành động mù quáng (như đi trong bóng tối). Dịch: Không có thông tin chính xác về hành động của các đối thủ, tôi đành dò dẫm trong bóng tối, cố tìm lối thoát cho tình thế đã xảy ra.","g":null}]},{"id":"07-s113","type":"exercise","title":"Bài 610 (Trang 322-323)","num":610,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя необходимый по смыслу по смыслу глагол движения. Объясните ваш выбор. (Mở ngoặc đơn, sử dụng động từ chuyển động cần thiết theo ý nghĩa. Giải thích sự lựa chọn của bạn)."},{"t":"para","text":"1. Что ты (лезть/ла́зить) ко мне со свои́ми вопро́сами?","b":1},{"t":"subhead","text":"Đáp án: ле́зешь","b":1},{"t":"para","text":"Dịch: Sao cậu cứ quấy rầy/xía vào tớ với mấy câu hỏi của cậu thế?"},{"t":"example","text":"Giải thích: Động từ лезть ở nghĩa bóng mang ý nghĩa sàm sỡ, quấy rầy, can thiệp vào chuyện người khác một cách khó chịu. Dùng dạng лезть để chỉ hành động đang diễn ra hoặc bản chất hành động gây phiền nhiễu."},{"t":"para","text":"2. Вре́мя (идти́/ходи́ть), на́до что-то реша́ть.","b":1},{"t":"subhead","text":"Đáp án: идёт","b":1},{"t":"para","text":"Dịch: Thời gian đang trôi, cần phải quyết định cái gì đó thôi."},{"t":"example","text":"Giải thích: Cố định: Время идёт (Thời gian trôi - một chiều, tuyến tính)."},{"t":"para","text":"3. Она́ (нести́/носи́ть) тра́ур по му́жу, кото́рый неда́вно у́мер.","b":1},{"t":"subhead","text":"Đáp án: но́сит","b":1},{"t":"para","text":"Dịch: Cô ấy đang để tang chồng, người vừa mới mất."},{"t":"example","text":"Giải thích: Носить (mặc, đeo, mang) dùng cho trang phục, kính, râu, tóc, tang chế... mang tính chất trạng thái kéo dài/thói quen → dùng đa chiều."},{"t":"para","text":"4. Я наблюда́л, как не́сколько пар под зву́ки ва́льса (плыть/пла́вать) по за́лу.","b":1},{"t":"subhead","text":"Đáp án: плы́ли","b":1},{"t":"para","text":"Dịch: Tôi quan sát vài cặp đôi lướt (trôi) nhẹ nhàng quanh phòng theo tiếng nhạc waltz."},{"t":"example","text":"Giải thích: Miêu tả dáng đi uyển chuyển, nhẹ nhàng như đang trôi (плыть) tại thời điểm quan sát."},{"t":"vocab","ru":"Я пригну́л го́лову","vi":"пу́ли (лете́ть/лета́ть) со всех сторо́н.","g":null},{"t":"subhead","text":"Đáp án: лете́ли","b":1},{"t":"para","text":"Dịch: Tôi cúi đầu xuống: đạn bay tới tấp từ mọi phía."},{"t":"example","text":"Giải thích: Đạn bay là chuyển động có hướng, tốc độ cao đang diễn ra → dùng лететь."},{"t":"para","text":"6. Письмо́ (идти́/ходи́ть) по рука́м, ка́ждый стара́лся прочита́ть его́ всем сам.","b":1},{"t":"subhead","text":"Đáp án: ходи́ло","b":1},{"t":"para","text":"Dịch: Bức thư được chuyền qua tay mọi người (đi vòng quanh), ai cũng cố tự đọc to nó cho mọi người nghe."},{"t":"example","text":"Giải thích: Chuyển động chuyền tay nhau trong một nhóm người, không theo một đường thẳng cố định mà đi vòng quanh → dùng đa chiều ходить."},{"t":"para","text":"7. Ни с кем из сосе́дей он дру́жбу не (вести́/води́ть).","b":1},{"t":"subhead","text":"Đáp án: во́дит","b":1},{"t":"para","text":"Dịch: Anh ta không giao du (kết bạn) với bất kỳ người hàng xóm nào."},{"t":"example","text":"Giải thích: Cụm cố định водить дружбу (kết bạn, giao du) - chỉ mối quan hệ kéo dài."},{"t":"para","text":"8. По её щека́м (бежа́ть/бе́гать) слёзы.","b":1},{"t":"subhead","text":"Đáp án: бежа́ли","b":1},{"t":"para","text":"Dịch: Nước mắt chảy (tuôn) trên má cô ấy."},{"t":"example","text":"Giải thích: Nước mắt chảy thành dòng xuống dưới (một chiều) → dùng бежать."},{"t":"para","text":"9. Не зна́я ни одного́ биле́та, он (плыть/пла́вать) на экза́мене, пыта́ясь хоть что-то отве́тить.","b":1},{"t":"subhead","text":"Đáp án: пла́вал","b":1},{"t":"para","text":"Dịch: Không thuộc một câu hỏi thi (vé) nào, cậu ta lúng túng (bơi) trong kỳ thi, cố gắng trả lời đại cái gì đó."},{"t":"example","text":"Giải thích: Плавать на экзамене (nghĩa bóng): lúng túng, không nắm chắc kiến thức, trả lời vòng vo → dùng đa chiều плавать."},{"t":"para","text":"10. Он с го́рдостью (нести́/носи́ть) фами́лию своего́ отца́ и де́да.","b":1},{"t":"subhead","text":"Đáp án: но́сит","b":1},{"t":"para","text":"Dịch: Anh ấy mang họ của cha và ông mình với niềm tự hào."},{"t":"example","text":"Giải thích: Mang tên/họ là trạng thái thường xuyên, lâu dài → dùng носить."},{"t":"para","text":"11. Стре́лки на цифербла́те неумоли́мо (ползти́/по́лзать) к ци́фре двена́дцать.","b":1},{"t":"subhead","text":"Đáp án: ползли́","b":1},{"t":"para","text":"Dịch: Kim đồng hồ chầm chậm nhích (bò) một cách tàn nhẫn về phía số 12."},{"t":"example","text":"Giải thích: Di chuyển chậm về một hướng xác định → dùng ползти."},{"t":"para","text":"12. В э́том году́ он чита́л студе́нтам тре́тьего ку́рса и (вести́/води́ть) спецку́рс.","b":1},{"t":"subhead","text":"Đáp án: вёл","b":1},{"t":"para","text":"Dịch: Năm nay ông ấy giảng bài cho sinh viên năm 3 và dạy (phụ trách) một chuyên đề."},{"t":"example","text":"Giải thích: Вести курс / урок (dạy học, chủ trì) dùng động từ вести. Ở quá khứ dùng вёл để chỉ quá trình diễn ra trong năm đó."},{"t":"para","text":"13. От пла́мени свечи́ по сте́нам (плыть/пла́вать) те́ни.","b":1},{"t":"subhead","text":"Đáp án: плы́ли","b":1},{"t":"para","text":"Dịch: Những cái bóng trôi (dao động) trên tường do ngọn nến."},{"t":"example","text":"Giải thích: Bóng di chuyển mờ ảo, lướt đi trên tường → dùng плыть."},{"t":"para","text":"14. Е́сли в жи́зни всё вре́мя (везти́/вози́ть), стано́вится ску́чно, теря́ется сти́мул к жи́зни.","b":1},{"t":"subhead","text":"Đáp án: везёт (nguyên mẫu везти́)"},{"t":"para","text":"Dịch: Nếu trong cuộc sống lúc nào cũng gặp may, thì sẽ trở nên nhàm chán, mất đi động lực sống."},{"t":"example","text":"Giải thích: Cấu trúc Komu + везёт (Ai đó gặp may) luôn dùng động từ một chiều везти ở ngôi thứ 3 số ít."},{"t":"para","text":"15. В тако́й ситуа́ции на ша́хматной доске́ на́до (идти́/ходи́ть) ферзём.","b":1},{"t":"subhead","text":"Đáp án: ходи́ть","b":1},{"t":"para","text":"Dịch: Trong tình huống như thế trên bàn cờ vua thì cần phải đi quân Hậu."},{"t":"example","text":"Giải thích: Nói về luật chơi hoặc chiến thuật chung (надо - cần phải) → dùng động từ đa chiều ходить. (Nếu là một nước đi cụ thể \"hãy đi quân Hậu\" thì dùng пойти)."},{"t":"para","text":"16. Вчера́ весь ве́чер (идти́/ходи́ть) дождь.","b":1},{"t":"subhead","text":"Đáp án: шёл","b":1},{"t":"para","text":"Dịch: Hôm qua mưa rơi (đi) suốt cả buổi tối."},{"t":"example","text":"Giải thích: Mưa rơi dùng идти (quá khứ шёл)."},{"t":"para","text":"17. Сейча́с она́ (нести́/носи́ть) коро́ткую стри́жку.","b":1},{"t":"subhead","text":"Đáp án: но́сит","b":1},{"t":"para","text":"Dịch: Bây giờ cô ấy để tóc ngắn."},{"t":"example","text":"Giải thích: Kiểu tóc (trạng thái, thời trang) → dùng носить."},{"t":"para","text":"18. Заче́м ты унижа́ешься, (ползти́/по́лзать) пе́ред ним, не сто́ит он твои́х слёз.","b":1},{"t":"subhead","text":"Đáp án: по́лзаешь","b":1},{"t":"para","text":"Dịch: Sao bạn lại hạ mình, quỵ lụy (bò lê) trước hắn ta làm gì, hắn không xứng với nước mắt của bạn đâu."},{"t":"example","text":"Giải thích: Hành động quỵ lụy hèn hạ (nghĩa bóng của bò qua bò lại dưới chân) → dùng ползать."},{"t":"para","text":"19. В настоя́щее вре́мя речь (идти́/ходи́ть) не о ва́ших пробле́мах, а обо всех нас.","b":1},{"t":"subhead","text":"Đáp án: идёт","b":1},{"t":"para","text":"Dịch: Hiện tại câu chuyện (vấn đề) đang xoay quanh (đi) không phải về vấn đề của bạn, mà là về tất cả chúng ta."},{"t":"example","text":"Giải thích: Cụm cố định: Речь идёт о... (Vấn đề là ở chỗ / Câu chuyện là về...)."},{"t":"vocab","ru":"По ко́мнате (плыть/пла́вать) клубы́ жёлтого ды́ма","vi":"прихо́дится открыва́ть фо́рточку.","g":null},{"t":"subhead","text":"Đáp án: плы́ли","b":1},{"t":"para","text":"Dịch: Những đám khói vàng trôi (lơ lửng/lan tỏa) trong phòng: đành phải mở cửa thông gió."},{"t":"example","text":"Giải thích: Khói lan tỏa thành luồng trong không khí → dùng плыть."},{"t":"para","text":"21. Кисть в его́ руке́ бы́стро (идти́/ходи́ть) по холсту́, выпи́сывая мале́йшие дета́ли портре́та.","b":1},{"t":"subhead","text":"Đáp án: ходи́ла","b":1},{"t":"para","text":"Dịch: Cây cọ trong tay ông ấy lướt (đi) nhanh thoăn thoắt trên toan, vẽ nên những chi tiết nhỏ nhất của bức chân dung."},{"t":"example","text":"Giải thích: Chuyển động qua lại trên bề mặt (vẽ) → dùng ходить."},{"t":"para","text":"22. Да, го́ды (лете́ть/лета́ть), и моло́же мы не стано́вимся.","b":1},{"t":"subhead","text":"Đáp án: летя́т","b":1},{"t":"para","text":"Dịch: Vâng, năm tháng vùn vụt trôi (bay), và chúng ta chẳng trẻ lại chút nào."},{"t":"example","text":"Giải thích: Thời gian trôi nhanh (một chiều) → dùng лететь."},{"t":"para","text":"23. Втору́ю неде́лю (идти́/ходи́ть) снег, весь го́род зава́лен сугро́бами.","b":1},{"t":"subhead","text":"Đáp án: идёт","b":1},{"t":"para","text":"Dịch: Tuyết rơi sang tuần thứ hai rồi, cả thành phố ngập trong những đống tuyết."},{"t":"example","text":"Giải thích: Hiện tượng thiên nhiên (tuyết) đang diễn ra → dùng идти."},{"t":"para","text":"24. Люба́я культу́ра (нести́/носи́ть) на себе́ отпеча́ток про́шлого.","b":1},{"t":"subhead","text":"Đáp án: несёт (từ нести́)"},{"t":"para","text":"Dịch: Bất kỳ nền văn hóa nào cũng mang trên mình dấu ấn của quá khứ."},{"t":"example","text":"Giải thích: Ở đây dùng нести (một chiều) với ý nghĩa trừu tượng: chứa đựng, bao hàm (như một đặc tính không thể tách rời). (Lưu ý: Sách Glazunova trong phần đáp án câu 24 bài 610 chọn несёт)."},{"t":"para","text":"25. Обы́чно он (идти́/ходи́ть) в джи́нсах и бе́лой футбо́лке.","b":1},{"t":"subhead","text":"Đáp án: хо́дит","b":1},{"t":"para","text":"Dịch: Bình thường cậu ấy mặc quần jean và áo phông trắng."},{"t":"example","text":"Giải thích: Thói quen ăn mặc → dùng ходить."},{"t":"para","text":"26. Ты (вести́/води́ть) себя́, как ребёнок.","b":1},{"t":"subhead","text":"Đáp án: ведёшь","b":1},{"t":"para","text":"Dịch: Cậu cư xử như một đứa trẻ con vậy."},{"t":"example","text":"Giải thích: Cụm cố định вести себя (cư xử)."},{"t":"para","text":"27. Всё (идти́/ходи́ть) к лу́чшему.","b":1},{"t":"subhead","text":"Đáp án: идёт","b":1},{"t":"para","text":"Dịch: Mọi chuyện đang tiến triển (đi) theo chiều hướng tốt đẹp."},{"t":"example","text":"Giải thích: Diễn biến sự việc theo một hướng → dùng идти."},{"t":"para","text":"611. Используя глаголы движения, дайте синонимичный вариант выделенных слов и словосочетаний. Объясните ваш выбор.","b":1},{"t":"example","text":"(Sử dụng động từ chuyển động, hãy đưa ra phương án đồng nghĩa cho các từ và cụm từ được in đậm. Giải thích sự lựa chọn của bạn)."},{"t":"example","text":"1. Обычно он очки не снимает.","b":1},{"t":"subhead","text":"Đáp án: но́сит (từ носи́ть)"},{"t":"para","text":"Dịch: Bình thường anh ấy đeo kính (không tháo kính)."},{"t":"example","text":"Giải thích: Động từ носи́ть (mang/vác - đa chiều) ở nghĩa bóng dùng để chỉ việc mặc quần áo, đeo phụ kiện (kính, râu, tóc) thường xuyên."},{"t":"example","text":"2. На улице льёт дождь.","b":1},{"t":"subhead","text":"Đáp án: идёт (từ идти́)"},{"t":"para","text":"Dịch: Ngoài trời mưa đang rơi."},{"t":"example","text":"Giải thích: Với các hiện tượng thời tiết (mưa, tuyết, mưa đá), tiếng Nga dùng động từ идти́ (đang diễn ra → một chiều)."},{"t":"example","text":"3. В детстве у неё были косы.","b":1},{"t":"subhead","text":"Đáp án: носи́ла (từ носи́ть)"},{"t":"para","text":"Dịch: Hồi nhỏ cô ấy để tóc bím."},{"t":"example","text":"Giải thích: Tương tự câu 1, носи́ть dùng cho kiểu tóc (để tóc dài, tết tóc...). Dùng quá khứ носила vì là thói quen trong quá khứ."},{"t":"example","text":"4. Сомнения постоянно возникают у меня в голове.","b":1},{"t":"subhead","text":"Đáp án: ле́зут (từ лезть)"},{"t":"para","text":"Dịch: Những nghi ngờ cứ liên tục len lỏi/chui vào đầu tôi."},{"t":"example","text":"Giải thích: Thành ngữ лезть в голову (chui vào đầu) diễn tả những ý nghĩ, giai điệu, hoặc sự nghi ngờ xâm nhập vào tâm trí một cách không mong muốn."},{"t":"example","text":"5. Этот цвет подходит к твоим глазам.","b":1},{"t":"subhead","text":"Đáp án: идёт (từ идти́)"},{"t":"para","text":"Dịch: Màu này hợp với mắt bạn."},{"t":"example","text":"Giải thích: Идти́ (ngôi thứ 3: идёт/иду́т) dùng để chỉ sự phù hợp về thẩm mỹ (quần áo, màu sắc)."},{"t":"example","text":"6. Он руководит семинаром для студентов II курса.","b":1},{"t":"subhead","text":"Đáp án: ведёт (từ вести́)"},{"t":"para","text":"Dịch: Ông ấy dẫn dắt/phụ trách buổi hội thảo cho sinh viên năm 2."},{"t":"example","text":"Giải thích: Вести́ (dẫn) ở nghĩa bóng là chủ trì, điều hành, giảng dạy một lớp học hoặc chương trình."},{"t":"example","text":"7. Для своего возраста он выполняет слишком большую нагрузку.","b":1},{"t":"subhead","text":"Đáp án: несёт (từ нести́)"},{"t":"para","text":"Dịch: Đối với tuổi của mình, ông ấy đang gánh vác một khối lượng công việc quá lớn."},{"t":"example","text":"Giải thích: Нести́ нагрузку / ответственность (gánh vác trọng trách/trách nhiệm) dùng động từ нести́."},{"t":"example","text":"8. Двигать слона на Е 5, чтобы отрезать противнику путь к отступлению.","b":1},{"t":"subhead","text":"Đáp án: перекры́ть / прегради́ть / перейти́ (доро́гу). (Trong ngữ cảnh cờ vua/chiến thuật, sách thường yêu cầu động từ chuyển động cơ bản). Ở đây ý là \"chặn đường\"."},{"t":"example","text":"Lựa chọn phù hợp nhất với động từ chuyển động: перейти́ (доро́гу) (ngáng đường/chặn đường)."},{"t":"para","text":"Dịch: Đi quân Tượng vào ô E5 để chặn/cắt đường rút lui của đối phương."},{"t":"vocab","ru":"Ему посчастливилось","vi":"он выиграл путёвку в круиз по Средиземному морю.","g":null},{"t":"subhead","text":"Đáp án: повезло́ (từ везти́)"},{"t":"para","text":"Dịch: Anh ấy gặp may: anh ấy đã thắng được một chuyến du lịch trên biển Địa Trung Hải."},{"t":"example","text":"Giải thích: Cấu trúc vô nhân xưng Кому + везти́ (Ai đó gặp may). Quá khứ: повезло́."},{"t":"example","text":"10. Часы тикают, значит всё в порядке.","b":1},{"t":"subhead","text":"Đáp án: иду́т (từ идти́)"},{"t":"para","text":"Dịch: Đồng hồ đang chạy, nghĩa là mọi thứ đều ổn."},{"t":"example","text":"Giải thích: Máy móc, đồng hồ hoạt động → dùng идти́."},{"t":"example","text":"11. Твоей шляпе уже лет пятнадцать, сколько ещё времени ты будешь ею пользоваться?","b":1},{"t":"subhead","text":"Đáp án: бу́дешь носи́ть (từ носи́ть)"},{"t":"para","text":"Dịch: Cái mũ của cậu được 15 năm rồi đấy, cậu còn định đội nó bao lâu nữa?"},{"t":"example","text":"Giải thích: Sử dụng trang phục/phụ kiện → носи́ть."},{"t":"example","text":"12. Как двигаются дела?","b":1},{"t":"subhead","text":"Đáp án: иду́т (từ идти́)"},{"t":"para","text":"Dịch: Công việc trôi chảy/diễn tiến thế nào rồi?"},{"t":"example","text":"Giải thích: Câu chào hỏi phổ biến: Как идут дела? (Mọi việc thế nào?)."},{"t":"example","text":"13. Мы будем регулярно встречаться для переговоров.","b":1},{"t":"subhead","text":"Đáp án: вести́ (перегово́ры)","b":1},{"t":"para","text":"Dịch: Chúng ta sẽ thường xuyên tiến hành đàm phán."},{"t":"example","text":"Giải thích: Cụm từ вести переговоры (tiến hành đàm phán). Nếu phải thay thế cả cụm \"встречаться для переговоров\", ta dùng вести переговоры."},{"t":"example","text":"14. Он поступает странно.","b":1},{"t":"subhead","text":"Đáp án: ведёт себя́ (từ вести́)"},{"t":"para","text":"Dịch: Anh ta cư xử kỳ lạ."},{"t":"example","text":"Giải thích: Вести себя = cư xử, hành xử."},{"t":"example","text":"15. Московский университет назван в честь великого русского учёного М.В.Ломоносова.","b":1},{"t":"subhead","text":"Đáp án: но́сит и́мя (từ носи́ть)"},{"t":"para","text":"Dịch: Đại học Moscow mang tên nhà bác học vĩ đại người Nga M.V. Lomonosov."},{"t":"example","text":"Giải thích: Носить имя (mang tên) chỉ trạng thái sở hữu tên gọi vinh danh."},{"t":"example","text":"16. Слухи распространялись с невероятной быстротой.","b":1},{"t":"subhead","text":"Đáp án: ползли́ (từ ползти́ - bò/lan truyền) hoặc лете́ли (bay)."},{"t":"example","text":"Phổ biến: ползли́ слу́хи (tin đồn lan ra)."},{"t":"para","text":"Dịch: Tin đồn lan truyền (bò đi) với tốc độ khó tin."},{"t":"example","text":"17. Он даже спорит с иронией.","b":1},{"t":"subhead","text":"Đáp án: ведёт спо́ры (từ вести́)"},{"t":"para","text":"Dịch: Anh ấy thậm chí tranh luận cũng đầy mỉa mai."},{"t":"example","text":"Giải thích: Вести спор (tiến hành cuộc tranh luận)."},{"t":"example","text":"18. Не приставай ко мне с вопросами.","b":1},{"t":"subhead","text":"Đáp án: лезь (từ лезть)"},{"t":"para","text":"Dịch: Đừng làm phiền/xía vào tôi với mấy câu hỏi đó."},{"t":"example","text":"Giải thích: Лезть (sàm sỡ, quấy rầy, làm phiền). Не лезь ко мне = Để tôi yên."},{"t":"example","text":"19. Да, время движется вперёд, моложе мы не становимся.","b":1},{"t":"subhead","text":"Đáp án: лети́т (bay) hoặc бежи́т (chạy) hoặc идёт (trôi/đi)."},{"t":"example","text":"Ngữ cảnh này: Thường than thở thời gian trôi nhanh → лети́т hoặc бежи́т."},{"t":"para","text":"Dịch: Ừ, thời gian vùn vụt trôi (bay/chạy), chúng ta chẳng trẻ lại chút nào."},{"t":"example","text":"20. Мы передавали фотографии из рук в руки, и каждому хотелось посмотреть великолепные снимки.","b":1},{"t":"subhead","text":"Đáp án: ходи́ли (từ ходи́ть)"},{"t":"para","text":"Dịch: Những bức ảnh được chuyền (đi vòng quanh) từ tay người này sang người khác..."},{"t":"example","text":"Giải thích: Ходить по рукам = chuyền tay nhau."},{"t":"example","text":"21. Ни перед кем не стоит унижаться.","b":1},{"t":"subhead","text":"Đáp án: по́лзать (từ по́лзать)"},{"t":"para","text":"Dịch: Không việc gì phải quỵ lụy (bò lê) trước bất kỳ ai."},{"t":"example","text":"Giải thích: Ползать перед кем-то = luồn cúi, quỵ lụy (nghĩa bóng của hành động bò)."},{"t":"example","text":"22. Что ты посылаешь меня то в магазин, то в прачечную, то на рынок!","b":1},{"t":"subhead","text":"Đáp án: гоня́ешь (từ гоня́ть)"},{"t":"para","text":"Dịch: Sao bạn cứ sai vặt/bắt tôi chạy lúc thì ra cửa hàng, lúc thì tiệm giặt, lúc thì ra chợ thế!"},{"t":"example","text":"Giải thích: Гонять (xua đuổi/bắt chạy đi chạy lại) dùng trong khẩu ngữ chỉ việc sai bảo ai đó đi nhiều nơi liên tục."},{"t":"example","text":"23. По его лицу струился пот.","b":1},{"t":"subhead","text":"Đáp án: бежа́л (từ бежа́ть) hoặc катился."},{"t":"para","text":"Dịch: Mồ hôi tuôn/chảy trên mặt anh ấy."},{"t":"example","text":"Giải thích: Chất lỏng chảy thành dòng trên bề mặt: бежать."},{"t":"example","text":"24. Он не поддерживал знакомства ни с кем из соседей.","b":1},{"t":"subhead","text":"Đáp án: води́л (từ води́ть)"},{"t":"para","text":"Dịch: Anh ta không giao du/kết giao với bất kỳ người hàng xóm nào."},{"t":"example","text":"Giải thích: Водить знакомство / дружбу = duy trì mối quan hệ/tình bạn."},{"t":"para","text":"612. Прочитайте предложения, обращая внимание на устойчивые словосочетания с глаголами движения. Определите их значение.","b":1},{"t":"example","text":"(Đọc các câu, chú ý đến các cụm từ cố định đi với động từ chuyển động. Xác định ý nghĩa của chúng)."},{"t":"example","text":"a) 1. Этот человек целый день ходит за мной по пятам, а я не знаю, что ему нужно; в голову не идёт, кто это может быть.","b":1},{"t":"vocab","ru":"Хо́дит по пята́м","vi":"Bám theo như hình với bóng / theo sát gót.","g":null},{"t":"vocab","ru":"В го́лову не идёт","vi":"Không thể hiểu nổi / không nghĩ ra được.","g":null},{"t":"para","text":"Dịch: Người này cứ bám theo tôi như hình với bóng cả ngày, mà tôi không biết anh ta cần gì; nghĩ mãi không ra đó có thể là ai."},{"t":"example","text":"2. Морской воздух идёт тебе на пользу, ты быстро поправляешься.","b":1},{"t":"vocab","ru":"Идёт на по́льзу","vi":"Có lợi / tốt cho sức khỏe.","g":null},{"t":"para","text":"Dịch: Gió biển rất tốt cho bạn, bạn đang bình phục nhanh đấy."},{"t":"example","text":"3. Почему ты всё время вмешиваешься в мои дела, мешаешь мне? Иди своей дорогой, занимайся своими проблемами.","b":1},{"t":"vocab","ru":"Иди́ свое́й доро́гой","vi":"Hãy lo việc của mình đi / Đi đường của mình đi (đừng xía vào chuyện người khác).","g":null},{"t":"para","text":"Dịch: Sao lúc nào bạn cũng can thiệp vào chuyện của tôi, làm phiền tôi thế? Hãy lo việc của bạn đi, giải quyết vấn đề của bạn ấy."},{"t":"example","text":"4. Никак не могу уснуть, эта история у меня из головы не идёт.","b":1},{"t":"vocab","ru":"Из головы́ не идёт","vi":"Bị ám ảnh / không thể quên được / cứ lởn vởn trong đầu.","g":null},{"t":"para","text":"Dịch: Mãi không ngủ được, câu chuyện này cứ ám ảnh tôi mãi."},{"t":"example","text":"5. Господи! От этих проблем голова идёт кругом.","b":1},{"t":"vocab","ru":"Голова́ идёт кру́гом","vi":"Đầu óc quay cuồng / chóng mặt / rối tung lên.","g":null},{"t":"para","text":"Dịch: Trời ơi! Mấy vấn đề này làm tôi đầu óc quay cuồng."},{"t":"example","text":"6. Не волнуйся, всё идёт своим ходом (чередом), как надо.","b":1},{"t":"vocab","ru":"Идёт свои́м хо́дом (чередо́м)","vi":"Diễn ra theo đúng trình tự / lẽ thường / suôn sẻ.","g":null},{"t":"para","text":"Dịch: Đừng lo, mọi thứ đang diễn ra suôn sẻ/đúng lộ trình, như nó phải thế."},{"t":"example","text":"7. У него всё в порядке, дела его идут в гору.","b":1},{"t":"vocab","ru":"Дела́ иду́т в го́ру","vi":"Sự nghiệp thăng tiến / làm ăn phát đạt (lên như diều gặp gió).","g":null},{"t":"para","text":"Dịch: Anh ấy mọi thứ đều ổn, công việc đang phất lên."},{"t":"example","text":"8. Почему ты всегда идёшь напролом, разве нельзя остановиться, подумать, посоветоваться?","b":1},{"t":"vocab","ru":"Идёшь напроло́м","vi":"Hành động bất chấp / đâm đầu vào / làm bừa (không quan tâm chướng ngại vật hay ý kiến khác).","g":null},{"t":"para","text":"Dịch: Sao lúc nào bạn cũng đâm đầu làm bừa thế, chẳng lẽ không thể dừng lại, suy nghĩ và xin lời khuyên sao?"},{"t":"example","text":"9. Ты идёшь нога в ногу с модой, ни на шаг не отстаёшь!","b":1},{"t":"vocab","ru":"Идёшь нога́ в но́гу","vi":"Bắt kịp / theo sát / đồng hành.","g":null},{"t":"para","text":"Dịch: Bạn bắt kịp xu hướng thời trang đấy, không lạc hậu bước nào!"},{"t":"example","text":"10. Жил-жил человек да и умер. Тут уж скажешь? Все под богом ходим.","b":1},{"t":"vocab","ru":"Все под бо́гом хо́дим","vi":"Sống chết có số / ai cũng có thể gặp rủi ro (Thành ngữ: Tất cả chúng ta đều đi dưới trướng của Chúa).","g":null},{"t":"para","text":"Dịch: Người đang sống sờ sờ đấy rồi đùng cái chết. Biết nói sao được? Sống chết có số cả."},{"t":"example","text":"b) 1. Я не имею привычки бежать от ответственности, но каждый должен нести свой крест.","b":1},{"t":"vocab","ru":"Бежа́ть от отве́тственности","vi":"Trốn tránh trách nhiệm.","g":null},{"t":"vocab","ru":"Нести́ свой крест","vi":"Gánh vác khổ đau/số phận của mình (Thành ngữ: Vác cây thập giá của mình).","g":null},{"t":"para","text":"Dịch: Tôi không có thói quen trốn tránh trách nhiệm, nhưng mỗi người đều phải gánh vác số phận của riêng mình."},{"t":"example","text":"2. Дела у нас сложились — дальше ехать некуда, нет ни одного безнадёжного положения. (Câu này có vẻ mâu thuẫn hoặc dùng nghĩa bóng tích cực hiếm gặp, nhưng дальше ехать некуда thường mang nghĩa tiêu cực)."},{"t":"vocab","ru":"Да́льше е́хать не́куда","vi":"Đến đường cùng / Không còn gì để nói / Tệ hại hết mức (Thường dùng khi tình huống bế tắc hoàn toàn hoặc khi ai đó làm điều gì quá quắt).","g":null},{"t":"note","text":"Lưu ý ngữ cảnh: Nếu vế sau là \"không có tình huống tuyệt vọng\" thì có thể câu này đang dùng ý mỉa mai hoặc sách in nhầm \"нет ни одного\" thành \"нет выхода\". Tuy nhiên, nếu dịch sát:"},{"t":"para","text":"Dịch: Tình hình của chúng ta đã đến nước này rồi (tệ hết mức)..."},{"t":"example","text":"3. У меня начинает крыша ехать от всей вашей информации.","b":1},{"t":"vocab","ru":"Кры́ша е́дет (từ lóng)","vi":"Phát điên / mất trí / đầu óc lú lẫn.","g":null},{"t":"para","text":"Dịch: Tôi bắt đầu phát điên (loạn óc) vì mớ thông tin của các bạn rồi đấy."},{"t":"example","text":"4. Мы привыкли плыть по течению и я буду бороться, буду до конца отстаивать свою точку зрения.","b":1},{"t":"vocab","ru":"Плыть по тече́нию","vi":"Sống buông thả / phó mặc cho số phận / nước chảy bèo trôi.","g":null},{"t":"para","text":"Dịch: Chúng ta đã quen sống phó mặc cho số phận, nhưng tôi sẽ đấu tranh, sẽ bảo vệ quan điểm của mình đến cùng."},{"t":"example","text":"5. Вряд ли кто-нибудь из этого сектора мог бы взяться за такое дело, все они мелко плавают, а тут нужен человек известный, птица высокого полёта.","b":1},{"t":"vocab","ru":"Ме́лко пла́вают","vi":"Bất tài / Tầm thường / Không đủ trình độ (bơi chỗ nông).","g":null},{"t":"vocab","ru":"Пти́ца высо́кого полёта","vi":"Nhân vật tầm cỡ / Người có quyền lực/địa vị cao (chim bay cao).","g":null},{"t":"para","text":"Dịch: Khó có ai ở khu vực này dám nhận việc đó, bọn họ toàn là hạng xoàng, mà ở đây cần một người nổi tiếng, một nhân vật tầm cỡ."},{"t":"example","text":"6. Все мы несём в этой жизни свой крест.","b":1},{"t":"vocab","ru":"Несём свой крест","vi":"Gánh chịu khổ đau/thử thách của cuộc đời.","g":null},{"t":"para","text":"Dịch: Tất cả chúng ta đều gánh vác nỗi khổ riêng trong cuộc đời này."},{"t":"example","text":"7. Что за ерунду (вздор, ахинею) ты несёшь?","b":1},{"t":"vocab","ru":"Нести́ ерунду́ / вздор","vi":"Nói nhảm / Nói linh tinh.","g":null},{"t":"para","text":"Dịch: Cậu đang nói lảm nhảm cái gì thế?"},{"t":"example","text":"8. Или скажи «да», или откажись. Зачем ты водишь его за нос, обещая неизвестно что?","b":1},{"t":"vocab","ru":"Води́ть за́ нос","vi":"Dắt mũi / Lừa dối / Hứa hão.","g":null},{"t":"para","text":"Dịch: Hoặc nói \"có\", hoặc từ chối đi. Sao cậu cứ dắt mũi người ta, hứa hẹn những điều không đâu thế?"},{"t":"example","text":"9. Этот человек всю жизнь ползает на брюхе перед начальством. Как можно уважать такого человека?","b":1},{"t":"vocab","ru":"По́лзать на брю́хе","vi":"Luồn cúi / Quỵ lụy / Nịnh bợ hèn hạ (bò bằng bụng).","g":null},{"t":"para","text":"Dịch: Kẻ này cả đời luồn cúi trước cấp trên. Làm sao có thể tôn trọng một người như thế?"},{"t":"example","text":"10. Не надо лезть на рожон, этим ты никому не поможешь и сам пропадёшь.","b":1},{"t":"vocab","ru":"Ле́зть на рожо́н","vi":"Chuốc họa vào thân / Hành động liều lĩnh ngu ngốc / Chọc ổ kiến lửa (lao vào mũi nhọn).","g":null},{"t":"para","text":"Dịch: Đừng có chuốc họa vào thân (làm liều), làm thế cậu chẳng giúp được ai mà còn tự hại mình đấy."},{"t":"example","text":"11. Да, он за словом в карман не лезет, так ответит, что потом долго помнить будешь.","b":1},{"t":"vocab","ru":"За сло́вом в карма́н не ле́зет","vi":"Hoạt ngôn / Đối đáp nhanh nhạy / Mồm mép tép nhảy (không cần thò tay vào túi tìm từ).","g":null},{"t":"para","text":"Dịch: Ừ, hắn ta hoạt ngôn lắm (đối đáp rất nhanh), hắn mà trả lời thì cậu sẽ nhớ đời đấy."},{"t":"example","text":"12. Он старается, из кожи вон лезет, но ничего у него не получается.","b":1},{"t":"vocab","ru":"Из ко́жи вон ле́зет","vi":"Cố gắng hết sức mình / Làm trâu làm ngựa / Vắt kiệt sức (chui ra khỏi da).","g":null},{"t":"para","text":"Dịch: Anh ấy cố gắng, làm hết sức mình, nhưng chẳng đạt được kết quả gì."},{"t":"example","text":"13. Успокойся, не надо лезть в бутылку.","b":1},{"t":"vocab","ru":"Ле́зть в буты́лку","vi":"Nổi cáu vô cớ / Giận quá mất khôn / Xưng xỉa.","g":null},{"t":"para","text":"Dịch: Bình tĩnh đi, đừng có nổi đóa lên thế."},{"t":"example","text":"14. Что толку от того, что ты кричишь и размахиваешь руками?!","b":1},{"t":"vocab","ru":"Разма́хивать рука́ми","vi":"Múa tay múa chân / Khua tay (biểu hiện sự bất lực hoặc tức giận nhưng không làm được gì).","g":null},{"t":"para","text":"Dịch: Cậu cứ hét lên và khua tay múa chân thì có ích gì đâu?!"},{"t":"example","text":"15. После всего, что случилось, он смеет показываться мне на глаза?! Надо гнать его в шею!","b":1},{"t":"vocab","ru":"Пока́зываться на глаза́","vi":"Vác mặt đến / Xuất hiện trước mặt.","g":null},{"t":"vocab","ru":"Гнать в ше́ю","vi":"Đuổi cổ / Tống cổ đi (đuổi đánh vào cổ).","g":null},{"t":"para","text":"Dịch: Sau tất cả những chuyện đã xảy ra, hắn còn dám vác mặt đến gặp tôi sao?! Phải tống cổ hắn đi!"},{"t":"example","text":"c) 1. Куда это ты несёшься сломя голову, пожар, что ли?","b":1},{"t":"vocab","ru":"Нести́сь сломя́ го́лову","vi":"Chạy bán sống bán chết / Chạy thục mạng (lao đi như gãy đầu).","g":null},{"t":"para","text":"Dịch: Cậu đi đâu mà chạy như ma đuổi thế, cháy nhà à?"},{"t":"example","text":"2. Чем ты недоволен? Живёшь как сыр в масле катаешься, всё у тебя есть, никаких проблем.","b":1},{"t":"vocab","ru":"Как сыр в ма́сле ката́ешься","vi":"Sống trong nhung lụa / Sướng như tiên / Chuột sa chĩnh gạo (như phô mai lăn trong bơ).","g":null},{"t":"para","text":"Dịch: Cậu còn bất mãn cái gì? Sống sướng như tiên (trong nhung lụa), có tất cả mọi thứ, chẳng phải lo nghĩ gì."},{"t":"vocab","ru":"Катишься ты по наклонной плоскости и сам этого не замечаешь","vi":"с работы тебя уволили, с квартиры выгнали.","g":null},{"t":"vocab","ru":"Кати́ться по накло́нной пло́скости","vi":"Trượt dốc không phanh / Sa ngã (lăn trên mặt phẳng nghiêng).","g":null},{"t":"para","text":"Dịch: Cậu đang trượt dốc không phanh (sa ngã) mà tự mình không nhận ra: bị đuổi việc, bị đuổi khỏi nhà."},{"t":"example","text":"4. Когда я рассказываю одну из своих историй, все по полу от смеха катаются, так здорово он умеет представить самые обыкновенные события в смешном виде.","b":1},{"t":"vocab","ru":"По́ по́лу от сме́ха ката́ются","vi":"Cười lăn lộn / Cười bò ra sàn.","g":null},{"t":"example","text":"Dịch: Khi tôi (hoặc anh ấy - ngôi thứ 3 hợp lý hơn với vế sau) kể một trong những câu chuyện của mình, mọi người đều cười lăn lộn, anh ấy rất giỏi kể những sự kiện bình thường nhất theo cách hài hước."}]},{"id":"07-s114","type":"exercise","title":"Bài 613 (Trang 324)","num":613,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя усто́йчивые сочета́ния с глаго́лами движе́ния, да́йте не́сколько сове́тов ва́шему знако́мому (знако́мой), кото́рый (кото́рая): (Sử dụng các cụm từ cố định với động từ chuyển động, hãy đưa ra vài lời khuyên cho người quen của bạn, người mà:)"},{"t":"para","text":"1. ...возмуща́ется и хо́чет идти́ сканда́лить с администра́цией рестора́на.","b":1},{"t":"example","text":"(...đang bức xúc và muốn đi gây gổ/làm ầm ĩ với ban quản lý nhà hàng.)"},{"t":"para","text":"Lời khuyên: Не лезь в буты́лку! / Не лезь на рожо́н!","b":1},{"t":"para","text":"Dịch: Đừng có nổi nóng vô cớ / chuốc họa vào thân!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Ле́зть в буты́лку","vi":"Nổi nóng, mất bình tĩnh một cách không cần thiết.","g":null},{"t":"vocab","ru":"Ле́зть на рожо́н","vi":"Hành động liều lĩnh, gây hấn với người mạnh hơn hoặc trong tình huống bất lợi.","g":null},{"t":"para","text":"2. ...наде́ется, что ему́ не придётся отвеча́ть за свою́ оши́бку.","b":1},{"t":"example","text":"(...hy vọng rằng anh ấy sẽ không phải chịu trách nhiệm cho lỗi lầm của mình.)"},{"t":"para","text":"Lời khuyên: От отве́тственности не уйдёшь (не убежи́шь).","b":1},{"t":"para","text":"Dịch: Cậu sẽ không trốn thoát được trách nhiệm đâu."},{"t":"example","text":"Giải thích: Dùng уйти́ (đi thoát) hoặc бежа́ть (chạy trốn) để chỉ việc trốn tránh nghĩa vụ."},{"t":"para","text":"3. ...стара́ется похуде́ть, да́же цено́й своего́ здоро́вья.","b":1},{"t":"example","text":"(...cố gắng giảm cân, thậm chí bằng cái giá là sức khỏe của mình.)"},{"t":"para","text":"Lời khuyên: Не доходи́ до кра́йности! / Не загоня́й себя́!","b":1},{"t":"para","text":"Dịch: Đừng đi đến mức cực đoan! / Đừng tự hành hạ bản thân (bắt mình chạy kiệt sức)!"},{"t":"example","text":"Giải thích: Загоня́ть (săn đuổi/bắt chạy đến kiệt sức) thường dùng cho ngựa, nghĩa bóng là làm việc hoặc ép bản thân quá sức."},{"t":"para","text":"4. ...е́дет с большо́й ско́ростью, не разбира́я доро́ги.","b":1},{"t":"example","text":"(...đang đi xe với tốc độ lớn, không quan sát đường sá.)"},{"t":"para","text":"Lời khuyên: Не неси́сь сломя́ го́лову!","b":1},{"t":"para","text":"Dịch: Đừng có lao đi như điên (bán sống bán chết) thế!"},{"t":"example","text":"Giải thích: Нести́сь сломя́ го́лову: Chạy/lao đi rất nhanh, mạo hiểm (nghĩa đen: như làm gãy đầu)."},{"t":"para","text":"5. ...стара́ется реши́ть свой вопро́с пря́мо, не счита́ясь с обстоя́тельствами.","b":1},{"t":"example","text":"(...cố gắng giải quyết vấn đề của mình một cách trực diện, không tính đến hoàn cảnh.)"},{"t":"para","text":"Lời khuyên: Не иди́ напроло́м!","b":1},{"t":"para","text":"Dịch: Đừng có đâm đầu làm bừa / hành động bất chấp!"},{"t":"example","text":"Giải thích: Идти́ напроло́м: Hành động quyết liệt bỏ qua mọi trở ngại hoặc quy tắc xã giao, thường mang nghĩa tiêu cực (thiếu khéo léo)."},{"t":"para","text":"6. ...всё вре́мя жа́луется на неприя́тности, пресле́дующие его́.","b":1},{"t":"example","text":"(...lúc nào cũng than vãn về những điều khó chịu cứ đeo bám anh ta.)"},{"t":"para","text":"Lời khuyên: Ка́ждый несёт свой крест.","b":1},{"t":"para","text":"Dịch: Mỗi người đều phải gánh vác nỗi khổ riêng.","b":1},{"t":"example","text":"Giải thích: Нести́ свой крест: Chấp nhận số phận, thử thách của cuộc đời."},{"t":"para","text":"7. ...унижа́ется пе́ред нача́льством.","b":1},{"t":"example","text":"(...hạ mình/nhục nhã trước cấp trên.)"},{"t":"para","text":"Lời khuyên: Не по́лзай на брю́хе (пе́ред ним)!","b":1},{"t":"para","text":"Dịch: Đừng có luồn cúi (bò bằng bụng) trước ông ta!"},{"t":"example","text":"Giải thích: По́лзать на брю́хе: Hành động nịnh bợ, khúm núm hèn hạ."},{"t":"para","text":"8. ...ока́зывает зна́ки внима́ния молодо́му челове́ку, к кото́рому она́ равноду́шна.","b":1},{"t":"example","text":"(...tỏ ra quan tâm đến chàng trai mà cô ấy thực sự thờ ơ [không yêu].)"},{"t":"para","text":"Lời khuyên: Не води́ его́ за́ нос! / Не моро́чь ему́ го́лову!","b":1},{"t":"para","text":"Dịch: Đừng dắt mũi anh ta! / Đừng làm anh ta rối trí!"},{"t":"example","text":"Giải thích: Води́ть за́ нос: Lừa dối, hứa hẹn hão huyền."},{"t":"para","text":"9. ...вме́шивается в ва́ши дела́.","b":1},{"t":"example","text":"(...can thiệp vào chuyện của bạn.)"},{"t":"para","text":"Lời khuyên: Иди́ свое́й доро́гой! / Не лезь не в своё де́ло!","b":1},{"t":"para","text":"Dịch: Hãy đi đường của bạn đi (Lo chuyện của bạn đi)! / Đừng xía vào chuyện không phải của mình!"},{"t":"example","text":"Giải thích: Иди́ свое́й доро́гой: Đừng can thiệp vào đời sống người khác."},{"t":"para","text":"10. ...хо́дит за ва́ми сле́дом.","b":1},{"t":"example","text":"(...đi theo sau bạn.)"},{"t":"para","text":"Lời khuyên: Не ходи́ за мной по пята́м!","b":1},{"t":"para","text":"Dịch: Đừng bám theo tôi như hình với bóng (theo gót) nữa!"},{"t":"example","text":"Giải thích: Ходи́ть по пята́м: Bám sát gót, theo dõi sát sao."},{"t":"para","text":"11. ...не пыта́ется боро́ться с жи́зненными тру́дностями, не противостои́т обстоя́тельствам, соглаша́ясь со всем, что происхо́дит вокру́г.","b":1},{"t":"example","text":"(...không cố gắng đấu tranh với khó khăn cuộc sống, không chống lại hoàn cảnh, chấp nhận tất cả những gì xảy ra xung quanh.)"},{"t":"para","text":"Lời khuyên: Не плыви́ по тече́нию!","b":1},{"t":"para","text":"Dịch: Đừng sống buông thả (nước chảy bèo trôi)!"},{"t":"example","text":"Giải thích: Плыть по тече́нию: Phó mặc cho số phận, không có chính kiến."},{"t":"para","text":"12. ...принима́ет у себя́ челове́ка, кото́рый пре́дал его́.","b":1},{"t":"example","text":"(...tiếp đón kẻ đã phản bội mình.)"},{"t":"para","text":"Lời khuyên: Гони́ его́ в ше́ю!","b":1},{"t":"para","text":"Dịch: Tống cổ (đuổi cổ) hắn đi!"},{"t":"example","text":"Giải thích: Гнать в ше́ю: Đuổi đi một cách thô bạo, dứt khoát."}]},{"id":"07-s115","type":"exercise","title":"Bài 614 (Trang 325)","num":614,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя усто́йчивые словосочета́ния с глаго́лами движе́ния, к вы́деленным слова́м подбери́те сино́нимы. (Sử dụng các cụm từ cố định với động từ chuyển động, hãy chọn từ đồng nghĩa cho các từ/cụm từ được in đậm)."},{"t":"example","text":"1. Куре́ние не ока́зывает положи́тельного де́йствия на твоё здоро́вье.","b":1},{"t":"subhead","text":"Đáp án: не идёт на по́льзу","b":1},{"t":"para","text":"Dịch: Hút thuốc không tốt (không đem lại lợi ích) cho sức khỏe của bạn."},{"t":"example","text":"Giải thích: Идти́ на по́льзу = Có lợi, tốt cho ai/cái gì."},{"t":"example","text":"2. Не на́до нарыва́ться на неприя́тности.","b":1},{"t":"subhead","text":"Đáp án: Не на́до лезть на рожо́н","b":1},{"t":"para","text":"Dịch: Đừng có chuốc họa vào thân (làm liều)."},{"t":"example","text":"Giải thích: Нарыва́ться на неприя́тности = Лезть на рожо́н."},{"t":"example","text":"3. Он живёт вдово́льстве, всё у него́ есть.","b":1},{"t":"subhead","text":"Đáp án: ката́ется как сыр в ма́сле","b":1},{"t":"para","text":"Dịch: Anh ta sống sướng như tiên (như phô mai lăn trong bơ)."},{"t":"example","text":"Giải thích: Ката́ться как сыр в ма́сле: Sống sung túc, không lo nghĩ gì."},{"t":"example","text":"4. Тебе́ придётся за всё отвеча́ть.","b":1},{"t":"subhead","text":"Đáp án: придётся нести́ отве́тственность (hoặc нести́ свой крест - nếu mang nghĩa gánh nặng số phận)."},{"t":"para","text":"Dịch: Bạn sẽ phải chịu trách nhiệm cho mọi thứ."},{"t":"example","text":"Giải thích: Нести́ отве́тственность: Chịu trách nhiệm."},{"t":"example","text":"5. Да, он о́чень лю́бит поговори́ть, с ним тру́дно спо́рить.","b":1},{"t":"subhead","text":"Đáp án: за сло́вом в карма́н не ле́зет","b":1},{"t":"para","text":"Dịch: Ừ, hắn ta mồm mép tép nhảy (đối đáp nhanh), khó mà tranh luận với hắn."},{"t":"example","text":"Giải thích: За сло́вом в карма́н не ле́зет: Hoạt ngôn, không bí từ."},{"t":"example","text":"6. Никто́ из нас не зна́ет, что его́ ждёт в э́той жи́зни.","b":1},{"t":"subhead","text":"Đáp án: все под бо́гом хо́дим","b":1},{"t":"para","text":"Dịch: Không ai trong chúng ta biết điều gì đang chờ đợi, sống chết có số cả."},{"t":"example","text":"Giải thích: Все под бо́гом хо́дим: Ám chỉ tương lai/số phận là do Chúa định, con người không biết trước được tai ương."},{"t":"example","text":"7. Что с тобо́й? Почему́ ты идёшь так ме́дленно?","b":1},{"t":"subhead","text":"Đáp án: е́ле но́ги воло́чишь / е́ле ползёшь","b":1},{"t":"para","text":"Dịch: Sao thế? Sao cậu lê bước chậm chạp (như rùa bò) thế?"},{"t":"example","text":"Giải thích: Е́ле но́ги волочи́ть (Lê chân không nổi) hoặc ползти́ (bò) dùng để chỉ đi rất chậm do mệt mỏi."},{"t":"example","text":"8. У меня́ все мы́сли в голове́ пу́таются от того́, что я сейча́с услы́шал.","b":1},{"t":"subhead","text":"Đáp án: голова́ идёт кру́гом","b":1},{"t":"para","text":"Dịch: Tôi đầu óc quay cuồng vì những gì vừa nghe được."},{"t":"example","text":"Giải thích: Голова́ идёт кру́гом: Chóng mặt, rối trí vì quá nhiều thông tin hoặc lo lắng."},{"t":"example","text":"9. Он си́льно смея́лся и не мог вы́молвить ни одного́ сло́ва.","b":1},{"t":"subhead","text":"Đáp án: ката́лся со́ смеху (от сме́ха)","b":1},{"t":"para","text":"Dịch: Anh ấy cười lăn lộn (cười bò) và không nói nên lời."},{"t":"example","text":"Giải thích: Ката́ться от сме́ха: Cười ngặt nghẽo, cười không kìm được."},{"t":"example","text":"10. Обма́н никому́ не помога́ет.","b":1},{"t":"subhead","text":"Đáp án: далеко́ не уе́дешь (на обма́не) / до добра́ не доведёт"},{"t":"para","text":"Dịch: Dối trá sẽ không đưa ai đi đến đâu cả / không đem lại kết quả tốt đẹp."},{"t":"example","text":"Giải thích: Thành ngữ На обма́не далеко́ не уе́дешь (Bằng sự dối trá thì không đi xa được)."},{"t":"example","text":"11. Не беспоко́йся, всё норма́льно.","b":1},{"t":"subhead","text":"Đáp án: Всё идёт свои́м чередо́м (свои́м хо́дом)","b":1},{"t":"para","text":"Dịch: Đừng lo, mọi thứ đang diễn ra suôn sẻ/đúng lộ trình."},{"t":"example","text":"Giải thích: Идти́ свои́м чередо́м: Diễn ra bình thường như quy luật vốn có."},{"t":"example","text":"12. Как я могу́ забы́ть о предстоя́щей встре́че! Все мы́сли то́лько о ней.","b":1},{"t":"subhead","text":"Đáp án: Она́ (встре́ча) у меня́ из головы́ не идёт","b":1},{"t":"para","text":"Dịch: Làm sao tôi quên được cuộc gặp sắp tới! Nó cứ lởn vởn trong đầu tôi (tôi bị ám ảnh về nó)."},{"t":"example","text":"Giải thích: Не идти́ из головы́: Không thể quên được, cứ suy nghĩ mãi."},{"t":"example","text":"13. Ду́маю, ты не име́ешь доста́точного о́пыта, не занима́ешь доста́точного положе́ния и не мо́жешь возгла́вить тако́е ва́жное де́ло.","b":1},{"t":"subhead","text":"Đáp án: ме́лко пла́ваешь","b":1},{"t":"para","text":"Dịch: Tôi nghĩ cậu trình độ còn non (bơi chỗ nông) và không thể lãnh đạo việc quan trọng như vậy."},{"t":"example","text":"Giải thích: Ме́лко пла́вать: Bất tài, thiếu kinh nghiệm, địa vị thấp."},{"t":"example","text":"14. Мы с ва́ми нахо́димся в сло́жной ситуа́ции, ху́же положе́ния быть не мо́жет.","b":1},{"t":"subhead","text":"Đáp án: да́льше е́хать не́куда","b":1},{"t":"para","text":"Dịch: Chúng ta đang ở trong tình thế cùng đường rồi (tệ hết mức)."},{"t":"example","text":"Giải thích: Да́льше е́хать не́куда: Tình huống bế tắc hoàn toàn, không thể tồi tệ hơn được nữa."},{"t":"para","text":"Lý thuyết cần nhớ (Trang 325-326)","b":1},{"t":"subhead","text":"Sự thay đổi về Thể (Вид):","b":1},{"t":"example","text":"Tiền tố + Động từ một chiều (идти́, бежа́ть...) → Động từ Hoàn thành thể (Perfective)."},{"t":"example","text":"Ví dụ: при + идти́ = прийти́ (đến nơi - hoàn thành)."},{"t":"example","text":"Tiền tố + Động từ đa chiều (ходи́ть, бе́гать...) → Động từ Chưa hoàn thành thể (Imperfective)."},{"t":"example","text":"Ví dụ: при + ходи́ть = приходи́ть (đến nơi - đang đến hoặc hay đến)."},{"t":"para","text":"Ý nghĩa các tiền tố trong bài này:","b":1},{"t":"vocab","ru":"В- (во-)","vi":"Chuyển động vào bên trong (входи́ть) hoặc đi lên (всходи́ть).","g":null},{"t":"vocab","ru":"Вы-","vi":"Chuyển động từ trong ra ngoài (выходи́ть).","g":null},{"t":"vocab","ru":"При-","vi":"Chuyển động đến đích, đến gần (приходи́ть).","g":null},{"t":"vocab","ru":"У-","vi":"Chuyển động rời đi xa, vắng mặt (уходи́ть).","g":null}]},{"id":"07-s116","type":"exercise","title":"Bài 615 (Trang 325)","num":615,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложения. Определи́те значе́ние глаго́лов движе́ния с приста́вками. Назови́те инфинити́вы, от кото́рых они́ образо́ваны. (Đọc các câu. Xác định ý nghĩa của các động từ chuyển động có tiền tố. Gọi tên động từ nguyên mẫu mà từ đó chúng được tạo thành)."},{"t":"para","text":"a) Tiền tố В- (Vào trong / Lên trên)","b":1},{"t":"para","text":"1. Он вошёл в ко́мнату и поздоро́вался. Ка́ждую мину́ту в кабине́т входи́ли посети́тели.","b":1},{"t":"vocab","ru":"вошёл (từ идти́)","vi":"Đi vào (hoàn thành, 1 lần). Dịch: Anh ấy đã bước vào phòng và chào hỏi.","g":null},{"t":"vocab","ru":"входи́ли (từ ходи́ть)","vi":"Đi vào (chưa hoàn thành, lặp lại). Dịch: Cứ mỗi phút lại có khách đi vào phòng làm việc.","g":null},{"t":"para","text":"2. В после́дний моме́нт я вбежа́л в электри́чку. Ми́мо меня́ в класс вбега́ли первокла́ссники.","b":1},{"t":"vocab","ru":"вбежа́л (từ бежа́ть)","vi":"Chạy vào (hoàn thành). Dịch: Vào giây phút cuối cùng tôi đã chạy vụt vào tàu điện.","g":null},{"t":"vocab","ru":"вбега́ли (từ бе́гать)","vi":"Chạy vào (chưa hoàn thành). Dịch: Những học sinh lớp một chạy ùa vào lớp ngang qua tôi.","g":null},{"t":"para","text":"3. Я внёс ве́щи в купе́. Э́то предложе́ние уже́ не́сколько раз вноси́ли в пове́стку дня.","b":1},{"t":"vocab","ru":"внёс (từ нести́)","vi":"Mang vào (hoàn thành). Dịch: Tôi đã mang đồ vào toa tàu.","g":null},{"t":"vocab","ru":"вноси́ли (từ носи́ть)","vi":"Đưa vào (nghĩa bóng: đề xuất), lặp lại. Dịch: Đề xuất này đã được đưa vào chương trình nghị sự vài lần rồi.","g":null},{"t":"para","text":"4. — Наш котёнок влез на де́рево и не мо́жет спусти́ться. — Не беспоко́йся, он влеза́л туда́ мно́го раз и ка́ждый раз спуска́лся самостоя́тельно.","b":1},{"t":"vocab","ru":"влез (từ лезть)","vi":"Leo lên (hoàn thành, vào trong không gian chật hoặc lên cao). Dịch: Con mèo con của chúng ta leo lên cây và không xuống được.","g":null},{"t":"vocab","ru":"влеза́л (từ ла́зить)","vi":"Leo lên (lặp lại). Dịch: Đừng lo, nó đã leo lên đó nhiều lần rồi và lần nào cũng tự xuống được.","g":null},{"t":"para","text":"b) Tiền tố Вы- (Ra ngoài)","b":1},{"t":"para","text":"1. Мы вы́ехали из до́ма в пять часо́в. Я выезжа́ю че́рез де́сять мину́т.","b":1},{"t":"vocab","ru":"вы́ехали (từ е́хать)","vi":"Rời khỏi/Đi ra (bằng xe) - hoàn thành. Dịch: Chúng tôi đã rời nhà lúc 5 giờ.","g":null},{"t":"vocab","ru":"выезжа́ю (từ е́здить)","vi":"Sắp rời đi/đang đi ra - chưa hoàn thành. Dịch: Tôi sẽ xuất phát sau 10 phút nữa.","g":null},{"t":"para","text":"2. Наш самолёт вы́летел то́чно по расписа́нию. Когда́ мы вылета́ли, пого́да была́ хоро́шая.","b":1},{"t":"vocab","ru":"вы́летел (từ лете́ть)","vi":"Cất cánh/Bay đi - hoàn thành. Dịch: Máy bay của chúng tôi đã cất cánh đúng giờ.","g":null},{"t":"vocab","ru":"вылета́ли (từ лета́ть)","vi":"Cất cánh - chưa hoàn thành (chỉ quá trình hoặc thời điểm). Dịch: Khi chúng tôi cất cánh, thời tiết rất đẹp.","g":null},{"t":"para","text":"3. В э́том году́ ле́том мы вы́везли дете́й на да́чу. Полдня́ рабо́чие вывози́ли ме́бель из на́шего о́фиса.","b":1},{"t":"vocab","ru":"вы́везли (từ везти́)","vi":"Chở đi/Đưa đi (bằng xe) - hoàn thành. Dịch: Mùa hè năm nay chúng tôi đã đưa bọn trẻ về nhà nghỉ ngoại ô.","g":null},{"t":"vocab","ru":"вывози́ли (từ вози́ть)","vi":"Chuyển đi - chưa hoàn thành (quá trình). Dịch: Suốt nửa ngày các công nhân chuyển đồ đạc ra khỏi văn phòng chúng tôi.","g":null},{"t":"para","text":"4. Когда́ мы вы́плыли из-под моста́, я уви́дел не́сколько ло́док. Мы наблюда́ли, как из-под моста́ ме́дленно выплыва́ла ло́дка.","b":1},{"t":"vocab","ru":"вы́плыли (từ плыть)","vi":"Bơi ra/Trôi ra - hoàn thành. Dịch: Khi chúng tôi bơi ra khỏi gầm cầu, tôi thấy vài chiếc thuyền.","g":null},{"t":"vocab","ru":"выплыва́ла (từ пла́вать)","vi":"Bơi ra - chưa hoàn thành (quá trình). Dịch: Chúng tôi quan sát một chiếc thuyền chầm chậm trôi ra từ gầm cầu.","g":null},{"t":"para","text":"5. Пожа́луйста, вы́тащи ру́ки из карма́нов. Он выта́скивал из портфе́ля докуме́нты оди́н за други́м и пока́зывал их мне.","b":1},{"t":"vocab","ru":"вы́тащи (từ тащи́ть)","vi":"Lôi ra/Rút ra - hoàn thành (mệnh lệnh). Dịch: Làm ơn rút tay ra khỏi túi quần.","g":null},{"t":"vocab","ru":"выта́скивал (từ таска́ть)","vi":"Lôi ra - chưa hoàn thành. Dịch: Anh ấy lôi từ cặp ra từng tập tài liệu một và cho tôi xem.","g":null},{"t":"para","text":"c) Tiền tố При- (Đến nơi)","b":1},{"t":"para","text":"1. Он пришёл с рабо́ты по́здно ве́чером. Она́ приходи́ла уже́ не́сколько раз.","b":1},{"t":"vocab","ru":"пришёл (từ идти́)","vi":"Đã đến/về - hoàn thành. Dịch: Anh ấy đi làm về muộn vào buổi tối.","g":null},{"t":"vocab","ru":"приходи́ла (từ ходи́ть)","vi":"Đã đến (và có thể đã đi) - chưa hoàn thành/lặp lại. Dịch: Cô ấy đã đến đây vài lần rồi.","g":null},{"t":"para","text":"2. Наве́рное, мы прие́хали о́чень ра́но. Ка́ждый год в ию́не приезжа́ю в Смоле́нск к роди́телям.","b":1},{"t":"vocab","ru":"прие́хали (từ е́хать)","vi":"Đã đến (bằng xe) - hoàn thành. Dịch: Có lẽ chúng ta đến sớm quá.","g":null},{"t":"vocab","ru":"приезжа́ю (từ е́здить)","vi":"Đến - chưa hoàn thành (thói quen). Dịch: Năm nào vào tháng 6 tôi cũng về Smolensk thăm bố mẹ.","g":null},{"t":"para","text":"3. Что ты принёс? Я приношу́ вам извине́ния за де́йствия мои́х колле́г.","b":1},{"t":"vocab","ru":"принёс (từ нести́)","vi":"Mang đến - hoàn thành. Dịch: Bạn mang cái gì đến thế?","g":null},{"t":"vocab","ru":"приношу́ (từ носи́ть)","vi":"Mang đến (nghĩa bóng) - chưa hoàn thành. Dịch: Tôi xin gửi lời (mang đến) xin lỗi tới các bạn về hành động của đồng nghiệp tôi.","g":null},{"t":"para","text":"4. Я приведу́ вам не́сколько приме́ров. Я привожу́ э́тот приме́р для того́, что́бы бы́ло поня́тно, что я име́ю в виду́.","b":1},{"t":"vocab","ru":"приведу́ (từ вести́)","vi":"Dẫn ra/Đưa ra - hoàn thành. Dịch: Tôi sẽ đưa ra cho các bạn vài ví dụ.","g":null},{"t":"vocab","ru":"привожу́ (từ води́ть)","vi":"Đưa ra - chưa hoàn thành. Dịch: Tôi đưa ra ví dụ này để các bạn hiểu ý tôi là gì.","g":null},{"t":"para","text":"d) Tiền tố У- (Rời đi/Xa dần)","b":1},{"t":"para","text":"1. От други́х ты убежа́ть мо́жешь, но от самого́ себя́ нет. Извини́, но сейча́с я не могу́ с тобо́й говори́ть, убега́ю в университе́т.","b":1},{"t":"vocab","ru":"убежа́ть (từ бежа́ть)","vi":"Chạy trốn - hoàn thành. Dịch: Bạn có thể chạy trốn người khác, nhưng không thể trốn chính mình.","g":null},{"t":"vocab","ru":"убега́ю (từ бе́гать)","vi":"Đang chạy đi - chưa hoàn thành. Dịch: Xin lỗi, giờ tôi không nói chuyện với bạn được, tôi đang chạy đến trường đây.","g":null},{"t":"para","text":"2. Он ушёл с рабо́ты пять мину́т наза́д. Когда́ он уходи́л, он проси́л переда́ть тебе́ э́ту запи́ску.","b":1},{"t":"vocab","ru":"ушёл (từ идти́)","vi":"Đã đi khỏi - hoàn thành. Dịch: Anh ấy đã rời chỗ làm 5 phút trước.","g":null},{"t":"vocab","ru":"уходи́л (từ ходи́ть)","vi":"Lúc rời đi - chưa hoàn thành. Dịch: Khi đi về, anh ấy nhờ chuyển cho bạn mảnh giấy này.","g":null},{"t":"para","text":"3. Он ушёл и унёс с собо́й все докуме́нты. Я никуда́ не уноси́ла твои́ бума́ги, они́ должны́ лежа́ть на столе́.","b":1},{"t":"vocab","ru":"унёс (từ нести́)","vi":"Mang đi mất - hoàn thành. Dịch: Anh ấy đã đi và mang theo tất cả tài liệu.","g":null},{"t":"vocab","ru":"уноси́ла (từ носи́ть)","vi":"Mang đi - chưa hoàn thành. Dịch: Em không hề mang giấy tờ của anh đi đâu cả, chúng chắc chắn phải ở trên bàn.","g":null},{"t":"para","text":"4. Я застрахова́л свою́ маши́ну на слу́чай, е́сли её уго́нят. К сожале́нию, маши́ны в на́шем го́роде угоня́ют ка́ждый день.","b":1},{"t":"vocab","ru":"уго́нят (từ гнать)","vi":"Lấy trộm (xe)/Đuổi đi - hoàn thành. Dịch: Tôi đã bảo hiểm xe phòng trường hợp nó bị lấy trộm.","g":null},{"t":"vocab","ru":"угоня́ют (từ гоня́ть)","vi":"Lấy trộm - chưa hoàn thành (lặp lại). Dịch: Tiếc là ở thành phố chúng tôi ngày nào cũng có xe bị lấy trộm.","g":null}]},{"id":"07-s117","type":"exercise","title":"Bài 616 (Trang 326)","num":616,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте необходи́мые по смы́слу глаго́лы движе́ния в фо́рме инфинити́ва с приста́вками: а) в-(во-) или при-; б) вы- или у-. (Thay dấu ba chấm bằng động từ chuyển động nguyên mẫu với tiền tố: a) v-(vo-) hoặc pri-; b) vy- hoặc u-)."},{"t":"para","text":"a) В- (vào trong/lên) hoặc ПРИ- (đến nơi/đem đến)","b":1},{"t":"para","text":"1. Не сто́йте в прихо́жей, вы мо́жете войти́ (проходи́ть), мы вас давно́ ждём. За́втра я смогу́ прийти́ к вам не ра́ньше девяти́ часо́в.","b":1},{"t":"subhead","text":"Đáp án: войти́; прийти́."},{"t":"para","text":"Dịch: Đừng đứng ở huyền quan, ông có thể vào trong, chúng tôi đợi ông lâu rồi. Ngày mai tôi chỉ có thể đến chỗ các bạn sau 9 giờ."},{"t":"example","text":"Giải thích: Войти́ (đi từ ngoài vào trong phòng). Прийти́ (đến một địa điểm/gặp ai đó)."},{"t":"para","text":"2. Нам уда́стся прие́хать в Москву́ то́лько в нача́ле октября́. Вы мо́жете въе́хать в но́вую кварти́ру, когда́ захоти́те.","b":1},{"t":"subhead","text":"Đáp án: прие́хать; въе́хать."},{"t":"para","text":"Dịch: Chúng tôi chỉ có thể đến Moscow vào đầu tháng 10. Các bạn có thể dọn vào (chuyển vào) căn hộ mới bất cứ khi nào muốn."},{"t":"example","text":"Giải thích: Прие́хать (đến thành phố). Въе́хать (dọn vào nhà, đi xe vào trong)."},{"t":"para","text":"3. Я прошу́ тебя́ сходи́ть в магази́н и принести́ проду́кты. Помоги́те мне, пожа́луйста, внести́ ве́щи в кварти́ру.","b":1},{"t":"subhead","text":"Đáp án: принести́; внести́."},{"t":"para","text":"Dịch: Mẹ nhờ con đi cửa hàng và mang thực phẩm về/đến. Làm ơn giúp tôi mang (khiêng) đồ vào căn hộ."},{"t":"example","text":"Giải thích: Принести́ (mang cái gì đến đích). Внести́ (mang từ ngoài vào trong không gian kín)."},{"t":"para","text":"4. В на́шу страну́ запрещено́ ввози́ть живо́тных без соотве́тствующих докуме́нтов. Вы мо́жете привезти́ бума́ги ко мне на рабо́ту?","b":1},{"t":"subhead","text":"Đáp án: ввози́ть; привезти́."},{"t":"para","text":"Dịch: Cấm nhập khẩu (mang vào) động vật vào nước ta mà không có giấy tờ. Bạn có thể mang (chở) giấy tờ đến chỗ làm cho tôi không?"},{"t":"example","text":"Giải thích: Ввози́ть (nhập khẩu, mang vào trong biên giới - dùng imperfective vì là luật cấm chung). Привезти́ (mang đến cho ai - cụ thể)."},{"t":"para","text":"5. Э́ту коро́бку бу́дет нелегко́ внести́ (вти́снуть/впихну́ть) в маши́ну. Что ты до́лжен был принести́ на пикни́к?","b":1},{"t":"subhead","text":"Đáp án: внести́ (hoặc втащи́ть nếu nặng); принести́."},{"t":"para","text":"Dịch: Cái hộp này sẽ không dễ mang vào trong xe đâu. Bạn đã phải mang cái gì đến buổi dã ngoại thế?"},{"t":"example","text":"Giải thích: Внести́ (mang vào trong). Принести́ (mang đến sự kiện)."},{"t":"para","text":"6. Тебе́ лу́чше поторопи́ться, ина́че ты прибежи́шь к фи́нишу после́дним. Дово́льно тру́дно взбежа́ть (взойти́) по ступе́ням на пя́тый эта́ж, ни ра́зу не останови́вшись.","b":1},{"t":"subhead","text":"Đáp án: прибежа́ть; взбежа́ть (hoặc взойти́ - đi lên)."},{"t":"para","text":"Dịch: Bạn nên nhanh lên, nếu không bạn sẽ chạy về đích cuối cùng đấy. Khá khó để chạy lên (leo lên) bậc thang tầng 5 mà không nghỉ lần nào."},{"t":"example","text":"Giải thích: Прибежа́ть (chạy đến đích). Взбежа́ть (chạy lên trên - tiền tố вз- chỉ hướng lên). Sách yêu cầu tiền tố в-, nhưng với cầu thang thường dùng вз-. Nếu bắt buộc в-, có thể dùng войти (đi vào tầng 5) nhưng ngữ cảnh \"bậc thang\" thì вз- (vzleste/vzbezhat) chính xác hơn. Trong khuôn khổ bài học в-, có thể sách ám chỉ nghĩa \"lên\" của в- (như всходить), nhưng вз- phổ biến hơn."},{"t":"note","text":"Lưu ý: Sách Glazunova đôi khi gộp в- và вз- vào nhóm nghĩa \"lên/vào\". Ở đây взбежать (chạy lên) là hợp lý nhất."},{"t":"para","text":"7. Сто́ит внести́ я́сность в э́тот вопро́с. Э́то лека́рство должно́ бы́стро принести́ тебе́ облегче́ние.","b":1},{"t":"subhead","text":"Đáp án: внести́; принести́."},{"t":"para","text":"Dịch: Cần phải làm sáng tỏ (đưa sự rõ ràng vào) vấn đề này. Thuốc này sẽ nhanh chóng mang lại sự nhẹ nhõm cho bạn."},{"t":"example","text":"Giải thích: Cụm cố định: Внести ясность (làm sáng tỏ). Принести облегчение (mang lại sự nhẹ nhõm/giảm đau)."},{"t":"para","text":"b) Вы- (ra ngoài) hoặc У- (rời đi)","b":1},{"t":"para","text":"1. Сего́дня не сто́ит выходи́ть из до́ма без ша́пки. Ты зна́ешь, он реши́л уйти́ из до́ма и жить самостоя́тельно.","b":1},{"t":"subhead","text":"Đáp án: выходи́ть; уйти́."},{"t":"para","text":"Dịch: Hôm nay không nên ra khỏi nhà mà không đội mũ. Bạn biết không, cậu ấy đã quyết định bỏ nhà đi và sống tự lập."},{"t":"example","text":"Giải thích: Выходи́ть (đi ra ngoài không gian nhà). Уйти́ из дома (bỏ nhà đi, rời đi hẳn)."},{"t":"para","text":"2. Че́рез час мы должны́ вы́ехать на шоссе́. Ду́маю, тебе́ лу́чше уе́хать, что́бы оконча́тельно не испо́ртить отноше́ния с партнёрами.","b":1},{"t":"subhead","text":"Đáp án: вы́ехать; уе́хать."},{"t":"para","text":"Dịch: Một tiếng nữa chúng ta phải xe ra (tiến ra) đường cao tốc. Tôi nghĩ tốt nhất bạn nên rời đi (đi nơi khác) để không làm hỏng hẳn quan hệ với đối tác."},{"t":"example","text":"Giải thích: Вы́ехать (lái xe từ chỗ hẹp ra chỗ rộng/lộ trình). Уе́хать (rời đi xa/tránh mặt)."},{"t":"para","text":"3. Самолёт вылета́ет то́чно по расписа́нию. Я улета́ю в суббо́ту, ты придёшь меня́ провожа́ть?","b":1},{"t":"subhead","text":"Đáp án: вылета́ет; улета́ю."},{"t":"para","text":"Dịch: Máy bay cất cánh (bay đi) đúng lịch trình. Tôi sẽ bay đi (rời đi) vào thứ bảy, bạn đến tiễn tôi nhé?"},{"t":"example","text":"Giải thích: Вылета́ть (hành động kỹ thuật cất cánh/rời sân bay). Улета́ть (người rời đi bằng máy bay)."},{"t":"para","text":"4. Я бою́сь, что мою́ маши́ну мо́гут угна́ть. За тако́е поведе́ние тебя́ мо́гут вы́гнать из кла́сса.","b":1},{"t":"subhead","text":"Đáp án: угна́ть; вы́гнать."},{"t":"para","text":"Dịch: Tôi sợ xe mình có thể bị lấy trộm. Vì hành vi như thế bạn có thể bị đuổi ra khỏi lớp."},{"t":"example","text":"Giải thích: Угна́ть (lấy trộm xe). Вы́гнать (đuổi ra ngoài)."},{"t":"para","text":"5. Извини́те, я до́лжен вы́йти на мину́ту. Я не могу́ уйти́ с рабо́ты, не сдав ключи́ от лаборато́рии.","b":1},{"t":"subhead","text":"Đáp án: вы́йти; уйти́."},{"t":"para","text":"Dịch: Xin lỗi, tôi phải ra ngoài một phút. Tôi không thể về (rời) chỗ làm mà chưa trả chìa khóa phòng thí nghiệm."},{"t":"example","text":"Giải thích: Вы́йти (ra ngoài chốc lát). Уйти́ (tan làm, đi về)."},{"t":"para","text":"6. Посмотри́те, несмотря́ на то что он упа́л с моста́ высото́й 20 ме́тров, ему́ удало́сь вы́плыть. Ры́ба сорвала́сь с крючка́, мелькну́ла в во́здухе и гото́ва была́ уплы́ть, но мы пойма́ли её сачко́м.","b":1},{"t":"subhead","text":"Đáp án: вы́плыть; уплы́ть."},{"t":"para","text":"Dịch: Nhìn kìa, mặc dù ngã từ cầu cao 20 mét, anh ấy vẫn bơi được lên (sống sót/nổi lên). Con cá tuột khỏi lưỡi câu, loáng cái trên không và suýt bơi đi mất, nhưng chúng tôi đã dùng vợt bắt được."},{"t":"example","text":"Giải thích: Вы́плыть (nổi lên mặt nước, bơi vào bờ an toàn). Уплы́ть (bơi đi xa, trốn thoát)."}]},{"id":"07-s118","type":"exercise","title":"Bài 617 (Trang 327)","num":617,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя глаго́лы движе́ния с приста́вками вы- и́ли с-, да́йте антоними́чные вариа́нты предложе́ний. (Sử dụng động từ chuyển động với tiền tố \"вы-\" hoặc \"с-\", hãy đưa ra các câu biến thể trái nghĩa)."},{"t":"subhead","text":"Gợi ý ngữ pháp trong khung (Trang 327):","b":1},{"t":"para","text":"В- (Во-) (Vào trong) ↔ Вы- (Ra ngoài)."},{"t":"para","text":"В- / Вз- (Lên trên bề mặt/Lên cao) ↔ С- (Со-) (Xuống dưới/Rời khỏi bề mặt)."},{"t":"example","text":"Ví dụ: Влезть на де́рево (Leo lên cây) ↔ Слезть с де́рева (Leo xuống khỏi cây)."},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"Ребёнок влез на стул. (Đứa bé đã leo lên ghế.)"},{"t":"para","text":"Trái nghĩa: Ребёнок слез со сту́ла."},{"t":"para","text":"Dịch: Đứa bé đã leo xuống khỏi ghế."},{"t":"example","text":"Giải thích: Влез на (lên bề mặt) → Слез со (xuống khỏi bề mặt)."},{"t":"para","text":"Я́щерица вползла́ в нору́. (Con thằn lằn đã bò vào hang.)"},{"t":"para","text":"Trái nghĩa: Я́щерица вы́ползла из норы́."},{"t":"para","text":"Dịch: Con thằn lằn đã bò ra khỏi hang."},{"t":"example","text":"Giải thích: Вползла в (vào trong) → Выползла из (ra ngoài)."},{"t":"para","text":"Он не мо́жет влезть на подоко́нник. (Cậu ấy không thể leo lên bệ cửa sổ.)"},{"t":"para","text":"Trái nghĩa: Он не мо́жет слезть с подоко́нника."},{"t":"para","text":"Dịch: Cậu ấy không thể leo xuống khỏi bệ cửa sổ."},{"t":"para","text":"Мы должны́ войти́ в зда́ние ро́вно в де́вять часо́в. (Chúng ta phải vào tòa nhà đúng 9 giờ.)"},{"t":"para","text":"Trái nghĩa: Мы должны́ вы́йти из зда́ния..."},{"t":"para","text":"Dịch: Chúng ta phải ra khỏi tòa nhà..."},{"t":"para","text":"Я с трудо́м смог втащи́ть чемода́н на ве́рхнюю по́лку. (Tôi khó khăn lắm mới kéo được cái vali lên tầng giá trên.)"},{"t":"para","text":"Trái nghĩa: Я с трудо́м смог стащи́ть чемода́н с ве́рхней по́лки."},{"t":"para","text":"Dịch: Tôi khó khăn lắm mới kéo (lôi) được cái vali xuống khỏi tầng giá trên."},{"t":"example","text":"Giải thích: Втащить на (kéo lên) → Стащить с (kéo xuống)."},{"t":"para","text":"Неда́вно мы въе́хали в кварти́ру у ста́нции метро́ \"Примо́рская\". (Gần đây chúng tôi đã dọn vào căn hộ ở ga tàu điện ngầm \"Primorskaya\".)"},{"t":"para","text":"Trái nghĩa: Неда́вно мы вы́ехали из кварти́ры..."},{"t":"para","text":"Dịch: Gần đây chúng tôi đã dọn ra (rời) khỏi căn hộ..."},{"t":"para","text":"Я без остано́вки взбежа́л на седьмо́й эта́ж. (Tôi chạy một mạch lên tầng 7 không nghỉ.)"},{"t":"para","text":"Trái nghĩa: Я без остано́вки сбежа́л с седьмо́го этажа́."},{"t":"para","text":"Dịch: Tôi chạy xuống từ tầng 7 không nghỉ."},{"t":"example","text":"Giải thích: Взбежал на (chạy lên) → Сбежал с (chạy xuống)."},{"t":"para","text":"Я наде́юсь, тебе́ уда́стся вкати́ть мяч в воро́та. (Tôi hy vọng bạn sẽ lăn được bóng vào gôn.)"},{"t":"para","text":"Trái nghĩa: ... вы́катить мяч из воро́т."},{"t":"para","text":"Dịch: ... lăn bóng ra khỏi gôn."},{"t":"para","text":"Что́бы доста́ть до выключа́теля, ты до́лжен влезть на стул. (Để với tới công tắc, bạn phải leo lên ghế.)"},{"t":"para","text":"Trái nghĩa: ... ты до́лжен слезть со сту́ла."},{"t":"para","text":"Dịch: ... bạn phải leo xuống khỏi ghế."},{"t":"para","text":"Я вбежа́л в класс, когда́ прозвене́л звоно́к. (Tôi chạy vào lớp khi chuông reo.)"},{"t":"para","text":"Trái nghĩa: Я вы́бежал из кла́сса..."},{"t":"para","text":"Dịch: Tôi chạy ra khỏi lớp..."}]},{"id":"07-s119","type":"exercise","title":"Bài 618 (Trang 327)","num":618,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc đơn, sử dụng động từ chuyển động cần thiết với tiền tố вы- (ra) hoặc с- (xuống/rời). Điền giới từ thích hợp vào chỗ trống. Giải thích lựa chọn."},{"t":"para","text":"Е́сли постуча́ть, змея́ должна́ (ползти́/по́лзать) ... ка́мня.","b":1},{"t":"subhead","text":"Đáp án: вы́ползти из-под","b":1},{"t":"para","text":"Dịch: Nếu gõ, con rắn sẽ bò ra từ dưới tảng đá."},{"t":"example","text":"Giải thích: Rắn ở dưới đá → dùng tiền tố вы- (ra) và giới từ из-под (từ dưới)."},{"t":"para","text":"Помоги́ мне (тащи́ть/таска́ть) ... ноги́ сапо́г, оди́н я уже́ снял, а с други́м ничего́ не получа́ется.","b":1},{"t":"subhead","text":"Đáp án: стащи́ть с","b":1},{"t":"para","text":"Dịch: Giúp tôi tháo (lôi/kéo) chiếc ủng ra khỏi chân với, tôi tháo được một chiếc rồi, còn chiếc kia thì chịu."},{"t":"example","text":"Giải thích: Tháo đồ chật (giày, nhẫn) dùng стащить (kéo tuột ra/xuống) + giới từ с."},{"t":"para","text":"На сле́дующей неде́ле он обеща́л (е́хать/е́здить) ... э́той кварти́ры.","b":1},{"t":"subhead","text":"Đáp án: вы́ехать из","b":1},{"t":"para","text":"Dịch: Tuần sau anh ấy hứa sẽ dọn ra (rời) khỏi căn hộ này."},{"t":"example","text":"Giải thích: Rời bỏ chỗ ở vĩnh viễn → выехать из."},{"t":"para","text":"Как ты не понима́ешь, я не могу́ (бежа́ть/бе́гать) ... уро́ков.","b":1},{"t":"subhead","text":"Đáp án: сбега́ть / сбежа́ть с","b":1},{"t":"para","text":"Dịch: Sao cậu không hiểu nhỉ, tớ không thể trốn (chuồn) học được."},{"t":"example","text":"Giải thích: Сбегать с уроков là cụm từ cố định: trốn học."},{"t":"para","text":"За́втра мы должны́ (идти́/ходи́ть) ... до́ма в де́вять часо́в.","b":1},{"t":"subhead","text":"Đáp án: вы́йти из","b":1},{"t":"para","text":"Dịch: Ngày mai chúng ta phải ra khỏi nhà lúc 9 giờ."},{"t":"example","text":"Giải thích: Rời khỏi không gian nhà để đi đâu đó → выйти из."},{"t":"para","text":"Тебе́ лу́чше (лезть/ла́зить) ... подоко́нника, ина́че ты мо́жешь упа́сть.","b":1},{"t":"subhead","text":"Đáp án: слезть с","b":1},{"t":"para","text":"Dịch: Con tốt nhất nên leo xuống khỏi bệ cửa sổ đi, kẻo ngã đấy."},{"t":"example","text":"Giải thích: Rời khỏi bề mặt cao (bệ cửa) → слезть с."},{"t":"para","text":"Мы уже́ давно́ хоте́ли (е́хать/е́здить) ... ледяно́й горы́.","b":1},{"t":"subhead","text":"Đáp án: съе́хать с","b":1},{"t":"para","text":"Dịch: Chúng tôi đã muốn trượt xuống từ núi băng từ lâu rồi."},{"t":"example","text":"Giải thích: Trượt/đi xe từ trên cao xuống → съехать с."},{"t":"para","text":"Я запу́тался и не могу́ (лезть/ла́зить) ... пеще́ры.","b":1},{"t":"subhead","text":"Đáp án: вы́лезти из","b":1},{"t":"para","text":"Dịch: Tôi bị mắc kẹt/rối và không thể chui/leo ra khỏi hang."},{"t":"example","text":"Giải thích: Ra khỏi không gian kín (hang) → вылезти из."},{"t":"para","text":"Е́сли ты пло́хо себя́ чу́вствуешь, тебе́ лу́чше прекрати́ть соревнова́ния и (идти́/ходи́ть) ... distáncii.","b":1},{"t":"subhead","text":"Đáp án: сойти́ с","b":1},{"t":"para","text":"Dịch: Nếu bạn thấy không khỏe, tốt nhất nên dừng thi đấu và rời khỏi đường đua."},{"t":"example","text":"Giải thích: Сойти с дистанции (bỏ cuộc/rời đường đua) là cụm cố định."},{"t":"para","text":"Снача́ла на́до (нести́/носи́ть) ве́щи ... ле́стницу, а пото́м мо́жно закры́ть дверь.","b":1},{"t":"subhead","text":"Đáp án: вы́нести на","b":1},{"t":"para","text":"Dịch: Trước tiên cần mang đồ ra cầu thang (chiếu nghỉ), rồi sau đó mới đóng cửa được."},{"t":"example","text":"Giải thích: Mang từ trong nhà ra không gian bên ngoài cửa (cầu thang chung) → вынести на."},{"t":"para","text":"Сиди́ споко́йно, не на́до всё вре́мя (ползти́/по́лзать) ... сту́ла.","b":1},{"t":"subhead","text":"Đáp án: сполза́ть со","b":1},{"t":"para","text":"Dịch: Ngồi yên đi, đừng có lúc nào cũng trườn/tuột xuống khỏi ghế thế."},{"t":"example","text":"Giải thích: Hành động trượt dần xuống khỏi bề mặt ghế → сползать с. Dùng сползать (chưa hoàn thành) vì có всё время (lúc nào cũng)."},{"t":"para","text":"Мо́жно (идти́/ходи́ть) ... ума́ от тако́го коли́чества нерешённых пробле́м!","b":1},{"t":"subhead","text":"Đáp án: сойти́ с","b":1},{"t":"para","text":"Dịch: Có thể phát điên (mất trí) vì đống vấn đề chưa giải quyết này mất!"},{"t":"example","text":"Giải thích: Thành ngữ сойти с ума (điên/mất trí)."},{"t":"para","text":"Я обеща́л (тащи́ть/таска́ть) тебя́ ... всех неприя́тностей и обяза́тельно сде́лаю э́то.","b":1},{"t":"subhead","text":"Đáp án: вы́тащить из","b":1},{"t":"para","text":"Dịch: Tôi đã hứa lôi/kéo bạn ra khỏi mọi rắc rối và chắc chắn sẽ làm điều đó."},{"t":"example","text":"Giải thích: Cứu ai đó thoát khỏi tình trạng xấu (nghĩa bóng của lôi ra khỏi hố) → вытащить из."},{"t":"para","text":"На ста́нции не́сколько ваго́нов (идти́/ходи́ть) ... ре́льсов.","b":1},{"t":"subhead","text":"Đáp án: сошли́ с","b":1},{"t":"para","text":"Dịch: Tại nhà ga, vài toa tàu đã trật (đi chệch khỏi) đường ray."},{"t":"example","text":"Giải thích: Сойти с рельсов (trật bánh) là cụm cố định."}]},{"id":"07-s120","type":"exercise","title":"Bài 619 (Trang 328)","num":619,"blocks":[{"t":"instruction","text":"Yêu cầu: Mở ngoặc đơn, dùng động từ ở thì Quá khứ với các tiền tố в- (во-), при-, вы-, у-. Giải thích."},{"t":"para","text":"Мы (е́хать/е́здить) из до́ма, когда́ на поля́х ещё лежа́л снег.","b":1},{"t":"subhead","text":"Đáp án: вы́ехали","b":1},{"t":"para","text":"Dịch: Chúng tôi đã rời (lái xe ra) khỏi nhà khi tuyết vẫn còn phủ trên các cánh đồng."},{"t":"example","text":"Giải thích: Rời khỏi địa điểm → выехать."},{"t":"para","text":"В про́шлом году́ наш де́тский сад на ле́то (везти́/вози́ть) дете́й на да́чу.","b":1},{"t":"subhead","text":"Đáp án: вывози́л (hoặc вы́вез)"},{"t":"para","text":"Dịch: Năm ngoái nhà trẻ của chúng tôi đã đưa (chở) bọn trẻ ra nhà nghỉ ngoại ô để nghỉ hè."},{"t":"example","text":"Giải thích: Dùng вывозил (chưa hoàn thành) để chỉ hoạt động tổ chức đưa đi (mang tính quy mô/quá trình), hoặc вывез (hoàn thành) để chỉ sự kiện đã xong. Вывозил phổ biến hơn khi nói về hoạt động của tổ chức."},{"t":"para","text":"Мы вас так до́лго жда́ли и ра́ды, что вы наконе́ц (идти́/ходи́ть).","b":1},{"t":"subhead","text":"Đáp án: пришли́","b":1},{"t":"para","text":"Dịch: Chúng tôi đợi bạn mãi và rất vui vì cuối cùng bạn cũng đến."},{"t":"example","text":"Giải thích: Đến nơi, xuất hiện → пришли."},{"t":"para","text":"Его́ нет, он (лете́ть/лета́ть) в командиро́вку на две неде́ли.","b":1},{"t":"subhead","text":"Đáp án: улете́л","b":1},{"t":"para","text":"Dịch: Anh ấy không có đây, anh ấy đã bay (đi) công tác 2 tuần rồi."},{"t":"example","text":"Giải thích: Rời đi xa bằng máy bay, hiện tại vắng mặt → улетел."},{"t":"para","text":"Ка́ждое ле́то мы (е́хать/е́здить) на мо́ре.","b":1},{"t":"subhead","text":"Đáp án: уезжа́ли (hoặc приезжа́ли)"},{"t":"para","text":"Dịch: Mùa hè nào chúng tôi cũng rời (thành phố) đi biển."},{"t":"example","text":"Giải thích: Nếu nhấn mạnh việc rời nhà đi nghỉ → уезжали. (Nếu chỉ kể lại việc đã đi và về rồi thì dùng ездили không tiền tố, nhưng đề bài bắt buộc dùng tiền tố)."},{"t":"example","text":"(Câu này trong sách gốc có thể bị in lỗi hoặc thiếu, dựa trên ngữ cảnh câu trả lời phổ biến của bài này): Заче́м ты это (нести́/носи́ть)? Я проси́л тебя́ совсе́м о друго́м."},{"t":"subhead","text":"Đáp án: принёс","b":1},{"t":"para","text":"Dịch: Bạn mang cái này đến làm gì? Tôi nhờ bạn việc khác hẳn mà."},{"t":"example","text":"Giải thích: Mang vật đến nơi người nói đang ở → принёс."},{"t":"example","text":"... (Tiếp tục mạch câu chuyện)"},{"t":"subhead","text":"Đáp án: (Xem câu 6)."},{"t":"para","text":"Она́ (вести́/води́ть) меня́ на доро́гу, да́льше я пошёл оди́н.","b":1},{"t":"subhead","text":"Đáp án: вы́вела","b":1},{"t":"para","text":"Dịch: Cô ấy dẫn tôi ra đường lớn, rồi tôi tự đi tiếp."},{"t":"example","text":"Giải thích: Dẫn từ trong (nhà/ngõ) ra ngoài đường → вывела."},{"t":"para","text":"В про́шлом году́ мою́ маши́ну (гнать/гоня́ть) два ра́за.","b":1},{"t":"subhead","text":"Đáp án: угоня́ли","b":1},{"t":"para","text":"Dịch: Năm ngoái xe tôi bị lấy trộm hai lần."},{"t":"example","text":"Giải thích: Угонять (lấy trộm xe). Vì \"2 lần\" nên dùng thể chưa hoàn thành угоняли (lặp lại)."},{"t":"para","text":"Ду́маю, все докуме́нты он (нести́/носи́ть) с собо́й.","b":1},{"t":"subhead","text":"Đáp án: унёс","b":1},{"t":"para","text":"Dịch: Tôi nghĩ anh ấy đã mang tất cả tài liệu đi theo rồi."},{"t":"example","text":"Giải thích: Mang đi khỏi nơi này → унёс."},{"t":"para","text":"Когда́ котёнок немно́го привы́к к но́вой обстано́вке, он (лезть/ла́зить) из-под дива́на к блю́дечку с молоко́м.","b":1},{"t":"subhead","text":"Đáp án: вы́лез","b":1},{"t":"para","text":"Dịch: Khi mèo con đã hơi quen chỗ mới, nó chui (bò) ra từ gầm ghế sofa đến đĩa sữa."},{"t":"example","text":"Giải thích: Chui ra từ không gian hẹp → вылез."},{"t":"para","text":"Запыха́вшись, он (бежа́ть/бе́гать) в ваго́н.","b":1},{"t":"subhead","text":"Đáp án: вбежа́л","b":1},{"t":"para","text":"Dịch: Thở hổn hển, anh ấy chạy vào toa tàu."},{"t":"example","text":"Giải thích: Chạy vào trong → вбежал."},{"t":"para","text":"Он ча́сто (идти́/ходи́ть) кури́ть на ле́стницу.","b":1},{"t":"subhead","text":"Đáp án: выходи́л","b":1},{"t":"para","text":"Dịch: Anh ấy thường ra cầu thang hút thuốc."},{"t":"example","text":"Giải thích: Đi ra ngoài (hành lang/cầu thang) → выходил. Dùng imperfective vì часто (thường xuyên)."},{"t":"para","text":"Кто (тащи́ть/таска́ть) со стола́ мою́ ру́чку? Верни́те на ме́сто!","b":1},{"t":"subhead","text":"Đáp án: утащи́л","b":1},{"t":"para","text":"Dịch: Ai đã chôm (tha/lấy mất) cái bút của tôi trên bàn rồi? Trả lại chỗ cũ ngay!"},{"t":"example","text":"Giải thích: Lấy đi mất (thường dùng утащить với ý nghĩa lấy trộm vặt hoặc mang đi đâu mất)."},{"t":"para","text":"Во́лны (гнать/гоня́ть) ло́дку к небольшо́му о́строву.","b":1},{"t":"subhead","text":"Đáp án: пригна́ли","b":1},{"t":"para","text":"Dịch: Sóng đã đẩy (lùa) chiếc thuyền đến một hòn đảo nhỏ."},{"t":"example","text":"Giải thích: Đẩy đến đích → пригнали."},{"t":"para","text":"Из окна́ ваго́на бы́ло ви́дно, как (бежа́ть/бе́гать) наза́д телегра́фные столбы́ и придоро́жные со́сны.","b":1},{"t":"subhead","text":"Đáp án: убега́ли","b":1},{"t":"para","text":"Dịch: Từ cửa sổ toa tàu có thể thấy các cột điện báo và hàng thông ven đường chạy lùi về phía sau."},{"t":"example","text":"Giải thích: Chuyển động lùi xa dần → убегали."},{"t":"para","text":"По́сле дождя́ ло́шадь (вести́/води́ть) из-под наве́са.","b":1},{"t":"subhead","text":"Đáp án: вы́вели","b":1},{"t":"para","text":"Dịch: Sau cơn mưa, người ta dắt ngựa ra khỏi mái che."},{"t":"example","text":"Giải thích: Dắt từ trong ra ngoài → вывели."},{"t":"vocab","ru":"Меня́ не́ было в го́роде три дня","vi":"я (е́хать/е́здить) на конфере́нцию.","g":null},{"t":"subhead","text":"Đáp án: уезжа́л","b":1},{"t":"para","text":"Dịch: Tôi đã vắng mặt ở thành phố 3 ngày: tôi đã đi (rời đi) dự hội nghị."},{"t":"example","text":"Giải thích: Nhấn mạnh việc vắng mặt do đã rời đi → уезжал."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 329)","b":1},{"t":"para","text":"Tiếng Nga: ! При присоединении приставок глаголы однонаправленного движения приобретают значение совершенного вида, а глаголы разнонаправленного движения остаются глаголами несовершенного вида."},{"t":"example","text":"Dịch và Giải thích: ! Khi thêm tiền tố, các động từ chuyển động một chiều (идти́, лете́ть, бежа́ть...) sẽ mang ý nghĩa Hoàn thành thể (chỉ hành động xảy ra 1 lần, đã xong hoặc sẽ xong hẳn)."},{"t":"example","text":"Ví dụ: при- + идти́ → прийти́ (đến nơi - hoàn thành)."},{"t":"example","text":"Ngược lại, các động từ chuyển động đa chiều (ходи́ть, лета́ть, бе́гать...) khi thêm tiền tố vẫn giữ nguyên là Chưa hoàn thành thể (chỉ quá trình, thói quen, hoặc hành động lặp lại)."},{"t":"example","text":"Ví dụ: при- + ходи́ть → приходи́ть (đến nơi - lặp lại/đang đến)."}]},{"id":"07-s121","type":"exercise","title":"Bài 620 (Trang 329)","num":620,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя необходимый по смыслу глагол движения в форме прошедшего времени с приставкой в- (во-), при-, вы- или у-. Объясните ваш выбор. Укажите варианты. (Mở ngoặc đơn, sử dụng động từ chuyển động cần thiết theo ý nghĩa ở thì quá khứ với tiền tố в- (во-), при-, вы- hoặc у-. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"Ý nghĩa tiền tố cần nhớ:","b":1},{"t":"vocab","ru":"В- (Во-)","vi":"Vào trong.","g":null},{"t":"vocab","ru":"Вы-","vi":"Ra ngoài.","g":null},{"t":"vocab","ru":"При-","vi":"Đến nơi.","g":null},{"t":"vocab","ru":"У-","vi":"Rời đi (đi mất).","g":null},{"t":"para","text":"1. Когда́ мы ... из аэропо́рта, пого́да была́ хоро́шая.","b":1},{"t":"subhead","text":"Đáp án: вылета́ли (từ лета́ть)"},{"t":"para","text":"Dịch: Khi chúng tôi đang bay ra (cất cánh) khỏi sân bay, thời tiết rất đẹp."},{"t":"example","text":"Giải thích: Dùng thể chưa hoàn thành (вылета́ли) để chỉ một quá trình đang diễn ra thì quan sát thấy thời tiết. Nếu dùng вы́летели (đã bay đi xong rồi) thì không mô tả được bối cảnh thời tiết trong lúc bay lên."},{"t":"para","text":"2. Когда́ он ... в зал, все по́няли, что ничего́ не получи́лось.","b":1},{"t":"subhead","text":"Đáp án: вошёл (từ идти́)"},{"t":"para","text":"Dịch: Khi anh ấy bước vào phòng sảnh, mọi người đều hiểu rằng chẳng đạt được kết quả gì."},{"t":"example","text":"Giải thích: Hành động đi vào đã hoàn tất (một lần, cụ thể) → dùng thể hoàn thành вошёл."},{"t":"para","text":"3. Он написа́л для вас э́ту запи́ску, когда́ ... на заня́тия.","b":1},{"t":"subhead","text":"Đáp án: убега́л (từ бе́гать)"},{"t":"para","text":"Dịch: Cậu ấy đã viết mảnh giấy này cho bạn khi đang vội chạy đi học."},{"t":"example","text":"Giải thích: Hành động \"viết\" xảy ra song song hoặc ngay trong lúc chuẩn bị rời đi (убега́л - chưa hoàn thành, chỉ quá trình rời đi vội vã). Tiền tố у- chỉ việc rời đi nơi khác."},{"t":"para","text":"4. Как то́лько он ..., разда́лся телефо́нный звоно́к.","b":1},{"t":"subhead","text":"Đáp án: уе́хал (từ е́хать)"},{"t":"para","text":"Dịch: Ngay khi anh ấy vừa rời đi (lái xe đi), thì điện thoại reo."},{"t":"example","text":"Giải thích: Hành động rời đi đã hoàn tất (как только - ngay khi đã...) → dùng thể hoàn thành уе́хал."},{"t":"para","text":"5. Когда́ она́ попроща́лась и ..., все вздохну́ли с облегче́нием.","b":1},{"t":"subhead","text":"Đáp án: ушла́ (từ идти́)"},{"t":"para","text":"Dịch: Khi cô ấy chào tạm biệt và bỏ đi (rời đi), mọi người đều thở phào nhẹ nhõm."},{"t":"example","text":"Giải thích: Hành động rời đi đã hoàn tất → thể hoàn thành ушла́."},{"t":"para","text":"6. Когда́ мы наконе́ц ... телеви́зор в ко́мнату, на не́сколько мину́т не могли́ прийти́ в себя́.","b":1},{"t":"subhead","text":"Đáp án: втащи́ли (từ тащи́ть)"},{"t":"para","text":"Dịch: Khi cuối cùng chúng tôi cũng lôi/khiêng được cái tivi vào phòng, chúng tôi mệt đến mức không thở nổi trong vài phút."},{"t":"example","text":"Giải thích: Kết quả của hành động nặng nhọc đã hoàn thành (наконец - cuối cùng cũng xong) → thể hoàn thành втащи́ли. Tiền tố в- chỉ hướng vào trong."},{"t":"para","text":"7. Я ... на у́лицу — у подъе́зда никого́ не́ было.","b":1},{"t":"subhead","text":"Đáp án: вы́бежал (từ бежа́ть)"},{"t":"para","text":"Dịch: Tôi chạy vụt ra đường — ở cổng chẳng còn ai cả."},{"t":"example","text":"Giải thích: Hành động chạy ra ngoài (để kiểm tra) diễn ra nhanh, trọn vẹn 1 lần → thể hoàn thành вы́бежал. Tiền tố вы- chỉ hướng ra ngoài."},{"t":"para","text":"8. Когда́ мы вчера́ ... домо́й, бы́ло уже́ по́здно.","b":1},{"t":"subhead","text":"Đáp án: пришли́ (từ идти́)"},{"t":"para","text":"Dịch: Hôm qua khi chúng tôi về đến nhà, trời đã muộn rồi."},{"t":"example","text":"Giải thích: Nhấn mạnh vào thời điểm đã có mặt ở đích đến (kết quả) → dùng пришли́. (Lưu ý: Nếu muốn nói \"trên đường đi bộ về thì trời tối\" ta dùng шли, nhưng đề bài bắt buộc dùng động từ có tiền tố, nên пришли́ là đáp án phù hợp nhất)."},{"t":"para","text":"9. Прошло́ мно́го лет, с тех пор как она́ ... из го́рода.","b":1},{"t":"subhead","text":"Đáp án: уе́хала (từ е́хать)"},{"t":"para","text":"Dịch: Đã nhiều năm trôi qua kể từ khi cô ấy rời khỏi thành phố."},{"t":"example","text":"Giải thích: Sự kiện rời đi đã xảy ra và hoàn tất trong quá khứ → thể hoàn thành уе́хала."},{"t":"para","text":"10. Когда́ я ... в ко́мнату, я уви́дел всех свои́х друзе́й.","b":1},{"t":"subhead","text":"Đáp án: вошёл (từ идти́) hoặc пришёл (từ идти́)"},{"t":"para","text":"Dịch: Khi tôi bước vào phòng (hoặc đến nơi), tôi nhìn thấy tất cả bạn bè."},{"t":"example","text":"Giải thích: Hành động vào phòng đã xảy ra xong thì mới nhìn thấy → thể hoàn thành. Вошёл (bước từ ngoài vào trong) hợp lý nhất với từ \"phòng\"."},{"t":"para","text":"11. Когда́ мы ... из го́рода, пошёл дождь.","b":1},{"t":"subhead","text":"Đáp án: выезжа́ли (từ е́здить)"},{"t":"para","text":"Dịch: Khi chúng tôi đang lái xe ra khỏi thành phố thì trời đổ mưa."},{"t":"example","text":"Giải thích: Mưa bắt đầu rơi trong quá trình di chuyển ra khỏi thành phố → thể chưa hoàn thành выезжа́ли."},{"t":"para","text":"12. Всё ста́ло бо́лее поня́тно, когда́ я ... не́сколько приме́ров.","b":1},{"t":"subhead","text":"Đáp án: привёл (từ вести́)"},{"t":"para","text":"Dịch: Mọi thứ trở nên dễ hiểu hơn khi tôi đưa ra (dẫn ra) vài ví dụ."},{"t":"example","text":"Giải thích: Привести́ пример (đưa ra ví dụ) là cụm cố định. Hành động đưa ra ví dụ đã xong → thể hoàn thành привёл."},{"t":"para","text":"13. Когда́ из-за туч ... со́лнце, в лесу́ ста́ло светле́е.","b":1},{"t":"subhead","text":"Đáp án: вы́шло (từ идти́)"},{"t":"para","text":"Dịch: Khi mặt trời ló ra (đi ra) khỏi đám mây, trong rừng trở nên sáng hơn."},{"t":"example","text":"Giải thích: Mặt trời xuất hiện (kết quả) → thể hoàn thành вы́шло."},{"t":"para","text":"14. Когда́ твой роди́тели ..., они́ попроси́ли меня́ позабо́титься о тебе́.","b":1},{"t":"subhead","text":"Đáp án: уезжа́ли (từ е́здить)"},{"t":"para","text":"Dịch: Khi bố mẹ bạn sắp đi/đang chuẩn bị đi, họ đã nhờ tôi chăm sóc bạn."},{"t":"example","text":"Giải thích: Lời dặn dò xảy ra trong lúc chuẩn bị rời đi (quá trình chia tay), chưa đi hẳn → thể chưa hoàn thành уезжа́ли."},{"t":"para","text":"15. Я приступи́л к рабо́те, по́сле того́ как мой колле́ги ... меня́ в курс де́ла.","b":1},{"t":"subhead","text":"Đáp án: ввели́ (từ вести́)"},{"t":"para","text":"Dịch: Tôi bắt tay vào việc sau khi các đồng nghiệp đã đưa tôi vào guồng công việc (hướng dẫn nhập môn)."},{"t":"example","text":"Giải thích: Ввести́ в курс де́ла (hướng dẫn/giới thiệu tình hình) là cụm cố định. Hành động hướng dẫn xong rồi mới làm việc → thể hoàn thành ввели́."},{"t":"para","text":"16. Де́ти о́чень обра́довались, когда́ мы ... им я́блоки из на́шего са́да.","b":1},{"t":"subhead","text":"Đáp án: принесли́ (từ нести́)"},{"t":"para","text":"Dịch: Lũ trẻ rất vui mừng khi chúng tôi mang táo từ vườn nhà đến cho chúng."},{"t":"example","text":"Giải thích: Mang đến đích (kết quả) → thể hoàn thành принесли́."}]},{"id":"07-s122","type":"exercise","title":"Bài 621 (Trang 329)","num":621,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя необходимый по смыслу глагол движения в форме настоящего или будущего простого времени с приставкой в- (во-), при-, вы- или у-. Объясните ваш выбор. Укажите варианты. (Mở ngoặc đơn, sử dụng động từ chuyển động cần thiết ở thì hiện tại hoặc tương lai đơn với tiền tố в- (во-), при-, вы- hoặc у-. Giải thích sự lựa chọn. Chỉ ra các phương án)."},{"t":"note","text":"Lưu ý:","b":1},{"t":"example","text":"Tiền tố + Động từ một chiều (идти...) → Tương lai đơn (sẽ làm và hoàn thành)."},{"t":"example","text":"Tiền tố + Động từ đa chiều (ходить...) → Hiện tại (lặp lại/đang diễn ra) hoặc Tương lai (nếu có từ chỉ tương lai)."},{"t":"para","text":"1. Я ... к тебе́ ро́вно в де́вять, будь гото́ва.","b":1},{"t":"subhead","text":"Đáp án: прие́ду (từ е́хать)"},{"t":"para","text":"Dịch: Tớ sẽ đến (bằng xe) chỗ cậu đúng 9 giờ, hãy chuẩn bị sẵn sàng nhé."},{"t":"example","text":"Giải thích: Hành động đến đích cụ thể vào một thời điểm trong tương lai → Tương lai hoàn thành прие́ду."},{"t":"para","text":"2. Ду́маю, я ... вас в курс де́ла чуть по́зже.","b":1},{"t":"subhead","text":"Đáp án: введу́ (từ вести́)"},{"t":"para","text":"Dịch: Tôi nghĩ tôi sẽ giới thiệu/đưa các bạn vào nội dung công việc sau một chút."},{"t":"example","text":"Giải thích: Cụm ввести́ в курс (như câu 15 bài 620). Hành động sẽ thực hiện một lần trong tương lai → Tương lai hoàn thành введу́."},{"t":"para","text":"3. Ка́ждую суббо́ту мы ... на стадио́н смотре́ть футбо́льный матч.","b":1},{"t":"subhead","text":"Đáp án: прихо́дим (từ ходи́ть)"},{"t":"para","text":"Dịch: Thứ Bảy nào chúng tôi cũng đến sân vận động xem bóng đá."},{"t":"example","text":"Giải thích: Hành động lặp đi lặp lại (каждую субботу) → Dùng động từ gốc đa chiều có tiền tố (Hiện tại chưa hoàn thành): прихо́дим."},{"t":"para","text":"4. Я ... в четве́рг, подгото́вьте, пожа́луйста, все необходи́мые докуме́нты.","b":1},{"t":"subhead","text":"Đáp án: улета́ю (từ лета́ть) hoặc вылета́ю"},{"t":"para","text":"Dịch: Tôi sẽ bay đi (rời đi) vào thứ Năm, làm ơn chuẩn bị mọi giấy tờ cần thiết."},{"t":"example","text":"Giải thích: Diễn tả lịch trình rời đi sắp tới. Dùng thì hiện tại của động từ gốc đa chiều (улета́ю) để chỉ một hành động tương lai đã lên kế hoạch chắc chắn. (Cũng có thể dùng вылета́ю - cất cánh/xuất phát)."},{"t":"para","text":"5. Не волну́йся, в суббо́ту я ... все ве́щи на да́чу.","b":1},{"t":"subhead","text":"Đáp án: вы́везу (từ везти́) hoặc увезу́"},{"t":"para","text":"Dịch: Đừng lo, thứ Bảy tớ sẽ chở hết đồ ra nhà nghỉ ngoại ô."},{"t":"example","text":"Giải thích: Hứa hẹn thực hiện trọn vẹn hành động vận chuyển trong tương lai → Tương lai hoàn thành вы́везу (chuyển ra khỏi nhà) hoặc увезу́ (chở đi nơi khác)."},{"t":"para","text":"6. Я ... не́сколько приме́ров, и вы сра́зу поймёте, о чём идёт речь.","b":1},{"t":"subhead","text":"Đáp án: приведу́ (từ вести́)"},{"t":"para","text":"Dịch: Tôi sẽ đưa ra (dẫn ra) vài ví dụ, và các bạn sẽ hiểu ngay vấn đề là gì."},{"t":"example","text":"Giải thích: Sẽ thực hiện hành động dẫn chứng → Tương lai hoàn thành приведу́."},{"t":"para","text":"7. Мы ... за́втра в семь часо́в утра́, наде́юсь, нас встре́тят.","b":1},{"t":"subhead","text":"Đáp án: выезжа́ем (từ е́здить)"},{"t":"para","text":"Dịch: Chúng tôi sẽ xuất phát (đi ra) vào 7 giờ sáng mai, hy vọng người ta sẽ đón chúng tôi."},{"t":"example","text":"Giải thích: Lịch trình khởi hành (выезжа́ем - hiện tại chỉ tương lai gần). Nếu muốn nhấn mạnh việc sẽ đến đích thì dùng прие́дем (sẽ đến), nhưng mốc \"7 giờ sáng\" thường gắn với lúc đi."},{"t":"para","text":"8. С ним всегда́ ... с любо́й глубины́.","b":1},{"t":"subhead","text":"Đáp án: вы́плывешь (từ плыть)"},{"t":"para","text":"Dịch: Đi với anh ấy thì lúc nào cũng bơi lên được (thoát hiểm) từ bất cứ độ sâu nào."},{"t":"example","text":"Giải thích: Nghĩa bóng: vượt qua khó khăn. Dùng tương lai hoàn thành вы́плывешь (ngôi thứ 2 số ít chỉ người chung chung) để chỉ khả năng thực hiện được kết quả."},{"t":"para","text":"9. Не сейча́с я ... его́ на рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: принесу́ (từ нести́)"},{"t":"para","text":"Dịch: Tôi sẽ không mang nó đến chỗ làm ngay bây giờ đâu."},{"t":"example","text":"Giải thích: Phủ định ý định thực hiện hành động ngay lập tức → Tương lai hoàn thành принесу́."},{"t":"para","text":"10. Э́тот приме́р я ... для того́, что́бы вы по́няли, наско́лько ва́жен экспериме́нт.","b":1},{"t":"subhead","text":"Đáp án: привожу́ (từ води́ть)"},{"t":"para","text":"Dịch: Tôi đưa ra ví dụ này là để các bạn hiểu thí nghiệm quan trọng thế nào."},{"t":"example","text":"Giải thích: Hành động đang thực hiện ngay lúc nói (hiện tại) → dùng động từ gốc đa chiều có tiền tố привожу́."},{"t":"para","text":"11. Мы ... к вам на новосе́лье.","b":1},{"t":"subhead","text":"Đáp án: придём (từ идти́)"},{"t":"para","text":"Dịch: Chúng tôi sẽ đến ăn tân gia nhà bạn."},{"t":"example","text":"Giải thích: Thông báo về một sự kiện sẽ xảy ra (đến nơi) → Tương lai hoàn thành придём."},{"t":"para","text":"12. Я ... вам свои́ извине́ния за заде́ржку.","b":1},{"t":"subhead","text":"Đáp án: приношу́ (từ носи́ть)"},{"t":"para","text":"Dịch: Tôi gửi (mang đến) lời xin lỗi vì sự chậm trễ."},{"t":"example","text":"Giải thích: Hành động diễn ra ngay lúc nói (formal) → Hiện tại приношу́."},{"t":"para","text":"13. Заче́м ты ... его́ в заблужде́ние относи́тельно своего́ уча́стия в э́том прое́кте?","b":1},{"t":"subhead","text":"Đáp án: вво́дишь (từ води́ть)"},{"t":"para","text":"Dịch: Tại sao bạn lại làm anh ấy lầm tưởng (đưa vào sự mê muội) về sự tham gia của bạn trong dự án này?"},{"t":"example","text":"Giải thích: Cụm вводи́ть в заблужде́ние (gây hiểu lầm/lừa dối). Hành động đang diễn ra hoặc có tính chất lặp lại → Hiện tại вво́дишь."},{"t":"para","text":"14. Я никого́ не ..., про́сто напомина́ю о том, что у ка́ждого есть рабо́та.","b":1},{"t":"subhead","text":"Đáp án: выгоня́ю (từ гоня́ть)"},{"t":"para","text":"Dịch: Tôi không hề đuổi ai ra cả, tôi chỉ nhắc là ai cũng có việc phải làm thôi."},{"t":"example","text":"Giải thích: Phủ định hành động đang diễn ra ở hiện tại → выгоня́ю."},{"t":"para","text":"15. Обы́чно по́сле рабо́ты он все бума́ги ... с собо́й.","b":1},{"t":"subhead","text":"Đáp án: уно́сит (từ носи́ть)"},{"t":"para","text":"Dịch: Thường thì sau giờ làm việc anh ấy mang hết giấy tờ theo (đi mất)."},{"t":"example","text":"Giải thích: Hành động lặp lại (обычно) → Hiện tại уно́сит (mang đi khỏi nơi làm việc)."},{"t":"para","text":"16. Я ... к вам на да́чу в ближа́йший четве́рг и ... с собо́й дете́й.","b":1},{"t":"subhead","text":"Đáp án: прие́ду; привезу́ (hoặc приезжа́ю / привожу́)"},{"t":"para","text":"Dịch: Tôi sẽ đến chỗ các bạn ở ngoại ô vào thứ Năm tới và sẽ chở theo bọn trẻ."},{"t":"example","text":"Giải thích: Kế hoạch cụ thể trong tương lai. Dùng Tương lai hoàn thành (прие́ду, привезу́) để khẳng định chắc chắn sẽ thực hiện. Cũng có thể dùng Hiện tại của động từ gốc đa chiều (приезжа́ю, привожу́) để chỉ lịch trình đã định. Đáp án прие́ду / привезу́ phổ biến hơn trong lời hứa."},{"t":"para","text":"17. Как пра́вило, он ... на самолёте, но, мо́жет быть, в э́тот раз он ... на по́езде.","b":1},{"t":"subhead","text":"Đáp án: прилета́ет (từ лета́ть); прие́дет (từ е́хать)"},{"t":"para","text":"Dịch: Theo lệ thường thì anh ấy bay đến (bằng máy bay), nhưng có lẽ lần này anh ấy sẽ đến bằng tàu hỏa."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vế 1: Как правило (thường lệ) → lặp lại → dùng прилета́ет (hiện tại, gốc đa chiều)."},{"t":"example","text":"Vế 2: В этот раз (lần này - cụ thể) → sẽ xảy ra 1 lần → dùng прие́дет (tương lai hoàn thành)."}]},{"id":"07-s123","type":"exercise","title":"Bài 622 (Trang 330)","num":622,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложе́ния, обраща́я внима́ние на усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками. Определи́те их значе́ние. (Đọc các câu, chú ý đến các cụm từ cố định với động từ chuyển động có tiền tố. Xác định ý nghĩa của chúng)."},{"t":"para","text":"Giải nghĩa và Dịch:","b":1},{"t":"example","text":"1. У него́ нет ни друзе́й, ни знако́мых, и к нему́ тру́дно войти́ в дове́рие.","b":1},{"t":"para","text":"Ý nghĩa: Làm cho người khác tin tưởng mình."},{"t":"para","text":"Dịch: Anh ấy không có bạn bè, cũng chẳng có người quen, và thật khó để lấy được lòng tin (đi vào sự tin tưởng) của anh ấy."},{"t":"example","text":"2. Мо́жет быть, снача́ла тебе́ э́то не понра́вится, но пото́м ты до́лжен войти́ во вкус.","b":1},{"t":"para","text":"Ý nghĩa: Bắt đầu cảm thấy thích thú/hứng thú với việc gì đó sau khi đã làm quen."},{"t":"para","text":"Dịch: Có thể ban đầu bạn sẽ không thích cái này, nhưng sau đó bạn sẽ bắt đầu thấy hứng thú (đi vào khẩu vị/thấy hay) thôi."},{"t":"example","text":"3. Ты до́лжен войти́ в моё положе́ние и поня́ть, что я не мог поступи́ть ина́че.","b":1},{"t":"para","text":"Ý nghĩa: Thông cảm, đặt mình vào hoàn cảnh của người khác."},{"t":"para","text":"Dịch: Bạn phải đặt mình vào hoàn cảnh của tôi và hiểu rằng tôi không thể làm khác được."},{"t":"example","text":"4. Нам придётся влезть в долги́, что́бы купи́ть э́ту кварти́ру.","b":1},{"t":"para","text":"Ý nghĩa: Vay mượn, mắc nợ."},{"t":"para","text":"Dịch: Chúng tôi sẽ phải mắc nợ (chui vào nợ nần) để mua căn hộ này."},{"t":"example","text":"5. Я хочу́ внести́ я́сность в э́тот вопро́с.","b":1},{"t":"para","text":"Ý nghĩa: Làm sáng tỏ, giải thích rõ ràng."},{"t":"para","text":"Dịch: Tôi muốn làm sáng tỏ (đưa sự rõ ràng vào) vấn đề này."},{"t":"example","text":"6. Свои́ми слова́ми ты вогна́л её в кра́ску.","b":1},{"t":"para","text":"Ý nghĩa: Làm ai đó đỏ mặt (vì xấu hổ hoặc ngượng ngùng)."},{"t":"para","text":"Dịch: Những lời nói của bạn đã làm cô ấy đỏ mặt tía tai."},{"t":"example","text":"7. Мне в го́лову пришла́ одна́ иде́я.","b":1},{"t":"para","text":"Ý nghĩa: Chợt nghĩ ra, nảy ra ý tưởng."},{"t":"para","text":"Dịch: Tôi vừa nảy ra (ý tưởng đến vào đầu) một ý tưởng."},{"t":"example","text":"8. Он всегда́ гото́в прийти́ на по́мощь свои́м друзья́м.","b":1},{"t":"para","text":"Ý nghĩa: Giúp đỡ."},{"t":"para","text":"Dịch: Anh ấy luôn sẵn sàng đến giúp đỡ bạn bè mình."},{"t":"example","text":"9. Ты до́лжен прийти́ в себя́ и успоко́иться.","b":1},{"t":"para","text":"Ý nghĩa: Tỉnh táo lại, lấy lại bình tĩnh (sau cú sốc, ngất xỉu hoặc tức giận)."},{"t":"para","text":"Dịch: Bạn cần phải tỉnh táo lại (về lại với bản thân) và bình tĩnh đi."},{"t":"example","text":"10. Твоё легкомы́слие тебя́ к добру́ не доведёт.","b":1},{"t":"para","text":"Ý nghĩa: Sẽ dẫn đến hậu quả xấu."},{"t":"para","text":"Dịch: Tính nông nổi của cậu sẽ chẳng đi đến đâu tốt đẹp cả (không dẫn tới điều thiện)."},{"t":"example","text":"11. Не приведи́ бог роди́телям пережи́ть смерть свои́х дете́й.","b":1},{"t":"para","text":"Ý nghĩa: Cầu mong điều đó không xảy ra (Lạy Chúa đừng để...)."},{"t":"para","text":"Dịch: Lạy Chúa đừng để (Chúa không dẫn tới) cảnh cha mẹ phải chứng kiến cái chết của con cái."},{"t":"example","text":"12. Отку́да я зна́ю об э́том?! Соро́ка на хвосте́ принесла́!","b":1},{"t":"para","text":"Ý nghĩa: Nghe tin đồn, biết được tin tức nhưng không muốn lộ nguồn tin (như kiểu \"chim lợn mách\")."},{"t":"para","text":"Dịch: Sao tôi biết chuyện này à?! Có con chim chích nó mách lẻo đấy (chim ác là mang tin trên đuôi)!"},{"t":"example","text":"13. Ты всё вре́мя прино́сишь себя́ в же́ртву свои́м бли́зким, но никто́ э́того не це́нит.","b":1},{"t":"para","text":"Ý nghĩa: Hy sinh bản thân."},{"t":"para","text":"Dịch: Bạn lúc nào cũng hy sinh bản thân (mang mình làm vật tế) cho người thân, nhưng chẳng ai trân trọng điều đó cả."},{"t":"example","text":"14. Ду́маю, на э́тот раз тебе́ не уда́стся вы́йти сухи́м из воды́.","b":1},{"t":"para","text":"Ý nghĩa: Thoát tội, không bị trừng phạt dù có làm sai (như: \"ướt chân mà không ướt giày\")."},{"t":"para","text":"Dịch: Tôi nghĩ lần này cậu sẽ không thể trốn tội trót lọt (bước ra khỏi nước mà vẫn khô ráo) đâu."},{"t":"example","text":"15. Ро́стом он, коне́чно, не вы́шел, но ра́зве э́то в челове́ке гла́вное.","b":1},{"t":"para","text":"Ý nghĩa: Thấp bé, không cao lớn (nghĩa đen: không phát triển về chiều cao)."},{"t":"para","text":"Dịch: Dĩ nhiên là anh ấy không cao lớn gì (chiều cao không đạt), nhưng chẳng lẽ đó là điều quan trọng nhất ở một con người sao."},{"t":"example","text":"16. Твои́ де́йствия на э́тот раз вы́шли за преде́лы разу́много.","b":1},{"t":"para","text":"Ý nghĩa: Vượt quá giới hạn, quá trớn."},{"t":"para","text":"Dịch: Hành động của bạn lần này đã vượt quá giới hạn của sự hợp lý rồi."},{"t":"example","text":"17. Не выходи́ из себя́, тебе́ вре́дно волнова́ться.","b":1},{"t":"para","text":"Ý nghĩa: Đừng nổi nóng, đừng mất bình tĩnh."},{"t":"para","text":"Dịch: Đừng có nổi nóng (đừng bước ra khỏi bản thân), kích động không tốt cho bạn đâu."},{"t":"example","text":"18. Наде́юсь, ты смо́жешь вы́вести его́ на чи́стую во́ду.","b":1},{"t":"para","text":"Ý nghĩa: Vạch trần sự thật, bóc trần bộ mặt thật của ai đó."},{"t":"para","text":"Dịch: Hy vọng cậu sẽ có thể vạch trần bộ mặt thật (dẫn hắn ra vùng nước sạch) của hắn ta."},{"t":"example","text":"19. Коне́чно, сейча́с он не ду́мает о после́дствиях, но в бу́дущем его́ поведе́ние вы́йдет ему́ бо́ком.","b":1},{"t":"para","text":"Ý nghĩa: Gây ra hậu quả xấu cho chính mình (gậy ông đập lưng ông)."},{"t":"para","text":"Dịch: Tất nhiên, bây giờ nó không nghĩ đến hậu quả, nhưng trong tương lai hành vi đó sẽ làm hại chính nó (trồi ra ở hông/gây rắc rối)."},{"t":"example","text":"20. С таки́ми оце́нками далеко́ не уе́дешь.","b":1},{"t":"para","text":"Ý nghĩa: Không thể tiến xa, không đạt được thành tựu gì."},{"t":"para","text":"Dịch: Với những điểm số như thế thì chẳng tiến xa được đâu."},{"t":"vocab","ru":"Бо́же мой, как ты меня́ напуга́л","vi":"у меня́ душа́ ушла́ в пя́тки.","g":null},{"t":"para","text":"Ý nghĩa: Sợ chết khiếp, sợ đến mức tim rớt ra ngoài."},{"t":"para","text":"Dịch: Trời ơi, cậu làm tớ sợ quá: hồn vía lên mây (linh hồn chui xuống gót chân) rồi này."},{"t":"example","text":"22. Пото́м они́ все вме́сте на меня́ набро́сились и ста́ли меня́ воспи́тывать, е́ле но́ги унёс.","b":1},{"t":"para","text":"Ý nghĩa: Suýt thì không thoát được, vất vả lắm mới trốn thoát."},{"t":"para","text":"Dịch: Sau đó tất cả bọn họ xông vào tôi và bắt đầu \"dạy dỗ\" tôi, tôi phải vất vả lắm mới chạy thoát thân (mới mang được đôi chân đi)."}]},{"id":"07-s124","type":"exercise","title":"Bài 623 (Trang 331)","num":623,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками в-, вы-, при-, у-, к вы́деленным слова́м и словосочета́ниям подбери́те сино́нимы. (Sử dụng các cụm từ cố định với động từ chuyển động có tiền tố в-, вы-, при-, у-, hãy chọn từ đồng nghĩa cho các từ và cụm từ được in đậm)."},{"t":"example","text":"1. Е́сли ты бу́дешь рабо́тать, как ра́ньше, мно́гого не добьёшься.","b":1},{"t":"subhead","text":"Đáp án: далеко́ не уе́дешь","b":1},{"t":"para","text":"Dịch: Nếu bạn cứ làm việc như trước, thì chẳng tiến xa được đâu."},{"t":"vocab","ru":"Ему́ уже́ давно́ всё изве́стно о на́шем реше́нии","vi":"кто-то ему́ сказа́л.","g":null},{"t":"subhead","text":"Đáp án: соро́ка на хвосте́ принесла́","b":1},{"t":"para","text":"Dịch: Anh ta đã biết hết về quyết định của chúng ta từ lâu rồi: có kẻ mách lẻo (chim ác là mang tin đến)."},{"t":"example","text":"3. Свои́ми слова́ми о до́лге и со́вести он заста́вил его́ покрасне́ть.","b":1},{"t":"subhead","text":"Đáp án: вогна́л его́ в кра́ску","b":1},{"t":"para","text":"Dịch: Bằng những lời nói về bổn phận và lương tâm, ông ấy đã làm anh ta đỏ mặt tía tai (ngượng chín mặt)."},{"t":"example","text":"4. Ду́маю, тебе́ бу́дет тру́дно доби́ться его́ расположе́ния.","b":1},{"t":"subhead","text":"Đáp án: войти́ к нему́ в дове́рие","b":1},{"t":"para","text":"Dịch: Tôi nghĩ bạn sẽ khó mà chiếm được lòng tin của ông ấy."},{"t":"example","text":"5. Кра́йне нежела́тельно, что́бы река́ во вре́мя наводне́ния затопи́ла берега́.","b":1},{"t":"subhead","text":"Đáp án: вы́шла из берего́в","b":1},{"t":"para","text":"Dịch: Cực kỳ không mong muốn việc con sông trong đợt lũ lụt tràn bờ (vỡ đê)."},{"t":"example","text":"6. Ра́ди тако́го слу́чая ты мо́жешь заня́ть де́нег у друзе́й.","b":1},{"t":"subhead","text":"Đáp án: влезть в долги́","b":1},{"t":"para","text":"Dịch: Vì dịp như thế này, bạn có thể vay mượn (mắc nợ) bạn bè."},{"t":"example","text":"7. Когда́ неожи́данно пога́с свет, я о́чень испуга́лся.","b":1},{"t":"subhead","text":"Đáp án: у меня́ душа́ ушла́ в пя́тки","b":1},{"t":"para","text":"Dịch: Khi đèn đột ngột tắt, tôi sợ chết khiếp (hồn vía lên mây)."},{"t":"example","text":"8. Э́та исто́рия для него́ пло́хо ко́нчится.","b":1},{"t":"subhead","text":"Đáp án: вы́йдет бо́ком","b":1},{"t":"para","text":"Dịch: Câu chuyện này sẽ gây hậu quả xấu (đem lại rắc rối) cho hắn ta."},{"t":"example","text":"9. Рабо́тали мы снача́ла неохо́тно, но незаме́тно для себя́ осво́ились и да́же ста́ли получа́ть от своего́ труда́ удово́льствие.","b":1},{"t":"subhead","text":"Đáp án: вошли́ во вкус","b":1},{"t":"para","text":"Dịch: Ban đầu chúng tôi làm việc miễn cưỡng, nhưng rồi không biết từ lúc nào đã bắt đầu thấy hứng thú (vào guồng/thấy hay)."},{"t":"example","text":"10. Твоё легкомы́сленное поведе́ние на доро́гах ниче́м хоро́шим для тебя́ не ко́нчится.","b":1},{"t":"subhead","text":"Đáp án: до добра́ не доведёт","b":1},{"t":"para","text":"Dịch: Thói hành xử nông nổi của bạn trên đường sẽ chẳng dẫn đến điều gì tốt đẹp đâu."},{"t":"example","text":"11. Нам на́до его́ разоблачи́ть.","b":1},{"t":"subhead","text":"Đáp án: вы́вести на чи́стую во́ду","b":1},{"t":"para","text":"Dịch: Chúng ta cần phải vạch trần bộ mặt thật của hắn."},{"t":"example","text":"12. Постара́йся поня́ть и прости́ть меня́.","b":1},{"t":"subhead","text":"Đáp án: войти́ в (моё) положе́ние","b":1},{"t":"para","text":"Dịch: Hãy cố gắng đặt mình vào hoàn cảnh của tôi (thông cảm cho tôi)."},{"t":"example","text":"13. Нельзя́ всё вре́мя из-за рабо́ты отка́зываться от о́тдыха вме́сте с семьёй.","b":1},{"t":"subhead","text":"Đáp án: приноси́ть себя́ в же́ртву","b":1},{"t":"para","text":"Dịch: Không thể lúc nào cũng hy sinh bản thân vì công việc mà bỏ bê nghỉ ngơi cùng gia đình."},{"t":"example","text":"14. Успоко́йся, не на́до так волнова́ться.","b":1},{"t":"subhead","text":"Đáp án: не выходи́ из себя́ / приди́ в себя́","b":1},{"t":"para","text":"Dịch: Bình tĩnh đi, đừng có mất bình tĩnh / hãy trấn tĩnh lại."},{"t":"example","text":"15. Пото́м они́ на́чали выража́ть своё недово́льствие мое́й рабо́той, и я чу́дом спасся.","b":1},{"t":"subhead","text":"Đáp án: е́ле но́ги унёс","b":1},{"t":"para","text":"Dịch: Sau đó họ bắt đầu tỏ vẻ không hài lòng với công việc của tôi, và tôi phải vất vả lắm mới thoát thân được."},{"t":"example","text":"16. Я уве́рен, ему́ не уда́стся оста́ться безнака́занным.","b":1},{"t":"subhead","text":"Đáp án: вы́йти сухи́м из воды́","b":1},{"t":"para","text":"Dịch: Tôi tin là hắn sẽ không thể thoát tội trót lọt (bình an vô sự) đâu."},{"t":"example","text":"17. Да что говори́ть, лицо́м он не удался́.","b":1},{"t":"subhead","text":"Đáp án: лицо́м он не вы́шел","b":1},{"t":"example","text":"Dịch: Còn nói gì nữa, anh ta nhan sắc thì kém (không đẹp trai). (Lưu ý: \"не вышел\" ở đây dùng cho ngoại hình, nghĩa là không được ưu tú về mặt đó)."},{"t":"example","text":"18. Я хочу́ разъясни́ть тебе́ сложи́вшееся положе́ние.","b":1},{"t":"subhead","text":"Đáp án: внести́ я́сность в","b":1},{"t":"para","text":"Dịch: Tôi muốn làm sáng tỏ tình hình hiện tại cho bạn."},{"t":"example","text":"19. На э́тот раз ты преступи́л черту́ дозво́ленного и тебе́ придётся отвеча́ть за свои́ посту́пки.","b":1},{"t":"subhead","text":"Đáp án: вы́шел за преде́лы / ра́мки","b":1},{"t":"para","text":"Dịch: Lần này cậu đã vượt quá giới hạn cho phép và cậu sẽ phải chịu trách nhiệm cho hành động của mình."},{"t":"example","text":"20. По э́тому по́воду у меня́ возни́кла одна́ мысль.","b":1},{"t":"subhead","text":"Đáp án: пришла́ в го́лову одна́ мысль / иде́я","b":1},{"t":"para","text":"Dịch: Về vụ này, tôi vừa nảy ra (trong đầu đến) một ý tưởng."},{"t":"example","text":"21. Снача́ла бы́ло тру́дно, но пото́м друзья́ помогли́ мне.","b":1},{"t":"subhead","text":"Đáp án: пришли́ мне на по́мощь","b":1},{"t":"para","text":"Dịch: Ban đầu thì khó khăn, nhưng sau đó bạn bè đã đến giúp đỡ tôi."}]},{"id":"07-s125","type":"exercise","title":"Bài 624 (Trang 331)","num":624,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте необходи́мые по смы́слу глаго́лы движе́ния с приста́вками в- (во-), при-, вы-, у- и́ли с-. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Thay dấu ba chấm bằng các động từ chuyển động cần thiết theo ý nghĩa với các tiền tố: в- (во-), при-, вы-, у- hoặc с-. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"note","text":"Lưu ý: Đây là một đoạn văn kể chuyện, nên các động từ cần phù hợp với ngữ cảnh liên kết."},{"t":"para","text":"1. Ве́чером я сообщи́ла свои́м друзья́м о том, что за́втра мы с роди́телями на неде́лю ... на мо́ре.","b":1},{"t":"subhead","text":"Đáp án: уе́дем (từ е́хать)"},{"t":"para","text":"Dịch: Buổi tối tôi báo cho bạn bè biết rằng ngày mai tôi và bố mẹ sẽ rời đi (đi vắng) biển một tuần."},{"t":"example","text":"Giải thích: Nhấn mạnh vào việc rời khỏi nơi cư trú trong một khoảng thời gian → dùng tiền tố у-. (Có thể dùng пое́дем - sẽ đi, nhưng đề bài không cho tiền tố по-)."},{"t":"para","text":"2. С утра́ мы ... из до́ма ве́щи, кото́рые должны́ бы́ли взять с собо́й, и укла́дывали их в маши́ну.","b":1},{"t":"subhead","text":"Đáp án: выноси́ли (từ носи́ть)"},{"t":"para","text":"Dịch: Từ sáng, chúng tôi đã mang (khuân) đồ đạc cần mang theo ra khỏi nhà và xếp vào xe hơi."},{"t":"example","text":"Giải thích: Mang từ trong nhà ra ngoài → tiền tố вы-. Dùng thể chưa hoàn thành (выноси́ли) để chỉ quá trình diễn ra liên tục/lặp lại vào buổi sáng cùng với hành động \"xếp đồ\" (укла́дывали)."},{"t":"para","text":"3. К сча́стью, ма́ма во́время заме́тила, как в бага́жник маши́ны ... на́ша ко́шка, за кото́рой на вре́мя на́шего отсу́тствия мы попроси́ли пригляде́ть сосе́дей.","b":1},{"t":"subhead","text":"Đáp án: вле́зла (từ лезть)"},{"t":"para","text":"Dịch: May thay, mẹ kịp thời nhận thấy con mèo nhà tôi, con mà chúng tôi đã nhờ hàng xóm trông hộ lúc vắng nhà, đã chui tọt (leo) vào cốp xe."},{"t":"example","text":"Giải thích: Chuyển động vào bên trong không gian hẹp/kín → tiền tố в-. Hành động đã xảy ra nhanh gọn → вле́зла."},{"t":"para","text":"4. Я ... ко́шку и ... её в дом.","b":1},{"t":"subhead","text":"Đáp án: вы́тащила (từ тащи́ть); внесла́ (từ нести́) hoặc унесла́."},{"t":"para","text":"Dịch: Tôi lôi con mèo ra và mang nó vào nhà."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Lôi ra khỏi cốp → вы́тащила (hoặc вы́нула - nhưng sách yêu cầu động từ chuyển động, тащить hợp lý với việc lôi con vật)."},{"t":"example","text":"Mang vào trong nhà → внесла́. (Hoặc унесла - mang đi chỗ khác)."},{"t":"para","text":"5. Когда́ мы наконе́ц ... из до́ма, на у́лице свети́ло со́лнце.","b":1},{"t":"subhead","text":"Đáp án: вы́ехали (từ е́хать)"},{"t":"para","text":"Dịch: Khi cuối cùng chúng tôi rời (lái xe ra) khỏi nhà, ngoài trời nắng đẹp."},{"t":"example","text":"Giải thích: Rời khỏi địa điểm bằng phương tiện → вы́ехали."},{"t":"para","text":"6. Но ско́ро ве́тер ... ту́чи и пошёл дождь.","b":1},{"t":"subhead","text":"Đáp án: пригна́л (từ гнать)"},{"t":"para","text":"Dịch: Nhưng chẳng bao lâu gió đã lùa (thổi) mây đến và trời đổ mưa."},{"t":"example","text":"Giải thích: Gió lùa mây đến địa điểm người nói → пригна́л."},{"t":"para","text":"7. Из-за дождя́ мы дви́гались о́чень ме́дленно, пока́ не ... на шоссе́.","b":1},{"t":"subhead","text":"Đáp án: вы́ехали (từ е́хать)"},{"t":"para","text":"Dịch: Do trời mưa, chúng tôi di chuyển rất chậm cho đến khi lái xe ra (tiến ra) đường cao tốc."},{"t":"example","text":"Giải thích: Đi từ đường nhỏ/nội bộ ra đường lớn → вы́ехали."},{"t":"para","text":"8. На маши́не нам от побере́жья добира́ться часо́в во́семь, и поэ́тому мы плани́ровали ... туда́ то́лько к ве́черу.","b":1},{"t":"subhead","text":"Đáp án: прие́хать (từ е́хать)"},{"t":"para","text":"Dịch: Chúng tôi phải đi xe mất 8 tiếng mới tới bờ biển, nên chúng tôi dự định chỉ đến đó vào buổi tối."},{"t":"example","text":"Giải thích: Đến đích → прие́хать."},{"t":"para","text":"9. Са́мым тру́дным был путь, проходя́щий по го́рному перева́лу. Снача́ла мы ... на го́ру, а пото́м ... вниз.","b":1},{"t":"subhead","text":"Đáp án: въезжа́ли (từ е́здить); съезжа́ли (từ е́здить) hoặc cặp hoàn thành въе́хали / съе́хали."},{"t":"para","text":"Dịch: Khó khăn nhất là đoạn đường qua đèo. Đầu tiên chúng tôi xe lên núi, rồi sau đó xe xuống."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Lên trên bề mặt/lên dốc → въ- (въезжали)."},{"t":"example","text":"Xuống dưới/xuống dốc → с- (съезжали). Dùng thể chưa hoàn thành để miêu tả quá trình leo đèo."},{"t":"para","text":"10. ..., из тунне́ля, мы уви́дели чуде́сный пейза́ж.","b":1},{"t":"subhead","text":"Đáp án: Вы́ехав (Trạng động từ của вы́ехать)"},{"t":"para","text":"Dịch: (Sau khi) xe ra khỏi đường hầm, chúng tôi nhìn thấy một phong cảnh tuyệt đẹp."},{"t":"example","text":"Giải thích: Câu này khuyết chủ ngữ ở vế đầu, cấu trúc phù hợp nhất là dùng Trạng động từ (Деепричастие) để chỉ hành động phụ của chủ ngữ \"мы\". Ra khỏi không gian kín → вы-."},{"t":"para","text":"11. Мы ... с доро́ги, и я ... из маши́ны, что́бы сде́лать как мо́жно бо́льше фотогра́фий, пока́ не потемне́ло.","b":1},{"t":"subhead","text":"Đáp án: съе́хали (từ е́хать); вы́шел (từ идти́)"},{"t":"para","text":"Dịch: Chúng tôi tách (lệch) khỏi đường chính (tấp vào lề), và tôi bước ra khỏi xe để chụp càng nhiều ảnh càng tốt trước khi trời tối."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Rời khỏi bề mặt đường/làn đường → съе́хали."},{"t":"example","text":"Bước từ trong xe ra ngoài → вы́шел."},{"t":"para","text":"12. Доро́га проходи́ла ме́жду го́рными верши́нами, вокру́г никого́ не́ было, то́лько иногда́ из придоро́жных кусто́в ... пти́цы, потрево́женные шу́мом маши́н.","b":1},{"t":"subhead","text":"Đáp án: вылета́ли (từ лета́ть)"},{"t":"para","text":"Dịch: Con đường chạy giữa các đỉnh núi, xung quanh không một bóng người, chỉ thi thoảng lũ chim bị tiếng xe làm động bay vụt ra từ những bụi cây ven đường."},{"t":"example","text":"Giải thích: Bay từ trong ra ngoài → вы-. Hành động lặp lại nhiều lần (иногда) → вылета́ли (chưa hoàn thành)."},{"t":"para","text":"13. Мы ... из до́ма на неде́лю, и ма́ма всю доро́гу беспоко́илась о на́шей ко́шке, кото́рая никогда́ ра́ньше не остава́лась одна́.","b":1},{"t":"subhead","text":"Đáp án: уе́хали (từ е́хать)"},{"t":"para","text":"Dịch: Chúng tôi đã đi (rời) khỏi nhà (để đi vắng) một tuần, và mẹ suốt dọc đường cứ lo cho con mèo chưa bao giờ phải ở một mình."},{"t":"example","text":"Giải thích: Nhấn mạnh việc rời đi xa/vắng mặt → уе́хали."},{"t":"para","text":"14. Ма́ма боя́лась, что ко́шка ... из до́ма.","b":1},{"t":"subhead","text":"Đáp án: убежи́т (từ бежа́ть) hoặc уйдёт."},{"t":"para","text":"Dịch: Mẹ sợ rằng con mèo sẽ bỏ (chạy) nhà đi mất."},{"t":"example","text":"Giải thích: Rời bỏ nơi ở → убежи́т/уйдёт."},{"t":"para","text":"15. Мы её успока́ивали, как могли́. Наконе́ц мы ... в гости́ницу. Не́сколько челове́к ... нас встреча́ть.","b":1},{"t":"subhead","text":"Đáp án: прие́хали (từ е́хать); вы́шли (từ идти́)"},{"t":"para","text":"Dịch: Chúng tôi an ủi mẹ hết mức có thể. Cuối cùng chúng tôi cũng đến khách sạn. Vài người bước ra đón chúng tôi."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Đến đích → прие́хали."},{"t":"example","text":"Từ trong khách sạn đi ra → вы́шли."},{"t":"para","text":"16. Мы поста́вили маши́ну в гара́ж и ... в гости́ницу. Кани́кулы начали́сь!","b":1},{"t":"subhead","text":"Đáp án: вошли́ (từ идти́)"},{"t":"para","text":"Dịch: Chúng tôi cất xe vào gara và bước vào khách sạn. Kỳ nghỉ bắt đầu!"},{"t":"example","text":"Giải thích: Đi từ ngoài vào trong → вошли́."},{"t":"para","text":"Глаго́лы движе́ния с приста́вками по-, до-; про-","b":1},{"t":"example","text":"(Động từ chuyển động với tiền tố po-, do-; pro-)"},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 332):","b":1},{"t":"subhead","text":"1. Tiền tố ПО-:","b":1},{"t":"vocab","ru":"Với động từ một chiều (идти, бежать...)","vi":"Tạo thành động từ Hoàn thành thể mang nghĩa bắt đầu chuyển động (khởi hành).","g":null},{"t":"example","text":"Ví dụ: пошёл (đã bắt đầu đi/đã đi), пое́хал (đã bắt đầu đi xe)."},{"t":"vocab","ru":"Với động từ đa chiều (ходить, бегать...)","vi":"Tạo thành động từ Hoàn thành thể mang nghĩa hành động diễn ra trong một khoảng thời gian ngắn (làm một chút rồi thôi).","g":null},{"t":"example","text":"Ví dụ: походи́л (đi bộ một lúc), побе́гал (chạy chơi một lúc)."},{"t":"subhead","text":"2. Tiền tố ДО-:","b":1},{"t":"example","text":"Mang nghĩa đạt tới đích/giới hạn (thường đi với giới từ до)."},{"t":"example","text":"Ví dụ: дойти́ до до́ма (đi đến tận nhà)."},{"t":"subhead","text":"3. Tiền tố ПРО-:","b":1},{"t":"para","text":"Mang nghĩa băng qua, đi qua (khoảng cách, vật cản) hoặc đi ngang qua."},{"t":"example","text":"Ví dụ: пройти́ че́рез лес (đi xuyên qua rừng), прое́хать ми́мо (lái xe ngang qua)."}]},{"id":"07-s126","type":"exercise","title":"Bài 625 (Trang 332)","num":625,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложе́ния. Определи́те значе́ние вы́деленных глаго́лов движе́ния с приста́вками. Назови́те инфинити́вы, от кото́рых они́ образо́ваны. (Đọc các câu. Xác định ý nghĩa của các động từ chuyển động có tiền tố được in đậm. Gọi tên động từ nguyên mẫu mà từ đó chúng được tạo thành)."},{"t":"para","text":"a) Tiền tố ПО- (Bắt đầu đi / Đi một lúc)","b":1},{"t":"example","text":"1. Спекта́кль зако́нчился, и мы пошли́ домо́й. Снача́ла я походи́л по па́рку, а пото́м спусти́лся к реке́.","b":1},{"t":"vocab","ru":"пошли́ (từ идти́ - một chiều)","vi":"Nghĩa là bắt đầu đi/khởi hành về nhà.","g":null},{"t":"example","text":"Dịch: Vở kịch kết thúc và chúng tôi ra về."},{"t":"vocab","ru":"походи́л (từ ходи́ть - đa chiều)","vi":"Nghĩa là đi dạo một lúc (hành động ngắn hạn).","g":null},{"t":"example","text":"Dịch: Lúc đầu tôi đi dạo một lát trong công viên, rồi sau đó xuống bờ sông."},{"t":"example","text":"2. Ребёнок вы́рвался из рук ня́ни и побежа́л к ма́тери. Ты мо́жешь побе́гать с друзья́ми, то́лько не уходи́ далеко́.","b":1},{"t":"vocab","ru":"побежа́л (từ бежа́ть - một chiều)","vi":"Nghĩa là bắt đầu chạy (lao tới).","g":null},{"t":"example","text":"Dịch: Đứa bé vùng khỏi tay bảo mẫu và chạy vụt về phía mẹ."},{"t":"vocab","ru":"побе́гать (từ бе́гать - đa chiều)","vi":"Nghĩa là chạy nhảy/chơi đùa một lúc.","g":null},{"t":"example","text":"Dịch: Con có thể chạy chơi một lát với bạn bè, nhưng đừng đi xa nhé."},{"t":"example","text":"3. Мне ка́жется, он понёс заслу́женное наказа́ние за своё легкомы́слие. Отда́й мне тяжёлую су́мку: поноси́л немно́го и хва́тит.","b":1},{"t":"vocab","ru":"понёс (từ нести́ - một chiều)","vi":"Nghĩa bóng gánh chịu/chịu đựng (bắt đầu chịu hậu quả).","g":null},{"t":"example","text":"Dịch: Tôi thấy anh ta đã phải chịu hình phạt xứng đáng cho sự nông nổi của mình."},{"t":"vocab","ru":"поноси́л (từ носи́ть - đa chiều)","vi":"Nghĩa là xách/mang một lúc.","g":null},{"t":"example","text":"Dịch: Đưa cái túi nặng đây cho tôi: bạn xách một lúc thế là đủ rồi."},{"t":"example","text":"4. Заче́м ты поле́з в э́то де́ло? Сра́зу бы́ло я́сно, что ниче́м хоро́шим оно́ не зако́нчится. Медвежо́нок немно́го пола́зал по дере́вьям, а пото́м спусти́лся на зе́млю.","b":1},{"t":"vocab","ru":"поле́з (từ лезть - một chiều)","vi":"Nghĩa bóng xen vào/dính líu vào (bắt đầu hành động).","g":null},{"t":"example","text":"Dịch: Sao cậu lại dính mũi (chui) vào vụ này làm gì? Ngay từ đầu đã rõ là nó chẳng kết thúc tốt đẹp đâu."},{"t":"vocab","ru":"пола́зал (từ ла́зить - đa chiều)","vi":"Nghĩa là leo trèo một lúc.","g":null},{"t":"example","text":"Dịch: Chú gấu con leo trèo cây một lúc, rồi tụt xuống đất."},{"t":"para","text":"b) Tiền tố ДО- (Đến tận nơi)","b":1},{"t":"example","text":"1. До дере́вни мы дошли́ то́лько ве́чером. Во вре́мя наводне́ния вода́ здесь доходи́ла до ближа́йших домо́в.","b":1},{"t":"vocab","ru":"дошли́ (từ идти́)","vi":"Hoàn thành thể. Nghĩa là đã đi đến nơi/đạt tới đích.","g":null},{"t":"example","text":"Dịch: Mãi đến tối chúng tôi mới đi (bộ) đến làng."},{"t":"vocab","ru":"доходи́ла (từ ходи́ть)","vi":"Chưa hoàn thành thể (gốc đa chiều + tiền tố). Nghĩa là dâng tới/lan tới (chỉ giới hạn không gian hoặc quá trình).","g":null},{"t":"example","text":"Dịch: Trong trận lụt, nước ở đây dâng tới tận những ngôi nhà gần nhất."},{"t":"example","text":"2. Не волну́йся, я довезу́ тебя́ до са́мого общежи́тия. В на́шем го́роде на́чали рабо́тать но́вые маршру́тные такси́, кото́рые дви́гаются по ра́зным направле́ниям и дово́зят пассажи́ров до са́мого до́ма.","b":1},{"t":"vocab","ru":"довезу́ (từ везти́)","vi":"Hoàn thành thể (gốc một chiều). Nghĩa là sẽ chở đến tận nơi.","g":null},{"t":"example","text":"Dịch: Đừng lo, tớ sẽ chở cậu đến tận ký túc xá."},{"t":"vocab","ru":"дово́зят (từ вози́ть)","vi":"Chưa hoàn thành thể (gốc đa chiều). Nghĩa là chở đến (thói quen/chức năng).","g":null},{"t":"example","text":"Dịch: Thành phố ta đã bắt đầu có xe taxi tuyến mới, chạy theo các hướng khác nhau và đưa (chở) khách về tận nhà."},{"t":"example","text":"3. Не могли́ бы вы довести́ меня́ до гости́ницы, я пло́хо ориенти́руюсь в э́том го́роде. Он привы́к любо́е де́ло доводи́ть до конца́.","b":1},{"t":"vocab","ru":"довести́ (từ вести́)","vi":"Hoàn thành thể. Nghĩa là dẫn đến tận nơi.","g":null},{"t":"example","text":"Dịch: Ông có thể làm ơn dẫn tôi đến khách sạn được không, tôi không rành đường thành phố này lắm."},{"t":"vocab","ru":"доводи́ть (từ води́ть)","vi":"Chưa hoàn thành thể. Nghĩa bóng làm cho tới nơi tới chốn/hoàn thành.","g":null},{"t":"example","text":"Dịch: Anh ấy quen việc gì cũng làm (dẫn dắt) cho đến cùng (hoàn tất)."},{"t":"example","text":"4. Я догна́л его́ уже́ на ле́стнице. Нет ничего́ ху́же, чем ждать и догоня́ть.","b":1},{"t":"vocab","ru":"догна́л (từ гнать)","vi":"Hoàn thành thể. Nghĩa là đuổi kịp/bắt kịp.","g":null},{"t":"example","text":"Dịch: Tôi đã đuổi kịp cậu ấy ngay trên cầu thang."},{"t":"vocab","ru":"догоня́ть (từ гоня́ть)","vi":"Chưa hoàn thành thể. Nghĩa là đuổi theo/phải chạy theo (để bắt kịp).","g":null},{"t":"example","text":"Dịch: Chẳng có gì tệ hơn là phải chờ đợi và phải chạy đuổi theo (ý nói lỡ việc phải cố vớt vát)."}]},{"id":"07-s127","type":"exercise","title":"Bài 626 (Trang 333)","num":626,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя нужную форму глагола движения с приставкой по-, вы- или у-. Объясните ваш выбор. Укажите варианты. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ chuyển động với tiền tố по-, вы- hoặc у-. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"subhead","text":"Gợi ý ngữ pháp trong khung (Trang 333):","b":1},{"t":"example","text":"Tiếng Nga: Глаголы движения с приставкой по- обозначают начало движения: Я пошёл в магазин (начал идти). В будущем времени глаголы движения с приставкой по- в значении «начать движение» употребляются как синонимы глаголов движения с приставкой по- в значении «совершить движение». Сравните: Завтра я иду (пойду) в театр."},{"t":"example","text":"Dịch & Giải thích: Động từ chuyển động với tiền tố по- biểu thị sự bắt đầu chuyển động: Tôi đã đi cửa hàng (đã bắt đầu đi). Ở thì tương lai, động từ chuyển động với tiền tố по- mang nghĩa \"bắt đầu chuyển động\" được dùng như từ đồng nghĩa với động từ mang nghĩa \"thực hiện chuyển động\" (sẽ đi). So sánh: Ngày mai tôi đi (sẽ đi) nhà hát."},{"t":"vocab","ru":"По-","vi":"Bắt đầu đi / Sẽ đi.","g":null},{"t":"vocab","ru":"Вы-","vi":"Đi ra khỏi.","g":null},{"t":"vocab","ru":"У-","vi":"Rời đi, đi mất (vắng mặt).","g":null},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"1. У́тром я (идти́/ходи́ть) в университе́т, а по́сле заня́тий бу́ду рабо́тать в библиоте́ке.","b":1},{"t":"subhead","text":"Đáp án: пойду́ (tương lai đơn của идти́ + по-)."},{"t":"para","text":"Dịch: Sáng nay tôi sẽ đi đến trường đại học, còn sau giờ học tôi sẽ làm việc ở thư viện."},{"t":"example","text":"Giải thích: Kế hoạch trong tương lai, dùng пойду để chỉ hành động sẽ di chuyển đến đó."},{"t":"para","text":"2. Когда́ мы наконе́ц (е́хать/е́здить) на шоссе́, моё настрое́ние заме́тно улу́чшилось.","b":1},{"t":"subhead","text":"Đáp án: вы́ехали (quá khứ của е́хать + вы-)."},{"t":"para","text":"Dịch: Khi cuối cùng chúng tôi lái xe ra đường cao tốc, tâm trạng tôi tốt lên trông thấy."},{"t":"example","text":"Giải thích: Di chuyển từ đường nhỏ/nội bộ ra đường lớn → dùng tiền tố вы- (ra)."},{"t":"para","text":"3. Он попроща́лся со мной и ме́дленно (брести́/броди́ть) вниз по у́лице.","b":1},{"t":"subhead","text":"Đáp án: побрёл (quá khứ của брести́ + по-)."},{"t":"para","text":"Dịch: Anh ấy chào tạm biệt tôi và chậm chạp lê bước (bắt đầu lê bước) xuống phố."},{"t":"example","text":"Giải thích: Bắt đầu hành động di chuyển rời đi sau khi chào → dùng по-."},{"t":"para","text":"4. Вчера́ ве́чером по́сле рабо́ты он (идти́/ходи́ть) и (нести́/носи́ть) все докуме́нты с собо́й.","b":1},{"t":"subhead","text":"Đáp án: ушёл; унёс."},{"t":"para","text":"Dịch: Tối qua sau giờ làm việc anh ấy đã về (rời đi) và mang tất cả tài liệu đi theo."},{"t":"example","text":"Giải thích: Rời khỏi chỗ làm và mang đồ đi mất → dùng tiền tố у-."},{"t":"para","text":"5. Я сел в маши́ну, захло́пнул за собо́й дверь, и мы (е́хать/е́здить).","b":1},{"t":"subhead","text":"Đáp án: пое́хали."},{"t":"para","text":"Dịch: Tôi ngồi vào xe, đóng sập cửa lại, và chúng tôi bắt đầu đi (lăn bánh)."},{"t":"example","text":"Giải thích: Thời điểm bắt đầu chuyển động → dùng по-."},{"t":"para","text":"6. В понеде́льник я (вести́/води́ть) дете́й в зоопа́рк.","b":1},{"t":"subhead","text":"Đáp án: поведу́ (hoặc ведук nếu đã lên lịch chắc chắn, nhưng bài yêu cầu tiền tố nên dùng поведу)."},{"t":"para","text":"Dịch: Thứ hai tôi sẽ dẫn bọn trẻ đi sở thú."},{"t":"example","text":"Giải thích: Dự định trong tương lai → по- + веду."},{"t":"para","text":"7. Она́ была́ здесь до обе́да, а пото́м (идти́/ходи́ть) и вряд ли сего́дня вернётся.","b":1},{"t":"subhead","text":"Đáp án: ушла́."},{"t":"para","text":"Dịch: Cô ấy đã ở đây trước bữa trưa, nhưng sau đó đã đi khỏi (về) và khó có thể quay lại hôm nay."},{"t":"example","text":"Giải thích: Rời đi và không còn ở đó nữa → dùng tiền tố у-."},{"t":"para","text":"8. На э́ти выходны́е мне наконе́ц удало́сь (везти́/вози́ть) всю семью́ за́ город.","b":1},{"t":"subhead","text":"Đáp án: вы́везти."},{"t":"para","text":"Dịch: Cuối tuần này cuối cùng tôi cũng đã có thể đưa (chở) cả nhà ra ngoại ô."},{"t":"example","text":"Giải thích: Đưa từ trong thành phố ra ngoài (ngoại ô) → dùng tiền tố вы-."},{"t":"para","text":"9. Соба́ка останови́лась, помаха́ла хвосто́м и (бежа́ть/бе́гать) вниз по у́лице.","b":1},{"t":"subhead","text":"Đáp án: побежа́ла."},{"t":"para","text":"Dịch: Con chó dừng lại, vẫy đuôi rồi chạy vụt xuống phố."},{"t":"example","text":"Giải thích: Bắt đầu hành động chạy sau khi dừng lại → dùng по-."},{"t":"para","text":"10. Останови́сь! Куда́ ты (нести́/носи́ть) мой чемода́н?","b":1},{"t":"subhead","text":"Đáp án: уно́сишь (hoặc несёшь nhưng bài yêu cầu tiền tố thì уносишь hợp lý với nghĩa \"mang đi đâu mất\")."},{"t":"note","text":"Lưu ý: Sách đáp án thường dùng уносишь (đang mang đi xa khỏi người nói) hoặc потащил (đã bắt đầu kéo đi - nhưng câu này ở hiện tại)."},{"t":"vocab","ru":"Nếu chọn по-","vi":"понес (đã mang đi) - không hợp ngữ cảnh \"đang mang\" (present).","g":null},{"t":"subhead","text":"Đáp án hợp lý nhất: уно́сишь (Bạn đang mang vali của tôi đi đâu đấy / đi mất đấy?)."},{"t":"para","text":"Dịch: Dừng lại! Bạn đang mang vali của tôi đi đâu đấy?"},{"t":"para","text":"11. Подожди́те, пожа́луйста, она́ на мину́ту (идти́/ходи́ть).","b":1},{"t":"subhead","text":"Đáp án: вы́шла."},{"t":"para","text":"Dịch: Xin vui lòng đợi một chút, cô ấy vừa ra ngoài một phút thôi."},{"t":"example","text":"Giải thích: Rời khỏi phòng trong thời gian ngắn → dùng вы́шла."},{"t":"para","text":"12. Где-то на середи́не реки́ он пры́гнул в во́ду и (плыть/пла́вать) к бе́регу.","b":1},{"t":"subhead","text":"Đáp án: поплы́л."},{"t":"para","text":"Dịch: Đâu đó giữa dòng sông cậu ấy nhảy xuống nước và bắt đầu bơi vào bờ."},{"t":"example","text":"Giải thích: Bắt đầu hành động bơi về hướng đích → dùng по-."},{"t":"para","text":"13. Налете́л ве́тер, ни́зкие облака́ (ползти́/по́лзать) по не́бу, приближа́лась гроза́.","b":1},{"t":"subhead","text":"Đáp án: поползли́."},{"t":"para","text":"Dịch: Gió ập đến, những đám mây thấp bắt đầu trườn (bò) trên bầu trời, cơn dông đang đến gần."},{"t":"example","text":"Giải thích: Mây bắt đầu di chuyển → dùng по-."},{"t":"para","text":"14. По́сле оконча́ния шко́лы она́ (е́хать/е́здить) в друго́й го́род поступа́ть в институ́т.","b":1},{"t":"subhead","text":"Đáp án: уе́хала (hoặc пое́хала)."},{"t":"para","text":"Dịch: Sau khi tốt nghiệp phổ thông, cô ấy đã rời đi sang thành phố khác để thi đại học."},{"t":"example","text":"Giải thích: Rời bỏ nơi cũ → уе́хала. Hoặc bắt đầu chuyến đi → пое́хала. Уехала nhấn mạnh sự vắng mặt ở nơi cũ."},{"t":"para","text":"15. Он (тащи́ть/таска́ть) из-под шка́фа чемода́н, откры́л его́ и на́чал укла́дывать свой ве́щи.","b":1},{"t":"subhead","text":"Đáp án: вы́тащил."},{"t":"para","text":"Dịch: Anh ấy lôi chiếc vali ra từ gầm tủ, mở nó ra và bắt đầu xếp đồ."},{"t":"example","text":"Giải thích: Lôi từ dưới gầm (bên trong/dưới) ra ngoài → dùng вы-."},{"t":"para","text":"16. Ско́лько мо́жно му́читься с зубно́й бо́лью! За́втра я (вести́/води́ть) тебя́ к врачу́.","b":1},{"t":"subhead","text":"Đáp án: поведу́."},{"t":"para","text":"Dịch: Còn chịu đựng đau răng đến bao giờ nữa! Ngày mai tôi sẽ dẫn bạn đi bác sĩ."},{"t":"example","text":"Giải thích: Quyết định thực hiện hành động trong tương lai → поведу́."},{"t":"para","text":"17. На про́шлой неде́ле мою́ маши́ну (гнать/гоня́ть) и тепе́рь я вы́нужден ходи́ть пешко́м.","b":1},{"t":"subhead","text":"Đáp án: угна́ли."},{"t":"para","text":"Dịch: Tuần trước xe của tôi đã bị lấy trộm (lái đi mất) và giờ tôi buộc phải đi bộ."},{"t":"example","text":"Giải thích: Угнать машину = lấy trộm xe (lái đi mất)."},{"t":"para","text":"18. Ну всё, до свида́ния, я (идти́/ходи́ть).","b":1},{"t":"subhead","text":"Đáp án: пошёл / пошла́."},{"t":"para","text":"Dịch: Thôi, tạm biệt nhé, tôi đi đây (bắt đầu đi)."},{"t":"example","text":"Giải thích: Thông báo bắt đầu rời đi ngay lúc nói → dùng quá khứ của пойти (пошёл) với nghĩa tương lai gần/bắt đầu ngay."}]},{"id":"07-s128","type":"exercise","title":"Bài 627 (Trang 334)","num":627,"blocks":[{"t":"instruction","text":"Yêu cầu: Замени́те, где мо́жно, глаго́лы движе́ния с приста́вкой при- глаго́лами с приста́вкой до-. Объясни́те ра́зницу в значе́ниях предложе́ний. (Thay thế các động từ chuyển động có tiền tố при- bằng các động từ có tiền tố до- ở những nơi có thể. Giải thích sự khác biệt về ý nghĩa của các câu)."},{"t":"subhead","text":"Gợi ý ngữ pháp trong khung (Trang 334):","b":1},{"t":"example","text":"Tiếng Nga: Глаго́лы движе́ния с приста́вкой до- ука́зывают на движе́ние, кото́рое зака́нчивается у вне́шней стороны́ объе́кта, и синоними́чны глаго́лам с приста́вкой при- в сочета́нии с предло́гом к: дойти́ до шко́лы = прийти́ к шко́ле. Глаго́лы движе́ния с приста́вкой при- в сочета́нии с други́ми предло́гами означа́ют значе́ние \"дости́чь какого-либо объе́кта\" + \"прони́кнуть внутрь него́\"."},{"t":"para","text":"Dịch & Giải thích:","b":1},{"t":"example","text":"Động từ với tiền tố до- (+ giới từ до) chỉ chuyển động kết thúc ở giới hạn/bên ngoài của đối tượng, đồng nghĩa với tiền tố при- đi với giới từ к."},{"t":"example","text":"Ví dụ: дойти́ до шко́лы (đi đến [cổng] trường) = прийти́ к шко́ле."},{"t":"example","text":"Động từ với tiền tố при- đi với các giới từ khác (в, на...) mang nghĩa \"đạt đến đối tượng\" + \"thâm nhập vào bên trong\". Trong trường hợp này, không thể thay thế bằng до-."},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"1. Мы пришли́ домо́й пе́ред са́мым обе́дом.","b":1},{"t":"para","text":"Thay thế: Мы дошли́ до́ дома..."},{"t":"example","text":"Giải thích: Пришли домой (Về đến nhà - vào trong nhà). Дошли до дома (Đi đến tận nhà - nhấn mạnh quãng đường đã đi xong, đứng trước nhà). Thay được nhưng nghĩa hơi khác (về đến nơi vs đi bộ đến nơi)."},{"t":"para","text":"2. Принеси́ мне, пожа́луйста, посы́лку к ваго́ну.","b":1},{"t":"para","text":"Thay thế: Донеси́... посы́лку до ваго́на."},{"t":"example","text":"Giải thích: Có giới từ к → thay bằng до- + до được. Nghĩa: Mang giúp kiện hàng đến chỗ toa tàu."},{"t":"para","text":"3. Я привезу́ вас на вокза́л.","b":1},{"t":"para","text":"Thay thế: Я довезу́ вас до вокза́ла."},{"t":"example","text":"Giải thích: Привезу на вокзал (Đưa đến nhà ga - đích đến chung). Довезу до вокзала (Chở đến tận nhà ga - nhấn mạnh việc hoàn thành quãng đường)."},{"t":"para","text":"4. Заче́м ты мне э́то принёс?! Я проси́л тебя́ совсе́м о друго́м!","b":1},{"t":"para","text":"Thay thế: Không thể thay thế (hoặc rất gượng gạo)."},{"t":"example","text":"Giải thích: Принёс ở đây có nghĩa là \"mang đến và đưa cho\", đối tượng là мне (tôi). Донёс có nghĩa là \"mang vác nặng nhọc đến đích\". Ở đây ý nghĩa là giao nhận vật, nên dùng при-."},{"t":"para","text":"5. Он прибежа́л к фи́нишу са́мым пе́рвым.","b":1},{"t":"para","text":"Thay thế: Он добежа́л до фи́ниша..."},{"t":"example","text":"Giải thích: Прибежал к = Добежал до (Chạy đến đích). Добежал nhấn mạnh nỗ lực chạy hết quãng đường."},{"t":"para","text":"6. Я с трудо́м приплы́л к бе́регу.","b":1},{"t":"para","text":"Thay thế: Я с трудо́м доплы́л до бе́рега."},{"t":"example","text":"Giải thích: Доплыл rất hợp lý vì có с трудом (một cách khó khăn) → nhấn mạnh việc cố gắng bơi cho đến khi chạm bờ."},{"t":"para","text":"7. Она́ о́чень бои́тся зубно́го врача́, ду́маю, её на́до бу́дет приводи́ть в его́ кабине́т за́ руку.","b":1},{"t":"para","text":"Thay thế: ... доводи́ть до его́ кабине́та..."},{"t":"example","text":"Giải thích: Приводить в (dẫn vào trong). Доводить до (dẫn đến cửa). Thay được nếu ý là dẫn đến cửa phòng."},{"t":"para","text":"8. Спаси́бо, я зна́ю доро́гу и прие́ду сам.","b":1},{"t":"para","text":"Thay thế: ... дое́ду сам."},{"t":"example","text":"Giải thích: Доеду (tự đi xe đến được đích)."},{"t":"para","text":"9. Приходи́те к нам в го́сти в суббо́ту.","b":1},{"t":"para","text":"Thay thế: Không thể thay thế."},{"t":"example","text":"Giải thích: Lời mời \"đến làm khách\" luôn dùng приходите. Доходите có nghĩa là \"đi bộ đến nơi (mệt mỏi)\" hoặc \"đạt tới trạng thái (chín, hỏng...)\"."},{"t":"para","text":"10. Вот мы и приплы́ли!","b":1},{"t":"para","text":"Thay thế: Вот мы и доплы́ли!"},{"t":"example","text":"Giải thích: Доплыли (Cuối cùng cũng bơi/đi thuyền đến nơi rồi). Nhấn mạnh hành trình đã kết thúc."},{"t":"example","text":"11. Ну, неда́вно мне пришло́сь остана́вливаться, так как неожи́данно пошёл дождь. Мы укры́лись под берёзой и ста́ли ждать... Вско́ре дождь прекрати́лся, мы вы́ехали... и пое́хали. К оди́ннадцати часа́м мы подъе́хали к до́му друзе́й... Он прибежа́л на седьмо́й эта́ж и останови́лся. (Câu gốc trong sách là: Он прибежал на седьмой этаж и остановился)."},{"t":"para","text":"Thay thế: Он добежа́л до седьмо́го этажа́..."},{"t":"para","text":"Giải thích: Chạy lên đến tận tầng 7."},{"t":"para","text":"12. За́втра мне ну́жно найти́ вре́мя и принести́ в библиоте́ку э́ти кни́ги.","b":1},{"t":"para","text":"Thay thế: ... донести́ до библиоте́ки..."},{"t":"example","text":"Giải thích: Принести в (mang vào trong để trả/mượn). Донести до (mang đến tận nơi)."},{"t":"para","text":"13. Ка́ждый год в конце́ ле́та я приезжа́ю на мо́ре.","b":1},{"t":"para","text":"Thay thế: ... я доезжа́ю до мо́ря."},{"t":"example","text":"Giải thích: Приезжаю на море (đến vùng biển nghỉ mát). Доезжаю до моря (lái xe/đi xe đến tận bờ biển). Nếu ý là \"đi nghỉ mát\" thì dùng при-. Nếu ý là hành trình di chuyển thì dùng до-. Trong ngữ cảnh này, приезжаю tự nhiên hơn, nhưng về mặt ngữ pháp chuyển động thì доезжаю có thể dùng để chỉ việc đến đích địa lý."},{"t":"para","text":"Tóm tắt sự khác biệt:","b":1},{"t":"vocab","ru":"При- (đến)","vi":"Nhấn mạnh kết quả là có mặt tại đích (thường vào bên trong hoặc tham gia hoạt động). Ví dụ: Прийти в школу (đến trường để học).","g":null},{"t":"vocab","ru":"До- (đến tận)","vi":"Nhấn mạnh quãng đường hoặc giới hạn đã đạt được (thường dừng lại ở bên ngoài). Ví dụ: Дойти до школы (đi bộ đến cổng trường).","g":null}]},{"id":"07-s129","type":"exercise","title":"Bài 628 (Trang 334-335)","num":628,"blocks":[{"t":"instruction","text":"Yêu cầu: В предложе́ниях определи́те значе́ние глаго́лов движе́ния. Назови́те инфинити́вы, от кото́рых образо́ваны глаго́лы движе́ния. Распредели́те предложе́ния по коло́нкам в зави́симости от хара́ктера движе́ния. (Trong các câu, hãy xác định ý nghĩa của động từ chuyển động. Gọi tên động từ nguyên mẫu mà từ đó chúng được tạo thành. Phân loại các câu vào các cột tùy thuộc vào tính chất của chuyển động)."},{"t":"para","text":"Các cột phân loại mẫu (theo sách):","b":1},{"t":"example","text":"Cột I (Đi ngang qua): Он прошёл ми́мо нас и да́же не огляну́лся. (Anh ấy đi ngang qua chúng tôi và thậm chí không ngoảnh lại.) → Ý nghĩa: Đi qua mà không dừng lại / Đi trượt qua."},{"t":"example","text":"Cột II (Hành động xảy ra trong lúc đi): Я услы́шал голоса́, когда́ проходи́л ми́мо его́ две́ри. (Tôi nghe thấy tiếng nói khi đi ngang qua cửa phòng anh ấy.) → Ý nghĩa: Quá trình đi qua."},{"t":"example","text":"Cột III (Khoảng cách/Thời gian): Це́лый день я проходи́л (сов.в.) по кабине́там, но так и не собра́л все ну́жные мне докуме́нты. (Tôi đã đi bộ cả ngày qua các phòng ban, nhưng vẫn không thu thập đủ giấy tờ cần thiết.) → Ý nghĩa: Bao trùm khoảng cách hoặc thời gian (làm việc gì đó bao lâu/bao xa)."},{"t":"para","text":"Giải chi tiết và Phân loại:","b":1},{"t":"example","text":"a) 1. Полдня́ я пробе́гал по магази́нам, что́бы купи́ть пода́рки. (từ бе́гать)"},{"t":"para","text":"Dịch: Tôi đã chạy đôn chạy đáo khắp các cửa hàng suốt nửa ngày để mua quà."},{"t":"example","text":"Phân loại: Cột III (Chỉ thời gian/quá trình kéo dài: полдня - nửa ngày)."},{"t":"example","text":"2. Она́ пробежа́ла ми́мо э́ту distánцию быстре́е всех. Когда́ я пробега́л ми́мо кио́ска, я купи́л газе́ту. (từ бежа́ть)"},{"t":"para","text":"Dịch:","b":1},{"t":"para","text":"Cô ấy đã chạy hết quãng đường này nhanh nhất. → Cột III (Chỉ khoảng cách đã hoàn thành)."},{"t":"para","text":"Khi tôi chạy ngang qua ki-ốt, tôi đã mua tờ báo. → Cột II (Hành động mua báo xảy ra trong lúc chạy qua)."},{"t":"example","text":"3. Я прое́хал свою́ ста́нцию и мне пришло́сь возвраща́ться. (từ е́хать)"},{"t":"para","text":"Dịch: Tôi đã đi quá (lỡ) trạm của mình và phải quay lại."},{"t":"para","text":"Phân loại: Cột I (Đi vượt qua đích, đi lỡ)."},{"t":"example","text":"4. По́езд ме́дленно проезжа́л ми́мо ста́нции. (từ езжа́ть - dạng chưa hoàn thành của проехать)"},{"t":"para","text":"Dịch: Đoàn tàu chầm chậm chạy ngang qua nhà ga."},{"t":"para","text":"Phân loại: Cột II (Miêu tả quá trình đi qua)."},{"t":"example","text":"5. Мы уже́ прое́здили на тра́нспорте три́ста рубле́й, мо́жет быть, лу́чше купи́м еди́ную ка́рточку на ме́сяц? (từ е́здить)"},{"t":"para","text":"Dịch: Chúng ta đã đi (tiêu tốn cho việc đi lại) hết 300 rúp rồi, hay là mua vé tháng đi?"},{"t":"para","text":"Phân loại: Cột III (Tiêu tốn nguồn lực/thời gian cho việc di chuyển)."},{"t":"example","text":"6. В настоя́щее вре́мя мы пролета́ем над Ура́льскими гора́ми. (từ лета́ть)"},{"t":"para","text":"Dịch: Hiện tại chúng ta đang bay qua dãy núi Ural."},{"t":"para","text":"Phân loại: Cột II (Quá trình bay qua địa điểm)."},{"t":"example","text":"7. Судя́ по показа́ниям прибо́ров, за год самолёт пролета́л три ты́сячи часо́в. (từ лета́ть)"},{"t":"para","text":"Dịch: Theo chỉ số thiết bị, trong một năm máy bay đã bay (tích lũy) được 3000 giờ."},{"t":"para","text":"Phân loại: Cột III (Tổng thời gian/khoảng cách thực hiện)."},{"t":"example","text":"8. Наша ко́шка, несмотря́ на огро́мной ско́рости, пролета́ла ми́мо. (Lưu ý: Câu này trong sách có thể in hơi lạ về ngữ pháp hoặc nghĩa bóng, nhưng ý là \"bay vèo qua\")."},{"t":"para","text":"Dịch: Con mèo của chúng tôi, bất chấp tốc độ lớn, đã bay vèo qua."},{"t":"para","text":"Phân loại: Cột I (Vụt qua)."},{"t":"example","text":"9. Всю жизнь он пропла́вал матро́сом на одно́м из корабле́й. (từ пла́вать)"},{"t":"para","text":"Dịch: Ông ấy đã đi biển (bơi/lênh đênh) làm thủy thủ suốt cả cuộc đời trên một con tàu."},{"t":"example","text":"Phân loại: Cột III (Toàn bộ thời gian: всю жизнь)."},{"t":"example","text":"10. Э́ту distánцию он проплы́л лу́чше всех. (từ плыть)"},{"t":"para","text":"Dịch: Anh ấy đã bơi hết quãng đường này tốt nhất trong mọi người."},{"t":"para","text":"Phân loại: Cột III (Hoàn thành khoảng cách)."},{"t":"example","text":"11. Мы наблюда́ли, как ми́мо нас проплыва́ли обло́мки корабля́. (từ плыть)"},{"t":"para","text":"Dịch: Chúng tôi quan sát những mảnh vỡ tàu trôi ngang qua chúng tôi."},{"t":"para","text":"Phân loại: Cột II (Quá trình trôi qua trước mắt)."},{"t":"example","text":"12. Це́лый день наш кот прола́зал по кры́шам и верну́лся домо́й то́лько к ве́черу. (từ ла́зить)"},{"t":"para","text":"Dịch: Cả ngày con mèo nhà tôi leo trèo trên các mái nhà và chỉ về nhà vào buổi tối."},{"t":"example","text":"Phân loại: Cột III (Thời gian: целый день)."},{"t":"example","text":"13. Когда́ я пролеза́л че́рез забо́р, я зацепи́лся за гвоздь и порва́л руба́шку. (từ ле́зть)"},{"t":"para","text":"Dịch: Khi tôi đang chui/leo qua hàng rào, tôi bị mắc vào cái đinh và làm rách áo."},{"t":"para","text":"Phân loại: Cột II (Hành động xảy ra trong lúc leo qua)."},{"t":"example","text":"14. Мы с трудо́м смогли́ проле́зть в э́ту щель. (từ лезть)"},{"t":"para","text":"Dịch: Chúng tôi vất vả lắm mới chui lọt qua cái khe này."},{"t":"para","text":"Phân loại: Cột I (Vượt qua chướng ngại vật/không gian hẹp thành công - nghĩa bóng của \"đi qua\")."},{"t":"example","text":"15. Че́рез кусты́ он пропо́лз бы́стро и бесшу́мно, как уж. (từ ползти́)"},{"t":"para","text":"Dịch: Cậu ta bò qua bụi rậm nhanh và không gây tiếng động như một con rắn."},{"t":"para","text":"Phân loại: Cột III (Hoàn thành hành động vượt qua không gian)."},{"t":"example","text":"16. Предоста́вленный самому́ себе́, ребёнок це́лый день пропо́лзал по ко́мнате. (từ по́лзать)"},{"t":"para","text":"Dịch: Bị bỏ mặc một mình, đứa bé đã bò khắp phòng cả ngày."},{"t":"example","text":"Phân loại: Cột III (Thời gian: целый день)."},{"t":"example","text":"b) 1. Ко́шка проноси́ла ми́мо нас котя́т одного́ за други́м. (từ носи́ть)"},{"t":"para","text":"Dịch: Con mèo tha (mang) từng đứa con một ngang qua chúng tôi."},{"t":"para","text":"Phân loại: Cột II (Quá trình mang qua trước mắt)."},{"t":"example","text":"2. Любо́вь к чте́нию он пронёс че́рез всю свою́ жизнь. (từ нести́)"},{"t":"para","text":"Dịch: Ông ấy đã mang tình yêu đọc sách theo suốt cuộc đời mình."},{"t":"para","text":"Phân loại: Cột III (Nghĩa bóng: duy trì trạng thái qua thời gian dài)."},{"t":"para","text":"Câu hỏi ngữ pháp (Trang 335)","b":1},{"t":"instruction","text":"Yêu cầu: Определи́те, кака́я приста́вка явля́ется антоними́чной приста́вке про- в тре́тьем значе́нии. (Xác định xem tiền tố nào là trái nghĩa với tiền tố про- ở ý nghĩa thứ ba)."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Trong ngữ cảnh bài học (đặc biệt là Cột I - Đi ngang qua mà không ghé vào / Đi lỡ), ý nghĩa thứ 3 thường được hiểu là đi qua, đi lỡ, không dừng lại."},{"t":"example","text":"Trái nghĩa với việc \"đi qua luôn\" (пройти мимо) là \"ghé vào\" (зайти)."},{"t":"subhead","text":"Đáp án: Tiền tố ЗА- (trong các từ như зайти, заехать - ghé vào)."},{"t":"note","text":"Lưu ý: Nếu hiểu \"ý nghĩa thứ 3\" theo phân loại Cột III (đi hết quãng đường/thời gian), thì không có tiền tố trái nghĩa trực tiếp một cách đơn giản. Nhưng trong hệ thống Glazunova, cặp đối lập phổ biến là Про- (đi qua/lỡ) ↔ За- (ghé vào)."}]},{"id":"07-s130","type":"exercise","title":"Bài 629 (Trang 335-336)","num":629,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя нужную форму глагола движения с приставкой про-. Объясните ваш выбор. Укажите варианты. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ chuyển động với tiền tố про-. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"1. Он взял скри́пку, (вести́/води́ть) смычко́м по стру́нам, и зал зати́х.","b":1},{"t":"subhead","text":"Đáp án: провёл (từ вести́)"},{"t":"para","text":"Dịch: Anh ấy cầm lấy cây vĩ cầm, kéo (lướt) vĩ qua dây đàn, và cả khán phòng im bặt."},{"t":"example","text":"Giải thích: Hành động một lần, cụ thể trên bề mặt → провёл."},{"t":"para","text":"2. Она́ посмотре́ла на него́, и по её лицу́ (бежа́ть/бе́гать) ирони́ческая усме́шка.","b":1},{"t":"subhead","text":"Đáp án: пробежа́ла (từ бежа́ть)"},{"t":"para","text":"Dịch: Cô ấy nhìn anh ta, và một nụ cười mỉa mai lướt qua (chạy qua) khuôn mặt cô."},{"t":"example","text":"Giải thích: Cảm xúc/biểu cảm xuất hiện nhanh trên mặt → пробежа́ла."},{"t":"para","text":"3. Когда́ по́езд (идти́/ходи́ть), лю́ди ста́ли расходи́ться.","b":1},{"t":"subhead","text":"Đáp án: прошёл (từ идти́)"},{"t":"para","text":"Dịch: Khi đoàn tàu đã đi qua, mọi người bắt đầu giải tán."},{"t":"example","text":"Giải thích: Tàu đi qua khỏi vị trí người nói → прошёл."},{"t":"para","text":"4. Мы (е́хать/е́здить) на маши́не весь го́род, что́бы найти́ его́.","b":1},{"t":"subhead","text":"Đáp án: прое́хали (từ е́хать)"},{"t":"para","text":"Dịch: Chúng tôi đã đi xe (xuyên qua/khắp) cả thành phố để tìm anh ấy."},{"t":"example","text":"Giải thích: Đi hết một khoảng không gian (cả thành phố) → прое́хали."},{"t":"para","text":"5. Почу́вствовав о́струю головну́ю боль, он закры́л глаза́ и (вести́/води́ть) ладо́нью по лбу.","b":1},{"t":"subhead","text":"Đáp án: провёл (từ вести́)"},{"t":"para","text":"Dịch: Cảm thấy đau đầu dữ dội, anh ấy nhắm mắt và vuốt (dẫn) lòng bàn tay qua trán."},{"t":"example","text":"Giải thích: Hành động vuốt tay trên bề mặt cơ thể → провёл."},{"t":"para","text":"6. Вре́мя от вре́мени по не́бу (плыть/пла́вать) чёрные ту́чи, но дождя́ не́ было.","b":1},{"t":"subhead","text":"Đáp án: проплыва́ли (từ плыть + про- → imperf)"},{"t":"para","text":"Dịch: Thi thoảng những đám mây đen trôi qua bầu trời, nhưng trời không mưa."},{"t":"example","text":"Giải thích: Hành động lặp lại (время от времени) → dùng thể chưa hoàn thành проплывали."},{"t":"para","text":"7. Журнали́сты (вести́/води́ть) на Кавка́зе не́сколько ме́сяцев и собра́ли о́чень интере́сный материа́л.","b":1},{"t":"subhead","text":"Đáp án: провели́ (từ вести́)"},{"t":"para","text":"Dịch: Các nhà báo đã ở (trải qua) vài tháng tại Kavkaz và thu thập được tài liệu rất thú vị."},{"t":"example","text":"Giải thích: Провести время (dành thời gian/ở lại)."},{"t":"para","text":"8. Иностра́нный отде́л был закры́т, и я напра́сно (тащи́ть/таска́ть) твой докуме́нты.","b":1},{"t":"subhead","text":"Đáp án: протаска́л (từ таска́ть)"},{"t":"para","text":"Dịch: Phòng đối ngoại đã đóng cửa, và tôi đã mang (vác) giấy tờ của bạn đi theo một cách vô ích."},{"t":"example","text":"Giải thích: Mang đi mang lại một cách vất vả trong một khoảng thời gian → протаска́л (gốc đa chiều)."},{"t":"para","text":"9. Бою́сь, я с трудо́м смогу́ (лезть/ла́зить) в э́ту щель.","b":1},{"t":"subhead","text":"Đáp án: проле́зть (từ лезть)"},{"t":"para","text":"Dịch: Tôi sợ là tôi sẽ khó mà chui lọt qua cái khe này."},{"t":"example","text":"Giải thích: Vượt qua không gian hẹp → проле́зть."},{"t":"para","text":"10. Остава́йся до́ма, ты то́лько зря (бежа́ть/бе́гать) по магази́нам, все необходи́мые проду́кты у нас есть.","b":1},{"t":"subhead","text":"Đáp án: пробе́гаешь (từ бе́гать)"},{"t":"para","text":"Dịch: Ở nhà đi, cậu chỉ chạy qua các cửa hàng vô ích thôi (tốn công chạy), chúng ta có đủ thực phẩm cần thiết rồi."},{"t":"example","text":"Giải thích: Tốn thời gian chạy đi chạy lại → пробегаешь (gốc đa chiều)."},{"t":"para","text":"11. Дереве́нские жи́тели, когда́ (идти́/ходи́ть) ми́мо э́того заколо́ченного до́ма, боязли́во огля́дывались и крести́лись.","b":1},{"t":"subhead","text":"Đáp án: проходи́ли (từ ходи́ть)"},{"t":"para","text":"Dịch: Người dân làng khi đi ngang qua ngôi nhà bị đóng đinh niêm phong này đều sợ hãi ngoái nhìn và làm dấu thánh giá."},{"t":"example","text":"Giải thích: Hành động lặp lại nhiều lần trong quá khứ → проходи́ли."},{"t":"para","text":"12. От стра́ха си́льная дрожь не́сколько раз (бежа́ть/бе́гать) по всему́ его́ те́лу, но он упря́мо шёл вперёд.","b":1},{"t":"subhead","text":"Đáp án: пробежа́ла (từ бежа́ть)"},{"t":"para","text":"Dịch: Vì sợ hãi, cơn run rẩy mạnh đã chạy dọc khắp cơ thể anh ấy vài lần, nhưng anh ấy vẫn bướng bỉnh đi về phía trước."},{"t":"example","text":"Giải thích: Cảm giác lan truyền khắp cơ thể → пробежала."},{"t":"para","text":"13. Все дни с утра́ до ве́чера я (вести́/води́ть) в больни́це у посте́ли отца́.","b":1},{"t":"subhead","text":"Đáp án: проводи́л (từ води́ть - ở đây mang nghĩa проводить время)"},{"t":"para","text":"Dịch: Suốt những ngày đó từ sáng đến tối tôi đã trải qua (ngồi/ở) trong bệnh viện bên giường bệnh của cha."},{"t":"example","text":"Giải thích: Dành thời gian → проводил."},{"t":"para","text":"14. Мы уже́ це́лый час (е́хать/е́здить) по всему́ го́роду, но так и не нашли́ то, что нам бы́ло ну́жно.","b":1},{"t":"subhead","text":"Đáp án: прое́здили (từ е́здить)"},{"t":"para","text":"Dịch: Chúng tôi đã đi xe vòng vèo (đi khắp) thành phố cả tiếng đồng hồ rồi mà vẫn không tìm thấy thứ cần tìm."},{"t":"example","text":"Giải thích: Đi lại khắp nơi trong một khoảng thời gian (cả tiếng) → прое́здили."},{"t":"para","text":"15. Год (лете́ть/лета́ть) за го́дом, но в его́ жи́зни ничего́ не меня́лось.","b":1},{"t":"subhead","text":"Đáp án: пролета́л (từ лета́ть) hoặc лете́л."},{"t":"example","text":"Ngữ cảnh này: Thường dùng пролета́л (trôi qua nhanh) hoặc лете́л. Sách dùng tiền tố про- nên chọn пролета́л."},{"t":"para","text":"Dịch: Năm tháng cứ trôi vùn vụt (bay qua), nhưng cuộc đời anh ấy chẳng có gì thay đổi."},{"t":"example","text":"Giải thích: Thời gian trôi nhanh → пролетал."},{"t":"para","text":"16. Нет, на э́тот раз им не уда́стся (вести́/води́ть) нас, мы бу́дем вести́ себя́ умно́.","b":1},{"t":"subhead","text":"Đáp án: провести́ (từ вести́)"},{"t":"para","text":"Dịch: Không, lần này bọn họ sẽ không thể lừa (dắt mũi) chúng ta đâu, chúng ta sẽ cư xử khôn ngoan."},{"t":"example","text":"Giải thích: Провести кого-то = lừa gạt ai đó."},{"t":"para","text":"17. За э́ти не́сколько мину́т у него́ пе́ред глаза́ми (идти́/ходи́ть) вся его́ жизнь.","b":1},{"t":"subhead","text":"Đáp án: прошла́ (từ идти́)"},{"t":"para","text":"Dịch: Trong vài phút đó, cả cuộc đời anh ấy đã trôi qua (hiện ra) trước mắt."},{"t":"example","text":"Giải thích: Cuộc đời trôi qua/tái hiện → прошла."},{"t":"para","text":"18. Оппози́ция воспо́льзовалась ситуа́цией, что́бы (тащи́ть/таска́ть) че́рез Ду́му вы́годный ей зако́н.","b":1},{"t":"subhead","text":"Đáp án: протащи́ть (từ тащи́ть)"},{"t":"para","text":"Dịch: Phe đối lập đã tận dụng tình thế để thông qua (kéo trót lọt) một đạo luật có lợi cho họ tại Duma."},{"t":"example","text":"Giải thích: Протащить закон = luồn lách/cố gắng thông qua luật."},{"t":"para","text":"19. На борт самолёта запрещено́ (нести́/носи́ть) ко́лющие и ре́жущие предме́ты.","b":1},{"t":"subhead","text":"Đáp án: проноси́ть (từ носи́ть)"},{"t":"para","text":"Dịch: Cấm mang (đưa vào/lọt qua cửa) các vật sắc nhọn lên máy bay."},{"t":"example","text":"Giải thích: Mang qua trạm kiểm soát → проносить."},{"t":"para","text":"20. Мину́т де́сять зал (вести́/води́ть) арти́ста аплодисме́нтами.","b":1},{"t":"subhead","text":"Đáp án: провожа́л (Đây là động từ khác: провожать - tiễn). Tuy nhiên, nếu bắt buộc dùng gốc вести/водить với tiền tố про-, thì đó là проводи́л (tiễn đưa). Nhưng ngữ cảnh vỗ tay tiễn nghệ sĩ vào cánh gà thường dùng провожал."},{"t":"note","text":"Lưu ý sách Glazunova: Có thể sách muốn dùng провожал (từ провожать, không phải водить). Nhưng nếu ép vào bài про-, thì проводил cũng có nghĩa là tiễn."},{"t":"subhead","text":"Đáp án: провожа́л / проводи́л."},{"t":"para","text":"Dịch: Suốt 10 phút, khán phòng đã tiễn nghệ sĩ bằng những tràng pháo tay."},{"t":"para","text":"21. Не сто́йте в дверя́х, (идти́/ходи́ть) в ко́мнату.","b":1},{"t":"subhead","text":"Đáp án: проходи́те (từ ходи́ть)"},{"t":"para","text":"Dịch: Đừng đứng ở cửa, hãy vào (đi qua vào) trong phòng."},{"t":"example","text":"Giải thích: Mời vào trong, đi qua ngưỡng cửa → проходите."},{"t":"para","text":"22. За́втра мы це́лый день бу́дем (вести́/води́ть) и встреча́ть госте́й.","b":1},{"t":"subhead","text":"Đáp án: провожа́ть (tiễn) - Lại là vấn đề động từ gốc. Проводить (hoàn thành) không đi với будем để tạo tương lai. Проводить (chưa hoàn thành - từ провожать) mới đúng."},{"t":"vocab","ru":"Nếu bắt buộc dùng водить","vi":"будем проводить (sẽ dẫn đường/tiễn - nghĩa này ít dùng với водить gốc).","g":null},{"t":"example","text":"Khả năng cao sách muốn dùng cặp đối lập встречать (đón) và провожа́ть (tiễn - про + вожать)."},{"t":"para","text":"Dịch: Ngày mai cả ngày chúng tôi sẽ tiễn và đón khách. [i]"},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 336)","b":1},{"t":"para","text":"Trước khi làm bài, bạn cần chú ý khung ngữ pháp quan trọng phân biệt ý nghĩa của động từ проводи́ть:"},{"t":"subhead","text":"Tiếng Nga: ! Глагола вести́/води́ть с приставкой про- образуется два глагола:"},{"t":"vocab","ru":"провести́ (сов.в.) / проводи́ть (несов.в.)","vi":"Он провёл с нами целый день (проводи́ть время); Он провёл воду в дом (проложи́ть).","g":null},{"t":"vocab","ru":"провожа́ть (несов.в.) / проводи́ть (сов.в.)","vi":"В субботу мы провожа́ли бабушку на вокзал. ! В переносном значении глагол сов.в. провести́ употребляется в значении «обмануть».","g":null},{"t":"para","text":"Dịch & Giải thích: ! Từ động từ вести́/води́ть với tiền tố про-, có hai cặp động từ được hình thành với ý nghĩa khác nhau:"},{"t":"subhead","text":"Провести́ (Hoàn thành) / Проводи́ть (Chưa hoàn thành):"},{"t":"example","text":"Nghĩa: Dành thời gian, trải qua (Anh ấy đã dành cả ngày với chúng tôi); hoặc dẫn/lắp đặt đường dây/ống (Anh ấy đã dẫn nước vào nhà)."},{"t":"note","text":"Lưu ý: Ở nghĩa này, проводи́ть là động từ Chưa hoàn thành (trọng âm thường rơi vào âm tiết cuối проводи́ть hoặc прово́дит ở hiện tại)."},{"t":"subhead","text":"Провожа́ть (Chưa hoàn thành) / Проводи́ть (Hoàn thành):"},{"t":"example","text":"Nghĩa: Tiễn đưa, tiễn chân (Thứ bảy chúng tôi đã tiễn bà ra nhà ga)."},{"t":"note","text":"Lưu ý: Ở nghĩa này, проводи́ть đóng vai trò là động từ Hoàn thành."},{"t":"para","text":"Nghĩa bóng: Động từ hoàn thành провести́ còn có nghĩa là \"lừa gạt, lừa dối\" (обмануть)."}]},{"id":"07-s131","type":"exercise","title":"Bài 630 (Trang 336)","num":630,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме один из глаголов движения с приставкой про- или в-. Вместо точек вставьте необходимые по смыслу предлоги. (Mở ngoặc đơn, sử dụng dạng cần thiết của một trong các động từ chuyển động với tiền tố про- hoặc в-. Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa)."},{"t":"para","text":"1. Не сто́йте у вы́хода, (идти́/ходи́ть), пожа́луйста, ... середи́ну ваго́на.","b":1},{"t":"subhead","text":"Đáp án: проходи́те в","b":1},{"t":"para","text":"Dịch: Đừng đứng ở cửa ra vào, làm ơn đi vào giữa toa tàu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Проходи́те","vi":"Mời ai đó di chuyển qua một khoảng không gian hoặc đi tiếp vào trong (lịch sự).","g":null},{"t":"example","text":"Giới từ в (vào) dùng với середи́ну (giữa)."},{"t":"para","text":"2. Тако́й уж он челове́к, все ходы́ и вы́ходы зна́ет, ... любу́ю ды́рку (лезть/ла́зить).","b":1},{"t":"subhead","text":"Đáp án: в любую дырку проле́зет (hoặc вле́зет)"},{"t":"para","text":"Dịch: Con người hắn là thế đấy, ngõ ngách nào cũng biết, lỗ nào cũng chui lọt."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Проле́зет (tương lai hoàn thành của пролезть)","vi":"Chỉ khả năng vượt qua khó khăn, luồn lách qua không gian hẹp (nghĩa bóng: xoay xở giỏi).","g":null},{"t":"example","text":"Giới từ в đã có sẵn trong cụm в любую дырку."},{"t":"para","text":"3. Он (идти́/ходи́ть) ... ко́мнату и поздоро́вался.","b":1},{"t":"subhead","text":"Đáp án: прошёл в (hoặc вошёл в)"},{"t":"para","text":"Dịch: Anh ấy đã đi vào trong phòng và chào hỏi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Прошёл в","vi":"Đi băng qua không gian khác để vào phòng.","g":null},{"t":"vocab","ru":"Вошёл в","vi":"Bước vào phòng. Cả hai đều chấp nhận được, nhưng прошёл nhấn mạnh việc di chuyển tới đích.","g":null},{"t":"para","text":"4. ... водо́й мы (плыть/пла́вать) ме́тров пять и́ли шесть.","b":1},{"t":"subhead","text":"Đáp án: Под водо́й мы проплы́ли","b":1},{"t":"para","text":"Dịch: Chúng tôi đã bơi được khoảng năm hoặc sáu mét dưới nước."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Giới từ Под (dưới) đi với водой."},{"t":"vocab","ru":"Проплы́ли","vi":"Bơi được một quãng đường cụ thể (5-6 mét) → tiền tố про- chỉ việc hoàn thành khoảng cách.","g":null},{"t":"para","text":"5. Не оставля́йте маши́ну ... у́лице, (е́хать/е́здить) ... двор.","b":1},{"t":"subhead","text":"Đáp án: на у́лице; въезжа́йте во"},{"t":"para","text":"Dịch: Đừng để xe trên đường, hãy lái vào trong sân."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"На улице","vi":"Trên phố.","g":null},{"t":"vocab","ru":"Въезжа́йте (Mệnh lệnh)","vi":"Lái xe từ ngoài vào trong cổng/sân → tiền tố в- (въ-). Giới từ во (vào).","g":null},{"t":"para","text":"6. ... гости́ной ... у́зкому коридо́ру они́ (идти́/ходи́ть) ... кабинет.","b":1},{"t":"subhead","text":"Đáp án: Из гости́ной по у́зкому коридо́ру они́ прошли́ в","b":1},{"t":"para","text":"Dịch: Từ phòng khách, họ đi (băng) qua hành lang hẹp vào phòng làm việc."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Из (từ), по (dọc theo), в (vào)."},{"t":"vocab","ru":"Прошли́","vi":"Đi dọc theo hành lang để đến đích.","g":null},{"t":"para","text":"7. Я хочу́ (нести́/носи́ть) ещё одно́ предложе́ние.","b":1},{"t":"subhead","text":"Đáp án: внести́","b":1},{"t":"para","text":"Dịch: Tôi muốn đưa ra (đề xuất/đệ trình) thêm một ý kiến nữa."},{"t":"example","text":"Giải thích: Внести́ предложение (đưa ý kiến vào biên bản/cuộc họp) là cụm cố định. Tiền tố в-."},{"t":"para","text":"8. Свои́м поведе́нием ты меня́ ... гроб (гнать/гоня́ть).","b":1},{"t":"subhead","text":"Đáp án: в гроб вго́нишь","b":1},{"t":"para","text":"Dịch: Với cách cư xử của con, con sẽ đưa (dồn) mẹ xuống mồ mất thôi."},{"t":"example","text":"Giải thích: Thành ngữ вогна́ть в гроб (làm ai khổ sở đến chết/xuống mồ). Dùng tương lai hoàn thành вгонишь để cảnh báo kết quả."},{"t":"para","text":"9. ... Москвы́ вы мо́жете сра́зу (е́хать/е́здить) ... Се́ргиев Поса́д.","b":1},{"t":"subhead","text":"Đáp án: Из Москвы́ ... прое́хать в","b":1},{"t":"para","text":"Dịch: Từ Moscow bạn có thể đi xe (thẳng) đến Sergiev Posad ngay."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Прое́хать","vi":"Đi xe vượt qua một khoảng cách để đến đích.","g":null}]},{"id":"07-s132","type":"exercise","title":"Bài 631 (Trang 337)","num":631,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложе́ния, обраща́я внима́ние на усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками по-, до-, про-, к вы́деленным словосочета́ниям подбери́те сино́нимы. (Đọc các câu, chú ý đến các cụm từ cố định (thành ngữ) đi với động từ chuyển động có tiền tố po-, do-, pro-. Tìm từ đồng nghĩa cho các cụm từ được in đậm)."},{"t":"example","text":"1. Я ду́маю, он далеко́ пойдёт, быть ему́ мини́стром, не ме́ньше.","b":1},{"t":"para","text":"Ý nghĩa: Sẽ thành công rực rỡ, có tương lai xán lạn."},{"t":"para","text":"Dịch: Tôi nghĩ cậu ấy sẽ tiến xa (thành công lớn), ít nhất cũng phải làm bộ trưởng."},{"t":"example","text":"Đồng nghĩa: добьётся большо́го успе́ха (sẽ đạt được thành công lớn)."},{"t":"example","text":"2. Е́сли уж на то пошло́ и все реши́ли приня́ть уча́стие в ве́чере, я то́же, как и все, бу́ду в нём уча́ствовать.","b":1},{"t":"para","text":"Ý nghĩa: Nếu sự việc đã diễn biến như vậy / Nếu đã đến nước này."},{"t":"para","text":"Dịch: Nếu chuyện đã thế rồi (mọi người đã quyết) và ai cũng tham gia buổi dạ tiệc, thì tôi cũng sẽ tham gia như mọi người."},{"t":"example","text":"Đồng nghĩa: раз так случи́лось / раз уж так сложи́лись обстоя́тельства (vì hoàn cảnh đã thế)."},{"t":"example","text":"3. О каки́х дохо́дах ты говори́шь! Де́нег нет, ско́ро все пойдём по́ миру.","b":1},{"t":"para","text":"Ý nghĩa: Trở nên nghèo khổ, đi ăn mày."},{"t":"para","text":"Dịch: Cậu nói về thu nhập nào chứ! Chẳng có tiền đâu, sắp đi ăn mày (ra đê mà ở) cả lũ rồi."},{"t":"example","text":"Đồng nghĩa: обнища́ем / ста́нем ни́щими (sẽ trở nên bần cùng)."},{"t":"example","text":"4. Свои́ми злы́ми шу́тками он спосо́бен любо́го довести́ до бе́лого кале́ния.","b":1},{"t":"para","text":"Ý nghĩa: Làm ai đó tức điên lên, chọc tức đến mức mất kiểm soát. (Nghĩa đen: nung kim loại đến mức trắng xóa)."},{"t":"para","text":"Dịch: Với những trò đùa ác ý của mình, hắn có thể làm bất cứ ai tức sôi máu (điên tiết)."},{"t":"example","text":"Đồng nghĩa: си́льно разозли́ть / вывести из себя́ (chọc giận điên người / làm mất bình tĩnh)."},{"t":"example","text":"5. Запо́мни и доведи́ до све́дения остальны́х всё, что я тебе́ сего́дня сказа́л.","b":1},{"t":"para","text":"Ý nghĩa: Thông báo, cho biết."},{"t":"para","text":"Dịch: Hãy nhớ và thông báo (phổ biến) cho những người còn lại tất cả những gì tôi nói với cậu hôm nay."},{"t":"example","text":"Đồng nghĩa: сообщи́ / проинформи́руй (thông báo / cung cấp thông tin)."},{"t":"example","text":"6. Ему́ па́лец в рот не клади́, он спосо́бен любо́го, да́же са́мого хи́трого, провести́!","b":1},{"t":"example","text":"Ý nghĩa: Lừa gạt, qua mặt. (Thành ngữ палец в рот не клади nghĩa là phải cẩn thận với người này, họ rất sắc sảo/nguy hiểm)."},{"t":"para","text":"Dịch: Đừng có dại mà dây vào hắn (đừng đặt ngón tay vào miệng hắn), hắn có thể lừa (qua mặt) bất cứ ai, kể cả kẻ ranh ma nhất!"},{"t":"example","text":"Đồng nghĩa: обману́ть / перехитри́ть (lừa dối / khôn lỏi hơn)."},{"t":"vocab","ru":"Э́того дня ме́жду ни́ми как бу́дто чёрная ко́шка пробежа́ла","vi":"не разгова́ривают, да́же не смо́трят друг на дру́га.","g":null},{"t":"para","text":"Ý nghĩa: Cãi nhau, bất hòa, xích mích (Mèo đen chạy qua giữa hai người)."},{"t":"para","text":"Dịch: Từ hôm đó giữa họ như thể có con mèo đen chạy qua (họ cạch mặt nhau): không nói chuyện, thậm chí không nhìn mặt nhau."},{"t":"example","text":"Đồng nghĩa: поссо́рились (đã cãi nhau/xích mích)."},{"t":"example","text":"8. На́до провести́ грань ме́жду тем, что мо́жно де́лать, и тем, чего́ на да́нном эта́пе мо́жно бу́дет обойти́сь.","b":1},{"t":"para","text":"Ý nghĩa: Phân biệt rõ ràng, vạch ra ranh giới."},{"t":"para","text":"Dịch: Cần phải vạch rõ ranh giới giữa những gì có thể làm và những gì ở giai đoạn này có thể bỏ qua."},{"t":"example","text":"Đồng nghĩa: разграни́чить / разделить (phân định / chia tách)."}]},{"id":"07-s133","type":"exercise","title":"Bài 632 (Trang 337)","num":632,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками по-, до-, про-, к вы́деленным словосочета́ниям подбери́те сино́нимы. (Sử dụng các cụm từ cố định với động từ chuyển động có tiền tố по-, до-, про-, hãy chọn từ đồng nghĩa cho các cụm từ được in đậm)."},{"t":"example","text":"1. Да они́ уже́ давно поссо́рились.","b":1},{"t":"subhead","text":"Đáp án: ме́жду ни́ми чёрная ко́шка пробежа́ла","b":1},{"t":"para","text":"Dịch: Ôi dào, bọn họ đã cạch mặt nhau (có con mèo đen chạy qua giữa họ) từ lâu rồi."},{"t":"example","text":"Giải thích: Thành ngữ чёрная ко́шка пробежа́ла (mèo đen chạy qua) dùng để chỉ sự bất hòa, cãi vã."},{"t":"example","text":"2. На́до уме́ть различа́ть добро́ и зло, хотя́ иногда́ э́то сде́лать не про́сто.","b":1},{"t":"subhead","text":"Đáp án: проводи́ть грань / черту́ (ме́жду добром и злом)","b":1},{"t":"para","text":"Dịch: Cần phải biết vạch rõ ranh giới giữa thiện và ác, mặc dù đôi khi làm điều đó không hề đơn giản."},{"t":"example","text":"Giải thích: Проводи́ть грань = phân biệt, vạch ranh giới."},{"t":"example","text":"3. Я уве́рена, что он без труда́ сде́лает карьеру, рабо́тая на э́том ме́сте.","b":1},{"t":"subhead","text":"Đáp án: далеко́ пойдёт","b":1},{"t":"para","text":"Dịch: Tôi tin chắc rằng cậu ấy sẽ tiến xa (thành công lớn) khi làm việc ở vị trí này."},{"t":"example","text":"Giải thích: Далеко́ пойдёт = sẽ có tương lai xán lạn, thăng tiến nhanh."},{"t":"example","text":"4. Не серди́ меня́ лу́чше, ви́дишь, у меня́ и так плохо́е настрое́ние.","b":1},{"t":"subhead","text":"Đáp án: Не доводи́ меня́ (до греха́ / до кра́йности)","b":1},{"t":"para","text":"Dịch: Tốt nhất là đừng chọc tức tôi (đừng dồn ép tôi), thấy không, tâm trạng tôi đang tệ sẵn rồi."},{"t":"example","text":"Giải thích: Доводи́ть кого-то = làm ai đó mất kiên nhẫn, chọc điên ai đó."},{"t":"example","text":"5. Нет, на э́тот раз он нас не обма́нет.","b":1},{"t":"subhead","text":"Đáp án: не проведёт","b":1},{"t":"para","text":"Dịch: Không, lần này hắn sẽ không lừa (dắt mũi) được chúng ta đâu."},{"t":"example","text":"Giải thích: Провести́ (nghĩa bóng) = lừa gạt."},{"t":"example","text":"6. Сообщи́ всем о том, что за́втра мы встреча́емся в во́семь утра́.","b":1},{"t":"subhead","text":"Đáp án: Доведи́ до све́дения всех / всех в изве́стность","b":1},{"t":"para","text":"Dịch: Hãy thông báo (đưa thông tin đến) cho mọi người biết rằng ngày mai chúng ta gặp nhau lúc 8 giờ sáng."},{"t":"example","text":"Giải thích: Довести́ до све́дения = thông báo chính thức."},{"t":"example","text":"7. Впро́чем, е́сли речь об э́том зашла́, я расскажу́ вам о нём одну́ любопы́тную исто́рию.","b":1},{"t":"subhead","text":"Đáp án: раз уж на то пошло́","b":1},{"t":"para","text":"Dịch: Mà thôi, nếu sự thể đã thế (nhân tiện nói về chuyện này), tôi sẽ kể cho các bạn nghe một câu chuyện thú vị về anh ta."},{"t":"example","text":"Giải thích: Раз (уж) на то пошло́ = nếu tình huống đã diễn ra như vậy/nhân tiện chuyện đang bàn."},{"t":"example","text":"8. Вско́ре по́сле э́того собы́тия он потеря́л всё и на́чал ни́щенствовать.","b":1},{"t":"subhead","text":"Đáp án: пошёл по́ миру","b":1},{"t":"para","text":"Dịch: Chẳng bao lâu sau sự kiện đó, ông ta mất tất cả và trở thành kẻ ăn mày (đi khắp thế gian xin ăn)."},{"t":"example","text":"Giải thích: Пойти́ по́ миру = khánh kiệt, đi ăn xin."}]},{"id":"07-s134","type":"exercise","title":"Bài 633 (Trang 337-338)","num":633,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте необходи́мые по смы́слу глаго́лы движе́ния с приста́вками по-, до-, при-, вы-, про- и́ли без приста́вок. Объясни́те ваш вы́бор. (Thay dấu ba chấm bằng các động từ chuyển động cần thiết theo ý nghĩa với các tiền tố по-, до-, при-, вы-, про- hoặc không có tiền tố. Giải thích sự lựa chọn của bạn)."},{"t":"example","text":"(Đây là một câu chuyện liền mạch, các động từ cần phù hợp với ngữ cảnh)."},{"t":"para","text":"1. В суббо́ту ве́чером мы с друзья́ми ... в теа́тр.","b":1},{"t":"subhead","text":"Đáp án: пошли́ (hoặc собрали́сь пойти́)"},{"t":"para","text":"Dịch: Tối thứ Bảy tôi và bạn bè đã đi (khởi hành) đến nhà hát."},{"t":"example","text":"Giải thích: Bắt đầu hành động đi đến đích → пошли́."},{"t":"para","text":"2. Мы ... из до́ма в шесть часо́в, что́бы пе́ред спекта́клем немно́го ... по у́лице, подыша́ть све́жим во́здухом.","b":1},{"t":"subhead","text":"Đáp án: вы́шли; пройти́сь (hoặc походи́ть)"},{"t":"para","text":"Dịch: Chúng tôi ra khỏi nhà lúc 6 giờ để trước giờ diễn có thể đi dạo một chút trên phố, hít thở không khí trong lành."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Ra khỏi nhà → вы́шли."},{"t":"example","text":"Đi dạo thư giãn trong thời gian ngắn → пройти́сь (đi dạo một vòng) hoặc походи́ть (đi lại một lúc)."},{"t":"para","text":"3. Мы ... на остано́вку трамва́я, ... в него́ и ... по направле́нию к тому́ теа́тру, кото́рый был нам ну́жен.","b":1},{"t":"subhead","text":"Đáp án: пришли́ (hoặc подошли́); вошли́ (hoặc се́ли); пое́хали"},{"t":"para","text":"Dịch: Chúng tôi đến trạm xe điện, bước vào xe và đi (xe) về hướng nhà hát mà chúng tôi cần."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Đến địa điểm chờ → пришли hoặc подошли (lại gần)."},{"t":"example","text":"Vào trong phương tiện → вошли."},{"t":"example","text":"Bắt đầu di chuyển bằng xe → пое́хали."},{"t":"para","text":"4. Мы до́лго ... по у́лицам, пыта́ясь найти́ пра́вильную доро́гу, пока́ не ... к Марии́нскому теа́тру.","b":1},{"t":"subhead","text":"Đáp án: кружи́ли / ходи́ли; вы́шли / подошли́"},{"t":"note","text":"Lưu ý: Vì ở đoạn trước họ đi xe (поехали), nên ở đây có thể họ đã xuống xe và đi bộ tìm (ходили) hoặc xe chạy lòng vòng (ездили). Tuy nhiên, ngữ cảnh \"tìm đường\" thường dùng плута́ли (lạc) hoặc кружи́ли (đi vòng vèo). Nếu bắt buộc dùng động từ chuyển động cơ bản: ездили (nếu còn trên xe) hoặc ходили (nếu đã xuống). Giả sử đã xuống xe:"},{"t":"para","text":"Dịch: Chúng tôi đi loanh quanh trên các con phố rất lâu để cố tìm đúng đường, cho đến khi đến được (bước ra/lại gần) nhà hát Mariinsky."},{"t":"example","text":"Đến gần đích sau khi tìm kiếm → подошли hoặc вышли к (đi ra tới chỗ)."},{"t":"example","text":"5. Она́ (билетёрша) объясни́ла нам, что (хотя́) мы ... на не́сколько мину́т, мы (мо́жем) ... ми́мо билетёра в гардеро́б. * (Cấu trúc câu gốc trong sách có thể hơi khác, tôi điền theo logic ngữ pháp)."},{"t":"subhead","text":"Đáp án: опозда́ли (động từ thường: muộn) - nhưng đề bài yêu cầu động từ chuyển động? Nếu bắt buộc động từ chuyển động: пришли́ по́зже (đến muộn)."},{"t":"para","text":"Vế sau: прошли́"},{"t":"para","text":"Dịch: Cô ấy giải thích rằng (dù) chúng tôi đến muộn vài phút, chúng tôi (vẫn được) đi qua người soát vé để vào phòng gửi đồ."},{"t":"example","text":"Giải thích: Đi qua trạm kiểm soát → прошли."},{"t":"para","text":"6. Зате́м мы ... в зал и нашли́ свои́ места́.","b":1},{"t":"subhead","text":"Đáp án: вошли́ (hoặc прошли́)"},{"t":"para","text":"Dịch: Sau đó chúng tôi bước vào khán phòng và tìm chỗ ngồi."},{"t":"example","text":"Giải thích: Vào không gian bên trong → вошли."},{"t":"para","text":"7. Свет пога́с, на сце́ну ... арти́сты, и спекта́кль начался́.","b":1},{"t":"subhead","text":"Đáp án: вы́шли","b":1},{"t":"para","text":"Dịch: Đèn tắt, các nghệ sĩ bước ra sân khấu, và vở diễn bắt đầu."},{"t":"example","text":"Giải thích: Từ cánh gà ra sân khấu (không gian mở trước mặt khán giả) → вы́шли."},{"t":"para","text":"8. Два с полови́ной часа́ ... незаме́тно.","b":1},{"t":"subhead","text":"Đáp án: прошли́ (hoặc пролете́ли)"},{"t":"para","text":"Dịch: Hai tiếng rưỡi trôi qua nhanh chóng (không ai để ý)."},{"t":"example","text":"Giải thích: Thời gian trôi qua → прошли hoặc пролетели (bay vèo qua)."},{"t":"para","text":"9. По́сле спекта́кля зри́тели до́лго ... арти́стов аплодисме́нтами.","b":1},{"t":"subhead","text":"Đáp án: провожа́ли","b":1},{"t":"para","text":"Dịch: Sau vở diễn, khán giả đã tiễn các nghệ sĩ rất lâu bằng những tràng pháo tay."},{"t":"example","text":"Giải thích: Провожать аплодисментами = vỗ tay tiễn nghệ sĩ vào trong."},{"t":"para","text":"10. Когда́ опусти́ли за́навес, мы ... в гардеро́б, оде́лись, ... на у́лицу и ... к остано́вке трамва́я.","b":1},{"t":"subhead","text":"Đáp án: пошли́ (hoặc спусти́лись); вы́шли; пошли́ (hoặc подошли́)"},{"t":"para","text":"Dịch: Khi màn nhung hạ xuống, chúng tôi đi đến phòng gửi đồ, mặc áo, ra phố và đi đến trạm xe điện."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Đi đến đích khác trong toà nhà → пошли."},{"t":"example","text":"Ra khỏi toà nhà → вы́шли."},{"t":"example","text":"Đi đến trạm xe → пошли/подошли."},{"t":"para","text":"11. Был чуде́сный ве́чер. Ми́мо нас не спеша́ ... лю́ди.","b":1},{"t":"subhead","text":"Đáp án: проходи́ли (hoặc шли)"},{"t":"para","text":"Dịch: Một buổi tối tuyệt vời. Mọi người thong thả đi (dạo) ngang qua chúng tôi."},{"t":"example","text":"Giải thích: Hành động diễn ra trước mắt, kéo dài → проходи́ли (đi qua) hoặc шли (đi bộ)."},{"t":"para","text":"12. Трамва́я до́лго не́ было, и мы реши́ли ... домо́й пешко́м.","b":1},{"t":"subhead","text":"Đáp án: пойти́ (hoặc идти́)"},{"t":"para","text":"Dịch: Mãi không có xe điện, và chúng tôi quyết định đi bộ về nhà."},{"t":"example","text":"Giải thích: Quyết định thực hiện hành động di chuyển → пойти."},{"t":"para","text":"13. Но когда́ мы ... до сле́дующей остано́вки, из-за угла́ показа́лся трамва́й.","b":1},{"t":"subhead","text":"Đáp án: дошли́","b":1},{"t":"para","text":"Dịch: Nhưng khi chúng tôi đi bộ đến trạm tiếp theo, thì xe điện xuất hiện từ sau góc phố."},{"t":"example","text":"Giải thích: Đi bộ đến một mốc cụ thể → дошли (do-)."},{"t":"para","text":"14. Мы ... в него́ и ... .","b":1},{"t":"subhead","text":"Đáp án: вошли́ (hoặc се́ли); пое́хали"},{"t":"para","text":"Dịch: Chúng tôi lên (vào) xe và đi."},{"t":"para","text":"15. Наро́ду бы́ло немно́го, мы ... в середи́ну ваго́на и се́ли.","b":1},{"t":"subhead","text":"Đáp án: прошли́","b":1},{"t":"para","text":"Dịch: Vắng người, chúng tôi đi vào (băng qua) giữa toa và ngồi xuống."},{"t":"example","text":"Giải thích: Di chuyển qua không gian nội bộ toa xe → прошли."},{"t":"para","text":"16. Когда́ мы ... ми́мо ста́нции метро́, ... си́льный дождь.","b":1},{"t":"subhead","text":"Đáp án: проезжа́ли; пошёл"},{"t":"para","text":"Dịch: Khi chúng tôi đang đi xe ngang qua ga tàu điện ngầm, thì trời đổ (bắt đầu) mưa to."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Đi xe ngang qua (quá trình) → проезжали."},{"t":"example","text":"Mưa bắt đầu rơi → пошёл дождь."},{"t":"para","text":"17. К сча́стью, у нас в су́мке бы́ли зо́нтики, кото́рые, как оказа́лось, мы не зря ... с собо́й весь ве́чер.","b":1},{"t":"subhead","text":"Đáp án: проноси́ли (hoặc носи́ли)"},{"t":"para","text":"Dịch: May thay, trong túi có ô, hóa ra chúng tôi đã không uổng công mang theo suốt cả buổi tối."},{"t":"example","text":"Giải thích: Mang theo bên mình trong một khoảng thời gian dài → проносили (nhấn mạnh tính liên tục/hoàn thành thời gian) hoặc носили (mang vác thông thường)."},{"t":"para","text":"18. Мы ... из трамва́я и ... к до́му.","b":1},{"t":"subhead","text":"Đáp án: вы́шли; побежа́ли (hoặc пошли́)"},{"t":"para","text":"Dịch: Chúng tôi xuống (ra khỏi) xe điện và chạy về nhà (vì trời mưa)."},{"t":"example","text":"Giải thích: Ra khỏi xe → вышли. Trời mưa nên thường sẽ побежали (bắt đầu chạy) hoặc пошли (đi nhanh)."},{"t":"para","text":"19. Дождь бы́стро ... .","b":1},{"t":"subhead","text":"Đáp án: прошёл","b":1},{"t":"para","text":"Dịch: Cơn mưa nhanh chóng qua đi (tạnh)."},{"t":"example","text":"Giải thích: Mưa tạnh/hết → дождь прошёл."},{"t":"para","text":"20. Дово́льные, мы ... до до́ма, подняли́сь на пя́тый эта́ж и позвони́ли.","b":1},{"t":"subhead","text":"Đáp án: добежа́ли / дошли́","b":1},{"t":"para","text":"Dịch: Hài lòng, chúng tôi đã chạy/đi về đến tận nhà, lên tầng 5 và bấm chuông."},{"t":"example","text":"Giải thích: Đến đích (cổng nhà) → до- (добежали/дошли)."},{"t":"para","text":"21. Дверь откры́ла моя́ ба́бушка и поинтересова́лась, хорошо́ ли мы ... ве́чер.","b":1},{"t":"subhead","text":"Đáp án: провели́","b":1},{"t":"para","text":"Dịch: Bà tôi mở cửa và hỏi thăm xem chúng tôi đã có (trải qua) một buổi tối vui vẻ không."},{"t":"example","text":"Giải thích: Провести́ время/вечер = dành thời gian/trải qua buổi tối."},{"t":"para","text":"22. Мы ... в кварти́ру, разде́лись, вы́пили ча́ю, а зате́м я ... свои́х друзе́й до гости́ницы.","b":1},{"t":"subhead","text":"Đáp án: вошли́; проводи́л"},{"t":"para","text":"Dịch: Chúng tôi vào căn hộ, thay đồ, uống trà, và sau đó tôi tiễn (đưa) các bạn về khách sạn."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Vào nhà → вошли."},{"t":"example","text":"Tiễn ai đó đến đâu → проводил."},{"t":"para","text":"Глаго́лы движе́ния с приста́вками под-, от-; с-","b":1},{"t":"example","text":"(Động từ chuyển động với các tiền tố pod-, ot-; s-)"},{"t":"para","text":"Ý nghĩa cơ bản của các tiền tố:","b":1},{"t":"vocab","ru":"Под- (подо-)","vi":"Chuyển động đến gần (tiếp cận), thường đi với giới từ к.","g":null},{"t":"vocab","ru":"От- (ото-)","vi":"Chuyển động rời xa một khoảng ngắn hoặc tách rời khỏi vật gì đó, thường đi với giới từ от.","g":null},{"t":"vocab","ru":"С- (со-)","vi":"Chuyển động từ trên xuống dưới (xuống dốc, xuống xe), hoặc rời khỏi bề mặt, thường đi với giới từ с.","g":null}]},{"id":"07-s135","type":"exercise","title":"Bài 634 (Trang 338-339)","num":634,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложе́ния. Определи́те значе́ние вы́деленных глаго́лов движе́ния с приста́вками. Назови́те инфинити́вы, от кото́рых они́ образо́ваны. (Đọc các câu. Xác định ý nghĩa của các động từ chuyển động có tiền tố được in đậm. Gọi tên động từ nguyên mẫu mà từ đó chúng được tạo thành)."},{"t":"para","text":"a) Tiền tố ПОД- (Đến gần)","b":1},{"t":"vocab","ru":"Подойди́, пожа́луйста, ко мне. Посмотри́","vi":"челове́к, кото́рый подхо́дит к кио́ску, — Па́вел Ви́кторович.","g":null},{"t":"vocab","ru":"подойди́ (từ идти́ - hoàn thành, mệnh lệnh)","vi":"Hãy lại gần.","g":null},{"t":"example","text":"Dịch: Làm ơn lại gần tôi."},{"t":"vocab","ru":"подхо́дит (từ ходи́ть - chưa hoàn thành)","vi":"Đang đi lại gần.","g":null},{"t":"example","text":"Dịch: Nhìn kìa: người đàn ông đang tiến lại gần ki-ốt là Pavel Viktorovich."},{"t":"example","text":"2. Маши́на подъе́хала к тротуа́ру и останови́лась. Обы́чно авто́бус подъезжа́ет к са́мой остано́вке.","b":1},{"t":"vocab","ru":"подъе́хала (từ е́хать - hoàn thành)","vi":"Đã lái xe đến gần.","g":null},{"t":"example","text":"Dịch: Chiếc ô tô đã tiến sát lề đường và dừng lại."},{"t":"vocab","ru":"подъезжа́ет (từ е́здить - chưa hoàn thành)","vi":"Lái đến gần (thường xuyên).","g":null},{"t":"example","text":"Dịch: Thông thường xe buýt đỗ sát (tiến vào) ngay bến."},{"t":"example","text":"3. Сади́сь, я подвезу́ тебя́ до институ́та. Э́тот авто́бус обы́чно подво́зит дете́й до шко́лы.","b":1},{"t":"vocab","ru":"подвезу́ (từ везти́ - hoàn thành)","vi":"Sẽ chở đến (tiện đường/cho đi nhờ).","g":null},{"t":"example","text":"Dịch: Lên xe đi, tớ sẽ chở cậu đến học viện."},{"t":"vocab","ru":"подво́зит (từ вози́ть - chưa hoàn thành)","vi":"Chở đến.","g":null},{"t":"example","text":"Dịch: Xe buýt này thường đưa đón (chở) trẻ em đến trường."},{"t":"example","text":"4. Подгони́, пожа́луйста, маши́ну бли́же к до́му. Не подгоня́й меня́, я успе́ю всё сде́лать во́время.","b":1},{"t":"vocab","ru":"подгони́ (từ гнать - hoàn thành)","vi":"Lái xe/điều khiển phương tiện đến gần.","g":null},{"t":"example","text":"Dịch: Làm ơn đánh (lái) xe lại gần nhà hơn chút."},{"t":"vocab","ru":"подгоня́й (từ гоня́ть - chưa hoàn thành)","vi":"Thúc giục (nghĩa bóng).","g":null},{"t":"example","text":"Dịch: Đừng có thúc giục tôi, tôi sẽ làm xong mọi thứ đúng hạn."},{"t":"para","text":"b) Tiền tố ОТ- (Rời ra xa/Tách ra)","b":1},{"t":"example","text":"1. От гру́ппы студе́нтов отошёл молодо́й челове́к и протяну́л мне конве́рт. Чем да́льше, тем бо́льше мы отхо́дим от ста́рых привы́чек.","b":1},{"t":"vocab","ru":"отошёл (từ идти́ - hoàn thành)","vi":"Bước tách ra/Rời ra một chút.","g":null},{"t":"example","text":"Dịch: Một chàng trai trẻ tách khỏi (bước ra từ) nhóm sinh viên và đưa cho tôi một chiếc phong bì."},{"t":"vocab","ru":"отхо́дим (từ ходи́ть - chưa hoàn thành)","vi":"Rời bỏ/từ bỏ (nghĩa bóng).","g":null},{"t":"example","text":"Dịch: Càng ngày chúng ta càng từ bỏ (rời xa) những thói quen cũ."},{"t":"subhead","text":"Gợi ý ngữ pháp trong khung (Trang 339):","b":1},{"t":"example","text":"Глаголы движения с приставкой от- (ото-) (Động từ chuyển động với tiền tố ot-/oto-) mang ý nghĩa di chuyển ra xa một khoảng cách không lớn (отойти́ на не́сколько шаго́в - lùi lại vài bước) hoặc di chuyển ra xa khỏi vật thể (отойти́ от окна́ - đi ra xa cửa sổ)."},{"t":"para","text":"Chúng trái nghĩa với động từ có tiền tố под- (подо-) (đến gần)."},{"t":"example","text":"2. Нам на́до отплы́ть от бе́рега на большо́е расстоя́ние. Когда́ мы отплыва́ли, на берегу́ показа́лся ещё оди́н уча́стник экспеди́ции.","b":1},{"t":"vocab","ru":"отплы́ть (từ плыть - hoàn thành)","vi":"Bơi/đi thuyền ra xa.","g":null},{"t":"example","text":"Dịch: Chúng ta cần bơi (chèo thuyền) ra xa khỏi bờ một khoảng lớn."},{"t":"vocab","ru":"отплыва́ли (từ пла́вать - chưa hoàn thành)","vi":"Đang bơi/rời bến ra xa.","g":null},{"t":"example","text":"Dịch: Khi chúng tôi đang rời bến, trên bờ xuất hiện thêm một thành viên nữa của đoàn thám hiểm."},{"t":"example","text":"3. Я до́лжен отнести́ ве́щи в ка́меру хране́ния. Не на́до относи́ть докуме́нты, мне они́ ещё понадо́бятся.","b":1},{"t":"vocab","ru":"отнести́ (từ нести́ - hoàn thành)","vi":"Mang đi (đến chỗ khác).","g":null},{"t":"example","text":"Dịch: Tôi phải mang đồ đến phòng giữ hành lý."},{"t":"vocab","ru":"относи́ть (từ носи́ть - chưa hoàn thành)","vi":"Mang đi.","g":null},{"t":"example","text":"Dịch: Đừng mang tài liệu đi, tôi vẫn còn cần chúng."},{"t":"example","text":"4. Отведи́ его́, пожа́луйста, на пе́рвый эта́ж и покажи́, где нахо́дится столо́вая. Ду́маю, он что́-то скрыва́ет: во вре́мя разгово́ра со мной он всё вре́мя отводи́л глаза́ в сто́рону.","b":1},{"t":"vocab","ru":"отведи́ (từ вести́ - hoàn thành)","vi":"Dẫn đi.","g":null},{"t":"example","text":"Dịch: Làm ơn dẫn cậu ấy xuống tầng 1 và chỉ cho cậu ấy nhà ăn ở đâu."},{"t":"vocab","ru":"отводи́л (từ води́ть - chưa hoàn thành)","vi":"Lảng tránh (ánh mắt).","g":null},{"t":"example","text":"Dịch: Tôi nghĩ cậu ta đang giấu giếm điều gì đó: trong lúc nói chuyện với tôi, cậu ta cứ lảng (đưa) mắt sang hướng khác."},{"t":"para","text":"в) Tiền tố С- (Xuống dưới / Rời khỏi bề mặt)","b":1},{"t":"example","text":"1. На э́том ме́сте в про́шлом году́ това́рный по́езд сошёл с ре́льсов. Мы наблюда́ли, как сне́жная лави́на ме́дленно сходи́ла с горы́.","b":1},{"t":"vocab","ru":"сошёл (từ идти́ - hoàn thành)","vi":"Trật bánh/Rời khỏi.","g":null},{"t":"example","text":"Dịch: Tại chỗ này năm ngoái một đoàn tàu chở hàng đã trật bánh (khỏi đường ray)."},{"t":"vocab","ru":"сходи́ла (từ ходи́ть - chưa hoàn thành)","vi":"Đổ xuống/Trôi xuống.","g":null},{"t":"example","text":"Dịch: Chúng tôi quan sát trận tuyết lở chầm chậm đổ xuống từ ngọn núi."},{"t":"example","text":"2. Пожа́луйста, сходи́ в магази́н за хле́бом. Мы съе́хали с доро́ги и останови́лись на обо́чине. Когда́ мы съезжа́ли, навстре́чу нам попа́лся зелёный грузови́к.","b":1},{"t":"vocab","ru":"сходи́ (từ ходи́ть - hoàn thành, nghĩa đặc biệt)","vi":"Đi đến đâu đó rồi về (tương đương пойти и вернуться). Lưu ý: Đây không phải nghĩa \"xuống\", mà là nghĩa \"đi một chuyến\".","g":null},{"t":"example","text":"Dịch: Làm ơn chạy (đi) ra cửa hàng mua bánh mì giúp."},{"t":"vocab","ru":"съе́хали (từ е́хать - hoàn thành)","vi":"Lái xe rời khỏi/xuống.","g":null},{"t":"example","text":"Dịch: Chúng tôi đã lái xe tách (rời) khỏi đường chính và dừng lại ở lề đường."},{"t":"vocab","ru":"съезжа́ли (từ е́здить - chưa hoàn thành)","vi":"Đang lái xe xuống/rời khỏi.","g":null},{"t":"example","text":"Dịch: Khi chúng tôi đang lái xe xuống/tách ra, chúng tôi gặp một chiếc xe tải màu xanh đi ngược chiều."},{"t":"subhead","text":"Gợi ý ngữ pháp trong khung (Trang 339):","b":1},{"t":"para","text":"Глаголы движения с приставкой с- (со-) (Động từ chuyển động với tiền tố s-/so-) đi với danh từ trả lời cho câu hỏi откуда? (từ đâu?), kết hợp với giới từ с (từ bề mặt)."},{"t":"example","text":"Ví dụ: сойти́ с по́езда (xuống tàu), слете́ть с де́рева (bay xuống từ cây)."},{"t":"example","text":"3. На сле́дующей неде́ле я хочу́ съе́здить в Но́вгород. С де́рева слете́ла пти́ца и опусти́лась ря́дом со мной на скаме́йку. Парк опусте́л, после́дние жёлтые ли́стья слета́ли с дере́вьев под напо́ром ве́тра.","b":1},{"t":"vocab","ru":"съе́здить (từ е́здить - hoàn thành)","vi":"Đi một chuyến (bằng xe) rồi về.","g":null},{"t":"example","text":"Dịch: Tuần sau tôi muốn đi (chơi/thăm) Novgorod một chuyến."},{"t":"vocab","ru":"слете́ла (từ лете́ть - hoàn thành)","vi":"Bay xuống/Bay rời khỏi.","g":null},{"t":"example","text":"Dịch: Một con chim bay xuống từ trên cây và đậu xuống băng ghế cạnh tôi."},{"t":"vocab","ru":"слета́ли (từ лета́ть - chưa hoàn thành)","vi":"Rụng xuống/Bay xuống.","g":null},{"t":"example","text":"Dịch: Công viên vắng tanh, những chiếc lá vàng cuối cùng rụng (bay) xuống từ cây dưới sức ép của gió."}]},{"id":"07-s136","type":"exercise","title":"Bài 635 (Trang 339-340)","num":635,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме один из глаголов движения с приставкой: а) под-(подо-) или при-; б) от-(ото-) или у-. Вместо точек вставьте необходимый по смыслу предлог. (Mở ngoặc đơn, sử dụng một trong các động từ chuyển động với tiền tố ở dạng thích hợp: a) pod-/podo- hoặc pri-; b) ot-/oto- hoặc u-. Thay dấu ba chấm bằng giới từ cần thiết theo ý nghĩa)."},{"t":"subhead","text":"Phân biệt:","b":1},{"t":"vocab","ru":"Под- + к","vi":"Đến gần, tiếp cận (chưa chắc đã vào trong).","g":null},{"t":"vocab","ru":"При- + в/на/к","vi":"Đến đích (kết thúc hành trình, thường là vào trong hoặc đến nơi).","g":null},{"t":"vocab","ru":"От- + от","vi":"Rời ra xa một chút, tách ra.","g":null},{"t":"vocab","ru":"У- + из/с","vi":"Rời đi hẳn, đi mất (vắng mặt).","g":null},{"t":"para","text":"a) Под- hay При-?","b":1},{"t":"para","text":"1. Когда́ мы (е́хать/е́здить) ... (дом), я издалека́ уви́дел стоя́щую на крыльце́ ба́бушку.","b":1},{"t":"subhead","text":"Đáp án: подъезжа́ли к до́му","b":1},{"t":"para","text":"Dịch: Khi chúng tôi đang lái xe đến gần nhà, từ xa tôi đã thấy bà đang đứng trên bậc thềm."},{"t":"example","text":"Giải thích: Hành động đang diễn ra (chưa đến nơi hẳn) và nhìn thấy từ xa → подъезжали к."},{"t":"para","text":"2. (Нести́/Носи́ть) ... (я), пожа́луйста, ру́чку и захвати́ лист бума́ги.","b":1},{"t":"subhead","text":"Đáp án: Принеси́ мне","b":1},{"t":"para","text":"Dịch: Làm ơn mang (lấy) cho tôi cái bút và cầm theo tờ giấy."},{"t":"example","text":"Giải thích: Yêu cầu mang vật đến cho người nói (đến đích) → принеси. (Dùng мне không cần giới từ)."},{"t":"para","text":"3. Она́ подняла́ упа́вшую ле́стницу, (тащи́ть/таска́ть) её ... (окно́) и вле́зла на черда́к.","b":1},{"t":"subhead","text":"Đáp án: подтащи́ла к окну́ (hoặc приставила nhưng đề bài yêu cầu động từ chuyển động тащить)"},{"t":"para","text":"Dịch: Cô ấy dựng cái thang bị đổ lên, kéo nó đến (gần) cửa sổ và leo lên gác mái."},{"t":"example","text":"Giải thích: Kéo vật đến gần vị trí để sử dụng → подтащила к."},{"t":"para","text":"4. Не сто́ит сли́шком суро́во (идти́/ходи́ть) ... (оце́нка) э́той рабо́ты.","b":1},{"t":"subhead","text":"Đáp án: подходи́ть к оце́нке","b":1},{"t":"para","text":"Dịch: Không nên tiếp cận (đánh giá) công việc này quá khắt khe."},{"t":"example","text":"Giải thích: Cụm từ подходи́ть к (tiếp cận vấn đề/đánh giá)."},{"t":"para","text":"5. Ве́чером, когда́ он (е́хать/е́здить) ... (рабо́та), де́ти броса́лись к нему́ с ра́достным кри́ком.","b":1},{"t":"subhead","text":"Đáp án: приезжа́л с рабо́ты","b":1},{"t":"para","text":"Dịch: Buổi tối, khi anh ấy đi làm về, lũ trẻ lao tới chỗ anh với tiếng reo hò vui sướng."},{"t":"example","text":"Giải thích: Hành động trở về nhà từ nơi làm việc → приезжал."},{"t":"para","text":"6. Каки́е оце́нки ты сего́дня (нести́/носи́ть) ... (шко́ла)?","b":1},{"t":"subhead","text":"Đáp án: принёс из шко́лы","b":1},{"t":"para","text":"Dịch: Hôm nay con mang điểm số nào từ trường về thế?"},{"t":"example","text":"Giải thích: Mang về nhà (đích đến) → принёс."},{"t":"para","text":"7. Помоги́ мне, пожа́луйста, (тащи́ть/таска́ть) су́мку ... (ваго́н).","b":1},{"t":"subhead","text":"Đáp án: подтащи́ть к ваго́ну (hoặc дотащить до)"},{"t":"para","text":"Dịch: Làm ơn giúp tôi kéo cái túi đến (sát) toa tàu."},{"t":"example","text":"Giải thích: Di chuyển vật nặng đến gần phương tiện → подтащить к."},{"t":"para","text":"8. Он разверну́л маши́ну и (е́хать/е́здить) ... (пара́дная).","b":1},{"t":"subhead","text":"Đáp án: подъе́хал к пара́дной","b":1},{"t":"para","text":"Dịch: Anh ấy quay xe và lái đến (đỗ trước) cổng chính."},{"t":"example","text":"Giải thích: Lái xe tiếp cận cổng vào → подъехал к."},{"t":"para","text":"9. По́езд (идти́/ходи́ть) ... (ста́нция), из него́ на́чали выходи́ть лю́ди.","b":1},{"t":"subhead","text":"Đáp án: подошёл к ста́нции (hoặc прибыл на станцию, пришёл на станцию)"},{"t":"para","text":"Dịch: Đoàn tàu cập bến (tiến vào ga), mọi người bắt đầu bước ra."},{"t":"example","text":"Giải thích: Với tàu bè vào bến, thường dùng подойти к платформе/станции (tiến vào/cập bến). Sách Glazunova thường ưu tiên sự đối lập под- (đến gần/cập vào) trong ngữ cảnh này."},{"t":"para","text":"10. На Рождество́ ... (мы) (е́хать/е́здить) ро́дственники из Смоле́нска.","b":1},{"t":"subhead","text":"Đáp án: к нам прие́хали","b":1},{"t":"para","text":"Dịch: Vào lễ Giáng sinh, họ hàng từ Smolensk đã đến chỗ chúng tôi."},{"t":"example","text":"Giải thích: Khách đến thăm (đến đích) → приехали."},{"t":"para","text":"11. Пти́цы (лете́ть/лета́ть) ... (окно́), сади́лись на подоко́нник, стуча́ли клю́вами в стекло́.","b":1},{"t":"subhead","text":"Đáp án: подлета́ли к окну́","b":1},{"t":"para","text":"Dịch: Những con chim bay đến cửa sổ, đậu lên bệ cửa và gõ mỏ vào kính."},{"t":"example","text":"Giải thích: Bay đến gần → подлетали к."},{"t":"para","text":"12. Не волну́йся, он до́лжен (е́хать/е́здить) ... (два часа́).","b":1},{"t":"subhead","text":"Đáp án: прие́хать к двум часа́м","b":1},{"t":"para","text":"Dịch: Đừng lo, anh ấy sẽ đến trước hai giờ."},{"t":"example","text":"Giải thích: Đến nơi (đích) vào thời điểm cụ thể → приехать."},{"t":"para","text":"13. Когда́ зазвуча́ла му́зыка, он (идти́/ходи́ть) ... (она́) и пригласи́л её на та́нец.","b":1},{"t":"subhead","text":"Đáp án: подошёл к ней","b":1},{"t":"para","text":"Dịch: Khi nhạc nổi lên, anh ấy tiến lại gần cô ấy và mời nhảy."},{"t":"example","text":"Giải thích: Tiếp cận người khác để mời → подошёл к."},{"t":"para","text":"b) От- hay У-?","b":1},{"t":"para","text":"1. Кот зашипе́л и был гото́в вцепи́ться в своего́ оби́дчика, мне пришло́сь (тащи́ть/таска́ть) его́ пода́льше.","b":1},{"t":"subhead","text":"Đáp án: оттащи́ть","b":1},{"t":"para","text":"Dịch: Con mèo rít lên và sẵn sàng lao vào kẻ xúc phạm nó, tôi đành phải lôi nó ra xa."},{"t":"example","text":"Giải thích: Kéo ra một khoảng cách an toàn (vẫn ở đó) → оттащить."},{"t":"para","text":"2. Все гру́стные мы́сли то́тчас (лете́ть/лета́ть) ... (он) прочь.","b":1},{"t":"subhead","text":"Đáp án: отлете́ли от него́","b":1},{"t":"para","text":"Dịch: Mọi suy nghĩ buồn bã ngay lập tức bay biến khỏi anh ấy."},{"t":"example","text":"Giải thích: Tách rời khỏi chủ thể → отлетели от."},{"t":"para","text":"3. Была́ глубо́кая о́сень, пти́цы давно́ (лете́ть/лета́ть) ... (юг).","b":1},{"t":"subhead","text":"Đáp án: улете́ли на юг","b":1},{"t":"para","text":"Dịch: Đã là cuối thu, chim chóc đã bay đi phương Nam từ lâu."},{"t":"example","text":"Giải thích: Bay đi xa, di cư hẳn → улетели."},{"t":"para","text":"4. По утра́м на траве́ серебри́лся и́ней; он (гнать/гоня́ть) велосипе́д ... (доро́га) и прислони́л его́ к забо́ру.","b":1},{"t":"subhead","text":"Đáp án: отогна́л ... от доро́ги","b":1},{"t":"para","text":"Dịch: Buổi sáng sương muối lấp lánh trên cỏ; anh ấy dắt xe đạp ra xa đường và dựa nó vào hàng rào."},{"t":"example","text":"Giải thích: Dời phương tiện ra khỏi vị trí cũ một đoạn ngắn → отогнал от."},{"t":"para","text":"5. Ты до́лжен (везти́/вози́ть) меня́ отсю́да, ни мину́ты не хочу́ здесь остава́ться.","b":1},{"t":"subhead","text":"Đáp án: увезти́","b":1},{"t":"para","text":"Dịch: Anh phải chở (đưa) em đi khỏi đây, em không muốn ở lại đây thêm một phút nào nữa."},{"t":"example","text":"Giải thích: Đưa đi hẳn nơi khác → увезти."},{"t":"para","text":"6. Чита́ет он день и ночь напролёт, его́ от кни́жки не (тащи́ть/таска́ть) ника́кими си́лами.","b":1},{"t":"subhead","text":"Đáp án: оттащи́ть","b":1},{"t":"para","text":"Dịch: Cậu ta đọc sách suốt ngày đêm, không sức nào lôi cậu ta ra khỏi cuốn sách được."},{"t":"example","text":"Giải thích: Tách ai đó ra khỏi vật gì → оттащить."},{"t":"para","text":"7. Он уже́ давно́ (идти́/ходи́ть) ... (де́ла), лет пять как (идти́/ходи́ть) ... (пе́нсия).","b":1},{"t":"subhead","text":"Đáp án: отошёл от дел; ушёл на пе́нсию"},{"t":"para","text":"Dịch: Ông ấy đã rửa tay gác kiếm (xa rời công việc) từ lâu, đã về hưu được 5 năm rồi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Отойти от дел","vi":"Thành ngữ chỉ việc ngừng tham gia điều hành/kinh doanh.","g":null},{"t":"vocab","ru":"Уйти на пенсию","vi":"Về hưu (trạng thái thay đổi hoàn toàn cuộc sống).","g":null},{"t":"para","text":"8. То́лько мы (е́хать/е́здить) ... (дом), как пошёл дождь.","b":1},{"t":"subhead","text":"Đáp án: отъе́хали от до́ма","b":1},{"t":"para","text":"Dịch: Chúng tôi vừa mới lái xe ra khỏi nhà (được một đoạn) thì trời mưa."},{"t":"example","text":"Giải thích: Rời khỏi mốc xuất phát một khoảng ngắn → отъехали от."},{"t":"para","text":"9. Я ду́маю, сейча́с тебе́ лу́чше (идти́/ходи́ть).","b":1},{"t":"subhead","text":"Đáp án: уйти́","b":1},{"t":"para","text":"Dịch: Tôi nghĩ bây giờ tốt hơn hết là bạn nên về (rời đi) đi."},{"t":"example","text":"Giải thích: Rời khỏi nơi này → уйти."},{"t":"para","text":"10. Мяч (лете́ть/лета́ть) ... (шта́нга) и упа́л к нога́м вратаря́.","b":1},{"t":"subhead","text":"Đáp án: отлете́л от шта́нги","b":1},{"t":"para","text":"Dịch: Quả bóng nảy ra (bay dội lại) từ cột dọc và rơi xuống chân thủ môn."},{"t":"example","text":"Giải thích: Va vào và bật ra → отлетел от."},{"t":"vocab","ru":"Признава́йтесь","vi":"кто (тащи́ть/таска́ть) ... (моя́ ру́чка)?","g":null},{"t":"subhead","text":"Đáp án: утащи́л мою́ ру́чку","b":1},{"t":"para","text":"Dịch: Khai thật đi: ai đã chôm (lấy mất) bút của tôi rồi?"},{"t":"example","text":"Giải thích: Lấy đi mất (thường mang nghĩa trộm vặt/giấu đi) → утащил."},{"t":"para","text":"12. У́тром (везти́/вози́ть) дете́й ... (шко́ла) и не забу́дь сходи́ть в магази́н.","b":1},{"t":"subhead","text":"Đáp án: отвези́ ... в шко́лу","b":1},{"t":"para","text":"Dịch: Sáng nay hãy chở bọn trẻ đến trường và đừng quên đi chợ nhé."},{"t":"example","text":"Giải thích: Chở ai đến đích rồi mình đi làm việc khác (thả xuống) → отвези (gốc от- mang nghĩa đưa đến đích rồi rời đi, hoặc tách con cái ra khỏi nhà để đưa đi). Lưu ý: Увези có nghĩa là chở đi xa (ví dụ đi nghỉ hè), còn đưa đi học hàng ngày dùng отвези."},{"t":"para","text":"13. По́сле та́нца он (вести́/води́ть) её на ме́сто.","b":1},{"t":"subhead","text":"Đáp án: отвёл","b":1},{"t":"para","text":"Dịch: Sau điệu nhảy, anh ấy đưa cô ấy về chỗ ngồi."},{"t":"example","text":"Giải thích: Dẫn ai đó rời khỏi sàn nhảy về chỗ cũ → отвёл."}]},{"id":"07-s137","type":"exercise","title":"Bài 636 (Trang 340)","num":636,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме один из глаголов движения с приставкой с- или от-. (Mở ngoặc đơn, sử dụng dạng cần thiết của một trong các động từ chuyển động với tiền tố с- hoặc от-)."},{"t":"subhead","text":"Gợi ý ngữ pháp quan trọng:","b":1},{"t":"vocab","ru":"Tiền tố С- + Động từ đa chiều (ходить, ездить...)","vi":"Mang nghĩa đi đến đâu đó rồi quay lại ngay (khứ hồi/đi một chuyến).","g":null},{"t":"example","text":"Ví dụ: сходи́ть в магази́н (chạy ra cửa hàng - rồi về)."},{"t":"vocab","ru":"Tiền tố ОТ-","vi":"Mang nghĩa đưa/mang ai hoặc cái gì rời khỏi chỗ này đến chỗ khác (thường nhấn mạnh chiều đi).","g":null},{"t":"example","text":"Ví dụ: отнести́ письмо́ (mang thư đi gửi)."},{"t":"para","text":"Giải chi tiết:","b":1},{"t":"para","text":"1. Сего́дня я до́лжен (идти́/ходи́ть) в ко́нсульство забра́ть па́спорт.","b":1},{"t":"subhead","text":"Đáp án: сходи́ть (từ ходи́ть)"},{"t":"para","text":"Dịch: Hôm nay tôi phải chạy (đi) đến lãnh sự quán để lấy hộ chiếu."},{"t":"example","text":"Giải thích: Nghĩa là đi đến đó, lấy xong rồi về → dùng с- + động từ đa chiều."},{"t":"para","text":"2. По́сле рабо́ты мне придётся (нести́/носи́ть) в химчи́стку зи́мние ве́щи.","b":1},{"t":"subhead","text":"Đáp án: отнести́ (từ нести́)"},{"t":"para","text":"Dịch: Sau giờ làm, tôi sẽ phải mang đồ mùa đông đến tiệm giặt khô."},{"t":"example","text":"Giải thích: Mang vật từ chỗ này đến chỗ khác (đích đến là tiệm giặt) → dùng от-."},{"t":"para","text":"3. (Бежа́ть/Бе́гать), пожа́луйста, посмотри́, кто пришёл.","b":1},{"t":"subhead","text":"Đáp án: Сбе́гай (từ бе́гать)"},{"t":"para","text":"Dịch: Em làm ơn chạy ra xem ai đến giúp với."},{"t":"example","text":"Giải thích: Yêu cầu chạy đi xem rồi quay lại báo cáo (hành động ngắn, khứ hồi) → dùng с- + động từ đa chiều."},{"t":"para","text":"4. Не волну́йся, я ми́гом (лете́ть/лета́ть) за хле́бом.","b":1},{"t":"subhead","text":"Đáp án: слётаю (từ лета́ть)"},{"t":"para","text":"Dịch: Đừng lo, tôi sẽ phi (bay) đi mua bánh mì nhoáng cái là về ngay."},{"t":"example","text":"Giải thích: Dùng летать với nghĩa bóng là \"đi rất nhanh\" (đi một loáng rồi về) → dùng с-."},{"t":"para","text":"5. Куда́ мне вас (везти́/вози́ть)?","b":1},{"t":"subhead","text":"Đáp án: отвезти́ (từ везти́)"},{"t":"para","text":"Dịch: Tôi phải chở các bạn đến đâu (thả ở đâu)?"},{"t":"example","text":"Giải thích: Chở khách đến đích → dùng от-."},{"t":"para","text":"6. Я бы́стро (плыть/пла́вать) на друго́й бе́рег и верну́сь.","b":1},{"t":"subhead","text":"Đáp án: спла́ваю (từ пла́вать)"},{"t":"para","text":"Dịch: Tôi sẽ bơi nhanh sang bờ bên kia rồi quay lại."},{"t":"example","text":"Giải thích: Bơi đi rồi về (khứ hồi) → dùng с-."},{"t":"para","text":"7. Тебе́ лу́чше (гнать/гоня́ть) мотоци́кл пода́льше от доро́ги.","b":1},{"t":"subhead","text":"Đáp án: отогна́ть (từ гнать)"},{"t":"para","text":"Dịch: Bạn nên dắt (đánh) xe máy ra xa khỏi đường một chút thì hơn."},{"t":"example","text":"Giải thích: Di chuyển phương tiện ra xa vật mốc (đường) → dùng от-."},{"t":"para","text":"8. Мы мо́жем (идти́/ходи́ть) на вы́ставку по́зже.","b":1},{"t":"subhead","text":"Đáp án: сходи́ть (từ ходи́ть)"},{"t":"para","text":"Dịch: Chúng ta có thể đi (thăm) triển lãm sau."},{"t":"example","text":"Giải thích: Đi xem triển lãm (đi chơi một chuyến) → dùng с-."},{"t":"para","text":"9. Е́сли в воскресе́нье всей семьёй (е́хать/е́здить) за́ город. (Câu này trong sách có thể là câu điều kiện hoặc rủ rê, tùy ấn bản có thể yêu cầu điền infinitive hoặc tương lai)."},{"t":"subhead","text":"Đáp án: съе́здить (hoặc съе́здим)"},{"t":"para","text":"Dịch: Nếu Chủ nhật cả nhà cùng đi (chơi) ngoại ô."},{"t":"example","text":"Giải thích: Đi chơi xa rồi về → dùng с- + động từ đa chiều (съездить)."},{"t":"para","text":"10. Дава́й я (нести́/носи́ть) э́то письмо́ на по́чту.","b":1},{"t":"subhead","text":"Đáp án: отнесу́ (từ нести́)"},{"t":"para","text":"Dịch: Để tôi mang lá thư này ra bưu điện cho."},{"t":"example","text":"Giải thích: Mang vật đi gửi (rời khỏi đây đến đích) → dùng от-."},{"t":"para","text":"11. Я прошу́ тебя́ (нести́/носи́ть) э́ту кни́гу в библиоте́ку.","b":1},{"t":"subhead","text":"Đáp án: отнести́ (từ нести́)"},{"t":"para","text":"Dịch: Mình nhờ bạn mang (trả) cuốn sách này đến thư viện."},{"t":"example","text":"Giải thích: Mang đi trả → dùng от-."},{"t":"para","text":"12. У́тром (везти́/вози́ть) дете́й в шко́лу и не забу́дь сходи́ть в магази́н.","b":1},{"t":"subhead","text":"Đáp án: отвези́ (từ везти́)"},{"t":"para","text":"Dịch: Sáng này hãy chở bọn trẻ đến trường và đừng quên đi chợ nhé."},{"t":"example","text":"Giải thích: Chở đến đích (trường) → dùng от-."},{"t":"para","text":"13. Андре́я к телефо́ну? Я могу́ за ним (бежа́ть/бе́гать).","b":1},{"t":"subhead","text":"Đáp án: сбе́гать (từ бе́гать)"},{"t":"para","text":"Dịch: (Gọi) Andrey nghe điện thoại à? Để tôi chạy (ù) đi gọi cậu ấy."},{"t":"example","text":"Giải thích: Chạy đi gọi rồi quay lại chỗ điện thoại → dùng с-."},{"t":"para","text":"14. У́тром я (вести́/води́ть) ребёнка в де́тский сад и пое́хал на рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: отвёл (từ вести́)"},{"t":"para","text":"Dịch: Sáng nay tôi đã đưa con đến nhà trẻ rồi đi làm."},{"t":"example","text":"Giải thích: Dẫn con đến lớp (đích đến) → dùng от-."},{"t":"para","text":"15. В суббо́ту он обеща́л (везти́/вози́ть) нас в кино́.","b":1},{"t":"subhead","text":"Đáp án: свози́ть (từ вози́ть) hoặc отвезти́."},{"t":"para","text":"Dịch: Thứ Bảy anh ấy hứa đưa (chở) chúng tôi đi xem phim."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Свозить","vi":"Chở đi chơi rồi chở về (bao trọn gói chuyến đi). Thường dùng cho đi chơi giải trí.","g":null},{"t":"vocab","ru":"Отвезти","vi":"Chỉ chở đến rạp (rồi tự về hoặc không nói rõ). Trong ngữ cảnh hứa hẹn đi chơi, свозить rất hay dùng. Tuy nhiên, отвезти cũng chấp nhận được.","g":null},{"t":"para","text":"16. Пожа́луйста (идти́/ходи́ть) к врачу́, твой ка́шель начина́ет меня́ беспоко́ить.","b":1},{"t":"subhead","text":"Đáp án: сходи́ (từ ходи́ть)"},{"t":"para","text":"Dịch: Làm ơn đi bác sĩ đi, cái ho của bạn bắt đầu làm tôi lo rồi đấy."},{"t":"example","text":"Giải thích: Đi khám bệnh (rồi về) → dùng с-."},{"t":"subhead","text":"Gợi ý ngữ pháp trước Bài 637 (Trang 341)","b":1},{"t":"para","text":"Tiếng Nga: Замени́те, где мо́жно, глаго́лы движе́ния с приста́вкой с- глаго́лами движе́ния с приста́вкой по-."},{"t":"para","text":"Giải thích sự khác biệt:","b":1},{"t":"vocab","ru":"С- + Động từ đa chiều (ходить, ездить...)","vi":"Đi một chuyến (khứ hồi) rồi đã về hoặc sẽ về. (Ví dụ: съездить - đi rồi về).","g":null},{"t":"vocab","ru":"По- + Động từ một chiều (идти, ехать...)","vi":"Bắt đầu đi (khởi hành) hoặc sẽ đi (đơn thuần chỉ hướng đi).","g":null},{"t":"vocab","ru":"С- + Động từ một chiều (идти, ехать...)","vi":"Đi xuống (xuống núi, xuống cầu thang) hoặc rời khỏi bề mặt.","g":null}]},{"id":"07-s138","type":"exercise","title":"Bài 637 (Trang 341)","num":637,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте в ну́жной фо́рме необходи́мый по смы́слу глаго́л движе́ния. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Thay dấu ba chấm bằng động từ chuyển động cần thiết theo ý nghĩa ở dạng thích hợp. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"a) съе́хать (lái xuống/rời khỏi) / съезжа́ть (đang xuống) / съе́здить (đi một chuyến)","b":1},{"t":"para","text":"1. Дава́й ... на обо́чину и посмо́трим, что случи́лось с за́дним колесо́м.","b":1},{"t":"subhead","text":"Đáp án: съе́дем (từ е́хать)"},{"t":"para","text":"Dịch: Chúng ta hãy tấp (lái xe xuống) vào lề đường và xem chuyện gì xảy ra với bánh sau."},{"t":"example","text":"Giải thích: Rời khỏi lòng đường chính sang lề đường → dùng с- với nghĩa \"xuống/tách ra\"."},{"t":"para","text":"2. Когда́ мы ... с доро́ги, ми́мо нас на большо́й ско́рости пронёсся автомоби́ль.","b":1},{"t":"subhead","text":"Đáp án: съе́хали (đã tấp xong) hoặc съезжа́ли (đang tấp)."},{"t":"para","text":"Dịch: Khi chúng tôi đã tấp (rời) khỏi đường chính, một chiếc ô tô lao vụt qua chúng tôi với tốc độ lớn."},{"t":"para","text":"Giải thích: Rời khỏi mặt đường."},{"t":"para","text":"3. За́втра ты до́лжен ... и купи́ть биле́ты на по́езд.","b":1},{"t":"subhead","text":"Đáp án: съе́здить (từ е́здить)"},{"t":"para","text":"Dịch: Ngày mai bạn phải đi (một chuyến) mua vé tàu."},{"t":"example","text":"Giải thích: Đi mua rồi về → dùng с- + động từ đa chiều."},{"t":"para","text":"b) сойти́ (xuống/rời) / сходи́ть (đang xuống / đi một chuyến)","b":1},{"t":"para","text":"1. Мы ... с горы́ под проливны́м дождём.","b":1},{"t":"subhead","text":"Đáp án: сходи́ли (đang đi xuống) hoặc сошли́ (đã xuống)."},{"t":"para","text":"Dịch: Chúng tôi đã đi xuống núi dưới cơn mưa như trút."},{"t":"example","text":"Giải thích: Đi từ trên cao xuống → dùng с- + động từ gốc идти/ходить với nghĩa \"xuống\"."},{"t":"para","text":"2. ..., пожа́луйста, с мое́й ноги́, ты стои́шь на ней.","b":1},{"t":"subhead","text":"Đáp án: Сойди́ (từ идти́)"},{"t":"para","text":"Dịch: Làm ơn bước xuống (bỏ chân ra) khỏi chân tôi, bạn đang giẫm lên nó đấy."},{"t":"example","text":"Giải thích: Rời khỏi bề mặt (chân người khác) → сойди."},{"t":"para","text":"3. Я ещё вчера́ ... в магази́н и купи́л всё необходи́мое.","b":1},{"t":"subhead","text":"Đáp án: сходи́л (từ ходи́ть)"},{"t":"para","text":"Dịch: Hôm qua tôi đã đi cửa hàng và mua mọi thứ cần thiết rồi."},{"t":"example","text":"Giải thích: Đi một chuyến rồi về → сходил."},{"t":"para","text":"в) сбежа́ть (chạy xuống / chạy trốn) / сбе́гать (chạy một chuyến / chạy trốn)","b":1},{"t":"para","text":"1. Ду́маю, тебе́ не сто́ит за́втра ... с заня́тий, ты мо́жешь встре́титься со свои́ми друзья́ми ве́чером.","b":1},{"t":"subhead","text":"Đáp án: сбега́ть (trốn/chuồn)"},{"t":"para","text":"Dịch: Tôi nghĩ ngày mai bạn không nên trốn (chuồn) học, bạn có thể gặp bạn bè vào buổi tối mà."},{"t":"example","text":"Giải thích: Сбегать с занятий = trốn học (nghĩa bóng của chạy khỏi nơi quy định)."},{"t":"para","text":"2. Дава́йте я ... в апте́ку за лека́рством.","b":1},{"t":"subhead","text":"Đáp án: сбе́гаю (từ бе́гать)"},{"t":"para","text":"Dịch: Để tôi chạy (ù) ra hiệu thuốc mua thuốc cho."},{"t":"example","text":"Giải thích: Chạy đi mua nhanh rồi về → сбегаю."},{"t":"para","text":"3. На ве́чере была́ така́я ску́ка, что мы ... отту́да че́рез полчаса́.","b":1},{"t":"subhead","text":"Đáp án: сбежа́ли (từ бежа́ть)"},{"t":"para","text":"Dịch: Buổi dạ tiệc chán đến mức chúng tôi đã chuồn (trốn/bỏ chạy) khỏi đó sau nửa tiếng."},{"t":"example","text":"Giải thích: Rời đi lén lút/vội vã → сбежали."},{"t":"para","text":"г) слете́ть (bay xuống / bay mất) / слета́ть (bay một chuyến)","b":1},{"t":"para","text":"1. За два дня я ... в Берли́н, Пари́ж и Ло́ндон и верну́лся обра́тно.","b":1},{"t":"subhead","text":"Đáp án: слета́л (từ лета́ть)"},{"t":"para","text":"Dịch: Trong hai ngày tôi đã bay (lượn) qua Berlin, Paris và London rồi quay trở lại."},{"t":"example","text":"Giải thích: Đi máy bay một vòng hành trình → слетал."},{"t":"para","text":"2. Из-за си́льного ве́тра с дере́вьев ... все ли́стья.","b":1},{"t":"subhead","text":"Đáp án: слете́ли (từ лете́ть)"},{"t":"para","text":"Dịch: Do gió mạnh, tất cả lá cây đã bay (rụng) xuống."},{"t":"example","text":"Giải thích: Rời khỏi cành rơi xuống đất → слетели."},{"t":"para","text":"3. Я наблюда́л, как с дере́вьев ... и па́дали на зе́млю разноцве́тные ли́стья.","b":1},{"t":"subhead","text":"Đáp án: слета́ли (từ лета́ть - ở đây là dạng chưa hoàn thành của слететь)"},{"t":"para","text":"Dịch: Tôi quan sát những chiếc lá nhiều màu sắc đang bay (rụng) khỏi cây và rơi xuống đất."},{"t":"example","text":"Giải thích: Miêu tả quá trình lá rụng → слетали."}]},{"id":"07-s139","type":"exercise","title":"Bài 638 (Trang 341-342)","num":638,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложе́ния, обраща́я внима́ние на усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками. Определи́те их значе́ние. (Đọc các câu, chú ý đến các cụm từ cố định với động từ chuyển động có tiền tố. Xác định ý nghĩa của chúng)."},{"t":"para","text":"Giải nghĩa và Dịch:","b":1},{"t":"example","text":"1. Ве́чер подошёл к концу́, го́сти на́чали расходи́ться.","b":1},{"t":"para","text":"Ý nghĩa: Kết thúc, tàn cuộc."},{"t":"para","text":"Dịch: Buổi tối đã đi đến hồi kết, khách khứa bắt đầu ra về."},{"t":"example","text":"2. Дава́йте подведём черту́ под вы́сказанными предложе́ниями. Ита́к, к чему́ мы пришли́?","b":1},{"t":"para","text":"Ý nghĩa: Tổng kết, chốt lại (nghĩa đen: gạch dưới)."},{"t":"para","text":"Dịch: Chúng ta hãy chốt lại (gạch dưới) những ý kiến đã được đưa ra. Tóm lại, chúng ta đã đi đến kết luận gì?"},{"t":"example","text":"3. Ты меня́ подведёшь под монасты́рь со свои́ми сове́тами.","b":1},{"t":"para","text":"Ý nghĩa: Đẩy ai vào tình huống khó khăn, nguy hiểm hoặc bị trừng phạt (nghĩa đen: đưa vào tu viện)."},{"t":"para","text":"Dịch: Cậu sẽ làm tôi khốn đốn (hại tôi thê thảm) với những lời khuyên của cậu đấy."},{"t":"example","text":"4. Тебе́-то ничего́, а вот мне отвеча́ть придётся. Подведи́ часы́, они́ у тебя́ отстаю́т на де́сять мину́т.","b":1},{"t":"para","text":"Ý nghĩa: Chỉnh lại đồng hồ cho đúng giờ."},{"t":"para","text":"Dịch: Cậu thì không sao, nhưng tôi thì phải chịu trách nhiệm. Hãy chỉnh lại đồng hồ đi, nó đang chạy chậm 10 phút đấy."},{"t":"example","text":"5. Да, челове́к он непросто́й, к нему́ так про́сто не подъе́дешь.","b":1},{"t":"para","text":"Ý nghĩa: Khó tiếp cận, khó làm thân hoặc khó nhờ vả."},{"t":"para","text":"Dịch: Ừ, ông ta là người không đơn giản, không dễ mà tiếp cận (làm thân) đâu."},{"t":"example","text":"6. Когда́ он наконе́ц появи́лся в гости́ной, у всех отлегло́ от се́рдца: зна́чит, все подозре́ния бы́ли напра́сны.","b":1},{"t":"para","text":"Ý nghĩa: Cảm thấy nhẹ nhõm, trút được gánh nặng lo âu (nghĩa đen: bong ra khỏi tim)."},{"t":"para","text":"Dịch: Khi cuối cùng anh ấy xuất hiện ở phòng khách, mọi người đều thở phào nhẹ nhõm (nhẹ cả người): nghĩa là mọi nghi ngờ đều vô căn cứ."},{"t":"example","text":"7. Э́ти воспомина́ния уже́ не име́ют на́до мной никако́й си́лы, они́ давно́ отошли́ в про́шлое.","b":1},{"t":"para","text":"Ý nghĩa: Trở thành quá khứ, lùi vào dĩ vãng."},{"t":"para","text":"Dịch: Những ký ức này không còn sức mạnh gì với tôi nữa, chúng đã lùi vào dĩ vãng từ lâu rồi."},{"t":"example","text":"8. Зна́ешь, полго́да уже́ не ел блино́в, а вчера́ отвёл ду́шу, заказа́л себе́ три по́рции.","b":1},{"t":"para","text":"Ý nghĩa: Làm gì đó cho thỏa thích, cho bõ thèm (nghĩa đen: dắt linh hồn đi chơi)."},{"t":"para","text":"Dịch: Biết không, nửa năm rồi tớ không ăn bánh xèo, nhưng hôm qua tớ đã ăn cho đã đời (thỏa thích), gọi hẳn 3 suất."},{"t":"example","text":"9. О́чень тру́дно ду́мать о челове́ке одно́, а говори́ть друго́е, вот я вчера́ и не выде́ржал, отвёл ду́шу: сказа́л Оле́гу всё, что я о нём ду́маю.","b":1},{"t":"para","text":"Ý nghĩa: Trút bầu tâm sự, nói hết nỗi lòng cho nhẹ người."},{"t":"para","text":"Dịch: Thật khó khi nghĩ về một người một đằng mà nói một nẻo, thế nên hôm qua tôi không kìm được nữa, đã xả hết nỗi lòng: nói cho Oleg biết tất cả những gì tôi nghĩ về cậu ta."},{"t":"example","text":"10. На э́тот раз обма́н ему́ с рук не сойдёт, придётся за него́ отве́тить.","b":1},{"t":"para","text":"Ý nghĩa: Không thoát tội, không được bỏ qua (nghĩa đen: không trôi khỏi tay)."},{"t":"para","text":"Dịch: Lần này sự dối trá của hắn sẽ không trót lọt đâu (hắn sẽ không thoát tội đâu), sẽ phải trả giá cho nó."},{"t":"example","text":"11. Он был мои́м лу́чшим дру́гом, но по́сле его́ отъе́зда на́ши отноше́ния постепе́нно сошли́ на нет: мы практи́чески переста́ли обща́ться.","b":1},{"t":"para","text":"Ý nghĩa: Dần biến mất, phai nhạt, trở về con số không."},{"t":"para","text":"Dịch: Cậu ấy từng là bạn thân nhất của tôi, nhưng sau khi cậu ấy đi, quan hệ của chúng tôi dần phai nhạt (tiêu tan): chúng tôi hầu như ngừng liên lạc."},{"t":"example","text":"12. От всех э́тих пробле́м мо́жно сойти́ с ума́!","b":1},{"t":"para","text":"Ý nghĩa: Phát điên, mất trí."},{"t":"para","text":"Dịch: Có thể phát điên vì tất cả những vấn đề này mất!"}]},{"id":"07-s140","type":"exercise","title":"Bài 639 (Trang 342)","num":639,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками от-(ото-), под-(подо-), с-(со-), к вы́деленным словосочета́ниям подбери́те сино́нимы. (Sử dụng các cụm từ cố định với động từ chuyển động có tiền tố ot-/oto-, pod-/podo-, s-/so-, hãy chọn từ đồng nghĩa cho các cụm từ được in đậm)."},{"t":"example","text":"1. Я смог успоко́иться то́лько тогда́, когда́ узна́л результа́ты экза́менов.","b":1},{"t":"subhead","text":"Đáp án: у меня́ отлегло́ от се́рдца","b":1},{"t":"para","text":"Dịch: Tôi chỉ thấy nhẹ nhõm (trút được gánh nặng) khi biết kết quả thi."},{"t":"example","text":"2. Уговори́ть его́ бу́дет непро́сто, он о́чень упря́мый челове́к.","b":1},{"t":"subhead","text":"Đáp án: к нему́ не подъе́дешь","b":1},{"t":"para","text":"Dịch: Sẽ không dễ tiếp cận (thuyết phục) anh ta đâu, anh ta là người rất bướng bỉnh."},{"t":"example","text":"3. По вечера́м вся молодёжь собира́лась в клу́бе, но со вре́менем одни́ обзавели́сь се́мьями, други́е уе́хали, и э́та тради́ция постепе́нно исче́зла.","b":1},{"t":"subhead","text":"Đáp án: сошла́ на нет","b":1},{"t":"para","text":"Dịch: Vào các buổi tối giới trẻ thường tụ tập ở câu lạc bộ, nhưng theo thời gian người thì lập gia đình, người thì đi xa, và truyền thống này dần mai một (biến mất)."},{"t":"example","text":"4. На́ша конфере́нция ока́нчивается, я хочу́ поблагодари́ть всех её уча́стников.","b":1},{"t":"subhead","text":"Đáp án: подхо́дит к концу́","b":1},{"t":"para","text":"Dịch: Hội nghị của chúng ta đang đi đến hồi kết, tôi muốn cảm ơn tất cả những người tham gia."},{"t":"example","text":"5. Позво́льте мне подыто́жить на́ше обсужде́ние.","b":1},{"t":"subhead","text":"Đáp án: подвести́ черту́ под на́шим обсужде́нием","b":1},{"t":"para","text":"Dịch: Cho phép tôi tổng kết (chốt lại) cuộc thảo luận của chúng ta."},{"t":"example","text":"6. Я ду́маю, э́то преступле́ние не оста́нется безнака́занным ни для кого́ из его́ организа́торов.","b":1},{"t":"subhead","text":"Đáp án: никому́ ... с рук не сойдёт","b":1},{"t":"para","text":"Dịch: Tôi nghĩ tội ác này sẽ không trót lọt (không ai thoát tội) đối với bất kỳ kẻ tổ chức nào."},{"t":"vocab","ru":"Тебе́ не на́до далеко́ е́здить","vi":"что́бы удовлетвори́ть своё жела́ние и пообща́ться с у́мными людьми́, сто́ит то́лько внима́тельно посмотре́ть вокру́г.","g":null},{"t":"subhead","text":"Đáp án: отвести́ ду́шу","b":1},{"t":"para","text":"Dịch: Bạn không cần phải đi đâu xa: để thỏa lòng (cho bõ thèm) giao tiếp với những người thông minh, chỉ cần nhìn kỹ xung quanh là được."},{"t":"example","text":"8. Свои́ми необду́манными слова́ми ты поста́вил меня́ в о́чень затрудни́тельное положе́ние.","b":1},{"t":"subhead","text":"Đáp án: подвёл меня́ под монасты́рь","b":1},{"t":"para","text":"Dịch: Với những lời nói thiếu suy nghĩ của mình, cậu đã đẩy tôi vào tình thế khốn đốn (hại tôi thê thảm)."},{"t":"example","text":"9. Будь споко́ен, не теря́й рассу́дка!","b":1},{"t":"subhead","text":"Đáp án: Не сходи́ с ума́!","b":1},{"t":"para","text":"Dịch: Bình tĩnh đi, đừng có điên lên (mất trí)!"},{"t":"example","text":"10. На́до узна́ть то́чное вре́мя и передви́нуть стре́лки на часа́х.","b":1},{"t":"subhead","text":"Đáp án: подвести́ часы́","b":1},{"t":"para","text":"Dịch: Cần phải xem giờ chính xác và chỉnh lại đồng hồ."}]},{"id":"07-s141","type":"exercise","title":"Bài 640 (Trang 342)","num":640,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте в ну́жной фо́рме необходи́мые по смы́слу глаго́лы движе́ния с приста́вками под-, про-, от-, с-, в- (во-), вы-, по-, у-, при-, до- и́ли без приста́вок. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Thay dấu ba chấm bằng các động từ chuyển động cần thiết theo ý nghĩa ở dạng thích hợp, với các tiền tố pod-, pro-, ot-, s-, v- (vo-), vy-, po-, u-, pri-, do- hoặc không có tiền tố. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"Đoạn văn: (Đây là một câu chuyện liền mạch về chuyến đi chơi)."},{"t":"para","text":"1. В суббо́ту мы реши́ли ... за́ город.","b":1},{"t":"subhead","text":"Đáp án: пое́хать (từ е́хать)"},{"t":"para","text":"Dịch: Vào thứ Bảy, chúng tôi quyết định đi (khởi hành) ra ngoại ô."},{"t":"example","text":"Giải thích: Quyết định thực hiện một hành động di chuyển → dùng по- để chỉ sự khởi đầu/ý định đi."},{"t":"para","text":"2. Мы вста́ли ра́но у́тром, поза́втракали и в семь утра́ ... из до́ма.","b":1},{"t":"subhead","text":"Đáp án: вы́шли (từ идти́)"},{"t":"para","text":"Dịch: Chúng tôi dậy sớm, ăn sáng và lúc 7 giờ sáng đã ra khỏi nhà."},{"t":"example","text":"Giải thích: Rời khỏi không gian bên trong (nhà) ra ngoài → tiền tố вы-."},{"t":"para","text":"3. Когда́ мы ... к остано́вке, мы уви́дели, что наш авто́бус то́лько что ... .","b":1},{"t":"subhead","text":"Đáp án: подошли́ (từ идти́); ушёл (từ идти́)"},{"t":"para","text":"Dịch: Khi chúng tôi đi đến (lại gần) trạm dừng, chúng tôi thấy xe buýt của mình vừa mới rời đi (đi mất)."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Подошли́ к","vi":"Tiếp cận, đến gần địa điểm.","g":null},{"t":"vocab","ru":"Ушёл","vi":"Rời đi và không còn ở đó nữa (lỡ xe).","g":null},{"t":"para","text":"4. Ждать нам пришло́сь дово́льно до́лго. Наконе́ц ... ну́жный нам авто́бус, мы ... в него́ и ... .","b":1},{"t":"subhead","text":"Đáp án: подошёл (hoặc пришёл); вошли́ (hoặc се́ли); пое́хали"},{"t":"para","text":"Dịch: Chúng tôi phải đợi khá lâu. Cuối cùng chiếc xe buýt cần thiết cũng đến (cập bến), chúng tôi lên (vào) xe và đi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Подошёл/Пришёл","vi":"Xe đến trạm.","g":null},{"t":"example","text":"Вошли́ (bước vào trong) hoặc се́ли (ngồi lên xe)."},{"t":"vocab","ru":"Пое́хали","vi":"Bắt đầu di chuyển bằng xe.","g":null},{"t":"para","text":"5. Когда́ мы ... на вокза́л, мы сра́зу ... к ка́ссам за биле́тами.","b":1},{"t":"subhead","text":"Đáp án: прие́хали; пошли́"},{"t":"para","text":"Dịch: Khi chúng tôi đến nhà ga, chúng tôi đi ngay đến quầy vé để mua vé."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Прие́хали","vi":"Đến đích (bằng xe buýt).","g":null},{"t":"vocab","ru":"Пошли́","vi":"Bắt đầu di chuyển (đi bộ) đến mục tiêu khác (quầy vé).","g":null},{"t":"para","text":"6. Мы купи́ли биле́ты и ... на платфо́рму.","b":1},{"t":"subhead","text":"Đáp án: вы́шли (hoặc прошли́)"},{"t":"para","text":"Dịch: Chúng tôi mua vé và bước ra sân ga."},{"t":"example","text":"Giải thích: Thường đi từ tòa nhà nhà ga ra sân ga (không gian hở/ngoài) dùng вы́шли."},{"t":"para","text":"7. На́ша электри́чка стоя́ла у платфо́рмы и должна́ была́ ... че́рез не́сколько мину́т.","b":1},{"t":"subhead","text":"Đáp án: отойти́ (từ идти́) hoặc уйти́"},{"t":"para","text":"Dịch: Tàu điện của chúng tôi đang đậu ở sân ga và sẽ phải rời bến (xuất phát) trong vài phút nữa."},{"t":"example","text":"Giải thích: Tàu rời khỏi vị trí đứng yên → отойти́ (rời bến)."},{"t":"para","text":"8. Когда́ мы ... по платфо́рме, мой друг помо́г пожило́й же́нщине ... до ваго́на тяжёлый чемода́н.","b":1},{"t":"subhead","text":"Đáp án: шли; донести́"},{"t":"para","text":"Dịch: Khi chúng tôi đang đi trên sân ga, bạn tôi đã giúp một người phụ nữ lớn tuổi mang chiếc vali nặng đến tận toa tàu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Шли","vi":"Hành động đang diễn ra (quá trình) không cần tiền tố.","g":null},{"t":"vocab","ru":"Донести́ ... до","vi":"Mang vật nặng đến một đích cụ thể (giới hạn).","g":null},{"t":"para","text":"9. Мы ... в ваго́н, по́езд тро́нулся и на́чал ме́дленно ... от платфо́рмы.","b":1},{"t":"subhead","text":"Đáp án: вошли́; отходи́ть"},{"t":"para","text":"Dịch: Chúng tôi bước vào toa, tàu chuyển bánh và bắt đầu chầm chậm rời khỏi sân ga."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вошли́","vi":"Vào trong.","g":null},{"t":"vocab","ru":"Отходи́ть","vi":"Bắt đầu quá trình tách ra xa vật mốc (sân ga).","g":null},{"t":"para","text":"10. Я стал смотре́ть в окно́ на дере́вья и телегра́фные столбы́, кото́рые стреми́тельно ... наза́д.","b":1},{"t":"subhead","text":"Đáp án: убега́ли (từ бе́гать) hoặc уходи́ли / проноси́лись"},{"t":"para","text":"Dịch: Tôi bắt đầu nhìn qua cửa sổ ngắm cây cối và cột điện tín, những thứ đang vùn vụt chạy lùi (lùi lại) về phía sau."},{"t":"example","text":"Giải thích: Dùng nghĩa bóng của убегать (chạy đi mất) để miêu tả cảnh vật lùi lại khi tàu chạy nhanh."},{"t":"para","text":"11. Наро́ду в электри́чке бы́ло немно́го. И́зредка ми́мо нас ... пассажи́ры, кото́рые неда́вно ... в ваго́н и́ли, наоборо́т, гото́вились к вы́ходу.","b":1},{"t":"subhead","text":"Đáp án: проходи́ли; вошли́"},{"t":"para","text":"Dịch: Trên tàu không đông lắm. Thi thoảng có những hành khách đi ngang qua chúng tôi, những người vừa mới lên (vào) toa hoặc ngược lại, đang chuẩn bị xuống."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Проходи́ли","vi":"Đi qua trước mặt (quá trình).","g":null},{"t":"vocab","ru":"Вошли́","vi":"Đã vào trong toa (hoàn thành).","g":null},{"t":"para","text":"12. Ко мне ... ма́ленький ма́льчик и протяну́л мне игру́шечный автомоби́ль.","b":1},{"t":"subhead","text":"Đáp án: подошёл (từ идти́)"},{"t":"para","text":"Dịch: Một cậu bé nhỏ lại gần tôi và đưa cho tôi một chiếc ô tô đồ chơi."},{"t":"example","text":"Giải thích: Tiếp cận chủ thể → подошёл."},{"t":"vocab","ru":"Автомоби́ль был действи́тельно о́чень хоро́ш","vi":"он мог ... вперёд и наза́д, мог ... не́скольких игру́шечных пассажи́ров и ... за собо́й прице́п.","g":null},{"t":"subhead","text":"Đáp án: е́здить; вози́ть; вози́ть / тащи́ть"},{"t":"para","text":"Dịch: Chiếc xe quả thực rất đẹp: nó có thể chạy (đi) tới và lui, có thể chở vài hành khách đồ chơi và kéo theo một cái rơ-moóc."},{"t":"example","text":"Giải thích: Chỉ khả năng/chức năng của xe → dùng động từ đa chiều không tiền tố: е́здить (đi xe), вози́ть (chở), вози́ть/тащи́ть (kéo theo)."},{"t":"para","text":"14. Я хоте́л поговори́ть с ма́льчиком о досто́инствах автомоби́ля, но ма́льчика ... его ма́ма, и он ... .","b":1},{"t":"subhead","text":"Đáp án: увела́; ушёл"},{"t":"para","text":"Dịch: Tôi định nói chuyện với cậu bé về ưu điểm của chiếc xe, nhưng mẹ cậu bé đã dẫn cậu đi, và cậu ấy đã đi mất."},{"t":"example","text":"Giải thích: Dẫn đi khỏi chỗ người nói → увела. Rời đi hẳn → ушёл."},{"t":"para","text":"15. А я продолжа́л смотре́ть в окно́, как пасту́х ... че́рез доро́гу своё ста́до, как над по́лем о́чень ни́зко ... самолёт, как в э́то вре́мя по реке́ ... ка́тер с рыбака́ми.","b":1},{"t":"subhead","text":"Đáp án: переводи́л; лете́л / пролета́л; плыл / проплыва́л"},{"t":"para","text":"Dịch: Còn tôi tiếp tục nhìn qua cửa sổ, xem cảnh người chăn gia súc dẫn đàn gia súc băng qua đường, cảnh chiếc máy bay bay rất thấp trên cánh đồng, cảnh chiếc cano chở ngư dân đang bơi (trôi) trên sông lúc đó."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Переводи́л","vi":"Dẫn qua (băng qua đường).","g":null},{"t":"vocab","ru":"Лете́л / пролета́л","vi":"Bay (quá trình diễn ra trước mắt).","g":null},{"t":"vocab","ru":"Плыл / проплыва́л","vi":"Bơi/đi thuyền.","g":null},{"t":"para","text":"16. Наконе́ц объяви́ли, что сле́дующая остано́вка — Зеленого́рск. Мы на́чали гото́виться к вы́ходу. По́езд ... к платфо́рме. Мы ... из ваго́на и уви́дели свои́х знако́мых, кото́рые ... на вокза́л встреча́ть нас.","b":1},{"t":"subhead","text":"Đáp án: подошёл; вы́шли; пришли́ (hoặc прие́хали)"},{"t":"para","text":"Dịch: Cuối cùng có thông báo trạm tới là Zelenogorsk. Chúng tôi bắt đầu chuẩn bị xuống. Tàu tiến vào (cập) sân ga. Chúng tôi bước ra khỏi toa và nhìn thấy người quen, những người đã đến nhà ga đón chúng tôi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Подошёл к","vi":"Tiếp cận/cập bến.","g":null},{"t":"vocab","ru":"Вы́шли","vi":"Ra khỏi.","g":null},{"t":"vocab","ru":"Пришли́","vi":"Đã có mặt tại đích (để đón).","g":null},{"t":"para","text":"17. На́ша пое́здка ... к концу́.","b":1},{"t":"subhead","text":"Đáp án: подошла́","b":1},{"t":"para","text":"Dịch: Chuyến đi của chúng tôi đã đi đến hồi kết."},{"t":"example","text":"Giải thích: Thành ngữ подойти́ к концу́ (kết thúc)."},{"t":"para","text":"18. Нам предстоя́ло де́сять дней ... (на да́че) у знако́мых на да́че.","b":1},{"t":"subhead","text":"Đáp án: провести́ (từ вести́)"},{"t":"para","text":"Dịch: Trước mắt chúng tôi là 10 ngày trải qua (ở) tại nhà nghỉ ngoại ô của người quen."},{"t":"example","text":"Giải thích: Провести́ время = dành thời gian/trải qua. Đây là động từ chuyển động gốc вести mang nghĩa bóng. (Cũng có thể dùng пожить/гостить nhưng sách đang luyện động từ chuyển động)."},{"t":"para","text":"19. Мы бу́дем ... по ле́су, собира́ть грибы́ и я́годы, ... в о́зере, ... на велосипе́де.","b":1},{"t":"subhead","text":"Đáp án: ходи́ть; пла́вать / купа́ться; ката́ться / е́здить"},{"t":"para","text":"Dịch: Chúng tôi sẽ đi dạo trong rừng, hái nấm và quả mọng, bơi trong hồ, đạp xe đạp."},{"t":"example","text":"Giải thích: Các hành động giải trí, lặp lại hoặc không phương hướng cụ thể → dùng động từ đa chiều không tiền tố: ходи́ть (đi bộ), пла́вать (bơi), ката́ться/е́здить (đi xe)."},{"t":"para","text":"20. По́сле о́тдыха в Зеленого́рске мы плани́руем ... на неде́лю к ро́дственникам в Но́вгород посмотре́ть Кремль. Да здра́вствуют кани́кулы!","b":1},{"t":"subhead","text":"Đáp án: съе́здить (hoặc пое́хать)"},{"t":"para","text":"Dịch: Sau kỳ nghỉ ở Zelenogorsk, chúng tôi dự định đi (chơi) một tuần ở chỗ họ hàng tại Novgorod để thăm Điện Kremlin. Kỳ nghỉ muôn năm!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Съе́здить","vi":"Đi một chuyến rồi về (thường dùng cho du lịch ngắn hạn).","g":null},{"t":"vocab","ru":"Пое́хать","vi":"Sẽ đi (khởi hành).","g":null},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 343)","b":1},{"t":"para","text":"Tiếng Nga: Глаголы движения с приставками пере-, об-, за-","b":1},{"t":"vocab","ru":"Пере-","vi":"обозначает перемещение из одного места в другое (перее́хать на но́вую кварти́ру) или движение через какой-либо предмет (перейти́ у́лицу).","g":null},{"t":"vocab","ru":"Об- (обо-)","vi":"обозначает движение вокруг предмета (объе́хать вокру́г па́мятника) или движение мимо чего-либо (обойти́ лу́жу).","g":null},{"t":"vocab","ru":"За-","vi":"обозначает попутное движение (зайти́ в магази́н) или движение за предмет (зайти́ за у́гол).","g":null},{"t":"para","text":"Dịch & Giải thích: Động từ chuyển động với tiền tố pere-, ob-, za-","b":1},{"t":"subhead","text":"Пере- (Pere-):","b":1},{"t":"example","text":"Biểu thị sự di chuyển từ nơi này sang nơi khác (chuyển chỗ ở). Ví dụ: перее́хать на но́вую кварти́ру (chuyển sang căn hộ mới)."},{"t":"example","text":"Hoặc chuyển động băng qua vật cản/không gian (băng qua). Ví dụ: перейти́ у́лицу (sang đường)."},{"t":"subhead","text":"Об- / Обо- (Ob- / Obo-):","b":1},{"t":"example","text":"Biểu thị chuyển động vòng quanh vật thể. Ví dụ: объе́хать вокру́г па́мятника (lái xe vòng quanh tượng đài)."},{"t":"example","text":"Hoặc chuyển động tránh/đi vòng qua cái gì đó. Ví dụ: обойти́ лу́жу (đi vòng tránh vũng nước)."},{"t":"subhead","text":"За- (Za-):","b":1},{"t":"example","text":"Biểu thị chuyển động ghé qua (tiện đường). Ví dụ: зайти́ в магази́н (ghé vào cửa hàng)."},{"t":"example","text":"Hoặc chuyển động ra phía sau vật thể. Ví dụ: зайти́ за у́гол (đi ra sau góc phố)."}]},{"id":"07-s142","type":"exercise","title":"Bài 641 (Trang 343-344)","num":641,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложе́ния. Определи́те значе́ние вы́деленных глаго́лов движе́ния с приста́вками. Назови́те инфинити́вы, от кото́рых они́ образо́ваны. (Đọc các câu. Xác định ý nghĩa của các động từ chuyển động có tiền tố được in đậm. Gọi tên động từ nguyên mẫu mà từ đó chúng được tạo thành)."},{"t":"para","text":"a) Tiền tố ПЕРЕ- (Băng qua / Chuyển chỗ)","b":1},{"t":"example","text":"1. Нам ну́жно перейти́ че́рез у́лицу. Так как здесь нет разреша́ющего перехо́д доро́жного зна́ка, не сто́ит переходи́ть на другу́ю сто́рону у́лицы.","b":1},{"t":"vocab","ru":"перейти́ (từ идти́ - hoàn thành)","vi":"Băng qua (sang bên kia).","g":null},{"t":"vocab","ru":"переходи́ть (từ ходи́ть - chưa hoàn thành)","vi":"Băng qua.","g":null},{"t":"para","text":"Dịch: Chúng ta cần sang đường. Vì ở đây không có biển báo cho phép sang đường, nên không đáng để băng qua phía bên kia đường đâu."},{"t":"example","text":"2. Маши́на перее́хала че́рез мост и останови́лась. Когда́ мы переезжа́ли на другу́ю кварти́ру, мы взя́ли с собо́й то́лько са́мые необходи́мые ве́щи. В мо́лодости он без труда́ переплы́ть Во́лгу. Я не реша́юсь в одино́чку переплыва́ть го́рные ре́ки.","b":1},{"t":"vocab","ru":"перее́хала (từ е́хать)","vi":"Đã lái xe qua (cầu).","g":null},{"t":"vocab","ru":"переезжа́ли (từ е́здить)","vi":"Đang chuyển nhà (dọn đi nơi khác).","g":null},{"t":"vocab","ru":"переплы́ть (từ плыть)","vi":"Bơi qua (bờ bên kia).","g":null},{"t":"vocab","ru":"переплыва́ть (từ пла́вать)","vi":"Bơi qua.","g":null},{"t":"para","text":"Dịch: Chiếc xe đã đi qua cầu và dừng lại. Khi chúng tôi chuyển sang căn hộ khác, chúng tôi chỉ mang theo những vật dụng cần thiết nhất. Thời trẻ ông ấy có thể dễ dàng bơi qua sông Volga. Tôi không dám bơi qua những con sông núi một mình."},{"t":"example","text":"3. Передава́йте всем приве́т. (Câu này có thể là lỗi in ấn trong sách hoặc ví dụ bổ sung, vì передавать là động từ \"chuyển giao\", không phải chuyển động thuần túy, nhưng có gốc давать)."},{"t":"note","text":"Lưu ý: Trong danh sách động từ chuyển động thường không tính передавать. Nếu sách có câu khác ở vị trí này, hãy báo tôi. Nếu là 4. Я бою́сь, что не смогу́ переле́зть че́рез э́тот забо́р, он сли́шком высо́кий. В про́шлый раз, когда́ я перелеза́л че́рез забо́р, в саду́ никого́ не́ было."},{"t":"vocab","ru":"переле́зть (từ лезть)","vi":"Leo qua.","g":null},{"t":"vocab","ru":"перелеза́л (từ ла́зить)","vi":"Đang leo qua.","g":null},{"t":"para","text":"Dịch: Tôi sợ là tôi không thể leo qua cái hàng rào này, nó cao quá. Lần trước khi tôi leo qua hàng rào, trong vườn không có ai cả."},{"t":"para","text":"b) Tiền tố ОБ- (Đi vòng / Đi khắp)","b":1},{"t":"example","text":"1. Нам придётся объе́хать э́то боло́то. Е́сли бу́дем объезжа́ть боло́то, на э́то уйдёт мно́го вре́мени. Пла́вая капита́ном корабля́, он объе́хал весь мир.","b":1},{"t":"vocab","ru":"объе́хать (từ е́хать)","vi":"Đi vòng tránh / Đi khắp.","g":null},{"t":"vocab","ru":"объезжа́ть (từ е́здить)","vi":"Đi vòng tránh.","g":null},{"t":"vocab","ru":"объе́хал (từ е́хать)","vi":"Đi khắp (thế giới).","g":null},{"t":"para","text":"Dịch: Chúng ta sẽ phải đi vòng tránh cái đầm lầy này. Nếu đi vòng đầm lầy thì sẽ mất nhiều thời gian lắm. Khi làm thuyền trưởng tàu, ông ấy đã đi khắp thế giới."},{"t":"example","text":"2. Пти́цы не́сколько раз облете́ли вокру́г до́ма и вновь опусти́лись на зе́млю. В э́тот год участи́лись пожа́ры, и лётчики не́сколько раз в день облета́ли леса́, что́бы во́время их заме́тить.","b":1},{"t":"vocab","ru":"облете́ли (từ лете́ть)","vi":"Bay vòng quanh.","g":null},{"t":"vocab","ru":"облета́ли (từ лета́ть)","vi":"Bay tuần tra (bay khắp/vòng quanh).","g":null},{"t":"para","text":"Dịch: Lũ chim bay vài vòng quanh nhà rồi lại đậu xuống đất. Năm nay hỏa hoạn xảy ra thường xuyên, và các phi công bay tuần tra rừng vài lần một ngày để kịp thời phát hiện."},{"t":"example","text":"3. Офици́анты обнесли́ госте́й заку́сками, и обе́д начался́. Хозя́йка по о́череди обноси́ла госте́й блю́дами.","b":1},{"t":"vocab","ru":"обнесли́ (từ нести́)","vi":"Mang đi mời khắp lượt (phục vụ).","g":null},{"t":"vocab","ru":"обноси́ла (từ носи́ть)","vi":"Mang mời từng người.","g":null},{"t":"para","text":"Dịch: Những người bồi bàn đã mang đồ khai vị mời khắp các vị khách, và bữa trưa bắt đầu. Bà chủ lần lượt bưng các món ăn mời khách."},{"t":"example","text":"4. Дава́й обго́ним э́ту маши́ну! Я ду́маю, не сто́ит её обгоня́ть, э́то опа́сно.","b":1},{"t":"vocab","ru":"обго́ним (từ гнать)","vi":"Vượt (xe).","g":null},{"t":"vocab","ru":"обгоня́ть (từ гоня́ть)","vi":"Vượt.","g":null},{"t":"para","text":"Dịch: Hãy vượt chiếc xe này đi! Tôi nghĩ không nên vượt nó đâu, nguy hiểm lắm."},{"t":"para","text":"в) Tiền tố ЗА- (Ghé vào / Đi sâu vào / Đi ra sau)","b":1},{"t":"example","text":"1. По доро́ге домо́й мне на́до забежа́ть в магази́н за хле́бом. В про́шлом году́ он ча́сто по вечера́м забега́л к нам, а сейча́с мы его́ почти́ не ви́дим.","b":1},{"t":"vocab","ru":"забежа́ть (từ бежа́ть)","vi":"Chạy ù vào / Ghé vào nhanh.","g":null},{"t":"vocab","ru":"забега́л (từ бе́гать)","vi":"Thường xuyên ghé vào.","g":null},{"t":"para","text":"Dịch: Trên đường về nhà tôi cần tạt (chạy) vào cửa hàng mua bánh mì. Năm ngoái buổi tối cậu ấy hay tạt qua chỗ chúng tôi, còn bây giờ chúng tôi hầu như không gặp cậu ấy."},{"t":"example","text":"2. В э́тот раз ты заплы́л о́чень далеко́, возвраща́йся наза́д. Не заплыва́й за буйки́, я бу́ду волнова́ться.","b":1},{"t":"vocab","ru":"заплы́л (từ плыть)","vi":"Bơi quá xa / Bơi sâu vào.","g":null},{"t":"vocab","ru":"заплыва́й (từ пла́вать)","vi":"Bơi quá giới hạn (phao tiêu).","g":null},{"t":"para","text":"Dịch: Lần này bạn bơi ra xa quá rồi, quay lại đi. Đừng bơi quá phao tiêu, tôi sẽ lo đấy."},{"t":"example","text":"3. Вчера́ к нам в ко́мнату залете́л воробе́й. В лесу́ бы́ло ти́хо и пусты́нно, то́лько и́зредка в него́ залета́ли пти́цы, но до́лго в нём не заде́рживались.","b":1},{"t":"vocab","ru":"залете́л (từ лете́ть)","vi":"Bay lọt vào trong.","g":null},{"t":"vocab","ru":"залета́ли (từ лета́ть)","vi":"Bay vào.","g":null},{"t":"para","text":"Dịch: Hôm qua có một con chim sẻ bay vào phòng chúng tôi. Trong rừng yên tĩnh và vắng vẻ, chỉ thi thoảng lũ chim bay lạc vào, nhưng không ở lại lâu."},{"t":"example","text":"4. Я занесу́ тебе́ кни́гу сего́дня ве́чером. Заноси́ в любо́й день, когда́ у тебя́ бу́дет свобо́дное вре́мя.","b":1},{"t":"vocab","ru":"занесу́ (từ нести́)","vi":"Mang đến đưa cho (tiện đường/ghé đưa).","g":null},{"t":"vocab","ru":"заноси́ (từ носи́ть)","vi":"Mang đến.","g":null},{"t":"para","text":"Dịch: Tối nay tớ sẽ mang sách qua cho cậu. Cứ mang qua bất cứ ngày nào cậu rảnh nhé."}]},{"id":"07-s143","type":"exercise","title":"Bài 642 (Trang 344)","num":642,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте словосочета́ния с глаго́лами движе́ния с приста́вкой пере-, обраща́я внима́ние на предло́ги. Продо́лжите ряд сочета́ющихся с ни́ми слов. (Đọc các cụm từ với động từ chuyển động có tiền tố пере-, chú ý đến các giới từ. Hãy tiếp tục dãy các từ kết hợp với chúng)."},{"t":"para","text":"Phân tích và Dịch:","b":1},{"t":"para","text":"а) Переходи́ть/перейти́ в... (Chuyển sang, gia nhập vào - thường dùng cho tôn giáo, trạng thái hoặc tổ chức)."},{"t":"example","text":"Các từ trong sách: христиа́нство (Cơ đốc giáo), будди́зм (Phật giáo), ..."},{"t":"para","text":"Mở rộng (theo gợi ý trong ngoặc):","b":1},{"t":"example","text":"в наступле́ние (chuyển sang thế tấn công)."},{"t":"example","text":"в ата́ку (chuyển sang tấn công)."},{"t":"example","text":"в Технологи́ческий институ́т (chuyển vào Viện Công nghệ)."},{"t":"example","text":"в университе́т (chuyển vào đại học)."},{"t":"example","text":"в ... класс (lên lớp ...)."},{"t":"para","text":"б) Переходи́ть/перейти́ на... (Chuyển sang phía/bên khác, đổi sang cái khác)."},{"t":"example","text":"Các từ trong sách: сто́рону проти́вника (sang phía kẻ thù), сто́рону ... (sang phía...)."},{"t":"para","text":"Mở rộng:","b":1},{"t":"example","text":"на друго́й факульте́т (sang khoa khác)."},{"t":"example","text":"на друго́й у́ровень (lên cấp độ khác)."},{"t":"example","text":"на «ты» (chuyển sang xưng hô thân mật - \"mày/tao\" hoặc \"anh/em\")."},{"t":"subhead","text":"Переводи́ть/перевести́ (chuyển đổi/dịch):","b":1},{"t":"example","text":"разгово́р на другу́ю те́му (chuyển cuộc nói chuyện sang chủ đề khác)."},{"t":"example","text":"кни́гу с англи́йского языка́ на ру́сский (dịch sách từ tiếng Anh sang tiếng Nga)."},{"t":"example","text":"стре́лку на две мину́ты наза́д / на оди́н час... (vặn kim đồng hồ lùi lại 2 phút / 1 tiếng...)."},{"t":"example","text":"взгляд (с одно́й карти́ны) на другу́ю карти́ну (chuyển ánh nhìn từ bức tranh này sang bức tranh khác)."},{"t":"para","text":"Chuyển trạng thái:","b":1},{"t":"example","text":"от оборо́ны к наступле́нию (từ phòng thủ sang tấn công)."},{"t":"example","text":"от разгово́ров к де́лу (từ lời nói sang hành động)."},{"t":"example","text":"от защи́ты к нападе́нию (từ bảo vệ sang tấn công)."},{"t":"example","text":"на другу́ю слу́жбу (sang công việc/đơn vị khác)."},{"t":"para","text":"в) Переходи́ть/перейти́ к... (Chuyển sang bước tiếp theo, tiếp cận)."},{"t":"example","text":"Các từ trong sách: оборо́не (sang phòng thủ), оса́де (sang bao vây), к ..."},{"t":"para","text":"Mở rộng:","b":1},{"t":"example","text":"к нача́лу (bắt đầu vào việc)."},{"t":"example","text":"к друго́й те́ме (sang chủ đề khác)."},{"t":"example","text":"к друго́му вопро́су (sang câu hỏi khác)."},{"t":"example","text":"к ученика́м / к воспи́танникам (đến chỗ học sinh/học viên - để kiểm tra hoặc giảng dạy)."},{"t":"para","text":"г) Переходи́ть/перейти́... (Không giới từ - Cách 4) (Vượt qua, vi phạm giới hạn)."},{"t":"example","text":"Các từ trong sách: грани́цы прили́чия (vượt quá giới hạn lịch sự), грани́цы дозво́ленного (giới hạn cho phép), грани́цы ... (biên giới...)."},{"t":"subhead","text":"Переноси́ть/перенести́ (Chịu đựng/trải qua):","b":1},{"t":"example","text":"тру́дности (chịu đựng khó khăn)."},{"t":"example","text":"... (bệnh tật, thử thách)."},{"t":"example","text":"не переноси́ть антибио́тиков / лжи (không dung nạp/dị ứng với thuốc kháng sinh / không chịu nổi sự dối trá)."}]},{"id":"07-s144","type":"exercise","title":"Bài 643 (Trang 345)","num":643,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме один из глаголов движения с приставкой пере-. Вместо точек вставьте необходимые по смыслу предлоги. Объясните ваш выбор. (Mở ngoặc đơn, sử dụng dạng cần thiết của một trong các động từ chuyển động với tiền tố пере-. Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa. Giải thích sự lựa chọn của bạn)."},{"t":"para","text":"1. Дава́йте (идти́/ходи́ть) ... (друга́я ко́мната).","b":1},{"t":"subhead","text":"Đáp án: перейдём в другу́ю ко́мнату","b":1},{"t":"para","text":"Dịch: Chúng ta hãy sang phòng khác đi."},{"t":"example","text":"Giải thích: Di chuyển từ không gian này sang không gian khác → перейдём (tương lai/mệnh lệnh rủ rê) + giới từ в (vào)."},{"t":"para","text":"2. Я на́чал его́ проси́ть (е́хать/е́здить) ... (я) на кварти́ру, но он не согласи́лся.","b":1},{"t":"subhead","text":"Đáp án: перее́хать ко мне","b":1},{"t":"para","text":"Dịch: Tôi bắt đầu mời anh ấy chuyển đến căn hộ của tôi, nhưng anh ấy không đồng ý."},{"t":"example","text":"Giải thích: Chuyển chỗ ở → перее́хать. Đến chỗ một người nào đó → giới từ к (ко đi với мне)."},{"t":"para","text":"3. Из кусто́в (вы́порхнуть) и (лете́ть/лета́ть) ... (доро́га) кака́я-то пти́ца.","b":1},{"t":"subhead","text":"Đáp án: перелете́ла че́рез доро́гу","b":1},{"t":"para","text":"Dịch: Từ bụi cây, một con chim nào đó vụt bay ra và bay băng qua đường."},{"t":"example","text":"Giải thích: Bay ngang qua vật cản (con đường) → перелете́ла + giới từ че́рез (qua)."},{"t":"para","text":"4. Она́ (лезть/ла́зить) ... (борт ло́дки) и вы́прыгнула на бе́рег.","b":1},{"t":"subhead","text":"Đáp án: переле́зла че́рез борт ло́дки","b":1},{"t":"para","text":"Dịch: Cô ấy leo qua mạn thuyền và nhảy lên bờ."},{"t":"example","text":"Giải thích: Leo qua vật cản → переле́зла + че́рез."},{"t":"para","text":"5. Я собира́юсь (идти́/ходи́ть) ... (заключи́тельная часть докла́да).","b":1},{"t":"subhead","text":"Đáp án: перейти́ к заключи́тельной ча́сти докла́да","b":1},{"t":"para","text":"Dịch: Tôi định chuyển sang phần kết luận của bài báo cáo."},{"t":"example","text":"Giải thích: Chuyển sang bước/giai đoạn tiếp theo → перейти́ + giới từ к."},{"t":"para","text":"6. Уви́дев его́ раздраже́ние, она́ бы́стро (вести́/води́ть) разгово́р ... (друга́я те́ма).","b":1},{"t":"subhead","text":"Đáp án: перевела́ разгово́р на другу́ю те́му","b":1},{"t":"para","text":"Dịch: Thấy anh ấy khó chịu, cô ấy nhanh chóng chuyển cuộc nói chuyện sang chủ đề khác."},{"t":"example","text":"Giải thích: Lái câu chuyện sang hướng khác → перевела́ + giới từ на."},{"t":"para","text":"7. Когда́ мы (лете́ть/лета́ть) ... (А́льпы), я любова́лся го́рными верши́нами.","b":1},{"t":"subhead","text":"Đáp án: перелета́ли че́рез А́льпы","b":1},{"t":"para","text":"Dịch: Khi chúng tôi bay qua dãy Alps, tôi đã ngắm nhìn những đỉnh núi."},{"t":"example","text":"Giải thích: Hành động đang diễn ra trong quá khứ (quá trình bay qua) → перелета́ли (chưa hoàn thành) + че́рез."},{"t":"para","text":"8. Че́рез не́сколько часо́в шторм (идти́/ходи́ть) ... (урага́н).","b":1},{"t":"subhead","text":"Đáp án: перешёл в урага́н","b":1},{"t":"para","text":"Dịch: Sau vài giờ, cơn bão đã chuyển thành siêu bão (cuồng phong)."},{"t":"example","text":"Giải thích: Thay đổi trạng thái/cấp độ → перешёл + giới từ в."},{"t":"para","text":"9. Мы (вести́/води́ть) взгляд ... (дом; сад).","b":1},{"t":"subhead","text":"Đáp án: перевели́ взгляд с до́ма на сад","b":1},{"t":"para","text":"Dịch: Chúng tôi chuyển ánh nhìn từ ngôi nhà sang khu vườn."},{"t":"example","text":"Giải thích: Chuyển hướng nhìn → перевели́ + cặp giới từ с ... на ... (từ ... sang ...)."},{"t":"para","text":"10. Нам лу́чше (нести́/носи́ть) собра́ние ... (семь часо́в ве́чера).","b":1},{"t":"subhead","text":"Đáp án: перенести́ собра́ние на семь часо́в ве́чера","b":1},{"t":"para","text":"Dịch: Tốt hơn chúng ta nên dời cuộc họp sang 7 giờ tối."},{"t":"example","text":"Giải thích: Dời lịch/thời gian → перенести́ + giới từ на (chỉ thời điểm đích)."},{"t":"para","text":"11. Он име́л обыкнове́ние (идти́/ходи́ть) ... (отча́яние; безу́держное весе́лье).","b":1},{"t":"subhead","text":"Đáp án: переходи́ть от отча́яния к безу́держному весе́лью","b":1},{"t":"para","text":"Dịch: Anh ấy có thói quen chuyển từ tuyệt vọng sang vui vẻ tột độ."},{"t":"example","text":"Giải thích: Thay đổi trạng thái cảm xúc (thói quen) → переходи́ть + cặp giới từ от ... к ...."},{"t":"para","text":"12. В конце́ ле́та на́ша семья́ (е́хать/е́здить) ... (го́род).","b":1},{"t":"subhead","text":"Đáp án: переезжа́ет в го́род (hoặc перее́дет)"},{"t":"para","text":"Dịch: Vào cuối hè, gia đình chúng tôi chuyển (về) thành phố."},{"t":"example","text":"Giải thích: Chuyển chỗ ở → переезжа́ет (thường xuyên/kế hoạch) + giới từ в."},{"t":"para","text":"13. Ему́ уже́ во́семь лет, в сле́дующем году́ он (идти́/ходи́ть) ... (второ́й класс).","b":1},{"t":"subhead","text":"Đáp án: перейдёт во второ́й класс","b":1},{"t":"para","text":"Dịch: Cậu bé đã 8 tuổi, năm sau cậu sẽ lên lớp hai."},{"t":"example","text":"Giải thích: Lên lớp → перейдёт + giới từ в (во trước từ bắt đầu bằng cụm phụ âm)."},{"t":"para","text":"14. Одно́й руко́й наш но́вый знако́мый по́днял кре́сло и (нести́/носи́ть) ... (окно́).","b":1},{"t":"subhead","text":"Đáp án: перенёс его́ к окну́","b":1},{"t":"para","text":"Dịch: Người quen mới của chúng tôi nhấc chiếc ghế bằng một tay và chuyển nó đến (gần) cửa sổ."},{"t":"example","text":"Giải thích: Di chuyển vật từ chỗ này sang chỗ khác → перенёс + giới từ к (đến gần)."},{"t":"para","text":"15. По́сле сме́рти хозя́ина его́ дом (идти́/ходи́ть) ... (насле́дники).","b":1},{"t":"subhead","text":"Đáp án: перешёл к насле́дникам","b":1},{"t":"para","text":"Dịch: Sau cái chết của chủ nhà, ngôi nhà của ông ấy được chuyển giao (thuộc về) những người thừa kế."},{"t":"example","text":"Giải thích: Chuyển quyền sở hữu → перешёл + giới từ к."},{"t":"para","text":"16. Оте́ц вы́нул часы́ и (вести́/води́ть) стре́лку ... (пять мину́т) вперёд.","b":1},{"t":"subhead","text":"Đáp án: перевёл стре́лку на пять мину́т вперёд","b":1},{"t":"para","text":"Dịch: Cha lấy đồng hồ ra và vặn (chỉnh) kim thêm 5 phút về phía trước."},{"t":"example","text":"Giải thích: Chỉnh đồng hồ → перевёл + giới từ на (chỉ lượng thời gian thay đổi)."},{"t":"para","text":"17. Зву́ки скри́пки (нести́/носи́ть) его́ ... (мир воспомина́ний).","b":1},{"t":"subhead","text":"Đáp án: перенесли́ его́ в мир воспомина́ний","b":1},{"t":"para","text":"Dịch: Tiếng vĩ cầm đưa anh ấy về thế giới của những kỷ niệm."},{"t":"example","text":"Giải thích: Mang đi/đưa đi (nghĩa bóng) → перенесли́ + giới từ в."},{"t":"para","text":"18. В спо́ре он ча́сто быва́л вспы́льчив и раздражи́телен и, отста́ивая свою́ то́чку зре́ния, мог (идти́/ходи́ть) ... (грани́цы разу́много).","b":1},{"t":"subhead","text":"Đáp án: перейти́ грани́цы разу́много","b":1},{"t":"para","text":"Dịch: Trong tranh luận anh ấy thường nóng nảy và cáu kỉnh, và khi bảo vệ quan điểm của mình, anh ấy có thể vượt quá giới hạn của sự hợp lý."},{"t":"example","text":"Giải thích: Vượt quá giới hạn (nghĩa bóng) → перейти́ + danh từ ở cách 4 (không cần giới từ, hoặc dùng через nhưng cụm cố định thường là перейти границы)."},{"t":"para","text":"19. Рабо́та в на́шем коллекти́ве ему́ не понра́вилась, и вско́ре он (вести́/води́ть) ... (друго́е ме́сто).","b":1},{"t":"subhead","text":"Đáp án: перевёлся на друго́е ме́сто","b":1},{"t":"para","text":"Dịch: Anh ấy không thích công việc trong tập thể của chúng tôi, và chẳng bao lâu sau anh ấy đã chuyển sang nơi khác."},{"t":"example","text":"Giải thích: Chuyển công tác/trường học → dùng động từ phản thân перевести́сь (từ gốc вести) → quá khứ перевёлся + giới từ на."}]},{"id":"07-s145","type":"exercise","title":"Bài 644 (Trang 345-346)","num":644,"blocks":[{"t":"instruction","text":"Yêu cầu: Замени́те вы́деленные глаго́лы движе́ния с приста́вкой пере- глаго́лами с приста́вкой об- (обо-). Объясни́те ра́зницу в значе́ниях предложе́ний. (Thay thế các động từ chuyển động được in đậm có tiền tố pere- bằng các động từ có tiền tố ob- (obo-). Giải thích sự khác biệt về ý nghĩa của các câu)."},{"t":"para","text":"Giải thích chung:","b":1},{"t":"vocab","ru":"Пере-","vi":"Mang nghĩa băng qua, đi xuyên qua, vượt qua từ bên này sang bên kia (vượt chướng ngại vật).","g":null},{"t":"vocab","ru":"Об- (Обо-)","vi":"Mang nghĩa đi vòng quanh, đi tránh qua (không đi xuyên qua mà đi đường vòng).","g":null},{"t":"example","text":"1. Мы перешли́ лу́жу и дви́нулись да́льше.","b":1},{"t":"para","text":"Thay thế: Мы обошли́ лу́жу..."},{"t":"para","text":"Dịch & So sánh:","b":1},{"t":"vocab","ru":"Перешли́","vi":"Chúng tôi đã lội qua (bước qua) vũng nước (đi xuyên qua nó).","g":null},{"t":"vocab","ru":"Обошли́","vi":"Chúng tôi đã đi vòng tránh vũng nước (đi mép ngoài để không bị ướt).","g":null},{"t":"example","text":"2. В э́том ме́сте невозмо́жно перее́хать боло́то, маши́на застя́нет.","b":1},{"t":"para","text":"Thay thế: ... объе́хать боло́то..."},{"t":"para","text":"Dịch & So sánh:","b":1},{"t":"vocab","ru":"Перее́хать","vi":"Ở chỗ này không thể lái xe băng qua (lội qua) đầm lầy, xe sẽ bị sa lầy.","g":null},{"t":"vocab","ru":"Объе́хать","vi":"... không thể lái xe đi vòng qua đầm lầy (có thể do đầm lầy quá lớn hoặc không có đường vòng).","g":null},{"t":"example","text":"3. Ло́дка переплыла́ о́зеро и скры́лась в камыша́х.","b":1},{"t":"para","text":"Thay thế: Ло́дка обплыла́ о́зеро..."},{"t":"para","text":"Dịch & So sánh:","b":1},{"t":"vocab","ru":"Переплыла́","vi":"Chiếc thuyền đã bơi băng qua (sang bờ bên kia) hồ và khuất trong đám lau sậy.","g":null},{"t":"vocab","ru":"Обплыла́","vi":"Chiếc thuyền đã bơi một vòng quanh hồ (hoặc bơi men theo bờ hồ).","g":null},{"t":"example","text":"4. Самолёт перелете́л лес и опусти́лся на поля́ну.","b":1},{"t":"para","text":"Thay thế: Самолёт облете́л лес..."},{"t":"para","text":"Dịch & So sánh:","b":1},{"t":"vocab","ru":"Перелете́л","vi":"Máy bay đã bay vượt qua khu rừng (từ phía này sang phía kia).","g":null},{"t":"vocab","ru":"Облете́л","vi":"Máy bay đã bay vòng quanh khu rừng (hoặc bay tránh khu rừng).","g":null},{"t":"example","text":"5. Тури́сты перешли́ го́ру и спусти́лись в доли́ну.","b":1},{"t":"para","text":"Thay thế: Тури́сты обошли́ го́ру..."},{"t":"para","text":"Dịch & So sánh:","b":1},{"t":"vocab","ru":"Перешли́","vi":"Du khách đã leo qua (vượt qua) ngọn núi (lên đỉnh rồi xuống).","g":null},{"t":"vocab","ru":"Обошли́","vi":"Du khách đã đi vòng qua chân núi (không leo lên).","g":null},{"t":"example","text":"6. Перейди́ э́тот дом, и ты уви́дишь апте́ку.","b":1},{"t":"para","text":"Thay thế: Обойди́ э́тот дом..."},{"t":"para","text":"Dịch & So sánh:","b":1},{"t":"vocab","ru":"Перейди́","vi":"(Câu này ít dùng với \"nhà\" trừ khi đi băng qua sân/mái). Ý ở đây có thể là đi qua (vượt qua mốc) ngôi nhà này.","g":null},{"t":"vocab","ru":"Обойди́","vi":"Hãy đi vòng qua ngôi nhà này (đi ra phía sau hoặc đi quanh nó), bạn sẽ thấy hiệu thuốc.","g":null},{"t":"example","text":"7. Мы перее́хали па́мятник и сверну́ли нале́во.","b":1},{"t":"para","text":"Thay thế: Мы объе́хали па́мятник..."},{"t":"para","text":"Dịch & So sánh:","b":1},{"t":"vocab","ru":"Перее́хали","vi":"Chúng tôi đã cán qua tượng đài (về nghĩa đen là không thể/tai nạn). Câu gốc có thể dùng với nghĩa \"đi qua mốc tượng đài\".","g":null},{"t":"vocab","ru":"Объе́хали","vi":"Chúng tôi đã lái xe vòng qua tượng đài (bùng binh) và rẽ trái.","g":null},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 346)","b":1},{"t":"para","text":"Tiếng Nga: Приста́вки в- (во-), за-","b":1},{"t":"vocab","ru":"За-","vi":"обозначает попутное движение (зайти́ в магази́н) или движение за предмет (зайти́ за де́рево).","g":null},{"t":"vocab","ru":"В-","vi":"обозначает целенаправленное движение (войти́ в магази́н) или движение внутрь (войти́ в ко́мнату).","g":null},{"t":"para","text":"Dịch & Giải thích: Tiền tố v- (vo-), za-","b":1},{"t":"vocab","ru":"За-","vi":"Biểu thị chuyển động kết hợp/tiện đường (ghé vào đâu đó một lát: зайти́ в магази́н - tạt vào cửa hàng) hoặc chuyển động ra phía sau vật thể (зайти́ за де́рево - đi ra sau cái cây).","g":null},{"t":"vocab","ru":"В-","vi":"Biểu thị chuyển động có mục đích chính (vào cửa hàng để làm việc/mua sắm chính: войти́ в магази́н) hoặc chuyển động vào bên trong không gian (войти́ в ко́мнату - bước vào phòng).","g":null}]},{"id":"07-s146","type":"exercise","title":"Bài 645 (Trang 346)","num":645,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме один из глаголов движения с приставкой за- или в- (во-). Вместо точек вставьте необходимые по смыслу предлоги. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ chuyển động với tiền tố za- hoặc v- (vo-). Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa)."},{"t":"para","text":"1. По доро́ге домо́й я (идти́/ходи́ть) ... (магази́н) за хле́бом.","b":1},{"t":"subhead","text":"Đáp án: зашёл в магази́н","b":1},{"t":"para","text":"Dịch: Trên đường về nhà, tôi đã tạt (ghé) vào cửa hàng mua bánh mì."},{"t":"example","text":"Giải thích: Hành động tiện đường (по дороге) → за-. Giới từ в (vào)."},{"t":"para","text":"2. Когда́ мы гуля́ли, пошёл дождь, и мы (бежа́ть/бе́гать) ... (ближа́йший подъе́зд).","b":1},{"t":"subhead","text":"Đáp án: забежа́ли в ближа́йший подъе́зд (hoặc вбежали)"},{"t":"para","text":"Dịch: Khi chúng tôi đang đi dạo thì trời mưa, và chúng tôi đã chạy (ù) vào cổng tòa nhà gần nhất (để trú)."},{"t":"example","text":"Giải thích: Chạy vào trú tạm thời hoặc ghé vào nhanh → за-. Giới từ в."},{"t":"para","text":"3. Мы (е́хать/е́здить) ... (го́род) и ско́ро оказа́лись в це́нтре.","b":1},{"t":"subhead","text":"Đáp án: въе́хали в го́род","b":1},{"t":"para","text":"Dịch: Chúng tôi đã lái xe vào thành phố và chẳng mấy chốc đã ở trung tâm."},{"t":"example","text":"Giải thích: Đi từ ngoài vào trong ranh giới thành phố → в- (въ-). Giới từ в."},{"t":"para","text":"4. По доро́ге в Но́вгород мы (е́хать/е́здить) ... (Тверь).","b":1},{"t":"subhead","text":"Đáp án: зае́хали в Тверь","b":1},{"t":"para","text":"Dịch: Trên đường đi Novgorod, chúng tôi đã ghé vào Tver."},{"t":"example","text":"Giải thích: Tiện đường ghé qua một địa điểm khác → за-. Giới từ в."},{"t":"para","text":"5. (Нести́/Носи́ть) ... (ко́мната) чемода́ны и поста́вь их на пол.","b":1},{"t":"subhead","text":"Đáp án: Внеси́ в ко́мнату","b":1},{"t":"para","text":"Dịch: Hãy mang vali vào phòng và đặt chúng xuống sàn."},{"t":"example","text":"Giải thích: Mang từ ngoài vào trong → в-. Giới từ в."},{"t":"para","text":"6. Е́сли ты пое́дешь на юг, (везти́/вози́ть) ... (мы) дете́й.","b":1},{"t":"subhead","text":"Đáp án: завези́ к нам (hoặc нам)"},{"t":"para","text":"Dịch: Nếu bạn đi về phía Nam, hãy chở (tiện đường đưa) bọn trẻ ghé qua chỗ chúng tôi."},{"t":"example","text":"Giải thích: Tiện đường chở ai đó đến đâu → за-. Đến chỗ người nào đó → giới từ к (+ Dat)."},{"t":"para","text":"7. Маши́на (е́хать/е́здить) ... (гара́ж).","b":1},{"t":"subhead","text":"Đáp án: въе́хала в гара́ж (hoặc заехала)"},{"t":"para","text":"Dịch: Chiếc xe đã chạy (tiến) vào gara."},{"t":"example","text":"Giải thích: Vào bên trong không gian hẹp → в- hoặc за- (lùi vào/ghé vào). Въехала nhấn mạnh hành động xuyên qua cửa vào trong."},{"t":"para","text":"8. Со́лнце (идти́/ходи́ть) ... (ту́ча), и ста́ло темно́.","b":1},{"t":"subhead","text":"Đáp án: зашло́ за ту́чу","b":1},{"t":"para","text":"Dịch: Mặt trời đã lặn (đi) ra sau đám mây, và trời trở nên tối sầm."},{"t":"example","text":"Giải thích: Chuyển động ra phía sau vật thể → за-. Giới từ за (+ Acc)."},{"t":"para","text":"9. Мяч (лете́ть/лета́ть) ... (воро́та).","b":1},{"t":"subhead","text":"Đáp án: влете́л в воро́та","b":1},{"t":"para","text":"Dịch: Quả bóng đã bay vào khung thành."},{"t":"example","text":"Giải thích: Bay vào bên trong → в-. Giới từ в."},{"t":"para","text":"10. Мяч (кати́ть/ката́ть) ... (дива́н), и мы до́лго не могли́ его́ доста́ть.","b":1},{"t":"subhead","text":"Đáp án: закати́лся за дива́н (động từ phản thân vì bóng tự lăn)"},{"t":"para","text":"Dịch: Quả bóng đã lăn tọt ra sau ghế sofa, và chúng tôi mãi không lấy được."},{"t":"example","text":"Giải thích: Lăn ra phía sau vật cản → за-. Giới từ за."},{"t":"para","text":"11. Кто (нести́/носи́ть) ... (зал) э́тот стул?","b":1},{"t":"subhead","text":"Đáp án: внёс в зал (hoặc принёс)"},{"t":"para","text":"Dịch: Ai đã mang cái ghế này vào phòng sảnh thế?"},{"t":"example","text":"Giải thích: Mang vào trong → в-. Giới từ в."},{"t":"para","text":"12. Он (идти́/ходи́ть) ... (у́гол) до́ма, что́бы ве́тер не дул ему́ в лицо́.","b":1},{"t":"subhead","text":"Đáp án: зашёл за у́гол","b":1},{"t":"para","text":"Dịch: Anh ấy đã đi nấp sau góc nhà để gió không thổi vào mặt."},{"t":"example","text":"Giải thích: Đi ra phía sau vật chắn → за-. Giới từ за."},{"t":"para","text":"13. Мы (плыть/пла́вать) ... (буйки́), и спаса́тель на́чал нам крича́ть.","b":1},{"t":"subhead","text":"Đáp án: заплыли́ за буйки́","b":1},{"t":"para","text":"Dịch: Chúng tôi đã bơi ra sau (vượt quá) phao tiêu, và nhân viên cứu hộ bắt đầu hét gọi chúng tôi."},{"t":"example","text":"Giải thích: Bơi vượt qua giới hạn/ra sau vật mốc → за-. Giới từ за."},{"t":"para","text":"14. (Идти́/Ходи́ть) ... (я) за́втра, я дам тебе́ э́ту кни́гу.","b":1},{"t":"subhead","text":"Đáp án: Зайди́ ко мне","b":1},{"t":"para","text":"Dịch: Mai ghé qua chỗ tôi nhé, tôi sẽ đưa bạn cuốn sách này."},{"t":"example","text":"Giải thích: Ghé thăm ngắn/tiện thể → за-. Đến chỗ người → к (+ Dat)."},{"t":"para","text":"15. (Е́хать/Е́здить) ... (мы) сего́дня ве́чером, мы бу́дем ра́ды вас ви́деть.","b":1},{"t":"subhead","text":"Đáp án: Заезжа́йте к нам","b":1},{"t":"para","text":"Dịch: Tối nay lái xe (ghé) qua chỗ chúng tôi chơi nhé, chúng tôi sẽ rất vui được gặp các bạn."},{"t":"example","text":"Giải thích: Mời ghé thăm bằng phương tiện → за-. Giới từ к."},{"t":"subhead","text":"Gợi ý ngữ pháp (Trang 346)","b":1},{"t":"para","text":"Tiếng Nga: Глаго́лы движе́ния с приста́вкой вы- ука́зывают на движе́ние изнутри́; глаго́лы с приста́вкой с- (со-) — на движе́ние вниз. Глаго́лы движе́ния с приста́вкой вз- (вс-) ука́зывают на движе́ние вверх.","b":1},{"t":"para","text":"Dịch & Giải thích:","b":1},{"t":"example","text":"Động từ chuyển động với tiền tố вы- chỉ chuyển động từ bên trong ra ngoài (trái nghĩa với в-, за- khi mang nghĩa \"vào\")."},{"t":"example","text":"Động từ chuyển động với tiền tố с- (со-) chỉ chuyển động từ trên xuống dưới (trái nghĩa với вз-, за- khi mang nghĩa \"lên\")."},{"t":"para","text":"Động từ chuyển động với tiền tố вз- (вс-) chỉ chuyển động hướng lên trên (lên cao)."}]},{"id":"07-s147","type":"exercise","title":"Bài 646 (Trang 346)","num":646,"blocks":[{"t":"instruction","text":"Yêu cầu: Определи́те значе́ние глаго́лов движе́ния с приста́вкой за-. Испо́льзуя глаго́лы движе́ния с приста́вками вы- и́ли с-, да́йте антоними́чный вариа́нт предложе́ний. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Xác định ý nghĩa của các động từ chuyển động có tiền tố za-. Sử dụng các động từ chuyển động có tiền tố vy- hoặc s-, hãy đưa ra phương án trái nghĩa cho các câu. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"Nguyên tắc chọn từ trái nghĩa:","b":1},{"t":"example","text":"Nếu за- nghĩa là \"đi vào\" (в) → Trái nghĩa là вы- (đi ra)."},{"t":"example","text":"Nếu за- nghĩa là \"leo lên\" (на) → Trái nghĩa là с- (leo xuống)."},{"t":"example","text":"Nếu за- nghĩa là \"đi ra sau\" (за) → Trái nghĩa là вы- (đi ra từ phía sau - из-за)."},{"t":"para","text":"1. В ваго́не я с трудо́м зале́з на ве́рхнюю по́лку.","b":1},{"t":"para","text":"Trái nghĩa: ... я с трудо́м слез с ве́рхней по́лки."},{"t":"para","text":"Dịch: Trong toa tàu, tôi vất vả lắm mới leo lên được giường tầng trên. ↔ ... tôi vất vả lắm mới leo xuống khỏi giường tầng trên."},{"t":"example","text":"Giải thích: Залез на (leo lên bề mặt) ↔ Слез с (leo xuống khỏi bề mặt)."},{"t":"para","text":"2. Мы до́лго не могли́ загна́ть гусе́й во двор.","b":1},{"t":"example","text":"Trái nghĩa: ... вы́гнать гусе́й со двора́ (hoặc из двора́)."},{"t":"para","text":"Dịch: Mãi chúng tôi không thể lùa đàn ngỗng vào sân. ↔ ... đuổi đàn ngỗng ra khỏi sân."},{"t":"example","text":"Giải thích: Загнать в (lùa vào trong) ↔ Выгнать из/с (đuổi ra ngoài)."},{"t":"para","text":"3. Ребя́та зале́зли на де́рево за возду́шным зме́ем.","b":1},{"t":"para","text":"Trái nghĩa: Ребя́та сле́зли с де́рева..."},{"t":"para","text":"Dịch: Lũ trẻ leo lên cây để lấy con diều. ↔ Lũ trẻ leo xuống khỏi cây..."},{"t":"example","text":"Giải thích: Залезть на (lên cây) ↔ Слезть с (xuống cây)."},{"t":"para","text":"4. Пожа́луйста, загони́ велосипе́д в гара́ж.","b":1},{"t":"para","text":"Trái nghĩa: ... вы́гони велосипе́д из гаража́."},{"t":"para","text":"Dịch: Làm ơn dắt (cất) xe đạp vào gara. ↔ ... dắt xe đạp ra khỏi gara."},{"t":"example","text":"Giải thích: Загони в (đưa vào trong) ↔ Выгони из (đưa ra ngoài)."},{"t":"para","text":"5. Не беспоко́йтесь, мы занесём ва́ши ве́щи в кварти́ру.","b":1},{"t":"para","text":"Trái nghĩa: ... мы вы́несем ва́ши ве́щи из кварти́ры."},{"t":"para","text":"Dịch: Đừng lo, chúng tôi sẽ mang đồ của bác vào căn hộ. ↔ ... chúng tôi sẽ mang đồ ra khỏi căn hộ."},{"t":"example","text":"Giải thích: Занести в (mang vào) ↔ Вынести из (mang ra)."},{"t":"para","text":"6. Ты не мог бы за́втра по́сле обе́да завезти́ на да́чу проду́кты?","b":1},{"t":"para","text":"Trái nghĩa: ... вы́везти с да́чи проду́кты?"},{"t":"para","text":"Dịch: Ngày mai sau bữa trưa bạn có thể chở thực phẩm đến nhà nghỉ ngoại ô không? ↔ ... chở thực phẩm từ nhà nghỉ ngoại ô ra/về không?"},{"t":"example","text":"Giải thích: Завезти на (chở đến/vào địa điểm) ↔ Вывезти с (chở ra khỏi)."},{"t":"para","text":"7. Кату́шка ни́ток закати́лась под шкаф.","b":1},{"t":"para","text":"Trái nghĩa: ... вы́катилась из-под шка́фа."},{"t":"para","text":"Dịch: Cuộn chỉ lăn tọt vào dưới gầm tủ. ↔ ... lăn ra từ dưới gầm tủ."},{"t":"example","text":"Giải thích: За- ... под (lăn vào dưới) ↔ Вы- ... из-под (lăn ra từ dưới)."},{"t":"para","text":"8. Двухле́тний ребёнок с трудо́м зале́з на стул.","b":1},{"t":"para","text":"Trái nghĩa: ... слез со сту́ла."},{"t":"para","text":"Dịch: Đứa bé 2 tuổi vất vả lắm mới leo lên được cái ghế. ↔ ... leo xuống khỏi cái ghế."},{"t":"example","text":"Giải thích: Lên ghế (залез на) ↔ Xuống ghế (слез с)."},{"t":"para","text":"9. Снача́ла я не хоте́л идти́, но мой друг затащи́л меня́ на э́ту вечери́нку.","b":1},{"t":"para","text":"Trái nghĩa: ... вы́тащил меня́ с э́той вечери́нки."},{"t":"para","text":"Dịch: Ban đầu tôi không muốn đi, nhưng bạn tôi đã lôi (kéo) tôi đến (vào) buổi tiệc này. ↔ ... lôi tôi ra khỏi buổi tiệc này."},{"t":"example","text":"Giải thích: Затащил на/в (kéo vào) ↔ Вытащил с/из (kéo ra)."},{"t":"para","text":"10. Дава́йте зае́дем в гара́ж, не оставля́ть же маши́ну здесь.","b":1},{"t":"para","text":"Trái nghĩa: Дава́йте вы́едем из гаража́..."},{"t":"para","text":"Dịch: Hãy lái xe vào gara đi, chẳng lẽ lại để xe ở đây. ↔ Hãy lái xe ra khỏi gara..."},{"t":"example","text":"Giải thích: Заехать в (vào trong) ↔ Выехать из (ra ngoài)."},{"t":"para","text":"11. Мяч залете́л на кры́шу шко́лы.","b":1},{"t":"para","text":"Trái nghĩa: Мяч слете́л с кры́ши шко́лы."},{"t":"para","text":"Dịch: Quả bóng bay lên mái trường. ↔ Quả bóng bay (rơi) xuống khỏi mái trường."},{"t":"example","text":"Giải thích: Залетел на (bay lên trên bề mặt) ↔ Слетел с (bay xuống/rơi khỏi bề mặt)."},{"t":"para","text":"12. Мы уви́дели, как он зашёл за у́гол до́ма.","b":1},{"t":"para","text":"Trái nghĩa: ... вы́шел из-за угла́ до́ма."},{"t":"para","text":"Dịch: Chúng tôi thấy anh ấy đi ra sau góc nhà (khuất). ↔ ... đi ra từ sau góc nhà (xuất hiện)."},{"t":"example","text":"Giải thích: Зашел за (đi ra sau) ↔ Вышел из-за (đi ra từ phía sau)."},{"t":"para","text":"13. Кот зале́з на шкаф и притаи́лся.","b":1},{"t":"para","text":"Trái nghĩa: Кот слез со шка́фа..."},{"t":"para","text":"Dịch: Con mèo leo lên nóc tủ và nấp kỹ. ↔ Con mèo leo xuống khỏi nóc tủ..."},{"t":"example","text":"Giải thích: Leo lên cao (залез на) ↔ Leo xuống (слез с)."},{"t":"para","text":"14. Я забежа́л на по́чту, купи́л газе́ту и стал ждать на остано́вке авто́буса.","b":1},{"t":"example","text":"Trái nghĩa: Я вы́бежал с по́чты (hoặc из по́чты)..."},{"t":"para","text":"Dịch: Tôi chạy ù vào bưu điện, mua tờ báo và đứng đợi ở trạm xe buýt. ↔ Tôi chạy ra khỏi bưu điện..."},{"t":"example","text":"Giải thích: Ghé vào nhanh (забежал) ↔ Chạy ra (выбежал)."},{"t":"para","text":"15. Внеза́пно со́лнце зашло́ за ту́чу, и на́ше настрое́ние измени́лось.","b":1},{"t":"para","text":"Trái nghĩa: ... вы́шло из-за ту́чи..."},{"t":"para","text":"Dịch: Bất ngờ mặt trời lặn (đi) ra sau đám mây, và tâm trạng chúng tôi thay đổi. ↔ ... ló ra từ sau đám mây..."},{"t":"example","text":"Giải thích: Đi ra sau vật che khuất (зашло за) ↔ Đi ra khỏi vật che khuất (вышло из-за)."}]},{"id":"07-s148","type":"exercise","title":"Bài 647 (Trang 347)","num":647,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме один из глаголов движения с приставкой за- или вз- (воз-). Объясните ваш выбор. Укажите варианты. (Mở ngoặc đơn, sử dụng dạng cần thiết của một trong các động từ chuyển động với tiền tố za- hoặc vz- (voz-). Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"subhead","text":"Phân biệt:","b":1},{"t":"vocab","ru":"За-","vi":"Ghé vào, tạt qua; đi vào sâu/xa; bắt đầu hành động.","g":null},{"t":"vocab","ru":"Вз- / Воз-","vi":"Di chuyển hướng lên trên (lên cao).","g":null},{"t":"para","text":"1. Спаси́бо за беспоко́йство, но ... (я) (е́хать/е́здить) мой друг на доро́ге в аэропо́рт.","b":1},{"t":"subhead","text":"Đáp án: за мно́й зае́дет","b":1},{"t":"para","text":"Dịch: Cảm ơn bạn đã lo lắng, nhưng bạn tôi sẽ ghé qua đón tôi trên đường ra sân bay."},{"t":"example","text":"Giải thích: Заедет за мной: Tiện đường ghé qua đón ai đó."},{"t":"para","text":"2. Он (идти́/ходи́ть) на престо́л в восемна́дцать лет по́сле сме́рти отца́.","b":1},{"t":"subhead","text":"Đáp án: взошёл","b":1},{"t":"para","text":"Dịch: Ông ấy lên ngôi (ngai vàng) năm 18 tuổi sau cái chết của cha."},{"t":"example","text":"Giải thích: Взойти́ на престо́л: Lên ngôi (nghĩa đen: bước lên cao)."},{"t":"para","text":"3. Самолёт (лета́ть/лете́ть) и раста́ял в во́здухе.","b":1},{"t":"subhead","text":"Đáp án: взлете́л","b":1},{"t":"para","text":"Dịch: Chiếc máy bay cất cánh (bay lên) và tan biến vào không trung."},{"t":"example","text":"Giải thích: Rời mặt đất bay lên cao → взлете́л."},{"t":"para","text":"4. Возвраща́ясь домо́й, мы (брести́/броди́ть) в незнако́мую дере́вню.","b":1},{"t":"subhead","text":"Đáp án: забрели́","b":1},{"t":"para","text":"Dịch: Trên đường về nhà, chúng tôi đã đi lạc (lang thang) vào một ngôi làng lạ."},{"t":"example","text":"Giải thích: Забрести́: Đi lang thang và vô tình vào đâu đó / đi quá xa."},{"t":"para","text":"5. Чу́вство ра́дости переполня́ло его́, он (бежа́ть/бе́гать) по ступе́нькам на тре́тий эта́ж и позвони́л в дверь.","b":1},{"t":"subhead","text":"Đáp án: взбежа́л","b":1},{"t":"para","text":"Dịch: Niềm vui tràn ngập trong lòng, anh ấy chạy vụt lên cầu thang lên tầng 3 và bấm chuông."},{"t":"example","text":"Giải thích: Chạy hướng lên trên (lên tầng) → взбежа́л."},{"t":"para","text":"6. Куда́ ты нас (вести́/води́ть)?","b":1},{"t":"subhead","text":"Đáp án: завёл (hoặc ведёшь)"},{"t":"para","text":"Dịch: Bạn đã dẫn chúng tôi vào đâu thế này? (thường mang nghĩa lạc đường/vào chỗ khó khăn)."},{"t":"example","text":"Giải thích: Завести́: Dẫn vào nơi sâu, xa hoặc lạc đường (giống Ivan Susanin dẫn quân Ba Lan vào rừng)."},{"t":"para","text":"7. Она́ пригласи́ла меня́ (идти́/ходи́ть) к ней поболта́ть.","b":1},{"t":"subhead","text":"Đáp án: зайти́","b":1},{"t":"para","text":"Dịch: Cô ấy mời tôi ghé qua chỗ cô ấy tán gẫu."},{"t":"example","text":"Giải thích: Đến thăm/ghé chơi → зайти́."},{"t":"para","text":"8. Наро́д его́ (вести́/води́ть) на трон, наро́д его́ и све́ргнет отту́да.","b":1},{"t":"subhead","text":"Đáp án: возвёл","b":1},{"t":"para","text":"Dịch: Nhân dân đã đưa ông ta lên ngai vàng, nhân dân cũng sẽ lật đổ ông ta khỏi đó."},{"t":"example","text":"Giải thích: Возвести́ на трон/престол: Đưa lên ngôi (trịnh trọng). Tiền tố воз- chỉ hướng lên cao (nghĩa bóng và đen)."},{"t":"para","text":"9. Когда́ (идти́/ходи́ть) со́лнце, лес напо́лнился пе́нием птиц.","b":1},{"t":"subhead","text":"Đáp án: взошло́","b":1},{"t":"para","text":"Dịch: Khi mặt trời mọc (lên), khu rừng tràn ngập tiếng chim hót."},{"t":"example","text":"Giải thích: Mặt trời mọc → взошло́ (đi lên)."},{"t":"para","text":"10. Разда́лся лай соба́к, и из-под мои́х ног с кри́ком (лете́ть/лета́ть) се́рые куропа́тки.","b":1},{"t":"subhead","text":"Đáp án: взлете́ли","b":1},{"t":"para","text":"Dịch: Tiếng chó sủa vang lên, và từ dưới chân tôi những con gà gô xám kêu quang quác bay vụt lên."},{"t":"example","text":"Giải thích: Bay từ dưới đất lên cao → взлете́ли."},{"t":"para","text":"11. Я (идти́/ходи́ть) в парикма́херскую побри́ться.","b":1},{"t":"subhead","text":"Đáp án: зашёл (đã ghé vào) hoặc захожу (đang ghé vào). Thường dùng quá khứ trong kể chuyện."},{"t":"para","text":"Dịch: Tôi đã tạt (ghé) vào tiệm cắt tóc để cạo râu."},{"t":"example","text":"Giải thích: Ghé vào một địa điểm trong thời gian ngắn/tiện đường → зашёл."},{"t":"para","text":"12. Бушева́вший над тайго́й ого́нь (нести́/носи́ть) к не́бу столбы́ чёрного ды́ма.","b":1},{"t":"subhead","text":"Đáp án: возноси́л (hoặc вздыма́л - nhưng đề bài yêu cầu gốc нести thì dùng возносил)."},{"t":"para","text":"Dịch: Ngọn lửa hoành hành trên cánh rừng taiga bốc (đưa) những cột khói đen lên tận trời."},{"t":"example","text":"Giải thích: Đưa lên cao (về phía bầu trời) → возноси́л (mang sắc thái mạnh/cao/trịnh trọng). [i]"}]},{"id":"07-s149","type":"exercise","title":"Bài 648 (Trang 347)","num":648,"blocks":[{"t":"instruction","text":"Yêu cầu: Прочита́йте предложе́ния, обраща́я внима́ние на усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками. Определи́те их значе́ние. (Đọc các câu, chú ý đến các cụm từ cố định (thành ngữ) với động từ chuyển động có tiền tố. Xác định ý nghĩa của chúng)."},{"t":"example","text":"1. Всё вре́мя он пыта́ется перейти́ нам доро́гу, захвати́ть са́мые вы́годные зака́зы, но, ду́маю, вряд ли ему́ уда́стся нас обойти́.","b":1},{"t":"para","text":"Ý nghĩa: Cản đường, ngáng trở, tranh giành quyền lợi."},{"t":"para","text":"Dịch: Lúc nào hắn cũng cố ngáng đường chúng ta, hớt tay trên những đơn hàng béo bở nhất, nhưng tôi nghĩ hắn khó mà vượt mặt được chúng ta."},{"t":"example","text":"2. Подожди́ немно́го, дай мне перевести́ дух, я о́чень уста́л, пока́ поднима́лся на девя́тый эта́ж.","b":1},{"t":"para","text":"Ý nghĩa: Nghỉ lấy hơi, nghỉ một lát cho lại sức."},{"t":"para","text":"Dịch: Đợi một chút, để tôi thở (nghỉ lấy hơi) đã, tôi mệt quá khi leo bộ lên tầng 9."},{"t":"example","text":"3. Сказа́ть нам по э́тому по́воду не́чего, ду́маю, э́тот вопро́с мы обойдём молча́нием, что́бы не обостря́ть отноше́ния.","b":1},{"t":"para","text":"Ý nghĩa: Lờ đi, không nhắc tới, giữ im lặng về vấn đề gì."},{"t":"para","text":"Dịch: Chúng tôi chẳng có gì để nói về vụ này cả, tôi nghĩ chúng ta sẽ lờ đi (bỏ qua trong im lặng) vấn đề này để không làm căng thẳng thêm các mối quan hệ."},{"t":"example","text":"4. Мы разгада́ем его́ наме́рения, ему́ не уда́стся обвести́ нас вокру́г па́льца.","b":1},{"t":"para","text":"Ý nghĩa: Lừa gạt, xỏ mũi, chơi khăm ai đó một cách khôn khéo."},{"t":"para","text":"Dịch: Chúng ta sẽ đoán ra ý đồ của hắn, hắn sẽ không thể xỏ mũi (lừa) chúng ta đâu."},{"t":"example","text":"5. Мы зашли́ сли́шком далеко́, тепе́рь тру́дно что́-либо меня́ть.","b":1},{"t":"para","text":"Ý nghĩa: Đã lún quá sâu, hành động đã tiến triển đến mức khó quay đầu lại hoặc thay đổi."},{"t":"para","text":"Dịch: Chúng ta đã lún quá sâu (đi quá xa) rồi, bây giờ khó mà thay đổi được gì nữa."},{"t":"example","text":"6. От всех э́тих вопро́сов у меня́ ум за ра́зум зашёл, я совсе́м переста́л что́-либо понима́ть.","b":1},{"t":"para","text":"Ý nghĩa: Rối trí, mụ mẫm đầu óc, không còn suy nghĩ sáng suốt được."},{"t":"para","text":"Dịch: Vì tất cả những câu hỏi này mà tôi rối tinh rối mù (đầu óc mụ mẫm), tôi hoàn toàn chẳng hiểu gì nữa cả."},{"t":"example","text":"7. Не на́до загоня́ть его́ в у́гол, ина́че тру́дно бу́дет контроли́ровать его́ де́йствия.","b":1},{"t":"para","text":"Ý nghĩa: Dồn vào thế bí, dồn vào chân tường (khiến ai đó không còn lối thoát)."},{"t":"para","text":"Dịch: Đừng dồn cậu ta vào chân tường, nếu không sẽ rất khó kiểm soát hành động của cậu ta đấy."},{"t":"example","text":"8. Куда́ э́то нас занесла́ нелёгкая?","b":1},{"t":"para","text":"Ý nghĩa: \"Cơn gió độc nào thổi chúng ta tới đây?\" (Câu cảm thán dùng khi bị lạc đến nơi xa lạ, khó chịu hoặc không mong muốn)."},{"t":"para","text":"Dịch: Cái quái gì đưa (khiến) chúng ta tới chốn này thế này?"},{"t":"example","text":"9. Он по у́ши зале́з в долги́, не зна́ю, как он бу́дет выкру́чиваться.","b":1},{"t":"para","text":"Ý nghĩa: Nợ nần chồng chất, nợ ngập đầu."},{"t":"para","text":"Dịch: Cậu ta đã nợ ngập đầu (chui vào nợ đến tận tai), tôi không biết cậu ta sẽ xoay xở thế nào."}]},{"id":"07-s150","type":"exercise","title":"Bài 649 (Trang 347)","num":649,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя усто́йчивые словосочета́ния с глаго́лами движе́ния с приста́вками пре-, об- (обо-), за-, к вы́деленным словосочета́ниям подбери́те сино́нимы. (Sử dụng các cụm từ cố định với động từ chuyển động có tiền tố pre-, ob- (obo-), za-, hãy tìm từ đồng nghĩa cho các cụm từ được in đậm)."},{"t":"example","text":"1. Он челове́к о́чень у́мный и хи́трый, его́ тру́дно обману́ть.","b":1},{"t":"subhead","text":"Đáp án: трудно обвести́ вокру́г па́льца","b":1},{"t":"para","text":"Dịch: Ông ta là người rất thông minh và ranh mãnh, khó mà lừa (xỏ mũi) được ông ta."},{"t":"example","text":"2. Кто э́то там не во́время пришёл?","b":1},{"t":"subhead","text":"Đáp án: кого́ там нелёгкая принесла́ (занесла́)","b":1},{"t":"para","text":"Dịch: Đứa nào (cơn gió độc nào) lại đến không đúng lúc thế kia?"},{"t":"example","text":"3. Я ду́маю, он наме́ренно не упомяну́л о на́шей пробле́ме в своём докла́де.","b":1},{"t":"subhead","text":"Đáp án: обошёл молча́нием (hoặc наме́ренно обошёл)"},{"t":"para","text":"Dịch: Tôi nghĩ anh ấy đã cố tình lờ đi (không nhắc đến) vấn đề của chúng ta trong báo cáo của mình."},{"t":"example","text":"4. Свои́ми де́йствиями он поста́вил нас в безвы́ходное положе́ние.","b":1},{"t":"subhead","text":"Đáp án: загна́л нас в у́гол","b":1},{"t":"para","text":"Dịch: Bằng những hành động của mình, hắn ta đã dồn chúng tôi vào chân tường."},{"t":"example","text":"5. Я хочу́ отдохну́ть, а пото́м мы продо́лжим рабо́ту.","b":1},{"t":"subhead","text":"Đáp án: перевести́ дух","b":1},{"t":"para","text":"Dịch: Tôi muốn nghỉ lấy hơi (nghỉ một lát), rồi chúng ta sẽ tiếp tục làm việc."},{"t":"example","text":"6. Я бою́сь, что сейча́с он не в состоя́нии разу́мно рассужда́ть и де́йствовать.","b":1},{"t":"subhead","text":"Đáp án: у него́ ум за ра́зум зашёл","b":1},{"t":"para","text":"Dịch: Tôi sợ là lúc này cậu ấy đang rối trí (đầu óc mụ mẫm) và không thể hành động hợp lý."},{"t":"example","text":"7. Он до́лжен всем вокру́г, не представля́ю, где ему́ уда́стся доста́ть де́нег, что́бы расплати́ться.","b":1},{"t":"subhead","text":"Đáp án: он по у́ши зале́з в долги́","b":1},{"t":"para","text":"Dịch: Hắn nợ tất cả mọi người xung quanh, hắn đã nợ ngập đầu rồi, không hiểu hắn kiếm đâu ra tiền mà trả."},{"t":"example","text":"8. Ду́маю, в коне́чном ито́ге, мы смо́жем перехвати́ть у них э́тот зака́з.","b":1},{"t":"subhead","text":"Đáp án: смо́жем перейти́ им доро́гу","b":1},{"t":"para","text":"Dịch: Tôi nghĩ, rốt cuộc chúng ta sẽ ngáng đường (hớt tay trên) được cái đơn hàng này của họ."},{"t":"example","text":"9. Он о́чень хитёр, ещё никому́ не удава́лось его́ обману́ть.","b":1},{"t":"subhead","text":"Đáp án: никому́ не удава́лось обвести́ его́ вокру́г па́льца","b":1},{"t":"para","text":"Dịch: Hắn rất ranh ma, chưa ai có thể lừa (xỏ mũi) được hắn."}]},{"id":"07-s151","type":"exercise","title":"Bài 650 (Trang 348)","num":650,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте в ну́жной фо́рме необходи́мые по смы́слу глаго́лы движе́ния с приста́вками пере-, об-, за-, вз-(вс-), по-, у-, при-, до-, в-(во-), от-, пере-, про-. Объясни́те ваш вы́бор. (Thay dấu ba chấm bằng các động từ chuyển động cần thiết theo ý nghĩa ở dạng thích hợp với các tiền tố được liệt kê. Giải thích sự lựa chọn của bạn)."},{"t":"example","text":"(Đây là một đoạn văn liền mạch kể về chuyến đi hái nấm)."},{"t":"para","text":"1. В суббо́ту мы реши́ли ... в да́льний лес за гриба́ми.","b":1},{"t":"subhead","text":"Đáp án: пое́хать / пойти́","b":1},{"t":"para","text":"Dịch: Thứ Bảy chúng tôi quyết định đi vào khu rừng xa để hái nấm."},{"t":"example","text":"Giải thích: Bắt đầu hành động di chuyển/dự định → по-."},{"t":"para","text":"2. Идти́ на́до бы́ло до́лго, поэ́тому мы ... из до́ма, когда́ со́лнце то́лько начина́ло ... на горизо́нте.","b":1},{"t":"subhead","text":"Đáp án: вы́шли; всходи́ть"},{"t":"para","text":"Dịch: Phải đi bộ xa, nên chúng tôi ra khỏi nhà khi mặt trời mới bắt đầu mọc (lên) ở chân trời."},{"t":"example","text":"Giải thích: Rời khỏi nhà → вы-. Mặt trời mọc → всходи́ть (đi lên)."},{"t":"para","text":"3. По доро́ге мы ... в сосе́дний дом за на́шими друзья́ми, кото́рые собира́лись ... вме́сте с на́ми.","b":1},{"t":"subhead","text":"Đáp án: зашли́; пойти́"},{"t":"para","text":"Dịch: Trên đường đi, chúng tôi ghé vào nhà hàng xóm đón bạn bè, những người cũng định đi cùng chúng tôi."},{"t":"example","text":"Giải thích: Ghé qua tiện đường → за-. Định đi cùng → пойти."},{"t":"para","text":"4. Путь наш лежа́л на се́вер. Мы ... ми́мо шлагба́ума, ... железнодоро́жную доро́гу и ... к боло́ту.","b":1},{"t":"subhead","text":"Đáp án: прошли́; перешли́; подошли́ (hoặc вышли)"},{"t":"para","text":"Dịch: Đường đi hướng về phía Bắc. Chúng tôi đi qua thanh chắn, băng qua đường sắt và đến (sát) đầm lầy."},{"t":"example","text":"Giải thích: Đi ngang qua → про-. Băng qua vật cản → пере-. Đến gần đích → под-."},{"t":"para","text":"5. Ле́то в э́том году́ бы́ло дождли́вым, и мы по́няли, что ... че́рез боло́то нам не уда́стся.","b":1},{"t":"subhead","text":"Đáp án: пройти́ (hoặc перейти́ / перебра́ться)"},{"t":"para","text":"Dịch: Mùa hè năm nay mưa nhiều, và chúng tôi hiểu rằng không thể đi (xuyên) qua đầm lầy được."},{"t":"example","text":"Giải thích: Vượt qua chướng ngại vật khó khăn → пройти (xuyên qua) hoặc перейти (sang bờ kia)."},{"t":"para","text":"6. Пришло́сь ... его́.","b":1},{"t":"subhead","text":"Đáp án: обходи́ть (hoặc обойти́)"},{"t":"para","text":"Dịch: Đành phải đi vòng qua nó."},{"t":"example","text":"Giải thích: Đi tránh chướng ngại vật → об-."},{"t":"para","text":"7. На э́то до́лжно бы́ло ... мину́т со́рок.","b":1},{"t":"subhead","text":"Đáp án: уйти́","b":1},{"t":"para","text":"Dịch: Việc này chắc phải mất (tiêu tốn) 40 phút."},{"t":"example","text":"Giải thích: Thời gian bị tiêu tốn → уйти."},{"t":"para","text":"8. К сча́стью, нам попа́лся попу́тный грузови́к, кото́рый нас ... как бли́же к ле́су.","b":1},{"t":"subhead","text":"Đáp án: подвёз","b":1},{"t":"para","text":"Dịch: May thay, chúng tôi gặp một chiếc xe tải đi cùng chiều, nó đã chở chúng tôi đến gần rừng hơn."},{"t":"example","text":"Giải thích: Cho đi nhờ/chở đến gần → подвёз (под- + везти)."},{"t":"para","text":"9. Когда́ мы ... до да́льнего ле́са, со́лнце ... за ту́чи, и мы опаса́лись, что в любу́ю мину́ту мо́жет ... дождь.","b":1},{"t":"subhead","text":"Đáp án: дое́хали (hoặc добрали́сь); зашло́; пойти́"},{"t":"para","text":"Dịch: Khi chúng tôi đến (bằng xe) khu rừng xa, mặt trời đã lặn (khuất) sau mây, và chúng tôi lo rằng mưa có thể đổ (bắt đầu) bất cứ lúc nào."},{"t":"example","text":"Giải thích: Đến đích → до-. Mặt trời khuất sau mây → за-. Mưa bắt đầu → пойти."},{"t":"para","text":"10. Мы ... в лес и разби́лись на небольши́е гру́ппы, что́бы удо́бнее бы́ло иска́ть грибы́.","b":1},{"t":"subhead","text":"Đáp án: вошли́","b":1},{"t":"para","text":"Dịch: Chúng tôi bước vào rừng và chia thành các nhóm nhỏ để tìm nấm dễ hơn."},{"t":"example","text":"Giải thích: Vào trong không gian (rừng) → в-."},{"t":"para","text":"11. Лес был ста́рым, ... запу́щенным, ка́ждую мину́ту нам прихо́дилось ... под пова́ленными бу́рей дере́вьями и ... че́рез кана́вы.","b":1},{"t":"subhead","text":"Đáp án: (подо) / за- (chỗ này sách in hơi lạ, có thể là tính từ запущенным đã đủ, nếu điền động từ thì là заросшим - mọc um tùm, nhưng đề bài yêu cầu động từ chuyển động? Có thể là lỗi in ấn hoặc казался? Nếu bỏ qua từ đầu tiên trong cụm này...); подлеза́ть; перепры́гивать / переступа́ть / перелеза́ть"},{"t":"para","text":"Dịch: Khu rừng già, (trông) hoang vắng, cứ mỗi phút chúng tôi lại phải chui dưới những cây bị bão quật đổ và nhảy/leo qua các con hào."},{"t":"example","text":"Giải thích: Chui xuống dưới → подлеза́ть. Vượt qua hào → пере-."},{"t":"vocab","ru":"Бы́ло ти́хо","vi":"пти́цы стара́лись ... э́тот лес стороно́й.","g":null},{"t":"subhead","text":"Đáp án: облета́ть (hoặc обходи́ть)"},{"t":"para","text":"Dịch: Trời yên tĩnh: chim chóc cố gắng bay tránh (vòng qua) khu rừng này."},{"t":"example","text":"Giải thích: Bay tránh → об-."},{"t":"para","text":"13. Да и люде́й сюда́ ре́дко ... нелёгкая.","b":1},{"t":"subhead","text":"Đáp án: зано́сит","b":1},{"t":"para","text":"Dịch: Và hiếm khi có ngọn gió nào đưa (thổi) người ta tới đây."},{"t":"example","text":"Giải thích: Thành ngữ заносит нелёгкая (bị đưa đẩy tới nơi không ngờ)."},{"t":"para","text":"14. Грибо́в бы́ло мно́го, хотя́ ка́ждую мину́ту приходи́лось ... от лица́ назо́йливых комаро́в.","b":1},{"t":"subhead","text":"Đáp án: отма́хиваться (Đây là động từ phản thân từ gốc махать, nhưng махать cũng là động từ chỉ cử động/chuyển động tay. Nếu bắt buộc dùng list đề bài thì khó, nhưng ngữ cảnh này chắc chắn là отмахиваться - xua đuổi)."},{"t":"para","text":"Dịch: Nấm rất nhiều, mặc dù cứ mỗi phút lại phải xua lũ muỗi dai dẳng khỏi mặt."},{"t":"para","text":"15. Внеза́пно из-под мои́х ног ... небольша́я пти́ца.","b":1},{"t":"subhead","text":"Đáp án: вы́летела (hoặc взлете́ла)"},{"t":"para","text":"Dịch: Bất ngờ từ dưới chân tôi một con chim nhỏ bay vụt ra."},{"t":"example","text":"Giải thích: Bay từ trong ra/từ dưới lên → вы- hoặc вз-."},{"t":"para","text":"16. Я останови́лся, что́бы ... дух, и заме́тил в траве́ гнездо́.","b":1},{"t":"subhead","text":"Đáp án: перевести́","b":1},{"t":"para","text":"Dịch: Tôi dừng lại để thở (lấy hơi) và nhận thấy một cái tổ trong cỏ."},{"t":"example","text":"Giải thích: Thành ngữ перевести́ дух."},{"t":"para","text":"17. Я ... из гнезда́ небольшо́е яйцо́, внима́тельно рассмотре́л его и положи́л обра́тно.","b":1},{"t":"subhead","text":"Đáp án: вы́нул (động từ вынуть không phải là động từ chuyển động thuần túy nhưng hay đi kèm nhóm này. Nếu bắt buộc động từ chuyển động gốc: вы́тащил - lôi ra). Sách Glazunova đôi khi mở rộng danh sách. Dùng вы́тащил hoặc достал là hợp lý nhất."},{"t":"para","text":"Dịch: Tôi lấy (lôi) từ trong tổ ra một quả trứng nhỏ, ngắm nghía kỹ rồi đặt lại."},{"t":"para","text":"18. Че́рез не́которое вре́мя мы обнару́жили, что ... сли́шком далеко́ в лес.","b":1},{"t":"subhead","text":"Đáp án: зашли́","b":1},{"t":"para","text":"Dịch: Một lúc sau, chúng tôi phát hiện ra mình đã đi quá sâu (lạc) vào rừng."},{"t":"example","text":"Giải thích: Đi sâu vào/quá xa → зашли."},{"t":"para","text":"19. Мы ста́ли крича́ть, что́бы ... на́ших друзе́й.","b":1},{"t":"subhead","text":"Đáp án: позва́ть (gọi) hoặc найти́ (tìm). Tìm (найти) có gốc идти (на-йти)."},{"t":"para","text":"Dịch: Chúng tôi bắt đầu hét lên để gọi/tìm bạn bè."},{"t":"para","text":"20. У всех ... от се́рдца.","b":1},{"t":"subhead","text":"Đáp án: отлегло́","b":1},{"t":"para","text":"Dịch: Mọi người đều thở phào nhẹ nhõm (trút được gánh nặng trong tim)."},{"t":"example","text":"Giải thích: Thành ngữ отлегло от сердца."},{"t":"para","text":"21. Мы встре́тились и обменя́лись впечатле́ниями. Кто́-то рассказа́л, что ... от медве́дя в двух шага́х и е́ле унёс но́ги.","b":1},{"t":"subhead","text":"Đáp án: прошёл","b":1},{"t":"para","text":"Dịch: Ai đó kể rằng đã đi qua một con gấu chỉ cách hai bước chân và suýt thì không chạy thoát (vắt chân lên cổ mà chạy)."},{"t":"example","text":"Giải thích: Đi ngang qua → прошёл."},{"t":"para","text":"22. Кто-то упа́л в кана́ву с водо́й и с трудо́м смог ... её.","b":1},{"t":"subhead","text":"Đáp án: перейти́ (hoặc переле́зть)"},{"t":"para","text":"Dịch: Ai đó ngã xuống hào nước và vất vả lắm mới vượt qua (leo qua) được nó."},{"t":"example","text":"Giải thích: Vượt qua vật cản → пере-. Lưu ý: câu gốc có thể là \"vượt qua\" hoặc \"leo ra khỏi\" (вылезти из), nhưng vì có từ её (Accusative) nên phải dùng động từ chuyển tiếp như перейти/перелезть."},{"t":"para","text":"23. Кто-то ви́дел, как впереди́ за дере́вьями ... олень, кого́-то напуга́ла змея́, кото́рая ... из-под ка́мня.","b":1},{"t":"subhead","text":"Đáp án: промелькну́л / пробежа́л; вы́ползла"},{"t":"para","text":"Dịch: Ai đó thấy đằng trước sau hàng cây một con hươu vụt qua/chạy qua, ai đó bị dọa bởi con rắn bò ra từ dưới tảng đá."},{"t":"example","text":"Giải thích: Chạy vụt qua → про-. Bò từ dưới lên/ra → вы-."},{"t":"para","text":"24. Но, в це́лом, всё зако́нчилось благополу́чно. Отдохну́в, мы ... домо́й.","b":1},{"t":"subhead","text":"Đáp án: пое́хали / дви́нулись / пошли́ (hoặc отпра́вились)"},{"t":"para","text":"Dịch: Nhưng nhìn chung, mọi thứ kết thúc tốt đẹp. Nghỉ ngơi xong, chúng tôi lên đường/đi về nhà."},{"t":"example","text":"Giải thích: Bắt đầu di chuyển về → по-."},{"t":"para","text":"25. В э́тот день ка́ждый из нас ... домо́й по це́лой корзи́не грибо́в.","b":1},{"t":"subhead","text":"Đáp án: принёс (hoặc привёз)"},{"t":"para","text":"Dịch: Hôm đó mỗi người chúng tôi mang (đem) về nhà cả một giỏ nấm đầy."},{"t":"example","text":"Giải thích: Mang về đến đích → при-."},{"t":"para","text":"26. Часть грибо́в мы пожа́рили, другу́ю часть ... в го́род.","b":1},{"t":"subhead","text":"Đáp án: отвезли́ (hoặc увезли́)"},{"t":"para","text":"Dịch: Một phần nấm chúng tôi xào, phần còn lại chở (mang) lên thành phố."},{"t":"example","text":"Giải thích: Mang đi nơi khác → от- hoặc у-."},{"t":"para","text":"27. Ле́то бы́стро ..., и зимо́й мы бу́дем вспомина́ть о нём, открыва́я пригото́вленные ле́том ба́нки с гриба́ми и я́годами.","b":1},{"t":"subhead","text":"Đáp án: прошло́ / пролете́ло","b":1},{"t":"para","text":"Dịch: Mùa hè nhanh chóng trôi qua (bay vèo qua), và mùa đông chúng tôi sẽ nhớ về nó khi mở những lọ nấm và quả mọng đã chuẩn bị từ hè."},{"t":"example","text":"Giải thích: Thời gian trôi qua → про-. [i]"}]},{"id":"07-s152","type":"exercise","title":"Bài 651 (Trang 349)","num":651,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, поставив глагол в форме настоящего или будущего простого времени. (Mở ngoặc đơn, chia động từ ở thì hiện tại hoặc tương lai đơn)."},{"t":"note","text":"Lưu ý: Các câu trong bài là thơ, nên trật tự từ có thể đảo lộn so với văn xuôi."},{"t":"vocab","ru":"Он мы́слит","vi":"\"Бу́ду ей спаси́тель. Не (потерпе́ть) чтоб разврати́тель Огне́м и вздо́хов и похва́л Младо́е се́рдце искуша́л\".","g":null},{"t":"subhead","text":"Đáp án: потерплю́","b":1},{"t":"para","text":"Dịch: Chàng nghĩ: \"Ta sẽ là vị cứu tinh của nàng. Ta sẽ không chịu đựng (để yên) cho kẻ trụy lạc dùng lửa của những tiếng thở dài và lời ca tụng để cám dỗ trái tim non trẻ\"."},{"t":"example","text":"Giải thích: Động từ потерпе́ть (hoàn thành thể). Trong ngữ cảnh \"sẽ không chịu đựng\", ta dùng thì tương lai đơn ngôi thứ nhất số ít (я - ta/tôi) → потерплю́."},{"t":"vocab","ru":"[я] (Заме́тить) кста́ти","vi":"все поэ́ты — Любви́ мечта́тельной друзья́.","g":null},{"t":"subhead","text":"Đáp án: Заме́чу","b":1},{"t":"para","text":"Dịch: Nhân tiện tôi sẽ lưu ý (nhắc) rằng: tất cả các nhà thơ đều là bạn của tình yêu mơ mộng."},{"t":"example","text":"Giải thích: Động từ заме́тить (hoàn thành thể). Hành động người nói thực hiện ngay lúc nói hoặc hướng tới tương lai gần như một lời nhận xét → Tương lai đơn ngôi thứ nhất số ít → заме́чу."},{"t":"vocab","ru":"Я был рождён для жи́зни ми́рной, Для дереве́нской тишины́","vi":"В глуши́ звучне́е го́лос ли́рный, Живе́е тво́рческие сны. Досу́гам посвятясь неви́нным, (Броди́ть) над о́зером пусты́нным, И far niente мой зако́н.","g":null},{"t":"subhead","text":"Đáp án: Брожу́","b":1},{"t":"example","text":"Dịch: Tôi sinh ra cho cuộc sống thanh bình, cho sự tĩnh lặng chốn thôn quê: Trong nơi hẻo lánh giọng đàn lyre vang hơn, những giấc mơ sáng tạo sống động hơn. Hiến mình cho những thú vui vô tội, tôi lang thang bên hồ nước vắng, và \"nhàn rỗi\" (far niente) là quy luật của tôi."},{"t":"example","text":"Giải thích: Động từ броди́ть (chưa hoàn thành thể). Diễn tả thói quen/hành động lặp lại ở hiện tại → Thì hiện tại ngôi thứ nhất số ít → брожу́."},{"t":"vocab","ru":"Я ка́ждым у́тром пробуждён Для сла́дкой не́ги и свобо́ды","vi":"Чита́ю ма́ло, до́лго (спать), Лету́чей сла́вы не (лови́ть).","g":null},{"t":"subhead","text":"Đáp án: сплю; ловлю́"},{"t":"para","text":"Dịch: Mỗi sáng tôi thức dậy cho sự an nhàn ngọt ngào và tự do: Tôi đọc ít, ngủ nhiều (lâu), chẳng màng (bắt) vinh quang phù du."},{"t":"example","text":"Giải thích: Cả hai động từ спать và лови́ть đều là chưa hoàn thành thể, diễn tả thói quen hằng ngày → Thì hiện tại ngôi tôi (я) → сплю và ловлю́."},{"t":"para","text":"5. [Я] (Изобрази́ть) ль в карти́не ве́рной Уединённый кабине́т, Где мод воспи́танник приме́рный Оде́т, разде́т и вновь оде́т?","b":1},{"t":"subhead","text":"Đáp án: Изображу́","b":1},{"t":"para","text":"Dịch: Liệu tôi có nên khắc họa (vẽ) trong một bức tranh chân thực căn phòng làm việc biệt lập, nơi người học trò gương mẫu của thời trang được mặc đồ, cởi đồ rồi lại mặc đồ?"},{"t":"example","text":"Giải thích: Động từ изобрази́ть (hoàn thành thể). Diễn tả ý định/khả năng trong tương lai → Tương lai đơn ngôi tôi (я) → изображу́."},{"t":"para","text":"6. И ны́не му́зу я впервы́е На све́тский ра́ут (приводи́ть); На пре́лести её степны́е С ревни́вой ро́бостью (гляде́ть).","b":1},{"t":"subhead","text":"Đáp án: привожу́; гляжу́"},{"t":"para","text":"Dịch: Và nay lần đầu tiên tôi đưa nàng thơ đến buổi tiệc thượng lưu; Tôi nhìn những vẻ đẹp thảo nguyên của nàng với sự rụt rè ghen tuông."},{"t":"example","text":"Giải thích: Приводи́ть và гляде́ть (chưa hoàn thành thể). Hành động đang diễn ra hoặc kể lại ở hiện tại (ны́не - ngày nay/bây giờ) → Thì hiện tại ngôi tôi → привожу́, гляжу́."},{"t":"para","text":"7. Кто заступи́л¹ Мавру́шу? признаю́сь, Не ве́даю и ко́нчить (торопи́ться).","b":1},{"t":"subhead","text":"Đáp án: тороплю́сь","b":1},{"t":"para","text":"Dịch: Ai thế chỗ Mavrusha? Thú thật, tôi không biết và tôi đang vội kết thúc đây."},{"t":"example","text":"Chú thích sách: ¹ Заступи́ть (từ cổ) = chiếm chỗ của ai đó."},{"t":"example","text":"Giải thích: Торопи́ться (chưa hoàn thành thể) → Thì hiện tại ngôi tôi → тороплю́сь."},{"t":"para","text":"8. Гада́ет ста́рость сквозь очки́ У гробово́й свое́й доски́, Всё потеря́в невозврати́мо; И всё равно́: наде́жда им (Лгать) де́тским ле́петом свои́м (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: лжёт","b":1},{"t":"para","text":"Dịch: Tuổi già đeo kính đoán mò bên tấm ván quan tài của mình, đã mất tất cả không thể vãn hồi; Nhưng cũng vậy thôi: hy vọng vẫn nói dối họ bằng những lời bập bẹ trẻ con của mình."},{"t":"example","text":"Giải thích: Chủ ngữ là наде́жда (hy vọng - ngôi thứ 3 số ít), động từ лгать (chưa hoàn thành thể) → Thì hiện tại → лжёт."},{"t":"para","text":"9. (Иска́ть) я в э́том ми́ре сочета́нья Прекра́сного и ве́чного. Вдали́ Я (ви́деть) ночь: пески́ среди́ молча́нья И звёздный свет над су́мраком земли́ (И.Бу́нин).","b":1},{"t":"subhead","text":"Đáp án: Ищу́; ви́жу"},{"t":"para","text":"Dịch: Tôi tìm kiếm trong thế giới này sự kết hợp giữa cái Đẹp và cái Vĩnh hằng. Đằng xa tôi thấy màn đêm: những bãi cát giữa sự im lặng và ánh sao trên bóng tối của thế gian."},{"t":"example","text":"Giải thích: Иска́ть và ви́деть (chưa hoàn thành thể) → Thì hiện tại ngôi tôi → ищу́, ви́жу."}]},{"id":"07-s153","type":"exercise","title":"Bài 652 (Trang 349-350)","num":652,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, поставив глагол в форме императива. (Mở ngoặc đơn, chia động từ ở dạng Mệnh lệnh thức)."},{"t":"para","text":"1. Не (ве́рить), не (ве́рить) себе́, мечта́тель молодо́й, Как я́звы, (боя́ться) вдохнове́нья... Оно́ тяжёлый бред души́ твое́й больно́й Иль пле́нной мы́сли раздраже́нье (М.Ле́рмонтов).","b":1},{"t":"subhead","text":"Đáp án: верь; верь; бо́йся"},{"t":"para","text":"Dịch: Đừng tin, đừng tin vào chính mình, hỡi kẻ mộng mơ trẻ tuổi, hãy sợ cảm hứng như sợ vết loét... Nó là cơn mê sảng nặng nề của tâm hồn bệnh hoạn hay là sự kích động của tư duy tù túng."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Не ве́рить (Imperative phủ định thường dùng chưa hoàn thành thể) → не верь."},{"t":"example","text":"Боя́ться (sợ hãi - trạng thái kéo dài/lời khuyên chung) → бо́йся."},{"t":"vocab","ru":"\"Ах, ня́ня, ня́ня, я тоску́ю, Мне то́шно, ми́лая моя́","vi":"Я пла́кать, я рыда́ть гото́ва!..\" — \"Дитя́ моё, ты нездоро́ва; Госпо́дь поми́луй и (спасти́)! Чего́ ты хо́чешь, (попроси́ть)...\".","g":null},{"t":"subhead","text":"Đáp án: спаси́; попроси́"},{"t":"para","text":"Dịch: \"Ôi vú em, vú em, con buồn quá, con thấy nôn nao, vú yêu dấu ơi: Con chực khóc, chực nức nở đây này!..\" — \"Con của ta, con ốm rồi; Xin Chúa thương xót và cứu giúp! Con muốn gì, hãy xin (bảo) đi...\"."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Спасти́ (cầu khẩn Chúa giúp một lần cụ thể - hoàn thành thể) → спаси́."},{"t":"example","text":"Попроси́ть (đề nghị thực hiện hành động cụ thể - hoàn thành thể) → попроси́."},{"t":"para","text":"3. (Помоли́ться) о ни́щей, о поте́рянной, О мое́й живо́й душе́, Ты в свои́х путя́х всегда́ уве́ренный, Свет узре́вший в шалаше́ (А.Ахма́това).","b":1},{"t":"subhead","text":"Đáp án: Помоли́сь","b":1},{"t":"para","text":"Dịch: Hãy cầu nguyện cho kẻ khốn cùng, cho kẻ lạc lối, cho linh hồn đang sống của tôi, hỡi người luôn vững tin trên con đường của mình, người đã thấy ánh sáng trong túp lều."},{"t":"example","text":"Giải thích: Помоли́ться (hoàn thành thể - yêu cầu thực hiện một hành động trọn vẹn) → Помоли́сь."},{"t":"vocab","ru":"Поп говори́т Балде́","vi":"\"Ла́дно. Не бу́дет нам обо́им накла́дно. (Пожи́ть)-ка на моём подво́рье, (Оказа́ть) своё усе́рдье и прово́рье²\".","g":null},{"t":"subhead","text":"Đáp án: Поживи́; окажи́"},{"t":"para","text":"Dịch: Ông cha đạo nói với Balda: \"Được rồi. Sẽ không tốn kém cho cả hai ta đâu. Hãy ở lại sân nhà ta một thời gian, hãy tỏ rõ sự siêng năng và tháo vát của ngươi nhé\"."},{"t":"example","text":"Chú thích sách: ² Прово́рье = sự tháo vát/nhanh nhẹn."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Пожи́ть (ở một thời gian - hoàn thành thể) → Поживи́."},{"t":"example","text":"Оказа́ть (tỏ ra/thể hiện - hoàn thành thể) → Окажи́."},{"t":"para","text":"5. Ты не (петь), солове́й, Под мои́м окно́м; (Улете́ть) в леса́ Мое́й ро́дины! (Полюби́ть) ты окно́ Души́-деви́цы... (Прощебета́ть) не́жно ей Про мою́ тоску́; Ты (сказа́ть), как без ней... (Trang 350) Со́хну, вя́ну я, что трава́ на степи́ Пе́ред о́сенью (А.Кольцо́в).","b":1},{"t":"subhead","text":"Đáp án: пой; Улети́; Полюби́; Прощебечи́; скажи́"},{"t":"para","text":"Dịch: Họa mi ơi, đừng hót dưới cửa sổ nhà ta; Hãy bay về những cánh rừng quê hương ta! Hãy yêu lấy khung cửa sổ của người con gái ta thương... Hãy hót (thì thầm) dịu dàng với nàng về nỗi sầu của ta; Hãy nói rằng vắng nàng... ta héo hon, tàn tạ như cỏ trên thảo nguyên trước mùa thu."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Не петь (Cấm đoán/Yêu cầu đừng làm gì → Chưa hoàn thành thể) → не пой."},{"t":"example","text":"Các động từ còn lại là yêu cầu thực hiện hành động cụ thể (hoàn thành thể): Улете́ть → Улети́; Полюби́ть → Полюби́; Прощебета́ть → Прощебечи́ (biến đổi âm т thành ч); Сказа́ть → Скажи́."},{"t":"para","text":"6. Огни́ — как ни́ти золоты́х бус, Ночно́го ли́стика во рту — вкус. (Освободи́ть) от дневны́х уз, Друзья́, (поня́ть), что я вам снюсь (М.Цвета́ева).","b":1},{"t":"subhead","text":"Đáp án: Освободи́те; пойми́те"},{"t":"para","text":"Dịch: Những ánh đèn như chuỗi hạt vàng, Vị chiếc lá đêm trong miệng. Hỡi các bạn, hãy giải thoát tôi khỏi những ràng buộc ban ngày, hãy hiểu rằng tôi chỉ là giấc mơ của các bạn thôi."},{"t":"subhead","text":"Giải thích: Mệnh lệnh hướng tới số nhiều (Друзья):"},{"t":"example","text":"Освободи́ть → Освободи́те."},{"t":"example","text":"Поня́ть → Пойми́те."},{"t":"para","text":"7. Не (спо́рить) о мужски́х права́х, Все объясни́мо в двух слова́х: Нет прав у нас, Как и у вас (С.Чёрный).","b":1},{"t":"subhead","text":"Đáp án: спо́рьте","b":1},{"t":"para","text":"Dịch: Đừng tranh cãi về quyền đàn ông, Mọi thứ giải thích trong hai từ thôi: Chúng tôi chẳng có quyền gì, Cũng như các cô thôi."},{"t":"example","text":"Giải thích: Не спо́рить (Cấm đoán/khuyên can → Chưa hoàn thành thể) → Не спо́рьте."},{"t":"para","text":"8. Е́сли жизнь тебя́ обма́нет, Не (печа́литься), не (серди́ться)! В день уны́ния (смири́ться): День весе́лья, (ве́рить), наста́нет (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: печа́лься; серди́сь; смири́сь; верь"},{"t":"para","text":"Dịch: Nếu cuộc đời lừa dối bạn, Đừng buồn rầu, đừng giận dữ! Trong ngày sầu thảm hãy nhẫn nhịn: Hãy tin rằng, ngày vui rồi sẽ tới."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Не печа́литься (Đừng buồn - Imperf) → Не печа́лься."},{"t":"example","text":"Не серди́ться (Đừng giận - Imperf) → Не серди́сь."},{"t":"example","text":"Смири́ться (Hãy chấp nhận/cam chịu - Perf, lời khuyên cho tình huống cụ thể) → Смири́сь."},{"t":"example","text":"Ве́рить (Hãy giữ niềm tin - Imperf, trạng thái) → Верь."}]},{"id":"07-s154","type":"exercise","title":"Bài 653 (Trang 350)","num":653,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, поставив глагол в форме настоящего или будущего простого времени. (Mở ngoặc đơn, chia động từ ở thì hiện tại hoặc tương lai đơn)."},{"t":"para","text":"1. Зауны́вный ве́тер (гнать) Ста́ю туч на край небе́с (Н.Некра́сов).","b":1},{"t":"subhead","text":"Đáp án: го́нит","b":1},{"t":"para","text":"Dịch: Cơn gió rền rĩ xua (lùa) đàn mây về phía chân trời."},{"t":"example","text":"Giải thích: Động từ гнать (xua, đuổi - chuyển động một chiều, chưa hoàn thành). Ngữ cảnh miêu tả thiên nhiên → Thì hiện tại, ngôi thứ 3 số ít (ве́тер). Гнать là động từ bất quy tắc nhóm 2 (го́нит)."},{"t":"para","text":"2. На мо́крый песо́к набега́ет волна́ И пе́ну им под но́ги (стлать) (А.Толсто́й).","b":1},{"t":"subhead","text":"Đáp án: сте́лет","b":1},{"t":"para","text":"Dịch: Con sóng xô vào bãi cát ướt và trải bọt nước xuống dưới chân họ."},{"t":"example","text":"Giải thích: Động từ стлать (trải ra - chưa hoàn thành). Miêu tả hành động sóng biển → Thì hiện tại, ngôi thứ 3 số ít (волна́). Chia: сте́лет (nhóm 1)."},{"t":"para","text":"3. Косо́й дождь (бить) по стёклам (В.Короле́нко).","b":1},{"t":"subhead","text":"Đáp án: бьёт","b":1},{"t":"para","text":"Dịch: Cơn mưa xiên quất (đập) vào cửa kính."},{"t":"example","text":"Giải thích: Động từ бить (đập, đánh - chưa hoàn thành). Thì hiện tại, ngôi thứ 3 số ít (дождь). Chia: бьёт."},{"t":"para","text":"4. Безымя́нные геро́и Осаждённых городо́в, Я вас в се́рдце се́рдца (скрыть), Ва́ша до́блесть вы́ше слов (Б.Пастерна́к).","b":1},{"t":"subhead","text":"Đáp án: скро́ю","b":1},{"t":"para","text":"Dịch: Những người anh hùng vô danh của các thành phố bị vây hãm, tôi sẽ giấu (khắc ghi) các bạn trong sâu thẳm trái tim, lòng dũng cảm của các bạn cao hơn mọi lời nói."},{"t":"example","text":"Giải thích: Động từ скрыть (giấu - hoàn thành thể). Diễn tả sự cam kết vĩnh viễn → Tương lai đơn, ngôi tôi (я). Chia: скро́ю."},{"t":"para","text":"5. Что за вздор ты (моло́ть)? (И.Турге́нев).","b":1},{"t":"subhead","text":"Đáp án: ме́лешь","b":1},{"t":"para","text":"Dịch: Cậu đang nói nhảm (xay) cái giọng gì thế?"},{"t":"example","text":"Giải thích: Động từ моло́ть (xay/nghiền; nghĩa bóng: nói năng luyên thuyên - chưa hoàn thành). Thì hiện tại, ngôi ты. Chia: ме́лешь."},{"t":"vocab","ru":"Христо́с сказа́л","vi":"“Убо́гие блаже́нны, Зави́ден рок слепцо́в, кале́к и ни́щих, Я их (взять) в надзвёздные селе́нья, Я сде́лаю их ры́царями не́ба и (назва́ть) славне́йшими из сла́вных...” (Н.Гумилёв).","g":null},{"t":"subhead","text":"Đáp án: возьму́; назову́"},{"t":"para","text":"Dịch: Chúa Kitô phán: “Những kẻ khốn cùng thật có phúc, số phận của những kẻ mù lòa, tàn tật và ăn xin thật đáng ghen tị, Ta sẽ đưa họ vào những cõi ở trên các vì sao, Ta sẽ biến họ thành những hiệp sĩ của bầu trời và sẽ gọi họ là những kẻ vinh quang nhất trong những kẻ vinh quang...”"},{"t":"example","text":"Giải thích: Взять (lấy/đưa đi) và назва́ть (gọi tên) đều là hoàn thành thể. Chúa hứa hẹn về hành động trong tương lai → Tương lai đơn, ngôi Я. Chia: возьму́, назову́."},{"t":"para","text":"7. Пусть! Я (приня́ть)! Но как же те, други́е... (Н.Гумилёв).","b":1},{"t":"subhead","text":"Đáp án: приму́","b":1},{"t":"para","text":"Dịch: Cứ thế đi! Tôi sẽ chấp nhận! Nhưng còn những người kia, những người khác..."},{"t":"example","text":"Giải thích: Động từ приня́ть (chấp nhận/đón nhận - hoàn thành thể). Quyết định chấp nhận số phận → Tương lai đơn, ngôi Я. Chia: приму́."},{"t":"para","text":"8. Чьей мы́слью мы тепе́рь (жить) и (дыша́ть), Чьи имена́ звуча́т нам как призы́вы? (Н.Гумилёв).","b":1},{"t":"subhead","text":"Đáp án: живём; ды́шим"},{"t":"para","text":"Dịch: Chúng ta giờ đây đang sống và thở bằng tư tưởng của ai, tên của những ai vang lên với chúng ta như những lời kêu gọi?"},{"t":"example","text":"Giải thích: Жить và дыша́ть (chưa hoàn thành thể). Hành động đang diễn ra ở hiện tại (тепе́рь). Ngôi мы. Chia: живём, ды́шим."},{"t":"para","text":"9. Нет, весь я не (умере́ть) — душа́ в заве́тной ли́ре Мой прах (пережи́ть) и тле́нья убежи́т, — И сла́вен бу́ду я... (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: умру́; переживёт"},{"t":"para","text":"Dịch: Không, ta sẽ không chết tất cả — linh hồn trong cây đàn lyre quý giá sẽ sống lâu hơn tro tàn của ta và thoát khỏi sự hư nát, — Và ta sẽ vinh quang..."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Умере́ть (chết - hoàn thành thể). Tương lai đơn, ngôi я → умру́."},{"t":"example","text":"Пережи́ть (sống sót qua/sống lâu hơn - hoàn thành thể). Chủ ngữ là душа́ (ngôi 3 số ít) → переживёт."},{"t":"para","text":"10. Круго́м тишина́; полде́нь; со́лнце так и (жечь) (Д.Григоро́вич).","b":1},{"t":"subhead","text":"Đáp án: жжёт","b":1},{"t":"para","text":"Dịch: Bốn bề tĩnh lặng; giữa trưa; mặt trời cứ thế mà thiêu đốt."},{"t":"example","text":"Giải thích: Động từ жечь (đốt/thiêu - chưa hoàn thành). Miêu tả trạng thái hiện tại. Ngôi 3 số ít (со́лнце). Chia: жжёт."},{"t":"para","text":"11. Недотро́га, тихо́ня в быту́, Ты сейча́с вся ого́нь, вся горе́нье. Дай (запере́ть) я твою́ красоту́ В тёмном те́реме стихотворе́нья (Б.Пастерна́к).","b":1},{"t":"subhead","text":"Đáp án: запру́","b":1},{"t":"para","text":"Dịch: Cô nàng kiêu kỳ, kẻ trầm lặng trong đời thường, Em giờ đây hoàn toàn là lửa, là sự rực cháy. Hãy để tôi khóa (nhốt) vẻ đẹp của em Trong tòa tháp tối của bài thơ."},{"t":"example","text":"Giải thích: Cấu trúc Дай + động từ quy chiếu ngôi thứ nhất (để tôi...) dùng tương lai đơn của động từ hoàn thành. Запере́ть (khóa lại) → запру́."},{"t":"para","text":"12. Но род твой не ве́чно судьбо́ю храни́м, Наста́нет тяжёлое вре́мя, (Обня́ть) ты свой Ки́ев и пла́мя, и дым (А.Толсто́й).","b":1},{"t":"subhead","text":"Đáp án: обни́мешь","b":1},{"t":"para","text":"Dịch: Nhưng dòng giống ngươi không được số phận che chở mãi đâu, Thời khắc khó khăn sẽ đến, Ngươi sẽ ôm lấy Kiev của mình cùng ngọn lửa và khói bụi."},{"t":"example","text":"Giải thích: Động từ обня́ть (ôm - hoàn thành thể). Tiên đoán tương lai (настанет...). Ngôi ты. Chia: обни́мешь."},{"t":"vocab","ru":"Мне го́лос был. Он звал уте́шно, Он говори́л","vi":"“Иди́ сюда́, Оста́вь свой край глухо́й и гре́шный, Оста́вь Росси́ю навсегда́. Я кровь от рук твои́х (отмы́ть), Из се́рдца вы́ну чёрный стыд, Я но́вым и́менем (покры́ть) боль пораже́ний и оби́д” (А.Ахма́това).","g":null},{"t":"subhead","text":"Đáp án: отмо́ю; покро́ю"},{"t":"para","text":"Dịch: Có một giọng nói đến với tôi. Nó gọi mời đầy an ủi, Nó bảo: “Hãy lại đây, Hãy bỏ lại xứ sở điếc đặc và tội lỗi của ngươi, Hãy bỏ lại nước Nga vĩnh viễn. Ta sẽ rửa sạch máu trên tay ngươi, Sẽ lấy nỗi nhục đen tối ra khỏi tim, Ta sẽ che phủ nỗi đau thất bại và tủi hờn bằng một cái tên mới”."},{"t":"example","text":"Giải thích: Отмы́ть (rửa sạch) và покры́ть (che phủ) đều là hoàn thành thể. Lời hứa cho tương lai. Ngôi Я. Chia: отмо́ю, покро́ю."}]},{"id":"07-s155","type":"exercise","title":"Bài 654 (Trang 350-351)","num":654,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, поставив глагол в форме императива. (Mở ngoặc đơn, chia động từ ở dạng Mệnh lệnh thức)."},{"t":"para","text":"1. Твой взгляд — да бу́дет твёрд и я́сен. (Стере́ть) случа́йные черты́ И ты уви́дишь: мир прекра́сен. (Познава́ть), где свет, — поймёшь, где тьма (А.Блок).","b":1},{"t":"subhead","text":"Đáp án: Сотри́; Познава́й"},{"t":"para","text":"Dịch: Ánh nhìn của ngươi — hãy rắn rỏi và sáng suốt. Hãy xóa đi những nét ngẫu nhiên Và ngươi sẽ thấy: thế giới thật tuyệt vời. Hãy nhận biết đâu là ánh sáng, — ngươi sẽ hiểu đâu là bóng tối."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Стере́ть (xóa bỏ - hoàn thành thể)","vi":"Yêu cầu thực hiện hành động cụ thể để đạt kết quả. Mệnh lệnh: Сотри́.","g":null},{"t":"vocab","ru":"Познава́ть (nhận thức/tìm hiểu - chưa hoàn thành thể)","vi":"Lời khuyên về một quá trình nhận thức. Mệnh lệnh: Познава́й.","g":null},{"t":"para","text":"2. (Приня́ть) ка́пель и (ложи́ться), (отдохну́ть) (А.Остро́вский).","b":1},{"t":"subhead","text":"Đáp án: Прими́; ложи́сь; отдохни́"},{"t":"para","text":"Dịch: Hãy uống vài giọt thuốc và nằm xuống, nghỉ ngơi đi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Приня́ть (uống thuốc - hoàn thành)","vi":"Прими́.","g":null},{"t":"vocab","ru":"Ложи́ться (nằm xuống - chưa hoàn thành)","vi":"Động từ này thường dùng ở Imperfective trong mệnh lệnh mời mọc/khuyên bảo (садись, ложись). Mệnh lệnh: ложи́сь.","g":null},{"t":"vocab","ru":"Отдохну́ть (nghỉ ngơi - hoàn thành)","vi":"отдохни́.","g":null},{"t":"para","text":"3. Ещё оди́н нену́жный день, Великоле́пный и нену́жный! (Прийти́), ласка́ющая тень, и ду́шу сму́тную оде́нь Свое́ю ри́зою жемчу́жной (Н.Гумилёв).","b":1},{"t":"subhead","text":"Đáp án: Приди́","b":1},{"t":"para","text":"Dịch: Thêm một ngày vô ích nữa, Tuyệt đẹp và vô ích! Hãy đến, hỡi bóng tối vỗ về, và hãy khoác lên linh hồn u sầu Tấm áo ngọc trai của người."},{"t":"example","text":"Giải thích: Прийти́ (đến - hoàn thành thể). Lời kêu gọi khẩn thiết. Mệnh lệnh: Приди́."},{"t":"para","text":"4. Взя́лся, так будь добр, служи́ че́стно, тяни́ до конца́ и не (ныть), не (жа́ловаться) (Д.Гра́нин).","b":1},{"t":"subhead","text":"Đáp án: ной; жа́луйся"},{"t":"para","text":"Dịch: Đã nhận làm thì hãy làm ơn phục vụ cho trung thực, kéo cày cho đến cùng và đừng than vãn, đừng kêu ca."},{"t":"example","text":"Giải thích: Mệnh lệnh phủ định (cấm đoán/khuyên đừng làm gì) thường dùng thể chưa hoàn thành (не + Imperf)."},{"t":"example","text":"Не ныть → не ной."},{"t":"example","text":"Не жа́ловаться → не жа́луйся."},{"t":"para","text":"5. (Взять) ж на ра́дость ди́кий мой пода́рок — Невзра́чное сухо́е ожере́лье Из мёртвых пчёл, мёд преврати́вших в со́лнце (О.Мандельшта́м).","b":1},{"t":"subhead","text":"Đáp án: Возьми́","b":1},{"t":"para","text":"Dịch: Hãy nhận (cầm lấy) món quà hoang dã của tôi làm niềm vui — Chuỗi hạt khô khan tầm thường Kết từ những con ong đã chết, những kẻ đã biến mật thành mặt trời."},{"t":"example","text":"Giải thích: Взять (cầm lấy - hoàn thành thể). Mệnh lệnh: Возьми́."},{"t":"para","text":"6. (Ли́ться), пе́сня зво́нкая, (вы́лить) трель уны́лую. В темноте́ мне ка́жется — обнима́ю ми́лую (С.Есе́нин).","b":1},{"t":"subhead","text":"Đáp án: Ле́йся; вы́лей"},{"t":"para","text":"Dịch: Hãy tuôn chảy, bài ca lảnh lót, hãy trút hết tiếng ngân nga u sầu. Trong bóng tối ta cứ ngỡ — đang ôm người yêu dấu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Ли́ться (tuôn chảy - chưa hoàn thành, chỉ quá trình)","vi":"Ле́йся.","g":null},{"t":"vocab","ru":"Вы́лить (đổ ra/trút hết - hoàn thành, chỉ kết quả trọn vẹn)","vi":"Вы́лей.","g":null},{"t":"para","text":"7. Годовщи́ну после́днюю пра́зднуй — ты (поня́ть), что сего́дня точь-в-точь На́шей пе́рвой зимы́ — той, алма́зной — Повторя́ется сне́жная ночь (А.Ахма́това).","b":1},{"t":"subhead","text":"Đáp án: пойми́","b":1},{"t":"para","text":"Dịch: Hãy ăn mừng ngày kỷ niệm cuối cùng — anh hãy hiểu rằng hôm nay, y hệt như Mùa đông đầu tiên của chúng ta — mùa đông kim cương ấy — Một đêm tuyết đang lặp lại."},{"t":"example","text":"Giải thích: Поня́ть (hiểu ra - hoàn thành thể). Yêu cầu nhận thức một sự thật. Mệnh lệnh: Пойми́."},{"t":"para","text":"8. Не (ждать) меня́ средь но́чи тёмной, До пе́рвых у́тренних луче́й Не (жечь) свече́й (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: жди; жги"},{"t":"para","text":"Dịch: Đừng đợi ta giữa đêm tối tăm, Cho đến những tia nắng sáng đầu tiên Đừng thắp (đốt) nến."},{"t":"para","text":"Giải thích: Mệnh lệnh phủ định (Đừng...) dùng thể chưa hoàn thành."},{"t":"example","text":"Не ждать → не жди."},{"t":"example","text":"Не жечь → не жги."}]},{"id":"07-s156","type":"exercise","title":"Bài 655 (Trang 351)","num":655,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, поставив глагол в форме прошедшего времени. (Mở ngoặc đơn, chia động từ ở thì quá khứ)."},{"t":"note","text":"Lưu ý ngữ pháp:","b":1},{"t":"example","text":"Các động từ kết thúc bằng -чь, -ти, -зти thường có dạng quá khứ bất quy tắc (ví dụ: жечь → жёг, жгла; нести → нёс, несла)."},{"t":"example","text":"Động từ расти (lớn lên) → рос, росла."},{"t":"example","text":"Động từ упасть (ngã/rơi) → упал, упала."},{"t":"para","text":"1. Какие меды́, какие квасы́ (вари́ться), какие пироги́ (печься) в Обло́мовке (И.Гончаров).","b":1},{"t":"subhead","text":"Đáp án: вари́лись; пекли́сь"},{"t":"para","text":"Dịch: Những loại mật ong nào, những loại nước kvass nào đã được nấu, những chiếc bánh nào đã được nướng ở Oblomovka."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вариться (nấu)","vi":"Chủ ngữ квасы (số nhiều) → варились.","g":null},{"t":"vocab","ru":"Печься (nướng)","vi":"Chủ ngữ пироги (số nhiều). Quá khứ: пёк, пекла, пекло, пекли → пеклись.","g":null},{"t":"para","text":"2. Какие стра́нные слова́ (Принести́) мне ти́хий день апре́ля (А.Ахматова).","b":1},{"t":"subhead","text":"Đáp án: Принёс","b":1},{"t":"para","text":"Dịch: Ngày tháng Tư tĩnh lặng đã mang đến cho tôi những lời lẽ lạ lùng làm sao."},{"t":"example","text":"Giải thích: Chủ ngữ là день (giống đực, số ít). Động từ принести (mang đến) → quá khứ giống đực: принёс."},{"t":"para","text":"3. Он был рождён для них, для тех наде́жд, Поэ́зии и сча́стья... Но, безу́мный — Из де́тских ра́но вы́рвался оде́жд И се́рдце бро́сил в мо́ре жи́зни шу́мной, И свет не пощади́л — и бог не (спасти́)! (М.Лермонтов).","b":1},{"t":"subhead","text":"Đáp án: спас","b":1},{"t":"para","text":"Dịch: Chàng sinh ra là dành cho chúng, cho những hy vọng ấy, cho thơ ca và hạnh phúc... Nhưng, kẻ điên rồ — Đã sớm thoát khỏi tấm áo trẻ thơ, Và ném trái tim vào biển đời ồn ã, Và thế gian không dung tha — và chúa cũng chẳng cứu vớt!"},{"t":"example","text":"Giải thích: Chủ ngữ là бог (giống đực). Động từ спасти (cứu) → quá khứ: спас, спасла... → спас."},{"t":"para","text":"4. Сын Алекса́ндр — бу́дущий писа́тель — (расти́) мечта́тельным, нетерпели́вым и рассе́янным ма́льчиком (К.Паустовский).","b":1},{"t":"subhead","text":"Đáp án: рос","b":1},{"t":"para","text":"Dịch: Con trai Alexander — nhà văn tương lai — đã lớn lên là một cậu bé hay mơ mộng, thiếu kiên nhẫn và đãng trí."},{"t":"example","text":"Giải thích: Chủ ngữ Сын/Александр (giống đực). Động từ расти (lớn lên) có quá khứ bất quy tắc: рос, росла → рос."},{"t":"para","text":"5. Он чу́вствовал, что, не отве́тив на письмо́ Да́рьи Алекса́ндровны, свое́ю неве́жливостью, о кото́рой он без кра́ски стыда́ не мог вспо́мнить, он (сжечь) свои́ корабли́... (Л.Толстой).","b":1},{"t":"subhead","text":"Đáp án: сжёг","b":1},{"t":"para","text":"Dịch: Anh ta cảm thấy rằng, việc không trả lời thư của Darya Alexandrovna, bằng sự khiếm nhã mà anh không thể nhớ lại nếu không đỏ mặt vì xấu hổ, anh ta đã đốt cháy những con tàu của mình (cắt đứt đường lui)..."},{"t":"example","text":"Giải thích: Chủ ngữ он (giống đực). Động từ сжечь (đốt) → quá khứ giống đực: сжёг (giống cái: жгла)."},{"t":"para","text":"6. (Мести́) весь ме́сяц в феврале́, И то и де́ло Свеча́ (горе́ть) на столе́, Свеча́ (горе́ть) (Б.Пастернак).","b":1},{"t":"subhead","text":"Đáp án: Мело́; горе́ла; горе́ла"},{"t":"para","text":"Dịch: Tuyết đã thổi (quét) suốt cả tháng Hai, Và chốc chốc Ngọn nến lại cháy trên bàn, Ngọn nến cháy."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Мести (quét/thổi tuyết)","vi":"Dùng ở dạng vô nhân xưng chỉ hiện tượng thiên nhiên (giống trung) → мело.","g":null},{"t":"vocab","ru":"Гореть (cháy)","vi":"Chủ ngữ Свеча (giống cái) → горела.","g":null},{"t":"para","text":"7. Сра́зу ста́ло ти́хо в до́ме, (Облете́ть) после́дний мак, (Замере́ть) я в до́лгой дрёме и встреча́ю ра́нний мрак (А.Ахматова).","b":1},{"t":"subhead","text":"Đáp án: Облете́л; Замерла́"},{"t":"para","text":"Dịch: Trong nhà bỗng trở nên yên tĩnh, Bông hoa anh túc cuối cùng đã rụng (bay đi), Tôi đã chết lặng (đứng tim) trong cơn mơ màng kéo dài và đón bóng tối sớm."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Облететь (rụng/bay hết lá/hoa)","vi":"Chủ ngữ мак (giống đực) → облетел.","g":null},{"t":"vocab","ru":"Замереть (đứng tim/chết lặng)","vi":"Chủ ngữ я (tác giả nữ - Akhmatova) → замерла.","g":null},{"t":"para","text":"8. Жизнь (упа́сть), Как в стака́н воды́ ресни́ца. Изолга́вшись на корню́, никого́ не виню́... (А.Тарковский).","b":1},{"t":"subhead","text":"Đáp án: упа́ла","b":1},{"t":"para","text":"Dịch: Cuộc đời đã rơi xuống, Như chiếc lông mi rơi vào cốc nước. Dối trá tận gốc rễ, tôi chẳng trách ai..."},{"t":"example","text":"Giải thích: Chủ ngữ Жизнь (giống cái). Động từ упасть (rơi) → упала."},{"t":"para","text":"9. Он да́ле¹, в сад, в лавро́вый лес, к решётке са́да, Вдоль о́зера, вокру́г водопа́да, Под мо́стики, в бесе́дки... нет! Княжна́ ушла́, (пропа́сть) и след! (А.Пушкин).","b":1},{"t":"subhead","text":"Đáp án: пропа́л","b":1},{"t":"para","text":"Dịch: Chàng đi xa hơn, vào vườn, vào rừng nguyệt quế, đến hàng rào khu vườn, Dọc theo hồ nước, quanh thác nước, Dưới những cây cầu nhỏ, vào các vọng lâu... không thấy đâu! Công chúa đã đi rồi, dấu vết cũng đã biến mất!"},{"t":"example","text":"Chú thích sách: ¹ Дале (từ cổ) = дальше (xa hơn)."},{"t":"example","text":"Giải thích: Chủ ngữ след (dấu vết - giống đực). Động từ пропасть (biến mất) → пропал."},{"t":"para","text":"10. И сно́ва на юг корабли́ (уходи́ть). И вы́мпел проща́льный высоко́ (взви́ться), И мо́ре (ласка́ть) их тёмные ки́ли, И ве́тер попу́тный (напря́чь) паруса́ (А.Блок).","b":1},{"t":"subhead","text":"Đáp án: уходи́ли; взви́лся; ласка́ло; напря́г"},{"t":"para","text":"Dịch: Và những con tàu lại rời đi về phương Nam. Và lá cờ hiệu chia tay đã bay vút (vươn) lên cao, Và biển cả vỗ về (âu yếm) những sống tàu sẫm màu của chúng, Và gió thuận chiều làm căng những cánh buồm."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Уходить","vi":"Chủ ngữ корабли (số nhiều) → уходили.","g":null},{"t":"vocab","ru":"Взвиться","vi":"Chủ ngữ вымпел (giống đực) → взвился.","g":null},{"t":"vocab","ru":"Ласкать","vi":"Chủ ngữ море (giống trung) → ласкало.","g":null},{"t":"vocab","ru":"Напрячь","vi":"Chủ ngữ ветер (giống đực) → напряг (quá khứ của động từ gốc -чь thường mất đuôi và biến đổi phụ âm cuối).","g":null}]},{"id":"07-s157","type":"exercise","title":"Bài 656 (Trang 351-352)","num":656,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, поставив глагол в форме прошедшего времени. (Mở ngoặc đơn, chia động từ ở thì quá khứ)."},{"t":"note","text":"Lưu ý ngữ pháp về động từ có hậu tố -НУ-:","b":1},{"t":"example","text":"Nhiều động từ hoàn thành thể có hậu tố -ну- khi chuyển sang quá khứ sẽ mất hậu tố -ну- (đặc biệt là các động từ chỉ sự thay đổi trạng thái như сохнуть, вянуть, погибнуть)."},{"t":"example","text":"Ví dụ: погибнуть → погиб (không phải погибнул)."},{"t":"example","text":"Tuy nhiên, các động từ chỉ hành động tức thời (momentary) thường giữ lại -ну- (крикнуть → крикнул, хлынуть → хлынул)."},{"t":"para","text":"1. Я па́мятник себе́ (воздви́гнуть) нерукотво́рный (А.Пушкин).","b":1},{"t":"subhead","text":"Đáp án: воздви́г","b":1},{"t":"para","text":"Dịch: Ta đã dựng cho mình một tượng đài không do tay người làm ra."},{"t":"example","text":"Giải thích: Воздвигнуть (dựng lên) → quá khứ giống đực mất -ну- → воздвиг."},{"t":"para","text":"2. Льёт дождь, он (хлы́нуть) с час наза́д.","b":1},{"t":"subhead","text":"Đáp án: хлы́нул","b":1},{"t":"para","text":"Dịch: Mưa đang xối xả, nó đã tuôn (ào xuống) từ một tiếng trước."},{"t":"example","text":"Giải thích: Хлынуть (tuôn ra bất ngờ/mạnh) là động từ chỉ hành động tức thời, giữ -ну- → хлынул."},{"t":"para","text":"3. Ско́шенная трава́ (вя́нуть) и (со́хнуть), излуча́я тягу́чий, дурма́нящий арома́т (М.Шолохов).","b":1},{"t":"subhead","text":"Đáp án: вя́ла; со́хла"},{"t":"para","text":"Dịch: Cỏ đã cắt đã héo và khô đi, tỏa ra một mùi hương nồng nàn, gây mê mẩn."},{"t":"example","text":"Giải thích: Вянуть (héo) và сохнуть (khô) là động từ chỉ trạng thái, mất -ну- ở quá khứ:"},{"t":"example","text":"Вянуть → вял, вяла."},{"t":"example","text":"Сохнуть → сох, сохла. Ở đây трава (giống cái) → вяла, сохла."},{"t":"para","text":"4. В во́здухе (па́хнуть) резедо́й и цвета́ми бе́лых ака́ций (И.Тургенев).","b":1},{"t":"subhead","text":"Đáp án: па́хло","b":1},{"t":"para","text":"Dịch: Trong không khí toả mùi (ngát hương) hoa mộc tê và hoa keo trắng."},{"t":"example","text":"Giải thích: Пахнуть (toả mùi) dùng ở dạng vô nhân xưng (giống trung) → mất -ну- → пахло."},{"t":"para","text":"5. Я (поки́нуть) роди́мый дом, Голубу́ю оста́вил Русь (С.Есенин).","b":1},{"t":"subhead","text":"Đáp án: поки́нул","b":1},{"t":"para","text":"Dịch: Tôi đã rời bỏ ngôi nhà thân yêu, Đã để lại nước Nga xanh thẳm."},{"t":"example","text":"Giải thích: Покинуть (rời bỏ) là động từ hoàn thành giữ -ну- → покинул."},{"t":"para","text":"6. Дома́шние сбежа́лись. Ночь крепча́ла. (Мелькну́ть) тень и потуши́л свечу́. Мой сон прошёл, а я ещё крича́ла (Б.Ахмадулина).","b":1},{"t":"subhead","text":"Đáp án: Мелькну́ла","b":1},{"t":"para","text":"Dịch: Người nhà chạy lại. Đêm dần đậm đặc. Một cái bóng vụt qua và thổi tắt nến. Giấc mơ của tôi đã qua, nhưng tôi vẫn còn la hét."},{"t":"example","text":"Giải thích: Мелькнуть (vụt qua/lóe lên) giữ -ну-. Chủ ngữ тень (cái bóng - giống cái) → мелькнула."},{"t":"para","text":"7. (Поги́бнуть) Поэ́т! — нево́льник че́сти — Пал, оклеве́танный молво́й... (М.Лермонтов).","b":1},{"t":"subhead","text":"Đáp án: Поги́б","b":1},{"t":"para","text":"Dịch: Nhà thơ đã chết (hy sinh)! — kẻ nô lệ của danh dự — Đã ngã xuống, bị tin đồn vu khống..."},{"t":"example","text":"Giải thích: Погибнуть (chết/hy sinh) mất -ну- → погиб."},{"t":"para","text":"8. (Умо́лкнуть) прости́вший мне грехи́. Лило́вый су́мрак га́сит све́чи (А.Ахматова).","b":1},{"t":"subhead","text":"Đáp án: Умо́лк","b":1},{"t":"para","text":"Dịch: Người tha thứ tội lỗi cho tôi đã im bặt. Hoàng hôn tím ngắt dập tắt những ngọn nến."},{"t":"example","text":"Giải thích: Умолкнуть (im lặng) mất -ну- → умолк."},{"t":"para","text":"9. Я (ути́хнуть). Го́ды сде́лали де́ло... (С.Есенин).","b":1},{"t":"subhead","text":"Đáp án: ути́х","b":1},{"t":"para","text":"Dịch: Tôi đã lắng xuống (bình tâm lại). Năm tháng đã làm xong việc của mình..."},{"t":"example","text":"Giải thích: Утихнуть (lắng xuống/nguôi ngoai) mất -ну- → утих."},{"t":"para","text":"10. Младо́й певе́ц Нашёл безвре́менный коне́ц! (Дохну́ть) бу́ря, цвет прекра́сный (Увя́нуть) на у́тренней заре́, (Поту́хнуть) ого́нь на алтаре́!.. (А.Пушкин).","b":1},{"t":"subhead","text":"Đáp án: Дохну́ла; Увя́л; Поту́х"},{"t":"para","text":"Dịch: Chàng ca sĩ trẻ Đã tìm thấy cái chết yểu! Cơn bão đã thổi qua, bông hoa tuyệt đẹp đã héo tàn trong rạng đông, Ngọn lửa trên bàn thờ đã tắt!.."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Дохнуть (thổi/phả - hành động tức thời) giữ -ну- → дохнула (fem, буря)."},{"t":"example","text":"Увянуть (héo) mất -ну- → увял (masc, цвет)."},{"t":"example","text":"Потухнуть (tắt) mất -ну- → потух (masc, огонь)."},{"t":"para","text":"11. Я спроси́ла у куку́шки, Ско́лько лет я проживу́... Со́сен (дро́гнуть) верху́шки, Жёлтый луч упа́л в траву́ (А.Ахматова).","b":1},{"t":"subhead","text":"Đáp án: дро́гнули","b":1},{"t":"para","text":"Dịch: Tôi hỏi chim cúc cu, Tôi sẽ sống được bao nhiêu năm... Những ngọn thông đã run rẩy, Tia nắng vàng rơi xuống cỏ."},{"t":"example","text":"Giải thích: Дрогнуть (run rẩy/rung động) trong ngữ cảnh này giữ -ну- (chỉ hành động xảy ra một lần). Chủ ngữ верхушки (số nhiều) → дрогнули."}]},{"id":"07-s158","type":"exercise","title":"Bài 657 (Trang 352)","num":657,"blocks":[{"t":"instruction","text":"Yêu cầu: В предложениях замените инфинитивы формами глаголов настоящего или будущего простого времени. (Trong các câu, hãy thay thế động từ nguyên mẫu bằng dạng của động từ ở thì hiện tại hoặc tương lai đơn)."},{"t":"para","text":"1. Сейча́с мы не (хоте́ть) вдава́ться в подро́бности происше́дшего.","b":1},{"t":"subhead","text":"Đáp án: хоти́м","b":1},{"t":"para","text":"Dịch: Bây giờ chúng tôi không muốn đi sâu vào chi tiết của những gì đã xảy ra."},{"t":"example","text":"Giải thích: Thì hiện tại, ngôi мы → хотим."},{"t":"para","text":"2. Он (уме́ть) бы́стро преодолева́ть все препя́тствия.","b":1},{"t":"subhead","text":"Đáp án: уме́ет","b":1},{"t":"para","text":"Dịch: Anh ấy biết (có khả năng) vượt qua mọi trở ngại một cách nhanh chóng."},{"t":"example","text":"Giải thích: Thì hiện tại, ngôi он → умеет."},{"t":"para","text":"3. Я не (мочь) сове́товать тебе́ сдава́ть экза́мены в ма́е.","b":1},{"t":"subhead","text":"Đáp án: могу́","b":1},{"t":"para","text":"Dịch: Tôi không thể khuyên bạn thi vào tháng Năm được."},{"t":"example","text":"Giải thích: Thì hiện tại, ngôi я → могу."},{"t":"example","text":"4. Мне о́чень (на́до) знать, должно́ существова́ть не́сколько вариа́нтов реше́ния э́той зада́чи. (Lưu ý: Sách in từ надо trong ngoặc, nhưng надо không chia. Dựa vào đáp án sách giáo khoa, từ này được thay thế bằng từ đồng nghĩa biến đổi được hoặc giữ nguyên ý nghĩa)."},{"t":"subhead","text":"Đáp án: ну́жно","b":1},{"t":"para","text":"Dịch: Tôi rất cần biết..."},{"t":"example","text":"Giải thích: Надо và нужно là từ chỉ trạng thái (predicative). Trong bài tập này, sách muốn thay thế bằng нужно (có thể coi là chuẩn mực hơn hoặc chỉ đơn giản là bài tập từ vựng)."},{"t":"para","text":"5. Наско́лько я (знать), должно́ существова́ть не́сколько вариа́нтов реше́ния это́й зада́чи.","b":1},{"t":"subhead","text":"Đáp án: зна́ю","b":1},{"t":"para","text":"Dịch: Theo như tôi biết, phải tồn tại vài phương án giải quyết bài toán này."},{"t":"example","text":"Giải thích: Cụm cố định Насколько я знаю (Theo tôi biết) → знаю."},{"t":"example","text":"6. В э́той ситуа́ции я вам могу́ то́лько сочу́вствовать; 7. Тебя́ не должно́ задева́ть равноду́шие окружа́ющих. (Câu 6 và 7 trong sách có thể là một câu ghép hoặc in liền nhau. Phần cần chia là существовать ở câu trước đó và các động từ này)."},{"t":"note","text":"Lưu ý: Câu 6 trong sách là: В этой ситуации я вам могу только (сочувствовать) -> сочувствую (Tôi thông cảm)."},{"t":"example","text":"Tuy nhiên, theo mạch bài tập ở trên (câu 4, 5 nối vào ý \"có nhiều phương án\"), câu 6 thực tế là: 6. Должно (существовать)... -> существу́ет (Tồn tại)."},{"t":"example","text":"Câu 7: 7. Тебя не должно (задевать)... -> задева́ет (Làm tổn thương/động chạm)."},{"t":"para","text":"Dịch (7): Sự thờ ơ của những người xung quanh không (nên) làm bạn tổn thương."},{"t":"example","text":"8. Не волну́йся, он мо́жет (преуспева́ть) во всём. (Sách in là Не волнуйся, он может... nhưng yêu cầu chia волнуйся và может? Hay преуспевать? Theo Key trong sách, đáp án là не волнуйся và может - tức là giữ nguyên dạng mệnh lệnh và hiện tại)."},{"t":"subhead","text":"Đáp án: Не волну́йся; мо́жет"},{"t":"para","text":"Dịch: Đừng lo, anh ấy có thể thành công trong mọi việc."},{"t":"para","text":"9. Он до́лжен (обра́довать) твоему́ прие́зду.","b":1},{"t":"subhead","text":"Đáp án: обра́дуется","b":1},{"t":"para","text":"Dịch: Anh ấy sẽ vui mừng vì sự đến thăm của bạn."},{"t":"example","text":"Giải thích: Tương lai đơn (hoàn thành thể) → обрадуется."},{"t":"para","text":"10. Ты не до́лжен (подозрева́ть) всех в изме́не.","b":1},{"t":"subhead","text":"Đáp án: до́лжен (giữ nguyên) hoặc thay đổi cấu trúc: Ты не должен подозревать... → Ý của bài là biến đổi cả cụm?"},{"t":"example","text":"Theo Key: не должны (số nhiều?)."},{"t":"example","text":"Phân tích lại: Có vẻ bài tập yêu cầu thay thế cụm \"modal + infinitive\" bằng động từ chia thì."},{"t":"example","text":"Ví dụ: Ты не должен подозревать → Ты не подозрева́й (Mệnh lệnh) hoặc Не подозрева́й?"},{"t":"para","text":"Nhưng đề bài là \"Hiện tại hoặc Tương lai\"."},{"t":"example","text":"Hãy xem lại câu 10: Ты не должен подозревать всех в измене."},{"t":"subhead","text":"Đáp án hợp lý nhất nếu bỏ должен: Не подозрева́й (Đừng nghi ngờ - Mệnh lệnh) hoặc Не подозрева́ешь (Bạn không nghi ngờ - Hiện tại). Tuy nhiên, nếu theo Key của sách Glazunova (trang 399) cho bài 657, nó liệt kê các động từ khuyết thiếu."},{"t":"example","text":"Key 657: 1. хотим, 2. умеет, 3. могу, 4. нужно, 5. знаю, 6. существует, 7. задевает, 8. не волнуйся, может, 9. должен (hiện tại), 10. не должны (số nhiều? - Có thể chủ ngữ là Вы trong bản gốc hoặc sách coi Ты đại diện chung)."},{"t":"example","text":"Kết luận: Điền не должны́ (nếu chủ ngữ Вы) hoặc не до́лжен (nếu chủ ngữ Ты)."},{"t":"para","text":"11. Почётму мы не мо́жем (спусти́ться) вниз, мы должны́ заночева́ть в гора́х.","b":1},{"t":"subhead","text":"Đáp án: не смо́жем; должны́"},{"t":"para","text":"Dịch: Tại sao chúng ta sẽ không thể xuống dưới, chúng ta phải ngủ đêm trên núi."},{"t":"example","text":"Giải thích: Не сможем (Tương lai - sẽ không thể). Должны (Hiện tại - phải)."},{"t":"para","text":"12. Я обяза́тельно (постара́ться) попро́бовать э́то блю́до.","b":1},{"t":"subhead","text":"Đáp án: постара́юсь","b":1},{"t":"para","text":"Dịch: Tôi nhất định sẽ cố gắng nếm thử món này."},{"t":"example","text":"Giải thích: Tương lai đơn (hoàn thành thể) → постараюсь."},{"t":"para","text":"13. Вы должны́ чётко (сформулирова́ть) свой зада́чи.","b":1},{"t":"subhead","text":"Đáp án: должны́","b":1},{"t":"para","text":"Dịch: Các bạn phải xác định rõ nhiệm vụ của mình."},{"t":"para","text":"14. Я смогу́ узна́ть прогно́з пого́ды по ра́дио.","b":1},{"t":"subhead","text":"Đáp án: смогу́","b":1},{"t":"para","text":"Dịch: Tôi sẽ có thể biết dự báo thời tiết qua đài."},{"t":"example","text":"Giải thích: Tương lai đơn → смогу."}]},{"id":"07-s159","type":"exercise","title":"Bài 658 (Trang 352-353)","num":658,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя глаголы в форме настоящего или будущего простого времени. (Mở ngoặc đơn, sử dụng động từ ở thì hiện tại hoặc tương lai đơn)."},{"t":"para","text":"1. Мы, старики́, уж ны́нче не (танцева́ть). Му́зыки гром не (призыва́ть) нас (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: танцу́ем; призыва́ет"},{"t":"para","text":"Dịch: Chúng ta, những người già, thời nay không còn khiêu vũ nữa. Tiếng sấm của âm nhạc không còn mời gọi chúng ta."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Танцева́ть (khiêu vũ)","vi":"Chủ ngữ мы (chúng ta) → танцу́ем.","g":null},{"t":"vocab","ru":"Призыва́ть (mời gọi/kêu gọi)","vi":"Chủ ngữ гром (tiếng sấm - số ít) → призыва́ет.","g":null},{"t":"para","text":"2. Прие́хавший по именно́му повеле́нию из Петербу́рга чино́вник (тре́бовать) вас сей же час к себе́ (Н.Го́голь).","b":1},{"t":"subhead","text":"Đáp án: тре́бует","b":1},{"t":"para","text":"Dịch: Viên quan chức đến từ Petersburg theo lệnh đích danh đang đòi (yêu cầu) các ngài đến gặp ông ta ngay bây giờ."},{"t":"example","text":"Giải thích: Chủ ngữ чино́вник (viên quan - ngôi thứ 3 số ít). Động từ тре́бовать (yêu cầu) → тре́бует."},{"t":"para","text":"3. По вечера́м и по ноча́м ей слы́шно бы́ло, как в саду́ игра́ла му́зыка, как ло́пались с тре́ском раке́ты, и ей каза́лось, что э́то Ку́кин (воева́ть) со свое́й судьбо́й и берёт при́ступом своего́ гла́вного врага́ — равноду́шную пу́блику (А.Че́хов).","b":1},{"t":"subhead","text":"Đáp án: вою́ет","b":1},{"t":"para","text":"Dịch: Vào các buổi chiều và buổi đêm, cô ấy nghe thấy tiếng nhạc chơi trong vườn, tiếng pháo thăng thiên nổ lách tách, và cô ấy cứ ngỡ rằng đó là Kukin đang chiến đấu với số phận của mình và đang tấn công kẻ thù chính của mình — đám công chúng thờ ơ."},{"t":"example","text":"Giải thích: Trong tiếng Nga, khi miêu tả suy nghĩ/cảm nhận trong quá khứ (казалось), mệnh đề phụ thường giữ nguyên thì của sự việc như lúc nó đang diễn ra (thì hiện tại). Kukin đang chiến đấu → вою́ет."},{"t":"para","text":"4. “На ста́рших сду́ру не (плева́ть)”, Резо́нно ду́мает верблю́д. Под ним, как гре́бни, хо́дят лю́ди (Б.Пастерна́к).","b":1},{"t":"subhead","text":"Đáp án: плюю́т","b":1},{"t":"para","text":"Dịch: \"Đừng vì ngu ngốc mà nhổ nước bọt vào người lớn tuổi (người ở trên cao)\", Con lạc đà nghĩ một cách có lý. Bên dưới nó, con người đi lại như những chiếc lược."},{"t":"example","text":"Giải thích: Câu này mang ý nghĩa như một quy tắc chung hoặc tục ngữ: \"Người ta không nhổ...\". Dùng ngôi thứ 3 số nhiều cho chủ ngữ ẩn (người ta) → плюю́т."},{"t":"para","text":"5. Лета́ют сны-мучи́тели Над гре́шными людьми́, И а́нгелы-храни́тели (Бесе́довать) с детьми́ (М.Ле́рмонтов).","b":1},{"t":"subhead","text":"Đáp án: Бесе́дуют","b":1},{"t":"para","text":"Dịch: Những giấc mơ dằn vặt bay lượn trên đầu những kẻ tội lỗi, Và những thiên thần hộ mệnh đang trò chuyện với lũ trẻ."},{"t":"example","text":"Giải thích: Chủ ngữ а́нгелы-храни́тели (các thiên thần - số nhiều). Động từ бесе́довать (trò chuyện) → бесе́дуют."},{"t":"para","text":"6. (Бушева́ть) пла́мя, трубя́т тру́бы, И ко́ни ры́жие летя́т (Н.Гумилёв).","b":1},{"t":"subhead","text":"Đáp án: Бушу́ет","b":1},{"t":"para","text":"Dịch: Ngọn lửa đang hoành hành (dữ dội), kèn đang thổi, Và những con ngựa hung đỏ đang bay đi."},{"t":"example","text":"Giải thích: Chủ ngữ пла́мя (ngọn lửa - giống trung số ít, danh từ đặc biệt kết thúc bằng -мя). Động từ бушева́ть → бушу́ет."},{"t":"para","text":"7. — Приближённые утвержда́ют, что э́то ревмати́зм, — говори́л Во́ланд, не спуска́я глаз с Маргари́ты, — но я си́льно (подозрева́ть), что э́та боль в коле́не оста́влена мне на па́мять одно́й очарова́тельной ве́дьмой... (М.Булга́ков).","b":1},{"t":"subhead","text":"Đáp án: подозрева́ю","b":1},{"t":"para","text":"Dịch: — Những kẻ cận thần khẳng định rằng đó là bệnh thấp khớp, — Woland nói, không rời mắt khỏi Margarita, — nhưng tôi nghi ngờ mạnh mẽ rằng cơn đau ở đầu gối này là do một phù thủy quyến rũ để lại làm kỷ niệm cho tôi..."},{"t":"example","text":"Giải thích: Chủ ngữ я (tôi). Động từ подозрева́ть (nghi ngờ) → подозрева́ю."},{"t":"para","text":"8. Оте́ц да́же бу́дет рад; он всё её го́нит меня́ служи́ть, а я всё (отгова́риваться) нездоро́вьем. А вот как он уви́дит, что жени́тьба принесла́ мне по́льзу, — (обра́доваться) и прости́т меня́ (Ф.Достое́вский).","b":1},{"t":"subhead","text":"Đáp án: отгова́риваюсь; обра́дуется"},{"t":"para","text":"Dịch: Cha thậm chí sẽ vui mừng; ông ấy cứ xua tôi đi phục vụ (làm việc), còn tôi thì cứ viện cớ là sức khỏe kém. Nhưng ngay khi ông ấy thấy rằng cuộc hôn nhân mang lại lợi ích cho tôi, — ông ấy sẽ vui mừng và tha thứ cho tôi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Отгова́риваться","vi":"Hành động lặp lại ở hiện tại, ngôi я → отгова́риваюсь.","g":null},{"t":"vocab","ru":"Обра́доваться","vi":"Hành động sẽ xảy ra trong tương lai (hoàn thành thể), ngôi он (cha) → обра́дуется.","g":null}]},{"id":"07-s160","type":"exercise","title":"Bài 659 (Trang 353-356)","num":659,"blocks":[{"t":"instruction","text":"Yêu cầu: В глаголах вместо точек вставьте, где необходимо, постфикс -ся (-сь). Объясните ваш выбор. (Trong các động từ, hãy điền hậu tố phản thân -ся (-сь) vào chỗ trống nếu cần thiết. Giải thích sự lựa chọn của bạn)."},{"t":"para","text":"a)","b":1},{"t":"example","text":"Dịch & Điền từ: Го́сти съезжа́лись на да́чу. (Khách khứa đang tụ tập/đổ về nhà nghỉ). (Chủ ngữ tự thực hiện hành động di chuyển đến cùng một chỗ → phản thân). За́ла заполня́лась да́мами и мужчи́нами, прие́хавшими в одно́ вре́мя из теа́тра, где дава́ли но́вую италья́нскую о́перу. (Sảnh được lấp đầy bởi các quý bà và quý ông đến cùng lúc từ nhà hát, nơi người ta đang diễn vở opera Ý mới). (Заполнялась: mang nghĩa bị động/trạng thái được lấp đầy. Давали: câu vô nhân xưng, người ta diễn vở opera (đối tượng trực tiếp) → không có -ся). Ма́ло-пома́лу поря́док установи́лся. (Dần dần trật tự được thiết lập). (Trật tự tự hình thành/bị động → установился). Да́мы за́няли свои́ места́ по дива́нам. (Các quý bà đã chiếm/ngồi vào chỗ của mình trên ghế sofa). (Hành động chủ động tác động lên đối tượng \"chỗ\" → không có -ся). О́коло их соста́вился кружо́к мужчи́н. (Xung quanh họ hình thành một vòng tròn nam giới). (Vòng tròn tự hình thành → составился). Ви́сты учреди́лись. (Các ván bài Whist được tổ chức/bắt đầu). (Bị động/tự phát → учредились). Оста́лось на нога́х не́сколько молоды́х люде́й; и смотр пари́жских литогра́фий замени́лся о́бщим разгово́ром (А.Пу́шкин). (Còn lại vài thanh niên đứng; và việc xem tranh in đá Paris được thay thế bằng cuộc trò chuyện chung). (Осталось: trạng thái còn lại. Заменился: bị thay thế → phản thân)."},{"t":"para","text":"б)","b":1},{"t":"example","text":"Dịch & Điền từ: Ита́к, мы спуска́лись с Гуд-Горы́ в Чёртову доли́ну. (Thế là, chúng tôi đang xuống từ núi Gud-Gora vào thung lũng Quỷ). (Hành động tự di chuyển của chủ ngữ → спускались). Ло́шади изму́чились, мы продро́гли; мете́ль гуде́ла сильне́е и сильне́е. (Những con ngựa đã kiệt sức, chúng tôi rét run; bão tuyết gầm rú ngày càng mạnh). (Ngựa bị mệt/trạng thái → измучились). “И ты, изгна́нница, — ду́мал я, — пла́чешь о свои́х широ́ких раздо́льных степя́х! (“Và mi, kẻ lưu đày, — tôi nghĩ, — mi đang khóc thương những thảo nguyên bao la khoáng đạt của mình!). (Плачешь: khóc - động từ chủ động, không có -ся). Там есть где разверну́ться холо́дные кры́лья, а здесь тебе́ ду́шно и те́сно, как орлу́, кото́рый с кри́ком бьётся о решётку желе́зной свое́й кле́тки” (М.Ле́рмонтов). (Ở đó có chỗ để đôi cánh lạnh giá dang ra/vung vẩy, còn ở đây mi thấy ngột ngạt và chật chội, như con đại bàng đang kêu gào và đập mình vào song sắt lồng nheo). (Развернуться: dang rộng (cánh của chính mình)/bung lụa. Бьётся: đập thân mình vào cái gì đó → phản thân)."},{"t":"para","text":"в)","b":1},{"t":"example","text":"Dịch & Điền từ: Был прекра́сный ию́льский день, оди́н из тех дней, кото́рые случа́ются то́лько тогда́, когда́ пого́да установи́лась надо́лго. (Đó là một ngày tháng Bảy tuyệt đẹp, một trong những ngày chỉ xảy ra khi thời tiết đã ổn định lâu dài). (Случаются: xảy ra. Установилась: thiết lập/ổn định - trạng thái tự thân). С са́мого ра́ннего утра́ не́бо я́сно; у́тренняя заря́ не пыла́ет пожа́ром: она́ разлива́ется кро́тким румя́нцем. (Từ sáng sớm tinh mơ bầu trời trong xanh; bình minh không bùng cháy như đám lửa: nó lan toả ánh hồng dịu dàng). (Пылает: cháy sáng - chủ động. Разливается: lan tỏa/tràn ra khắp nơi - phản thân). Со́лнце — све́тлое и приве́тливо-лучеза́рное — ми́рно всплыва́ет под у́зкой и дли́нной ту́чкой, свежо́ просия́ет и погрузи́тся в лило́вый её тума́н. (Mặt trời — sáng sủa và rạng rỡ chào đón — yên bình nổi lên dưới đám mây dài và hẹp, tỏa sáng tươi mới và chìm vào màn sương tím của nó). (Всплывает, просияет: hành động tự thân chủ động. Погрузится: tự chìm mình vào/lặn vào → phản thân). Но вот опя́ть хлы́нули игра́ющие лучи́, — и ве́село и велича́во, сло́вно взлета́я, поднима́ется могу́чее свети́ло. (Nhưng rồi những tia nắng nhảy múa lại tuôn trào, — và vui vẻ, oai vệ, như thể đang bay lên, vầng thái dương hùng mạnh nhô lên). (Хлынули: tuôn ra - chủ động. Поднимается: tự nâng mình lên/mọc → phản thân). О́коло полу́дня обыкнове́нно появля́ется мно́жество кру́глых высо́ких облако́в. (Khoảng giữa trưa thường xuất hiện vô số những đám mây tròn cao). (Появляется: xuất hiện - phản thân). Подо́бно острова́м, разбро́санным по бесконе́чно разли́вшейся реке́, почти́ не тро́гаются с ме́ста; да́лее, к небоскло́ну, они́ сдвига́ются, тесня́тся, они́ все наскво́зь прони́кнуты све́том и теплото́й (И.Турге́нев). (Giống như những hòn đảo nằm rải rác trên dòng sông tràn ngập vô tận, chúng hầu như không nhúc nhích khỏi chỗ; xa hơn, về phía chân trời, chúng xích lại gần nhau, chen chúc nhau, tất cả đều thấm đẫm ánh sáng và hơi ấm). (Разлившейся: đã tràn bờ. Трогаются: chuyển động/nhúc nhích. Сдвигаются: dịch lại gần nhau. Теснятся: chen chúc. Tất cả đều là hành động tự thân/tương hỗ → có -ся)."}]},{"id":"07-s161","type":"exercise","title":"Bài 660 (Trang 354)","num":660,"blocks":[{"t":"instruction","text":"Yêu cầu: Испо́льзуя глаго́лы с по́стфиксом -ся (-сь), замени́те вы́деленные словосочета́ния синоними́чными. (Sử dụng các động từ có hậu tố -ся (-сь), hãy thay thế các cụm từ được in đậm bằng các từ đồng nghĩa)."},{"t":"note","text":"Lưu ý ngữ pháp: Khi thay thế bằng động từ phản thân (-ся), cấu trúc câu và cách (casus) của các từ đi kèm thường sẽ thay đổi."},{"t":"example","text":"1. Я сожале́ю о том, что я сде́лал, мне сты́дно.","b":1},{"t":"subhead","text":"Đáp án: раска́иваюсь в том","b":1},{"t":"para","text":"Dịch: Tôi hối hận về (ăn năn về) những gì tôi đã làm, tôi thấy xấu hổ."},{"t":"example","text":"Giải thích: Сожале́ть о (tiếc về - Cách 6) → Раска́иваться в (hối hận/ăn năn về - Cách 6)."},{"t":"example","text":"2. Мы никогда́ не ду́мали о твоём предложе́нии.","b":1},{"t":"subhead","text":"Đáp án: не заду́мывались","b":1},{"t":"para","text":"Dịch: Chúng tôi chưa bao giờ suy nghĩ (ngẫm nghĩ kỹ) về đề nghị của bạn."},{"t":"example","text":"Giải thích: Не ду́мали (không nghĩ) → Не заду́мывались (không suy tư/cân nhắc sâu)."},{"t":"example","text":"3. Я вы́нужден поступа́ть в соотве́тствии с реше́нием суда́.","b":1},{"t":"subhead","text":"Đáp án: вы́нужден подчиня́ться (реше́нию)"},{"t":"para","text":"Dịch: Tôi buộc phải tuân theo (phục tùng) phán quyết của tòa án."},{"t":"example","text":"Giải thích: Cụm поступа́ть в соотве́тствии с (hành động phù hợp với - Cách 5) được thay bằng подчиня́ться (tuân theo - Cách 3). Do đó, с реше́нием đổi thành реше́нию."},{"t":"example","text":"4. Не говори́ ничего́, я хочу́ сам поня́ть что произошло́.","b":1},{"t":"subhead","text":"Đáp án: хочу́ сам разобра́ться (в том)"},{"t":"para","text":"Dịch: Đừng nói gì cả, tôi muốn tự mình làm rõ (hiểu rõ ngọn ngành) chuyện gì đã xảy ra."},{"t":"example","text":"Giải thích: Поня́ть (hiểu) → Разобра́ться (tự mình tìm hiểu/phân tích để hiểu - thường đi với в + Cách 6)."},{"t":"example","text":"5. За после́днее вре́мя це́ны значи́тельно вы́росли.","b":1},{"t":"subhead","text":"Đáp án: подняли́сь / увели́чились","b":1},{"t":"para","text":"Dịch: Thời gian gần đây giá cả đã tăng lên đáng kể."},{"t":"example","text":"Giải thích: Вы́росли (lớn lên/tăng trưởng) → Подняли́сь (dâng lên/tăng lên - phản thân của поднять)."},{"t":"example","text":"6. Жизнь его́ в э́том го́роде ещё не пришла́ в но́рму.","b":1},{"t":"subhead","text":"Đáp án: не нала́дилась / не устро́илась","b":1},{"t":"para","text":"Dịch: Cuộc sống của anh ấy ở thành phố này vẫn chưa ổn định (đi vào nề nếp)."},{"t":"example","text":"Giải thích: Пришла́ в но́рму (trở lại bình thường) → Нала́дилась (trở nên tốt đẹp/trôi chảy)."},{"t":"example","text":"7. Он испы́тывал го́рдость за своего́ сы́на.","b":1},{"t":"subhead","text":"Đáp án: горди́лся (свои́м сы́ном)"},{"t":"para","text":"Dịch: Ông ấy tự hào về con trai mình."},{"t":"example","text":"Giải thích: Испы́тывать го́рдость за (+ Cách 4) → Горди́ться (+ Cách 5 - свои́м сы́ном)."},{"t":"example","text":"8. Я понима́ю, что ты испы́тываешь раздраже́ние, но ты до́лжен взять себя́ в ру́ки.","b":1},{"t":"subhead","text":"Đáp án: раздража́ешься","b":1},{"t":"para","text":"Dịch: Tôi hiểu là bạn đang cáu kỉnh (bực bội), nhưng bạn phải kiềm chế bản thân."},{"t":"example","text":"Giải thích: Испы́тывать раздраже́ние (cảm thấy bực bội) → Раздража́ться (nổi cáu)."},{"t":"example","text":"9. Я понима́ю, что ты до́лжен взять в жёны свою́ одноку́рсницу.","b":1},{"t":"subhead","text":"Đáp án: до́лжен жени́ться на (свое́й одноку́рснице)"},{"t":"para","text":"Dịch: Tôi hiểu là cậu phải cưới (kết hôn với) cô bạn học cùng khóa."},{"t":"example","text":"Giải thích: Взять в жёны (+ Cách 4) → Жени́ться на (+ Cách 6 - свое́й одноку́рснице)."},{"t":"example","text":"10. Он затро́нул о́чень ва́жный вопро́с.","b":1},{"t":"subhead","text":"Đáp án: косну́лся (о́чень ва́жного вопро́са)"},{"t":"para","text":"Dịch: Anh ấy đã đề cập đến (chạm tới) một vấn đề rất quan trọng."},{"t":"example","text":"Giải thích: Затро́нуть (+ Cách 4) → Косну́ться (+ Cách 2 - вопро́са)."},{"t":"example","text":"11. Не сто́ит обсужда́ть дета́ли предстоя́щего путеше́ствия.","b":1},{"t":"subhead","text":"Đáp án: не сто́ит каса́ться (дета́лей)"},{"t":"para","text":"Dịch: Không đáng để đả động đến (bàn tới) các chi tiết của chuyến đi sắp tới."},{"t":"example","text":"Giải thích: Обсужда́ть (+ Cách 4) → Каса́ться (chạm đến/đả động - + Cách 2)."},{"t":"example","text":"12. Он с трудо́м прошёл че́рез толпу́ к трибу́не.","b":1},{"t":"subhead","text":"Đáp án: проби́лся (сквозь толпу́ / че́рез толпу́)"},{"t":"para","text":"Dịch: Anh ấy khó khăn lắm mới chen được (mở đường) qua đám đông để đến bục phát biểu."},{"t":"example","text":"Giải thích: Прошёл (đi qua) → Проби́лся (tự phá vỡ lối đi/chen lấn để qua)."},{"t":"example","text":"13. Она́ была́ непохо́жа на свои́х рове́сников.","b":1},{"t":"subhead","text":"Đáp án: отлича́лась от (свои́х рове́сников)"},{"t":"para","text":"Dịch: Cô ấy khác biệt với những người cùng trang lứa."},{"t":"example","text":"Giải thích: Непохо́жа на (+ Cách 4) → Отлича́лась от (+ Cách 2)."},{"t":"example","text":"14. Вы всё уви́дите са́ми и приобретёте уве́ренность в том, что мы вы́брали пра́вильное реше́ние.","b":1},{"t":"subhead","text":"Đáp án: убеди́тесь в том","b":1},{"t":"para","text":"Dịch: Các bạn sẽ tự thấy tất cả và sẽ tin chắc (thuyết phục bản thân) rằng chúng tôi đã chọn giải pháp đúng."},{"t":"example","text":"Giải thích: Приобрести́ уве́ренность (có được sự tin tưởng) → Убеди́ться (tin chắc/xác thực)."},{"t":"example","text":"15. Пожа́луйста, поста́вь свою́ по́дпись внизу́ докуме́нта.","b":1},{"t":"subhead","text":"Đáp án: распиши́сь","b":1},{"t":"para","text":"Dịch: Làm ơn ký tên vào phía dưới tài liệu."},{"t":"example","text":"Giải thích: Поста́вить по́дпись → Расписа́ться."},{"t":"example","text":"16. Все в до́ме испы́тывали страх пе́ред ним.","b":1},{"t":"subhead","text":"Đáp án: боя́лись (его́)"},{"t":"para","text":"Dịch: Mọi người trong nhà đều sợ ông ta."},{"t":"example","text":"Giải thích: Испы́тывать страх пе́ред (+ Cách 5) → Боя́ться (+ Cách 2 - его́)."},{"t":"example","text":"17. По-мо́ему, осо́бенно си́льный интере́с он проявля́ет к лёгкой атле́тике.","b":1},{"t":"subhead","text":"Đáp án: интересу́ется лёгкой атле́тикой","b":1},{"t":"para","text":"Dịch: Theo tôi, anh ấy đặc biệt quan tâm (hứng thú) đến điền kinh."},{"t":"example","text":"Giải thích: Проявля́ть интере́с к (+ Cách 3) → Интересова́ться (+ Cách 5 - лёгкой атле́тикой)."},{"t":"example","text":"18. По-мо́ему, осо́бенно си́льный интере́с он проявля́ет к лёгкой атле́тике: це́лыми дня́ми пропада́ет на стадио́не.","b":1},{"t":"subhead","text":"Đáp án: трениру́ется","b":1},{"t":"para","text":"Dịch: ...suốt ngày tập luyện ở sân vận động."},{"t":"example","text":"Giải thích: Пропада́ет (biến mất/ở lì - nghĩa bóng) trong ngữ cảnh sân vận động → Трениру́ется (tập luyện)."},{"t":"example","text":"19. Ты до́лжен сде́лать всё возмо́жное, что́бы дости́чь свое́й це́ли.","b":1},{"t":"subhead","text":"Đáp án: постара́ться","b":1},{"t":"para","text":"Dịch: Bạn phải cố gắng hết sức để đạt được mục tiêu của mình."},{"t":"example","text":"Giải thích: Сде́лать всё возмо́жное (làm mọi thứ có thể) → Постара́ться (cố gắng)."},{"t":"example","text":"20. Тебе́ сто́ит испо́льзовать э́тот слу́чай.","b":1},{"t":"subhead","text":"Đáp án: воспо́льзоваться э́тим слу́чаем","b":1},{"t":"para","text":"Dịch: Bạn nên tận dụng cơ hội này."},{"t":"example","text":"Giải thích: Испо́льзовать (+ Cách 4) → Воспо́льзоваться (+ Cách 5)."}]},{"id":"07-s162","type":"exercise","title":"Bài 661 (Trang 355)","num":661,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте необходи́мые по смы́слу приста́вки. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Thay dấu ba chấm bằng các tiền tố cần thiết theo ý nghĩa. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"Đoạn văn trích từ \"Người đàn bà có con chó nhỏ\" (A. Chekhov).","b":1},{"t":"para","text":"1. Теа́тр был по́лон. Всё вре́мя, пока́ пу́блика ...ходи́ла и ...нима́ла места́, Гу́ров жа́дно иска́л глаза́ми.","b":1},{"t":"subhead","text":"Đáp án: входи́ла (hoặc приходи́ла); занима́ла"},{"t":"para","text":"Dịch: Nhà hát đã chật kín. Suốt thời gian khán giả đi vào (đến) và chiếm (ngồi vào) chỗ, Gurov hau háu đưa mắt tìm kiếm."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Входи́ла","vi":"Đi vào trong khán phòng.","g":null},{"t":"vocab","ru":"Занима́ла","vi":"Chiếm chỗ/ngồi vào chỗ.","g":null},{"t":"para","text":"2. ...шла и А́нна Серге́евна. Она́ се́ла в тре́тьем ряду́, и когда́ Гу́ров ...гляну́л на неё, то се́рдце у него́ ...жа́лось, и он по́нял я́сно, что для него́ тепе́рь на всём све́те нет бли́же, доро́же и важне́е человека;","b":1},{"t":"subhead","text":"Đáp án: Вошла́; взгляну́л; сжа́лось"},{"t":"para","text":"Dịch: Anna Sergeevna cũng đã bước vào. Cô ngồi ở hàng ghế thứ ba, và khi Gurov liếc nhìn cô, trái tim anh thắt lại (co lại), và anh hiểu rõ rằng giờ đây trên thế gian này không có ai gần gũi, quý giá và quan trọng hơn đối với anh;"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вошла́","vi":"Bước vào (hoàn thành).","g":null},{"t":"vocab","ru":"Взгляну́л","vi":"Nhìn thoáng qua/liếc nhìn (вз- chỉ hành động tức thời/hướng lên).","g":null},{"t":"vocab","ru":"Сжа́лось","vi":"Co thắt lại (vì xúc động).","g":null},{"t":"para","text":"3. она́, ...теря́вшаяся в провинциа́льной толпе́, э́та ма́ленькая же́нщина, ниче́м не замеча́тельная, с вульга́рной лорне́ткой в рука́х, ...полня́ла тепе́рь всю его́ жизнь, была́ его́ го́рем, ра́достью, еди́нственным сча́стьем, и ду́мал о том, как она́ хороша́. Ду́мал и мечта́л.","b":1},{"t":"subhead","text":"Đáp án: затеря́вшаяся; наполня́ла (hoặc заполня́ла)"},{"t":"para","text":"Dịch: cô ấy, người lạc lõng (lẩn khuất) trong đám đông tỉnh lẻ, người phụ nữ nhỏ bé này, chẳng có gì nổi bật, với chiếc kính lorgnette thô thiển trên tay, giờ đây lấp đầy cả cuộc đời anh, là nỗi buồn, niềm vui, hạnh phúc duy nhất của anh, và anh nghĩ về việc cô ấy đẹp biết bao. Anh nghĩ và mơ mộng."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Затеря́вшаяся","vi":"Bị lạc/chìm nghỉm trong đám đông (за- chỉ sự đi sâu vào/mất hút).","g":null},{"t":"vocab","ru":"Наполня́ла","vi":"Làm đầy/tràn ngập.","g":null},{"t":"para","text":"4. Вме́сте с А́нной Серге́евной ...шёл и сел ря́дом молодо́й челове́к с небольши́ми ба́кенами, о́чень высо́кий, суту́лый; он при ка́ждом ша́ге ...ка́чивал голово́й и, каза́лось, постоя́нно кла́нялся. Вероя́тно, э́то был муж, кото́рого она́ тогда́ в Я́лте, в поры́ве го́рького чу́вства, ...звала́ лаке́ем. И в са́мом де́ле, в его́ дли́нной фигу́ре, в ба́кенах, в небольшо́й лы́сине бы́ло что́-то лаке́йски-скро́мное.","b":1},{"t":"subhead","text":"Đáp án: вошёл; пока́чивал; прозвала́ (hoặc назва́ла)"},{"t":"para","text":"Dịch: Cùng với Anna Sergeevna, một chàng trai trẻ đã bước vào và ngồi bên cạnh, anh ta có bộ râu quai nón nhỏ, rất cao, lưng gù; mỗi bước đi anh ta lại lắc lư (gật gù) đầu và dường như lúc nào cũng đang cúi chào. Có lẽ, đây là người chồng mà hồi ở Yalta, trong cơn cay đắng, cô đã gọi (đặt biệt danh) là tên đầy tớ. Quả thực, trong dáng người dài ngoằng, bộ râu, cái đầu hơi hói của anh ta có nét gì đó khiêm nhường kiểu đầy tớ."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вошёл","vi":"Bước vào.","g":null},{"t":"vocab","ru":"Пока́чивал","vi":"Lắc lư nhẹ/gật gù (по- chỉ hành động diễn ra nhẹ/lặp lại).","g":null},{"t":"vocab","ru":"Прозвала́","vi":"Đặt biệt danh/gọi tên (про- + звать).","g":null},{"t":"para","text":"5. В пе́рвом антра́кте муж ...шёл кури́ть, она́ оста́лась в кре́сле. Гу́ров, сиде́вший то́же в парте́ре, ...шёл к ней и сказа́л дрожа́щим го́лосом, улыба́ясь наси́льно: — Здра́вствуйте. Она́ ...гля́нула на него́ и ...бледне́ла, пото́м ещё раз ...гля́нула с у́жасом, не ве́ря глаза́м, и кре́пко ...жа́ла в рука́х вме́сте ве́ер и лорне́тку, очеви́дно боя́сь с собо́й, что́бы не ...па́сть в о́бморок.","b":1},{"t":"subhead","text":"Đáp án: вы́шел (hoặc пошёл); подошёл; взгля́нула; побледне́ла; взгля́нула; сжа́ла; упа́сть"},{"t":"para","text":"Dịch: Trong giờ giải lao đầu tiên, người chồng đi ra hút thuốc, cô ấy ngồi lại ghế. Gurov, cũng ngồi ở tầng trệt, đã đi đến chỗ cô và nói với giọng run run, gượng cười: — Chào em. Cô ấy ngước nhìn anh và tái nhợt đi, rồi lại nhìn lần nữa với vẻ kinh hoàng, không tin vào mắt mình, và nắm chặt chiếc quạt cùng kính lorgnette trong tay, rõ ràng đang đấu tranh với bản thân để không ngã xỉu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вы́шел","vi":"Đi ra ngoài (để hút thuốc).","g":null},{"t":"vocab","ru":"Подошёл","vi":"Tiếp cận/đến gần.","g":null},{"t":"vocab","ru":"Взгля́нула","vi":"Ngước nhìn nhanh.","g":null},{"t":"vocab","ru":"Побледне́ла","vi":"Trở nên tái nhợt (по- chỉ sự thay đổi trạng thái).","g":null},{"t":"vocab","ru":"Сжа́ла","vi":"Nắm chặt/bóp chặt.","g":null},{"t":"vocab","ru":"Упа́сть","vi":"Ngã/rơi.","g":null},{"t":"para","text":"6. О́ба молча́ли. Она́ сиде́ла, он стоя́л, ...пу́ганный её смуще́нием, не реша́ясь сесть ря́дом. ...пе́ли настра́иваемые скри́пки и фле́йта, ста́ло вдруг стра́шно, каза́лось, что из всех лож смо́трят. Но вот она́ ...ста́ла и бы́стро ...шла́ к вы́ходу; он — за ней, и о́ба шли бестолко́во, по коридо́рам, по ле́стницам, то ...нима́ясь, то ...пуска́ясь, и мелька́ли каки́е-то лю́ди в суде́йских, учи́тельских и уде́льных мунди́рах, и все со значка́ми; мелька́ли да́мы, шу́бы на ве́шалках, дул сквозно́й ве́тер, обдава́я за́пахом таба́чных оку́рков. И Гу́ров, у кото́рого си́льно би́лось се́рдце, ду́мал: “О, го́споди! И к чему́ э́ти лю́ди, э́тот орке́стр”.","b":1},{"t":"subhead","text":"Đáp án: испу́ганный (hoặc напу́ганный); Запе́ли; вста́ла; пошла́; поднима́ясь; спуска́ясь"},{"t":"para","text":"Dịch: Cả hai đều im lặng. Cô ngồi, anh đứng, hoảng sợ trước sự bối rối của cô, không dám ngồi xuống bên cạnh. Những cây vĩ cầm và sáo đang lên dây bỗng cất tiếng (vang lên), đột nhiên cảm thấy sợ hãi, dường như từ tất cả các lô ghế mọi người đang nhìn. Nhưng rồi cô đứng dậy và nhanh chóng đi ra lối ra; anh đi theo cô, và cả hai đi một cách vô định, dọc theo hành lang, cầu thang, khi thì đi lên, khi thì đi xuống, và thoáng qua những người mặc đồng phục tòa án, giáo viên, công chức, tất cả đều đeo huy hiệu; thoáng qua các quý bà, áo lông trên mắc, gió lùa thổi qua, phả vào mùi tàn thuốc lá. Và Gurov, tim đập mạnh, nghĩ: “Ôi Chúa ơi! Những người này, dàn nhạc này để làm gì cơ chứ”."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Испу́ганный","vi":"Bị làm cho sợ hãi (tính động từ).","g":null},{"t":"vocab","ru":"Запе́ли","vi":"Bắt đầu hát/vang lên (за- chỉ sự bắt đầu).","g":null},{"t":"vocab","ru":"Вста́ла","vi":"Đứng dậy (в- + стать).","g":null},{"t":"vocab","ru":"Пошла́","vi":"Bắt đầu đi.","g":null},{"t":"vocab","ru":"Поднима́ясь / спуска́ясь","vi":"Đi lên / đi xuống.","g":null},{"t":"vocab","ru":"И в э́ту мину́ту он вдруг ...по́мнил","vi":"как тогда́ ве́чером на ста́нции, проводи́в А́нну Серге́евну, говори́л себе́, что всё ко́нчилось и они́ уже́ никогда́ не ...ви́дятся. Но как ещё далеко́ бы́ло до конца́! На у́зкой, мра́чной ле́стнице, где бы́ло ...пи́сано “ход в амфитеа́тр”, она́ останови́лась.","g":null},{"t":"subhead","text":"Đáp án: вспо́мнил; уви́дятся; напи́сано"},{"t":"para","text":"Dịch: Và ngay lúc đó anh chợt nhớ lại: buổi tối hôm ấy ở nhà ga, sau khi tiễn Anna Sergeevna, anh đã tự nhủ rằng mọi chuyện đã kết thúc và họ sẽ không bao giờ gặp lại nhau nữa. Nhưng cái kết còn xa vời biết bao! Trên chiếc cầu thang hẹp và tối tăm, nơi có viết “lối lên khán đài”, cô dừng lại."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вспо́мнил","vi":"Nhớ lại (hồi tưởng).","g":null},{"t":"vocab","ru":"Уви́дятся","vi":"Gặp nhau (thấy nhau).","g":null},{"t":"vocab","ru":"Напи́сано","vi":"Được viết (thụ động cách).","g":null},{"t":"para","text":"8. — Как вы меня́ ...пуга́ли! — сказа́ла она́, тяжело́ дыша́, всё ещё бле́дная, ошеломлённая. — О, как вы меня́ ...пуга́ли! Я едва́ жива́. Заче́м вы ...е́хали? Заче́м?","b":1},{"t":"subhead","text":"Đáp án: напуга́ли; напуга́ли; прие́хали"},{"t":"para","text":"Dịch: — Anh làm em sợ quá! — cô nói, thở nặng nhọc, vẫn tái nhợt, bàng hoàng. — Ôi, anh làm em sợ quá! Em chết khiếp đi được. Anh đến đây làm gì? Tại sao?"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Напуга́ли","vi":"Làm ai đó sợ hãi (hoàn thành).","g":null},{"t":"vocab","ru":"Прие́хали","vi":"Đến nơi (bằng phương tiện).","g":null}]},{"id":"07-s163","type":"exercise","title":"Bài 662 (Trang 355-356)","num":662,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме глагол совершенного или несовершенного вида. Объясните ваш выбор. Укажите варианты. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ thể hoàn thành hoặc chưa hoàn thành. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"1. Не (беспоко́иться), я всегда́ могу́ (выделя́ть/вы́делить) вре́мя, что́бы вас (принима́ть/приня́ть).","b":1},{"t":"subhead","text":"Đáp án: беспоко́йтесь; вы́делить (hoặc выделя́ть); приня́ть"},{"t":"para","text":"Dịch: Đừng lo lắng, tôi luôn có thể dành thời gian để tiếp bạn."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не беспоко́йтесь","vi":"Mệnh lệnh thức phủ định thường dùng thể chưa hoàn thành (НСВ) để khuyên bảo hoặc trấn an.","g":null},{"t":"vocab","ru":"Могу вы́делить","vi":"Động từ мочь (có thể) chỉ khả năng thực hiện một hành động cụ thể đạt kết quả → dùng thể hoàn thành (СВ) вы́делить. (Tuy nhiên, nếu nhấn mạnh khả năng lặp lại \"luôn luôn\" có thể dùng выделя́ть).","g":null},{"t":"vocab","ru":"Что́бы приня́ть","vi":"Mục đích của việc dành thời gian là để thực hiện trọn vẹn hành động tiếp đón → СВ приня́ть.","g":null},{"t":"para","text":"2. Вы мо́жете не (продолжа́ть/продо́лжить) э́ту рабо́ту, е́ю (занима́ться/заня́ться) други́е.","b":1},{"t":"subhead","text":"Đáp án: продолжа́ть; займу́тся (tương lai của заня́ться)"},{"t":"para","text":"Dịch: Bạn có thể không (cần) tiếp tục công việc này nữa, những người khác sẽ làm (đảm nhận) nó."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Можете не продолжа́ть","vi":"Cấu trúc мочь не + động từ nguyên mẫu thường mang nghĩa \"không cần thiết phải làm gì\" (sự cho phép không làm), dùng thể chưa hoàn thành (НСВ) продолжа́ть.","g":null},{"t":"vocab","ru":"Займу́тся","vi":"Hành động sẽ xảy ra và hoàn tất trong tương lai bởi người khác → СВ заня́ться (chia ở thì tương lai).","g":null},{"t":"para","text":"3. Тебе́ нельзя́ (пренебрега́ть/пренебре́чь) свои́ми обя́занностями: мы все на тебя́ (рассчи́тывать/рассчита́ть).","b":1},{"t":"subhead","text":"Đáp án: пренебрега́ть; рассчи́тываем"},{"t":"para","text":"Dịch: Cậu không được phép lơ là trách nhiệm của mình: tất cả chúng tôi đều trông cậy vào cậu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Нельзя́ пренебрега́ть","vi":"Cấu trúc нельзя́ (không được phép/cấm) + động từ nguyên mẫu luôn dùng thể chưa hoàn thành (НСВ).","g":null},{"t":"vocab","ru":"Рассчи́тываем","vi":"Trạng thái tin tưởng/trông cậy đang diễn ra ở hiện tại → НСВ рассчи́тывать (chia hiện tại).","g":null},{"t":"para","text":"4. (Боя́ться/испуга́ться) не на́до, я не смогу́ (отвеча́ть/отве́тить) на твой вопро́с;","b":1},{"t":"subhead","text":"Đáp án: Боя́ться; отве́тить"},{"t":"para","text":"Dịch: Không cần phải sợ đâu, tôi sẽ không thể trả lời câu hỏi của bạn;"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Боя́ться не на́до","vi":"Не на́до + НСВ (lời khuyên không cần thiết phải duy trì trạng thái cảm xúc).","g":null},{"t":"vocab","ru":"Не смогу́ отве́тить","vi":"Chỉ sự bất khả thi trong việc hoàn thành một hành động cụ thể → СВ отве́тить.","g":null},{"t":"para","text":"5. За́втра он бу́дет о́чень за́нят и мо́жет не (вспомина́ть/вспо́мнить) о твое́й про́сьбе;","b":1},{"t":"subhead","text":"Đáp án: вспо́мнить (theo ngữ cảnh kết quả) hoặc вспомина́ть (theo Key sách)."},{"t":"note","text":"Lưu ý: Key của sách (trang 400) chọn вспомина́ть. Điều này ngụ ý trạng thái tâm trí: \"anh ấy bận và có thể sẽ không nhớ đến/không mảy may nghĩ đến\"."},{"t":"para","text":"Dịch: Ngày mai anh ấy sẽ rất bận và có thể sẽ không nhớ (để tâm) đến lời thỉnh cầu của bạn đâu."},{"t":"example","text":"Giải thích: Dùng НСВ вспомина́ть để nhấn mạnh việc anh ta sẽ không thực hiện hành động trí óc đó trong suốt thời gian bận rộn."},{"t":"vocab","ru":"Нельзя́ (по́льзоваться/воспо́льзоваться) ли́фтом","vi":"он не (рабо́тать/порабо́тать);","g":null},{"t":"subhead","text":"Đáp án: по́льзоваться; рабо́тает"},{"t":"para","text":"Dịch: Không được sử dụng thang máy: nó không hoạt động."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Нельзя́ по́льзоваться","vi":"Cấm đoán → НСВ.","g":null},{"t":"vocab","ru":"Не рабо́тает","vi":"Chỉ trạng thái hiện tại của thang máy (hỏng/đang sửa) → НСВ, thì hiện tại.","g":null},{"t":"para","text":"7. Я не могу́ це́лый день (занима́ться/заня́ться) одни́м де́лом;","b":1},{"t":"subhead","text":"Đáp án: занима́ться","b":1},{"t":"para","text":"Dịch: Tôi không thể làm (bận rộn với) một việc suốt cả ngày được;"},{"t":"example","text":"Giải thích: Có từ chỉ thời gian kéo dài це́лый день (suốt cả ngày) → dùng НСВ занима́ться để chỉ quá trình."},{"t":"para","text":"8. В любо́й моме́нт я могу́ (прерыва́ть/прерва́ть) свою́ рабо́ту и (помога́ть/помо́чь) вам;","b":1},{"t":"subhead","text":"Đáp án: прерва́ть; помо́чь"},{"t":"para","text":"Dịch: Bất cứ lúc nào tôi cũng có thể ngắt (dừng) công việc của mình và giúp bạn;"},{"t":"example","text":"Giải thích: В любо́й моме́нт (bất cứ lúc nào) + могу (có khả năng) chỉ khả năng thực hiện một hành động trọn vẹn, tức thì → dùng СВ (прерва́ть và помо́чь)."},{"t":"para","text":"9. Нельзя́ всё вре́мя (отдыха́ть/отдохну́ть).","b":1},{"t":"subhead","text":"Đáp án: отдыха́ть","b":1},{"t":"para","text":"Dịch: Không thể lúc nào cũng nghỉ ngơi được."},{"t":"example","text":"Giải thích: Нельзя́ + всё вре́мя (suốt) → НСВ (chỉ hành động kéo dài liên tục)."}]},{"id":"07-s164","type":"exercise","title":"Bài 663 (Trang 356-358)","num":663,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме глагол совершенного или несовершенного вида. Объясните ваш выбор. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ thể hoàn thành hoặc chưa hoàn thành. Giải thích sự lựa chọn của bạn)."},{"t":"para","text":"1. Мне ка́жется, челове́ка мо́жно (счита́ть/посчита́ть) взро́слым то́лько тогда́, когда́ его́ вме́сто у́тренников начина́ют (приглаша́ть/пригласи́ть) на вечера́.","b":1},{"t":"subhead","text":"Đáp án: счита́ть; приглаша́ть"},{"t":"para","text":"Dịch: Tôi thấy là, có thể coi một người là trưởng thành chỉ khi người đó bắt đầu được mời dự các buổi dạ tiệc tối thay vì các buổi diễn ban ngày (cho trẻ con)."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Счита́ть","vi":"Quan điểm chung, trạng thái kéo dài → НСВ.","g":null},{"t":"vocab","ru":"Начина́ют приглаша́ть","vi":"Sau động từ giai đoạn (начинать) luôn dùng động từ nguyên mẫu thể chưa hoàn thành (НСВ).","g":null},{"t":"para","text":"2. Одна́жды па́па (приглаша́ть/пригласи́ть) меня́ на пра́здничный ве́чер в больни́цу, то есть к себе́ на рабо́ту,","b":1},{"t":"subhead","text":"Đáp án: пригласи́л","b":1},{"t":"para","text":"Dịch: Một lần nọ, bố đã mời tôi đến dự buổi tiệc tối ở bệnh viện, tức là chỗ làm của bố,"},{"t":"example","text":"Giải thích: Одна́жды (một lần nọ) chỉ hành động xảy ra một lần trong quá khứ → СВ пригласи́л."},{"t":"para","text":"3. и я (соглаша́ться/согласи́ться) и сра́зу (чу́вствовать/почу́вствовать) себя́ как-то уве́ренней и взросле́е.","b":1},{"t":"subhead","text":"Đáp án: согласи́лся; почу́вствовал"},{"t":"para","text":"Dịch: và tôi đã đồng ý và ngay lập tức cảm thấy tự tin và người lớn hơn hẳn."},{"t":"example","text":"Giải thích: Chuỗi các hành động xảy ra nối tiếp nhau (bố mời → tôi đồng ý → tôi cảm thấy) → dùng СВ (согласи́лся, почу́вствовал)."},{"t":"para","text":"4. Проща́ясь и внима́тельно огля́дывая нас напосле́док, ма́ма и ба́бушка о́чень проси́ли меня́ не (говори́ть/сказа́ть) в больни́це глу́постей и всё вре́мя (по́мнить/вспо́мнить) о том, что я уже́ в шесто́м кла́ссе.","b":1},{"t":"subhead","text":"Đáp án: говори́ть; по́мнить"},{"t":"para","text":"Dịch: Khi chia tay và ngắm nghía chúng tôi lần cuối, mẹ và bà khẩn khoản bảo tôi đừng nói điều gì ngốc nghếch ở bệnh viện và phải luôn nhớ rằng tôi đã học lớp sáu rồi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не говори́ть","vi":"Yêu cầu/cấm đoán không thực hiện hành động (đừng nói lung tung) → НСВ.","g":null},{"t":"vocab","ru":"Всё вре́мя по́мнить","vi":"Từ всё вре́мя (suốt/luôn luôn) chỉ trạng thái liên tục → НСВ.","g":null},{"t":"para","text":"5. Но е́сли бы да́же я и хоте́л об э́том (забыва́ть/забы́ть), в тот ве́чер мне э́то не (удава́ться/уда́сться), потому́ что ка́ждый из па́пиных сослужи́вцев обяза́тельно (говори́ть/сказа́ть):","b":1},{"t":"subhead","text":"Đáp án: забы́ть; удало́сь; говори́л"},{"t":"para","text":"Dịch: Nhưng ngay cả khi tôi muốn quên điều đó đi chăng nữa, thì tối hôm đó tôi cũng không thể làm được (không thành công), bởi vì từng người đồng nghiệp của bố chắc chắn đều nói:"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Хоте́л забы́ть","vi":"Muốn thực hiện trọn vẹn hành động quên (kết quả) → СВ забы́ть.","g":null},{"t":"vocab","ru":"Не удало́сь","vi":"Kết quả thực tế của buổi tối hôm đó (dù có muốn cũng không được) → СВ удало́сь (quá khứ). (Sách Glazunova key dùng удалось).","g":null},{"t":"vocab","ru":"Ка́ждый ... говори́л","vi":"Chủ ngữ là ка́ждый (mỗi người) thực hiện hành động lần lượt, lặp đi lặp lại → НСВ говори́л.","g":null},{"t":"para","text":"6. — Ну, и в како́м же ты кла́ссе? — В шесто́м, — (отвеча́ть/отве́тить) я.","b":1},{"t":"subhead","text":"Đáp án: отвеча́л","b":1},{"t":"para","text":"Dịch: — Chà, thế cháu học lớp mấy rồi? — Lớp sáu ạ, — tôi trả lời."},{"t":"example","text":"Giải thích: Vì có nhiều người hỏi (ở câu trước), nên hành động trả lời cũng diễn ra nhiều lần → НСВ отвеча́л."},{"t":"para","text":"7. Не мо́жет быть! Пото́м ка́ждый обяза́тельно (обраща́ться/обрати́ться) к па́пе и (восклица́ть/воскли́кнуть):","b":1},{"t":"subhead","text":"Đáp án: обраща́лся; восклица́л"},{"t":"para","text":"Dịch: Không thể nào! Sau đó ai cũng nhất định quay sang bố và thốt lên:"},{"t":"example","text":"Giải thích: Hành động lặp lại của nhiều người (каждый) → НСВ."},{"t":"para","text":"8. — У вас уже́ тако́й большо́й сын?! Тру́дно (ве́рить/пове́рить)... Хотя́ о́чень на вас похо́ж. О́чень!","b":1},{"t":"subhead","text":"Đáp án: пове́рить","b":1},{"t":"para","text":"Dịch: — Anh đã có con trai lớn thế này rồi ư?! Khó mà tin được... Mặc dù rất giống anh. Rất giống!"},{"t":"example","text":"Giải thích: Тру́дно пове́рить: Cụm từ chỉ khả năng đạt được kết quả (tin vào một sự thật) → СВ пове́рить."},{"t":"para","text":"9. Ма́ме то́же (говори́ть/сказа́ть), что я на неё похо́ж. Поэ́тому я ника́к не мог (составля́ть/соста́вить) о свое́й вне́шности како́го-либо определённого мне́ния.","b":1},{"t":"subhead","text":"Đáp án: говори́ли; соста́вить"},{"t":"para","text":"Dịch: Mọi người cũng nói với mẹ là tôi giống mẹ. Vì thế tôi mãi không thể hình thành (đưa ra) được ý kiến xác định nào về ngoại hình của mình."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Говори́ли","vi":"Người ta nói nhiều lần (chung chung) → НСВ.","g":null},{"t":"vocab","ru":"Не мог соста́вить","vi":"Không thể đạt được kết quả (hình thành ý kiến) dù đã cố gắng → СВ соста́вить.","g":null},{"t":"subhead","text":"10. Ма́ма была́ краси́вая, а о па́пе ба́бушка как-то (говори́ть/сказа́ть):","b":1},{"t":"subhead","text":"Đáp án: сказа́ла","b":1},{"t":"para","text":"Dịch: Mẹ thì đẹp, còn về bố thì có lần bà đã nói:"},{"t":"example","text":"Giải thích: Как-то (có lần nọ) chỉ hành động xảy ra một lần trong quá khứ → СВ сказа́ла."},{"t":"para","text":"11. — Краса́вцем его́, коне́чно тру́дно (называ́ть/назва́ть)...","b":1},{"t":"subhead","text":"Đáp án: назва́ть","b":1},{"t":"para","text":"Dịch: — Tất nhiên, khó mà gọi nó là người đẹp trai được..."},{"t":"example","text":"Giải thích: Трудно назва́ть: Khó có thể thực hiện hành động định danh đó (kết quả) → СВ назва́ть."},{"t":"para","text":"12. — И не (называ́ть/назва́ть), е́сли тебе́ тру́дно! — (отвеча́ть/отве́тить) я. — Пожа́луйста... Но его́ всё равно́ все (люби́ть/полюби́ть)!","b":1},{"t":"subhead","text":"Đáp án: называ́й; отве́тил; лю́бят"},{"t":"para","text":"Dịch: — Thì bà đừng gọi thế, nếu bà thấy khó! — tôi đáp. — Mặc kệ... Nhưng mọi người dù sao cũng đều yêu mến bố!"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не называ́й","vi":"Mệnh lệnh phủ định (cấm/khuyên không làm) → НСВ называ́й.","g":null},{"t":"vocab","ru":"Отве́тил","vi":"Hành động đáp lại cụ thể trong tình huống quá khứ đó (một lần) → СВ отве́тил.","g":null},{"t":"vocab","ru":"Все лю́бят","vi":"Chỉ trạng thái tình cảm kéo dài/thường xuyên → НСВ лю́бят.","g":null}]},{"id":"07-s165","type":"exercise","title":"Bài 664 (Trang 358)","num":664,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме глагол однонаправленного или разнонаправленного движения. Объясните ваш выбор. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ chuyển động một chiều hoặc đa chiều. Giải thích sự lựa chọn của bạn)."},{"t":"para","text":"1. Во́зле до́ма была́ кутерьма́. По асфальти́рованному тротуа́ру, усе́янному би́тым стекло́м, (бежа́ть/бе́гать) и что́-то выкри́кивали лю́ди (М.Булга́ков).","b":1},{"t":"subhead","text":"Đáp án: бе́гали","b":1},{"t":"para","text":"Dịch: Gần nhà xảy ra một sự hỗn loạn. Trên vỉa hè trải nhựa rải đầy mảnh kính vỡ, mọi người chạy ngược chạy xuôi (chạy toán loạn) và la hét điều gì đó."},{"t":"example","text":"Giải thích: Hành động chạy không theo một hướng cụ thể, hỗn loạn → Động từ đa chiều бе́гать (quá khứ: бе́гали)."},{"t":"para","text":"2. Пусть ка́ждый возьмёт в ру́ки по у́лице... чёрт возьми́, по у́лице — по метле́! и вы́мели бы всю у́лицу, что (идти́/ходи́ть) к тракти́ру, и вы́мели бы чи́сто... (Н.Го́голь).","b":1},{"t":"subhead","text":"Đáp án: идёт","b":1},{"t":"para","text":"Dịch: Hãy để mỗi người cầm lấy một con phố... quỷ tha ma bắt, cầm lấy một cái chổi thay vì con phố! và quét sạch con phố dẫn (đi) đến quán rượu, và quét cho thật sạch..."},{"t":"example","text":"Giải thích: Con đường/phố xá trải dài theo một hướng về phía đích → Dùng động từ một chiều идти́ (hiện tại: идёт)."},{"t":"para","text":"3. “Я неме́дленно (везти́/вози́ть) тебя́ прочь отсю́да, — сказа́л Макс. — Снима́й хала́т и надева́й пальто́” (В.Набо́ков).","b":1},{"t":"subhead","text":"Đáp án: везу́ (hoặc увезу́ nếu cho phép dùng tiền tố, nhưng đề bài thường yêu cầu gốc từ: везу)"},{"t":"para","text":"Dịch: \"Anh sẽ chở em đi khỏi đây ngay lập tức, — Max nói. — Cởi áo choàng ra và mặc áo khoác vào\"."},{"t":"example","text":"Giải thích: Hành động cụ thể, diễn ra ngay lập tức theo một hướng (rời đi) → Động từ một chiều везти́ (hiện tại: везу́ - dùng thì hiện tại để chỉ tương lai gần quả quyết)."},{"t":"para","text":"4. Что ж? По́сле нас бу́дут (лете́ть/лета́ть) на возду́шных шара́х, изме́нятся пиджаки́, откро́ют, быть мо́жет, шесто́е чу́вство и разовью́т его́, но жизнь оста́нется всё та же... (А.Че́хов).","b":1},{"t":"subhead","text":"Đáp án: лета́ть","b":1},{"t":"para","text":"Dịch: Sao nào? Sau thời đại chúng ta người ta sẽ bay bằng khinh khí cầu, áo vest sẽ thay đổi, có thể người ta sẽ khám phá ra giác quan thứ sáu và phát triển nó, nhưng cuộc sống vẫn sẽ y nguyên như vậy..."},{"t":"example","text":"Giải thích: Khả năng/hành động chung chung lặp lại trong tương lai → Động từ đa chiều лета́ть."},{"t":"para","text":"5. Влюблённые, чья грусть, как облака́, И нея́сные заду́мчивые лэ́ди, Како́й доро́гой вас (вести́/води́ть) тоска́ (Н.Гумилёв)?","b":1},{"t":"subhead","text":"Đáp án: ведёт","b":1},{"t":"para","text":"Dịch: Những kẻ đang yêu, mà nỗi buồn như mây, Và những quý cô mơ màng khó hiểu, Nỗi sầu dẫn các người đi theo con đường nào?"},{"t":"example","text":"Giải thích: Hình ảnh \"con đường\" (какой дорогой) gợi ý sự di chuyển theo một hướng cụ thể → Động từ một chiều вести́ (hiện tại: ведёт)."},{"t":"para","text":"6. Знако́мство у ней бы́ло большо́е и разнообра́зное. К ней всё, быва́ло, го́сти (е́хать/е́здить), и всё бог зна́ет каки́е лю́ди... (Ф.Достое́вский).","b":1},{"t":"subhead","text":"Đáp án: е́здили","b":1},{"t":"para","text":"Dịch: Mối quan hệ của bà ấy rất rộng và đa dạng. Khách khứa cứ, như thường lệ, đến (đi lại) chỗ bà ấy, và toàn là những người trời ơi đất hỡi..."},{"t":"example","text":"Giải thích: Từ бывало (thường thì/đã từng) chỉ hành động lặp đi lặp lại trong quá khứ → Động từ đa chiều е́здить (quá khứ: е́здили)."},{"t":"para","text":"7. Я, пра́вда, знал, что е́сли у челове́ка всю жизнь (идти́/ходи́ть) от ме́лких неуда́ч ко всё бо́лее кру́пным, серьёзным неуда́чам, то еди́нственное здесь — перешиби́ть судьбу́ че́м-нибудь э́таким отча́янным... (В.Коне́цкий).","b":1},{"t":"subhead","text":"Đáp án: идёт","b":1},{"t":"para","text":"Dịch: Thú thực tôi biết rằng, nếu cuộc đời con người cứ đi (tiến triển) từ những thất bại nhỏ đến những thất bại ngày càng lớn và nghiêm trọng hơn, thì cách duy nhất ở đây là đập tan số phận bằng một hành động liều lĩnh nào đó..."},{"t":"example","text":"Giải thích: Diễn tả quá trình tiến triển liên tục theo một chiều hướng (từ nhỏ đến lớn) → Động từ một chiều идти́ (hiện tại: идёт - chủ ngữ ẩn là жизнь hoặc всё)."},{"t":"para","text":"8. За желе́зной решёткой игра́ли в те́ннис. (Лете́ть/Лета́ть) бе́лый мя́чик (И.Ильф, Е.Петро́в).","b":1},{"t":"subhead","text":"Đáp án: Лета́л","b":1},{"t":"para","text":"Dịch: Sau hàng rào sắt người ta đang chơi quần vợt. Quả bóng trắng bay qua bay lại."},{"t":"example","text":"Giải thích: Trong môn quần vợt, bóng bay qua lại nhiều lần → Động từ đa chiều лета́ть (quá khứ: лета́л)."},{"t":"para","text":"9. Он встал и на́чал (идти́/ходи́ть) по ко́мнате (Л.Толсто́й).","b":1},{"t":"subhead","text":"Đáp án: ходи́ть","b":1},{"t":"para","text":"Dịch: Ông ấy đứng dậy và bắt đầu đi lại trong phòng."},{"t":"example","text":"Giải thích: Đi lại trong một không gian giới hạn (по комнате), không có đích đến cụ thể → Động từ đa chiều ходи́ть."},{"t":"para","text":"10. А ночь (лете́ть/лета́ть) ти́хо и пла́вно, как на кры́льях (И.Турге́нев).","b":1},{"t":"subhead","text":"Đáp án: лете́ла","b":1},{"t":"para","text":"Dịch: Và màn đêm trôi (bay) đi tĩnh lặng và êm đềm, như trên đôi cánh."},{"t":"example","text":"Giải thích: Thời gian trôi qua theo một chiều → Động từ một chiều лете́ть (quá khứ: лете́ла)."},{"t":"para","text":"11. И не рису́ю я, и не пою́, И не (вести́/води́ть) смычко́м черноголо́сым... (О.Мандельшта́м).","b":1},{"t":"subhead","text":"Đáp án: вожу́","b":1},{"t":"para","text":"Dịch: Và tôi không vẽ, tôi không hát, Và tôi không kéo (đưa) cây vĩ cầm giọng đen đúa..."},{"t":"example","text":"Giải thích: Hành động kéo vĩ cầm là đưa cây vĩ qua lại (lặp lại/chuyển động đi về) → Động từ đa chiều води́ть (hiện tại: вожу́)."},{"t":"para","text":"12. Теку́т бесе́ды в тишине́; Луна́ (плыть/пла́вать) в ночно́м тума́не (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: плывёт","b":1},{"t":"para","text":"Dịch: Những cuộc trò chuyện trôi đi trong tĩnh lặng; Mặt trăng trôi (bơi) trong màn sương đêm."},{"t":"example","text":"Giải thích: Mặt trăng di chuyển trên bầu trời theo một hướng (từ góc nhìn người quan sát tại một thời điểm) → Động từ một chiều плыть (hiện tại: плывёт)."},{"t":"para","text":"13. И тако́й это день был осе́нний, сухо́й, со́лнце све́тит, а хо́лодно, и ве́тер, и пыль несёт, и жёлтый лист кру́тит; а я не зна́ю, како́й час, и что э́то за ме́сто, и куда́ та доро́га (вести́/води́ть)... (Н.Леско́в).","b":1},{"t":"subhead","text":"Đáp án: ведёт","b":1},{"t":"para","text":"Dịch: ...và tôi không biết bây giờ là mấy giờ, đây là nơi nào, và con đường kia dẫn đi đâu..."},{"t":"example","text":"Giải thích: Con đường dẫn về một hướng cụ thể → Động từ một chiều вести́ (hiện tại: ведёт)."},{"t":"para","text":"14. Но дни (бежа́ть/бе́гать), (бежа́ть/бе́гать) го́да — Им не сойти́ться никогда́! (М.Ле́рмонтов).","b":1},{"t":"subhead","text":"Đáp án: бегу́т; бегу́т"},{"t":"para","text":"Dịch: Nhưng ngày tháng trôi nhanh (chạy), năm tháng trôi qua, — Họ sẽ chẳng bao giờ gặp lại nhau!"},{"t":"example","text":"Giải thích: Thời gian trôi đi không trở lại (một chiều) → Động từ một chiều бежа́ть (hiện tại: бегу́т)."}]},{"id":"07-s166","type":"exercise","title":"Bài 665 (Trang 359)","num":665,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскройте скобки, употребляя в нужной форме глагол однонаправленного или разнонаправленного движения. Объясните ваш выбор. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ chuyển động một chiều hoặc đa chiều. Giải thích sự lựa chọn của bạn)."},{"t":"para","text":"1. — Вы меня́ не (гнать/гоня́ть)? нет! а я бы́ло сам хоте́л (бежа́ть/бе́гать) от вас. Я и уйду́... (Ф.Достое́вский).","b":1},{"t":"subhead","text":"Đáp án: го́ните; бежа́ть"},{"t":"para","text":"Dịch: — Các người không đuổi tôi đấy chứ? Không à! Thế mà tôi đã định tự mình bỏ chạy khỏi các người. Tôi sẽ đi đây..."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не гоните","vi":"Hành động xua đuổi cụ thể tại thời điểm nói → Một chiều гнать.","g":null},{"t":"vocab","ru":"Хотел бежать","vi":"Ý định bỏ chạy (rời đi) theo một hướng cụ thể → Một chiều бежа́ть.","g":null},{"t":"para","text":"2. — Так вот кака́я мысль (брести́/броди́ть) у тебя́ в уме́ (И.Гончаро́в).","b":1},{"t":"subhead","text":"Đáp án: бро́дит","b":1},{"t":"para","text":"Dịch: — Hóa ra cái ý nghĩ đang lảng vảng (lang thang) trong đầu cậu là thế đấy."},{"t":"example","text":"Giải thích: Suy nghĩ quẩn quanh trong đầu (không hướng cụ thể) → Đa chiều броди́ть."},{"t":"para","text":"3. [Марке́лов] ел ма́ло, бо́льше (кати́ть/ката́ть) ша́рики из хле́ба (И.Турге́нев).","b":1},{"t":"subhead","text":"Đáp án: ката́л","b":1},{"t":"para","text":"Dịch: [Markelov] ăn ít, chủ yếu vò (lăn) những viên bi từ ruột bánh mì."},{"t":"example","text":"Giải thích: Hành động vo tròn/lăn qua lại tại chỗ → Đa chiều ката́ть."},{"t":"para","text":"4. Да зато́, смотри́, чтоб ло́шади хоро́шие бы́ли! Ямщика́м скажи́, что я бу́ду дава́ть по целко́вому²; что́бы так, как фельдъе́геря, (кати́ть/ката́ть) и пе́сни бы пе́ли! (Н.Го́голь).","b":1},{"t":"subhead","text":"Đáp án: кати́ли","b":1},{"t":"para","text":"Dịch: Nhưng này, nhớ chọn ngựa cho tốt! Bảo với mấy gã xà ích là ta sẽ thưởng mỗi người một rúp; để họ phi (xe) nhanh như lính trạm và còn hát hò nữa!"},{"t":"example","text":"Giải thích: Катить ở đây mang nghĩa lao đi nhanh về phía trước (như lính đưa thư) → Một chiều кати́ть."},{"t":"para","text":"5. Плаку́чая и́ва ка́жется ещё печа́льнее, и по стволу́ её (ползти́/по́лзать) слёзы (А.Че́хов).","b":1},{"t":"subhead","text":"Đáp án: ползу́т","b":1},{"t":"para","text":"Dịch: Cây liễu rủ trông càng buồn hơn, và những giọt nước mắt bò (chảy) trên thân cây."},{"t":"example","text":"Giải thích: Nước mắt chảy xuống (một chiều) → Một chiều ползти́."},{"t":"para","text":"6. То На́стенька вдруг захо́чет домо́й, я не сме́ю удержа́ть и захочу́ проводи́ть её до са́мого до́ма. То она́ вздохнёт, и сно́ва слези́нка набежи́т и (тащи́ть/таска́ть) меня́ сно́ва (идти́/ходи́ть), болта́ть, говори́ть (Ф.Достое́вский).","b":1},{"t":"subhead","text":"Đáp án: та́щит; идти́"},{"t":"para","text":"Dịch: Khi thì Nastenka chợt muốn về nhà... Khi thì cô ấy thở dài, và giọt nước mắt lại trào ra và lại lôi (kéo) tôi đi, tán gẫu, nói chuyện."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Тащит","vi":"Mặc dù có cấu trúc lặp lại То... то..., nhưng động từ тащит ở đây miêu tả sức lôi kéo cụ thể, mạnh mẽ của cảm xúc tại khoảnh khắc đó (như một dòng chảy liên tục) → Dùng тащит (một chiều) mang tính hình tượng cao hơn.","g":null},{"t":"vocab","ru":"Идти","vi":"Hành động đi bộ nói chung → идти.","g":null},{"t":"para","text":"7. Берёзовая ро́ща горе́ла, и ве́тер (гнать/гоня́ть) пря́мо на нас тёмные, ша́ткие столбы́ ды́ма (А.Каве́рин).","b":1},{"t":"subhead","text":"Đáp án: гнал","b":1},{"t":"para","text":"Dịch: Rừng bạch dương đang cháy, và gió thổi (lùa) những cột khói đen lung lay thẳng về phía chúng tôi."},{"t":"example","text":"Giải thích: Gió thổi khói về một hướng cụ thể (прямо на нас) → Một chiều гнать (quá khứ: гнал)."},{"t":"para","text":"8. Ба́бка Ю́ля, напои́в телёнка и зада́в корм пти́це, (тащи́ть/таска́ть) во́ду, раста́пливала печь (Ю.Наги́бин).","b":1},{"t":"subhead","text":"Đáp án: таска́ла","b":1},{"t":"para","text":"Dịch: Bà Yulia, sau khi cho bê uống nước và cho gia cầm ăn, lại xách nước, nhóm lò."},{"t":"example","text":"Giải thích: Hành động xách nước là công việc lặp lại, đi đi lại lại nhiều lần để lấy nước → Đa chiều таска́ть (quá khứ: таска́ла)."},{"t":"para","text":"9. И до́лго ещё (ползти́/по́лзать) они́ по по́лу, ища́ поте́рянных де́нег (И.Гончаро́в).","b":1},{"t":"subhead","text":"Đáp án: по́лзали","b":1},{"t":"para","text":"Dịch: Và họ còn bò trên sàn rất lâu để tìm số tiền bị mất."},{"t":"example","text":"Giải thích: Bò qua bò lại trên sàn để tìm kiếm → Đa chiều по́лзать (quá khứ: по́лзали)."},{"t":"para","text":"10. Проща́й, свобо́дная стихи́я! В после́дний раз передо мно́й Ты (кати́ть/ката́ть) во́лны голубы́е И бле́щешь го́рдою красо́й (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: ка́тишь","b":1},{"t":"para","text":"Dịch: Vĩnh biệt, hỡi nguyên tố tự do (biển cả)! Lần cuối cùng trước mắt ta, Ngươi cuộn (lăn) những con sóng xanh Và toả sáng với vẻ đẹp kiêu hãnh."},{"t":"example","text":"Giải thích: Sóng biển cuộn trào vào bờ (hướng về phía nhà thơ) → Một chiều кати́ть (hiện tại: ка́тишь)."},{"t":"para","text":"11. Кули́к на́чал сова́ть в су́мку пена́л и кни́ги; они́ ника́к не (лезть/ла́зить) (А.Толсто́й).","b":1},{"t":"subhead","text":"Đáp án: ле́зли","b":1},{"t":"para","text":"Dịch: Kulik bắt đầu nhét hộp bút và sách vào cặp; chúng cứ không chịu chui vào (vừa)."},{"t":"example","text":"Giải thích: Лезть dùng với nghĩa \"vừa vặn/chui lọt vào không gian chật\". Ở đây là cố nhét vào nhưng không được (hành động hướng vào trong) → Một chiều лезть (quá khứ: ле́зли)."}]},{"id":"07-s167","type":"exercise","title":"Bài 666 (Trang 360-361)","num":666,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскро́йте ско́бки, употребля́я в ну́жной фо́рме глаго́лы движе́ния с по́стфиксом -ся и́ли без по́стфикса. Объясни́те ваш вы́бор. (Mở ngoặc đơn, sử dụng dạng cần thiết của động từ chuyển động có hậu tố -ся hoặc không có hậu tố. Giải thích sự lựa chọn của bạn)."},{"t":"para","text":"Giải thích ngữ pháp chung:","b":1},{"t":"vocab","ru":"Không có -ся (Ngoại động từ)","vi":"Dùng khi chủ ngữ thực hiện hành động tác động lên đối tượng khác (có bổ ngữ ở Cách 4 không giới từ). Ví dụ: тащить сумку (kéo cái túi).","g":null},{"t":"vocab","ru":"Có -ся (Nội động từ/Phản thân)","vi":"Dùng khi hành động tự thân, di chuyển không có đối tượng tác động trực tiếp, hoặc trong các thành ngữ chỉ trạng thái.","g":null},{"t":"para","text":"1. — Увы́, не́ту! Не́ту! — крича́ла тру́бка, — уе́хал. — А куда́? — За́ город (кати́ть/ката́ть) на маши́не (М.Булга́ков).","b":1},{"t":"subhead","text":"Đáp án: кати́л","b":1},{"t":"para","text":"Dịch: — Than ôi, không có! Không có! — ống nghe hét lên, — ông ấy đi rồi. — Đi đâu? — Ông ấy đang lái xe (lao đi) ra ngoại ô."},{"t":"example","text":"Giải thích: Кати́ть (một chiều) ở đây dùng với nghĩa thông tục là \"lái xe/đi xe nhanh\" về một hướng cụ thể. Hành động chủ động của chủ ngữ."},{"t":"para","text":"2. Вот она́ как ста́ла выздора́вливать, то и начала́ опя́ть расска́зывать, как она́ пре́жде жила́... тут и про Азо́рку рассказа́ла, как её на реке́, за го́родом, мальчи́шки (тащи́ть/таска́ть) Азо́рку на верёвке топи́ть... (Ф.Достое́вский).","b":1},{"t":"subhead","text":"Đáp án: тащи́ли","b":1},{"t":"para","text":"Dịch: Khi bà ấy bắt đầu hồi phục, bà lại bắt đầu kể về cuộc sống trước kia... rồi bà kể cả chuyện con Azorka, chuyện lũ con trai ở bờ sông ngoại ô đang lôi (kéo) con Azorka bằng dây thừng đi dìm nước như thế nào..."},{"t":"example","text":"Giải thích: Hành động cụ thể đang diễn ra trong quá khứ (lôi đi một chiều). Có đối tượng tác động là Азо́рку → Ngoại động từ тащи́ли."},{"t":"para","text":"3. И меня́ (гнать/гоня́ть) трево́га, быть мо́жет, отча́яние (А.Толсто́й).","b":1},{"t":"subhead","text":"Đáp án: гнала́","b":1},{"t":"para","text":"Dịch: Và nỗi lo âu, hay có lẽ là sự tuyệt vọng, đang xua (thúc bách) tôi đi."},{"t":"example","text":"Giải thích: Трево́га (cái gì) thúc đẩy меня (ai - đối tượng). Động từ một chiều гнать (quá khứ giống cái гнала) chỉ áp lực liên tục tại thời điểm đó."},{"t":"para","text":"4. По я́сному не́бу пла́вно (нести́сь/носи́ться), не закрыва́я со́лнца, ни́зкие, ды́мчатые ту́чи и по времена́м роня́ли на поля́ оби́льные пото́ки внеза́пного ли́вня (И.Турге́нев).","b":1},{"t":"subhead","text":"Đáp án: несли́сь","b":1},{"t":"para","text":"Dịch: Trên bầu trời quang đãng, những đám mây thấp màu khói trôi (lướt) nhanh êm ả, không che khuất mặt trời, và thỉnh thoảng trút xuống cánh đồng những đợt mưa rào bất chợt xối xả."},{"t":"example","text":"Giải thích: Mây tự di chuyển nhanh theo một hướng → Động từ phản thân một chiều нести́сь."},{"t":"para","text":"5. “Чёрт побери́”, — и, сев в киби́тку, благополу́чно просле́довал в тот край, куда́ Мака́р теля́т не (гнать/гоня́ть) (Н.Салтыко́в-Щедри́н).","b":1},{"t":"subhead","text":"Đáp án: гоня́л","b":1},{"t":"para","text":"Dịch: \"Quỷ tha ma bắt\", — và, ngồi lên xe ngựa, hắn bình an đi đến cái nơi mà \"Makar chưa từng lùa bê tới\" (tức là nơi khỉ ho cò gáy/rất xa xôi)."},{"t":"example","text":"Giải thích: Thành ngữ Куда Макар телят не гонял luôn dùng động từ đa chiều гонял (chưa từng lùa bao giờ/lặp lại)."},{"t":"para","text":"6. Я вскочи́л и гляжу́, а ночь лу́нная, и мне ви́дно, что э́то опя́ть та же ко́шечка бе́лая уже́ друго́го, живо́го мое́го голубёнка (тащи́ть/таска́ть) (Н.Леско́в).","b":1},{"t":"subhead","text":"Đáp án: та́щит","b":1},{"t":"para","text":"Dịch: Tôi nhảy dựng lên và nhìn, đêm trăng sáng, và tôi thấy vẫn là con mèo trắng ấy đang lôi một con chim bồ câu non khác còn sống của tôi đi."},{"t":"example","text":"Giải thích: Hành động đang diễn ra trước mắt, tác động lên đối tượng (голубёнка) → та́щит (một chiều, ngoại động từ)."},{"t":"para","text":"7. Пот гра́дом (кати́ть/ката́ть) у Ива́на Ива́новича и у Ива́на Ники́форовича (Н.Го́голь).","b":1},{"t":"subhead","text":"Đáp án: кати́лся","b":1},{"t":"para","text":"Dịch: Mồ hôi tuôn (lăn) như mưa trên người Ivan Ivanovich và Ivan Nikiforovich."},{"t":"example","text":"Giải thích: Mồ hôi tự chảy xuống. Кати́ться градом là cách diễn đạt cố định. Dùng кати́лся (quá khứ)."},{"t":"para","text":"8. Фаго́т станови́лся на коле́ни, ору́довал рожко́м надева́льной, кот, изнемога́я под гру́дами су́мочек и ту́фель, (тащи́ть/таска́ть) от витри́ны к табуре́там и обра́тно (М.Булга́ков).","b":1},{"t":"subhead","text":"Đáp án: таска́л","b":1},{"t":"para","text":"Dịch: Fagott quỳ xuống, loay hoay với cái đón gót, còn con mèo, kiệt sức dưới đống túi xách và giày dép, khuân (vác) từ tủ kính đến ghế đẩu và ngược lại."},{"t":"example","text":"Giải thích: Hành động qua lại (туда и обратно) → Động từ đa chiều таска́л (ngoại động từ, vì mang vác giày/túi)."},{"t":"para","text":"9. Вечо́р, ты по́мнишь, вью́га зли́лась, На му́тном не́бе мгла (нести́сь/носи́ться) (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: носи́лась","b":1},{"t":"para","text":"Dịch: Tối qua, em nhớ không, bão tuyết gầm gào, Trên bầu trời đục ngầu màn sương mù bay lượn (vần vũ)."},{"t":"example","text":"Giải thích: Sương mù bay không định hướng cụ thể, bao trùm bầu trời → Đa chiều phản thân носи́лась."},{"t":"vocab","ru":"Суета́ подняла́сь ужасне́йшая","vi":"хоте́ли то́тчас же (тащи́ть/таска́ть) его́ наве́рх, чтоб перемени́ть бельё (Ф.Достое́вский).","g":null},{"t":"subhead","text":"Đáp án: тащи́ть","b":1},{"t":"para","text":"Dịch: Một sự nhốn nháo kinh khủng nổi lên: họ muốn lôi (khiêng) anh ta lên lầu ngay lập tức để thay đồ."},{"t":"example","text":"Giải thích: Hành động một lần, theo một hướng cụ thể (lên lầu), tác động lên đối tượng (его) → тащи́ть (một chiều, ngoại động từ)."},{"t":"para","text":"11. Замеча́тельный челове́к. И тако́й весельча́к. (Кати́ть/Ката́ть) со сме́ху, когда́ она́ ему́ призна́лась в мои́х к ней отноше́ниях (В.Набо́ков).","b":1},{"t":"subhead","text":"Đáp án: Ка́тится (hoặc Ката́ется)"},{"t":"para","text":"Dịch: Một người tuyệt vời. Và vui tính quá. Anh ta cười lăn lộn (lăn ra cười) khi cô ấy thú nhận với anh ta về mối quan hệ của tôi với cô ấy."},{"t":"example","text":"Giải thích: Thành ngữ кати́ться/ката́ться со смеху (cười lăn cười bò). Ở ngữ cảnh này dùng ка́тится (như một dòng chảy cảm xúc tại thời điểm đó) hoặc ката́ется (lăn lộn qua lại) đều có thể gặp, nhưng ка́тится thường mang nghĩa \"cười ngặt nghẽo/tuôn trào\"."},{"t":"para","text":"12. Са́мый препусте́йший-пусто́й челове́к. Я его́ и пре́жде, когда́ он ещё не был так ве́лик... быва́ло, по я́рмаркам (тащи́ть/таска́ть) и у госпо́д по-францу́зски посо́бия себе́ проси́т (Н.Леско́в).","b":1},{"t":"subhead","text":"Đáp án: таска́л","b":1},{"t":"para","text":"Dịch: Một kẻ rỗng tuếch nhất trong những kẻ rỗng tuếch. Trước đây, khi hắn chưa vĩ đại như thế... tôi đã từng, có dạo, lôi (dắt) hắn đi khắp các hội chợ, và hắn xin tiền trợ cấp từ các quý ông bằng tiếng Pháp."},{"t":"example","text":"Giải thích: Быва́ло (đã từng/thường) + đi khắp nơi (по ярмаркам) → Động từ đa chiều таска́л."},{"t":"para","text":"13. — Пожа́луйста, ду́шенька! — сказа́ла Лизаве́та Ива́новна, вспы́хнув от её замеча́ния, — вперёд ко мне запи́сок не (нести́/носи́ть);","b":1},{"t":"subhead","text":"Đáp án: носи́","b":1},{"t":"para","text":"Dịch: — Làm ơn đi, cô em! — Lizaveta Ivanovna nói, đỏ mặt vì lời nhận xét của bà ta, — từ nay về sau đừng mang thư từ đến cho tôi nữa;"},{"t":"example","text":"Giải thích: Mệnh lệnh phủ định (не...) thường dùng động từ chưa hoàn thành. Ở đây cấm hành động lặp lại/chung chung → носи́ (đa chiều)."},{"t":"para","text":"14. Пото́м, в су́мерках, по окну́ стал тихо́нько потре́скивать дождь, (кати́ть/ката́ть) по стеклу́ стру́йки, остана́вливались неуве́ренно и сно́ва бы́стро сбега́ли вниз (В.Набо́ков).","b":1},{"t":"subhead","text":"Đáp án: кати́лись","b":1},{"t":"para","text":"Dịch: Sau đó, trong hoàng hôn, mưa bắt đầu gõ nhẹ lên cửa sổ, những dòng nước nhỏ lăn trên kính, ngập ngừng dừng lại rồi lại nhanh chóng chảy xuống dưới."},{"t":"example","text":"Giải thích: Chủ ngữ là струйки (những dòng nước - số nhiều) tự chảy xuống → Phản thân кати́лись."},{"t":"para","text":"15. — О́бщие рассужде́ния! — продолжа́л Пига́сов, — смерть моя́ э́ти о́бщие рассужде́ния, обозре́ния, заключе́ния! Всё э́то осно́вано на так называ́емых убежде́ниях; вся́кий толку́ет о свои́х убежде́ниях и ещё уваже́ния к ним тре́бует, (нести́сь/носи́ться) с ни́ми... Эх! (И.Турге́нев).","b":1},{"t":"subhead","text":"Đáp án: но́сится","b":1},{"t":"para","text":"Dịch: — Toàn lý luận chung chung! — Pigasov tiếp tục, — tôi chúa ghét mấy cái lý luận, đánh giá, kết luận chung chung này! Tất cả đều dựa trên cái gọi là niềm tin; ai cũng huyên thuyên về niềm tin của mình và còn đòi hỏi người ta phải tôn trọng, cứ làm như báu vật (chạy lăng xăng/ôm khư khư) với chúng... Hừ!"},{"t":"example","text":"Giải thích: Thành ngữ носи́ться с чем-то (quan trọng hóa vấn đề/ôm khư khư ý tưởng và làm rùm beng lên). Dùng но́сится (số ít, đại diện cho всякий - bất kỳ ai)."},{"t":"para","text":"16. Одна́жды оте́ц (кати́ть/ката́ть) меня́ на ло́дке с па́русом (М.Го́рький).","b":1},{"t":"subhead","text":"Đáp án: ката́л (hoặc прокати́л)"},{"t":"para","text":"Dịch: Một lần nọ, cha chở tôi đi chơi trên chiếc thuyền buồm."},{"t":"example","text":"Giải thích: Đi chơi thuyền thường là đi một vòng rồi quay lại hoặc đi dạo không mục đích → ката́л. Nếu nhấn mạnh kết quả \"đã chở một chuyến\" có thể dùng прокатил, nhưng trong bài tập so sánh gốc thì ката́л (đa chiều) phù hợp ngữ cảnh \"đi chơi/đi dạo\"."}]},{"id":"07-s168","type":"exercise","title":"Bài 667 (Trang 361)","num":667,"blocks":[{"t":"instruction","text":"Yêu cầu: Допо́лните усто́йчивые словосочета́ния необходи́мыми по смы́слу глаго́лами движе́ния. (Bổ sung vào các cụm từ cố định (thành ngữ) các động từ chuyển động cần thiết theo ý nghĩa)."},{"t":"para","text":"1. Ка́ждый в э́той жи́зни ... свой крест.","b":1},{"t":"subhead","text":"Đáp án: несёт","b":1},{"t":"para","text":"Dịch: Mỗi người trong cuộc đời này đều mang (vác) cây thánh giá của riêng mình (chịu đựng gánh nặng/số phận khổ đau)."},{"t":"para","text":"2. Дела́ его́ ... в го́ру, он преуспева́ет.","b":1},{"t":"subhead","text":"Đáp án: иду́т","b":1},{"t":"para","text":"Dịch: Công việc của anh ấy đang lên như diều gặp gió (đi lên núi), anh ấy đang thành công."},{"t":"vocab","ru":"Жизнь у него́ ска́зочная","vi":"как сыр в ма́сле ....","g":null},{"t":"subhead","text":"Đáp án: ката́ется","b":1},{"t":"para","text":"Dịch: Cuộc sống của cậu ta như trong cổ tích: sướng như tiên (lăn lộn như phô mai trong bơ) (đầy đủ, sung túc)."},{"t":"para","text":"4. Не пристава́й к нему́, не ... в буты́лку.","b":1},{"t":"subhead","text":"Đáp án: лезь","b":1},{"t":"para","text":"Dịch: Đừng chọc ghẹo nó, đừng nổi nóng (chui vào chai) vô cớ."},{"t":"note","text":"Lưu ý: Лезть в бутылку nghĩa là nổi giận, tự ái hoặc làm quá lên một cách vô lý."},{"t":"para","text":"5. Мне ка́жется, всё норма́льно, всё ... свои́м хо́дом.","b":1},{"t":"subhead","text":"Đáp án: идёт","b":1},{"t":"para","text":"Dịch: Tôi thấy mọi thứ vẫn bình thường, mọi thứ vẫn diễn ra (đi) theo trình tự của nó."},{"t":"para","text":"6. За таки́е де́рзкие слова́ его́ на́до ... в ше́ю отсю́да.","b":1},{"t":"subhead","text":"Đáp án: гнать","b":1},{"t":"para","text":"Dịch: Vì những lời hỗn xược như thế, cần phải tống cổ (đuổi vào cổ) hắn ra khỏi đây."},{"t":"para","text":"7. Куда́ ты так спеши́шь? ... сломя́ го́лову.","b":1},{"t":"subhead","text":"Đáp án: Лети́шь / Несёшься","b":1},{"t":"para","text":"Dịch: Cậu vội đi đâu thế? Lao đi (bay/chạy) như điên (như gãy đầu)."},{"t":"para","text":"8. Всю жизнь ... по пята́м, не даёт мне самому́ ша́гу ступи́ть.","b":1},{"t":"subhead","text":"Đáp án: хо́дит","b":1},{"t":"para","text":"Dịch: Suốt đời cứ bám (đi) theo gót chân, không để tôi tự bước đi bước nào."},{"t":"para","text":"9. Ду́маю, физи́ческая рабо́та всем ... на по́льзу.","b":1},{"t":"subhead","text":"Đáp án: пойдёт","b":1},{"t":"para","text":"Dịch: Tôi nghĩ, lao động chân tay sẽ có ích (đi vào lợi ích) cho tất cả mọi người."},{"t":"para","text":"10. Беда́ твоя́ в том, что ты всё вре́мя ... по тече́нию.","b":1},{"t":"subhead","text":"Đáp án: плывёшь","b":1},{"t":"para","text":"Dịch: Cái dở của cậu là lúc nào cậu cũng trôi (bơi) theo dòng nước (sống thụ động, buông xuôi)."},{"t":"para","text":"11. Мо́жет быть, он че́стный челове́к, но не мне ка́жется, в э́том де́ле он тебя́ за нос ....","b":1},{"t":"subhead","text":"Đáp án: во́дит","b":1},{"t":"para","text":"Dịch: Có thể hắn là người trung thực, nhưng tôi lại không thấy thế, trong vụ này hắn đang dắt mũi bạn đấy (lừa dối/hứa hão)."},{"t":"para","text":"12. Поторопи́сь, ... нога́ за́ ногу, так мы мо́жем опозда́ть.","b":1},{"t":"subhead","text":"Đáp án: идёшь / плетёшься","b":1},{"t":"para","text":"Dịch: Nhanh lên, đi cứ như rùa bò (chân nọ đá chân kia) thế này thì chúng ta muộn mất."},{"t":"para","text":"13. Дела́ его́ иду́т всё ху́же и ху́же, он ... по накло́нной пло́скости.","b":1},{"t":"subhead","text":"Đáp án: ка́тится","b":1},{"t":"para","text":"Dịch: Công việc của hắn ngày càng tồi tệ, hắn đang tuột dốc không phanh (lăn trên mặt phẳng nghiêng/sa đọa)."},{"t":"para","text":"14. Не сто́ит ... напроло́м, мо́жет быть, лу́чше подожда́ть и осмотре́ться?","b":1},{"t":"subhead","text":"Đáp án: лезть / идти́","b":1},{"t":"example","text":"Dịch: Không nên xông bừa (leo/đi) vào chỗ nguy hiểm/làm tới tấp bất chấp hậu quả, có lẽ tốt hơn là đợi và quan sát? (Лезть напролом phổ biến hơn)."},{"t":"para","text":"15. Никто́ не мо́жет предсказа́ть свою́ судьбу́, все под бо́гом ....","b":1},{"t":"subhead","text":"Đáp án: хо́дим","b":1},{"t":"para","text":"Dịch: Không ai có thể đoán trước số phận mình, tất cả chúng ta đều đi (sống) dưới quyền Chúa (số phận do trời định)."}]},{"id":"07-s169","type":"exercise","title":"Bài 668 (Trang 361)","num":668,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек вста́вьте необходи́мые по смы́слу приста́вки. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Thay dấu ba chấm bằng các tiền tố cần thiết theo ý nghĩa. Giải thích sự lựa chọn của bạn. Chỉ ra các phương án)."},{"t":"para","text":"Đoạn văn trích từ tác phẩm \"Rudin\" của I. Turgenev.","b":1},{"t":"para","text":"1. ...шло ещё не́сколько лет.","b":1},{"t":"subhead","text":"Đáp án: Прошло́","b":1},{"t":"para","text":"Dịch: Lại thêm vài năm nữa trôi qua."},{"t":"para","text":"Giải thích: Diễn tả thời gian trôi qua, hết quãng này đến quãng khác → Tiền tố про-."},{"t":"para","text":"2. Был осе́нний холо́дный день. К крыльцу́ гла́вной гости́ницы губе́рнского го́рода С-а ...е́хала коля́ска;","b":1},{"t":"subhead","text":"Đáp án: подъе́хала","b":1},{"t":"para","text":"Dịch: Đó là một ngày mùa thu lạnh giá. Một cỗ xe ngựa đã chạy đến (đỗ lại) bên thềm khách sạn chính của thành phố tỉnh lẻ S-a;"},{"t":"para","text":"Giải thích: Di chuyển đến gần một địa điểm và dừng lại (tiếp cận) → Tiền tố под-."},{"t":"para","text":"3. из неё ...лез господи́н, ещё не пожило́й, но уже́ успе́вший приобрести́ ту полноту́ ту́ловища, кото́рую привы́кли называть почте́нной.","b":1},{"t":"subhead","text":"Đáp án: вы́лез","b":1},{"t":"para","text":"Dịch: một quý ông leo ra từ trong đó (xe ngựa), người chưa già nhưng đã kịp có được sự đẫy đà của cơ thể mà người ta quen gọi là \"đáng kính\"."},{"t":"para","text":"Giải thích: Di chuyển từ trong không gian chật hẹp (xe ngựa) ra ngoài, hành động có chút khó khăn (leo ra) → Tiền tố вы-."},{"t":"para","text":"4. Подня́вшись по ле́стнице на второ́й эта́ж, гро́мким го́лосом спроси́л себе́ ко́мнату. Из-за ни́зких ши́рмочек вы́скочил дли́нный лаке́й и ...шёл вперёд прово́рной боково́й похóдкой.","b":1},{"t":"subhead","text":"Đáp án: прошёл (hoặc пошёл)"},{"t":"para","text":"Dịch: Sau khi lên cầu thang lên tầng hai, ông ta lớn tiếng hỏi thuê một phòng. Từ sau những tấm bình phong thấp, một gã đầy tớ cao kều nhảy ra và đi lên phía trước với dáng đi nghiêng nhanh nhẹn."},{"t":"example","text":"Giải thích: Đi về phía trước một quãng để dẫn đường → Tiền tố про- (đi qua/đi trước một đoạn) hoặc по- (bắt đầu đi). Trong văn cảnh này, прошёл вперёд (đi lên trước) là hợp lý nhất."},{"t":"para","text":"5. Войдя́ в ну́мер, прое́зжий то́тчас сбро́сил с себя́ шине́ль и шарф, пото́м веле́л позва́ть своего́ слугу́. Прое́зжий э́тот был не кто ино́й, как Ле́жнев. Слуга́ Ле́жнева ...шёл в ко́мнату.","b":1},{"t":"subhead","text":"Đáp án: вошёл","b":1},{"t":"para","text":"Dịch: Khi bước vào phòng, người khách lập tức cởi áo khoác lớn và khăn quàng, sau đó ra lệnh gọi người hầu của mình. Người khách này không ai khác chính là Lezhnev. Người hầu của Lezhnev đã bước vào phòng."},{"t":"example","text":"Giải thích: Đi từ ngoài vào trong phòng → Tiền tố в- (biến thể во- trước nhóm phụ âm)."},{"t":"para","text":"6. — Ну вот, брат, мы и ...е́хали, — промо́лвил Ле́жнев, — а ты всё боя́лся, что ши́на с колеса́ соско́чит.","b":1},{"t":"subhead","text":"Đáp án: прие́хали (hoặc дое́хали)"},{"t":"para","text":"Dịch: — Nào chú em, thế là chúng ta đã đến nơi, — Lezhnev nói, — thế mà cậu cứ sợ cái đai sắt bánh xe bị tuột ra."},{"t":"example","text":"Giải thích: Hoàn thành chuyến đi, đến đích → Tiền tố при- (đến nơi) hoặc до- (đi đến đích cuối cùng). Приехали phổ biến hơn trong giao tiếp thông thường."},{"t":"para","text":"7. — Никого́ здесь нет? — разда́лся го́лос в коридо́ре. Ле́жнев вздро́гнул и стал прислу́шиваться. — Эй! кто там? — повтори́л го́лос. Ле́жнев встал, ...шёл к две́ри и бы́стро отвори́л её.","b":1},{"t":"subhead","text":"Đáp án: подошёл","b":1},{"t":"para","text":"Dịch: — Ở đây không có ai à? — một giọng nói vang lên ngoài hành lang. Lezhnev giật mình và bắt đầu lắng nghe. — Này! Ai ở đó? — giọng nói lặp lại. Lezhnev đứng dậy, tiến lại (đi đến) phía cửa và nhanh chóng mở nó ra."},{"t":"para","text":"Giải thích: Di chuyển đến gần vật thể (cửa) trong một khoảng cách ngắn → Tiền tố под-."},{"t":"para","text":"8. Пе́ред ним стоя́л челове́к сре́днего ро́ста, почти́ совсе́м седо́й и сгорбленный.","b":1},{"t":"para","text":"Dịch (để hiểu ngữ cảnh): Trước mặt ông ta là một người đàn ông tầm thước, tóc bạc gần như trắng xóa và lưng còng."},{"t":"para","text":"9. — Ру́дин! — воскли́кнул он с волне́нием. — Вы меня́ не узнаёте? — Миха́йло Миха́йлыч! — воскли́кнул Ру́дин и протяну́л ему́ ру́ку, но смути́лся и ...вёл её бы́ло наза́д.","b":1},{"t":"subhead","text":"Đáp án: отвёл","b":1},{"t":"para","text":"Dịch: — Rudin! — ông thốt lên đầy xúc động. — Ông không nhận ra tôi sao? — Mikhailo Mikhailych! — Rudin thốt lên và đưa tay ra cho ông, nhưng rồi bối rối và định rụt tay lại."},{"t":"example","text":"Giải thích: Đưa tay ra rồi lại đưa về vị trí cũ/ra xa (rụt lại) → Tiền tố от- (tách rời/đưa ra xa). Cụm отвёл назад (đưa lùi lại/rụt lại)."},{"t":"para","text":"10. Ле́жнев поспе́шно ухвати́лся за неё обе́ими рука́ми. — ...йди́те, ...йди́те ко мне! — сказа́л он Ру́дину и ...вёл его́ в ну́мер (И.Турге́нев, “Ру́дин”).","b":1},{"t":"subhead","text":"Đáp án: Войди́те; войди́те; ввёл (hoặc завёл)"},{"t":"para","text":"Dịch: Lezhnev vội vàng nắm lấy tay ông ấy bằng cả hai tay. — Hãy vào, hãy vào chỗ tôi! — ông nói với Rudin và dẫn ông ấy vào phòng."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Войдите","vi":"Mời vào trong (từ ngoài vào) → Tiền tố в-.","g":null},{"t":"vocab","ru":"Ввёл","vi":"Dẫn ai đó vào trong → Tiền tố в- (+ вести).","g":null}]},{"id":"07-s170","type":"exercise","title":"Bài 669 (Trang 362)","num":669,"blocks":[{"t":"instruction","text":"Yêu cầu: Допо́лните усто́йчивые словосочета́ния необходи́мыми по смы́слу глаго́лами движе́ния с приста́вками. (Bổ sung vào các cụm từ cố định (thành ngữ) các động từ chuyển động có tiền tố cần thiết theo ý nghĩa)."},{"t":"para","text":"1. С тех пор ме́жду ни́ми, как бу́дто чёрная ко́шка ....","b":1},{"t":"subhead","text":"Đáp án: пробежа́ла","b":1},{"t":"para","text":"Dịch: Kể từ đó giữa họ như thể có con mèo đen chạy qua (ý nói mối quan hệ bị rạn nứt, họ cãi nhau)."},{"t":"example","text":"Thành ngữ: Чёрная кошка пробежала = xảy ra bất hòa."},{"t":"para","text":"2. Ду́маю, на́до ... я́сность в наш с ва́ми разгово́р.","b":1},{"t":"subhead","text":"Đáp án: внести́","b":1},{"t":"para","text":"Dịch: Tôi nghĩ cần phải làm sáng tỏ (mang sự rõ ràng vào) cuộc nói chuyện của chúng ta."},{"t":"example","text":"Thành ngữ: Внести ясность = làm rõ vấn đề."},{"t":"para","text":"3. На э́тот раз ему́ не уда́стся ... сухи́м из воды́.","b":1},{"t":"subhead","text":"Đáp án: вы́йти","b":1},{"t":"para","text":"Dịch: Lần này hắn sẽ không thể bình an vô sự (bước ra khô ráo từ nước) đâu."},{"t":"example","text":"Thành ngữ: Выйти сухим из воды = thoát tội/thoát nạn mà không bị tổn hại (dù có lỗi)."},{"t":"para","text":"4. Я хо́чу ... до ва́шего све́дения, что не наме́рен в дальне́йшем сле́довать ва́шим указа́ниям.","b":1},{"t":"subhead","text":"Đáp án: довести́","b":1},{"t":"para","text":"Dịch: Tôi muốn thông báo (đưa đến sự biết) cho ngài biết rằng tôi không có ý định tuân theo chỉ dẫn của ngài trong tương lai nữa."},{"t":"example","text":"Thành ngữ: Довести до сведения = thông báo chính thức."},{"t":"para","text":"5. Как тебе́ могло́ ... в го́лову тако́е реше́ние?","b":1},{"t":"subhead","text":"Đáp án: прийти́","b":1},{"t":"para","text":"Dịch: Làm sao cái quyết định như thế lại có thể nảy ra (đi vào đầu) trong đầu bạn được chứ?"},{"t":"example","text":"Thành ngữ: Прийти в голову = nảy ra ý tưởng."},{"t":"para","text":"6. У него́ с голово́й всё в поря́дке, он в жи́зни далеко́ ....","b":1},{"t":"subhead","text":"Đáp án: пойдёт","b":1},{"t":"para","text":"Dịch: Cậu ấy rất thông minh (đầu óc ổn), cậu ấy sẽ tiến xa trong đời."},{"t":"example","text":"Thành ngữ: Далеко пойти = thành công lớn/tiến xa."},{"t":"para","text":"7. На э́тот раз тебе́ не уда́стся ... меня́, я бу́ду о́чень осторо́жен.","b":1},{"t":"subhead","text":"Đáp án: провести́","b":1},{"t":"para","text":"Dịch: Lần này cậu sẽ không thể lừa (dắt mũi) tớ đâu, tớ sẽ rất cảnh giác."},{"t":"example","text":"Thành ngữ: Провести кого-то = lừa gạt ai đó."},{"t":"para","text":"8. Ты до́лжен ... себя́ в ру́ки.","b":1},{"t":"subhead","text":"Đáp án: взять","b":1},{"t":"para","text":"Dịch: Bạn phải kiềm chế (nắm lấy) bản thân (trấn tĩnh lại)."},{"t":"example","text":"Thành ngữ: Взять себя в руки = giữ bình tĩnh, làm chủ cảm xúc."},{"t":"note","text":"Lưu ý: Mặc dù взять không phải là động từ chuyển động thuần túy (motion verb), nhưng nó thường được xếp vào nhóm động từ tác động/vận chuyển trong các bài tập từ vựng rộng (như нести - mang, вести - dắt). Trong ngữ cảnh bài tập về thành ngữ này, đây là đáp án duy nhất phù hợp."},{"t":"para","text":"9. Дела́ иду́т всё ху́же и ху́же, ско́ро все мы ... по́ миру.","b":1},{"t":"subhead","text":"Đáp án: пойдём","b":1},{"t":"para","text":"Dịch: Công việc ngày càng tồi tệ, chẳng mấy chốc tất cả chúng ta sẽ đi ăn mày (đi khắp thế gian)."},{"t":"example","text":"Thành ngữ: Пойти по миру = khánh kiệt, trở thành ăn mày."},{"t":"para","text":"10. Не беспоко́йся, я всегда́ смогу́ ... к тебе́ на по́мощь.","b":1},{"t":"subhead","text":"Đáp án: прийти́","b":1},{"t":"para","text":"Dịch: Đừng lo, tôi sẽ luôn có thể đến giúp bạn."},{"t":"example","text":"Thành ngữ: Прийти на помощь = đến cứu giúp."},{"t":"para","text":"11. Ты напра́сно рассерди́лся на мои́ слова́, я из его́ кабине́та е́ле но́ги ....","b":1},{"t":"subhead","text":"Đáp án: унёс","b":1},{"t":"para","text":"Dịch: Bạn giận lời tôi nói là vô ích thôi, tôi suýt thì không thoát (mang nổi chân) khỏi văn phòng ông ta đấy (chạy bán sống bán chết)."},{"t":"example","text":"Thành ngữ: Еле ноги унести = may mà chạy thoát/thoát chết trong gang tấc."},{"t":"para","text":"12. Я зна́ю, ты гото́в ... себя́ в же́ртву обстоя́тельствам, но сто́ит ли э́то де́лать.","b":1},{"t":"subhead","text":"Đáp án: принести́","b":1},{"t":"para","text":"Dịch: Tôi biết bạn sẵn sàng hy sinh (mang bản thân làm vật tế) cho hoàn cảnh, nhưng có đáng làm thế không."},{"t":"example","text":"Thành ngữ: Принести в жертву = hy sinh."},{"t":"para","text":"13. Я уве́рен, мы смо́жем ... его́ на чи́стую во́ду.","b":1},{"t":"subhead","text":"Đáp án: вы́вести","b":1},{"t":"para","text":"Dịch: Tôi tin chắc chúng ta sẽ có thể vạch trần (đưa hắn ra vùng nước sạch) hắn."},{"t":"example","text":"Thành ngữ: Вывести на чистую воду = vạch trần bộ mặt thật/tội lỗi."},{"t":"para","text":"14. Твоя́ ложь в конце́ концо́в ... тебе́ бо́ком.","b":1},{"t":"subhead","text":"Đáp án: вы́йдет","b":1},{"t":"para","text":"Dịch: Lời nói dối của cậu rốt cuộc sẽ làm hại (đi ra đằng hông) cậu thôi."},{"t":"example","text":"Thành ngữ: Выйти боком = mang lại hậu quả xấu/gậy ông đập lưng ông."},{"t":"para","text":"15. Свои́ми вопро́сами ты мо́жешь кого́ уго́дно ... до бе́лого кале́ния.","b":1},{"t":"subhead","text":"Đáp án: довести́","b":1},{"t":"para","text":"Dịch: Bằng những câu hỏi của mình, cậu có thể khiến bất kỳ ai phát điên (đưa đến độ nung trắng)."},{"t":"example","text":"Thành ngữ: Довести до белого каления = chọc tức ai đó đến cực điểm."},{"t":"para","text":"16. У меня́ от стра́ха душа́ ... в пя́тки.","b":1},{"t":"subhead","text":"Đáp án: ушла́","b":1},{"t":"para","text":"Dịch: Tôi sợ đến mức hồn xiêu phách lạc (linh hồn chui xuống gót chân)."},{"t":"example","text":"Thành ngữ: Душа в пятки ушла = sợ chết khiếp."},{"t":"para","text":"17. Ты до́лжен ... в моё положе́ние и помо́чь мне.","b":1},{"t":"subhead","text":"Đáp án: войти́","b":1},{"t":"para","text":"Dịch: Bạn phải đặt mình vào (đi vào) hoàn cảnh của tôi và giúp tôi."},{"t":"example","text":"Thành ngữ: Войти в положение = thông cảm/thấu hiểu hoàn cảnh."}]},{"id":"07-s171","type":"exercise","title":"Bài 670 (Trang 362-363)","num":670,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскро́йте ско́бки, употребля́я в ну́жной фо́рме глаго́лы однонапра́вленного или разнонапра́вленного движе́ния с приста́вками. Вме́сто то́чек, где ну́жно, вста́вьте необходи́мые по смы́слу предло́ги. (Mở ngoặc đơn, sử dụng động từ chuyển động một chiều hoặc đa chiều với các tiền tố ở dạng thích hợp. Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa nếu cần)."},{"t":"para","text":"1. Я дам тебе́ четы́реста фра́нков, но ты полу́чишь их от меня́ то́лько в том слу́чае, е́сли (переходи́ть/перейти́) ... (правосла́вная ве́ра) (М.Салтыко́в-Щедри́н);","b":1},{"t":"subhead","text":"Đáp án: перейдёшь в правосла́вную ве́ру","b":1},{"t":"para","text":"Dịch: Tôi sẽ đưa cho anh bốn trăm franc, nhưng anh sẽ chỉ nhận được số tiền đó từ tôi trong trường hợp anh chuyển sang đạo Chính thống giáo."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Перейти́ (hoàn thành thể)","vi":"Chỉ hành động chuyển đổi dứt điểm từ trạng thái này sang trạng thái khác (tôn giáo).","g":null},{"t":"subhead","text":"Cấu trúc: перейти́ в + Cách 4 (Accusative) → в правосла́вную ве́ру."},{"t":"para","text":"2. Когда́, в 1940 году́, я реши́л (переходи́ть/перейти́) ... (англи́йский язы́к), беда́ моя́ заключа́лась в том, что пе́ред тем, в тече́ние пятна́дцати с ли́шком лет, я писа́л по-ру́сски и э́ти го́ды наложи́ли со́бственный отпеча́ток на своё ору́дие, на своего́ посре́дника (В.Набо́ков);","b":1},{"t":"subhead","text":"Đáp án: перейти́ на англи́йский язы́к","b":1},{"t":"para","text":"Dịch: Khi tôi quyết định chuyển sang (viết bằng) tiếng Anh vào năm 1940, nỗi khổ của tôi nằm ở chỗ trước đó, trong hơn mười lăm năm, tôi đã viết bằng tiếng Nga..."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Реши́л перейти́","vi":"Quyết định thực hiện một sự thay đổi (hoàn thành thể).","g":null},{"t":"subhead","text":"Cấu trúc: перейти́ на + Cách 4 (khi nói về chuyển sang ngôn ngữ khác/chế độ khác) → на англи́йский язы́к."},{"t":"para","text":"3. Ликоспа́стов почему́-то уе́хал на Кавка́з, прия́теля мое́го, у кото́рого я похища́л револьве́р, (переводи́ть/перевести́) ... (слу́жба) в Ленингра́д, а Бомба́рдов заболе́л воспале́нием по́чек, и его́ помести́ли в лече́бницу (М.Булга́ков);","b":1},{"t":"subhead","text":"Đáp án: перевели́ по слу́жбе (hoặc слу́жба перевела́)"},{"t":"para","text":"Dịch: Chẳng hiểu sao Likospastov lại đi Kavkaz, người bạn mà tôi đã lấy trộm khẩu súng lục thì được (cơ quan) thuyên chuyển công tác đến Leningrad..."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Перевести́","vi":"Chuyển ai đó đi nơi khác (hoàn thành thể, quá khứ). Ở đây dùng số nhiều перевели (người ta chuyển anh ấy - câu vô nhân xưng) hoặc служба перевела (cơ quan chuyển).","g":null},{"t":"example","text":"Giới từ: Thường dùng перевести в (đến đâu) по службе (theo công việc). Nếu điền vào chỗ trống ... (служба) thì hợp lý nhất là слу́жба перевела́ (chủ ngữ là служба)."},{"t":"para","text":"4. Я не (переноси́ть/перенести́) ... (ложь) (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: переношу́ лжи (hoặc ложь)"},{"t":"para","text":"Dịch: Tôi không chịu đựng được sự dối trá."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Не переноси́ть","vi":"Không chịu đựng được (tính cách/thói quen) → Dùng hiện tại, chưa hoàn thành thể переношу́.","g":null},{"t":"example","text":"Sau động từ phủ định mạnh hoặc từ chỉ trạng thái tinh thần, bổ ngữ có thể ở Cách 2 (лжи) hoặc Cách 4 (ложь). Cách 4 phổ biến hơn trong văn nói hiện đại, Cách 2 mang sắc thái văn học/phủ định tuyệt đối."},{"t":"para","text":"5. Но зла́ков на поля́х всё нет, и́бо глу́повцы от безде́йствия ве́село-бу́йственного (переходи́ть/перейти́) ... (безде́йствие мра́чное) (М.Салтыко́в-Щедри́н);","b":1},{"t":"subhead","text":"Đáp án: перехо́дят в безде́йствие мра́чное","b":1},{"t":"para","text":"Dịch: Nhưng ngũ cốc trên đồng vẫn không có, bởi vì dân Glupov chuyển từ sự lười biếng vui vẻ-náo nhiệt sang sự lười biếng ảm đạm."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Перехо́дят","vi":"Diễn tả quy luật/quá trình diễn ra (hiện tại, chưa hoàn thành).","g":null},{"t":"subhead","text":"Cấu trúc: переходи́ть в + Cách 4 (trạng thái mới) → в безде́йствие."},{"t":"para","text":"6. Он опубликова́л дово́льно любопы́тные “Злоключе́ния Диплома́та” (переводи́ть/перевести́) ... (англи́йский язы́к) “Бори́са Годуно́ва” (В.Набо́ков);","b":1},{"t":"subhead","text":"Đáp án: перевёл на англи́йский язы́к","b":1},{"t":"para","text":"Dịch: Ông ta đã xuất bản cuốn \"Những tai ương của nhà ngoại giao\" khá thú vị, [và] đã dịch tác phẩm \"Boris Godunov\" sang tiếng Anh."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Перевёл","vi":"Hành động đã hoàn tất (dịch xong) → Hoàn thành thể перевести́.","g":null},{"t":"subhead","text":"Cấu trúc: перевести́ на + Cách 4 (ngôn ngữ đích) → на англи́йский язы́к."},{"t":"para","text":"7. Разгово́р (переходи́ть/перейти́) ... (злоупотребле́ний власте́й) в Соединённых Шта́тах, на А́нна то́тчас же (переводи́ть/перевести́) его́ ... (друга́я те́ма) (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: перешёл на злоупотребле́ния власте́й; перевела́; на другу́ю те́му"},{"t":"para","text":"Dịch: Cuộc trò chuyện chuyển sang việc lạm quyền ở Hoa Kỳ, nhưng Anna ngay lập tức chuyển nó sang chủ đề khác."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Перешёл / Перевела́","vi":"Các hành động xảy ra nối tiếp nhau trong quá khứ (hoàn thành thể).","g":null},{"t":"subhead","text":"Cấu trúc: перейти́/перевести́ на + Cách 4 (chủ đề mới) → на злоупотребле́ния / на другу́ю те́му."},{"t":"para","text":"8. Лесни́к погляде́л на о́браз, ... (о́браз) (переводи́ть/перевести́) глаза́ ... (охо́тник) и опусти́л их на скамью́ (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: с о́браза; перевёл; на охо́тника"},{"t":"para","text":"Dịch: Người gác rừng nhìn vào bức tranh thánh, chuyển ánh mắt từ bức tranh thánh sang người thợ săn và hạ mắt xuống ghế dài."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Перевёл глаза","vi":"Di chuyển ánh nhìn (hoàn thành).","g":null},{"t":"subhead","text":"Cấu trúc: с + Cách 2 (từ đâu) на + Cách 4 (sang đâu) → с о́браза ... на охо́тника."},{"t":"para","text":"9. Спи́рьку обра́довало, что хозя́ин (переходи́ть/перейти́) ... (“ты”) — так лу́чше. (В.Шукши́н);","b":1},{"t":"subhead","text":"Đáp án: перешёл на “ты”","b":1},{"t":"para","text":"Dịch: Spirka vui mừng vì ông chủ chuyển sang (xưng hô) \"mày/cậu\" — thế tốt hơn."},{"t":"example","text":"Giải thích: Перейти на ты (thành ngữ: chuyển sang cách xưng hô thân mật). Dùng quá khứ hoàn thành перешёл."},{"t":"para","text":"10. Зате́м сын черномо́рского геро́я мя́гко, без нажи́ма (переходи́ть/перейти́) ... (де́ло) (И.Ильф, Е.Петро́в);","b":1},{"t":"subhead","text":"Đáp án: перешёл к де́лу","b":1},{"t":"para","text":"Dịch: Sau đó, con trai của người anh hùng Biển Đen nhẹ nhàng, không gây áp lực, chuyển sang công việc chính."},{"t":"example","text":"Giải thích: Перейти к делу (bắt tay vào việc/đi vào trọng tâm). Giới từ к + Cách 3."},{"t":"para","text":"11. Он боя́лся расспро́сов о хо́де де́ла Коре́йко, поэ́тому серди́то соедини́л бро́ви и (переходи́ть/перейти́) ... (нападе́ние) (И.Ильф, Е.Петро́в);","b":1},{"t":"subhead","text":"Đáp án: перешёл в нападе́ние (hoặc к нападе́нию)"},{"t":"para","text":"Dịch: Hắn sợ bị hỏi về tiến độ vụ Koreiko, nên cau mày giận dữ và chuyển sang tấn công."},{"t":"example","text":"Giải thích: Перейти в нападение/в наступление (chuyển sang thế tấn công)."},{"t":"para","text":"12. Он (переходи́ть/перейти́) от нас ... (слу́жба) в одну́ из петербу́ргских больни́ц, а поздне́е был, по слу́хам, изве́стным врачо́м в По́льше (В.Набо́ков).","b":1},{"t":"subhead","text":"Đáp án: перешёл на слу́жбу","b":1},{"t":"para","text":"Dịch: Ông ấy chuyển từ chỗ chúng tôi đến làm việc (phục vụ) tại một trong những bệnh viện ở Petersburg..."},{"t":"example","text":"Giải thích: Перейти на службу (chuyển công tác/nơi làm việc)."}]},{"id":"07-s172","type":"exercise","title":"Bài 671 (Trang 363-364)","num":671,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскро́йте ско́бки, употребля́я в ну́жной фо́рме оди́н из глаго́лов движе́ния с приста́вкой под-, при- или до-. Вме́сто то́чек вста́вьте необходи́мые по смы́слу предло́ги. (Mở ngoặc đơn, sử dụng một trong các động từ chuyển động với tiền tố под- (tiếp cận), при- (đến nơi), hoặc до- (đạt tới giới hạn/đích) ở dạng thích hợp. Thay dấu ba chấm bằng các giới từ cần thiết)."},{"t":"para","text":"1. Он хоте́л (бежа́ть/бе́гать) ... (она́); но, вспо́мнив, что могли́ быть посторо́нние, огляну́лся на балко́нную дверь и покрасне́л (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: подбежа́ть к ней","b":1},{"t":"para","text":"Dịch: Chàng định chạy lại phía nàng; nhưng nhớ ra có thể có người lạ, chàng nhìn lại cửa ban công và đỏ mặt."},{"t":"example","text":"Giải thích: Chạy lại gần ai đó → под- + giới từ к (+ Cách 3)."},{"t":"para","text":"2. — Я пойду́. А вы остава́йтесь. Я сама́ (идти́/ходи́ть) (И.Ильф, Е.Петро́в);","b":1},{"t":"subhead","text":"Đáp án: дойду́ (hoặc приду́)"},{"t":"para","text":"Dịch: — Tôi đi đây. Còn các vị cứ ở lại. Tôi sẽ tự đi đến nơi (tự lo được đường đi)."},{"t":"example","text":"Giải thích: Ngữ cảnh là tự đi đến đích mà không cần tiễn/giúp → дойду (đi đến đích) hoặc доберусь. Trong danh sách cho phép, дойду hợp lý nhất."},{"t":"para","text":"3. (Идти́/Ходи́ть) ли час мое́й свобо́ды? Пора́, пора́! — взыва́ю к ней; Брожу́ над мо́рем, жду пого́ды, Маню́ ветри́ла корабле́й (А.Пу́шкин);","b":1},{"t":"subhead","text":"Đáp án: Придёт","b":1},{"t":"para","text":"Dịch: Liệu giờ phút tự do của ta có đến không? Đã đến lúc rồi! — ta kêu gọi nó..."},{"t":"example","text":"Giải thích: Thời gian/sự kiện đến → Придёт (Tương lai của прийти)."},{"t":"para","text":"4. Звёзды уже́ начина́ли бледне́ть и не́бо сере́ло, когда́ коля́ска (е́хать/е́здить) ... (крыльцо́) до́мика в Васи́льевском (И.Турге́нев);","b":1},{"t":"subhead","text":"Đáp án: подъе́хала к крыльцу́","b":1},{"t":"para","text":"Dịch: Những vì sao đã bắt đầu mờ đi và bầu trời xám xịt, khi cỗ xe ngựa chạy đến (đỗ lại) trước thềm ngôi nhà nhỏ ở Vasilievskoye."},{"t":"example","text":"Giải thích: Xe đi đến sát vật thể (bậc thềm) → Подъехала к (+ Cách 3)."},{"t":"para","text":"5. [Ива́н Ива́нович] бро́сился в во́ду с шу́мом и поплы́л; (плыть/пла́вать) ... (са́мая середи́на) плёса и нырну́л (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: доплы́л до са́мой середи́ны","b":1},{"t":"para","text":"Dịch: Ivan Ivanovich lao xuống nước ầm ầm và bơi; bơi đến đúng giữa vùng nước lặng thì lặn xuống."},{"t":"example","text":"Giải thích: Bơi đến một điểm đích xác định (giữa hồ) → Доплыл до (+ Cách 2)."},{"t":"para","text":"6. Дожда́вшись конца́ кадри́ли, Си́тников (вести́/води́ть) Арка́дия ... (Одинцо́ва) (И.Турге́нев);","b":1},{"t":"subhead","text":"Đáp án: подввёл ... к Одинцо́вой"},{"t":"para","text":"Dịch: Đợi điệu nhảy quadrille kết thúc, Sitnikov dẫn Arkady lại chỗ Odintsova."},{"t":"example","text":"Giải thích: Dẫn ai đó lại gần ai đó (để giới thiệu/gặp mặt) → Подвёл к."},{"t":"para","text":"7. Он сходи́л и (нести́/носи́ть) отве́т стра́нный, что А́нна Андре́евна и князь Никола́й Ива́нович с нетерпе́нием ожида́ют меня́ к себе́ (Ф.Достое́вский);","b":1},{"t":"subhead","text":"Đáp án: принёс","b":1},{"t":"para","text":"Dịch: Anh ta đi và mang về (đem đến) một câu trả lời lạ lùng..."},{"t":"example","text":"Giải thích: Đi và quay lại mang theo kết quả → Принёс."},{"t":"para","text":"8. Весна́ была́ ра́нняя. Уже́ в нача́ле ма́рта полили́сь с гор ручьи́ и (лете́ть/лета́ть) грачи́ (М.Салтыко́в-Щедри́н);","b":1},{"t":"subhead","text":"Đáp án: прилете́ли","b":1},{"t":"para","text":"Dịch: Mùa xuân đến sớm. Ngay đầu tháng Ba, suối đã chảy từ trên núi xuống và lũ quạ đã bay về."},{"t":"example","text":"Giải thích: Chim di cư bay về khi xuân đến → Прилетели."},{"t":"para","text":"9. Лобы́тко, скользя́ по парке́ту, (лете́ть/лета́ть) ... (сире́невая ба́рышня) и понёсся с не́ю по за́ле. Та́нцы начали́сь (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: подлете́л к сире́невой ба́рышне","b":1},{"t":"para","text":"Dịch: Lobytko, lướt trên sàn gỗ, lao vụt (bay) đến chỗ cô tiểu thư mặc áo tím và cùng cô lướt đi trong phòng. Khiêu vũ bắt đầu."},{"t":"example","text":"Giải thích: Di chuyển nhanh đến gần ai đó (theo nghĩa bóng là \"bay đến\") → Подлетел к."},{"t":"para","text":"10. [Бессо́нов] (вести́/води́ть) Да́шу ... (гости́ница), прости́лся учти́во (А.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: проводи́л / довёл до гости́ницы (hoặc привёл в гостиницу)"},{"t":"para","text":"Dịch: Bessonov đưa (dẫn) Dasha đến khách sạn, rồi chia tay lịch sự."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Довёл до","vi":"Dẫn đi đến tận đích.","g":null},{"t":"vocab","ru":"Привёл в","vi":"Dẫn vào trong.","g":null},{"t":"vocab","ru":"Проводил до","vi":"Tiễn đến tận nơi (Phổ biến nhất trong ngữ cảnh này, nhưng đề bài yêu cầu под/при/до). Vậy chọn довёл до гости́ницы (dẫn đến tận khách sạn).","g":null},{"t":"para","text":"11. У́тром Степа́н (кати́ть/ката́ть) в Я́годное. Волну́ясь привяза́л ло́шадь у воро́т, пошёл в людску́ю (М.Шо́лохов);","b":1},{"t":"subhead","text":"Đáp án: прикати́л (hoặc подкатил)"},{"t":"para","text":"Dịch: Buổi sáng Stepan lái xe (đánh xe) đến Yagodnoye. Hồi hộp buộc ngựa ở cổng, rồi đi vào khu nhà gia nhân."},{"t":"example","text":"Giải thích: Đến nơi bằng phương tiện → Прикатил (đến nơi) hoặc Подкатил (đến sát cổng). Vì sau đó buộc ngựa ở cổng, подкатил (đến sát) hoặc прикатил (đến làng Yagodnoye) đều được. Прикатил nhấn mạnh việc đã đến đích."},{"t":"para","text":"12. Ибраги́м чу́вствовал, что судьба́ его́ должна́ перемени́ться и что связь его́ ра́но и́ли по́здно могла́ (идти́/ходи́ть) ... (све́дение) гра́фа (А.Пу́шкин).","b":1},{"t":"subhead","text":"Đáp án: дойти́ до све́дения","b":1},{"t":"para","text":"Dịch: Ibragim cảm thấy số phận mình sắp thay đổi và mối quan hệ của anh sớm muộn gì cũng có thể đến tai (đến sự hiểu biết) của bá tước."},{"t":"example","text":"Giải thích: Thành ngữ дойти до сведения (được ai đó biết đến). Cấu trúc до- + giới từ до."}]},{"id":"07-s173","type":"exercise","title":"Bài 672 (Trang 364)","num":672,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскро́йте ско́бки, употребля́я в ну́жной фо́рме оди́н из глаго́лов движе́ния с приста́вкой от- (ото-), вы- и́ли у-. Вме́сто то́чек вста́вьте необходи́мые по смы́слу предло́ги. (Mở ngoặc đơn, sử dụng một trong các động từ chuyển động với tiền tố от- (ото-) [rời xa một quãng ngắn/đưa đi], вы- [đi ra khỏi] hoặc у- [rời đi hẳn/vắng mặt] ở dạng thích hợp. Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa)."},{"t":"para","text":"1. — Она́ заче́м к нам приезжа́ла? — спроси́ла Не́лли как бу́дто с недово́льным ви́дом, когда́ Алекса́ндра Семёновна (е́хать/е́здить) (Ф.Достое́вский);","b":1},{"t":"subhead","text":"Đáp án: уе́хала","b":1},{"t":"para","text":"Dịch: — \"Cô ta đến chỗ chúng ta làm gì thế?\" — Nelly hỏi với vẻ mặt dường như không hài lòng khi Alexandra Semenovna đã rời đi."},{"t":"para","text":"Giải thích: Hành động đã hoàn tất, nhân vật đã rời khỏi địa điểm đó → Tiền tố у- (chỉ sự vắng mặt/rời đi)."},{"t":"para","text":"2. Из плацка́ртного мя́гкого ваго́на № 9 ки́евского по́езда, прише́дшего в Москву́, в числе́ други́х (идти́/ходи́ть) пассажи́р с ма́леньким фи́бровым чемода́нчиком в руке́ (М.Булга́ков);","b":1},{"t":"subhead","text":"Đáp án: вы́шел","b":1},{"t":"para","text":"Dịch: Từ toa xe giường nằm mềm số 9 của chuyến tàu Kiev đến Moscow, trong số những người khác, một hành khách đã bước ra với chiếc vali sợi nhỏ trên tay."},{"t":"para","text":"Giải thích: Di chuyển từ trong không gian kín (toa tàu) ra ngoài → Tiền tố вы-."},{"t":"para","text":"3. Земляку́ Корча́гина — Алёше Кохано́вскому — бы́ло пору́чено (везти́/вози́ть) больно́го в родно́й го́род (Н.Остро́вский);","b":1},{"t":"subhead","text":"Đáp án: отвезти́","b":1},{"t":"para","text":"Dịch: Người đồng hương của Korchagin — Alyosha Kokhanovsky — được giao nhiệm vụ chở (đưa) người bệnh về thành phố quê hương."},{"t":"example","text":"Giải thích: Đưa ai đó đến một địa điểm cụ thể (в родной город) → Tiền tố от- (thường dùng отвезти để chỉ việc vận chuyển đến đích)."},{"t":"para","text":"4. Скажи́ Кири́лу Петро́вичу, чтоб он скоре́е убира́лся, а то я велю́ его́ (гнать/гоня́ть) ... (двор) (А.Пу́шкин);","b":1},{"t":"subhead","text":"Đáp án: вы́гнать со двора́","b":1},{"t":"para","text":"Dịch: Hãy bảo Kirila Petrovich cuốn xéo ngay đi, nếu không ta sẽ ra lệnh tống cổ (đuổi) hắn ra khỏi sân."},{"t":"para","text":"Giải thích:","b":1},{"t":"para","text":"Đuổi ra khỏi không gian giới hạn (sân) → Tiền tố вы-."},{"t":"example","text":"Giới từ đi với вы- khi rời khỏi bề mặt/sân bãi (двор) là с/со → со двора."},{"t":"para","text":"5. — Кто ви́дел вас одна́жды, тот наве́ки (нести́/носи́ть) ... (собо́й) ваш боже́ственный о́браз (М.Ле́рмонтов);","b":1},{"t":"subhead","text":"Đáp án: унесёт с собо́й","b":1},{"t":"para","text":"Dịch: — Ai đã gặp nàng một lần, kẻ đó sẽ mang theo hình ảnh thánh thiện của nàng bên mình mãi mãi."},{"t":"example","text":"Giải thích: Mang cái gì đó đi theo mình (rời đi cùng nó) → Tiền tố у-. С собой (với bản thân)."},{"t":"para","text":"6. Сняли́сь с я́коря, (идти́/ходи́ть) попу́тным ве́тром и то́лько (идти́/ходи́ть) ... (бе́рег) ми́ли три, как поду́л проти́вный [ве́тер] (И.Гончаро́в);","b":1},{"t":"subhead","text":"Đáp án: вы́шли; отошли́ от бе́рега"},{"t":"para","text":"Dịch: Nhổ neo, ra khơi (đi ra) nhờ gió thuận và chỉ vừa đi cách bờ khoảng ba dặm thì gió ngược thổi đến."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вышли","vi":"Rời cảng ra biển → Tiền tố вы-.","g":null},{"t":"vocab","ru":"Отошли от","vi":"Di chuyển ra xa một khoảng cách so với vật mốc → Tiền tố от- + giới từ от.","g":null},{"t":"para","text":"7. Толстя́к махну́л руко́й, схвати́л шля́пу и (бежа́ть/бе́гать) ... (ко́мната) (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: вы́бежал из ко́мнаты","b":1},{"t":"para","text":"Dịch: Gã béo phẩy tay, vớ lấy cái mũ và chạy ra khỏi phòng."},{"t":"para","text":"Giải thích: Chạy từ trong ra ngoài → Tiền tố вы- + giới từ из."},{"t":"para","text":"8. Варва́ра Миха́йловна реши́ла не остава́ться бо́льше с гостя́ми ни одно́й мину́ты. Ей хоте́лось поскоре́е (идти́/ходи́ть) ... (своя́ ко́мната), лечь, успоко́иться, забы́ться сном (А.Купри́н);","b":1},{"t":"subhead","text":"Đáp án: уйти́ в свою́ ко́мнату","b":1},{"t":"para","text":"Dịch: Varvara Mikhailovna quyết định không ở lại với khách thêm một phút nào nữa. Cô ấy muốn nhanh chóng rời đi (về) phòng mình, nằm xuống, tĩnh tâm và chìm vào giấc ngủ."},{"t":"para","text":"Giải thích: Rời bỏ đám đông để đi chỗ khác → Tiền tố у-. Đích đến là phòng → giới từ в."},{"t":"para","text":"9. Господа́, я до́лжен бу́ду приказа́ть вас (вести́/води́ть) наруши́теля тишины́! (М.Салтыко́в-Щедри́н);","b":1},{"t":"subhead","text":"Đáp án: вы́вести","b":1},{"t":"para","text":"Dịch: Thưa quý vị, tôi sẽ buộc phải ra lệnh đưa (dẫn) kẻ gây rối trật tự ra ngoài!"},{"t":"para","text":"Giải thích: Dẫn ra khỏi nơi hiện tại → Tiền tố вы-."},{"t":"para","text":"10. — Ня́ня! Не ви́дишь, что ребёнка (бежа́ть/бе́гать) ... (со́лнышко)! (Вести́/Води́ть) его́ ... (холодо́к) (И.Гончаро́в);","b":1},{"t":"subhead","text":"Đáp án: убежа́л на со́лнышко; Уведи́ ... в холодо́к"},{"t":"para","text":"Dịch: — Vú em! Ngươi không thấy đứa bé đã chạy tót ra nắng sao! Hãy dắt nó đi (ra) chỗ mát."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Убежал","vi":"Chạy đi mất/chạy ra chỗ khác (khỏi tầm kiểm soát).","g":null},{"t":"vocab","ru":"Уведи","vi":"Dắt đi chỗ khác/dắt rời đi → Tiền tố у-.","g":null},{"t":"para","text":"11. Едва́ он (е́хать/е́здить) не́сколько шаго́в, как ту́ча, с утра́ угрожа́вшая дождём (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: отъе́хал","b":1},{"t":"para","text":"Dịch: Ngay khi ông ta vừa đánh xe đi được (đi xa) vài bước, thì đám mây đen, đe dọa mưa từ sáng..."},{"t":"para","text":"Giải thích: Di chuyển một khoảng ngắn từ điểm xuất phát → Tiền tố от-."},{"t":"para","text":"12. Они́ вы́брали ло́дку поме́ньше и (нести́/носи́ть) ... (она́) на бе́рег все ве́щи (В.Арсе́ньев);","b":1},{"t":"subhead","text":"Đáp án: вы́несли из неё","b":1},{"t":"para","text":"Dịch: Họ chọn một chiếc thuyền nhỏ hơn và khuân (mang) tất cả đồ đạc từ đó lên bờ."},{"t":"para","text":"Giải thích: Mang từ trong (thuyền) ra ngoài → Tiền tố вы- + giới từ из."},{"t":"para","text":"13. Оте́ц (везти́/вози́ть) меня́ в дере́вню и це́лые двена́дцать лет не (е́хать/е́здить) никуда́ (И.Турге́нев).","b":1},{"t":"subhead","text":"Đáp án: увёз; выезжа́л"},{"t":"para","text":"Dịch: Cha đưa (chở) tôi về làng (rời khỏi nơi cũ) và suốt mười hai năm trời không đi (ra) đâu cả."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Увёз","vi":"Chở đi hẳn (rời đi).","g":null},{"t":"vocab","ru":"Не выезжал","vi":"Không đi ra khỏi phạm vi làng/nhà (thường xuyên) → Tiền tố вы- (chưa hoàn thành thể).","g":null}]},{"id":"07-s174","type":"exercise","title":"Bài 673 (Trang 364-365)","num":673,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскро́йте ско́бки, употребля́я в ну́жной фо́рме оди́н из глаго́лов движе́ния с приста́вкой вы- и́ли с-. Вме́сто то́чек вста́вьте необходи́мые по смы́слу предло́ги. (Mở ngoặc đơn, sử dụng một trong các động từ chuyển động với tiền tố вы- [đi ra khỏi] hoặc с- [đi xuống/rời khỏi bề mặt] ở dạng thích hợp. Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa)."},{"t":"para","text":"1. Видна́ тропи́нка в куста́рнике, она́ (бежа́ть/бе́гать) к мо́рю изви́листой зме́йкой (В.Коне́цкий);","b":1},{"t":"subhead","text":"Đáp án: выбега́ет","b":1},{"t":"para","text":"Dịch: Có thể thấy một con đường mòn trong bụi rậm, nó chạy ra biển như một con rắn ngoằn ngoèo."},{"t":"para","text":"Giải thích: Con đường từ trong bụi rậm lộ ra/dẫn ra khoảng trống → Tiền tố вы-."},{"t":"para","text":"2. Но (е́хать/е́здить) ... Минера́льных Вод бы́ло не та́к-то легко́ (И.Ильф, Е.Петро́в);","b":1},{"t":"subhead","text":"Đáp án: вы́ехать из","b":1},{"t":"para","text":"Dịch: Nhưng rời khỏi (đi ra khỏi) Mineralnye Vody không dễ dàng như vậy."},{"t":"para","text":"Giải thích: Rời khỏi ranh giới thành phố → Tiền tố вы- + giới từ из."},{"t":"para","text":"3. Те́хник огляну́лся на ка́шель и, уви́дев нота́риуса, отупе́л на мгнове́ние, пото́м же вспы́хнул, вскочи́л и (бежа́ть/бе́гать) ... (кабине́т) (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: вы́бежал из кабине́та","b":1},{"t":"para","text":"Dịch: Viên kỹ thuật viên ngoái lại khi nghe tiếng ho, và khi nhìn thấy viên công chứng, hắn đờ người ra một lúc, rồi đỏ mặt, bật dậy và chạy ra khỏi phòng làm việc."},{"t":"para","text":"Giải thích: Chạy từ trong phòng ra ngoài → Tiền tố вы- + giới từ из."},{"t":"para","text":"4. В том ме́сте, где полева́я доро́га влива́лась в пусты́нное шоссе́, (лезть/ла́зить) ... (велосипе́д) и прислони́л его́ к телегра́фному столбу́ (В.Набо́ков).","b":1},{"t":"subhead","text":"Đáp án: слез с велосипе́да","b":1},{"t":"para","text":"Dịch: Ở chỗ con đường đồng hòa vào xa lộ vắng vẻ, [anh ta] xuống xe đạp và dựng nó vào cột điện báo."},{"t":"para","text":"Giải thích: Xuống khỏi phương tiện/bề mặt → Tiền tố с- + giới từ с."},{"t":"para","text":"5. — Нет, не могу́ ви́деть э́того, нет, не могу́! — закрича́ла А́нна Ри́чардовна и (бежа́ть/бе́гать) в секрета́рскую, а за не́ю как пу́ля вы́летел и бухга́лтер. (М.Булга́ков);","b":1},{"t":"subhead","text":"Đáp án: вы́бежала","b":1},{"t":"para","text":"Dịch: — Không, tôi không thể nhìn cảnh này, không, tôi không thể! — Anna Richardovna hét lên và chạy biến (chạy ra) sang phòng thư ký, và tay kế toán cũng lao ra theo cô như một viên đạn."},{"t":"para","text":"Giải thích: Chạy ra khỏi chỗ hiện tại để sang phòng khác → Tiền tố вы-."},{"t":"para","text":"6. Корне́й в у́треннем фа́ртуке (бежа́ть/бе́гать) ... (ле́стница) (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: сбежа́л с ле́стницы","b":1},{"t":"para","text":"Dịch: Korney trong chiếc tạp dề buổi sáng chạy xuống cầu thang."},{"t":"example","text":"Giải thích: Chạy từ trên cao xuống → Tiền tố с- + giới từ с (hoặc по). Ở đây dùng с để chỉ hành động chạy xuống hết cầu thang."},{"t":"para","text":"7. Домо́й Семён (е́хать/е́здить) в тот же день (В.Шукши́н);","b":1},{"t":"subhead","text":"Đáp án: вы́ехал","b":1},{"t":"para","text":"Dịch: Semyon lên đường (rời đi) về nhà ngay trong ngày hôm đó."},{"t":"para","text":"Giải thích: Bắt đầu hành trình rời khỏi một nơi → Tiền tố вы-."},{"t":"para","text":"8. — Ну! — заме́тила Да́рья Миха́йловна, — взобра́лся Африка́н Семёныч на своего́ конька́ тепе́рь не (лезть/ла́зить) ... (он) до ве́чера (И.Турге́нев);","b":1},{"t":"subhead","text":"Đáp án: сле́зет с него́","b":1},{"t":"para","text":"Dịch: — Chà! — Darya Mikhailovna nhận xét, — Afrikan Semyonych đã cưỡi lên con ngựa tủ của mình rồi, giờ thì ông ấy sẽ không xuống khỏi nó cho đến tối đâu."},{"t":"example","text":"Thành ngữ: Взобраться на конька = Bắt đầu nói về chủ đề yêu thích/sở trường."},{"t":"para","text":"Giải thích: Leo xuống khỏi cái gì (ngựa) → Tiền tố с- + giới từ с."},{"t":"para","text":"9. Из полуоткры́тых улы́бкою губ, выка́зывавших два ря́да бе́лых, ро́вных, как же́мчуг, зубо́в, (лете́ть/лета́ть) поры́вистое дыха́ние (Ф.Достое́вский);","b":1},{"t":"subhead","text":"Đáp án: вылета́ло","b":1},{"t":"para","text":"Dịch: Từ đôi môi hé mở nụ cười, để lộ hai hàng răng trắng đều như ngọc, hơi thở dồn dập bay ra (thoát ra)."},{"t":"para","text":"Giải thích: Bay từ trong ra ngoài → Tiền tố вы-."},{"t":"para","text":"10. Она́ не могла́ реши́ться позва́ть де́вушку и ещё ме́ньше (идти/ходи́ть) вниз и увида́ть сы́на и гуверна́нтку (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: сойти́","b":1},{"t":"para","text":"Dịch: Bà ấy không thể quyết định gọi cô hầu gái và càng không thể đi xuống dưới nhà để gặp con trai và cô gia sư."},{"t":"example","text":"Giải thích: Đi từ trên xuống dưới (вниз) → Tiền tố с-."},{"t":"para","text":"11. Мать е́хала с отцо́м со ста́нции Си́верской, а мы, де́ти, (е́хать/е́здить) им навстре́чу (В.Набо́ков);","b":1},{"t":"subhead","text":"Đáp án: вы́ехали","b":1},{"t":"para","text":"Dịch: Mẹ đi cùng cha từ ga Siverskaya, còn lũ trẻ chúng tôi đánh xe ra đón họ."},{"t":"para","text":"Giải thích: Đi ra khỏi nhà để đón ai đó → Tiền tố вы-."},{"t":"para","text":"12. Свя́занный мгнове́нно ру́хнул на́земь, как бу́дто ему́ подруби́ли но́ги, кра́ска (бежа́ть/бе́гать) ... (его́ лицо́) и глаза́ обессмы́слились (М.Булга́ков);","b":1},{"t":"subhead","text":"Đáp án: сбежа́ла с его́ лица́","b":1},{"t":"para","text":"Dịch: Kẻ bị trói ngay lập tức đổ sụp xuống đất, như thể bị chặt chân, sắc mặt biến sắc (máu chạy khỏi mặt) và đôi mắt trở nên vô hồn."},{"t":"para","text":"Giải thích: Rời khỏi bề mặt (mặt) → Tiền tố с- + giới từ с."},{"t":"para","text":"13. Наконе́ц дверь с гро́хотом отвори́лась, (лете́ть/лета́ть), кружа́сь и повёртываясь на во́здухе, Крак, по́йнтер Степа́на Арка́дьича, и (идти́/ходи́ть) сам Степа́н Арка́дьич с ружьём в рука́х и с сига́рой во рту (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: вы́летел; вы́шел"},{"t":"para","text":"Dịch: Cuối cùng cánh cửa mở toang với tiếng ầm, Krak - con chó săn của Stepan Arkadyich - bay vù ra, xoay tròn và lộn nhào trên không, và chính Stepan Arkadyich bước ra với khẩu súng trên tay và điếu xì gà trên miệng."},{"t":"para","text":"Giải thích: Cả hai đều di chuyển từ trong nhà ra ngoài qua cửa → Tiền tố вы-."},{"t":"para","text":"14. Она́ раскры́ла зо́нтик и хоте́ла бы́ло идти́ домо́й, как вдруг из-за угла́ избу́шки (е́хать/е́здить), на ни́зеньких беговы́х дро́жках, челове́к лет три́дцати (И.Турге́нев);","b":1},{"t":"subhead","text":"Đáp án: вы́ехал","b":1},{"t":"para","text":"Dịch: Cô mở ô và định đi về nhà, thì bỗng từ sau góc túp lều, một người đàn ông khoảng ba mươi tuổi đánh xe (đi xe) ra trên chiếc xe ngựa thấp."},{"t":"para","text":"Giải thích: Xuất hiện từ phía sau vật cản (đi ra) → Tiền tố вы-."},{"t":"para","text":"15. Держа́ кувши́н над голово́й, Грузи́нка у́зкою тропо́й (Идти́/Ходи́ть) к бе́регу (М.Ле́рмонтов).","b":1},{"t":"subhead","text":"Đáp án: сходи́ла","b":1},{"t":"para","text":"Dịch: Đội chiếc bình trên đầu, cô gái Gruzia đi xuống bờ sông theo con đường mòn hẹp."},{"t":"para","text":"Giải thích: Đi từ trên cao xuống thấp (xuống bờ sông để lấy nước) → Tiền tố с-."}]},{"id":"07-s175","type":"exercise","title":"Bài 674 (Trang 365-366)","num":674,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскро́йте ско́бки, употребля́я в ну́жной фо́рме оди́н из глаго́лов движе́ния с приста́вкой от- и́ли с-. Вме́сто то́чек вста́вьте необходи́мые по смы́слу предло́ги. (Mở ngoặc đơn, sử dụng một trong các động từ chuyển động với tiền tố от- [rời xa/đưa đi] hoặc с- [đi xuống/đi nhanh một mạch rồi về] ở dạng thích hợp. Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa)."},{"t":"para","text":"1. Посмотри́те, поговори́те с сосе́дями, (идти́/ходи́ть) на рабо́ту (В.Шукши́н);","b":1},{"t":"subhead","text":"Đáp án: сходи́те","b":1},{"t":"para","text":"Dịch: Hãy nhìn xem, nói chuyện với hàng xóm, rồi đi làm đi."},{"t":"para","text":"Giải thích:","b":1},{"t":"example","text":"Trong ngữ cảnh này, сходи́те (Mệnh lệnh thức) mang nghĩa \"hãy thực hiện hành động đi đến đó\" (một chuyến đi trọn vẹn hoặc mệnh lệnh giục giã nhẹ nhàng trong văn nói). Tiền tố с- + ходить mang nghĩa hoàn thành cho hành động đi lại."},{"t":"para","text":"2. Эй, послу́шай, брат! (Нести́/Носи́ть) письмо́ ... (по́чта), и скажи́ почтме́йстеру, чтоб он при́нял без де́нег (Н.Го́голь);","b":1},{"t":"subhead","text":"Đáp án: Снеси́ ... на по́чту"},{"t":"para","text":"Dịch: Này, nghe đây người anh em! Hãy mang lá thư ra bưu điện, và bảo ông trưởng bưu cục nhận cho mà không cần tiền."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Снеси́","vi":"Đây là dạng mệnh lệnh của động từ снести́ (mang đi/chuyển đi). Trong văn học cổ điển (Gogol), снести thường được dùng thay cho отнести (mang đi) với nghĩa giao việc vặt.","g":null},{"t":"para","text":"Giới từ chỉ hướng đến địa điểm chức năng (bưu điện): на."},{"t":"para","text":"3. — Послу́шайте, — сказа́л я, почти́ не зна́я, с чего́ и нача́ть, — не горю́йте об Азо́рке. Пойдёмте, я вас (везти́/вози́ть) ... (дом). Успоко́йтесь (Ф.Достое́вский);","b":1},{"t":"subhead","text":"Đáp án: отвезу́ ... домо́й"},{"t":"para","text":"Dịch: — Nghe này, — tôi nói, gần như không biết bắt đầu từ đâu, — đừng đau buồn về Azorka nữa. Đi nào, tôi sẽ chở (đưa) bà về nhà. Hãy bình tĩnh lại."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Отвезу́","vi":"Hành động đưa/chở ai đó rời khỏi chỗ hiện tại để đến đích khác → Tiền tố от- (отвезти - hoàn thành thể, tương lai đơn).","g":null},{"t":"vocab","ru":"Домой","vi":"Trạng từ chỉ hướng (về nhà), không cần giới từ.","g":null},{"t":"para","text":"4. Оте́ц Фёдор заяви́л, что э́тим же ве́чером до́лжен вы́ехать по де́лу, и потре́бовал, что́бы Катери́на Алекса́ндровна (бежа́ть/бе́гать) ... (брат бу́лочник) и взяла́ у него́ на неде́лю пальто́ с бара́шковым воротнико́м (И.Ильф, Е.Петро́в);","b":1},{"t":"subhead","text":"Đáp án: сбе́гала к бра́ту бу́лочнику","b":1},{"t":"para","text":"Dịch: Cha Fyodor tuyên bố rằng ngay tối nay ông phải đi công chuyện, và yêu cầu Katerina Alexandrovna chạy ù sang chỗ anh trai làm thợ làm bánh và mượn ông ấy chiếc áo khoác cổ lông cừu trong một tuần."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Сбе́гала","vi":"Hành động chạy đi rồi quay lại nhanh chóng (làm việc vặt) → Tiền tố с- (сбегать - hoàn thành thể).","g":null},{"t":"para","text":"Chạy đến chỗ ai đó: Giới từ к + Cách 3 (Dative)."},{"t":"para","text":"5. Мы ожида́ли ребёнка. Я (везти́/вози́ть) тебя́ в больни́цу о́коло Ба́йришер Плац и в пять часо́в утра́ шёл домо́й, в Грунева́льд (В.Набо́ков);","b":1},{"t":"subhead","text":"Đáp án: отвёз","b":1},{"t":"para","text":"Dịch: Chúng ta đang chờ đón đứa con chào đời. Anh đã chở em đến bệnh viện gần Bayerischer Platz và lúc năm giờ sáng anh đi bộ về nhà, ở Grunewald."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Отвёз","vi":"Hành động chở đi đến đích đã hoàn tất trong quá khứ → Tiền tố от- (отвезти).","g":null},{"t":"para","text":"6. — Ну, всё-таки я (бежа́ть/бе́гать) ... (она́). Ты не успе́ешь шля́пы наде́ть, я верну́сь (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: сбе́гаю к ней","b":1},{"t":"para","text":"Dịch: — Thôi, dù sao tôi cũng sẽ chạy ù sang chỗ cô ấy. Anh chưa kịp đội mũ thì tôi đã về rồi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Сбе́гаю","vi":"Chạy đi nhanh rồi về ngay → Tiền tố с-.","g":null},{"t":"example","text":"Đến chỗ ai: Giới từ к + Cách 3 (ней)."},{"t":"para","text":"7. Быва́ло, прие́дет к ней попа́дья и́ли поме́щица, а она́ (вести́/води́ть) её в у́гол и дава́й ду́шу (вести́/води́ть) — всё о том же, о бли́зкой сме́рти (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: отведёт; отводи́ть"},{"t":"para","text":"Dịch: Thường thì, hễ có bà vợ linh mục hay bà địa chủ đến thăm, là bà ấy lại dẫn bà khách vào góc nhà và bắt đầu trút bầu tâm sự — vẫn toàn về chuyện đó, về cái chết cận kề."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Отведёт","vi":"Dẫn ai đó tách ra/đi ra một chỗ khác (vào góc) → Tiền tố от-. Dùng tương lai đơn (отведёт) trong ngữ cảnh kể chuyện lặp lại (бывало).","g":null},{"t":"vocab","ru":"Отводи́ть ду́шу","vi":"Thành ngữ \"trút bầu tâm sự/giải tỏa nỗi lòng\".","g":null},{"t":"vocab","ru":"Плю́нул царь","vi":"“Так лих же: нет! Ничего́ ты не полу́чишь. Сам себя́ ты, гре́шник, му́чишь; Убира́йся, цел пока́; (Тащи́ть/Таска́ть) старика́!” (А.Пу́шкин);","g":null},{"t":"subhead","text":"Đáp án: Оттащи́те","b":1},{"t":"para","text":"Dịch: Nhà vua nhổ toẹt: “Thật là đồ khốn: không! Ngươi sẽ chẳng nhận được gì hết. Tự ngươi làm khổ mình thôi, tên tội đồ; Cút ngay khi còn toàn thây; Lôi lão già này đi!”"},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Оттащи́те","vi":"Mệnh lệnh thức, yêu cầu lôi ai đó ra xa/đi chỗ khác → Tiền tố от-.","g":null},{"t":"para","text":"9. — Зна́ю я одного́ челове́чка, — обрати́лся он к глу́повцам, — не к нему́ ли нам наперёд поклони́ться? Он (сиде́ть/сиде́ть) в ка́рцере! (М.Салтыко́в-Щедри́н) 10. [Антон Антонович]: — Вы (идти́/ходи́ть)-ка к до́ктору да посове́туйтесь с ним (Ф.Достое́вский).","b":1},{"t":"note","text":"Lưu ý: Trong sách gốc, bài tập này có thể bị ngắt quãng hoặc đánh số khác nhau tùy ấn bản. Câu 9 về \"người ngồi tù\" thường không yêu cầu điền động từ chuyển động trong bài này (vì сидеть không phải động từ chuyển động). Câu 10 mới là câu cần điền."},{"t":"subhead","text":"Đáp án (câu 10): Сходи́те-ка","b":1},{"t":"para","text":"Dịch: — Này ông Yakov Petrovich, — Anton Antonovich tiếp tục. — Ông thử đi khám bác sĩ và xin lời khuyên xem sao."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Сходи́те","vi":"Lời khuyên đi đến đâu đó (và quay về), thực hiện một chuyến đi → Tiền tố с-. Hậu tố -ка làm câu mệnh lệnh mềm mỏng hơn.","g":null}]},{"id":"07-s176","type":"exercise","title":"Bài 675 (Trang 366)","num":675,"blocks":[{"t":"instruction","text":"Yêu cầu: Раскро́йте ско́бки, употребля́я в ну́жной фо́рме оди́н из глаго́лов движе́ния с приста́вкой про- и́ли в-. Вме́сто то́чек вста́вьте необходи́мые по смы́слу предло́ги. (Mở ngoặc đơn, sử dụng một trong các động từ chuyển động với tiền tố про- [đi qua/xuyên qua] hoặc в- [đi vào] ở dạng thích hợp. Thay dấu ba chấm bằng các giới từ cần thiết theo ý nghĩa)."},{"t":"para","text":"1. А ме́жду тем како́е-то но́вое ощуще́ние отозва́лось во всём существе́ господи́на Голя́дкина: тоска́ не тоска́, страх не страх... лихора́дочный тре́пет (бежа́ть/бе́гать) ... (жи́лам) его́ (Ф.Достое́вский);","b":1},{"t":"subhead","text":"Đáp án: пробежа́л по жи́лам","b":1},{"t":"para","text":"Dịch: Và trong lúc đó, một cảm giác mới mẻ nào đó vang lên trong toàn bộ con người ông Golyadkin: buồn chẳng ra buồn, sợ chẳng ra sợ... một cơn run rẩy sốt sắng chạy dọc huyết quản ông."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Пробежа́л","vi":"Chạy qua/chạy dọc theo (hoàn thành thể) → Tiền tố про-.","g":null},{"t":"para","text":"Giới từ đi kèm: по + Cách 3 (chạy dọc theo cái gì)."},{"t":"para","text":"2. В избу́ (лете́ть/лета́ть) ве́тер. Ого́нь на све́чке беспоко́йно замелька́л, я́рко вспы́хнул и поту́х (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: влете́л (hoặc ворвался)"},{"t":"para","text":"Dịch: Gió thổi thốc vào trong lều. Ngọn lửa trên cây nến chập chờn không yên, bùng lên sáng rực rồi tắt ngấm."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Влете́л","vi":"Bay vào/lao vào trong (chỉ luồng gió mạnh) → Tiền tố в-.","g":null},{"t":"para","text":"3. — Хо́чешь в кабине́т? — мра́чно хму́рясь, сказа́л Лёвин по-францу́зски Степа́ну Арка́дьичу. — (Идти́/Ходи́ть) в кабине́т, вы там переговори́те (Л.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: Войдём (hoặc Пойдём)"},{"t":"para","text":"Dịch: — Cậu muốn vào phòng làm việc à? — Levin cau mày ảm đạm nói bằng tiếng Pháp với Stepan Arkadyich. — Chúng ta hãy vào phòng làm việc, các cậu sẽ nói chuyện ở đó."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Войдём","vi":"Mời/rủ đi vào trong không gian kín (phòng) → Tiền tố в-.","g":null},{"t":"para","text":"4. Ну что ты? к чему́? заче́м? Что за ве́треность така́я! Вдруг (бежа́ть/бе́гать), как угоре́лая ко́шка (Н.Го́голь);","b":1},{"t":"subhead","text":"Đáp án: вбежа́ла (hoặc вы́бежала tùy ngữ cảnh trước đó, nhưng thường là chạy vào hoặc chạy ra bất ngờ)."},{"t":"example","text":"Ngữ cảnh Gogol: Thường miêu tả ai đó chạy xộc vào/chạy biến đi. Nếu chạy vào phòng → вбежа́ла."},{"t":"para","text":"Dịch: Em làm sao thế? Để làm gì? Tại sao? Cái tính khí đồng bóng gì thế này! Đột nhiên chạy xộc vào/chạy biến đi như con mèo bị bỏng."},{"t":"para","text":"5. Её не́ было до́ма. И в кали́точку (идти́/ходи́ть) челове́к. Он (идти́/ходи́ть) в дом по како́му-то де́лу к мое́му застро́йщику, пото́м сошёл в са́дик и как-то о́чень бы́стро свёл со мной знако́мство (М.Булга́ков);","b":1},{"t":"subhead","text":"Đáp án: вошёл; вошёл (hoặc прошёл)"},{"t":"para","text":"Dịch: Cô ấy không có nhà. Và một người đàn ông bước vào cổng nhỏ. Ông ta đi vào nhà có việc gì đó với người chủ thầu của tôi, sau đó xuống vườn và làm quen với tôi rất nhanh."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вошёл","vi":"Đi từ ngoài vào trong (cổng, nhà) → Tiền tố в-.","g":null},{"t":"para","text":"6. Но вот разда́лся стук экипа́жа (е́хать/е́здить) на двор, и че́рез не́сколько мгнове́ний лаке́й (идти́/ходи́ть) в гости́ную и по́дал Да́рье Миха́йловне письмо́ на сере́бряном блю́дечке (И.Турге́нев);","b":1},{"t":"subhead","text":"Đáp án: въе́хавшего; вошёл"},{"t":"para","text":"Dịch: Nhưng rồi vang lên tiếng xe ngựa đang đi vào sân, và vài khoảnh khắc sau người hầu bước vào phòng khách và đưa cho Darya Mikhailovna một lá thư trên chiếc đĩa bạc nhỏ."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Въе́хавшего","vi":"(Tính động từ) Đi vào sân bằng phương tiện → Tiền tố в-.","g":null},{"t":"vocab","ru":"Вошёл","vi":"Đi vào phòng → Tiền tố в-.","g":null},{"t":"para","text":"7. (Идти́/Ходи́ть) ве́тер, подня́л гри́вы лошаде́й, наду́л мали́новые рукава́ ку́чера (В.Набо́ков);","b":1},{"t":"subhead","text":"Đáp án: Прошёл","b":1},{"t":"para","text":"Dịch: Một cơn gió thổi qua (quét qua), làm dựng đứng bờm ngựa, thổi phồng tay áo màu mâm xôi của người đánh xe."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Прошёл","vi":"Gió di chuyển qua không gian, tác động lướt qua → Tiền tố про-.","g":null},{"t":"para","text":"8. Прие́хав домо́й, она́ (идти́/ходи́ть) чёрным хо́дом к себе́ в спа́льню и прилегла́ на посте́ль му́жа (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: прошла́ (hoặc вошла)"},{"t":"para","text":"Dịch: Về đến nhà, cô ấy đi theo lối cửa sau vào phòng ngủ của mình và nằm xuống giường chồng."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Прошла́","vi":"Đi xuyên qua một lối đi/quãng đường (lối cửa sau) để đến đích → Tiền tố про- là hay nhất (đi qua lối đó). Вошла (đi vào) cũng chấp nhận được.","g":null},{"t":"para","text":"9. За ночь в стани́цу (идти́/ходи́ть) кру́пные си́лы каза́ков (А.Толсто́й);","b":1},{"t":"subhead","text":"Đáp án: вошли́","b":1},{"t":"para","text":"Dịch: Trong đêm, các lực lượng lớn của quân Cossack đã tiến vào làng Stanitsa."},{"t":"example","text":"Giải thích: Quân đội đi vào địa phận → Tiền tố в- (вошли)."},{"t":"para","text":"10. — Мы с Серёжей, — сказа́л мой оте́ц, — по́сле ча́ю пойдём осма́тривать ко́нный заво́д, а пото́м (идти́/ходи́ть) на ру́дники и на ме́льницу (С.Акса́ков);","b":1},{"t":"subhead","text":"Đáp án: пройдём (hoặc зайдём)"},{"t":"para","text":"Dịch: — Bố và Seryozha, — cha tôi nói, — sau khi uống trà sẽ đi xem trại nuôi ngựa, và sau đó sẽ đi qua (đi tới) khu mỏ và cối xay gió."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Пройдём","vi":"Đi bộ một quãng đến địa điểm tiếp theo → Tiền tố про- (mang nghĩa đi dạo/đi thăm thú).","g":null},{"t":"para","text":"11. Ива́н перешёл че́рез доро́гу, (идти́/ходи́ть) в дом... И его́ до́лго не́ было (А.Че́хов);","b":1},{"t":"subhead","text":"Đáp án: вошёл","b":1},{"t":"para","text":"Dịch: Ivan băng qua đường, đi vào trong nhà... Và anh ta ở trong đó rất lâu."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вошёл","vi":"Đi từ ngoài vào trong → Tiền tố в-.","g":null},{"t":"para","text":"12. (Идти́/Ходи́ть) в ко́мнату — Ва́ли не́ было. Зашёл в другу́ю ко́мнату — и там нет. — Убежа́ла (В.Шукши́н).","b":1},{"t":"subhead","text":"Đáp án: Вошёл","b":1},{"t":"para","text":"Dịch: [Anh ta] bước vào phòng — Vali không có đó. Ghé sang phòng khác — cũng không có. — Chạy mất rồi."},{"t":"para","text":"Giải thích:","b":1},{"t":"vocab","ru":"Вошёл","vi":"Bước vào không gian phòng → Tiền tố в-.","g":null}]},{"id":"07-s177","type":"exercise","title":"Bài 676 (Trang 367)","num":676,"blocks":[{"t":"instruction","text":"Yêu cầu: В усто́йчивых словосочета́ниях вста́вьте необходи́мые по смы́слу глаго́лы движе́ния с приста́вками. (Trong các cụm từ cố định (thành ngữ), hãy điền các động từ chuyển động có tiền tố cần thiết theo ý nghĩa)."},{"t":"para","text":"1. Вчера́ я у меня́ от всех э́тих пробле́м ум за ра́зум (зайти́).","b":1},{"t":"subhead","text":"Đáp án: зашёл","b":1},{"t":"para","text":"Dịch: Hôm qua tôi đã bối rối tột độ (đầu óc mụ mị) vì tất cả những vấn đề này."},{"t":"example","text":"Giải thích: Thành ngữ ум за разум зашёл (trí khôn đi trốn sau trí tuệ - tức là mất khả năng suy nghĩ sáng suốt, bị lú lẫn)."},{"t":"para","text":"2. Ну что ж, пора́ (подвести́) черту́ под на́шим разгово́ром.","b":1},{"t":"subhead","text":"Đáp án: подвести́","b":1},{"t":"para","text":"Dịch: Chà, đã đến lúc chốt lại (kết thúc) cuộc trò chuyện của chúng ta."},{"t":"example","text":"Giải thích: Thành ngữ подвести черту (gạch một đường kẻ dưới - tổng kết, kết thúc)."},{"t":"para","text":"3. Он ду́мает, его́ поведе́ние ему́ с рук (сойти́), не тут-то бы́ло!","b":1},{"t":"subhead","text":"Đáp án: сойдёт","b":1},{"t":"para","text":"Dịch: Hắn tưởng hành vi của hắn sẽ trót lọt (vô sự/không bị trừng phạt), nhưng nhầm to rồi!"},{"t":"example","text":"Giải thích: Thành ngữ сойти с рук (trôi đi khỏi tay - thoát tội, làm sai mà không bị phạt). Dùng thì tương lai сойдёт."},{"t":"para","text":"4. Подожди́ немно́го, дай мне (перевести́) дух.","b":1},{"t":"subhead","text":"Đáp án: перевести́","b":1},{"t":"para","text":"Dịch: Đợi một chút, để tôi lấy lại hơi (thở phào) đã."},{"t":"example","text":"Giải thích: Thành ngữ перевести дух (lấy hơi, nghỉ lấy sức sau khi mệt hoặc sợ hãi)."},{"t":"para","text":"5. Я никому́ не позво́лю (обвести́) меня́ вокру́г па́льца.","b":1},{"t":"subhead","text":"Đáp án: обвести́","b":1},{"t":"para","text":"Dịch: Tôi sẽ không cho phép ai dắt mũi (lừa gạt) tôi đâu."},{"t":"example","text":"Giải thích: Thành ngữ обвести вокруг пальца (quấn quanh ngón tay - lừa gạt ai đó một cách khéo léo)."},{"t":"para","text":"6. Наш конце́рт (подходи́ть) к концу́.","b":1},{"t":"subhead","text":"Đáp án: подхо́дит","b":1},{"t":"para","text":"Dịch: Buổi hòa nhạc của chúng ta đang đi đến hồi kết."},{"t":"example","text":"Giải thích: Cụm từ подходить к концу (sắp kết thúc). Dùng thì hiện tại."},{"t":"para","text":"7. У меня́ дух (захва́тывать) от восто́рга.","b":1},{"t":"subhead","text":"Đáp án: захва́тывает","b":1},{"t":"para","text":"Dịch: Tôi nín thở (nghẹt thở/choáng ngợp) vì sung sướng."},{"t":"example","text":"Giải thích: Thành ngữ дух захватывает (cảm giác mạnh khiến nín thở). Mặc dù захватывать không phải là động từ chuyển động thuần túy (motion verb) như идти/ехать, nhưng trong ngữ cảnh bài tập rộng về các động từ vận động/tác động, nó thường được xếp vào nhóm này. (Lưu ý: Nếu bắt buộc dùng động từ chuyển động gốc ходить/носить... thì câu này không có đáp án, nhưng захватывает là đáp án chuẩn của thành ngữ này)."},{"t":"para","text":"8. Когда́ она́ позвони́ла, у меня́ от се́рдца (отлечь).","b":1},{"t":"subhead","text":"Đáp án: отлегло́","b":1},{"t":"para","text":"Dịch: Khi cô ấy gọi điện, tôi thấy nhẹ cả người (trút được gánh nặng trong lòng)."},{"t":"example","text":"Giải thích: Thành ngữ отлегло от сердца (nỗi lo lắng rời khỏi tim)."},{"t":"para","text":"9. Вчера́ на ве́чере весели́лись во всю, (отвести́) ду́шу.","b":1},{"t":"subhead","text":"Đáp án: отвели́","b":1},{"t":"para","text":"Dịch: Hôm qua ở buổi tiệc chúng tôi đã vui đùa hết mình, thỏa nỗi lòng (xả láng)."},{"t":"example","text":"Giải thích: Thành ngữ отвести душу (làm cho thỏa thích, trút bầu tâm sự)."},{"t":"para","text":"10. Снача́ла мы ви́делись раз в неде́лю, пото́м раз в ме́сяц, и постепе́нно на́ши встре́чи (сойти́) на нет.","b":1},{"t":"subhead","text":"Đáp án: сошли́","b":1},{"t":"para","text":"Dịch: Ban đầu chúng tôi gặp nhau mỗi tuần một lần, sau đó mỗi tháng một lần, và dần dần các cuộc gặp gỡ của chúng tôi tiêu tan (biến mất hẳn)."},{"t":"example","text":"Giải thích: Thành ngữ сойти на нет (trở về số không, tàn lụi)."},{"t":"vocab","ru":"У него́ пробле́мы","vi":"он по у́ши (влезть) в долги́.","g":null},{"t":"subhead","text":"Đáp án: влез","b":1},{"t":"para","text":"Dịch: Anh ta có vấn đề rồi: anh ta đã ngập (chui vào) trong nợ nần đến tận cổ."},{"t":"example","text":"Giải thích: Thành ngữ влезть в долги (mắc nợ)."},{"t":"para","text":"12. Он (перейти́) нам доро́гу и бу́дет нам меша́ть.","b":1},{"t":"subhead","text":"Đáp án: перешёл (hoặc перейдёт)"},{"t":"para","text":"Dịch: Hắn đã ngáng đường (tranh giành quyền lợi) chúng ta và sẽ cản trở chúng ta."},{"t":"example","text":"Giải thích: Thành ngữ перейти дорогу (đi ngang qua đường ai đó - cản trở, tranh giành)."},{"t":"para","text":"13. От всех э́тих дел, кото́рые на нас навали́лись, с ума́ (сойти́) мо́жно.","b":1},{"t":"subhead","text":"Đáp án: сойти́","b":1},{"t":"para","text":"Dịch: Vì tất cả những việc đổ lên đầu chúng ta thế này, có mà phát điên mất thôi."},{"t":"example","text":"Giải thích: Thành ngữ сойти с ума (phát điên)."}]},{"id":"07-s178","type":"exercise","title":"Bài 677 (Trang 367-368)","num":677,"blocks":[{"t":"instruction","text":"Yêu cầu: Вме́сто то́чек, где ну́жно, вста́вьте необходи́мые по смы́слу приста́вки. Раскро́йте ско́бки, употребля́я в ну́жной фо́рме оди́н из глаго́лов движе́ния. Объясни́те ваш вы́бор. Укажи́те вариа́нты. (Thay dấu ba chấm bằng các tiền tố cần thiết. Mở ngoặc đơn, sử dụng dạng thích hợp của động từ chuyển động. Giải thích sự lựa chọn và chỉ ra các phương án)."},{"t":"note","text":"Lưu ý: Bài này dựa trên đoạn trích từ tác phẩm \"Những linh hồn chết\" (Мёртвые души) của N. Gogol."},{"t":"para","text":"а)","b":1},{"t":"example","text":"Dịch & Điền từ: В воро́та гости́ницы губе́рнского го́рода NN въе́хала (е́хать/е́здить) дово́льно краси́вая небольша́я бри́чка, в како́й е́здят (е́хать/е́здить) холостяки́: отста́вные полко́вники, штабс-капита́ны, поме́щики, име́ющие о́коло со́тни душ крестья́н, — сло́вом, все те, кото́рых называ́ют господа́ми сре́дней руки́. (Một chiếc xe ngựa nhỏ khá đẹp đã đi vào cổng khách sạn của thành phố tỉnh lẻ NN, loại xe mà những người độc thân thường đi: các đại tá về hưu, các đại úy, các địa chủ có khoảng một trăm nông nô, — tóm lại, tất cả những người được gọi là quý ông hạng trung)."},{"t":"vocab","ru":"Въехала","vi":"Hành động một lần, đi vào trong cổng (hoàn thành thể) → Tiền tố в-.","g":null},{"t":"vocab","ru":"Ездят","vi":"Hành động thường xuyên, đặc trưng của nhóm người (đa chiều/lặp lại) → Ездить (hiện tại: ездят).","g":null},{"t":"example","text":"В бри́чке сиде́л господи́н. Въезд его́ не произвёл в го́роде соверше́нно никако́го шу́ма и не был сопровожда́ем ниче́м осо́бенным; то́лько два ру́сских мужика́, стоя́вшие про́тив гости́ницы, сде́лали ко́е-каки́е замеча́ния, относи́вшиеся, впро́чем, бо́лее к экипа́жу, чем к сиде́вшему в нём. «Вишь ты, — сказа́л оди́н друго́му, — вон како́е колесо́! что ты ду́маешь, дое́дет (е́хать/е́здить) то колесо́, е́сли б случи́лось, до Москвы́ и́ли не дое́дет (е́хать/е́здить)?» — «Дое́дет», — отвеча́л друго́й. «А до Каза́ни-то, я ду́маю, не дое́дет (е́хать/е́здить)?» — «В Каза́нь не дое́дет», — отвеча́л друго́й. Э́тим разгово́р и ко́нчился. (Trong xe có một quý ông ngồi. Sự xuất hiện của ông ta không gây ra bất kỳ tiếng ồn nào trong thành phố... chỉ có hai người nông dân Nga... đưa ra vài nhận xét... \"Nhìn kìa, — một người nói, — cái bánh xe kia kìa! Cậu nghĩ sao, cái bánh xe đó liệu có đi đến được Moscow không, nếu cần?\" — \"Đến được\", — người kia đáp. \"Thế còn đến Kazan, tớ nghĩ là không đến được đâu nhỉ?\" — \"Đến Kazan thì không đến được\", — người kia đáp)."},{"t":"vocab","ru":"Доедет","vi":"Đạt đến đích giới hạn (Moscow, Kazan) → Tiền tố до- (hoàn thành thể).","g":null},{"t":"example","text":"Да ещё, когда́ бри́чка подъе́хала (е́хать/е́здить) к гости́нице, встре́тился молодо́й челове́к в бе́лых пантало́нах... придержива́л руко́й карту́з, кото́рый чуть не слете́л (лете́ть/лета́ть) с его́ головы́ от ве́тра, и пошёл (идти́/ходи́ть) свое́й доро́гой. (Và nữa, khi chiếc xe đi đến (đỗ lại) khách sạn, có một chàng trai trẻ... tay giữ chiếc mũ lưỡi trai suýt thì bay mất khỏi đầu vì gió, và bước đi theo đường của mình)."},{"t":"vocab","ru":"Подъехала","vi":"Đến gần/tiếp cận khách sạn → Tiền tố под-.","g":null},{"t":"vocab","ru":"Слетел","vi":"Rời khỏi bề mặt (đầu) → Tiền tố с-. (Dùng слетел vì có с головы).","g":null},{"t":"vocab","ru":"Пошёл","vi":"Bắt đầu hành động đi rời đi → Tiền tố по-.","g":null},{"t":"example","text":"Когда́ экипа́ж въе́хал (е́хать/е́здить) во двор, господи́н был встре́чен тракти́рным слуго́ю. Он вы́бежал (бежа́ть/бе́гать) прово́рно с салфе́ткой в руке́ и поввёл (вести́/води́ть) господи́на вверх пока́зывать ниспо́сланный ему́ бо́гом поко́й. (Khi cỗ xe đi vào sân, quý ông được người hầu quán trọ đón tiếp. Hắn ta nhanh nhẹn chạy ra với chiếc khăn ăn trên tay và dẫn quý ông lên lầu để chỉ căn phòng...)"},{"t":"vocab","ru":"Въехал","vi":"Đi vào trong sân → Tiền tố в-.","g":null},{"t":"vocab","ru":"Выбежал","vi":"Chạy từ trong nhà ra đón → Tiền tố вы-.","g":null},{"t":"vocab","ru":"Повёл","vi":"Bắt đầu dẫn đi/dẫn lên → Tiền tố по-.","g":null},{"t":"para","text":"б)","b":1},{"t":"example","text":"Dịch & Điền từ: Всё бы́ло гото́во. И сам геро́й наконе́ц при тракти́рных и чужи́х лаке́ях, собра́вшихся позева́ть, как выезжа́ет (е́хать/е́здить) чужо́й ба́рин, и сел в экипа́ж, — и бри́чка, в кото́рой е́здят (е́хать/е́здить) холостяки́... (Mọi thứ đã sẵn sàng. Và cuối cùng nhân vật chính, trước mặt đám người hầu quán trọ và người lạ tụ tập để xem một ông chủ lạ mặt rời đi (khởi hành) như thế nào, đã ngồi lên xe, — và chiếc xe ngựa, loại mà những người độc thân thường đi...)"},{"t":"vocab","ru":"Выезжает","vi":"Đang diễn ra quá trình rời đi (quan sát quá trình) → Tiền tố вы- (chưa hoàn thành thể).","g":null},{"t":"vocab","ru":"Ездят","vi":"Hành động lặp lại/đặc trưng (như câu đầu đoạn a) → Đa chiều ездить.","g":null},{"t":"example","text":"кото́рая так до́лго застоя́лась в го́роде... вы́ехала (е́хать/е́здить) из воро́т гости́ницы. “Сла́ва те, го́споди!” — поду́мал Чи́чиков и перекрести́лся. (chiếc xe đã nằm lại trong thành phố quá lâu... đã đi ra khỏi cổng khách sạn. \"Tạ ơn Chúa!\" — Chichikov nghĩ và làm dấu thánh)."},{"t":"vocab","ru":"Выехала","vi":"Đã hoàn tất việc đi ra → Tiền tố вы- (hoàn thành thể).","g":null},{"t":"example","text":"С каки́м-то неопределённым чу́вством гляде́л он на дома́, сте́ны, забо́р и у́лицы, кото́рые та́кже с свое́й стороны́ как бу́дто подска́кивая, ме́дленно уходи́ли (идти́/ходи́ть) наза́д. (Với một cảm xúc mơ hồ nào đó, ông nhìn những ngôi nhà, bức tường, hàng rào và đường phố, những thứ dường như cũng đang nhảy múa và chầm chậm lùi (trôi) về phía sau)."},{"t":"vocab","ru":"Уходили назад","vi":"Di chuyển ra xa/lùi lại phía sau → Tiền tố у- (chưa hoàn thành thể).","g":null},{"t":"example","text":"При поворо́те в одну́ из у́лиц бри́чка должна́ была́ останови́ться, потому́ что во всю длину́ её шла (идти́/ходи́ть) бесконе́чная погреба́льная проце́ссия (Н.Го́голь, “Мёртвые ду́ши”). (Ở khúc cua vào một con phố, chiếc xe ngựa buộc phải dừng lại, bởi vì đang đi dọc suốt chiều dài con phố là một đám tang dài vô tận)."},{"t":"vocab","ru":"Шла","vi":"Đám tang đang di chuyển (theo một hướng) → Một chiều идти (quá khứ шла).","g":null}]}]};
